/* ============================================================
   Procedure: [dbo].[usp_getMicrositeNameForMicrosite]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_getMicrositeNameForMicrosite] --335
	@UserID BIGINT
AS
BEGIN
	SELECT REPLACE(cpd.PageName, 'www.kit19.com/', '') AS Name
	FROM   ClientPageDetail AS cpd
	WHERE  cpd.[User_ID] = @UserID
END



GO

