CREATE   PROCEDURE dbo.Usp_GetMinAdSpend --'Facebook'
(
  @Type nvarchar(500)
)
as
Begin
   Select isnull(MinimumAdSpend,0) as MinimumAdSpend  from DigitalMarketingMaster where type = @Type
End



