/* ============================================================
   Procedure: [dbo].[Usp_GetMobileByEnquiryID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetMobileByEnquiryID]  
(  
 @EnquiryID bigint,    
 @WhichMob int  
  
)   
as  
Begin  
  
    if(@WhichMob = 1)  
 Begin  
     select isnull(MobileNo,'') from UserEnquiry(nolock) where  EnquiryID = @EnquiryID      
 End  
 else if(@WhichMob = 2)  
 Begin  
   select isnull(MobileNo1,'') from userEnquiry(nolock) where  EnquiryID = @EnquiryID      
 End  
 else if(@WhichMob = 3)  
 Begin  
   select isnull(MobileNo2,'') from userEnquiry(nolock) where  EnquiryID = @EnquiryID      
 End  
  else if(@WhichMob = 4)  
 Begin  
   select isnull(MobileNo,'')  as  MobileNo ,isnull(MobileNo1,'') as MobileNo1 , isnull(MobileNo2,'') as MobileNo2 from userEnquiry(nolock) where  EnquiryID = @EnquiryID      
 End



End  


GO

