/* ============================================================
   Procedure: [dbo].[USP_GetMobileFromQueue_International]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--USP_GetMobileFromQueue_International 100        
CREATE   PROC [dbo].[USP_GetMobileFromQueue_International]                                                  
(                                                  
@TOTALCOUNT INT =100                                         
)                                                  
AS             
        
BEGIN                                                
SET NOCOUNT ON                                                
DECLARE @TOPCOUNT INT                                                
DECLARE @RESTCOUNTAFTERDirect INT                                               
DECLARE @RESTCOUNTAFTERPriority  INT                                            
SET @TOPCOUNT = @TOTALCOUNT                                                
              
                 
DECLARE @TEMPTABLE TABLE                                                
(                                                
  MessageID BIGINT,         
                                               
  Mobile VARCHAR(20),                                                
  Message NVARCHAR(Max),                                              
  SenderID  NVARCHAR(20),                                              
  SmppID tinyint ,                                              
  U_ID int,                                            
  IsUnicode bit,                                             
   priority tinyint ,                                
BATCHID bigint,                           
Operator NVARCHAR(6),        
CountryCode nvarchar(10)        
)                         
                                    
INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,        
IsUnicode,priority, BATCHID,Operator,CountryCode FROM  Int_MessageQueueNew         
WHERE  PRIORITY=2 and SmppID=2 --order by convert(datetime,messageinsertdate,100)                      
SET @RESTCOUNTAFTERDirect =@@ROWCOUNT                                                
                                                
IF (@RESTCOUNTAFTERDirect< @TOPCOUNT)                                                
 BEGIN                                                
                                           
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT-@RESTCOUNTAFTERDirect ) MessageID,Mobile,[Message],        
 SenderID,SmppID, U_ID,IsUnicode,priority,BATCHID,Operator,CountryCode FROM  dbo.Int_MessageQueueNew         
 WHERE  PRIORITY=1 and SmppID=2  --order by --convert(datetime,messageinsertdate,100)                          
                         
     SET @RESTCOUNTAFTERPriority =@@ROWCOUNT                                             
                                                
                                            
 IF ((@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)< @TOPCOUNT)                                               
  BEGIN                                            
   SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDirect +@RESTCOUNTAFTERPriority)                                                
 INSERT INTO @TEMPTABLE SELECT TOP(@TOPCOUNT) MessageID,Mobile,[Message],SenderID,SmppID,U_ID,      
 IsUnicode, priority,BATCHID,Operator,CountryCode FROM  dbo.Int_MessageQueueNew       
 WHERE  PRIORITY=0 and  SmppID=2  --order by convert(datetime,messageinsertdate,100)           
                  
 END                                            
END                         
 delete FROM Int_MessageQueueNew where MESSAGEID in (select MESSAGEID  from @TEMPTABLE )        
                         
                                 
SELECT right(MessageID,9) UserTag,MessageId, rtrim(ltrim(Mobile)) as Mobile,        
 rtrim(ltrim([Message])) As [Message] ,rtrim(ltrim(SenderID))                        
As SenderID,U_ID,IsUnicode,priority,BATCHID,Operator  FROM @TEMPTABLE                         
                        
END     


GO

