/* ============================================================
   Procedure: [dbo].[usp_getmobileno_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getmobileno_New]      
 @entity   NVARCHAR(20),       
    @entityid BIGINT      
AS      
    BEGIN      
        DECLARE @parentid BIGINT;      
        IF @entity = 'lead'      
            BEGIN      
                SELECT @parentid = parentid      
                FROM userleads(NOLOCK)      
                WHERE id = @entityid;      
                SELECT Mobile      
                FROM      
                (      
                    SELECT ISNULL(CAST(countrycode AS NVARCHAR) + '-' + CAST(mobileno AS NVARCHAR), '') AS Mobile      
                    FROM userleads(NOLOCK)      
                    WHERE id = @entityid      
                          AND NULLIF(MobileNo, '') IS NOT NULL      
                    UNION      
                    SELECT ISNULL(CAST(countrycode1 AS NVARCHAR) + '-' + CAST(MobileNo1 AS NVARCHAR), '') AS Mobile      
                    FROM userleads(NOLOCK)      
                    WHERE id = @entityid      
                          AND NULLIF(MobileNo1, '') IS NOT NULL      
                    UNION      
                    SELECT ISNULL(CAST(CountryCode2 AS NVARCHAR) + '-' + CAST(MobileNo2 AS NVARCHAR), '') AS Mobile      
                    FROM userleads(NOLOCK)      
                    WHERE id = @entityid      
                          AND NULLIF(MobileNo2, '') IS NOT NULL      
                ) A      
                WHERE ISNULL(mobile, '') <> ''      
                --      AND NOT EXISTS      
                --(      
                --    SELECT 1      
                --    FROM MySMSConversations.dbo.convusers  WHERE channelid = 2      
                --          AND channelprofileid = replace(replace(a.mobile, '+', ''), '-', '')      
                --          AND convuserparentid = @parentid and isactive = 1   
                --);      
        END;      
        ELSE      
            IF @entity = 'enquiry'      
                BEGIN      
                    SELECT @parentid = parentid      
                    FROM userenquiry(NOLOCK)      
                    WHERE EnquiryID = @entityid;      
                          
     SELECT Mobile      
                    FROM      
                    (      
                        SELECT ISNULL(CAST(countrycode AS NVARCHAR) + '-' + CAST(mobileno AS NVARCHAR), '') AS Mobile      
                        FROM userenquiry(NOLOCK)      
                        WHERE EnquiryID = @entityid      
                              AND NULLIF(MobileNo, '') IS NOT NULL      
                        UNION      
                        SELECT ISNULL(CAST(countrycode1 AS NVARCHAR) + '-' + CAST(MobileNo1 AS NVARCHAR), '') AS Mobile      
                        FROM userenquiry(NOLOCK)      
                        WHERE EnquiryID = @entityid      
                              AND NULLIF(MobileNo1, '') IS NOT NULL      
                        UNION      
                        SELECT ISNULL(CAST(CountryCode2 AS NVARCHAR) + '-' + CAST(mobileno AS NVARCHAR), '') AS Mobile      
                        FROM userenquiry(NOLOCK)      
                        WHERE EnquiryID = @entityid      
                              AND NULLIF(MobileNo2, '') IS NOT NULL      
                    ) A      
                    --WHERE ISNULL(mobile, '') <> ''      
                    --      AND NOT EXISTS      
                    --(      
                    --    SELECT 1      
                    --    FROM MySMSConversations.dbo.convusers      
                    --    WHERE channelid = 2      
                    --          AND channelprofileid = replace(replace(a.mobile, '+', ''), '-', '')      
                    --          AND convuserparentid = @parentid and isactive = 1      
                    --);      
            END;      
		ELSE      
            IF @entity = 'team'      
                BEGIN      
                    SELECT @parentid = parentid FROM User_Detail(NOLOCK) WHERE User_ID = @entityid;      
                          
     SELECT Mobile      
                    FROM      
      (      
                        SELECT ISNULL(trim(CAST(countrycode AS NVARCHAR)) + '-' + CAST(str(Mobile) AS NVARCHAR(10)), '') AS Mobile      
             FROM user_detail(NOLOCK)      
                        WHERE User_ID = @entityid AND NULLIF(Mobile, '') IS NOT NULL      
                        UNION      
                SELECT ISNULL(CAST(wa_country_code AS NVARCHAR) + '-' + CAST(wa_mobile_no AS NVARCHAR), '') AS Mobile      
                        FROM user_detail(NOLOCK)      
                        WHERE User_ID = @entityid      
                              AND NULLIF(wa_mobile_no, '') IS NOT NULL      
                    ) A      
                    WHERE ISNULL(mobile, '') <> ''      
                    --      AND NOT EXISTS      
                    --(      
                    --    SELECT 1      
                    --    FROM MySMSConversations.dbo.convusers      
                    --    WHERE channelid = 2      
                    --          AND channelprofileid = replace(replace(a.mobile, '+', ''), '-', '')      
                    --          AND convuserparentid = @parentid and isactive = 1      
                    --);      
            END;      
    END; 


