/* ============================================================
   Procedure: [dbo].[usp_GetMobileNoByParentIdAndUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-------------------------------------------

CREATE   PROCEDURE [dbo].[usp_GetMobileNoByParentIdAndUserId]
    @ParentId BIGINT
AS
BEGIN
    BEGIN TRY
        -- Declare variables to store the fetched MobileNo and CountryCode
        DECLARE @MobileNo NVARCHAR(50), 
                @CountryCode NVARCHAR(50), 
                @Result NVARCHAR(100);

        -- Fetch the MobileNo and CountryCode from user_detail table
        SELECT 
            @MobileNo = LTRIM(RTRIM(STR(Mobile, 20, 0))),
            @CountryCode = LTRIM(RTRIM(CountryCode))
        FROM user_detail
        WHERE parentid = @ParentId AND user_id = @ParentId;

        -- Remove any leading/trailing spaces and signs from CountryCode
        IF @CountryCode IS NOT NULL
        BEGIN
            SET @CountryCode = REPLACE(REPLACE(@CountryCode, '+', ''), '-', '');  -- Remove '+' and '-' signs
        END

        -- Check if MobileNo or CountryCode is found
        IF @MobileNo IS NOT NULL AND @CountryCode IS NOT NULL
        BEGIN
            -- Concatenate MobileNo and CountryCode, remove spaces
            SET @Result = REPLACE(@CountryCode + @MobileNo, ' ', '');

            SELECT @Result AS MobileNoWithCountryCode;  -- Return the concatenated result
        END
        ELSE
        BEGIN
            -- Return a message if no records are found
            SELECT 'No matching records found' AS Message;
        END
    END TRY
    BEGIN CATCH
        -- Error handling
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrorState INT = ERROR_STATE();

        -- Log the error or return the error details
        SELECT 
            @ErrorMessage AS ErrorMessage, 
            @ErrorSeverity AS ErrorSeverity, 
            @ErrorState AS ErrorState;

        EXEC usp_InsertErrorInfo;
    END CATCH
END;




GO

/* ============================================================
   Procedure: [dbo].[usp_GetMobileNumberUnsubscribed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[usp_GetMobileNumberUnsubscribed]
	@SearchID BIGINT,
	@SearchText VARCHAR(50) = NULL,
	@PageSize INT = 0
AS
BEGIN
	BEGIN TRY
		SELECT DISTINCT fgun.mobileno
		FROM   SearchDetails AS sd
		       OUTER APPLY funcGetUnsubscribeNumbersCRM(sd.FromDate, sd.ToDate) AS 
		fgun
		WHERE  sd.ID = @SearchID
		       AND ISNULL(fgun.mobileno, '') <> ''
		       AND ISNULL(fgun.mobileno, '') LIKE '%' + @SearchText + '%'
		ORDER BY
		       fgun.mobileno
	END TRY
	BEGIN CATCH
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetModuleCode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_GetModuleCode]
    @UserID BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- Fetch module
        SELECT ModuleName, ModuleCode
        FROM TBL_UA_ModuleMaster (NOLOCK)
        WHERE Active = 1 
          AND Type = 'Page'
          AND ModuleName IN ('Leads', 'Enquiries');
    END TRY
    BEGIN CATCH
        -- Handle the error
        DECLARE @ErrorMessage NVARCHAR(4000);
        DECLARE @ErrorSeverity INT;
        DECLARE @ErrorState INT;

        -- Retrieve error information
        SELECT 
            @ErrorMessage = ERROR_MESSAGE(),
            @ErrorSeverity = ERROR_SEVERITY(),
            @ErrorState = ERROR_STATE();

        -- Log the error (you can adjust this to log to a table or another logging mechanism)
        INSERT INTO ErrorLog (ErrorMessage, ErrorSeverity, ErrorState, ErrorDate)
        VALUES (@ErrorMessage, @ErrorSeverity, @ErrorState, GETDATE());

        -- Optionally, re-throw the error to the calling application
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);
    END CATCH
END;





GO

