CREATE   PROCEDURE [dbo].[usp_getNextScheduleDate] --3852--1913--632  
    
(@CampaignID BIGINT)    
AS    
BEGIN    
  
 CREATE TABLE #TempMonths    
 (    
  SceduleName     VARCHAR(250),    
  MonthlyNo       BIGINT    
 )    
     
 CREATE TABLE #tempMonthDay    
 (    
  SceduleName     VARCHAR(250),    
  MonthNo         BIGINT,    
  MonthDay        BIGINT,  
  Dates datetime      
 )    
     
 CREATE TABLE #tempWeekly    
 (    
  SceduleName     VARCHAR(250),    
  WeekNo          BIGINT,  
  WeeklyHours varchar(20),  
  WeeklyMins varchar(20),  
  Date datetime    
 )     
     
 DECLARE @NextStatusDate DATETIME 
 declare @time nvarchar(10)   
     
 DECLARE @RunAt                    BIT,    
         @IsSchedule               INT,    
         @ScheduleID               BIGINT,    
         @IsOnce                   INT,    
         @IsDaily                  INT,    
         @isWeekly                 INT,    
         @IsMonthly                INT,    
         @OnceHours                INT,    
         @OnceMins                 INT,    
         @DailyHours               INT,    
         @DailyMins                INT,    
         @WeeklyDayNo              VARCHAR(500),    
         @WeeklyHours              INT,    
         @WeeklyMins               INT,    
         @MonthlyMonthNo           VARCHAR(500),    
         @MonthlyDayNo             VARCHAR(500),    
         @MonthlyHours             INT,    
         @MonthlyMins              INT,    
         @LastExecutedDateTime     VARCHAR(50) ,
		 @createdby bigint   
     
 SELECT @RunAt = ucm.IsRunAfter,    
        @IsSchedule     = ucm.IsSchedule,    
        @ScheduleID     = ucm.ScheduleID,
		@createdby=ucm.Createdby    
 FROM   UserCampaignMaster AS ucm    
 WHERE  ucm.ID = @CampaignID    
     
 IF @IsSchedule = 1    
 BEGIN    
     SELECT @IsOnce = us.IsOnce,    
            @IsDaily            = us.IsDaily,    
            @isWeekly           = us.IsWeekly,    
            @IsMonthly          = us.IsMonthly,    
            @OnceHours          = us.OnceHours,    
            @OnceMins           = us.OnceMins,    
            @DailyHours         = us.DailyHours,    
            @DailyMins          = us.DailyMins,    
            @WeeklyDayNo        = us.WeeklyDayNo,    
            @WeeklyHours        = us.WeeklyHours,    
            @WeeklyMins         = us.WeeklyMins,    
            @MonthlyMonthNo     = us.MonthNo,    
            @MonthlyDayNo       = us.MonthlyDayNo,    
            @MonthlyHours       = us.MonthlyHours,    
            @MonthlyMins        = us.MonthlyMins    
     FROM   UserSchedules AS us    
     WHERE  us.ID = @ScheduleID    
     SELECT TOP 1 @LastExecutedDateTime = uceh.ExecutionTime    
     FROM   UserCampaignExecutionHistory AS uceh    
     WHERE  uceh.CampaignID = @CampaignID and uceh.IsExecuted=1   
     ORDER BY    
            uceh.ExecutionTime DESC    
     IF ISNULL(@LastExecutedDateTime, '') = ''    
     BEGIN    
         SET @LastExecutedDateTime = CONVERT(VARCHAR(20), GETDATE(), 105)    
     END    
     --ELSE     
     IF ISNULL(@isWeekly, 0) = 1    
     BEGIN    
         --SELECT 1    
           
          set @time =  
          (select top 1 cast(weeklyhours as varchar) +':' + CAST(weeklymins as varchar) FROM   UserSchedules  AS us    
         WHERE  us.ID = @ScheduleID)  
         INSERT INTO #tempWeekly    
           (    
             SceduleName,    
             WeekNo,  
             WeeklyHours,  
             WeeklyMins,  
             Date    
           )    
         SELECT us.SceduleName,    
                fs.[value]     AS WeekNo ,  
                WeeklyHours,  
                WeeklyMins ,  
                case when datepart(dw,getdate())=fs.value and DATEADD(DAY, (DATEDIFF(DAY, ((fs.value + 5) % 7), GETDATE()) / 7) * 7 , ((fs.value + 5) % 7)) + @time>GETDATE() then DATEADD(DAY, (DATEDIFF(DAY, ((fs.value + 5) % 7), GETDATE()) / 7) * 7 , ((fs
.value + 5) % 7)) + @time else DATEADD(DAY, (DATEDIFF(DAY, ((fs.value + 5) % 7), GETDATE()) / 7) * 7 + 7, ((fs.value + 5) % 7)) + @time end  
         FROM   UserSchedules  AS us    
OUTER APPLY dbo.fn_Split(us.WeeklyDayNo, '#') AS fs    
         WHERE  us.ID = @ScheduleID  
         set @NextStatusDate=(select MIN(date) from #tempWeekly where DATE>GETDATE())  
         /*set @time=(select top 1 cast(weeklyhours as varchar) +':' + CAST(weeklymins as varchar) from #tempWeekly)    
           
        SELECT case when datepart(dw,getdate())=5 and DATEADD(DAY, (DATEDIFF(DAY, ((5 + 5) % 7), GETDATE()) / 7) * 7 , ((5 + 5) % 7)) + '14:00'>GETDATE() then DATEADD(DAY, (DATEDIFF(DAY, ((5 + 5) % 7), GETDATE()) / 7) * 7 , ((5 + 5) % 7)) else DATEADD(DAY
, (DATEDIFF(DAY, ((5 + 5) % 7), GETDATE()) / 7) * 7 + 7, ((5 + 5) % 7)) end AS NextDay  
        SELECT DATEADD(d, 1 - DATEPART(dw, getdate()), getdate())  
         select DATEADD(DAY,(13 - (@@DATEFIRST + DATEPART(WEEKDAY,getdate())))%7,GETDATE())*/  
         /*select @time  
         select max(weekno),  
         DATEADD(d,max(weekno)-datepart(dw,GETDATE()),datediff(day, 0, getdate())) + @time,  
         DATEADD(d,max(weekno)-datepart(dw,getdate()),getdate())-getdate(),  
         MIN(weekno),  
         dateadd(d,(7-DATEPART(dw,getdate()) + min(weekno)),datediff(day, 0, getdate())) + @time from #tempWeekly*/  
         /*set @NextStatusDate=(select case when DATEADD(d,max(weekno)-datepart(dw,GETDATE()),datediff(day, 0, getdate())) + @time>getdate() then DATEADD(d,max(weekno)-datepart(dw,GETDATE()),datediff(day, 0, getdate())) + @time else dateadd(d,(7-DATEPART(
dw,getdate()) + min(weekno)),datediff(day, 0, getdate())) + @time end from #tempWeekly)*/  
           
           
     END    
     IF @IsOnce = 1    
     BEGIN  
	 set @time=cast(@oncehours as varchar) +':' + CAST(@oncemins as varchar)  
     SElecT @NextStatusDate = case when dbo.fn_getusertimefromIndiantime(@createdby,getdate())<dateadd(d,0,(datediff(day, 0, dbo.fn_getusertimefromIndiantime(@createdby,getdate()))))+@time
	 then dateadd(d,0,(datediff(day, 0, dbo.fn_getusertimefromIndiantime(@createdby,getdate()))))+@time else dateadd(d,1,(datediff(day, 0, dbo.fn_getusertimefromIndiantime(@createdby,getdate()))))+@time end from 
	 usercampaignmaster where ID=@CampaignID  
     END    
     ELSE   
     IF @IsDaily = 1    
     BEGIN   
     set @time=cast(@dailyhours as varchar) +':' + CAST(@dailymins as varchar) 
               
     declare @nxt datetime=case when dateadd(d, datediff(d,0, GETDATE()), 0)+@time>getdate() then  dateadd(d, datediff(d,0, GETDATE()), 0)+@time else dateadd(d,1,dateadd(d, datediff(d,0, GETDATE()), 0)+@time) end  
     set @NextStatusDate=@nxt
     END    
     ELSE   
     IF @IsMonthly = 1    
     BEGIN    
         INSERT INTO #TempMonths    
           (    
             SceduleName,    
             MonthlyNo    
           )    
         SELECT us.SceduleName,    
                fs.[value]     AS MonthlyNo    
         FROM   UserSchedules  AS us    
                OUTER APPLY dbo.fn_Split(us.MonthNo, '#') AS fs    
         WHERE  us.ID = @ScheduleID   
   
 set @time =cast(@monthlyhours as varchar) +':' + CAST(@monthlymins as varchar)  
         INSERT INTO #tempMonthDay    
           (    
             SceduleName,    
             MonthNo,    
             MonthDay,  
             dates    
           )    
    SELECT us.SceduleName,    
                fs2.[value],    
                fs.[value],CONVERT(datetime,cast(fs2.[value] as varchar(2))+'-'+ cast(fs.[value] as varchar(2))+'-'+CAST(datepart(yy,getdate()) as varchar(4)),102)+@time    
         FROM   UserSchedules AS us    
                OUTER APPLY dbo.fn_Split(us.MonthlyDayNo, '#') AS fs    
         OUTER APPLY dbo.fn_Split(us.MonthNo, '#') AS fs2    
         WHERE  us.ID = @ScheduleID  
           
set @NextStatusDate= case when exists(select 1 from #tempMonthDay where DATEDIFF(ss,GETDATE(),dates)>1) then (select top 1 dates from #tempMonthDay where DATEDIFF(ss,GETDATE(),dates)>1 order by DATEDIFF(ss,GETDATE(),dates)) else (select MIN(dateadd(yy,1,dates)) from #tempMonthDay) end           
                      
 END    
 END    
     
    DROP TABLE #tempMonthDay    
    DROP TABLE #TempMonths    
    DROP TABLE #tempWeekly    
     
 SELECT @CampaignID      AS CampaignID,    
        @NextStatusDate  AS NextExecutionDate    
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_getNextScheduleDateOLDOriginal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
    
CREATE   PROCEDURE [dbo].[usp_getNextScheduleDateOLDOriginal] -- 1709   
    
(@CampaignID BIGINT)    
AS    
BEGIN    
 CREATE TABLE #TempMonths    
 (    
  SceduleName     VARCHAR(250),    
  MonthlyNo       BIGINT    
 )    
     
     
     
     
     
     
     
 CREATE TABLE #tempMonthDay    
 (    
  SceduleName     VARCHAR(250),    
  MonthNo         BIGINT,    
  MonthDay        BIGINT    
 )    
     
     
     
     
     
     
     
     
     
     
     
 CREATE TABLE #tempWeekly    
 (    
  SceduleName     VARCHAR(250),    
  WeekNo          BIGINT    
 )     
     
     
     
     
     
     
     
 DECLARE @NextStatusDate DATETIME    
     
     
     
     
     
     
     
 DECLARE @RunAt                    BIT,    
         @IsSchedule               INT,    
         @ScheduleID               BIGINT,    
         @IsOnce                   INT,    
         @IsDaily                  INT,    
         @isWeekly                 INT,    
         @IsMonthly                INT,    
         @OnceHours                INT,    
         @OnceMins                 INT,    
         @DailyHours               INT,    
         @DailyMins                INT,    
         @WeeklyDayNo              VARCHAR(500),    
         @WeeklyHours              INT,    
         @WeeklyMins               INT,    
         @MonthlyMonthNo           VARCHAR(500),    
         @MonthlyDayNo             VARCHAR(500),    
         @MonthlyHours             INT,    
         @MonthlyMins              INT,    
         @LastExecutedDateTime     VARCHAR(50)    
     
     
     
     
     
     
     
     
     
     
     
     
     
     
     
 SELECT @RunAt = ucm.IsRunAfter,    
        @IsSchedule     = ucm.IsSchedule,    
        @ScheduleID     = ucm.ScheduleID    
 FROM   UserCampaignMaster AS ucm    
 WHERE  ucm.ID = @CampaignID    
     
     
     
     
     
     
     
     
     
     
     
     
     
     
     
 IF @IsSchedule = 1    
 BEGIN    
     SELECT @IsOnce = us.IsOnce,    
            @IsDaily            = us.IsDaily,    
            @isWeekly           = us.IsWeekly,    
            @IsMonthly          = us.IsMonthly,    
            @OnceHours          = us.OnceHours,    
            @OnceMins           = us.OnceMins,    
            @DailyHours         = us.DailyHours,    
            @DailyMins          = us.DailyMins,    
            @WeeklyDayNo        = us.WeeklyDayNo,    
            @WeeklyHours        = us.WeeklyHours,    
            @WeeklyMins         = us.WeeklyMins,    
            @MonthlyMonthNo     = us.MonthNo,    
            @MonthlyDayNo       = us.MonthlyDayNo,    
            @MonthlyHours       = us.MonthlyHours,    
            @MonthlyMins        = us.MonthlyMins    
     FROM   UserSchedules AS us    
     WHERE  us.ID = @ScheduleID    
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
     SELECT TOP 1 @LastExecutedDateTime = uceh.ExecutionTime    
     FROM   UserCampaignExecutionHistory AS uceh    
     WHERE  uceh.CampaignID = @CampaignID    
     ORDER BY    
            uceh.ExecutionTime DESC    
         
         
         
         
         
         
         
         
         
         
         
         
         
         
         
     IF ISNULL(@LastExecutedDateTime, '') = ''    
     BEGIN    
         SET @LastExecutedDateTime = CONVERT(VARCHAR(20), GETDATE(), 105)    
     END    
     --ELSE     
         
         
         
         
         
         
         
     IF ISNULL(@isWeekly, 0) = 1    
     BEGIN    
         --SELECT 1    
             
         INSERT INTO #tempWeekly    
           (    
             SceduleName,    
             WeekNo    
           )    
         SELECT us.SceduleName,    
                fs.[value]     AS WeekNo    
         FROM   UserSchedules  AS us    
                OUTER APPLY dbo.fn_Split(us.WeeklyDayNo, '#') AS fs    
         WHERE  us.ID = @ScheduleID    
             
             
             
             
             
             
             
             
             
             
             
             
             
             
             
         IF EXISTS (    
                SELECT *    
                FROM   #tempWeekly AS ttt    
                WHERE  DATEPART(dw, GETDATE()) = ttt.WeekNo    
            )    
         BEGIN    
     SET @NextStatusDate = (    
                     CONVERT(    
                         DATETIME,    
                         CONVERT(    
                             VARCHAR(20),    
                             CAST(DATEPART(m, DATEADD(DAY, 1, GETDATE())) AS VARCHAR(20))    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             + '-'    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             +    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             CAST(DATEPART(d, DATEADD(DAY, 1, GETDATE())) AS VARCHAR(20))    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             + '-'    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             +    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             CAST(DATEPART(yy, DATEADD(DAY, 1, GETDATE())) AS VARCHAR(20))    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             + ' '    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             +    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             CAST(@WeeklyHours AS VARCHAR(10))    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             +    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             ':'    
                                 
                                 
                                 
                                 
                                 
                    
                                 
                             +    
                                 
                                 
                                 
                                 
                                 
                                 
                                 
                             CAST(@WeeklyMins AS VARCHAR(10)),    
                             112    
                         )    
                     )    
                 )    
         END    
         ELSE    
         BEGIN    
             IF EXISTS(    
                    SELECT DATEADD(DAY, ttt.WeekNo - DATEPART(dw, GETDATE()), GETDATE())    
                    FROM   #tempWeekly AS ttt    
                    WHERE  ttt.WeekNo > DATEPART(dw, GETDATE())    
                )    
             BEGIN    
                 SELECT TOP 1 @NextStatusDate = CONVERT(    
                            DATETIME,    
                            CONVERT(    
                                VARCHAR(20),    
                                DATEADD(DAY, ttt.WeekNo -DATEPART(dw, GETDATE()), GETDATE()),    
                                105    
                            )    
                                
                                
                                
                                
                                
                                
                                
                            + ' ' + CAST(@WeeklyHours AS VARCHAR(10)) +    
                                
                                
                                
                                
                                
                                
                                
                            ':'    
                                
                                
                                
                                
                                
                                
                                
                            + CAST(@WeeklyMins AS VARCHAR(10)) + ':00'    
                        )    
                 FROM   #tempWeekly AS ttt    
                 WHERE  ttt.WeekNo > DATEPART(dw, GETDATE())    
                 ORDER BY    
                        ttt.WeekNo    
             END    
             ELSE    
             BEGIN    
                 SELECT TOP 1 @NextStatusDate = CONVERT(    
                            DATETIME,    
                            CONVERT(    
                                VARCHAR(20),    
                                DATEADD(DAY, ttt.WeekNo + 7 -DATEPART(dw, GETDATE()), GETDATE()),    
                                105    
                            )    
                                
                                
                                
                                
                                
                                
                                
                            + ' ' + CAST(@WeeklyHours AS VARCHAR(10)) +    
                                
                                
                                
                                
                                
                                
                                
                            ':'    
                                
                                
                                
                                
                                
                                
                                
                            + CAST(@WeeklyMins AS VARCHAR(10)) + ':00'    
                        )    
                 FROM   #tempWeekly AS ttt    
                 ORDER BY    
                        ttt.WeekNo    
             END    
         END    
     END    
         
         
         
         
         
         
         
         
         
     IF @IsOnce = 1    
     BEGIN    
          SET @NextStatusDate = DATEADD(minute, 1, CONVERT(VARCHAR(20), @LastExecutedDateTime, 112))    
     END    
     ELSE     
         
         
         
  
         
         
         
     IF @IsDaily = 1    
     BEGIN    
     declare @nxt datetime=dateadd(MINUTE,@dailymins,dateadd(HOUR,@DailyHours,dateadd(day, datediff(day, 0, @LastExecutedDateTime), 0)))   
     --select @nxt  
     declare @validdate int=case when @nxt>getdate() then 0 else ceiling(datediff(d,@nxt,getdate())) end    
     select @NextStatusDate = DATEADD(d,@validdate,@nxt)  
       
     --SET @NextStatusDate = DATEADD(DAY, 1, CONVERT(VARCHAR(20), @LastExecutedDateTime, 112))    
     END    
     ELSE     
         
         
         
         
         
         
         
     IF @IsMonthly = 1    
     BEGIN    
         INSERT INTO #TempMonths    
           (    
             SceduleName,    
             MonthlyNo    
           )    
         SELECT us.SceduleName,    
                fs.[value]     AS MonthlyNo    
         FROM   UserSchedules  AS us    
                OUTER APPLY dbo.fn_Split(us.MonthNo, '#') AS fs    
         WHERE  us.ID = @ScheduleID    
             
             
             
             
             
             
             
             
             
             
             
             
             
             
             
         INSERT INTO #tempMonthDay    
           (    
             SceduleName,    
             MonthNo,    
             MonthDay    
           )    
    SELECT us.SceduleName,    
                fs.[value],    
                fs.[value]    
         FROM   UserSchedules AS us    
                OUTER APPLY dbo.fn_Split(us.MonthlyDayNo, '#') AS fs    
             
             
             
             
             
             
             
         OUTER APPLY dbo.fn_Split(us.MonthNo, '#') AS fs2    
         WHERE  us.ID = @ScheduleID    
             
             
             
             
             
             
             
             
             
             
             
             
             
             
             
         IF EXISTS (    
                SELECT 'x'    
                FROM   #TempMonths t    
                WHERE  DATEPART(m, GETDATE()) = t.MonthlyNo    
            )    
         BEGIN    
             IF EXISTS (    
                    SELECT 'x'    
                    FROM   #tempMonthDay t    
                    WHERE  DATEPART(DAY, GETDATE()) = t.MonthDay    
                )    
             BEGIN    
                 SET @NextStatusDate = (    
                         CONVERT(    
                             DATETIME,    
                             CONVERT(    
                                 VARCHAR(20),    
                                 CAST(DATEPART(m, GETDATE()) AS VARCHAR(20))    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 + '-'    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 +    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 CAST(DATEPART(d, DATEADD(DAY, 1, GETDATE())) AS VARCHAR(20))    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 + '-'    
                                     
                                     
                                     
                 
                                     
                                     
                                     
                                 +    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 CAST(DATEPART(yy, GETDATE()) AS VARCHAR(20))    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 + ' '    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 +    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 CAST(@MonthlyHours AS VARCHAR(10))    
                                     
                                     
                                     
                
                                     
                                     
                                     
                                 + ':'    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 +    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 CAST(@MonthlyMins AS VARCHAR(10)),    
                                 112    
                             )    
                         )    
                     )    
             END    
             ELSE    
             BEGIN    
                 IF EXISTS (    
                        SELECT 'x'    
                        FROM   #tempMonthDay t    
                        WHERE  t.MonthDay > DATEPART(DAY, GETDATE())    
                    )    
                 BEGIN    
                     SELECT TOP 1 @NextStatusDate = CONVERT(    
                                DATETIME,    
                                CONVERT(    
                                    VARCHAR(20),    
                                    DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE()),    
                                    112    
                                )    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ' ' + CAST(@MonthlyHours AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ':' + CAST(@MonthlyMins AS VARCHAR(10))    
                                    
                                    
                                    
                                    
   
                                    
                                    
                                + ':00'    
                            )    
                     FROM   #tempMonthDay AS t    
                            INNER JOIN #TempMonths tt    
                                 ON  t.MonthNo = tt.MonthlyNo    
                     WHERE  t.MonthDay > DATEPART(DAY, GETDATE())    
                     ORDER BY    
                            tt.MonthlyNo,    
                            t.MonthDay    
                 END    
                 ELSE    
                 BEGIN    
                     SELECT TOP 1 @NextStatusDate = CONVERT(    
                                DATETIME,    
                                CONVERT(    
                                    VARCHAR(20),    
                                    DATEADD(    
                                        MONTH,    
                                        1,    
                                        DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())    
                                    ),    
                                    112    
                                )    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ' ' + CAST(@MonthlyHours AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                            + ':' + CAST(@MonthlyMins AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ':00'    
                            )    
                     FROM   #tempMonthDay AS t    
                            INNER JOIN #TempMonths tt    
                                 ON  t.MonthNo = tt.MonthlyNo    
                     ORDER BY    
                            tt.MonthlyNo,    
                            t.MonthDay    
                 END    
             END    
         END    
         ELSE    
         BEGIN    
             IF EXISTS (    
                    SELECT 'x'    
                    FROM   #tempMonthDay t    
                    WHERE  DATEPART(DAY, GETDATE()) = t.MonthDay    
                )    
             BEGIN    
                 SELECT TOP 1 @NextStatusDate = CONVERT(    
                            DATETIME,    
                            CONVERT(    
                                VARCHAR(20),    
                                DATEADD(    
                                    MONTH,    
                                    tt.MonthlyNo    
                                        
                                        
                                        
                                        
                                        
                                        
                                        
                                    -DATEPART(m, GETDATE()),    
                                    DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())    
                                ),    
                                112    
                            )    
                                
                                
                                
                                
                                
                                
                                
                            + ' ' + CAST(@MonthlyHours AS VARCHAR(10))    
                                
                                
                                
                                
                                
                                
                                
                            + ':' + CAST(@MonthlyMins AS VARCHAR(10))    
                                
                                
                                
                                
                                
                                
                                
                            + ':00'    
                        )    
                 FROM   #tempMonthDay AS t    
                        INNER JOIN #TempMonths tt    
                             ON  tt.MonthlyNo >    
                                     
                                     
                                     
                                     
                                     
                                     
                                     
                                 DATEPART(m, GETDATE())    
                 WHERE  DATEPART(DAY, GETDATE()) = t.MonthDay    
                 ORDER BY    
                        tt.MonthlyNo,    
                        t.MonthDay    
             END    
             ELSE    
             BEGIN    
                 IF EXISTS (    
                        SELECT 'x'    
                        FROM   #tempMonthDay t    
                        WHERE  t.MonthDay > DATEPART(DAY, GETDATE())    
                    )    
                 BEGIN    
                     SELECT TOP 1 @NextStatusDate = CONVERT(    
                                DATETIME,    
                                CONVERT(    
                                    VARCHAR(20),    
                                    DATEADD(    
                                        MONTH,    
                                        tt.MonthlyNo    
                                            
                                            
          
                                            
                                            
                                            
                                            
                                        -DATEPART(m, GETDATE()),    
                                        DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())    
                                    ),    
                                    112    
                                )    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ' ' + CAST(@MonthlyHours AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ':' + CAST(@MonthlyMins AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ':00'    
                            )    
                     FROM   #tempMonthDay AS t    
                            INNER JOIN #TempMonths tt    
                                 ON  tt.MonthlyNo >    
                                         
                                         
                                         
                                         
                                         
                                         
                                         
                                     DATEPART(m, GETDATE())    
                     WHERE  t.MonthDay > DATEPART(DAY, GETDATE())    
                     ORDER BY                                tt.MonthlyNo,    
                            t.MonthDay    
                 END    
                 ELSE    
                 BEGIN    
                     SELECT TOP 1 @NextStatusDate = CONVERT(    
                                DATETIME,    
                                CONVERT(    
                                    VARCHAR(20),    
                                    DATEADD(    
                                        MONTH,    
                                        tt.MonthlyNo    
                                            
                                            
                                            
                                            
                                            
                                            
                                            
                                        -DATEPART(m, GETDATE()),    
                                        DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())    
                                    ),    
                                    112    
                                )    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ' ' + CAST(@MonthlyHours AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ':' + CAST(@MonthlyMins AS VARCHAR(10))    
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                + ':00'    
                            )    
                    FROM   #tempMonthDay AS t    
                            INNER JOIN #TempMonths tt    
                                 ON  tt.MonthlyNo >    
                                         
                                         
                                         
                                         
                                         
                                         
                                         
                                     DATEPART(m, GETDATE())    
                     ORDER BY    
                            tt.MonthlyNo,    
                            t.MonthDay    
                 END    
             END    
         END    
     END    
