/* ============================================================
   Procedure: [dbo].[usp_getNextScheduleDateSchedules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_getNextScheduleDateSchedules] --10  
@ScheduleID BIGINT  
AS  
BEGIN  
 DECLARE @NextStatusDate DATETIME   
   
 DECLARE @RunAt                    BIT,  
         @IsSchedule               BIT,   
         @IsOnce                   BIT,  
         @IsDaily                  BIT,  
         @isWeekly                 BIT,  
         @IsMonthly                BIT,  
         @OnceHours                TINYINT,  
         @OnceMins                 TINYINT,  
         @DailyHours               TINYINT,  
         @DailyMins                TINYINT,  
         @WeeklyDayNo              VARCHAR(500),  
         @WeeklyHours              TINYINT,  
         @WeeklyMins               TINYINT,  
         @MonthlyMonthNo           VARCHAR(500),  
         @MonthlyDayNo             VARCHAR(500),  
         @MonthlyHours             TINYINT,  
         @MonthlyMins              TINYINT   
   
    
    
     SELECT @IsOnce = us.IsOnce,  
            @IsDaily            = us.IsDaily,  
            @isWeekly           = us.IsWeekly,  
            @IsMonthly          = us.IsMonthly,  
            @OnceHours          = us.OnceHours,  
            @OnceMins           = us.OnceMins,  
            @DailyHours         = us.DailyHours,  
            @DailyMins          = us.DailyMins,  
            @WeeklyDayNo        = us.WeeklyDayNo,  
            @WeeklyHours        = us.WeeklyHours,  
            @WeeklyMins         = us.WeeklyMins,  
            @MonthlyMonthNo     = us.MonthNo,  
            @MonthlyDayNo       = us.MonthlyDayNo,  
            @MonthlyHours       = us.MonthlyHours,  
            @MonthlyMins        = us.MonthlyMins  
     FROM   UserSchedules AS us  
     WHERE  us.ID = @ScheduleID  
       
        
        
       
     IF @IsOnce = 1  
     BEGIN  
         SET @NextStatusDate = NULL  
     END  
     ELSE   
       
     IF @IsDaily = 1  
     BEGIN  
         SET @NextStatusDate = (  
                 CONVERT(  
                     DATETIME,  
                     CONVERT(VARCHAR(20), GETDATE(), 112) + ' ' +  
                       
                     CAST(@DailyHours AS VARCHAR(10))   
                       
                     +  
                       
                     ':' + CAST(@DailyMins AS VARCHAR(10))  
                 )  
             )  
     END  
     ELSE   
       
     IF @isWeekly = 1  
     BEGIN  
         WITH T(SceduleName, WeeklyNo) --Column names for Temporary table  
                
              AS  
                
              (  
                  SELECT us.SceduleName,  
                         fs.[value]  
                  FROM   UserSchedules AS us  
                         OUTER APPLY dbo.fn_Split(us.WeeklyDayNo, '#') AS fs  
                  WHERE  us.ID = @ScheduleID  
              )  
           
           
           
         SELECT t.SceduleName,  
                t.WeeklyNo INTO     #temptable  
         FROM   T                AS t  
           
           
           
         IF EXISTS (  
                SELECT *  
                FROM   #temptable AS ttt  
                WHERE  DATEPART(dw, GETDATE()) = ttt.WeeklyNo  
            )  
         BEGIN  
             SET @NextStatusDate = (  
                     CONVERT(  
                         DATETIME,  
                         CONVERT(  
                             VARCHAR(20),  
                             CAST(DATEPART(m, GETDATE()) AS VARCHAR(20)) +  
                               
                             '-' + CAST(DATEPART(d, GETDATE()) AS VARCHAR(20))  
                               
                             + '-' + CAST(DATEPART(yy, GETDATE()) AS VARCHAR(20))   
                               
                             + ' ' + CAST(@WeeklyHours AS VARCHAR(10))  
                               
                             +  
                               
                             ':' + CAST(@WeeklyMins AS VARCHAR(10)),  
                             112  
                         )  
                     )  
                 )  
         END  
         ELSE  
    BEGIN  
             IF EXISTS(  
                    SELECT DATEADD(DAY, ttt.WeeklyNo -DATEPART(dw, GETDATE()), GETDATE())  
                    FROM   #temptable AS ttt  
                    WHERE  ttt.WeeklyNo > DATEPART(dw, GETDATE())  
                )  
             BEGIN  
                 SELECT TOP 1 @NextStatusDate = CONVERT(  
                            DATETIME,  
                            CONVERT(  
                                VARCHAR(20),  
                                DATEADD(DAY, ttt.WeeklyNo -DATEPART(dw, GETDATE()), GETDATE()),  
                                105  
                            ) + ' ' + CAST(@WeeklyHours AS VARCHAR(10)) + ':'   
                              
                            +  
                              
                            CAST(@WeeklyMins AS VARCHAR(10)) + ':00'  
                        )  
                 FROM   #temptable AS ttt  
                 WHERE  ttt.WeeklyNo > DATEPART(dw, GETDATE())  
                 ORDER BY  
                        ttt.WeeklyNo  
             END  
             ELSE  
             BEGIN  
                 SELECT TOP 1 @NextStatusDate = CONVERT(  
                            DATETIME,  
                            CONVERT(  
                                VARCHAR(20),  
                                DATEADD(DAY, ttt.WeeklyNo + 7 -DATEPART(dw, GETDATE()), GETDATE()),  
                                105  
                            ) + ' ' + CAST(@WeeklyHours AS VARCHAR(10)) + ':'   
                              
                            +  
                              
                            CAST(@WeeklyMins AS VARCHAR(10)) + ':00'  
                        )  
                 FROM   #temptable AS ttt  
                 ORDER BY  
                        ttt.WeeklyNo  
             END  
         END   
           
           
           
         DROP TABLE #temptable  
     END  
     ELSE   
       
     IF @IsMonthly = 1  
     BEGIN  
         WITH T(SceduleName, MonthlyNo) --Column names for Temporary table  
                
              AS  
                
              (  
                  SELECT us.SceduleName,  
                         fs.[value]  
                  FROM   UserSchedules AS us  
                         OUTER APPLY dbo.fn_Split(us.MonthNo, '#') AS fs  
                  WHERE  us.ID = @ScheduleID  
              )  
           
           
           
         SELECT * INTO     #TempMonths  
         FROM   T       AS t  
           
         ;  
           
         WITH TMonthDays(SceduleName, MonthNo, MonthDay) --Column names for Temporary table  
                
              AS  
                
              (  
                  SELECT us.SceduleName,  
                         fs.[value],  
                         fs.[value]  
                  FROM   UserSchedules AS us  
                         OUTER APPLY dbo.fn_Split(us.MonthlyDayNo, '#') AS fs  
                    
                  OUTER APPLY dbo.fn_Split(us.MonthNo, '#') AS fs2  
                  WHERE  us.ID = @ScheduleID  
              )  
           
           
           
         SELECT * INTO         #tempMonthDay  
         FROM   TMonthDays  AS t  
           
           
           
         IF EXISTS (  
                SELECT 'x'  
                FROM   #TempMonths t  
                WHERE  DATEPART(m, GETDATE()) = t.MonthlyNo  
            )  
         BEGIN  
             IF EXISTS (  
                    SELECT 'x'  
                    FROM   #tempMonthDay t  
                    WHERE  DATEPART(DAY, GETDATE()) = t.MonthDay  
                )  
             BEGIN  
                 SET @NextStatusDate = (  
                         CONVERT(  
                             DATETIME,  
                             CONVERT(  
                                 VARCHAR(20),  
                                 CAST(DATEPART(m, GETDATE()) AS VARCHAR(20))   
                                   
                                 +  
                                   
                                 '-' + CAST(DATEPART(d, GETDATE()) AS VARCHAR(20))  
                                   
                                 + '-' + CAST(DATEPART(yy, GETDATE()) AS VARCHAR(20))   
                                   
                                 + ' ' + CAST(@MonthlyHours AS VARCHAR(10))  
                                   
                                 +  
                                   
                                 ':' + CAST(@MonthlyMins AS VARCHAR(10)),  
                                 112  
                             )  
                         )  
                     )  
             END  
             ELSE  
             BEGIN  
                 IF EXISTS (  
                        SELECT 'x'  
                        FROM   #tempMonthDay t  
                        WHERE  t.MonthDay > DATEPART(DAY, GETDATE())  
                    )  
                 BEGIN  
                     SELECT TOP 1 @NextStatusDate = CONVERT(  
                                DATETIME,  
                                CONVERT(  
                                    VARCHAR(20),  
                                    DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE()),  
                                    112  
                                ) + ' ' + CAST(@MonthlyHours AS VARCHAR(10))   
                                  
                                +  
                                  
                                ':' +  
                                  
                                CAST(@MonthlyMins AS VARCHAR(10)) + ':00'  
                            )  
                     FROM   #tempMonthDay AS t  
                            INNER JOIN #TempMonths tt  
                                 ON  t.MonthNo = tt.MonthlyNo  
                     WHERE  t.MonthDay > DATEPART(DAY, GETDATE())  
                     ORDER BY  
                            tt.MonthlyNo,  
                            t.MonthDay  
                 END  
                 ELSE  
                 BEGIN  
                     SELECT TOP 1 @NextStatusDate = CONVERT(  
                                DATETIME,  
                                CONVERT(  
                                    VARCHAR(20),  
                                    DATEADD(  
                                        MONTH,  
                                        1,  
                                        DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())  
                                    ),  
                                    112  
                                ) + ' ' + CAST(@MonthlyHours AS VARCHAR(10))   
                                  
                                +  
                                  
                                ':' +  
                                  
                                CAST(@MonthlyMins AS VARCHAR(10)) + ':00'  
                            )  
                     FROM   #tempMonthDay AS t  
                            INNER JOIN #TempMonths tt  
                                 ON  t.MonthNo = tt.MonthlyNo  
                     ORDER BY  
                            tt.MonthlyNo,  
                            t.MonthDay  
                 END  
             END  
         END  
         ELSE  
         BEGIN  
             IF EXISTS (  
                    SELECT 'x'  
                    FROM   #tempMonthDay t  
                    WHERE  DATEPART(DAY, GETDATE()) = t.MonthDay  
                )  
             BEGIN  
                 SELECT TOP 1 @NextStatusDate = CONVERT(  
                            DATETIME,  
                            CONVERT(  
                                VARCHAR(20),  
                                DATEADD(  
                                    MONTH,  
                                    tt.MonthlyNo -DATEPART(m, GETDATE()),  
                                    DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())  
                                ),  
                                112  
                            ) + ' ' + CAST(@MonthlyHours AS VARCHAR(10)) +  
                              
                            ':' +  
                              
                            CAST(@MonthlyMins AS VARCHAR(10)) + ':00'  
                        )  
                 FROM   #tempMonthDay AS t  
                        INNER JOIN #TempMonths tt  
                             ON  tt.MonthlyNo > DATEPART(m, GETDATE())  
                 WHERE  DATEPART(DAY, GETDATE()) = t.MonthDay  
                 ORDER BY  
                        tt.MonthlyNo,  
                        t.MonthDay  
             END  
             ELSE  
             BEGIN  
                 IF EXISTS (  
                        SELECT 'x'  
                        FROM   #tempMonthDay t  
                        WHERE  t.MonthDay > DATEPART(DAY, GETDATE())  
                    )  
                 BEGIN  
                     SELECT TOP 1 @NextStatusDate = CONVERT(  
                                DATETIME,  
                                CONVERT(  
                                    VARCHAR(20),  
                                    DATEADD(  
                                        MONTH,  
                                        tt.MonthlyNo -DATEPART(m, GETDATE()),  
                                        DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())  
                                    ),  
                                    112  
                                ) + ' ' + CAST(@MonthlyHours AS VARCHAR(10))   
                                  
                                +  
                                  
                                ':' +  
                                  
                                CAST(@MonthlyMins AS VARCHAR(10)) + ':00'  
                            )  
                     FROM   #tempMonthDay AS t  
                            INNER JOIN #TempMonths tt  
                                 ON  tt.MonthlyNo > DATEPART(m, GETDATE())  
                     WHERE  t.MonthDay > DATEPART(DAY, GETDATE())  
                     ORDER BY  
                            tt.MonthlyNo,  
                            t.MonthDay  
                 END  
                 ELSE  
                 BEGIN  
                     SELECT TOP 1 @NextStatusDate = CONVERT(  
                                DATETIME,  
                                CONVERT(  
                                    VARCHAR(20),  
                                    DATEADD(  
                                        MONTH,  
                                        tt.MonthlyNo -DATEPART(m, GETDATE()),  
                                        DATEADD(DAY, t.MonthDay -DATEPART(DAY, GETDATE()), GETDATE())  
                                    ),  
                                    112  
                                ) + ' ' + CAST(@MonthlyHours AS VARCHAR(10))   
                                  
                                +  
                                  
                                ':' +  
                                  
                                CAST(@MonthlyMins AS VARCHAR(10)) + ':00'  
                            )  
                     FROM   #tempMonthDay AS t  
                            INNER JOIN #TempMonths tt  
                                 ON  tt.MonthlyNo > DATEPART(m, GETDATE())  
                     ORDER BY  
                            tt.MonthlyNo,  
                            t.MonthDay  
                 END  
             END  
         END  
           
           
           
         DROP TABLE #tempMonthDay  
           
         DROP TABLE #TempMonths  
     END  
    
   declare @ParentID bigint = 0
   select @ParentID = isnull(ParentID,0) from UserSchedules  where  ID = @ScheduleID
   
   
 SELECT @ScheduleID  AS ScheduleID,  
        dbo.[fn_getusertimefromindiantime](@ParentID,@NextStatusDate) AS NextExecutionDate  
END  
         
         
  
         
  



GO

