         DROP TABLE #tempMonthDay  
           
         DROP TABLE #TempMonths  
     END  
    
   declare @ParentID bigint = 0
   select @ParentID = isnull(ParentID,0) from UserSchedules  where  ID = @ScheduleID
   
   
 SELECT @ScheduleID  AS ScheduleID,  
        dbo.[fn_getusertimefromindiantime](@ParentID,@NextStatusDate) AS NextExecutionDate  
END  
         
         
  
         
  


