/* ============================================================
   Procedure: [dbo].[usp_getnotification_sms_count]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getnotification_sms_count --'20220401','20220501'
@fromdate nvarchar(50),@todate nvarchar(50)
as
begin
if isdate(@fromdate)=1 and isdate(@todate)=1 and @todate>@fromdate
begin
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)      
select @fromdate as FromDate,@todate as Todate,parentid,(select user_login from user_detail(nolock) where user_id=u.parentid) ParentUser,
sum(case when createdon between @fromdate and dateadd(dd,1,@todate) then 1 else 0 end) Notification_SMS_Sent,count(1) Consumption_Till_Date
into #temp
from notificationhistory(nolock) n
join user_detail(nolock) u on n.n_userid=u.User_ID
where nmodeid=2 --and createdon between @fromdate and dateadd(dd,1,@todate)
group by parentid
order by count(1) desc

SET @xml =CAST(( SELECT FromDate AS 'td','',ToDate AS 'td','',ParentID AS 'td','',       
ParentUser  AS 'td','',Notification_SMS_Sent as 'td','',Consumption_Till_Date from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))      
SET @body ='<html><H1>Notification SMS used by users from '+@fromdate +' to '+@todate+
'</H1><body><table border = 2><tr><th>From Date</th><th>To Date</th><th>Parentid</th><th>ParentUser</th><th>Notification_SMS_Sent</th><th>Consumption_Till_Date</th></tr>'       
SET @body = @body + @xml +'</table></body></html>'      
EXEC msdb.dbo.sp_send_dbmail      
@profile_name='Alerts',       
@recipients='csshukla@pelsoftlabs.in',      
@blind_copy_recipients='karuna@pelsoftlabs.in',      
@subject='Notification SMS consumption by users',      
@body = @body,      
@body_format ='HTML'      
drop table #temp      
end
else
begin
Select 'Fromdate and todate should be valid dates and todate should be later than or equal to FromDate'
end

end




GO

/* ============================================================
   Procedure: [dbo].[Usp_GetNotificationContent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetNotificationContent]  
(  
  @ID bigint  
)  
as  
Begin  
--declare @id bigint=37383097
  declare @entity nvarchar(20),@entityid bigint,@view nvarchar(200),@reftable nvarchar(50),@refid nvarchar(100),@parentid bigint
  select @reftable=reftable,@refid=refid,@parentid=dbo.ufn_getuserparentid(n_userid) from notificationhistory(nolock) where id = @ID   

  declare @ename nvarchar(100),@edescription nvarchar(2000),@eventtype nvarchar(200),@encrypt_a varbinary(200),@e_n nvarchar(500)

  declare @mid bigint,@partner_userid bigint,@url nvarchar(255),@r_id bigint,@type int,@partner_type int

select @mid=m_id,@type=Type from user_detail(nolock) where user_id=@parentid
select @partner_userid=user_id,@r_id=reseller_id,@partner_type=partner_type from reseller_detail(nolock) where Reseller_ID=@mid

if @partner_type in (2,3) and @type=0 and @parentid<>335--Silver and Gold (white labelled partner)
begin
select @r_id=reseller_id from reseller_detail(nolock) where Reseller_ID=@mid
end
else if @partner_type in (2,3) or @type=3 or @parentid=335
begin
select @r_id=reseller_id,@partner_userid=user_id from reseller_detail(nolock) where user_ID=@parentid
end
else if  @partner_type=1--Bronze (Non white labelled partner)
begin
select @mid=m_id from user_detail(nolock) where user_id=@partner_userid
--Partner_userid and @r_id will be the reseller_id of the immediate white labelled partner above bronze partner whose branding will apply
select @partner_userid=user_id ,@r_id=reseller_id from reseller_detail(nolock) where Reseller_ID=@mid
end

select @url =dbo.fn_userdomain(@partner_userid)



  select @entity=
  case when @reftable='tbl_LeadEventHistory' then 'Lead' when @reftable='tbl_enquiryEventHistory' then 'Enquiry' when 
  @reftable='tbl_userEventHistory' then 'User' end
 select @entityid= 
 case when @entity='Lead' then (select leadid from tbl_leadeventhistory(nolock) where historyid=@refid)
 when @entity='Enquiry' then (select enquiryid from tbl_enquiryeventhistory(nolock) where historyid=@refid)
 when @entity='User' then (select userid from tbl_usereventhistory(nolock) where historyid=@refid) end
 
 
 select @entityid=leadid from tbl_leadeventhistory(nolock) where historyid=@refid and @entity='Lead'
 select @entityid=enquiryid from tbl_enquiryeventhistory(nolock) where historyid=@refid and @entity='Enquiry'
 select @entityid=userid from tbl_usereventhistory(nolock) where historyid=@refid and @entity='User'

 select @encrypt_a= EncryptByPassPhrase('EncryptActivityID', cast(@refid as varchar(100) ))
select @e_n='0x'+convert(varchar(max),@encrypt_a,2)   

	
	select isnull(content,'') as Content, case 
	when @entity='Lead' then isnull(nullif(@url,''),'https://kit19.com')+'/ActivityView.aspx?ActivityId='+@e_n+'&EntityName='+@entity
	--'https://kit19.com/UserCRMCampaign/LeadDetails.aspx?LeadID='+cast(@entityid as nvarchar)
	when @entity='Enquiry' then isnull(nullif(@url,''),'https://kit19.com')+'/ActivityView.aspx?ActivityId='+@e_n+'&EntityName='+@entity
	--'https://kit19.com/UserCRMCampaign/Enquiry.aspx?EnquiryID='+cast(@entityid as nvarchar)
	else isnull(nullif(@url,''),'https://kit19.com')
	--'https://Kit19.com' 
		end as [URL]
	from notificationhistory(nolock) where id = @ID   
  
End


--select top 10 * from notificationhistory(nolock) where dbo.ufn_getuserparentid(n_userid) in (select user_id from user_detail(nolock) where m_id=12141)
--select top 10 * from mysmsreport.dbo.tbl_LeadEventHistory_archived(nolock) where historyid=8890499


GO

/* ============================================================
   Procedure: [dbo].[usp_getNotificationHystory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getNotificationHystory](  
@userId bigint,  
@filter nvarchar(max) = '',                 
 @fromDate datetime= null,                                      
 @ToDate datetime= null,                                      
 @OffsetValue int = 0,                    
 @PagingSize int  = 100       
)  
as  
begin  
--declare @userId bigint=34594,  
--@filter nvarchar(max) = '',                 
-- @fromDate datetime='11-sep-2022',                                      
-- @ToDate datetime= '05-May-2024',                                      
-- @OffsetValue int = 0,                    
-- @PagingSize int  = 100   
declare                     
  @StartPoint int  = (@OffsetValue + 1), @Endpoint int = (@OffsetValue + @PagingSize), @ParentId bigint = 0                    
                    
  
select * from ( select     row_number() over(partition by nfh.n_userid order by nfh.Id desc) as SNo,  
    count(nfh.n_userid) over() as TotalRow ,nfh.[id] ,nfm.title ,nfh.[notificationid]  ,nfh.[reftable],nfh.[refid],      
    (dbo.func_Tbl_eventProfilePic(nfh.reftable,nfh.refid)) as ProfilePic,   
 (dbo.funcToGetEnquiryIDLeadIDUserID(nfh.reftable,nfh.refid)) as EnquryLeadUserID,   
 format(nfh.[createdon],'dd-MMM-yyyy HH:mm:ss') createdon, nfh.[readon], nfh.[content], nfh.[IsDeleted], nfh.[n_userid],  
 (select case when nfh.readon is null then 0     
              when nfh.readon is not null  then 1            
                 else 0            
            end   
  ) as ReadStatus,  
  dbo.fn_getNotificationURL(nfh.[id]) as URL  
from notificationhistory(nolock) as nfh            
    join notificationsmaster(nolock)  as nfm on nfh.notificationid = nfm.id            
    join User_Detail(nolock) as ud on nfh.n_userid = ud.User_ID            
    left join NotificationLastUpdate(nolock) as NLU on nfh.n_userid = NLU.UserID             
where nfh.n_userid =@userId   
      and  isnull(nfh.IsDeleted,0) = 0              
      and nfh.readon  is null     
      and nfm.modeid=1  
   and (1 = (case when isnull(@filter, '') = '' then 1    
                 when isnull(@filter, '') <> ''                   
      and (nfh.n_userid like '%'+@filter+'%') or (nfh.content like '%'+@filter+'%') or (nfh.[reftable] like '%'+@filter+'%') or (nfm.title like '%'+@filter+'%') then 1     else 0 end))  
   and  cast(nfh.[createdon]  as date)  between cast(@fromDate as date)  and  cast(@ToDate as date)  
 ) b where b.SNo between @StartPoint and @Endpoint    
                  
end  
  


GO

