CREATE   PROCEDURE dbo.Usp_GetNotificationsByUserID --34594
(
  @UserID bigint
)
as
Begin
      SELECT id, notificationid, IsDeleted, readon, isnull(n_userid,0) as n_userid, isnull(nmodeid,0) as nmodeid    FROM [notificationhistory](nolock)
	   where readon is null and isnull(IsDeleted,0) = 0 
	   and isnull(n_userid,0) = @UserID
	   and  DATEDIFF(DAY, CreatedOn, getdate()) < 3 
	   order by ID desc  
end


