   from notificationhistory(nolock) as nfh          
 --  join tbl_LeadEventHistory(nolock) as tlh          
 -- on nfh.refid = tlh.HistoryID          
   join notificationsmaster(nolock)  as nfm          
    on nfh.notificationid = nfm.id          
