/* ============================================================
   Procedure: [dbo].[Usp_GetOneTimeRecordStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Author:		Deepak Kumar
-- Create date: 10Nov2014 
-- Description:	This proc is use  for Get OTP details based on user Name
-- =============================================
CREATE   PROCEDURE Usp_GetOneTimeRecordStatus --'sms88888888819.info','DEMOSMS','','08/10/2013','10/11/2014'
@url varchar(550),
@userName varchar(150),
@mobile varchar(20),
@fdate varchar(10),
@todate varchar(10)

AS
BEGIN
 DECLARE @WHERE VARCHAR(MAX);
 DECLARE @QUERY VARCHAR(MAX);
 declare @usertype int ;
 set  @usertype=(SELECT TOP 1 [Type] FROM [dbo].[User_Detail] WHERE  [User_Login]=@userName);
 
 SET @WHERE=''; SET @QUERY=''
	SET NOCOUNT ON;
	IF(@userName='SMS19')
	begin
	
	 set @WHERE =  @WHERE +'1=1 and '
	 
	end else 
	begin
	 set @WHERE = @WHERE+'[UserName] ='''+@userName+''' and '
	end
	
	IF(@mobile='')
	BEGIN
	SET @WHERE= @WHERE +' 1=1  AND '
	END ELSE 
	BEGIN
	SET @WHERE= @WHERE+' [MobileNo] = '+@mobile+' AND '
	END 
	 
	IF(@fdate ='' OR @todate ='')
	BEGIN
	SET  @WHERE = @WHERE + ' 1 = 1 '
	END ELSE BEGIN
	SET @WHERE= @WHERE+' CONVERT(DATETIME ,[LoginTime],103 )  BETWEEN CONVERT(DATETIME ,'''+@fdate+''',103 ) AND   dateadd(day,1, CONVERT(DATETIME ,'''+@todate+''',103 ))'  
	END
	SET @QUERY =+'SELECT [UserName],[MobileNo],[OTP],Convert(varchar(24),[LoginTime],113) as DateTime
  FROM [dbo].[OneTimePassword]  (nolock) where '+ @WHERE +'order  by [ID] desc'
	print(@QUERY);
	exec(@QUERY);
	

	SET NOCOUNT OFF;
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetOpenTicketsForGraph_Kit19]
   ============================================================ */

