SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.Usp_GetOpenTicketsForGraph_Kit19 --233,335        
(        
@EnqNo bigint,        
@kit19UserID bigint        
        
)         
        
as        
        
Begin        
        
  Declare @DateCurrentTo date = null        
        
   CREATE TABLE #TempLinked                                          
    (                                          
      Result VARCHAR(200)                                          
    )                 
                            
     INSERT INTO #TempLinked                                          
     EXEC GetStatusofLinkedServer 'CRM'                                          
     IF NOT EXISTS(                                          
        SELECT 'x'                                          
        FROM   #TempLinked                                          
    )                               
    begin           
        
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID         
 and Stage = 'Customer Accepted Setup Request'          
         
 --for temp        
          
 --Declare @DateCurrentTo date = null        
  --  set @DateCurrentTo = '2019-01-01 21:08:03.167'        
    select CONVERT(date,Date_Created) as Date,COUNT(CONVERT(date,Date_Created)) as Count  from Serv_TicketMaster where Status = 1 and ParentID = @kit19UserID and CONVERT(date,Date_Created) >= convert(date,@DateCurrentTo)  
 group by CONVERT(date,Date_Created) order by CONVERT(date,Date_Created) asc  
        
        
   end        
        
  drop table  #TempLinked        
        
        
End        
        




GO

/* ============================================================
   Procedure: [dbo].[usp_GetOrderDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetOrderDetails  
 @OrderID BIGINT  
AS  
BEGIN  
 SELECT uo.CustomerName, uo.CustomerMobile, uo.CustomerEmail,  
        uo.CustomerAddress, uo.TotalAmount, uo.CreatedOn, uop.Qty, uop.Price,  
        uop.ProductID, pm.Name, pm.FullPath,pm.[Description]  
 FROM   UserOrders                    AS uo  
        INNER JOIN UserOrderProducts  AS uop  
             ON  uo.ID = uop.OrderID  
        INNER JOIN ProductMaster      AS pm  
             ON  pm.ProductID = uop.ProductID  
 WHERE  uo.ID = @OrderID  
END  


GO

