BEGIN        
   select
    prdmst.ProductID, prdmst.Name,
    prdmst.UserID, prdmst.Image, prdmst.Description, 
    prdmst.Price, prdmst.IsPublished, prdmst.IsActive,
   
   -- prdmst.CreatedOn,    
    dbo.[fn_getusertimefromindiantime]((select top 1 isnull(ParentID,0) from User_Detail where USER_ID = prdmst.userid) ,prdmst.CreatedOn) as CreatedOn,
    prdmst.CreatedBy, prdmst.FullPath, prdmst.IsFeatured,    
    ordprod.ID, ordprod.OrderID, ordprod.ProductID, ordprod.Qty, ordprod.Price as orderprice    
   
    from ProductMaster prdmst    
  inner join UserOrderProducts ordprod    
  on prdmst.ProductID=ordprod.ProductID where ordprod.OrderID=@OrderID    

END    



