/* ============================================================
   Procedure: [dbo].[usp_GetOrderSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE [dbo].[usp_GetOrderSummary]  --335       
 @ParentID BIGINT          
AS          
BEGIN     
 select * into #TMPTBL from UserLeads where ParentID = @Parentid           
 SELECT uo.ID       AS OrderID,          
        uo.CustomerName,          
        uo.CustomerMobile,          
        uo.CustomerEmail,          
        uo.CustomerAddress,          
        uo.TotalAmount,      
        uo.EnquiryID,        
        Convert(varchar(10),CONVERT(date,dbo.[fn_getusertimefromindiantime](uo.ParentID,uo.CreatedOn) ,106),103) as CreatedOn,        
        (          
            SELECT COUNT(*)          
            FROM   UserOrderProducts AS uop          
            WHERE  uop.OrderID = uo.ID          
        ) AS NoOfProducts,    
        ISNULL(                        
                       (                        
                           SELECT TOP 1                        
                                              
                                  1                        
                           FROM   #TMPTBL AS Ul                        
                           WHERE  Ul.Parentid = @ParentID                        
                                  AND (                        
                                          ISNULL(NULLIF(Ul.Countrycode, ''), '1')                         
            +                        
                                                                  
                                          ISNULL(NULLIF(Ul.Mobileno, ''), '1')                         
                                          = ISNULL(NULLIF(Ue.Countrycode, ''), '2')                         
                                                                  
                                          + ISNULL(NULLIF(Ue.Mobileno, ''), '2')                        
                                                               
                                                          
                                                         
                                                               
                                                   
                                                            
                                                              
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                         
                                             =                        
                                                                     
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')             
                                                          
                                                        
                                    
                            )                        
                       ),                        
                       0                        
                   )              
                          
                                     
            AS Leads ,    
             (CASE                         
                        WHEN Ue.Isopen = '1' THEN 'open'                       
                        ELSE 'close'                        
                   END) as Isopen           
 FROM   UserOrders  AS uo     
 INNER JOIN Userenquiry Ue      
  ON  uo.EnquiryID = Ue.EnquiryID                       
 WHERE  uo.ParentID = @ParentID          
END    



GO

