/* ============================================================
   Procedure: [dbo].[USP_GetPageWiseHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[USP_GetPageWiseHistory]
    @UserID NVARCHAR(50),
	@FromDate Datetime,
	@Todate Datetime,
	@PageNumber int,
	@PageSize int
AS
BEGIN

--declare
--  @UserID NVARCHAR(50) =32222,
--	@FromDate Datetime = '2025-03-31',
--	@Todate Datetime = '2025-03-31',
--	@PageNumber int =1,
--	@PageSize int =100

	DECLARE @PreviousFromDate DATETIME = DATEADD(DAY, -DATEDIFF(DAY, @FromDate, @Todate) - 1, @FromDate);
	DECLARE @PreviousToDate DATETIME = DATEADD(DAY, -DATEDIFF(DAY, @FromDate, @Todate) - 1, @Todate);

	DECLARE @Offset INT = (@PageNumber - 1) * @PageSize; -- Calculate offset
	DECLARE @Fetch INT = @PageSize; -- Number of rows to fetch

	declare @ParentId bigint
	
	select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserID

	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserID  

	-- select * from #tempUsers

	-- Pre-Aggregate Previous Period Data
    CREATE TABLE #PrevTotal (UserID BIGINT, SpendTime BIGINT);
    INSERT INTO #PrevTotal (UserID, SpendTime)
    SELECT 
        tem.UserID,
        SUM(ted.SpendTime) AS SpendTime
    FROM tbl_user_engagement_track_master (NOLOCK) tem
    INNER JOIN tbl_user_engagement_track_details ted ON ted.UserEngMasterId = tem.EngagementID
    WHERE ted.CreatedDate >= @PreviousFromDate AND ted.CreatedDate < DATEADD(DAY, 1, @PreviousToDate)
    GROUP BY tem.UserID;


	declare @tblPageUsers table(
		id int identity(1,1),
		UserId bigint,
		EngId bigint
	)

	insert into @tblPageUsers(UserId , EngId)
	 select distinct tem.UserID , tem.EngagementID  FROM tbl_user_engagement_track_master (NOLOCK) tem
    INNER JOIN tbl_user_engagement_track_details ted(nolock) ON ted.UserEngMasterId = tem.EngagementID
    WHERE ted.CreatedDate >= @PreviousFromDate AND ted.CreatedDate < DATEADD(DAY, 1, @PreviousToDate)
 

	SELECT 
    COUNT(*) OVER () AS TotalRecords,
    CASE
        WHEN SUM(tem.SpendTime) > MAX(ISNULL(pt.SpendTime, 0)) THEN 'Up'
        WHEN SUM(tem.SpendTime) < MAX(ISNULL(pt.SpendTime, 0)) THEN 'Down'
        ELSE 'Same'
    END AS Lag,
    MAX(tem.Mode) AS Mode,
    CONCAT(FORMAT(CAST(@FromDate AS DATE), 'dd-MMM-yyyy'), ' to ', FORMAT(CAST(@Todate AS DATE), 'dd-MMM-yyyy')) AS Period,
    tem.PageURL AS [PageName],
    CONCAT(ud.User_ID, ' (', User_Login, ')') AS [UserLogin],
	coalesce( (select count(1) from @tblPageUsers  where EngId = tem.UserEngMasterId ),0) as UsersCount,
    CONCAT(
        FLOOR(SUM(tem.SpendTime) / 3600), ' h ',
        FLOOR(CAST(SUM(tem.SpendTime) AS INT) % 3600 / 60), ' m ',
        CAST(SUM(tem.SpendTime) AS INT) % 60, ' s'
    ) AS [ActiveTime],
    CONCAT(
        FLOOR(SUM(tem.InactiveTime) / 3600), ' h ',
        FLOOR(CAST(SUM(tem.InactiveTime) AS INT) % 3600 / 60), ' m ',
        CAST(SUM(tem.InactiveTime) AS INT) % 60, ' s'
    ) AS [PassiveTime]
FROM (
    SELECT DISTINCT 
        tem.UserID, 
        tem.PageURL, 
		ted.UserEngMasterId,
        ted.Mode, 
        ted.SpendTime, 
        ted.InactiveTime, 
        ted.CreatedDate 
    FROM tbl_user_engagement_track_master (NOLOCK) tem 
    INNER JOIN tbl_user_engagement_track_details ted ON ted.UserEngMasterId = tem.EngagementID
    WHERE 
        tem.UserID = @UserID 
        AND FORMAT(ted.CreatedDate, 'yyyy-MM-dd') BETWEEN CAST(@FromDate AS DATE) AND CAST(@Todate AS DATE)
) tem 
LEFT JOIN #tempUsers tu ON tem.UserID = tu.User_ID
LEFT JOIN User_Detail ud ON tem.UserID = ud.User_ID
LEFT JOIN #PrevTotal pt ON pt.UserID = tem.UserID
GROUP BY 
    CONCAT(ud.User_ID, ' (', User_Login, ')'),
    tem.UserID, 
    tem.PageURL,
	tem.UserEngMasterId
ORDER BY 
    CONCAT(ud.User_ID, ' (', User_Login, ')') DESC
	OFFSET @Offset ROWS FETCH NEXT @Fetch ROWS ONLY;

	 DROP TABLE #tempUsers;
    DROP TABLE #PrevTotal;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetParentChildUsers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_GetParentChildUsers @Userid=33819
-- exec usp_GetParentChildUsers @Userid=335,@SearchValue='May'
CREATE   PROC usp_GetParentChildUsers
(
	@UserId bigint=335,
	@SearchValue varchar(20)=''
)
As
Begin
	-- declare @Userid int=32222,@SearchValue varchar(20)=''
	declare @ParentId bigint=0, @IsAdmin int=0

	Select @ParentId=ParentId, @IsAdmin= Case When IsAdmin=1 or User_id=parentId then 1 else 0 end
	from user_detail(nolock)
	Where User_Id=@Userid

	If(@UserId = 335)
	Begin
		If(@SearchValue != '')
		Begin
			Select User_Id, UserName=User_Login + ' | ' + '(' + isnull(FName,'') + isnull(' ' + LName,'') + ')' + ' | ' + cast(User_Id as varchar)
			From User_Detail(nolock)
			Where User_Login like @SearchValue + '%'
			Order By 2
		End
		Else
		Begin
			Select User_Id, UserName=User_Login + ' | ' + '(' + isnull(FName,'') + isnull(' ' + LName,'') + ')' + ' | ' + cast(User_Id as varchar)
			From User_Detail(nolock)
			Where IsAdmin=1 or User_id=parentId
			Order By 2
		End
	End
	Else
	Begin
		If(@IsAdmin=1)
		Begin
			If(@SearchValue != '')
			Begin
				Select User_Id, UserName=User_Login + ' | ' + '(' + isnull(FName,'') + isnull(' ' + LName,'') + ')' + ' | ' + cast(User_Id as varchar)
				From User_Detail(nolock)
				Where ParentId=@ParentId and User_Login like @SearchValue + '%'
				Order By 2		
			End
			Else
			Begin
				Select User_Id, UserName=User_Login + ' | ' + '(' + isnull(FName,'') + isnull(' ' + LName,'') + ')' + ' | ' + cast(User_Id as varchar)
				From User_Detail(nolock)
				Where ParentId=@ParentId
				Order By 2		
			End
		End
		Else
		Begin
			If(@SearchValue != '')
			Begin
				Select User_Id, UserName=User_Login + ' | ' + '(' + isnull(FName,'') + isnull(' ' + LName,'') + ')' + ' | ' + cast(User_Id as varchar)
				From User_Detail(nolock)
				Where User_id=@UserId and User_Login like @SearchValue + '%'
				Order By 2		
			End
			Else
			Begin
				Select User_Id, UserName=User_Login + ' | ' + '(' + isnull(FName,'') + isnull(' ' + LName,'') + ')' + ' | ' + cast(User_Id as varchar)
				From User_Detail(nolock)
				Where User_id=@UserId
				Order By 2		
			End
		End
	End

End



