/* ============================================================
   Procedure: [dbo].[usp_GetPassthruDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetPassthruDetails      
(      
@CallSid nvarchar(200),     
@From nvarchar(50),      
@To nvarchar(50),      
@Direction nvarchar(50),      
@DialCallDuration Bigint,      
@StartTime nvarchar(100),      
@CurrentTime nvarchar(100),      
@EndTime nvarchar(100),      
@CallType nvarchar(100),      
@Digits nvarchar(50),      
@RecordingUrl nvarchar(200)  ,      
@CustomField nvarchar(50),      
@DialWhomNumber nvarchar(50)      
      
)      
as      
Begin      
declare @user_login nvarchar(50),@user_id bigint,@description nvarchar(200), @id bigint  
if exists(select 1 from user_detail(nolock) where '0'+STR(mobile)=@From and M_ID=10043)  
begin  
 select @user_login=user_login,@user_id=user_id from user_detail(nolock) where '0'+STR(mobile)=@From and M_ID=10043    
end  
if not exists(select 'x' from Passthru where  CallSid = @CallSid )     
Begin    
insert into Passthru      
     (      
       CallSid    
       ,[From]      
      ,[To]      
      ,Direction      
      ,DialCallDuration      
      ,StartTime      
      ,CurrentTime      
      ,EndTime      
      ,CallType      
      ,digits      
      ,RecordingUrl      
      ,CustomField      
      ,DialWhomNumber      
      ,CreatedDate      
            
            
      )       
    values(    
       @CallSid      
       ,@From      
      ,@To      
      ,@Direction      
      ,@DialCallDuration      
      ,@StartTime      
      ,@CurrentTime      
      ,@EndTime      
      ,@CallType      
      ,@Digits      
      ,@RecordingUrl      
      ,@CustomField      
      ,@DialWhomNumber      
      ,GETDATE()      
     )    
select @id=SCOPE_IDENTITY()  
if @user_id is not null  
begin  
select @description='User '+cast(@user_login as nvarchar)+' has just called at helpline number '   
exec Usp_InsertUserEventDetails 'User called up',@user_ID,@Description,'passthru',@ID    
  
end   
End    
else    
Begin    
update Passthru set [From] = @From      
      ,[To] = @To      
      ,Direction = @Direction      
      ,DialCallDuration = @DialCallDuration     
      ,StartTime = @StartTime     
      ,CurrentTime = @CurrentTime      
      ,EndTime  = @EndTime    
      ,CallType = @CallType     
      ,digits  = @Digits    
      ,RecordingUrl = @RecordingUrl     
      ,CustomField = @CustomField     
      ,DialWhomNumber = @DialWhomNumber     
        
      where CallSid = @CallSid    
    End    
select @id=id from Passthru(nolock) where CallSid = @CallSid  
if @user_id is not null  
begin  
select @description='User '+cast(@user_login as nvarchar)+' called at helpline number and '+ case when @DialCallDuration>0 then ' the call was answered at an agent with mobile '+ CAST(@DialWhomNumber as nvarchar) +' the call lasted for '+cast(@DialCallDuration as nvarchar) + ' seconds'   
else ' the call was not attended by anyone ' end  
exec Usp_InsertUserEventDetails 'User called up',@user_ID,@Description,'passthru',@ID    
end             
 select 'Record Saved'            
End   
  
  
  
  
  
  select top 10 user_login,user_id,p.* from Passthru p join user_detail(nolock) u
  on '0'+STR(mobile)=p.[From]
   order by p.ID desc
  select user_login,user_id from user_detail(nolock) where STR(mobile)=@From and M_ID=10043  


GO

