   Procedure: [dbo].[usp_GetPaymentRequests]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetPaymentRequests]      
@referid int      
as      
begin   
if exists(select 1 from referrer_details where @referid=ID and Isadmin<>1)
begin
select id,cast(a.datecreated as date) AS Date,PaymentRequested,isnull(PayoutStatus,'Open') as Status,ModeOfPayment from PayoutStatus a where Referrerid=@referid and isnull(PaymentRequested,0)<>0 order by DateCreated desc
end
else 
begin
select id,cast(a.datecreated as date) AS Date,PaymentRequested,isnull(PayoutStatus,'Open') as Status,ModeOfPayment from PayoutStatus a where  isnull(PaymentRequested,0)<>0 order by DateCreated desc
end
end  
  


