CREATE   PROC usp_getpayouttracking --4  
@referredcontactid bigint  
as  
begin  
declare @referrerid int=(select referrerid from ReferredContacts where ID=@referredcontactid)  
declare @editable bit=(select 1 from PayoutStatus where @referredcontactid=referredcontactid and Type='Payout Approved' and ID=(select MAX(id) from PayoutStatus where @referrerid=referrerid))  
Select top 1 @editable as editable ,commissionid,r.slabname,referredcontactid,p.commissionamount,remarks from PayoutTracking p join Referrer_Payout_Rates r on r.ID=p.commissionid where ReferredContactId=@referredcontactid and p.Status='Payment Approved'  order by p.id desc     
end  
  





