/* ============================================================
   Procedure: [dbo].[usp_GetPendingVoiceRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
CREATE   PROC [dbo].[usp_GetPendingVoiceRecord]  
As  
Begin  
  if datepart(hour,getdate()) between 9 and 21
  begin
SELECT TOP 1 id,   
             [dnino],  
             CASE  
                 WHEN sipname = 'Airtel2'  
                 THEN clino  
                 ELSE CONCAT([countrycode], [clino])  
             END AS [clino],   
             [appid],   
             originatetrunk,   
             originatecliprefix,   
             originateclisuffix,   
             originatedniprefix,   
             originatednipostfix,   
             sipname,   
             context,   
             sipheader,   
             ISNULL(CAST(v_activityid AS NVARCHAR), '') v_activityid,   
             ISNULL(v_entity, '') v_entity  
FROM Kit19Cloudvoicefinaltbl WITH(NOLOCK)  
WHERE([processed] = 0  
      OR ([processed] = 2  
          AND (ScheduleDateTime > DATEADD(minute, -60, GETDATE())  
               OR ScheduleDateTime IS NULL)  
          AND DATEDIFF(hh, lastaccesstime, GETDATE()) > 20  
          AND dialstatus <> 'ANSWER'  
          AND retries < 2))  
     AND ISNULL(ScheduleDateTime, GETDATE()) <= GETDATE()  
     AND sipname IN('Jio', 'tata', 'go', 'Airtel2')  
ORDER BY processed,priority desc,scheduledatetime,isnull(retries,0),  
ISNULL(lastaccesstime, dateadd(d,-1,GETDATE())) ;  
  end
End  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetPhysicalAppointmentList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetPhysicalAppointmentList]     
  @TaskId BIGINT    
 ,@CreatedBy BIGINT    
AS    
BEGIN    
  
--declare @TaskId BIGINT=0, @CreatedBy BIGINT=50169  
  
Declare @ParentId bigint     
    
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy    
    
select * From (  
    select Id, TasKName, IconClass, ParentId, IsDeleted, IsPredefined, CreatedOn, CreatedBy, isnull(TaskType, 'VirtualApt') TaskType from tbl_tsk_UserTaskMaster(nolock) utma where utma.IsDeleted = 0     
    --and utma.Id = (case when @TaskId > 0 then @TaskId else utma.Id End)    
    and utma.TaskType='PhysicalMeeting' and 1 = (  
    case when IsPredefined = 1  then 1   
    when dbo.ufn_getuserparentid(utma.CreatedBy) = @ParentId then 1   
    else 0 end )  
    union  
    select Id, TasKName, IconClass, ParentId, IsDeleted, IsPredefined, CreatedOn, CreatedBy,  
    isnull(TaskType, 'VirtualMeeting') TaskType from tbl_tsk_UserTaskMaster(nolock) utma where utma.Id=8  
    ) T  Where T.Id = (case when @TaskId > 0 then @TaskId else T.Id End)    


  
if(@TaskId > 0)    
Begin    
--Collabrator    
select * from tbl_tsk_TaskActionPermission(nolock) where Task_Type_Id = @TaskId and Parent_Id = @ParentId    
    
--Field Executive    
select * from TBL_ET_PhyApptTypeFieldExecutivePermission(nolock) where Task_Type_Id = @TaskId and Parent_Id = @ParentId    
    
--OutCome    
select * from tbl_tsk_UserOutcomeMaster(nolock) where CreatedBy = @CreatedBy and IsDeleted = 0    
End    
    
    
END; 




GO

