/* ============================================================
   Procedure: [dbo].[usp_getpipelineaspercalendarKit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_getpipelineaspercalendarKit19 --335       
	(@user_id BIGINT)
AS
BEGIN
	--;WITH cte AS       
	-- (      
	-- SELECT a.user_Id, a.reportto, a.name      
	-- FROM User_Login a      
	-- WHERE user_Id = @user_id      
	-- UNION ALL      
	-- SELECT a.user_Id, a.reportto, a.Name      
	-- FROM User_Login a JOIN cte c ON a.ReportTo = c.User_ID      
	-- --where jobstatus='on job'      
	-- )      
	-- SELECT ReportTo, USER_ID, name into #users      
	-- FROM cte order by User_ID     
	DECLARE @IsAdmin BIT = 0

	SELECT @IsAdmin = isnull(IsAdmin, 0)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @user_id

	--select * into #users from User_Detail where user_id
	-- in (  case when @IsAdmin = 1 then  (select top 1 USER_ID from User_Detail p where p.ParentID = @user_id)
	--   else @user_id
	--End  
	--    )
	IF (@IsAdmin = 1)
	BEGIN
		SELECT *
		INTO #users1
		FROM User_Detail
		WHERE ParentID = @user_id

		SELECT month(estimatedclosuredate) AS Month
			,year(estimatedclosuredate) AS Year
			,sum(CASE 
					WHEN expired = 0
						THEN amount * (probability / cast(100 AS FLOAT))
					ELSE 0
					END) AS EstimatedRevenue
			,sum(CASE 
					WHEN expired = 1
						THEN 1
					ELSE 0
					END) ExpiredCount
			,sum(CASE 
					WHEN expired = 0
						THEN 1
					ELSE 0
					END) ActiveCount
			,isnull(sum(CASE 
						WHEN expired = 0
							THEN amount
						ELSE 0
						END), 0) AS TotalAmount
		FROM (
			SELECT e.id
				,e.CreatedDate
				,e.LeadID
				,e.Amount
				,e.CreatedBy
				,e.DealOwner
				,e.EstimatedClosureDate
				,e.Probability
				,e.Remarks
				,P.Name AS Pipeline
				,S.Name AS Stage
				,CASE 
					WHEN datediff(d, e.CreatedDate, getdate()) > P.DealExpiry
						THEN 1
					ELSE 0
					END AS Expired
			FROM Pipeline_Master P
			JOIN PipelineStages S ON P.id = S.PipelineID
			JOIN LeadPipelineMapping e ON e.PipeLineStage = S.ID
			JOIN #users1 u ON e.DealOwner = u.User_ID
			WHERE e.isdeleted = 0
			) A
		GROUP BY month(estimatedclosuredate)
			,year(estimatedclosuredate)
		ORDER BY month(estimatedclosuredate)
			,year(estimatedclosuredate)

		SELECT e.id
			,e.CreatedDate
			,e.LeadID
			,e.Amount
			,e.CreatedBy
			,e.DealOwner
			,isnull((
					SELECT isnull(User_Login, '')
					FROM User_Detail
					WHERE USER_ID = e.DealOwner
					), '') AS DealOwnerByName
			,Month(e.EstimatedClosureDate) AS Month
			,year(estimatedclosuredate) AS Year
			,e.EstimatedClosureDate
			,e.Probability
			,e.Remarks
			,P.Name AS Pipeline
			,S.Name AS Stage
			,CASE 
				WHEN datediff(d, e.CreatedDate, getdate()) > P.DealExpiry
					THEN 1
				ELSE 0
				END AS Expired
			,(
				SELECT isnull(CompanyName, '')
				FROM userleads(NOLOCK)
				WHERE ID = e.LeadID
				) AS CompanyName
		FROM Pipeline_Master P
		JOIN PipelineStages S ON P.id = S.PipelineID
		JOIN LeadPipelineMapping e ON e.PipeLineStage = S.ID
		JOIN #users1 u ON e.DealOwner = u.User_ID
		WHERE e.isdeleted = 0
		ORDER BY month(estimatedclosuredate)
			,year(estimatedclosuredate)
	END
	ELSE
	BEGIN
		SELECT *
		INTO #users2
		FROM User_Detail
		WHERE User_ID = @user_id

		SELECT month(estimatedclosuredate) AS Month
			,year(estimatedclosuredate) AS Year
			,sum(CASE 
					WHEN expired = 0
						THEN amount * (probability / cast(100 AS FLOAT))
					ELSE 0
					END) AS EstimatedRevenue
			,sum(CASE 
					WHEN expired = 1
						THEN 1
					ELSE 0
					END) ExpiredCount
			,sum(CASE 
					WHEN expired = 0
						THEN 1
					ELSE 0
					END) ActiveCount
			,isnull(sum(CASE 
						WHEN expired = 0
							THEN amount
						ELSE 0
						END), 0) AS TotalAmount
		FROM (
			SELECT e.id
				,e.CreatedDate
				,e.LeadID
				,e.Amount
				,e.CreatedBy
				,e.DealOwner
				,e.EstimatedClosureDate
				,e.Probability
				,e.Remarks
				,P.Name AS Pipeline
				,S.Name AS Stage
				,CASE 
					WHEN datediff(d, e.CreatedDate, getdate()) > P.DealExpiry
						THEN 1
					ELSE 0
					END AS Expired
			FROM Pipeline_Master P
			JOIN PipelineStages S ON P.id = S.PipelineID
			JOIN LeadPipelineMapping e ON e.PipeLineStage = S.ID
			JOIN #users2 u ON e.DealOwner = u.User_ID
			WHERE e.isdeleted = 0
			) A
		GROUP BY month(estimatedclosuredate)
			,year(estimatedclosuredate)
		ORDER BY month(estimatedclosuredate)
			,year(estimatedclosuredate)

		SELECT e.id
			,e.CreatedDate
			,e.LeadID
			,e.Amount
			,e.CreatedBy
			,e.DealOwner
			,isnull((
					SELECT isnull(User_Login, '')
					FROM User_Detail
					WHERE USER_ID = e.DealOwner
					), '') AS DealOwnerByName
			,Month(e.EstimatedClosureDate) AS Month
			,year(estimatedclosuredate) AS Year
			,e.EstimatedClosureDate
			,e.Probability
			,e.Remarks
			,P.Name AS Pipeline
			,S.Name AS Stage
			,CASE 
				WHEN datediff(d, e.CreatedDate, getdate()) > P.DealExpiry
					THEN 1
				ELSE 0
				END AS Expired
			,(
				SELECT isnull(CompanyName, '')
				FROM userleads(NOLOCK)
				WHERE ID = e.LeadID
				) AS CompanyName
		FROM Pipeline_Master P
		JOIN PipelineStages S ON P.id = S.PipelineID
		JOIN LeadPipelineMapping e ON e.PipeLineStage = S.ID
		JOIN #users2 u ON e.DealOwner = u.User_ID
		WHERE e.isdeleted = 0
		ORDER BY month(estimatedclosuredate)
			,year(estimatedclosuredate)
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id
		,@Activity_type = 'View_Deal_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Pipeline_Master'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_getpipelineaspercalendarKit19_WithFilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].usp_getpipelineaspercalendarKit19_WithFilter --   '335#34673',3,'15#14#29','11/09/2020','12/09/2020',0,9999999,0,335   
  (
    
  @DealOwner nvarchar(max),
  @PipelineID bigint,
  @StageIDs nvarchar(max),
  @LastModifiedDateFrom datetime,
  @LastModifiedDateTo datetime,
  @AmountFrom numeric(18,2),
  @AmountTo numeric(18,2),      
  @IsExpiry bit,
  @user_id bigint
    

)          
as          
begin    
          
 --;WITH cte AS           
 -- (          
 -- SELECT a.user_Id, a.reportto, a.name          
 -- FROM User_Login a          
 -- WHERE user_Id = @user_id          
 -- UNION ALL          
 -- SELECT a.user_Id, a.reportto, a.Name          
 -- FROM User_Login a JOIN cte c ON a.ReportTo = c.User_ID          
 -- --where jobstatus='on job'          
 -- )          
 -- SELECT ReportTo, USER_ID, name into #users          
 -- FROM cte order by User_ID         
      
    declare @IsAdmin bit = 0            
    select @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @user_id    
         
       --select * into #users from User_Detail where user_id    
       -- in (  case when @IsAdmin = 1 then  (select top 1 USER_ID from User_Detail p where p.ParentID = @user_id)    
       --   else @user_id    
       --End      
       --    )    
     
 if(@IsAdmin = 1)    
   Begin    
    
    select * into #users1 from User_Detail(nolock) where ParentID = @user_id    
             
select month(estimatedclosuredate) as Month,year(estimatedclosuredate) as Year,sum(case when expired=0 then amount*(probability/cast(100 as float)) else 0 end) as EstimatedRevenue,sum(case when expired=1 then 1 else 0 end) ExpiredCount ,sum(case when     
  
    
 expired=0 then 1 else 0 end) ActiveCount , isnull(sum(case when expired=0 then amount else 0 end),0) as TotalAmount from          
(select e.id,e.CreatedDate,e.LeadID,e.Amount,e.CreatedBy,e.DealOwner,e.EstimatedClosureDate,e.Probability,e.Remarks,          
P.Name as Pipeline,S.Name as Stage,case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end as Expired from           
Pipeline_Master P(nolock)           
join PipelineStages S(nolock)  on P.id=S.PipelineID          
join LeadPipelineMapping e(nolock)  on e.PipeLineStage=S.ID          
join #users1 u on e.DealOwner=u.User_ID  
left join (select value as user_id from fn_Split(@DealOwner,'#')) A on A.user_id=e.dealowner        
left join (select value as StageID from fn_Split(@StageIDs,'#')) stg on stg.StageID = e.PipeLineStage
where e.isdeleted = 0   
  and e.DealOwner=case when @DealOwner = '' then e.DealOwner else A.user_id end
  and p.ID = @PipelineID
  and e.PipeLineStage = case when @StageIDs = '' then e.PipeLineStage else stg.StageID  end
  and e.CreatedDate between @LastModifiedDateFrom and @LastModifiedDateTo 
  and e.Amount between @AmountFrom and @AmountTo
  and @IsExpiry = case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end


  --and e.DealOwner  in (  case when @DealOwner = '' then  e.DealOwner  
    --                     else  (select fn.value from dbo.[fn_Split](@DealOwner,'#') as fn )   
    --   end       
    --   )  

 )  A          
group by month(estimatedclosuredate),year(estimatedclosuredate)  order by month(estimatedclosuredate),year(estimatedclosuredate)        
 select e.id,e.CreatedDate,e.LeadID,e.Amount,e.CreatedBy,e.DealOwner,isnull((select isnull(User_Login,'') from User_Detail where USER_ID = e.DealOwner),'') as DealOwnerByName          
 ,Month(e.EstimatedClosureDate) as Month,year(estimatedclosuredate) as Year,e.EstimatedClosureDate,e.Probability,e.Remarks,          
P.Name as Pipeline,S.Name as Stage,case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end as Expired       
,(select  isnull(CompanyName,'')   from userleads(nolock)  where ID = e.LeadID) as CompanyName      
      
from           
Pipeline_Master P(nolock)            
join PipelineStages S(nolock)  on P.id=S.PipelineID          
join LeadPipelineMapping e(nolock)  on e.PipeLineStage=S.ID          
join #users1 u on e.DealOwner=u.User_ID   
left join (select value as user_id from fn_Split(@DealOwner,'#')) A on A.user_id=e.dealowner 
left join (select value as StageID from fn_Split(@StageIDs,'#')) stg on stg.StageID = e.PipeLineStage     
where e.isdeleted = 0   
  and e.DealOwner=case when @DealOwner = '' then e.DealOwner else A.user_id end
  and p.ID = @PipelineID
  and e.PipeLineStage = case when @StageIDs = '' then e.PipeLineStage else stg.StageID  end
  and e.CreatedDate between @LastModifiedDateFrom and @LastModifiedDateTo
  and e.Amount between @AmountFrom and @AmountTo
  and @IsExpiry = case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end
 --and e.DealOwner  in (  case when @DealOwner = '' then e.DealOwner  
 --                        else  (select fn.value from dbo.[fn_Split](@DealOwner,'#') as fn )   
 --      end       
 --      )  

  
 order by month(estimatedclosuredate),year(estimatedclosuredate)         
          
  End    
else    
  Begin    
         
  select * into #users2 from User_Detail(nolock)  where User_ID = @user_id    
             
select month(estimatedclosuredate) as Month,year(estimatedclosuredate) as Year,sum(case when expired=0 then amount*(probability/cast(100 as float)) else 0 end) as EstimatedRevenue,sum(case when expired=1 then 1 else 0 end) ExpiredCount ,sum(case when     
  
    
 expired=0 then 1 else 0 end) ActiveCount , isnull(sum(case when expired=0 then amount else 0 end),0) as TotalAmount from        
(select e.id,e.CreatedDate,e.LeadID,e.Amount,e.CreatedBy,e.DealOwner,e.EstimatedClosureDate,e.Probability,e.Remarks,          
P.Name as Pipeline,S.Name as Stage,case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end as Expired from           
Pipeline_Master P (nolock)           
join PipelineStages S(nolock)  on P.id=S.PipelineID          
join LeadPipelineMapping e(nolock)  on e.PipeLineStage=S.ID          
join #users2 u on e.DealOwner=u.User_ID   
left join (select value as user_id from fn_Split(@DealOwner,'#')) A on A.user_id=e.dealowner
left join (select value as StageID from fn_Split(@StageIDs,'#')) stg on stg.StageID = e.PipeLineStage         
where e.isdeleted = 0  
   and e.DealOwner=case when @DealOwner = '' then e.DealOwner else A.user_id end
   and p.ID = @PipelineID
   and e.PipeLineStage = case when @StageIDs = '' then e.PipeLineStage else stg.StageID  end
   and e.CreatedDate between @LastModifiedDateFrom and @LastModifiedDateTo
   and e.Amount between @AmountFrom and @AmountTo
   and @IsExpiry = case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end
   --and e.DealOwner  in (  case when @DealOwner = '' then e.DealOwner  
   --                      else  (select fn.value from dbo.[fn_Split](@DealOwner,'#') as fn )   
   --    end       
   --   )  


  
 ) A          
group by month(estimatedclosuredate),year(estimatedclosuredate)  order by month(estimatedclosuredate),year(estimatedclosuredate)        
 select e.id,e.CreatedDate,e.LeadID,e.Amount,e.CreatedBy,e.DealOwner,isnull((select isnull(User_Login,'') from User_Detail where USER_ID = e.DealOwner),'') as DealOwnerByName          
 ,Month(e.EstimatedClosureDate) as Month,year(estimatedclosuredate) as Year,e.EstimatedClosureDate,e.Probability,e.Remarks,          
P.Name as Pipeline,S.Name as Stage,case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end as Expired       
,(select  isnull(CompanyName,'')   from userleads(nolock)  where ID = e.LeadID) as CompanyName      
      
from           
Pipeline_Master P (nolock)           
join PipelineStages S(nolock)  on P.id=S.PipelineID          
join LeadPipelineMapping e(nolock)  on e.PipeLineStage=S.ID          
join #users2 u on e.DealOwner=u.User_ID  
left join (select value as user_id from fn_Split(@DealOwner,'#')) A on A.user_id=e.dealowner
left join (select value as StageID from fn_Split(@StageIDs,'#')) stg on stg.StageID = e.PipeLineStage            
where e.isdeleted = 0   
   and e.DealOwner=case when @DealOwner = '' then e.DealOwner else A.user_id end
   and p.ID = @PipelineID
    and e.PipeLineStage = case when @StageIDs = '' then e.PipeLineStage else stg.StageID  end
	and e.CreatedDate between @LastModifiedDateFrom and @LastModifiedDateTo
	and e.Amount between @AmountFrom and @AmountTo
	and @IsExpiry = case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end
 --and e.DealOwner  in (  case when @DealOwner = '' then e.DealOwner  
 --                        else  (select fn.value from dbo.[fn_Split](@DealOwner,'#') as fn )   
 --      end       
 --      )  

  
 order by month(estimatedclosuredate),year(estimatedclosuredate)         
         
    
  End    
    
    
    
