join PipelineStages S(nolock)  on P.id=S.PipelineID                
join LeadPipelineMapping e(nolock)  on e.PipeLineStage=S.ID
join #userleadsBySegment uls on e.LeadID = uls.ID
join #users2 u on e.DealOwner=u.User_ID     
