   and cast(''', cast(@LastModifiedDateTo as nvarchar(50)) ,''' as date)      
   and e.Amount between ',cast(@AmountFrom as nvarchar(50)),' and ',cast(@AmountTo as nvarchar(50)),'      
   and ', cast(@IsExpiry as nvarchar) ,' = case when datediff(d,e.CreatedDate,getdate())>P.DealExpiry then 1 else 0 end      
       
  ) A                
