 (select distinct date_month,date_year from Calendar c (nolock) join user_detail(nolock) u on start_dts between u.DateCreated and dateadd(yy,1,getdate())
 and u.user_id= ', cast(@parentid as nvarchar(50)) , ' ) as Q on Q.date_month=b.month and Q.date_year=b.year
