,(select  isnull(LeadNo,''0'')   from userleads(nolock)  where ID = e.LeadID) as LeadNo            
,(select  isnull(ProfileImgFileName,'''') from userleads(nolock)  where ID = e.LeadID) as ProfileImgFileName  
