left join (select value as user_id from fn_Split(''', @DealOwner, ''' ,''#'')) A on A.user_id=e.dealowner      
left join (select value as StageID from fn_Split(''', @StageIDs , ''',''#'')) stg on stg.StageID = e.PipeLineStage                  
  
