/* ============================================================
   Procedure: [dbo].[Usp_GetPipelineList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


    
CREATE   PROCEDURE [dbo].[Usp_GetPipelineList] --34594    
@userid BIGINT ,    
@pipelinename nvarchar(max)=null,    
@estfromdt datetime =null,    
@esttodt datetime =null,    
@createfromdt datetime = null,    
@createtodt datetime=null,    
@remarks nvarchar(max)=null,    
@leadname nvarchar(max)=null,  
@columnName nvarchar(max)=null,  
@sortby char(4)=null  ,
@filtertext nvarchar(max) ='',
@sortbytext nvarchar(100) = '',
@mode varchar(10) = null
AS    
BEGIN    

if @sortbytext <> '' AND @sortbytext IS NOT  NULL
begin 
	set @sortbytext ='ORDER BY '+@sortbytext
end 


if @filtertext <> '' AND @filtertext IS NOT  NULL
begin 
	set @filtertext ='where '+@filtertext
end 

Create Table #temp (User_ID BIGINT, Name VARCHAR(100), IMAGE VARCHAR(100))

Declare @parentid bigint 

SELECT @parentid = parentid from User_Detail where user_id=@userid 

insert into #temp 
execute use_getUserDetails @userid

if(@mode='all')
BEGIN 

	
SELECT lpm.ID as LeadPipelinemapID,lPm.LeadID,Ul.leadNo, Ul.PersonName, Pm.Name as PipeLineName, Pm.ID as PipelineID, Pms.Name As PipeLineStage, Pms.ID as PipeLineStageid,     
		ROUND(lPm.Probability,0) AS Probability, lpm.Amount, lpm.Remarks,  
		Convert(varchar,dbo.fn_getusertimefromindiantime(@userid, lpm.CreatedDate),100) AS CreatedDate,   
		Convert(varchar,dbo.fn_getusertimefromindiantime(@userid, lPm.EstimatedClosureDate ),100) AS EstimatedClosureDate , lpm.CreatedBy, Ud.FName, Ud.LName, Ud.User_Login,lPm.DealOwner As DealOwnerID,  
		 UdLo.FName +' '+UdLo.LName +' ( '+UdLo.User_Login+' )' As DealOwnerName, UdLo.User_Login As DealOwnerLogin,Cast (lpm.isDeleted as Varchar) isDeleted,  
		 Convert(varchar,dbo.fn_getusertimefromindiantime(@userid, lpm.DeletedOn),100) As DeletedOn  
		FROM LeadPipelineMapping lPm WITH(NOLOCK)    
		JOIN UserLeads Ul  WITH(NOLOCK) ON lPm.LeadID=Ul.ID    
		JOIN pipeline_master Pm WITH(NOLOCK) ON Pm.ID=lPm.PipelineID    
		JOIN PipelineStages Pms WITH(NOLOCK) ON Pms.ID=lpm.PipeLineStage    
		JOIN User_Detail Ud WITH(NOLOCK) ON Ud.User_ID= lpm.CreatedBy     
		JOIN User_Detail UdLo WITH(NOLOCK) ON UdLo.User_ID= lpm.DealOwner  
		Join #temp on #temp.User_ID=lpm.CreatedBy 
		--AND lpm.IsDeleted=0    
		AND (@pipelinename IS NULL OR Pm.Name LIKE '%'+@pipelinename+'%')    
		 AND (@estfromdt IS NULL OR lPm.EstimatedClosureDate > @estfromdt)    
		 AND (@esttodt IS NULL OR lPm.EstimatedClosureDate < @esttodt)    
		 AND (@createfromdt IS NULL OR lPm.CreatedDate >@createfromdt)    
		 AND (@createtodt IS NULL OR lPm.CreatedDate < @createtodt)    
		 AND (@remarks IS NULL OR lpm.Remarks LIKE '%'+@remarks+'%')    
		 AND (@leadname IS NULL OR Ul.PersonName LIKE '%'+@leadname+'%')    
		 ORDER BY   
		Case WHEN @columnName='pipemapid' and @sortby='desc' Then lpm.ID  END DESC,
		Case WHEN @columnName='leadno' and @sortby='desc' Then Ul.LeadNo  END DESC,
		Case WHEN @columnName='personname' and @sortby='desc'  Then Ul.PersonName  END DESC,
		Case WHEN @columnName='pipelinename' and @sortby='desc'  Then Pm.Name  END DESC,
		Case WHEN @columnName='pipelinestage' and @sortby='desc'  Then Pms.Name  END DESC,
		Case WHEN @columnName='createddate' and @sortby='desc'  Then lpm.CreatedDate   END DESC,
		Case WHEN @columnName='estimateddate' and @sortby='desc'  Then lpm.EstimatedClosureDate  END DESC,
		Case WHEN @columnName='deletedon' and @sortby='desc'  Then lpm.DeletedOn   END DESC,
		Case WHEN @columnName='dealowner' and @sortby='desc'  Then UdLo.FName  END DESC,
		
		CASE WHEN @columnName='pipemapid' and @sortby='asc' Then lpm.ID  END ASC,   
		CASE WHEN @columnName='leadno' and @sortby='asc'  Then Ul.LeadNo  END ASC,   
		CASE WHEN @columnName='personname' and @sortby='asc'  Then Ul.PersonName  END ASC,   
		CASE WHEN @columnName='pipelinename' and @sortby='asc'  Then Pm.Name END ASC,    
		CASE WHEN @columnName='pipelinestage' and @sortby='asc'  Then Pms.Name END ASC,    
		CASE WHEN @columnName='createddate' and @sortby='asc'  Then lpm.CreatedDate  END ASC,   
		CASE WHEN @columnName='estimateddate' and @sortby='asc'  Then lpm.EstimatedClosureDate END ASC,    
		CASE WHEN @columnName='deletedon' and @sortby='asc'  Then lpm.DeletedOn  END ASC,
		CASE WHEN @columnName='dealowner' and @sortby='asc'  Then UdLo.FName  END ASC  
END

 ELSE IF @mode ='filter'
 begin
 DECLARE @sqls NVARCHAR(MAX)
 
 SET  @sqls =N'select LeadPipelinemapID, LeadID, leadNo, PersonName, PipeLineName, PipelineID, PipeLineStage, PipeLineStageid, Probability, Amount, Remarks,\
	CreatedDate,EstimatedClosureDate, CreatedBy, FName, LName, User_Login, DealOwnerID, DealOwnerName, DealOwnerLogin,isDeleted,DeletedOn from (
 SELECT lpm.ID as LeadPipelinemapID,lPm.LeadID,Ul.leadNo, Ul.PersonName, Pm.Name as PipeLineName, Pm.ID as PipelineID, Pms.Name As PipeLineStage, Pms.ID as PipeLineStageid,     
 ROUND(lPm.Probability,0) AS Probability, lpm.Amount, lpm.Remarks,  
 Convert(varchar,dbo.fn_getusertimefromindiantime('+ CAST(@userid as varchar) +', lpm.CreatedDate),100) AS CreatedDate,   
 Convert(varchar,dbo.fn_getusertimefromindiantime('+ CAST(@userid as varchar) +', lPm.EstimatedClosureDate ),100) AS EstimatedClosureDate , lpm.CreatedBy, Ud.FName, Ud.LName, Ud.User_Login,lPm.DealOwner As DealOwnerID,  
  UdLo.FName+'' ''+ UdLo.LName +''(''+ +UdLo.User_Login+'')'' As DealOwnerName, UdLo.User_Login As DealOwnerLogin,Cast (lpm.isDeleted as Varchar) isDeleted,  
  Convert(varchar,dbo.fn_getusertimefromindiantime('+ CAST(@userid as varchar) +', lpm.DeletedOn),100) As DeletedOn  
 FROM LeadPipelineMapping lPm WITH(NOLOCK)    
 JOIN UserLeads Ul  WITH(NOLOCK) ON lPm.LeadID=Ul.ID    
 JOIN pipeline_master Pm WITH(NOLOCK) ON Pm.ID=lPm.PipelineID    
 JOIN PipelineStages Pms WITH(NOLOCK) ON Pms.ID=lpm.PipeLineStage    
 JOIN User_Detail Ud WITH(NOLOCK) ON Ud.User_ID= lpm.CreatedBy     
 JOIN User_Detail UdLo WITH(NOLOCK) ON UdLo.User_ID= lpm.DealOwner  
 Join #temp on #temp.User_ID=lpm.CreatedBy )A 
 ' +@filtertext +' ' + @sortbytext
 
 print @sqls 
 execute sp_executesql @sqls
 end
END    
    
--Usp_GetPipelineList @userid=34594,@mode='filter',@sortby='desc'   



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetPipelineList_WithSegmentation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
 CREATE   PROCEDURE [dbo].[Usp_GetPipelineList_WithSegmentation] --34594    
@userid BIGINT ,    
@pipelinename nvarchar(max)=null,    
@estfromdt datetime =null,    
@esttodt datetime =null,    
@createfromdt datetime = null,    
@createtodt datetime=null,    
@remarks nvarchar(max)=null,    
@leadname nvarchar(max)=null,  
@columnName nvarchar(max)=null,  
@sortby char(4)=null  ,
@filtertext nvarchar(max) ='',
@sortbytext nvarchar(100) = '',
@mode varchar(10) = null,  
@CriteriaName nvarchar(500) = null  
AS    
BEGIN    

  if(trim(isnull(@CriteriaName,'')) = '')  
   begin  
      exec Usp_GetPipelineList @userid , @pipelinename ,@estfromdt ,@esttodt ,@createfromdt ,@createtodt ,@remarks ,@leadname ,@columnName ,  
          @sortby ,@filtertext ,@sortbytext ,@mode   
      
       return   
   end  
               

      declare @QueryOrderbySelect nvarchar(max) = '' 
	  declare @QueryOrderbySelectFinal nvarchar(max) = ''
	  

  declare @QueryOrderby nvarchar(max) = concat( N' select  @QueryOrderbySelect =  concat( Case WHEN ''',@columnName,''' =''pipemapid'' and ''',@sortby,''' =''desc''
        Then ''lpm.ID DESC'' END , '' '' ,
		Case WHEN ''',@columnName,''' =''leadno'' and ''',@sortby,''' =''desc'' Then ''Ul.LeadNo DESC'' END , '' '' ,
		Case WHEN ''',@columnName,''' =''personname'' and ''',@sortby,''' =''desc''  Then ''Ul.PersonName DESC'' END , '' '' ,
		Case WHEN ''',@columnName,''' =''pipelinename'' and ''',@sortby,''' =''desc''  Then ''Pm.Name DESC'' END , '' '' ,
		Case WHEN ''',@columnName,''' =''pipelinestage'' and ''',@sortby,''' =''desc''  Then ''Pms.Name DESC'' END , '' '' ,
		Case WHEN ''',@columnName,''' =''createddate'' and ''',@sortby,''' =''desc''  Then ''lpm.CreatedDate DESC''  END , '' '' ,
		Case WHEN ''',@columnName,''' =''estimateddate'' and ''',@sortby,''' =''desc''  Then ''lpm.EstimatedClosureDate DESC''  END , '' '' ,
		Case WHEN ''',@columnName,''' =''deletedon'' and ''',@sortby,''' =''desc''  Then ''lpm.DeletedOn DESC''  END , '' '' ,
		Case WHEN ''',@columnName,''' =''dealowner'' and ''',@sortby,''' =''desc''  Then ''UdLo.FName DESC''  END , '' '' ,
		
		CASE WHEN ''',@columnName,''' =''pipemapid'' and ''',@sortby,''' =''asc'' Then ''lpm.ID ASC'' END , '' '' ,   
		CASE WHEN ''',@columnName,''' =''leadno'' and ''',@sortby,''' =''asc''  Then ''Ul.LeadNo ASC''  END , '' '' ,  
		CASE WHEN ''',@columnName,''' =''personname'' and ''',@sortby,''' =''asc''  Then ''Ul.PersonName ASC'' END , '' '' ,   
		CASE WHEN ''',@columnName,''' =''pipelinename'' and ''',@sortby,''' =''asc''  Then ''Pm.Name ASC'' END , '' '' ,    
		CASE WHEN ''',@columnName,''' =''pipelinestage'' and ''',@sortby,''' =''asc''  Then ''Pms.Name ASC'' END , '' '' ,    
		CASE WHEN ''',@columnName,''' =''createddate'' and ''',@sortby,''' =''asc''  Then ''lpm.CreatedDate ASC'' END , '' '' ,   
		CASE WHEN ''',@columnName,''' =''estimateddate'' and ''',@sortby,''' =''asc''  Then ''lpm.EstimatedClosureDate ASC'' END , '' '' ,    
		CASE WHEN ''',@columnName,''' =''deletedon'' and ''',@sortby,''' =''asc''  Then ''lpm.DeletedOn ASC'' END , '' '' ,
		CASE WHEN ''',@columnName,''' =''dealowner'' and ''',@sortby,''' =''asc''  Then ''UdLo.FName ASC'' END ,'''' )    ','')   


    --print @QueryOrderby
	  exec sp_executesql @QueryOrderby, N'@QueryOrderbySelect nvarchar(max) out', @QueryOrderbySelectFinal out
	-- print @QueryOrderbySelectFinal  

			   

if @sortbytext <> '' AND @sortbytext IS NOT  NULL
begin 
	set @sortbytext ='ORDER BY '+@sortbytext
end 


if @filtertext <> '' AND @filtertext IS NOT  NULL
begin 
	set @filtertext ='where '+@filtertext
end 

Create Table #temp (User_ID BIGINT, Name VARCHAR(100), IMAGE VARCHAR(100))

Declare @parentid bigint 

SELECT @parentid = parentid from User_Detail where user_id=@userid 

insert into #temp 
execute use_getUserDetails @userid
    
	/*
  declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)    
  declare @ProcParam nvarchar(max) = N''' set nocount on ; exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment 1,'
  + cast(@LeadCount as nvarchar(100))+',''''' + @Criterianame + ''''',' + cast(@UserID as nvarchar(50)) + ',0,''''Name''''    
    WITH RESULT SETS    
    (    
      (    
        ID bigint    
      )    
    )'''     
        
 -- print @ProcParam    
    
    declare @QueryTotality nvarchar(max) = concat( N' SELECT ID into #userleadsBySegment      
     FROM      
      OPENROWSET(''sqlncli11'',''Server=10.0.0.132;Database=mysms_dev;Uid=kit19;PWD=P@ssword3110;'',', @ProcParam , ')','') 

	  */

	 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID  
	
	 drop table if exists  #userleadsBySegment 
    
     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	 
	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
     declare @QueryTotality nvarchar(max) = ''



if(@mode='all')
BEGIN 
   Declare @QueryAll nvarchar(max) = Concat(@QueryTotality, ' ; ',' 
	  SELECT lpm.ID as LeadPipelinemapID,lPm.LeadID,Ul.leadNo, Ul.PersonName, Pm.Name as PipeLineName, Pm.ID as PipelineID, Pms.Name As PipeLineStage
	    , Pms.ID as PipeLineStageid, ROUND(lPm.Probability,0) AS Probability, lpm.Amount, lpm.Remarks,  
		Convert(varchar,dbo.fn_getusertimefromindiantime(', cast(@userid as nvarchar(50)) ,' , lpm.CreatedDate),100) AS CreatedDate,   
		Convert(varchar,dbo.fn_getusertimefromindiantime(', cast(@userid as nvarchar(50)) ,' , lPm.EstimatedClosureDate ),100) AS EstimatedClosureDate ,
		lpm.CreatedBy, Ud.FName, Ud.LName, Ud.User_Login,lPm.DealOwner As DealOwnerID,  
		UdLo.FName ', ' + ' ,' ','UdLo.LName', ' + ' , ''' ( '' + ', 'UdLo.User_Login' , ' + ' ,''' )''  As DealOwnerName, UdLo.User_Login As DealOwnerLogin,
		Cast (lpm.isDeleted as Varchar) isDeleted,  
		 Convert(varchar,dbo.fn_getusertimefromindiantime( ', cast(@userid as nvarchar(50)) ,' , lpm.DeletedOn),100) As DeletedOn  
		FROM LeadPipelineMapping lPm WITH(NOLOCK)    
		JOIN UserLeads Ul  WITH(NOLOCK) ON lPm.LeadID=Ul.ID    
		join #userleadsBySegment as uls on Ul.ID = uls.ID 
		JOIN pipeline_master Pm WITH(NOLOCK) ON Pm.ID=lPm.PipelineID    
		JOIN PipelineStages Pms WITH(NOLOCK) ON Pms.ID=lpm.PipeLineStage    
		JOIN User_Detail Ud WITH(NOLOCK) ON Ud.User_ID= lpm.CreatedBy     
		JOIN User_Detail UdLo WITH(NOLOCK) ON UdLo.User_ID= lpm.DealOwner  
		Join #temp as tmpUsers on tmpUsers.User_ID=lpm.CreatedBy 
		--AND lpm.IsDeleted=0    
		 where (  nullif(''', @pipelinename ,''','''') IS NULL OR Pm.Name LIKE ''%', @pipelinename ,'%'')    
		 AND (nullif(''', @estfromdt ,''','''') IS NULL OR  cast(lPm.EstimatedClosureDate as date) >
		         cast( isnull(nullif(''', @estfromdt ,''',''''),''01-Jan-1900'' ) as date  ))    
		 AND (nullif(''', @esttodt ,''','''') IS NULL OR cast( lPm.EstimatedClosureDate as date ) <
		 cast( isnull(nullif(''', @esttodt ,''',''''),''31-Jan-2100'' ) as date ))    
		 AND (nullif(''', @createfromdt ,''','''') IS NULL OR cast( lPm.CreatedDate as date ) >
		 cast( isnull(nullif(''', @createfromdt ,''',''''),''01-Jan-1900'' ) as date  ))    
		 AND (nullif(''', @createtodt , ''','''') IS NULL OR cast( lPm.CreatedDate as date )
		 < cast( isnull(nullif(''', @createtodt ,''',''''),''31-Jan-2100'' ) as date ))    
		 AND ( nullif(''', @remarks, ''','''') IS NULL OR lpm.Remarks LIKE ''%', @remarks ,'%'')    
		 AND ( nullif(''', @leadname, ''','''') IS NULL OR Ul.PersonName LIKE ''%', @leadname ,'%'')    
		 ORDER BY ', @QueryOrderbySelectFinal ,'')

     print @QueryAll
	 exec sp_executesql @QueryAll
	 
END

 ELSE IF @mode ='filter'
 begin
 DECLARE @sqls NVARCHAR(MAX)
 
 SET  @sqls = @QueryTotality + N'select LeadPipelinemapID, LeadID, leadNo, PersonName, PipeLineName, PipelineID, PipeLineStage, PipeLineStageid, Probability, Amount, Remarks,
	CreatedDate,EstimatedClosureDate, CreatedBy, FName, LName, User_Login, DealOwnerID, DealOwnerName, DealOwnerLogin,isDeleted,DeletedOn from (
 SELECT lpm.ID as LeadPipelinemapID,lPm.LeadID,Ul.leadNo, Ul.PersonName, Pm.Name as PipeLineName, Pm.ID as PipelineID, Pms.Name As PipeLineStage, Pms.ID as PipeLineStageid,     
 ROUND(lPm.Probability,0) AS Probability, lpm.Amount, lpm.Remarks,  
 Convert(varchar,dbo.fn_getusertimefromindiantime('+ CAST(@userid as varchar) +', lpm.CreatedDate),100) AS CreatedDate,   
 Convert(varchar,dbo.fn_getusertimefromindiantime('+ CAST(@userid as varchar) +', lPm.EstimatedClosureDate ),100) AS EstimatedClosureDate , lpm.CreatedBy, Ud.FName, Ud.LName, Ud.User_Login,lPm.DealOwner As DealOwnerID,  
  UdLo.FName+'' ''+ UdLo.LName +''(''+ +UdLo.User_Login+'')'' As DealOwnerName, UdLo.User_Login As DealOwnerLogin,Cast (lpm.isDeleted as Varchar) isDeleted,  
  Convert(varchar,dbo.fn_getusertimefromindiantime('+ CAST(@userid as varchar) +', lpm.DeletedOn),100) As DeletedOn  
 FROM LeadPipelineMapping lPm WITH(NOLOCK)    
 JOIN UserLeads Ul  WITH(NOLOCK) ON lPm.LeadID=Ul.ID
 join #userleadsBySegment as uls on Ul.ID = uls.ID 
 JOIN pipeline_master Pm WITH(NOLOCK) ON Pm.ID=lPm.PipelineID    
 JOIN PipelineStages Pms WITH(NOLOCK) ON Pms.ID=lpm.PipeLineStage    
 JOIN User_Detail Ud WITH(NOLOCK) ON Ud.User_ID= lpm.CreatedBy     
 JOIN User_Detail UdLo WITH(NOLOCK) ON UdLo.User_ID= lpm.DealOwner  
 Join #temp on #temp.User_ID=lpm.CreatedBy )A 
 ' +@filtertext +' ' + @sortbytext
 
 print @sqls 
 execute sp_executesql @sqls
 end

   drop table if exists  #userleadsBySegment 

END    
    
