/* ============================================================
   Procedure: [dbo].[Usp_GetPipelinesFromLeadID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetPipelinesFromLeadID
(
  @LeadID bigint
)
as
Begin

    select * from Pipeline_Master    
  where  ID in (    
            
     select distinct P.ID as PipelineID  from     
    Pipeline_Master P     
    join PipelineStages S on P.id=S.PipelineID    
    join LeadPipelineMapping e on e.PipeLineStage=S.ID    
    where e.isdeleted=0 and e.LeadID=@LeadID and    
   -- e.id = (select max(id) from EnqPipelineMapping where Enqno=e.Enqno and PipeLineStageID=e.PipeLineStageID)    
   e.id in (select isnull(id,0) from LeadPipelineMapping where LeadID=e.LeadID and PipeLineStage=e.PipeLineStage)    
  )  

End


GO

