/* ============================================================
   Procedure: [dbo].[Usp_GetPipelineStagesByMassPipelines]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetPipelineStagesByMassPipelines  --358 --492 --'2,3,4'    
(      
  @PiplineIDCollections nvarchar(max)      
)      
as      
Begin      
     select pstg.id  as PipelineStageID , ppln.ID as PipelineID ,ppln.Name as PiplineName , pstg.Name + '('+ppln.name+')' as PipelineStage, pstg.Name as StageName  from PipelineStages(nolock) as pstg      
     join Pipeline_Master(nolock) as ppln              
        on pstg.PipelineID = ppln.ID and  isnull(pstg.IsDeleted,0) = 0 
    where  isnull(ppln.IsDeleted,0) = 0   
    and ppln.ID in (select value as bigint from fn_Split(@PiplineIDCollections,','))  
	and isnull(pstg.IsDeleted,0) = 0
	order by pstg.Sequence asc    
 end   


GO

