/* ============================================================
   Procedure: [dbo].[Usp_GetPredefcustomFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

           
              
CREATE   PROCEDURE [dbo].[Usp_GetPredefcustomFields]                
                
    @userId bigint,            
 @apiname varchar(20)=null ,          
 @fieldid bigint=null,          
 @mode varchar(10)=null          
                
as                 
begin                
declare @parentid int = (Select ParentID from User_Detail where User_ID= @userId)                
-- declare @parentid int = 34594, @apiname varchar(20) = 'JustDial'               
drop table if exists #temp            
create table #temp (            
ID varchar(100),            
COLUMN_NAME varchar(100),            
DATA_TYPE varchar(100)  ,          
Fieldtype varchar(10)          
)            
if @mode='all'          
BEGIN          
if(@apiname='JustDial')            
BEGIN            
insert into #temp             
 select COLUMN_NAME as ID ,COLUMN_NAME,DATA_TYPE,'enq' as Fieldtype from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='UserEnquiry'  and COLUMN_NAME not in                 
 ('PersonName','MobileNo','EmailID','CountryCode','PinCode','InitialRemarks', 'EnquiryID', 'ParentID', 'CreatedDate', 'CreatedBy', 'IsOpen', 'LeadNo', 'img_ext', 'ProfileImgFileName',                
 'enquirysource',  'WhatsAppNoColName', 'whereAddress', 'latitude', 'longitude','IsduplicateEmail','IsduplicateMobile')                  
 END            
            
 else if(@apiname='IndiaMart')            
BEGIN            
insert into #temp             
 select COLUMN_NAME as ID ,COLUMN_NAME,DATA_TYPE, 'enq' as Fieldtype from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='UserEnquiry' and COLUMN_NAME not in                 
 ('PersonName','MobileNo','EmailID','CountryCode','MobileNo1', 'EmailID1', 'CountryCode1', 'CompanyName', 'OfficeAddress', 'ResidentialAddress', 'City', 'State',             
 'Country','PinCode','InitialRemarks', 'EnquiryID', 'ParentID', 'CreatedDate', 'CreatedBy', 'IsOpen', 'LeadNo', 'img_ext', 'ProfileImgFileName',                
 'enquirysource',  'WhatsAppNoColName', 'whereAddress', 'latitude', 'longitude','IsduplicateEmail','IsduplicateMobile')                  
 END            
 else if(@apiname='TradeIndia')            
BEGIN            
insert into #temp             
 select COLUMN_NAME as ID ,COLUMN_NAME,DATA_TYPE, 'enq' as Fieldtype from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME='UserEnquiry' and COLUMN_NAME not in                 
 ('PersonName','MobileNo','EmailID','CountryCode','MobileNo1', 'EmailID1', 'CountryCode1', 'CompanyName', 'OfficeAddress', 'ResidentialAddress', 'City', 'State',             
 'Country','PinCode','InitialRemarks',  'EnquiryID', 'ParentID', 'CreatedDate', 'CreatedBy', 'IsOpen', 'LeadNo', 'img_ext',             
 'ProfileImgFileName','enquirysource',  'WhatsAppNoColName', 'whereAddress', 'latitude', 'longitude','IsduplicateEmail','IsduplicateMobile')                  
 END            
 else if(@apiname='Sulekha')            
