/* ============================================================
   Procedure: [dbo].[usp_GetPreEnquiryExecute]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetPreEnquiryExecute --7,'',0
	@SearchID BIGINT,
	@SearchText VARCHAR(50) = NULL,
	@PageSize INT = 0
AS
BEGIN
	BEGIN TRY
		EXEC [CRM].CRMDB.dbo.usp_GetPreEnquiryExecuteinCRM @SearchID  
		
		IF (@PageSize = 0)
		BEGIN
		    SELECT DISTINCT TOP 100 msd.EnqNo,
		           msd.Name,
		           msd.Mobile_No,
		           msd.Mobile_No2,
		           msd.Mobile_No3,
		           msd.R_Address,
		           msd.O_Address,
		           msd.Executive,
		           msd.ServiceName,
		           msd.[Status],
		           msd.VisitStatus,
		           msd.MeetingStatus,
		           msd.EMail,
		           msd.Email2,
		           msd.Email3,
		           msd.company_name,
		           (
		               SELECT COUNT(*)
		               FROM   [CRM].CRMDB.dbo.MYSMSSearchDetails 
		                      msd
		               WHERE  msd.SearchID = @SearchID
		           ) AS Total_Records
		    FROM   [CRM].CRMDB.dbo.MYSMSSearchDetails msd
		    WHERE  msd.SearchID = @SearchID
		           AND (
		                   ISNULL(@SearchText, '') = ''
		                   OR msd.Mobile_No LIKE '%' + @SearchText + '%'
		                   OR msd.Mobile_No2 LIKE '%' + @SearchText + '%'
		                   OR msd.Mobile_No3 LIKE '%' + @SearchText + '%'
		                   OR msd.Name LIKE '%' + @SearchText + '%'
		                   OR msd.R_Address LIKE '%' + @SearchText + '%'
		                   OR msd.O_Address LIKE '%' + @SearchText + '%'
		                   OR msd.Executive LIKE '%' + @SearchText + '%'
		                   OR msd.[Status] LIKE '%' + @SearchText + '%'
		                   OR msd.ServiceName LIKE '%' + @SearchText + '%'
		                   OR msd.VisitStatus LIKE '%' + @SearchText + '%'
		                   OR msd.MeetingStatus LIKE '%' + @SearchText + '%'
		                   OR msd.EMail LIKE '%' + @SearchText + '%'
		                   OR msd.Email2 LIKE '%' + @SearchText + '%'
		                   OR msd.Email3 LIKE '%' + @SearchText + '%'
		                   OR msd.company_name LIKE '%' + @SearchText + '%'
		               )
		END
		ELSE
		BEGIN
		    SELECT DISTINCT msd.EnqNo,
		           msd.Name,
		           msd.Mobile_No,
		           msd.Mobile_No2,
		           msd.Mobile_No3,
		           msd.R_Address,
		           msd.O_Address,
		           msd.Executive,
		           msd.ServiceName,
		           msd.[Status],
		           msd.VisitStatus,
		           msd.MeetingStatus,
		           msd.EMail,
		           msd.Email2,
		           msd.Email3,
		           msd.company_name,
		           (
		               SELECT COUNT(*)
		               FROM   [CRM].CRMDB.dbo.MYSMSSearchDetails 
		                      msd
		               WHERE  msd.SearchID = @SearchID
		           ) AS Total_Records
		    FROM   [CRM].CRMDB.dbo.MYSMSSearchDetails msd
		    WHERE  msd.SearchID = @SearchID
		           AND (
		                   ISNULL(@SearchText, '') = ''
		                   OR msd.Mobile_No LIKE '%' + @SearchText + '%'
		                   OR msd.Mobile_No2 LIKE '%' + @SearchText + '%'
		                   OR msd.Mobile_No3 LIKE '%' + @SearchText + '%'
		                   OR msd.Name LIKE '%' + @SearchText + '%'
		                   OR msd.R_Address LIKE '%' + @SearchText + '%'
		                   OR msd.O_Address LIKE '%' + @SearchText + '%'
		                   OR msd.Executive LIKE '%' + @SearchText + '%'
		                   OR msd.[Status] LIKE '%' + @SearchText + '%'
		                   OR msd.ServiceName LIKE '%' + @SearchText + '%'
		                   OR msd.VisitStatus LIKE '%' + @SearchText + '%'
		                   OR msd.MeetingStatus LIKE '%' + @SearchText + '%'
		                   OR msd.EMail LIKE '%' + @SearchText + '%'
		                   OR msd.Email2 LIKE '%' + @SearchText + '%'
		                   OR msd.Email3 LIKE '%' + @SearchText + '%'
		                   OR msd.company_name LIKE '%' + @SearchText + '%'
		               )
		END
	END TRY
	BEGIN CATCH
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END 



GO

