/* ============================================================
   Procedure: [dbo].[Usp_GetPremiumCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**********************                    
SP use for Insert Record in PremiumMessage                    
********************/                    
CREATE   PROC [dbo].[Usp_GetPremiumCount] --4200276                     
@BATCHID bigint                       
AS                      
Begin                     
                     
Declare @UserId int,@dnd int,@invalid int,@filterMode int,@total int,@priority int,@UserFilter varchar(20)                      
Declare @COUNTPERCENTAGE Int                      
Declare @SendPercentByDnd int,@SendPercentByInvalid int,@totalSend int,@Dnddeduct int,@InvalidDeduct int                     
Declare @RemainMesage int                      
Declare @count int,@Allowdnd int,@msgSource int,@PremiumCount bigint                      
-----------------------------                    
create table #Temptable    
(                                
MessageSourceID  bigint,                                 
MessageID bigint,                                 
Mobile nvarchar(20),                                 
[Message] nvarchar(2000),                                 
SENDerID nvarchar(100),                                 
SmppID tinyint,                                 
Priority tinyint,                                 
U_ID bigint,                                 
IsUniCode bit,                                 
IsDND bit,                                 
Operator varchar(6),                                 
MessageBatchID nchar(20),                                 
Isallowdnd tinyint)                        
---------------------------                     
SELECT top(1) @dnd=Dnd,@total=total,@UserId=userid,@invalid=Invalid FROM Message_detail with(nolock) WHERE batchid=@BATCHID                        
        
select top(1) @FilterMode=isnull(filterMode,0) from batchinfo with(nolock) WHERE BatchID=@BATCHID        
                 
if @FilterMode=0          
begin         
select top(1) @FilterMode=isnull(filterMode,1) from user_detail with(nolock)  where user_id=@UserId           
end       
select top(1) @UserFilter=isnull(UserFilter,'MTIX_PRO') from user_detail with(nolock) where user_id=@UserId           
         
select top(1) @Allowdnd=isnull(Isallowdnd,0) from MessageSource with(nolock) WHERE MessageBatchID=@BATCHID                            
select top(1) @priority=Isnull(IsPrority,0) from batchinfo with(nolock) WHERE BatchID=@BATCHID               
select  @msgSource=IsNull(Count(mobile),0) from MessageSource with(nolock) WHERE MessageBatchID=@BATCHID                            
select top(1) @PremiumCount=count(isnull(messageid,0)) from PremiumMessage  with(nolock)  where batchid=@BATCHID --and priority=0                        
                       
 IF @total > 98                    
Begin                    
IF @priority = 0                    
Begin                     
Set @RemainMesage=@total-@dnd-@invalid                 
 set @COUNTPERCENTAGE=0               
 Set @totalSend= 0              
set @SendPercentByDnd=0                    
if @Allowdnd=0                    
Begin                    
 Set @RemainMesage=@total-@dnd-@invalid                    
End                    
Else If @Allowdnd=2                    
 Begin                    
SET @RemainMesage=@total-@invalid                    
SET @dnd=0                    
End                    
Else If @Allowdnd=3                    
 Begin                    
SET @RemainMesage=@total-@invalid                    
SET @dnd=0                    
 End                     
                    
IF 1=1--(@UserFilter='MTIX_TRC' OR  @UserFilter='MTIX_PRO')      
BEGIN                    
SET @SendPercentByDnd=(dbo.RETURNPERCENTAGE(@total,10*isnull(@filtermode,1),@dnd))                       
SET @SendPercentByInvalid=(dbo.RETURNPERCENTAGE(@total,10*isnull(@filtermode,1),@invalid))                     
END      
      
Set @totalSend= @SendPercentByDnd                    
Set @COUNTPERCENTAGE= @RemainMesage - @SendPercentByDnd                    
IF @COUNTPERCENTAGE < 0                    
Begin                    
set @COUNTPERCENTAGE=0                    
    End                    
                   
if @PremiumCount>0              
BEGIN              
IF @PremiumCount<@COUNTPERCENTAGE              
 BEGIN              
  SET @COUNTPERCENTAGE=@COUNTPERCENTAGE-@PremiumCount                    
 END              
 ELSE              
 BEGIN              
 SET @COUNTPERCENTAGE=0              
 END              
               
END                      
    
declare @countt int    
while(@COUNTPERCENTAGE > 0)       -- and @FilterMode <> 10                          
  Begin      
RETRY:                                             
BEGIN TRY                                          
BEGIN TRAN    
select @countt=dbo.fn_Min_No(@COUNTPERCENTAGE,1000)  
  INSERT INTO #Temptable(MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,IsDND,Operator,MESSAGEBATCHID,Isallowdnd)                                 
  select top (@countt) MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,IsDND, Operator,   
  MESSAGEBATCHID,Isallowdnd from MESSAGESOURCE  with(nolock)  WHERE     MESSAGEBATCHID=@BATCHID                        
                                  
  INSERT INTO PremiumMessage(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,    
  IsDND, Operator, BatchID,Isallowdnd)                                 
  SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                 
  IsDND, Operator, MessageBatchID,Isallowdnd FROM #Temptable                                 
                                  
  DELETE MESSAGESOURCE FROM MESSAGESOURCE JOIN #Temptable tmp ON MESSAGESOURCE.MessageID=tmp.MessageID                    
  delete from #Temptable       
      
  set @COUNTPERCENTAGE=@COUNTPERCENTAGE-@countt     
COMMIT                                          
END TRY                                          
BEGIN CATCH      
IF @@TRANCOUNT>0                                          
ROLLBACK                                          
EXECUTE USP_INSERTERRORINFO;     
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number    
BEGIN    
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms    
GOTO RETRY -- Go to Label RETRY    
END                                               
END CATCH                              
  End      
      
drop table #Temptable                     
                           
update Message_detail set process=@totalSend,Premium=Premium+@COUNTPERCENTAGE,RemainMessage=RemainMessage+@RemainMesage,MessageinSource=@msgSource,FilterMode=@FilterMode,Allowdnd=@Allowdnd where Batchid=@BATCHID                      
END                     
End                     
                     
End 



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetPremiumCount_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**********************                            
SP use for Insert Record in PremiumMessage                            
********************/                            
CREATE   PROC [dbo].[Usp_GetPremiumCount_new] --4200276                             
@BATCHID bigint                               
AS                              
Begin                             
Declare @UserId int,@dnd int,@invalid int,@filterMode int,@total int,@priority int,@UserFilter varchar(20)                              
Declare @COUNTPERCENTAGE Int  =0                            
Declare @SendPercentByDnd int,@SendPercentByInvalid int,@totalSend int=0,@Dnddeduct int,@InvalidDeduct int                             
Declare @RemainMesage int                              
Declare @count int,@Allowdnd int,@msgSource int,@PremiumCount bigint =0 ,@tobededucted int,@tobesent int                            
-----------------------------                            
create table #Temptable            
(                                        
MessageSourceID  bigint,                                         
MessageID bigint,                                         
Mobile nvarchar(20),                                         
[Message] nvarchar(2000),                                         
SENDerID nvarchar(100),                                         
SmppID tinyint,                                         
Priority tinyint,                                         
U_ID bigint,                                         
IsUniCode bit,                                         
IsDND bit,                                         
Operator varchar(6),                                         
MessageBatchID nchar(20),                                         
Isallowdnd tinyint)                                
---------------------------                             
--SELECT top(1) @invalid=Invalid FROM Message_detail with(nolock) WHERE batchid=@BATCHID                                
select top(1) @FilterMode=isnull(filterMode,0),@UserId=userid,@total=totalrecords,@priority=Isnull(IsPrority,0) from batchinfo with(nolock) WHERE BatchID=@BATCHID                
select @msgSource=count(1) from MessageSource (nolock) where messagebatchid=@batchid                         
select @premiumcount=count(1) from premiummessage(nolock) where batchid=@batchid     
select @PremiumCount=isnull(@premiumcount,0)    
if @FilterMode=0                  
begin                 
select top(1) @FilterMode=isnull(filterMode,1) from user_detail with(nolock)  where user_id=@UserId                   
end               
      
select top(1) @UserFilter=isnull(UserFilter,'MTIX_PRO') from user_detail with(nolock) where user_id=@UserId                   
                              
IF @total > 98                            
Begin        
set @SendPercentByDnd=(dbo.RETURNPERCENTAGE(@total,10*isnull(@filtermode,1),0))        
select @tobesent=isnull(@SendPercentByDnd,0)    
select @tobededucted=@total-@tobesent    
SET @COUNTPERCENTAGE=@tobededucted-@premiumcount--isnull(@total-@SendPercentByDnd,0)    
      
IF @COUNTPERCENTAGE < 0        
Begin                            
set @COUNTPERCENTAGE=0                            
End                            
END                              
            
declare @countt int            
while(@COUNTPERCENTAGE > 0)       -- and @FilterMode <> 10                                  
Begin              
RETRY:                                                     
BEGIN TRY                                                  
BEGIN TRAN            
select @countt=dbo.fn_Min_No(@COUNTPERCENTAGE,1000)          
INSERT INTO #Temptable(MessageSourceID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,IsDND,Operator,MESSAGEBATCHID,Isallowdnd)                                         
select top (@countt) MessageSourceID,MessageID,m.Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,IsDND, Operator, MESSAGEBATCHID,Isallowdnd 
from MESSAGESOURCE m with(nolock)  left join clientmobile c with (nolock) on c.Mobile=m.mobile
where c.id is null and MESSAGEBATCHID=@BATCHID                          
                                          
  INSERT INTO PremiumMessage(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,            
  IsDND, Operator, BatchID,Isallowdnd)                                         
  SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                         
  IsDND, Operator, MessageBatchID,Isallowdnd FROM #Temptable                                         
  select @PremiumCount=@PremiumCount+@@ROWCOUNT       
         
  DELETE MESSAGESOURCE FROM MESSAGESOURCE JOIN #Temptable tmp ON MESSAGESOURCE.MessageID=tmp.MessageID                            
  delete from #Temptable               
              
  set @COUNTPERCENTAGE=@COUNTPERCENTAGE-@countt             
COMMIT                                                  
END TRY                                                  
BEGIN CATCH              
IF @@TRANCOUNT>0                                                  
ROLLBACK                                                  
EXECUTE USP_INSERTERRORINFO;             
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number            
BEGIN            
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms            
GOTO RETRY -- Go to Label RETRY            
END                                                       
END CATCH                                      
End              
select @premiumcount=isnull((select count(1) from premiummessage(nolock) where batchid=@batchid),0)     
              
drop table #Temptable                             
                                   
update Message_detail set dnd=0,invalid=0,process=0,Premium=@PremiumCount,RemainMessage=@SendPercentByDnd,  
MessageinSource=@msgSource,      
FilterMode=@FilterMode,Allowdnd=0 where Batchid=@BATCHID                              
END 


GO

