MessageID bigint,                                         
Mobile nvarchar(20),                                         
[Message] nvarchar(2000),                                         
SENDerID nvarchar(100),                                         
SmppID tinyint,                                         
Priority tinyint,                                         
U_ID bigint,                                         
IsUniCode bit,                                         
IsDND bit,                                         
Operator varchar(6),                                         
MessageBatchID nchar(20),                                         
Isallowdnd tinyint)                                
---------------------------                             
--SELECT top(1) @invalid=Invalid FROM Message_detail with(nolock) WHERE batchid=@BATCHID                                
select top(1) @FilterMode=isnull(filterMode,0),@UserId=userid,@total=totalrecords,@priority=Isnull(IsPrority,0) from batchinfo with(nolock) WHERE BatchID=@BATCHID                
select @msgSource=count(1) from MessageMonitor (nolock) where batchid=@batchid                         
select @premiumcount=count(1) from premiummessage(nolock) where batchid=@batchid     
select @PremiumCount=isnull(@premiumcount,0)    
if @FilterMode=0                  
begin                 
select top(1) @FilterMode=isnull(filterMode,1) from user_detail with(nolock)  where user_id=@UserId                   
end               
      
select top(1) @UserFilter=isnull(UserFilter,'MTIX_PRO') from user_detail with(nolock) where user_id=@UserId                   
                              
IF @total > 98                            
Begin        
set @SendPercentByDnd=(dbo.RETURNPERCENTAGE(@total,10*isnull(@filtermode,1),0))        
select @tobesent=isnull(@SendPercentByDnd,0)    
select @tobededucted=@total-@tobesent    
SET @COUNTPERCENTAGE=@tobededucted-@premiumcount--isnull(@total-@SendPercentByDnd,0)    
      
IF @COUNTPERCENTAGE < 0        
Begin                            
set @COUNTPERCENTAGE=0                            
End                            
END                              

print concat('Batchid: ',@batchid,' before clientmsg: total count: ',@total,'@tobesent: ',@tobesent,', @tobedeductedtotal: ',@tobededucted,', @tobedeductedexcPremium: ',@COUNTPERCENTAGE )
drop table if exists #clientmsg
SELECT MessageMonitorID into #clientmsg
from MessageMonitor p with(nolock)  join mysms.dbo.clientmobile c with (nolock) on p.mobile=c.mobile             
WHERE BATCHID = @BATCHID     
select @COUNTPERCENTAGE=@COUNTPERCENTAGE-(select count(1) from #clientmsg)

print concat('Batchid: ',@batchid,' after clientmsg: total count: ',@total,'@tobesent: ',@tobesent,', @tobedeductedtotal: ',@tobededucted,', @tobedeductedexcPremium: ',@COUNTPERCENTAGE )
            
declare @countt int            
while(@COUNTPERCENTAGE > 0)       -- and @FilterMode <> 10                                  
Begin              
RETRY:                                                     
BEGIN TRY                                                  
BEGIN TRAN            
select @countt=dbo.fn_Min_No(@COUNTPERCENTAGE,1000)          
INSERT INTO #Temptable(MessageMonitorID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,IsDND,Operator,MESSAGEBATCHID,Isallowdnd)                                         
select top (@countt) MessageMonitorID,MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,IsDND, Operator, BATCHID,Isallowdnd from MessageMonitor  with(nolock)  WHERE BATCHID=@BATCHID  
and  MessageMonitorID not in (select MessageMonitorID from #clientmsg )                                         
                                          
  INSERT INTO PremiumMessage(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,            
  IsDND, Operator, BatchID,Isallowdnd)                                         
  SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                         
  IsDND, Operator, MessageBatchID,Isallowdnd FROM #Temptable 
  select @PremiumCount=@PremiumCount+@@ROWCOUNT       
   
   
print concat('Batchid: ',@batchid,' while ongoing: total Premium: ',@PremiumCount, ', to be deducted: ',@COUNTPERCENTAGE )

  DELETE MessageMonitor FROM MessageMonitor JOIN #Temptable tmp ON MessageMonitor.MessageID=tmp.MessageID                            
  delete from #Temptable               
              
  set @COUNTPERCENTAGE=@COUNTPERCENTAGE-@countt             
COMMIT                                                  
END TRY                                                  
BEGIN CATCH              
IF @@TRANCOUNT>0                                                  
ROLLBACK                                                  
EXECUTE USP_INSERTERRORINFO;             
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number            
BEGIN            
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms            
GOTO RETRY -- Go to Label RETRY            
END                                                       
END CATCH                                      
End              
select @premiumcount=isnull((select count(1) from premiummessage(nolock) where batchid=@batchid),0)     
 print concat('Batchid: ',@batchid,' Final total Premium: ',@PremiumCount)
             
drop table #Temptable                             
                                   
update Message_detail set dnd=0,invalid=0,process=0,Premium=@PremiumCount,RemainMessage=@SendPercentByDnd,  
MessageinSource=@msgSource,      
FilterMode=@FilterMode,Allowdnd=0 where Batchid=@BATCHID                              
END 






GO

