/* ============================================================
   Procedure: [dbo].[usp_GetProcedureParametersAsJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetProcedureParametersAsJson
(
    @ProcedureName NVARCHAR(256),
    @DisplayName NVARCHAR(256)
)
AS
BEGIN

    --DECLARE 
    --    @ProcedureName NVARCHAR(256) = 'usp_fb_RemoveOldIntegrationByParentId',
    --    @DisplayName NVARCHAR(256) = 'Remove old facebook integrations by ParentId'

    SET NOCOUNT ON;

    DECLARE 
        @ParameterJson NVARCHAR(MAX) = N'{}'

    SET @ParameterJson = (

    SELECT 
        ParameterName = p.name,
        DataType = t.name,
        MaxLength = p.max_length,
        Precision = p.precision,
        Scale = p.scale,
        IsOutput = CASE WHEN p.is_output = 1 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END
    FROM sys.parameters p
    INNER JOIN sys.types t ON p.user_type_id = t.user_type_id
    INNER JOIN sys.objects o ON p.object_id = o.object_id
    WHERE o.type = 'P' 
      AND o.name = @ProcedureName
    FOR JSON PATH)

    if(not exists(select * from tbl_internalOperationProcedures(nolock) where ProcedureName = @ProcedureName))
    begin
        insert into tbl_internalOperationProcedures
            (ProcedureName, DisplayName, ParameterJson)
        select @ProcedureName, @DisplayName, @ParameterJson
    end

    
END



GO

