SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetProductDemoBySearch]  --'a',34594    
(    
  @ProductNameOrDesc nvarchar(500),    
  @UserID bigint    
)    
as    
Begin    
  Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserID )  

	exec Usp_createProductMasterTable @ParentID

	Declare @Query nvarchar(max) = Concat( N' 

   select    
   PM.ProductID     
   ,PM.Name    
     ,    
   (    
     case when  isnull(nullif(PM.[Image],''''),'''')  <> '''' then PM.[Image]    
       else ''ProductImages/SampleProduct.jpg''    
    end     
   ) as [Image]    
     ,PM.[Description]    
     ,PM.[Price]    
     ,PM.[CreatedOn]    
     ,PM.[CreatedBy]    
     ,(    
     case when  isnull(nullif(PM.FullPath,''''),'''')  <> '''' then FullPath    
       else ''https://docs.kit19.com/kit19/ProductImages/SampleProduct.jpg''    
    end     
   ) as FullPath    
     ,PM.[sku]    
     ,PM.[category_id]    
  ,pc.CategoryName    
     ,PM.[SellingAccount]    
     ,PM.[CostPrice]    
     ,PM.[Cast_Account]    
      from tbl_ProductMaster_', Cast(@ParentID as nvarchar(max)),' (nolock) as PM    
   left join Product_Category(nolock) as PC             
      on Pm.category_id = PC.id    
      
    where ((PM.Name like ''%',@ProductNameOrDesc,'%'') or (PM.Description like ''%',@ProductNameOrDesc,'%''))
	           and PM.USERID = ',Cast(@UserID as nvarchar(max)) , ' and isnull(PM.IsActive,0) = 1    
	            ')
         
		 print @Query
         exec sp_executesql @Query 

End


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetProductDetailByProductID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetProductDetailByProductID] --14063,32222  --'63',44601
(  
 @ProductID bigint,  
 @userid bigint  
)  
 as                      
 Begin                      
    -- declare @ProductID bigint =1, @userid bigint =34594        
   Declare @sqls nvarchar(max) ='',@status int, @tableName nvarchar(max) =''           
   declare @parentid bigint = (Select ParentID from User_Detail where user_id = @userid)          
   DECLARE @fjson nVARCHAR(max)='';          
 drop table if exists #temp         
        
 create table #temp (id int identity)        
        
     EXEC @status = Usp_CreateProductTableByParentID @userid, @tableName output   
	 
	-- print cast(@parentid as nvarchar) 

  declare @col varchar(max), @col1 varchar(max)         
  (Select @col = string_agg(COLUMN_NAME+' nvarchar(max)',','),@col1=string_agg(COLUMN_NAME,',') From INFORMATION_SCHEMA.COLUMNS where TABLE_NAME=@tableName and TABLE_CATALOG=db_name() and COLUMN_NAME not in ('ProductID','Name','UserID','Image','Description'
,'Price','IsPublished','IsActive','CreatedOn','CreatedBy','FullPath','IsFeatured','sku','sale_priceNoUSE','quantity','category_id','HomeTaxIDs','OtherTaxIDs','tax_idNoUSE','UpdatedAt','DeletedAt','SellingAccount','CostPrice','Cast_Account','I
sDigitalService','IsGoods','IsServices','SACCode','HSNCode','IsTaxable','DecimalRateItemQuantity','UnitID','IsSaleable', 'ThumbnailUrl','VariantsJson','VCombinationJson')  )    
   
 if @col is not null   
 Begin  
   exec('alter table #temp add ' + @col)         
    set @sqls = ' insert into #temp select '+@col1+' from  '+@tableName+' where ProductID='+cast(@ProductId as varchar)+''        
    print @sqls        
        Execute sp_executesql @sqls        
   -- select  * from #temp        
    set  @fjson= (select  * from #temp for json auto,include_null_values)    
	print @fjson
   -- set @fjson = ''
	--select @fjson        
   END     
    
	--print 'step 1'

   SET @sqls= concat( N'          
   select distinct * from (                             
   SELECT PM.ProductID, PM.Name, PM.UserID, PM.Image, PM.Description, isnull(PM.Price, 0) as Price , PM.IsPublished, PM.IsActive, PM.CreatedOn, PM.CreatedBy, PM.FullPath, PM.IsFeatured, 
   isnull(PM.IsSaleable, 1) as IsSaleable, isnull(PM.sku, '''') as sku, isnull(PM.quantity, 0) as quantity , isnull(PM.category_id, 0) as category_id, PC.CategoryName, 
   isnull(PM.HomeTaxIDs, '''') as HomeTaxIDs,            
   (select stuff                            
    (  
      ( select '','' + tbl2.name + ''('' + cast(tbl2.rate as nvarchar(100)) + ''%)'' from  
      (select name,rate                            
      from MySMSInvoicing.dbo.taxes(nolock)                              
     where id in                            
     (                            
        select cast(isnull(nullif(value,''''),0) as bigint) as id  from fn_Split(PM.HomeTaxIDs,'','')  
     )) as tbl2                            
      FOR XML PATH('''')), 1, 1, '''')                            
     ) as HomeTaxesByName ,PM.OtherTaxIDs,                            
   (select stuff                            
       (  
           (select '','' + tbl2.name + ''('' + cast(tbl2.rate as nvarchar(100)) + ''%)'' from                      
      (select name,rate  
    from MySMSInvoicing.dbo.taxes(nolock)  
   where id in  
   (                            
  select cast(isnull(nullif(value,''''),0) as bigint) as id  from fn_Split(PM.OtherTaxIDs,'','')  
   )) as tbl2                            
   FOR XML PATH('''')), 1, 1, '''')                            
 ) as OtherTaxesByName,  
  PM.UpdatedAt, PM.DeletedAt, isnull(PM.SellingAccount, 0) as SellingAccount , ACNT_selling.name as SellingAccountName, isnull(PM.CostPrice, 0) as CostPrice, 
  isnull(PM.Cast_Account, 0) as Cast_Account,ACNT_cost.name as CostAccountName, isnull(PM.IsDigitalService,0) as IsDigitalService, isnull(PM.IsGoods, 0) as IsGoods, 
  isnull(PM.IsServices, 0) as IsServices, PM.SACCode, PM.HSNCode, isnull(PM.IsTaxable, 0) as IsTaxable, isnull(PM.DecimalRateItemQuantity, 0) as DecimalRateItemQuantity,        
   isnull(PM.UnitID,0) as UnitID ,UN.unitdisplay,                            
    (select stuff(  
    ( select '','' + tbl.Tag from                             
      (select TM.Tag from EntityTagMapping(nolock) as ETM left join TagMaster(nolock) as TM                        
     on ETM.TagID = TM.ID 
	     and ETM.TM_ParentID = ' + cast(@UserID AS NVARCHAR) + '  
     where ETM.Entity = ''Product'' 
	    and   ETM.TM_ParentID = ' + cast(@UserID AS NVARCHAR) + '  
	 and ETM.EntityID = PM.ProductID) as tbl                            
   FOR XML PATH('''')), 1, 1, '''')                            
    ) as ProductTags ,
	
 ltrim(rtrim((select                            
     stuff(                             
    ( select '', '' + tbl.Tag + '':'' +cast(tbl.ID as nvarchar(100)) from                             
      (select TM.ID,tm.Tag from EntityTagMapping(nolock) as ETM left join TagMaster(nolock) as TM  
     on ETM.TagID = TM.ID
	     and ETM.TM_ParentID = ' + cast(@UserID AS NVARCHAR) + '  
     where ETM.Entity = ''Product'' 
	     and ETM.TM_ParentID = ' + cast(@UserID AS NVARCHAR) + '     
	 and ETM.EntityID = PM.ProductID) as tbl                            
   FOR XML PATH('''')), 1, 1, '''')                            
    )))as ProductTagsByID , 
	
    (select stuff(                             
    ( select '','' + tbl.ImageURL from                             
      (                       
     select isnull(PIMinner.ImageURL,'''') as ImageURL from ProductImageMapping(nolock) as PIMinner where PIMinner.ProductID = PM.ProductID  
	          and isnull(PIMinner.ParentID,0) = ' + cast(@parentid AS NVARCHAR) + '    
    ) as tbl                            
   FOR XML PATH('''')), 1, 1, '''')                            
    ) as ProductImages , ThumbnailUrl
	, 
	'''+@fjson+N''' as customjson,PM.VariantsJson,PM.VCombinationJson  
   FROM '+@tableName+N'(nolock) as PM left  join [MySMSInvoicing].[dbo].[accounts](nolock) as ACNT_cost            
   on PM.Cast_Account = ACNT_cost.id left  join [MySMSInvoicing].[dbo].[accounts](nolock) as ACNT_selling  
  on PM.SellingAccount = ACNT_selling.id left join unit(nolock) as UN  
  on Pm.UnitID = UN.id left join Product_Category(nolock) as PC  
  on Pm.category_id = PC.id left join ProductImageMapping(nolock) as PIM  
  on PM.ProductID = PIM.ProductID and isnull(PIM.ParentID,0) = ' + cast(@parentid AS NVARCHAR) + '  
   where PM.ProductID = '+cast ( @ProductID as varchar)+N'                      
    )                          
  as O_TBL','')           
          
 -- select len(@sqls)        
 print cast(@sqls as varchar(max))        
 EXECUTE sp_executesql @sqls          
           
  End  


GO

