CREATE   PROCEDURE [dbo].[Usp_GetProductDetailsByProductID] --8743  
  (  
    @ProductID bigint  
  )  
  as  
  Begin  
  
  SELECT
       PM.[ProductID]  
      ,PM.[Name]  
      ,PM.[UserID]  
      ,PM.[Image]  
      ,PM.[Description]  
      ,PM.[Price]  
      ,PM.[IsPublished]  
      ,PM.[IsActive]  
      ,PM.[CreatedOn]  
      ,PM.[CreatedBy]  
      ,PM.[FullPath]  
   ,isnull((select  
  stuff  
      (   
    (select '#' + tbl.ImageURL from  
        (select ImageURL from productImageMapping with (nolock) where ProductID = PM.ProductID ) as tbl  
        FOR XML PATH('')), 1, 1, '')),PM.FullPath)as ImageFullPathCollections   
      ,PM.[IsFeatured]  
      ,PM.[sku]  
      ,PM.[quantity]  
      ,PM.[category_id]  
      ,PM.[HomeTaxIDs]  
      ,PM.[OtherTaxIDs]  
      ,PM.[UpdatedAt]  
      ,PM.[DeletedAt]  
      ,PM.[SellingAccount]  
      ,PM.[Cast_Price]  
      ,PM.[Cast_Account]  
      ,PM.[IsDigitalService]  
      ,PM.[IsGoods]  
      ,PM.[IsServices]  
      ,PM.[SACCode]  
      ,PM.[HSNCode]  
      ,PM.[IsTaxable]  
      ,PM.[DecimalRateItemQuantity]  
      ,PM.[UnitID]
	  ,(select unitname from unit with (nolock) where ID = PM.UnitID) as UnitName
	  ,(select unitdisplay from unit with (nolock) where ID = PM.UnitID) as UnitDisplay    
      ,PM.[IsSaleable],
	  ud.CompnayName as CompanyName  
  FROM [ProductMaster] as PM  with (nolock)
       join User_Detail as UD  with (nolock)
	   on PM.UserID = UD.User_ID
	 where PM.ProductID = @ProductID 
        
  end 




