/* ============================================================
   Procedure: [dbo].[Usp_GetProductDetailsWithPaginationComm]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_GetProductDetailsWithPaginationComm] -- 34594,N' order by productid desc ',N'',0,20           
(           
 @UserId bigint,           
 @FilterText nvarchar(max) = '',           
 @OperationMode nvarchar(20) = '',           
 @OffsetValue int = 0,           
 @PagingSize int = 1000           
)           
as           
Begin           
           
-- Declare           
--@UserId bigint = 39699,           
-- @FilterText nvarchar(max) = '',           
-- @OperationMode nvarchar(20) = '',           
-- @OffsetValue int = 0,           
-- @PagingSize int = 20           
if(@OperationMode != '')
Begin
Declare @ParentId bigint = (Select top 1 ParentId from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId);  

WITH ctename (Id, CriteriaName, CriteriaType, ProductIDs, AllProductDefault, SearchApplyTo, OrderBy, ColumnName, Operator, Value)   
  AS (  
  Select pc.Id, pc.CriteriaName, pc.CriteriaType, pc.ProductIDs, pc.AllProductDefault, pc.SearchApplyTo, pc.OrderBy,
  isnull(psc.ColumnName, '') ColumnName, isnull(psc.Operator, '') Operator, isnull(psc.Value, '') Value
  from ProductSearchCriteria pc 
  left join ProductSearchCondition psc on pc.ID = psc.CriteriaID
  where pc.ParentID = @parentId and pc.CriteriaName like '%'+ @FilterText +'%')

  select @FilterText = STRING_AGG (ISNULL(Result,' '), ' and ')--, REPLACE(STRING_AGG(ISNULL(ProductIDs, ''), ' '),' ', '') ManualSearch
  from (
  select Id, CriteriaName, CriteriaType, ProductIDs, AllProductDefault, SearchApplyTo, OrderBy, ColumnName, Operator, Value,
  case when CriteriaType = @OperationMode then ColumnName +' ' + Operator +' ' + Value else ' ' end 
  Result from ctename) res;

  set @FilterText = ' and (' + @FilterText + ') order by ProductID desc '

End

  DECLARE @sqls nvarchar(max) = '',@status INT,     
  @tableName nvarchar(max)= ''       
     
 EXEC @status = Usp_CreateProductTableByParentID @userid, @tableName output    
   declare @col varchar(max), @col1 varchar(max)   
  (Select @col=string_agg('PM.'+COLUMN_NAME,',') From INFORMATION_SCHEMA.COLUMNS where TABLE_NAME=@tableName and TABLE_CATALOG='Mysms' and COLUMN_NAME not in ('ProductID','Name',    
    'UserID','Image','Description','Price','IsPublished','IsActive','CreatedOn','CreatedBy','FullPath','IsFeatured','sku','sale_priceNoUSE',    
    'quantity','category_id','HomeTaxIDs','OtherTaxIDs','tax_idNoUSE','UpdatedAt','DeletedAt','SellingAccount','Cast_Price','Cast_Account',    
    'IsDigitalService','IsGoods','IsServices','SACCode','HSNCode','IsTaxable','DecimalRateItemQuantity','UnitID','IsSaleable')  )  
   
    if @status =1    
 begin    
  Declare @QueryString nvarchar(max) = N' select count(O_TBL.ProductID) over() as TotalRow,* from (           
  SELECT PM.ProductID,PM.Name,PM.UserID,PM.Image,PM.Description,isnull(PM.Price,0) as Price ,PM.IsPublished,PM.IsActive,PM.CreatedOn,PM.CreatedBy,PM.FullPath,PM.IsFeatured, isnull(PM.sku,'''') as sku           
  ,isnull(PM.quantity,0) as quantity , isnull(PM.category_id,0) as category_id,PC.CategoryName,isnull(PM.HomeTaxIDs,'''') as HomeTaxIDs ,           
            
  -- (select           
  -- stuff           
  -- (           
  -- ( select '','' + tbl2.name + ''('' + cast(tbl2.rate as nvarchar(100)) + ''%)'' from           
  -- (select name,rate           
  -- from [mysmsinvoicing].dbo.taxes with (nolock)           
  -- where id in           
  -- (           
  -- select cast(isnull(nullif(value,''''),0) as bigint) as id from fn_Split(PM.HomeTaxIDs,'','')           
  -- )) as tbl2           
  -- FOR XML PATH('''')), 1, 1, '''')           
            
  --)           
  '''' as HomeTaxesByName           
  ,           
  PM.OtherTaxIDs,           
            
  -- (select           
  -- stuff           
  -- (           
  -- ( select '','' + tbl2.name + ''('' + cast(tbl2.rate as nvarchar(100)) + ''%)'' from           
  -- (select name,rate           
  -- from [mysmsinvoicing].dbo.taxes with (nolock)           
  -- where id in           
  -- (           
  -- select cast(isnull(nullif(value,''''),0) as bigint) as id from fn_Split(PM.OtherTaxIDs,'','')           
  -- )) as tbl2           
  -- FOR XML PATH('''')), 1, 1, '''')           
  --)           
  '''' as OtherTaxesByName ,           
            
  PM.UpdatedAt,PM.DeletedAt,isnull(PM.SellingAccount,0) as SellingAccount , ACNT_selling.name as SellingAccountName,isnull(PM.Cast_Price,0) as Cast_Price, isnull(PM.Cast_Account,0) as Cast_Account,ACNT_cost.name as CostAccountName ,    
  isnull(PM.IsDigitalService,0) as IsDigitalService           
  ,isnull(PM.IsGoods,0) as IsGoods,isnull(PM.IsServices,0) as IsServices ,PM.SACCode,PM.HSNCode, isnull(PM.IsTaxable,0) as IsTaxable ,isnull(PM.DecimalRateItemQuantity,0) as DecimalRateItemQuantity,isnull(PM.UnitID,0) as UnitID ,UN.unitdisplay           
            
  ,           
  -- (select           
  -- stuff(           
  -- ( select '','' + tbl.Tag from           
  -- (select TM.Tag from EntityTagMapping with (nolock) as ETM           
  --left join TagMaster with (nolock) as TM           
  -- on ETM.TagID = TM.ID           
  -- where ETM.Entity = ''Product''           
  -- and ETM.EntityID = PM.ProductID) as tbl           
  --FOR XML PATH('''')), 1, 1, '''')           
  -- )           
  '''' as ProductTags,'+@col+'          
            
            
  FROM '+@tableName+' as PM with (nolock)           
  left join [mysmsinvoicing_dev].[dbo].[accounts] as ACNT_cost with (nolock)           
  on PM.Cast_Account = ACNT_cost.id           
  left join [mysmsinvoicing_dev].[dbo].[accounts] as ACNT_selling with (nolock)           
  on PM.SellingAccount = ACNT_selling.id           
  left join unit as UN with (nolock)           
  on Pm.UnitID = UN.id           
  left join Product_Category as PC with (nolock)           
  on Pm.category_id = PC.id           
            
       
  where PM.DeletedAt is null and PM.UserID = ' + cast(@UserID as nvarchar) + ' ) as O_TBL where 1 = 1 ' +           
  iif( @OperationMode = 'export', '', iif(@FilterText = '', ' order by ProductID desc           
  OFFSET ' + cast( @OffsetValue as nvarchar) + ' Rows FETCH NEXT ' + cast(@PagingSize as nvarchar) + ' ROWS ONLY ',           
  @FilterText + ' OFFSET ' + cast( @OffsetValue as nvarchar) + ' Rows FETCH NEXT ' + cast(@PagingSize as nvarchar) + ' ROWS ONLY ') )           
            
            
            
  print @QueryString           
            
  execute sp_executesql @QueryString           
 END    
  
 End



GO

