CREATE   PROCEDURE [dbo].[Usp_GetProductDetailsWithPaginationFBNew] -- 34594,N' order by productid desc ',N'',0,20             
(             
 @UserId bigint,             
 @FilterText nvarchar(max) = '',             
 @Ids nvarchar(max) = '',             
 @OperationMode nvarchar(20) = '',             
 @OffsetValue int = 0,             
 @PagingSize int = 20             
)             
as             
Begin             
             
-- Declare             
--@UserId bigint = 39699,             
-- @FilterText nvarchar(max) = '',             
-- @OperationMode nvarchar(20) = '',             
-- @OffsetValue int = 0,             
-- @PagingSize int = 20             
   DECLARE @sqls nvarchar(max) = '',@status INT,       
  @tableName nvarchar(max)= ''         
       
 EXEC @status = Usp_CreateProductTableByParentID @userid, @tableName output      
   declare @col varchar(max), @col1 varchar(max)     
  (Select @col=string_agg('PM.'+COLUMN_NAME,',') From INFORMATION_SCHEMA.COLUMNS where TABLE_NAME=@tableName and TABLE_CATALOG='mysms_dev' and COLUMN_NAME not in ('ProductID','Name', 'UserID','description','price','FullPath','sku','quantity','SACCode','UnitID')  )    
     
    if @status =1      
 begin      
  Declare @QueryString nvarchar(max) = N' select count(O_TBL.ProductID) over() as TotalRow,* from (             
  SELECT PM.ProductID,PM.Name,PM.Description,isnull(PM.Price,0) as Price, PM.FullPath, isnull(PM.sku,'''') as sku,
  isnull(PM.quantity,0) as quantity, PC.CategoryName CategoryName2, PC.CategoryName, PM.SACCode, 
  isnull(PM.UnitID,0) as UnitID, UN.unitdisplay, '+@col+'            
  FROM '+@tableName+' as PM with (nolock)             
  left join [mysmsinvoicing_dev].[dbo].[accounts] as ACNT_cost with (nolock)             
  on PM.Cast_Account = ACNT_cost.id             
  left join [mysmsinvoicing_dev].[dbo].[accounts] as ACNT_selling with (nolock)             
  on PM.SellingAccount = ACNT_selling.id             
  left join unit as UN with (nolock)             
  on Pm.UnitID = UN.id             
