  on Pm.category_id = PC.id             
  
  where PM.DeletedAt is null and PM.UserID = ' + cast(@UserID as nvarchar) + ' ) as O_TBL where 1 = 1  and ProductId in ('+ @Ids +') ' +             
  iif( @OperationMode = 'export', '', iif(@FilterText = '', ' order by ProductID desc             
