/* ============================================================
   Procedure: [dbo].[Usp_GetProductId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- select dbo.ufn_GetProductId('LEATHER BAG#CHIVAS REGAL#sHIRT',16301,'#')  
-- select dbo.ufn_GetProductId('CHIVAS REGAL',16301,'#')  
-- select dbo.ufn_GetProductId('CHIVAS REGAdssL',16301,'#')  
CREATE   PROCEDURE Usp_GetProductId  
(  
    @sProductNames varchar(max),  
    @UserID bigint,  
    @Separator varchar(1)='#',
	@Out nvarchar(max)  output
)  
