/* ============================================================
   Procedure: [dbo].[usp_GetProductImportFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetProductImportFields] --34594  --- new
(
    @parentid BIGINT
)
AS
BEGIN
    -- Declare table name dynamically
    DECLARE @tableName VARCHAR(50)
    SET @tableName = 'tbl_productmaster_' + CAST(@parentid AS VARCHAR)

    -- Fetch column names with proper mappings
    SELECT *
    FROM
    (
        SELECT 'Sno' AS COLUMN_NAME, 'varchar' AS DATA_TYPE
        UNION ALL
        SELECT 
            CASE 
                WHEN COLUMN_NAME = 'Name' THEN 'Name'
                WHEN COLUMN_NAME = 'HomeTaxIDs' THEN 'HomeTaxName'
                WHEN COLUMN_NAME = 'OtherTaxIDs' THEN 'OtherTaxName'
				   
                WHEN COLUMN_NAME = 'Price' THEN 'SalePrice'
                WHEN COLUMN_NAME = 'CostPrice' THEN 'CostPrice'
				
				WHEN COLUMN_NAME = 'category_id' THEN 'CategoryName'
				When COLUMN_NAME ='UserID' THEN 'CreatedBy'
                WHEN COLUMN_NAME = 'UnitID' THEN 'UnitName'
                WHEN COLUMN_NAME = 'sku' THEN 'sku'
                ELSE COLUMN_NAME 
            END AS COLUMN_NAME,
            DATA_TYPE
        FROM INFORMATION_SCHEMA.COLUMNS
        WHERE TABLE_NAME = @tableName 
          AND TABLE_CATALOG = DB_NAME()
          AND COLUMN_NAME NOT IN 
          ('createdby', 'productid', 'DeletedAt', 'IsActive', 
           'Cast_Account', 'SellingAccount', 'FullPath', 'sale_priceNoUSE', 
           'tax_idNoUSE', 'SellingAccount', 'Cast_Account')
    ) AS tbl
END



