/* ============================================================
   Procedure: [dbo].[usp_GetProductImportStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetProductImportStatus] 
(  
 @FromDate DATETIME  
 ,@ToDate DATETIME  
 ,@UserId BIGINT  
 ,@ImportRow_Id BIGINT = 0  
 )  
AS  
BEGIN  
 --Declare @FromDate datetime = '13-Apr-2022', @ToDate datetime = '13-Apr-2023', @UserId  bigint = 32222, @ImportRow_Id bigint= 8   
  
  IF (@ImportRow_Id > 0)  
  BEGIN  
   SELECT 
    ImportRow_Id,  
    [User_Id],  
    CONVERT(VARCHAR, ImportDate, 0) AS ImportDate,  
    IsProcessed = CASE   
        WHEN IsProcessed = 1 THEN 'Yes'  
        ELSE 'No'  
    END,  
    TotalRecords AS TotalCount,  
    (ISNULL(ProductInsCnt, 0) + ISNULL(ProductUpdCnt, 0)) AS TotalImported,  
    IsValid = CASE   
        WHEN ISNULL(Remarks, '') = '' THEN 'Yes'  
        ELSE 'No'  
    END,  
    Status = CASE  
        WHEN IsProcessed = 0 THEN 'Under Process'  
        WHEN (ISNULL(ProductInsCnt, 0) + ISNULL(ProductUpdCnt, 0)) > 0 THEN 'Import Successful'  
        WHEN (ISNULL(ProductInsCnt, 0) + ISNULL(ProductUpdCnt, 0)) = 0 AND IsProcessed = 1 THEN 'Import Failed'  
        ELSE 'Pending'  
    END,  
    FailureReason = CASE  
        WHEN ISNULL(Remarks, '') = '' THEN ''  
        ELSE Remarks  
    END  
FROM tbl_ProductImportSummary WITH (NOLOCK)  
   WHERE [User_Id] = @UserId  
    AND ImportRow_Id = @ImportRow_Id  
  END  
  ELSE  
  BEGIN  
  SELECT 
    ImportRow_Id,  
    [User_Id],  
    CONVERT(VARCHAR, ImportDate, 0) AS ImportDate,  
    IsProcessed = CASE   
        WHEN IsProcessed = 1 THEN 'Yes'  
        ELSE 'No'  
    END,  
    TotalRecords AS TotalCount,  
    (ISNULL(ProductInsCnt, 0) + ISNULL(ProductUpdCnt, 0)) AS TotalImported,  
    IsValid = CASE   
        WHEN ISNULL(Remarks, '') = '' THEN 'Yes'  
        ELSE 'No'  
    END,  
    Status = CASE  
        WHEN IsProcessed = 0 THEN 'Under Process'  
        WHEN (ISNULL(ProductInsCnt, 0) + ISNULL(ProductUpdCnt, 0)) > 0 THEN 'Import Successful'  
        WHEN (ISNULL(ProductInsCnt, 0) + ISNULL(ProductUpdCnt, 0)) = 0 AND IsProcessed = 1 THEN 'Import Failed'  
        ELSE 'Pending'  
    END,  
    FailureReason = CASE  
        WHEN ISNULL(Remarks, '') = '' THEN ''  
        ELSE Remarks  
    END,
	 ProcessAt = CASE  
        WHEN IsProcessed = 1 THEN ISNULL(EndDateTime, GETDATE())  
        ELSE NULL  
    END  
FROM tbl_ProductImportSummary WITH (NOLOCK)  
WHERE [User_Id] IN (  
    SELECT User_id  
    FROM User_Detail (nolock)  
    WHERE ParentId = @UserId  
        OR User_id = @UserId  
)  
AND CONVERT(VARCHAR, ImportDate, 106) BETWEEN @FromDate AND @ToDate  
ORDER BY ImportDate DESC;
  END  
  
 DECLARE @tablename VARCHAR(MAX),@activity VARCHAR(MAX)  
  
  SET @tablename = 'tbl_ProductImportSummary'  
  SET @activity = 'View_ImpSumry_Product'  
  
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = @activity  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = @tablename  
END  



GO

