/* ============================================================
   Procedure: [dbo].[Usp_GetProfileDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
    
-- =============================================      
-- Author:  <vinay kumar upadhyay,chandra prakash singh>      
-- Create date: <20/04/2015>      
-- Description: < This sp used for getuser profile details used for sms19 apps>      
-- =============================================      
CREATE   PROCEDURE [dbo].[Usp_GetProfileDetails]  --  '20718','fetch' --'19540','fetch'      
@User_ID int,      
@Action varchar(10)      
AS      
BEGIN     
declare @UserCategory varchar(30),@Currency varchar(30),@Country varchar(100),@Plan varchar(100),@ExpiryDate varchar(20);  
select @UserCategory=UserCategory from User_Detail where User_ID=@User_ID  
select @Currency =[Currency],@Country=Country_Name FROM [KITEVER].[dbo].[M_Country] where [CountryCode]=(select CountryCode from user_detail(nolock) where User_ID=@User_ID)   
if(@UserCategory=2)  
begin  
select @Plan=[PlanName] FROM [KITEVER].[dbo].[PlanMaster] PM(nolock) where id=1  
end  
else  
begin  
select @Plan=[PlanName],@ExpiryDate=[ExpiryDate] FROM [KITEVER].[dbo].[PlanMaster] PM(nolock) join [KITEVER].[dbo].[MerchantSubscription] MS(nolock)  
on PM.id=MS.[PlanID]  
end  
if (@Action='Fetch')      
BEGIN      
 Declare @ProfilePicturePath VARCHAR(100);     
 SELECT @ProfilePicturePath=ProfilePicturePath from User_detail(NOLOCK) where User_ID=@User_ID       
 if(@ProfilePicturePath != '')    
 BEGIN    
  SELECT @ProfilePicturePath as ProfilePicturePath, FName,CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile,EMail,pincode,Gender,Address, Merchant_Code, Merchant_Url, User_DOB,@UserCategory as UserCategory,@Plan as [Plan],@ExpiryDate as ExpiryDate,@Country as Country,
  @Currency as Currency,CompnayName,DOE from User_Detail where User_ID=@User_ID      
 END    
 ELSE    
 BEGIN    
  SELECT @ProfilePicturePath = DefaultAppLogo from SMS19_APP_Logo_MasterTable    
  SELECT @ProfilePicturePath as ProfilePicturePath, FName,CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20)) as Mobile,EMail,pincode,Gender,Address,Merchant_Code, Merchant_Url, User_DOB,@UserCategory as UserCategory,@Plan as [Plan],@ExpiryDate as ExpiryDate,
@Country as Country,@Currency as Currency,CompnayName,DOE from User_Detail where User_ID=@User_ID   
  END     
END      
END      
    
    


GO

