CREATE   PROCEDURE dbo.Usp_GetQuickLinqSuggestTo  --'e',335  
(    
  @Filter nvarchar(500),    
  @UserID bigint    
)    
as    
Begin    
    
  select * from  
  (  
    select    
    [ID]    
      ,[PageID]    
      ,[QuickLinkName]    
      ,[Path]    
      ,[UserID]    
       
  from [UserQuickLinks]  where QuickLinkName like '%' +@Filter +  '%'    
   and  isnull([UserID],0) = @UserID    
  
   union   
  
  select    
       [ID]    
      ,[PageID]    
      ,[QuickLinkName]    
      ,[Path]    
      ,[UserID]    
       
  from [UserQuickLinks]  where QuickLinkName like '%' +@Filter +  '%'    
   and isnull([UserID],0) = 0  
   ) as tbl  
     order by tbl.QuickLinkName asc  
  
    
End


