/* ============================================================
   Procedure: [dbo].[usp_GetRecipientsEventBased]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

              
CREATE   PROCEDURE [dbo].[usp_GetRecipientsEventBased]              
              
AS              
              
BEGIN              
              
 SELECT A.CampaignID,              
              
        A.ParentID,              
              
        A.Applicabilty,              
              
        A.ApplicabiltyGroupList,              
              
        A.ExclusionsGroupList,              
              
        A.NotificationMail,              
              
        A.ExclusionsNumber,              
              
        A.Exclusions,              
              
        A.InclusionsNumber,              
              
        A.AccountUsed,              
              
        A.SenderID,              
              
        A.[Message],              
              
        A.TemplateID,              
              
        A.TemplateGroupID,              
              
        A.IsUnicode,              
              
        A.EventsName              
              
                      
              
        INTO     #TempTemplate              
              
 FROM   (              
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   fs.[value]  AS Applicabilty,              
              
                   0           AS ApplicabiltyGroupList,              
              
                   0           AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   0           AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm  (nolock)            
              
                   OUTER APPLY dbo.fn_Split(ucm.Applicabilty, '#') AS fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.MailReplyTo = ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))              
              
                                     
              
                       < 0              
              
                   AND ucm.IsActive = 1              
              
                          
              
            UNION ALL              
              
                          
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   0           AS Applicabilty,              
              
                   fs.[value]  AS ApplicabiltyGroupList,              
              
                   0           AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
    
                   0           AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
             ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
    FROM   UserCampaignMaster ucm  (nolock)            
              
                   OUTER APPLY dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS               
              
            fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
         AND ucm.MailReplyTo = ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))              
              
                                     
              
                       < 0              
              
             
              
            UNION ALL              
              
                          
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   0           AS Applicabilty,              
              
                   0           AS ApplicabiltyGroupList,              
              
                   fs.[value]  AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   0           AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
   ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm   (nolock)           
              
                   OUTER APPLY dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS               
              
            fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
                   AND ucm.MailReplyTo = ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))              
              
                                     
              
                       < 0              
              
                          
              
            UNION ALL              
              
                          
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   0           AS Applicabilty,              
              
      0           AS ApplicabiltyGroupList,              
              
                   0           AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   fs.[value]  AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm    (nolock)          
              
                   OUTER APPLY dbo.fn_Split(ucm.Exclusions, '#') AS fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
                   AND ucm.MailReplyTo = ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))              
              
                                     
              
                       < 0              
              
   )        A              
              
 ORDER BY              
              
        A.CampaignID              
              
               
