                 @ParentIDGroupExc BIGINT,              
              
                 @CampaignIDGroupExc BIGINT              
              
                       
              
                       
              
                       
              
         DECLARE @ListID                BIGINT,              
              
                 @ParentIDList          BIGINT,              
              
                 @CampaignIDList        BIGINT,              
              
                 @ListIDExc             BIGINT,              
              
                 @ParentIDListExc       BIGINT,              
              
                 @CampaignIDListExc     BIGINT              
              
                       
              
                       
              
                       
              
         SELECT TOP 1 @Applicability1 = SearchID,              
              
                @ParentIDApp       = ParentID,              
              
                @CampaignIDApp     = CampaignID              
              
         FROM   #TempApplicability              
              
         ORDER BY              
              
                SearchID,              
              
                ParentID              
              
                       
              
                       
              
                       
              
         SELECT TOP 1 @GroupID = GroupID,              
              
                @ParentIDGroup       = ParentID,              
              
                @CampaignIDGroup     = CampaignID              
              
         FROM   #TempApplicabilityGroups              
              
         ORDER BY              
              
                GroupID,              
              
                ParentID              
              
                       
              
                       
              
                       
              
         DELETE               
              
         FROM   #TempApplicabilityGroups                        
         WHERE  GroupID = @GroupID              
              
                AND ParentID = @ParentIDGroup              
              
                AND CampaignID = @CampaignIDGroup              
              
                       
              
                       
              
                       
              
         SELECT TOP 1 @ListID = ListID,              
              
                @ParentIDList       = ParentID,              
              
                @CampaignIDList     = CampaignID              
              
         FROM   #TempApplicabilitylists              
              
         ORDER BY              
              
                ListID,              
              
                ParentID              
              
                       
              
                       
              
                       
              
         DELETE               
              
         FROM   #TempApplicabilitylists              
              
         WHERE  ListID = @ListID              
              
                AND ParentID = @ParentIDGroup              
              
                AND CampaignID = @CampaignIDGroup              
              
                       
              
                       
              
                       
              
         DECLARE @Excluded1         BIGINT,              
              
                 @ParentIDExc       BIGINT,              
              
                 @CampaignIDExc     BIGINT              
              
                       
              
                       
              
                       
              
         SELECT TOP 1 @Excluded1 = SearchID,              
              
                @ParentIDExc       = ParentID,              
              
                @CampaignIDExc     = CampaignID              
              
         FROM   #TempExclusion              
              
         ORDER BY              
              
                SearchID,              
              
                ParentID              
              
                       
              
                
              
                       
              
         SELECT TOP 1 @GroupIDExc = GroupID,              
              
                @ParentIDGroupExc       = ParentID,              
              
                @CampaignIDGroupExc     = CampaignID              
              
         FROM   #TempExclusionGroups              
              
         ORDER BY              
              
                GroupID,              
              
                ParentID              
              
                       
              
                       
              
                   
              
         DELETE               
              
         FROM   #TempExclusionGroups              
              
         WHERE  GroupID = @GroupIDExc              
              
                AND ParentID = @ParentIDGroupExc              
              
                AND CampaignID = @CampaignIDGroupExc              
              
                       
              
                       
              
                       
              
         SELECT TOP 1 @ListIDExc = ListID,              
              
                @ParentIDListExc       = ParentID,              
              
                @CampaignIDListExc     = CampaignID              
              
         FROM   #TempExclusionlists              
              
         ORDER BY              
              
                ListID,              
              
                ParentID              
              
                       
              
                       
              
                       
              
         DELETE               
              
         FROM   #TempExclusionlists              
              
         WHERE  ListID = @ListIDExc              
              
                AND ParentID = @ParentIDListExc              
              
        AND CampaignID = @CampaignIDListExc              
              
                       
              
                       
              
                       
              
         DELETE               
              
         FROM   #TempApplicability              
              
         WHERE  SearchID = @Applicability1              
              
                AND ParentID = @ParentIDApp              
              
                       
              
                       
              
                       
              
         DELETE               
              
         FROM   #TempExclusion              
              
         WHERE  SearchID = @Excluded1              
              
 AND ParentID = @ParentIDExc              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchApp              
              
           (              
              
             MobileNo,              
              
             CampaignID,              
              
             ParentID              
              
           )              
              
         SELECT usd.MobileNumber,              
              
                @CampaignIDList,              
              
                @ParentIDList              
              
         FROM   UserSearchData AS usd   (nolock)           
              
         WHERE  usd.ParentID = @ParentIDList              
              
                AND usd.ImportedListID = @ListID              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchApp              
              
           (              
              
             MobileNo,              
              
             CampaignID,              
              
   ParentID              
              
           )              
              
         SELECT cd.Contact_Mobile,              
              
                @CampaignIDGroup,              
              
                @ParentIDGroup              
              
         FROM   Contact_Detail AS cd   (nolock)           
              
                INNER JOIN Contact_Group_Detail AS cgd    (nolock)          
              
                     ON  cgd.Contact_ID = cd.Contact_ID              
              
         WHERE  cgd.Group_ID = @GroupID              
              
    
              
                       
              
                       
              
         INSERT INTO #TempTableSearchApp              
              
           (              
              
             PersonName,              
              
             CompanyName,              
              
             MobileNo,              
              
             MobileNo1,              
              
             MobileNo2,              
              
             EmailID,              
              
             EmailID1,              
              
             EmailID2,              
              
             Country,              
              
             [STATE],              
              
             City,              
              
             PinCode,              
              
             ResidentialAddress,              
              
             OfficeAddress,              
              
             SourceName,              
              
             MediumName,              
              
             CampaignName,              
              
             InitialRemarks,              
              
             SearchID,              
              
             ParentID,              
              
             CampaignID              
              
           )              
              
         EXEC usp_ExecuteUserSearch              
              
                            
              
            @ParentIDApp,              
              
              @Applicability1,              
              
              @CampaignIDApp              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchExc              
              
           (              
              
             MobileNo,              
              
             CampaignID,              
              
             ParentID              
              
           )              
              
         SELECT usd.MobileNumber,              
              
                @CampaignIDListExc,              
              
                @ParentIDListExc              
              
         FROM   UserSearchData AS usd  (nolock)            
              
         WHERE  usd.ParentID = @ParentIDListExc              
              
                AND usd.ImportedListID = @ListIDExc              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchExc              
              
           (              
              
             MobileNo,              
              
             CampaignID,              
              
             ParentID              
              
           )              
              
         SELECT cd.Contact_Mobile,              
              
                @CampaignIDGroupExc,              
              
                @ParentIDGroupExc              
              
         FROM   Contact_Detail AS cd   (nolock)           
              
                INNER JOIN Contact_Group_Detail AS cgd  (nolock)            
              
                     ON  cgd.Contact_ID = cd.Contact_ID              
              
         WHERE  cgd.Group_ID = @GroupIDExc              
              
                       
             
                       
              
                       
              
         INSERT INTO #TempTableSearchExc              
              
           (              
              
             PersonName,              
              
             CompanyName,              
              
             MobileNo,              
              
             MobileNo1,              
              
             MobileNo2,              
              
             EmailID,              
              
             EmailID1,              
              
             EmailID2,              
              
             Country,              
              
             [STATE],              
              
             City,              
              
             PinCode,              
              
             ResidentialAddress,              
              
             OfficeAddress,              
              
             SourceName,              
              
             MediumName,              
              
             CampaignName,              
              
             InitialRemarks,              
              
             SearchID,              
              
             ParentID,              
              
             CampaignID              
              
           )              
              
         EXEC usp_ExecuteUserSearch              
              
                            
              
              @ParentIDExc,              
              
              @Excluded1,              
              
              @CampaignIDExc              
              
     END              
              
 END              
              
               
              
               
              
               
              
 IF EXISTS(              
              
        SELECT *              
              
        FROM   #TempTemplate              
              
        WHERE EventsName = 'ENQADD'              
              
    )              
              
 BEGIN              
              
     SELECT tt.MobileNo,              
              
            tt.ParentID,              
              
            ucs.CampaignID              
              
                          
              
            INTO #TempEnq         
              
     FROM   (              
              
                SELECT ue.MobileNo,              
              
                       ue.ParentID,              
              
                       ue.CreatedDate              
              
                FROM   UserEnquiry AS ue  (nolock)            
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                                     
              
                       <= 0              
              
                       AND ue.ParentID IN (SELECT tt.ParentID              
              
                                           FROM   #TempTemplate tt              
              
                                           WHERE  EventsName = 'ENQADD')              
              
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                                         
              
                    >= -2              
              
                              
              
                UNION              
              
                              
              
                SELECT ue.MobileNo1,              
              
                       ue.ParentID,              
              
                       ue.CreatedDate              
              
                FROM   UserEnquiry AS ue  (nolock)            
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                                     
              
                       <= 0              
              
                       AND ue.ParentID IN (SELECT tt.ParentID              
              
                                           FROM   #TempTemplate tt              
              
                                           WHERE  EventsName = 'ENQADD')              
              
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))        
              
                                         
              
                           >= -2              
              
                              
              
                UNION              
              
                              
              
                SELECT ue.MobileNo2,              
              
                       ue.ParentID,              
              
                       ue.CreatedDate              
              
                FROM   UserEnquiry AS ue    (nolock)          
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                           
              
                       <= 0              
              
                       AND ue.ParentID IN (SELECT tt.ParentID              
              
                                           FROM   #TempTemplate tt              
              
                                           WHERE  EventsName = 'ENQADD')              
            
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                                         
              
                           >= -2              
              
            ) tt              
              
            OUTER APPLY #TempTableSearchApp ucs              
              
     WHERE  ucs.ParentID = tt.ParentID              
              
            AND tt.MobileNo <> ''              
              
            AND (              
              
                    CAST(tt.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                  
              
         IN (SELECT CAST(B.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                        FROM   (              
              
                                   SELECT tsex.MobileNo              
              
                                FROM   #TempTableSearchApp AS tsex              
              
                                                 
              
                                   UNION              
              
                                                 
              
                                   SELECT tsex.MobileNo1              
              
                                   FROM   #TempTableSearchApp AS tsex              
              
                                                 
              
                                   UNION              
              
                                                 
              
                                   SELECT tsex.MobileNo2              
              
                                   FROM   #TempTableSearchApp AS tsex              
             
                               ) B              
              
                        WHERE  CAST(B.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                             
              
                               NOT IN (SELECT CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                       FROM   (              
              
                                                  SELECT tsex.MobileNo              
              
                                                  FROM   #TempTableSearchexc AS               
              
                                                         tsex              
              
                                                                
              
                                                  UNION              
              
                                                       
              
                                                  SELECT tsex.MobileNo1              
              
                                                  FROM   #TempTableSearchexc AS               
              
                                                         tsex              
              
                                                                
              
                                                  UNION              
              
                                                                
              
                                                  SELECT tsex.MobileNo2              
              
                                                  FROM   #TempTableSearchexc AS               
              
                                                         tsex              
              
                                              ) A))              
              
                )              
              
                   
              
                   
              
                   
              
     INSERT INTO UserCampaignExecutionHistory              
              
       (              
              
         -- ID -- this column value is auto-generated              
              
                       
              
         CampaignID,              
              
         ExecutionTime,              
              
         NoOfRecipients,              
              
         Response,              
              
         BatchID,              
              
         IsRecipients,              
              
         IsMessages,              
              
         IsExecuted,              
              
         ParentID              
              
       )              
              
     SELECT DISTINCT tt.CampaignID,              
              
            GETDATE(),              
              
            0,              
              
            NULL,              
              
            0,              
              
            1,              
              
            0,              
              
            0,              
              
            tt.ParentID              
              
     FROM   #TempEnq tt              
              
                   
              
                   
              
                   
              
     INSERT INTO UserCampaignExecutionRecipientsMessage              
              
       (              
              
         -- MessageID -- this column value is auto-generated              
              
                       
              
         BatchID,              
              
         Mobile,              
              
         [Message],              
              
         MessageStatus,              
              
         SenderID,              
              
         MessageInsertDate,              
              
         ScheduledDate,              
              
         ScheduledTime,              
              
         SmppID,              
              
         U_ID,              
              
         IsUniCode,              
              
         IsDnd,              
              
         IsAirtel,              
              
         MobileSubSet,              
              
         ValidNo,              
              
         IsPrority,              
              
         IsAllowDND,              
              
         DBType,              
              
         ParentID,              
              
         CampaignID,              
              
         IsCompleted              
              
       )              
              
     SELECT NULL,              
              
            A.MobileNo,              
              
            NULL,              
              
            NULL,              
              
            NULL,              
              
            GETDATE(),              
              
 GETDATE(),              
              
            GETDATE(),              
              
            (              
              
                SELECT TOP 1 ud.SmppID              
              
                FROM   User_Detail AS ud  (nolock)            
              
                WHERE  ud.[User_ID] IN (SELECT ucm.AccountUsed              
              
                                        FROM   UserCampaignMaster AS ucm              
              
                                        WHERE  ucm.ID = A.CampaignID              
              
                                               AND ucm.IsActive = 1)              
              
            ),              
              
            (              
              
                SELECT TOP 1 ucm.AccountUsed              
              
                FROM   UserCampaignMaster AS ucm  (nolock)            
              
                WHERE  ucm.ID = A.CampaignID              
              
                       AND ucm.IsActive = 1              
              
            ),              
              
            0,              
              
            0,              
              
            0,                      
            '',              
              
            0,              
              
            0,              
              
            0,              
              
            '',              
              
            A.ParentID,              
              
            A.CampaignID,              
              
            0              
              
     FROM   (         
              
                SELECT DISTINCT tt.MobileNo,              
              
                       tt.ParentID,              
              
                       tt.CampaignID              
              
                FROM   #TempEnq tt              
              
                GROUP BY              
              
                       tt.MobileNo,      
              
                       tt.ParentID,              
              
                       tt.CampaignID              
              
            ) A              
              
                   
              
                   
              
                   
              
     DROP TABLE #TempEnq              
              
 END              
              
               
          
               
              
               
              
 IF EXISTS(              
              
        SELECT *              
              
        FROM   #TempTemplate              
              
        WHERE  EventsName = 'LEDADD'              
              
    )              
              
 BEGIN              
              
     SELECT tt.MobileNo,              
              
            tt.ParentID,              
              
            ucs.CampaignID              
              
                          
              
            INTO #TempLeads              
              
     FROM   (              
              
                SELECT ue.MobileNo,              
              
