                         FROM  #TempTemplate tt              
              
            WHERE  EventsName = 'ENQADD')              
              
            ) tt             
              
            OUTER APPLY #TempTableSearchApp ucs              
              
     WHERE  ucs.ParentID = tt.ParentID              
              
            AND tt.MobileNo <> ''              
              
            AND (              
              
                    CAST(tt.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                  
              
                    IN (SELECT CAST(B.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                        FROM   (              
              
                                   SELECT tsex.MobileNo              
              
                                   FROM   #TempTableSearchApp AS tsex              
              
                                                 
              
                                   UNION              
              
                                                 
              
                                   SELECT tsex.MobileNo1              
              
                                   FROM   #TempTableSearchApp AS tsex              
              
                                                 
              
                                   UNION              
              
                                                 
              
                                   SELECT tsex.MobileNo2              
              
                                   FROM   #TempTableSearchApp AS tsex              
              
                               ) B              
              
                        WHERE  CAST(B.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                             
              
                               NOT IN (SELECT CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                       FROM   (              
              
                                                  SELECT tsex.MobileNo              
              
                                                  FROM   #TempTableSearchexc AS               
              
                                                         tsex              
              
                                                                
              
                                                  UNION              
              
                                                                
              
                                                  SELECT tsex.MobileNo1              
              
                                                  FROM   #TempTableSearchexc AS               
              
                                                         tsex              
              
                                                                
              
                                                  UNION              
              
                                                                
              
                                                  SELECT tsex.MobileNo2              
              
                                                  FROM   #TempTableSearchexc AS               
              
                                                         tsex              
              
                                              ) A))              
              
                )              
              
                   
              
                   
              
                   
              
