                       INNER JOIN LeadInteractionHistory AS lih (nolock)             
              
                            ON  lih.LeadNo = ue.LeadNo              
              
                            AND lih.ParentID = ue.ParentID              
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(lih.CreatedOn, GETDATE()))              
              
                            
              
                       >= -2              
              
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(lih.CreatedOn, GETDATE()))              
              
                                         
              
                           <= 0              
              
                       AND lih.ParentID IN (SELECT tt.ParentID              
              
                                            FROM   #TempTemplate tt              
              
                                            WHERE  EventsName = 'FOLADD')              
              
            )              
              
                          
              
            tt              
              
            OUTER APPLY #TempTableSearchApp ucs              
              
     WHERE  ucs.ParentID = tt.ParentID              
                      AND tt.MobileNo <> ''              
              
            AND (              
              
                    CAST(tt.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                                  
              
                    IN (SELECT CAST(B.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))              
              
                        FROM   (              
              
                                   SELECT tsex.MobileNo              
              
                                   FROM   #TempTableSearchApp AS tsex              
              
                                                 
              
                                   UNION              
              
                                                 
              
                                   SELECT tsex.MobileNo1              
              
                                   FROM   #TempTableSearchApp AS tsex              
              
                           
              
                                   UNION              
              
                                                 
              
