UPDATE A            
SET step1=1,step1datetime=getdate(),step1recipients = isnull(B.[RecipientsCount],0)        
FROM [dbo].UserCampaignHistory A INNER JOIN             
(SELECT u.campaignid,isnull(count(ur.[campaignid]),0) AS [RecipientsCount]            
         FROM UserCampaignHistory u (nolock) left outer join usercampaignexecutionrecipientsmessage ur (nolock) on u.CampaignID=ur.CampaignID group by u.CampaignID            
 ) B            
ON A.[campaignid] = B.[campaignid] join ##campaignrun c on a.ID=c.CampaignrunID             
              
                   
              
