/* ============================================================
   Procedure: [dbo].[usp_GetRecipientsEventBased2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON





CREATE   PROCEDURE [dbo].[usp_GetRecipientsEventBased2]



AS



BEGIN



	SELECT A.CampaignID,



	       A.ParentID,



	       A.Applicabilty,



	       A.ApplicabiltyGroupList,



	       A.ExclusionsGroupList,



	       A.NotificationMail,



	       A.ExclusionsNumber,



	       A.Exclusions,



	       A.InclusionsNumber,



	       A.AccountUsed,



	       A.SenderID,



	       A.[Message],



	       A.TemplateID,



	       A.TemplateGroupID,



	       A.IsUnicode,



	       A.EventsName



	       



	       



	       



	       INTO #TempTemplate



	FROM   (



	           SELECT ucm.ID      AS CampaignID,



	                  ucm.ParentID,



	                  fs.[value]  AS Applicabilty,



	                  0           AS ApplicabiltyGroupList,



	                  0           AS ExclusionsGroupList,



	                  ucm.NotificationMail,



	                  ucm.ExclusionsNumber,



	                  0           AS Exclusions,



	                  ucm.InclusionsNumber,



	                  ucm.AccountUsed,



	                  ucm.SenderID,



	                  ucm.[Message],



	                  ucm.TemplateID,



	                  ucm.TemplateGroupID,



	                  ucm.IsUnicode,



	                  ucm.EventsName



	           FROM   UserCampaignMaster ucm



	                  OUTER APPLY dbo.fn_Split(ucm.Applicabilty, '#') AS fs



	           WHERE  ucm.IsEventBased = 1



	                  AND ucm.MailReplyTo = ''



	                  



	                  AND DATEDIFF(



	                          MINUTE,



	                          GETDATE(),



	                          CASE 



	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())



	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())



	                          END



	                      ) 



	                      



	                      > 0



	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))



	                      



	                      < 0



	           



	           



	           



	           UNION ALL



	           



	           



	           



	           SELECT ucm.ID      AS CampaignID,



	                  ucm.ParentID,



	                  0           AS Applicabilty,



	                  fs.[value]  AS ApplicabiltyGroupList,



	                  0           AS ExclusionsGroupList,



	                  ucm.NotificationMail,



	                  ucm.ExclusionsNumber,



	                  0           AS Exclusions,



	                  ucm.InclusionsNumber,



	                  ucm.AccountUsed,



	                  ucm.SenderID,



	                  ucm.[Message],



	                  ucm.TemplateID,



	                  ucm.TemplateGroupID,



	                  ucm.IsUnicode,



	                  ucm.EventsName



	           FROM   UserCampaignMaster ucm



	                  OUTER APPLY dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS fs



	           WHERE  ucm.IsEventBased = 1



	                  AND ucm.MailReplyTo = ''



	                  



	                  AND DATEDIFF(



	                          MINUTE,



	                          GETDATE(),



	                          CASE 



	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())



	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())



	                          END



	                      ) 



	                      



	                      > 0



	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))



	                      



	                      < 0



	           



	           



	           



	           UNION ALL



	           



	           



	           



	           SELECT ucm.ID      AS CampaignID,



	                  ucm.ParentID,



	                  0 AS Applicabilty,



	                  0           AS ApplicabiltyGroupList,



	                  fs.[value]  AS ExclusionsGroupList,



	                  ucm.NotificationMail,



	                  ucm.ExclusionsNumber,



	         0           AS Exclusions,



	                  ucm.InclusionsNumber,



	                  ucm.AccountUsed,



	                  ucm.SenderID,



	                  ucm.[Message],



	                  ucm.TemplateID,



	                  ucm.TemplateGroupID,



	                  ucm.IsUnicode,



	                  ucm.EventsName



	           FROM   UserCampaignMaster ucm



	                  OUTER APPLY dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS fs



	           WHERE  ucm.IsEventBased = 1



	                  AND ucm.MailReplyTo = ''



	                  



	                  AND DATEDIFF(



	                          MINUTE,



	                          GETDATE(),



	                          CASE 



	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())



	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())



	                          END



	                      ) 



	                      



	                      > 0



	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))



	                      



	                      < 0



	           



	           



	           



	           UNION ALL



	           



	           



	           



	           SELECT ucm.ID      AS CampaignID,



	                  ucm.ParentID,



	                  0           AS Applicabilty,



	                  0           AS ApplicabiltyGroupList,



	                  0           AS ExclusionsGroupList,



	                  ucm.NotificationMail,



	                  ucm.ExclusionsNumber,



	                  fs.[value]  AS Exclusions,



	                  ucm.InclusionsNumber,



	                  ucm.AccountUsed,



	                  ucm.SenderID,



	                  ucm.[Message],



	                  ucm.TemplateID,



	                  ucm.TemplateGroupID,



	                  ucm.IsUnicode,



	                  ucm.EventsName



	           FROM   UserCampaignMaster ucm



	                  OUTER APPLY dbo.fn_Split(ucm.Exclusions, '#') AS fs



	           WHERE  ucm.IsEventBased = 1



	                  AND ucm.MailReplyTo = ''



	                  



	                  AND DATEDIFF(



	                          MINUTE,



	                          GETDATE(),



	                          CASE 



	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())



	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())



	                          END



	                      ) 



	                      



	                      > 0



	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))



	                      



	                      < 0



	       ) A



	



	



	



	



	



	



	



	SELECT CampaignID,



	       Applicabilty,



	       ExclusionsNumber,



	       Exclusions,



	       InclusionsNumber,



	       AccountUsed,



	       EventsName



	       



	       



	       



	       INTO     #TempMessage



	FROM   (



	           SELECT tt.CampaignID  AS CampaignID,



	                  CASE 



	                       WHEN tt.[Message] = '' THEN CASE 



	                                                        WHEN tt.TemplateID =



	                                                             



	                                                             



	                                                             



	                                                             0 THEN CASE 



	                                                                         WHEN 



	         tt.TemplateGroupID 



	                                                                              



	                                                                              



	                                                                              



	                                                                              =



	       



	                                                                              



	                                                                              



	                                                                              0 THEN 



	                                                                              ''



	                                                                         ELSE 



	                                                                              1



	                                                                    END



	                                                        ELSE 1



	                                                   END



	                       ELSE 1



	                  END            AS IsMessage,



	                  tt.Applicabilty,



	                  tt.ApplicabiltyGroupList,



	                  tt.ExclusionsGroupList,



	                  tt.ExclusionsNumber,



	                  tt.Exclusions,



	                  tt.InclusionsNumber,



	                  tt.AccountUsed,



	                  tt.EventsName



	           FROM   #TempTemplate     tt



	       )        A



	WHERE  IsMessage = 1



	



	



	



	



	



	



	



	DECLARE @Body VARCHAR(500)



	



	



	



	



	



	



	



	IF NOT EXISTS (



	       SELECT 'x'



	       FROM   #TempTemplate



	   )



	BEGIN



	    SET @Body = 'No Campaign Found'



	    



	    



	    



	    



	    



	    



	    



	    SELECT @Body



	END



	ELSE



	BEGIN



	    IF EXISTS(



	           SELECT AccountUsed



	           FROM   #TempMessage tt



	                  INNER JOIN User_Detail ud



	                       ON  ud.[User_ID] = tt.AccountUsed



	           WHERE  ud.[Status] = 0



	       )



	    BEGIN



	        SET @Body = 'User Inactive'



	        



	        



	        



	        



	        



	        



	        



	        SELECT @Body



	    END



	    ELSE



	    BEGIN



	        CREATE TABLE #TempApplicability



	        (



	        	SearchID       BIGINT,



	        	ParentID       BIGINT,



	        	CampaignID     BIGINT



	        )



	        



	        



	        



	        



	        



	        



	        



	        CREATE TABLE #TempApplicabilityGroups



	        (



	        	GroupID        BIGINT,



	        	ParentID       BIGINT,



	        	CampaignID     BIGINT



	        )



	        



	        



	        



	        



	        



	        



	        



	        CREATE TABLE #TempApplicabilityLists



	        (



	        	ListID         BIGINT,



	        	ParentID       BIGINT,



	        	CampaignID     BIGINT



	        )



	        



	        



	        



	        



	        



	        



	        



	        INSERT INTO #TempApplicability



	          (



	            SearchID,



	            ParentID,



	            CampaignID



	          )



	        SELECT tt.Applicabilty,



	               tt.ParentID,



	               tt.CampaignID



	        FROM   #TempTemplate tt



	        



	        



	        



	        



	        



	        



	        



	        INSERT INTO #TempApplicabilityGroups



	          (



	            GroupID,



	            ParentID,



	            CampaignID



	          )



	        SELECT tt.ApplicabiltyGroupList,



	               tt.ParentID,



	               tt.CampaignID



	        FROM   #TempTemplate tt



	        



	        



	        



	        



	        



	        



	        



	     INSERT INTO #TempApplicabilitylists



	          (



	            ListID,



	            ParentID,



	            CampaignID



	          )



	        SELECT tt.ApplicabiltyGroupList,



	               tt.ParentID,



	               tt.CampaignID



	        FROM   #TempTemplate tt



	        



	        



	        



	        



	        



	        



	        



