/* ============================================================
   Procedure: [dbo].[usp_GetRecipientsEventBased3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetRecipientsEventBased3]
AS
BEGIN
	SELECT A.CampaignID,
	       A.ParentID,
	       A.Applicabilty,
	       A.ApplicabiltyGroupList,
	       A.ExclusionsGroupList,
	       A.NotificationMail,
	       A.ExclusionsNumber,
	       A.Exclusions,
	       A.InclusionsNumber,
	       A.AccountUsed,
	       A.SenderID,
	       A.[Message],
	       A.TemplateID,
	       A.TemplateGroupID,
	       A.IsUnicode,
	       A.EventsName
	       
	       INTO     #TempTemplate
	FROM   (
	           SELECT ucm.ID      AS CampaignID,
	                  ucm.ParentID,
	                  fs.[value]  AS Applicabilty,
	                  0           AS ApplicabiltyGroupList,
	                  0           AS ExclusionsGroupList,
	                  ucm.NotificationMail,
	                  ucm.ExclusionsNumber,
	                  0           AS Exclusions,
	                  ucm.InclusionsNumber,
	                  ucm.AccountUsed,
	                  ucm.SenderID,
	                  ucm.[Message],
	                  ucm.TemplateID,
	                  ucm.TemplateGroupID,
	                  ucm.IsUnicode,
	                  ucm.EventsName
	           FROM   UserCampaignMaster ucm
	                  OUTER APPLY dbo.fn_Split(ucm.Applicabilty, '#') AS fs
	           WHERE  ucm.IsEventBased = 1
	                  AND ucm.MailReplyTo = ''
	                  AND DATEDIFF(
	                          MINUTE,
	                          GETDATE(),
	                          CASE 
	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())
	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())
	                          END
	                      ) > 0
	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))
	                      
	                      < 0
	           
	           UNION ALL
	           
	           SELECT ucm.ID      AS CampaignID,
	                  ucm.ParentID,
	                  0           AS Applicabilty,
	                  fs.[value]  AS ApplicabiltyGroupList,
	                  0           AS ExclusionsGroupList,
	                  ucm.NotificationMail,
	                  ucm.ExclusionsNumber,
	                  0           AS Exclusions,
	                  ucm.InclusionsNumber,
	                  ucm.AccountUsed,
	                  ucm.SenderID,
	                  ucm.[Message],
	                  ucm.TemplateID,
	                  ucm.TemplateGroupID,
	                  ucm.IsUnicode,
	                  ucm.EventsName
	           FROM   UserCampaignMaster ucm
	                  OUTER APPLY dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS 
	           fs
	           WHERE  ucm.IsEventBased = 1
	                  AND ucm.MailReplyTo = ''
	                  AND DATEDIFF(
	                          MINUTE,
	                          GETDATE(),
	                          CASE 
	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())
	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())
	                          END
	                      ) > 0
	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))
	                      
	                      < 0
	           
	           UNION ALL
	           
	           SELECT ucm.ID      AS CampaignID,
	                  ucm.ParentID,
	                  0           AS Applicabilty,
	                  0           AS ApplicabiltyGroupList,
	                  fs.[value]  AS ExclusionsGroupList,
	                  ucm.NotificationMail,
	                  ucm.ExclusionsNumber,
	                  0           AS Exclusions,
	                  ucm.InclusionsNumber,
	                  ucm.AccountUsed,
	                  ucm.SenderID,
	                  ucm.[Message],
	                  ucm.TemplateID,
	                  ucm.TemplateGroupID,
	                  ucm.IsUnicode,
	                  ucm.EventsName
	           FROM   UserCampaignMaster ucm
	                  OUTER APPLY dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS 
	           fs
	           WHERE  ucm.IsEventBased = 1
	                  AND ucm.MailReplyTo = ''
	                  AND DATEDIFF(
	                          MINUTE,
	                          GETDATE(),
	                          CASE 
	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())
	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())
	                          END
	                      ) > 0
	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))
	                      
	                      < 0
	           
	           UNION ALL
	           
	           SELECT ucm.ID      AS CampaignID,
	                  ucm.ParentID,
	                  0           AS Applicabilty,
	                  0           AS ApplicabiltyGroupList,
	                  0           AS ExclusionsGroupList,
	                  ucm.NotificationMail,
	                  ucm.ExclusionsNumber,
	                  fs.[value]  AS Exclusions,
	                  ucm.InclusionsNumber,
	                  ucm.AccountUsed,
	                  ucm.SenderID,
	                  ucm.[Message],
	                  ucm.TemplateID,
	                  ucm.TemplateGroupID,
	                  ucm.IsUnicode,
	                  ucm.EventsName
	           FROM   UserCampaignMaster ucm
	                  OUTER APPLY dbo.fn_Split(ucm.Exclusions, '#') AS fs
	           WHERE  ucm.IsEventBased = 1
	                  AND ucm.MailReplyTo = ''
	                  AND DATEDIFF(
	                          MINUTE,
	                          GETDATE(),
	                          CASE 
	                               WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())
	                               ELSE ISNULL(ucm.ExpiryDate, GETDATE())
	                          END
	                      ) > 0
	                  AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))
	                      
	                      < 0
	       )        A
	ORDER BY
	       A.CampaignID
	
	
	
	SELECT CampaignID,
	       Applicabilty,
	       ExclusionsNumber,
	       Exclusions,
	       InclusionsNumber,
	       AccountUsed,
	       EventsName
	       
	       INTO     #TempMessage
	FROM   (
	           SELECT tt.CampaignID  AS CampaignID,
	                  CASE 
	                       WHEN tt.[Message] = '' THEN CASE 
	                                                        WHEN tt.TemplateID = 
	                                                             0 THEN CASE 
	                                                                         WHEN 
	                                                                              tt.TemplateGroupID 
	                                                                              = 
	                                                                              0 THEN 
	                                                                              ''
	                                                                         ELSE 
	                                                                              1
	                                                                    END
	                                                        ELSE 1
	                                                   END
	                       ELSE 1
	                  END            AS IsMessage,
	                  tt.Applicabilty,
	                  tt.ApplicabiltyGroupList,
	                  tt.ExclusionsGroupList,
	                  tt.ExclusionsNumber,
	                  tt.Exclusions,
	                  tt.InclusionsNumber,
	                  tt.AccountUsed,
	                  tt.EventsName
	           FROM   #TempTemplate     tt
	       )        A
	WHERE  IsMessage = 1
	
	
	
	DECLARE @Body VARCHAR(500)
	
	
	
	IF NOT EXISTS (
	       SELECT 'x'
	       FROM   #TempTemplate
	   )
	BEGIN
	    SET @Body = 'No Campaign Found'
	    
	    
	    
	    SELECT @Body
	END
	ELSE
	BEGIN
	    IF EXISTS(
	           SELECT AccountUsed
	           FROM   #TempMessage tt
	                  INNER JOIN User_Detail ud
	                       ON  ud.[User_ID] = tt.AccountUsed
	           WHERE  ud.[Status] = 0
	       )
	    BEGIN
	        SET @Body = 'User Inactive'
	        
	        
	        
	        SELECT @Body
	    END
	    ELSE
	    BEGIN
	        CREATE TABLE #TempApplicability
	        (
	        	SearchID       BIGINT,
	        	ParentID       BIGINT,
	        	CampaignID     BIGINT
	        )
	        
	        
	        
	        CREATE TABLE #TempApplicabilityGroups
	        (
	        	GroupID        BIGINT,
	        	ParentID       BIGINT,
	        	CampaignID     BIGINT
	        )
	        
	        
	        
	        CREATE TABLE #TempApplicabilityLists
	        (
	        	ListID         BIGINT,
	        	ParentID       BIGINT,
	        	CampaignID     BIGINT
	        )
	        
	        
	        
	        INSERT INTO #TempApplicability
	          (
	            SearchID,
	            ParentID,
	            CampaignID
	          )
	        SELECT tt.Applicabilty,
	               tt.ParentID,
	               tt.CampaignID
	        FROM   #TempTemplate tt
	        
	        
	        
	        INSERT INTO #TempApplicabilityGroups
	          (
	            GroupID,
	            ParentID,
	            CampaignID
	          )
	        SELECT tt.ApplicabiltyGroupList,
	               tt.ParentID,
	               tt.CampaignID
	        FROM   #TempTemplate tt
	        
	        
	        
	        INSERT INTO #TempApplicabilitylists
	          (
	            ListID,
	            ParentID,
	            CampaignID
	          )
	        SELECT tt.ApplicabiltyGroupList,
	               tt.ParentID,
	               tt.CampaignID
	        FROM   #TempTemplate tt
	        
	        
	        
	        CREATE TABLE #TempExclusion
	        (
	        	SearchID       BIGINT,
	        	ParentID       BIGINT,
	        	CampaignID     BIGINT
	        )
	        
	        
	        
	        CREATE TABLE #TempExclusionGroups
	        (
	        	GroupID        BIGINT,
	        	ParentID       BIGINT,
	        	CampaignID     BIGINT
	        )
	        
	        
	        
	        CREATE TABLE #TempExclusionLists
	        (
	        	ListID         BIGINT,
	        	ParentID       BIGINT,
	        	CampaignID     BIGINT
	        )
	        
	        
	        
	        INSERT INTO #TempExclusion
	          (
	            SearchID,
	            ParentID,
	            CampaignID
	          )
	        SELECT tt.Exclusions,
	               tt.ParentID,
	               tt.CampaignID
	        FROM   #TempTemplate tt
	        
	        
	        
	        INSERT INTO #TempExclusionGroups
	          (
	            GroupID,
	            ParentID,
	            CampaignID
	          )
	        SELECT tt.ExclusionsGroupList,
	               tt.ParentID,
	               tt.CampaignID
	        FROM   #TempTemplate tt
	        
	        
	        
	        INSERT INTO #TempExclusionlists
	          (
	            ListID,
	            ParentID,
	            CampaignID
	          )
	        SELECT tt.ExclusionsGroupList,
	               tt.ParentID,
	               tt.CampaignID
	        FROM   #TempTemplate tt
	        
	        
	        
	        CREATE TABLE #TempTableSearchApp
	        (
	        	CampaignID             BIGINT,
	        	SearchID               BIGINT,
	        	ParentID               BIGINT,
	        	PersonName             NVARCHAR(200),
	        	CompanyName            NVARCHAR(200),
	        	MobileNo               NVARCHAR(200),
	        	MobileNo1              NVARCHAR(200),
	        	MobileNo2              NVARCHAR(200),
	        	EmailID                NVARCHAR(200),
	        	EmailID1               NVARCHAR(200),
	        	EmailID2               NVARCHAR(200),
	        	City                   NVARCHAR(200),
	        	STATE                  NVARCHAR(200),
	        	Country                NVARCHAR(200),
	        	CountryCode            NVARCHAR(200),
	        	PinCode                NVARCHAR(200),
	        	ResidentialAddress     NVARCHAR(200),
	        	OfficeAddress          NVARCHAR(200),
	        	SourceName             NVARCHAR(200),
	        	MediumName             NVARCHAR(200),
	        	CampaignName           NVARCHAR(200),
	        	InitialRemarks         NVARCHAR(1000)
	        )
	        
	        
	        
	        CREATE TABLE #TempTableSearchExc
	        (
	        	CampaignID             BIGINT,
	        	SearchID               BIGINT,
	        	ParentID               BIGINT,
	        	PersonName             NVARCHAR(200),
	        	CompanyName            NVARCHAR(200),
	        	MobileNo               NVARCHAR(200),
	        	MobileNo1              NVARCHAR(200),
	        	MobileNo2              NVARCHAR(200),
	        	EmailID                NVARCHAR(200),
	        	EmailID1               NVARCHAR(200),
	        	EmailID2               NVARCHAR(200),
	        	City                   NVARCHAR(200),
	        	STATE                  NVARCHAR(200),
	        	Country                NVARCHAR(200),
	        	CountryCode            NVARCHAR(200),
	        	PinCode                NVARCHAR(200),
	        	ResidentialAddress     NVARCHAR(200),
	        	OfficeAddress          NVARCHAR(200),
	        	SourceName             NVARCHAR(200),
	        	MediumName             NVARCHAR(200),
	        	CampaignName           NVARCHAR(200),
	        	InitialRemarks         NVARCHAR(1000)
	        )
	        
	        
	        
	        DECLARE @CountApp     INT = (
	                    (
	                        SELECT COUNT(*)
	                        FROM   #TempApplicability
	                    )
	                    
	                    + (
	                        SELECT COUNT(*)
	                        FROM   #TempApplicabilityGroups
	                    )
	                    
	                    + (
	                        SELECT COUNT(*)
	                        FROM   #TempApplicabilityLists
	                    )
	                )
	        
	        DECLARE @CountExc     INT = (
	                    (
	                        SELECT COUNT(*)
	                        FROM   #TempExclusion
	                    )
	                    
	                    + (
	                        SELECT COUNT(*)
	                        FROM   #TempExclusionGroups
	                    )
	                    
	                    + (
	                        SELECT COUNT(*)
	                        FROM   #TempExclusionLists
	                    )
	                )
	        
	        DECLARE @Count INT = 0
	        
	        
	        
	        IF (@CountExc > @CountApp)
	        BEGIN
	            SET @Count = @CountExc
	        END
	        ELSE
	        BEGIN
	            SET @Count = @CountApp
	        END
	        
	        
	        
	        WHILE (@Count > 0)
	        BEGIN
	            SET @Count = @Count - 1
	            
	            
	            
	            DECLARE @Applicability1 BIGINT,
	                    @ParentIDApp BIGINT,
	                    @CampaignIDApp BIGINT
	            
	            DECLARE @GroupID BIGINT,
	                    @ParentIDGroup BIGINT,
	                    @CampaignIDGroup BIGINT,
	                    @GroupIDExc BIGINT,
	                    @ParentIDGroupExc BIGINT,
	                    @CampaignIDGroupExc BIGINT
	            
	            DECLARE @ListID              BIGINT,
	                    @ParentIDList        BIGINT,
	                    @CampaignIDList      BIGINT,
	                    @ListIDExc           BIGINT,
	                    @ParentIDListExc     BIGINT,
	                    @CampaignIDListExc BIGINT
	            
	            
	            
	            SELECT TOP 1 @Applicability1 = SearchID,
	                   @ParentIDApp       = ParentID,
	                   @CampaignIDApp     = CampaignID
	            FROM   #TempApplicability
	            ORDER BY
	                   SearchID,
	                   ParentID
	            
	            
	            
	            SELECT TOP 1 @GroupID = GroupID,
	                   @ParentIDGroup       = ParentID,
	                   @CampaignIDGroup     = CampaignID
	            FROM   #TempApplicabilityGroups
	            ORDER BY
	                   GroupID,
	                   ParentID
	            
	            
	            
	            DELETE 
	            FROM   #TempApplicabilityGroups
	            WHERE  GroupID = @GroupID
	                   AND ParentID = @ParentIDGroup
	                   AND CampaignID = @CampaignIDGroup
	            
	            
	            
	            SELECT TOP 1 @ListID = ListID,
	                   @ParentIDList       = ParentID,
	                   @CampaignIDList     = CampaignID
	            FROM   #TempApplicabilitylists
	            ORDER BY
	                   ListID,
	                   ParentID
	            
	            
	            
	            DELETE 
	            FROM   #TempApplicabilitylists
	            WHERE  ListID = @ListID
	                   AND ParentID = @ParentIDGroup
	                   AND CampaignID = @CampaignIDGroup
	            
	            
	            
	            DECLARE @Excluded1         BIGINT,
	                    @ParentIDExc       BIGINT,
	                    @CampaignIDExc     BIGINT
	            
	            
	            
	            SELECT TOP 1 @Excluded1 = SearchID,
	                   @ParentIDExc       = ParentID,
	                   @CampaignIDExc     = CampaignID
	            FROM   #TempExclusion
	            ORDER BY
	                   SearchID,
	                   ParentID
	            
	            
	            
	            SELECT TOP 1 @GroupIDExc = GroupID,
	                   @ParentIDGroupExc = ParentID,
	                   @CampaignIDGroupExc = CampaignID
	            FROM   #TempExclusionGroups
	            ORDER BY
	                   GroupID,
	                   ParentID
	            
	            
	            
	            DELETE 
	            FROM   #TempExclusionGroups
	            WHERE  GroupID = @GroupIDExc
	                   AND ParentID = @ParentIDGroupExc
	                   AND CampaignID = @CampaignIDGroupExc
	            
	            
	            
	            SELECT TOP 1 @ListIDExc = ListID,
	                   @ParentIDListExc = ParentID,
	                   @CampaignIDListExc = CampaignID
	            FROM   #TempExclusionlists
	            ORDER BY
	                   ListID,
	                   ParentID
	            
	            
	            
	            DELETE 
	            FROM   #TempExclusionlists
	            WHERE  ListID = @ListIDExc
	                   AND ParentID = @ParentIDListExc
	                   AND CampaignID = @CampaignIDListExc
	            
	            
	            
	            DELETE 
	            FROM   #TempApplicability
	            WHERE  SearchID = @Applicability1
	                   AND ParentID = @ParentIDApp
	            
	            
	            
	            DELETE 
	            FROM   #TempExclusion
	            WHERE  SearchID = @Excluded1
	                   AND ParentID = @ParentIDExc
	            
	            
	            
	            INSERT INTO #TempTableSearchApp
	              (
	                MobileNo,
	                CampaignID,
	                ParentID
	              )
	            SELECT usd.MobileNumber,
	                   @CampaignIDList,
	                   @ParentIDList
	            FROM   UserSearchData AS usd
	            WHERE  usd.ParentID = @ParentIDList
	                   AND usd.ImportedListID = @ListID
	            
	            
	            
	            INSERT INTO #TempTableSearchApp
	              (
	                MobileNo,
	                CampaignID,
	                ParentID
	              )
	            SELECT cd.Contact_Mobile,
	                   @CampaignIDGroup,
	                   @ParentIDGroup
	            FROM   Contact_Detail AS cd
	                   INNER JOIN Contact_Group_Detail AS cgd
	                        ON  cgd.Contact_ID = cd.Contact_ID
	            WHERE  cgd.Group_ID = @GroupID
	            
	            
	            
	            INSERT INTO #TempTableSearchApp
	              (
	                PersonName,
	                CompanyName,
	                MobileNo,
	                MobileNo1,
	                MobileNo2,
	                EmailID,
	                EmailID1,
	                EmailID2,
	                Country,
	                [STATE],
	                City,
	                PinCode,
	                ResidentialAddress,
	                OfficeAddress,
	                SourceName,
	                MediumName,
	                CampaignName,
	                InitialRemarks,
	                SearchID,
	                ParentID,
	                CampaignID
	              )
	            EXEC usp_ExecuteUserSearch
	                 
	                 @ParentIDApp,
	                 @Applicability1,
	                 @CampaignIDApp
	            
	            
	            
	            INSERT INTO #TempTableSearchExc
	              (
	                MobileNo,
	                CampaignID,
	                ParentID
	              )
	            SELECT usd.MobileNumber,
	                   @CampaignIDListExc,
	                   @ParentIDListExc
	            FROM   UserSearchData AS usd
	            WHERE  usd.ParentID = @ParentIDListExc
	                   AND usd.ImportedListID = @ListIDExc
	            
	            
	            
	            INSERT INTO #TempTableSearchExc
	              (
	                MobileNo,
	                CampaignID,
	                ParentID
	              )
	            SELECT cd.Contact_Mobile,
	                   @CampaignIDGroupExc,
	                   @ParentIDGroupExc
	            FROM   Contact_Detail AS cd
	                   INNER JOIN Contact_Group_Detail AS cgd
	                        ON  cgd.Contact_ID = cd.Contact_ID
	            WHERE  cgd.Group_ID = @GroupIDExc
	            
	            
	            
	            INSERT INTO #TempTableSearchExc
	              (
	                PersonName,
	                CompanyName,
	                MobileNo,
	                MobileNo1,
	                MobileNo2,
	                EmailID,
	                EmailID1,
	                EmailID2,
	                Country,
	                [STATE],
	                City,
	                PinCode,
	                ResidentialAddress,
	                OfficeAddress,
	                SourceName,
	                MediumName,
	                CampaignName,
	                InitialRemarks,
	                SearchID,
	                ParentID,
	                CampaignID
	              )
	            EXEC usp_ExecuteUserSearch
	                 
	                 @ParentIDExc,
	                 @Excluded1,
	                 @CampaignIDExc
	        END
	    END
	END
	 
	
	IF EXISTS(
	       SELECT *
	       FROM   #TempTemplate
	       WHERE  EventsName = 'ENQADD'
	   )
	BEGIN
	    SELECT ue.MobileNo,
	           ue.ParentID,
	            ucs.CampaignID INTO #TempEnq
	    FROM   UserEnquiry               AS ue
	            OUTER APPLY #TempTableSearchApp ucs
	    WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))
	           
	           >= -5
	           AND ucs.ParentID=ue.ParentID
	           AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))
	               
	               <= 0
	           AND ue.ParentID IN (SELECT tt.ParentID
	                               FROM   #TempTemplate tt
	                               WHERE  EventsName = 'ENQADD')
	           AND (
	                   CAST(ue.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                   
	                   NOT  IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	                   OR CAST(ue.MobileNo1 COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                      
	                      NOT IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	                   OR CAST(ue.MobileNo2 COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                      
	                      NOT
	                      
	                      IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	               )
	    
	    
	    
	    INSERT INTO UserCampaignExecutionHistory
	      (
	        -- ID -- this column value is auto-generated
	        
	        CampaignID,
	        ExecutionTime,
	        NoOfRecipients,
	        Response,
	        BatchID,
	        IsRecipients,
	        IsMessages,
	        IsExecuted,
	        ParentID
	      )
	    SELECT DISTINCT tt.CampaignID,
	           GETDATE(),
	           0,
	           NULL,
	           0,
	           1,
	           0,
	           0,
	           tt.ParentID
	    FROM   #TempEnq tt
	    
	    
	    
	    INSERT INTO UserCampaignExecutionRecipientsMessage
	      (
	        -- MessageID -- this column value is auto-generated
	        
	        BatchID,
	        Mobile,
	        [Message],
	        MessageStatus,
	        SenderID,
	        MessageInsertDate,
	        ScheduledDate,
	        ScheduledTime,
	        SmppID,
	        U_ID,
	        IsUniCode,
	        IsDnd,
	        IsAirtel,
	        MobileSubSet,
	        ValidNo,
	        IsPrority,
	        IsAllowDND,
	        DBType,
	        ParentID,
	        CampaignID,
	        IsCompleted
	      )
	    SELECT NULL,
	           tt.MobileNo,
	           NULL,
	           NULL,
	           NULL,
	           GETDATE(),
	           GETDATE(),
	           GETDATE(),
	           (
	               SELECT TOP 1 ud.SmppID
	               FROM   User_Detail AS ud
	               WHERE  ud.[User_ID] IN (SELECT ucm.AccountUsed
	                                       FROM   UserCampaignMaster AS ucm
	                                       WHERE  ucm.ID = tt.CampaignID)
	           ),
	           (
	               SELECT TOP 1 ucm.AccountUsed
	               FROM   UserCampaignMaster AS ucm
	               WHERE  ucm.ID = tt.CampaignID
	           ),
	           0,
	           0,
	           0,
	           '',
	           0,
	           0,
	           0,
	           '',
	           tt.ParentID,
	           tt.CampaignID,
	           0
	    FROM   #TempEnq tt
	    
	    
	    
	    DROP TABLE #TempEnq
	END
	
	
	
	IF EXISTS(
	       SELECT *
	       FROM   #TempTemplate
	       WHERE  EventsName = 'LEDADD'
	   )
	BEGIN
	    SELECT ue.MobileNo,
	           ue.ParentID,
	           ucs.CampaignID  AS CampaignID
	           
	           INTO #TempLeads
	    FROM   UserLeads                 AS ue
	         OUTER APPLY #TempTableSearchApp ucs
	    WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedOn, GETDATE()))
	           
	           >= -5
	           AND ucs.ParentID=ue.ParentID
	           AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedOn, GETDATE()))
	               
	               <= 0
	           AND ue.ParentID IN (SELECT tt.ParentID
	                               FROM   #TempTemplate tt
	                               WHERE  EventsName = 'ENQADD')
	           AND (
	                   CAST(ue.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                   
	                   NOT  IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	                   OR CAST(ue.MobileNo1 COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                      
	                      NOT IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	                   OR CAST(ue.MobileNo2 COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                      
	                      NOT
	                      
	                      IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	               )
	    
	    
	    
	    
	    INSERT INTO UserCampaignExecutionHistory
	      (
	        -- ID -- this column value is auto-generated
	        
	        CampaignID,
	        ExecutionTime,
	        NoOfRecipients,
	        Response,
	        BatchID,
	        IsRecipients,
	        IsMessages,
	        IsExecuted,
	        ParentID
	      )
	    SELECT DISTINCT tt.CampaignID,
	           GETDATE(),
	           0,
	           NULL,
	           0,
	           1,
	           0,
	           0,
	           tt.ParentID
	    FROM   #TempLeads tt
	    
	    
	    
	    INSERT INTO UserCampaignExecutionRecipientsMessage
	      (
	        -- MessageID -- this column value is auto-generated
	        
	        BatchID,
	        Mobile,
	        [Message],
	        MessageStatus,
	        SenderID,
	        MessageInsertDate,
	        ScheduledDate,
	        ScheduledTime,
	        SmppID,
	        U_ID,
	        IsUniCode,
	        IsDnd,
	        IsAirtel,
	        MobileSubSet,
	        ValidNo,
	        IsPrority,
	        IsAllowDND,
	        DBType,
	        ParentID,
	        CampaignID,
	        IsCompleted
	      )
	    SELECT NULL,
	           tt.MobileNo,
	           NULL,
	           NULL,
	           NULL,
	           GETDATE(),
	           GETDATE(),
	           GETDATE(),
	           (
	               SELECT TOP 1 ud.SmppID
	               FROM   User_Detail AS ud
	               WHERE  ud.[User_ID] IN (SELECT ucm.AccountUsed
	                                       FROM   UserCampaignMaster AS ucm
	                                       WHERE  ucm.ID = tt.CampaignID)
	           ),
	           (
	               SELECT TOP 1 ucm.AccountUsed
	               FROM   UserCampaignMaster AS ucm
	               WHERE  ucm.ID = tt.CampaignID
	           ),
	           0,
	           0,
	           0,
	           '',
	           0,
	           0,
	           0,
	           '',
	           tt.ParentID,
	           tt.CampaignID,
	           0
	    FROM   #TempLeads tt
	    
	    
	    
	    DROP TABLE #TempLeads
	END
	
	
	
	IF EXISTS(
	       SELECT *
	       FROM   #TempTemplate
	       WHERE  EventsName = 'FOLADD'
	   )
	BEGIN
	    SELECT ue.MobileNo,
	           ue.ParentID,
	           ucs.CampaignID  AS CampaignID
	           
	           INTO #TempFollowUp
	    FROM   UserLeads                 AS ue
	           INNER JOIN LeadInteractionHistory AS lih
	                ON  lih.LeadNo = ue.LeadNo
	                AND lih.ParentID = ue.ParentID 
	        OUTER APPLY #TempTableSearchApp ucs
	    WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(lih.CreatedOn, GETDATE()))
	           
	           >= -5
	           AND ucs.ParentID=ue.ParentID
	           AND DATEDIFF(MINUTE, GETDATE(), ISNULL(lih.CreatedOn, GETDATE()))
	               
	               <= 0
	           AND ue.ParentID IN (SELECT tt.ParentID
	                               FROM   #TempTemplate tt
	                               WHERE  EventsName = 'ENQADD')
	           AND (
	                   CAST(ue.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                   
	                   NOT  IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	                   OR CAST(ue.MobileNo1 COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                      
	                      NOT IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	                   OR CAST(ue.MobileNo2 COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                      
	                      NOT
	                      
	                      IN (SELECT  CAST(A.MobileNo COLLATE Latin1_General_CI_AI AS VARCHAR(50))
	                            FROM   (
	                                       SELECT tsex.MobileNo
	                                       FROM   #TempTableSearchexc AS tsex
	                                       UNION
	                                       SELECT tsex.MobileNo1
	                                       FROM   #TempTableSearchexc AS tsex 
	                                       UNION
	                                       SELECT tsex.MobileNo2
	                                       FROM   #TempTableSearchexc AS tsex
	                                   ) A
	                   )
	               )
	    
	    
	    
	    INSERT INTO UserCampaignExecutionHistory
	      (
	        -- ID -- this column value is auto-generated
	        
	        CampaignID,
	        ExecutionTime,
	        NoOfRecipients,
	        Response,
	        BatchID,
	        IsRecipients,
	        IsMessages,
	        IsExecuted,
	        ParentID
	      )
	    SELECT DISTINCT tt.CampaignID,
	           GETDATE(),
	           0,
	           NULL,
	           0,
	           1,
	           0,
	           0,
	           tt.ParentID
	    FROM   #TempFollowUp tt
	    
	    
	    
	    INSERT INTO UserCampaignExecutionRecipientsMessage
	      (
	        -- MessageID -- this column value is auto-generated
	        
	        BatchID,
	        Mobile,
	        [Message],
	        MessageStatus,
	        SenderID,
	        MessageInsertDate,
	        ScheduledDate,
	        ScheduledTime,
	        SmppID,
	        U_ID,
	        IsUniCode,
	        IsDnd,
	        IsAirtel,
	        MobileSubSet,
	        ValidNo,
	        IsPrority,
	        IsAllowDND,
	        DBType,
	        ParentID,
	        CampaignID,
	        IsCompleted
	      )
	    SELECT NULL,
	           tt.MobileNo,
	           NULL,
	           NULL,
	           NULL,
	           GETDATE(),
	           GETDATE(),
	           GETDATE(),
	           (
	               SELECT TOP 1 ud.SmppID
	               FROM   User_Detail AS ud
	               WHERE  ud.[User_ID] IN (SELECT ucm.AccountUsed
	                                       FROM   UserCampaignMaster AS ucm
	                                       WHERE  ucm.ID = tt.CampaignID)
	           ),
	           (
	               SELECT TOP 1 ucm.AccountUsed
	               FROM   UserCampaignMaster AS ucm
	               WHERE  ucm.ID = tt.CampaignID
	           ),
	           0,
	           0,
	           0,
	           '',
	           0,
	           0,
	           0,
	           '',
	           tt.ParentID,
	           tt.CampaignID,
	           0
	    FROM   #TempFollowUp tt
	    
	    
	    
	    DROP TABLE #TempFollowUp
	END
	
	
	
	DROP TABLE #TempTableSearchApp
	
	
	
	DROP TABLE #TempExclusion
	
	
	
	DROP TABLE #TempApplicability
	
	
	
	DROP TABLE #TempExclusionGroups
	
	
	
	DROP TABLE #TempApplicabilityGroups
	
	
	
	DROP TABLE #TempExclusionLists
	
	
	
	DROP TABLE #TempApplicabilityLists
	
	
	
	DROP TABLE #TempTableSearchExc
	
	
	
	DROP TABLE #TempTemplate
	
	
	
	DROP TABLE #TempMessage
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetRecipientsEventBasedMails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

              
CREATE   PROCEDURE [dbo].[usp_GetRecipientsEventBasedMails]              
              
AS              
              
BEGIN              
              
 SELECT A.CampaignID,              
              
        A.ParentID,              
              
        A.Applicabilty,              
              
        A.ApplicabiltyGroupList,              
              
        A.ExclusionsGroupList,              
              
        A.NotificationMail,              
              
        A.ExclusionsNumber,              
              
        A.Exclusions,              
              
        A.InclusionsNumber,              
              
        A.AccountUsed,              
              
        A.SenderID,              
              
        A.[Message],              
              
        A.TemplateID,              
              
        A.TemplateGroupID,              
              
        A.IsUnicode,              
              
        A.EventsName              
              
                      
              
        INTO #TempTemplate              
              
 FROM   (              
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   fs.[value]  AS Applicabilty,              
              
                   0           AS ApplicabiltyGroupList,              
              
                   0           AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   0           AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm              
              
                   OUTER APPLY dbo.fn_Split(ucm.Applicabilty, '#') AS fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
                   AND ucm.MailReplyTo <> ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))               
              
                       < 0              
              
                          
              
            UNION ALL              
              
                          
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   0           AS Applicabilty,              
              
                   fs.[value]  AS ApplicabiltyGroupList,              
              
                   0           AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   0           AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
         
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm        
              
                   OUTER APPLY dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS               
              
            fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
                   AND ucm.MailReplyTo <> ''             
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                 ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))               
              
                       < 0              
              
                          
              
            UNION ALL              
              
                          
              
           SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   0           AS Applicabilty,              
              
                   0           AS ApplicabiltyGroupList,              
              
                   fs.[value]  AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   0       AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm              
              
                   OUTER APPLY dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS               
              
            fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
                   AND ucm.MailReplyTo <> ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
                           GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))               
              
                  < 0              
              
                          
              
            UNION ALL              
              
                          
              
            SELECT ucm.ID      AS CampaignID,              
              
                   ucm.ParentID,              
              
                   0           AS Applicabilty,              
              
                   0           AS ApplicabiltyGroupList,              
              
                   0           AS ExclusionsGroupList,              
              
                   ucm.NotificationMail,              
              
                   ucm.ExclusionsNumber,              
              
                   fs.[value]  AS Exclusions,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.AccountUsed,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
              
                   ucm.TemplateID,              
              
                   ucm.TemplateGroupID,              
              
                   ucm.IsUnicode,              
              
                   ucm.EventsName              
              
            FROM   UserCampaignMaster ucm              
              
                   OUTER APPLY dbo.fn_Split(ucm.Exclusions, '#') AS fs              
              
            WHERE  ucm.IsEventBased = 1              
              
                   AND ucm.IsActive = 1              
              
                   AND ucm.MailReplyTo <> ''              
              
                   AND DATEDIFF(              
              
                           MINUTE,              
              
    GETDATE(),              
              
                           CASE               
              
                                WHEN ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1, GETDATE())              
              
                                ELSE ISNULL(ucm.ExpiryDate, GETDATE())              
              
                           END              
              
                       ) > 0              
              
                   AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ucm.StartDate, GETDATE()))               
              
                       < 0              
              
        )              
              
                      
              
        A              
              
