             CampaignID              
              
           )              
              
         EXEC usp_ExecuteUserSearch              
              
                            
              
              @ParentIDApp,              
              
              @Applicability1,              
              
              @CampaignIDApp              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchExc              
              
           (              
              
             EmailID,              
              
      CampaignID,              
              
             ParentID              
              
           )              
           
         SELECT usd.EmailID,              
              
                @CampaignIDListExc,              
              
                @ParentIDListExc              
              
         FROM   UserSearchData AS usd              
              
         WHERE  usd.ParentID = @ParentIDListExc              
              
                AND usd.ImportedListID = @ListIDExc              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchExc              
              
           (              
              
             EmailID,              
              
             CampaignID,              
              
             ParentID              
              
           )              
              
         SELECT cd.Contact_Email,              
              
                @CampaignIDGroupExc,              
              
                @ParentIDGroupExc              
              
         FROM   Contact_Detail AS cd              
              
                INNER JOIN Contact_Group_Detail AS cgd              
              
                     ON  cgd.Contact_ID = cd.Contact_ID              
              
         WHERE  cgd.Group_ID = @GroupIDExc              
              
                       
              
                       
              
                       
              
         INSERT INTO #TempTableSearchExc              
              
           (              
              
             PersonName,            
              
             CompanyName,              
              
             MobileNo,              
              
             MobileNo1,              
              
             MobileNo2,              
              
    EmailID,              
              
             EmailID1,              
              
             EmailID2,              
              
             Country,              
              
             [STATE],              
              
             City,              
              
             PinCode,              
              
             ResidentialAddress,              
              
             OfficeAddress,              
              
             SourceName,              
              
             MediumName,              
              
             CampaignName,              
              
             InitialRemarks,              
              
             SearchID,              
              
             ParentID,              
              
             CampaignID              
              
           )              
              
         EXEC usp_ExecuteUserSearch              
              
                            
              
              @ParentIDExc,              
              
              @Excluded1,              
              
            @CampaignIDExc              
              
     END              
              
 END              
              
               
              
               
              
               
              
 IF EXISTS(              
              
        SELECT *              
              
        FROM   #TempTemplate              
              
        WHERE  EventsName = 'ENQADD'              
              
    )              
              
 BEGIN              
              
     SELECT tt.EmailID,              
              
            tt.ParentID,              
              
            ucs.CampaignID              
              
                          
              
            INTO #TempEnq              
              
     FROM   (              
              
                SELECT ue.EmailID,              
             
                       ue.ParentID,              
              
                       ue.CreatedDate              
              
                FROM   UserEnquiry AS ue              
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
       <= 0              
              
                       AND ue.ParentID IN (SELECT tt.ParentID              
              
                                           FROM   #TempTemplate tt              
              
                                           WHERE  EventsName = 'ENQADD')              
              
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                           >= -2              
              
                              
              
                UNION              
              
                              
              
                SELECT ue.EmailID1,              
              
                       ue.ParentID,              
              
                       ue.CreatedDate              
              
                FROM   UserEnquiry AS ue              
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                       <= 0              
              
                       AND ue.ParentID IN (SELECT tt.ParentID              
              
                                           FROM   #TempTemplate tt              
              
                                           WHERE  EventsName = 'ENQADD')              
              
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                           >= -2              
              
                              
              
                UNION              
              
                              
              
                SELECT ue.EmailID2,              
              
                       ue.ParentID,              
              
                       ue.CreatedDate              
              
                FROM   UserEnquiry AS ue              
              
                WHERE  DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                       <= 0              
              
                       AND ue.ParentID IN (SELECT tt.ParentID              
       
                                           FROM   #TempTemplate tt              
              
                                           WHERE  EventsName = 'ENQADD')              
              
                       AND DATEDIFF(MINUTE, GETDATE(), ISNULL(ue.CreatedDate, GETDATE()))               
              
                           >= -2              
              
       ) tt              
              
            OUTER APPLY #TempTableSearchApp ucs              
              
     WHERE  ucs.ParentID = tt.ParentID              
              
