                       tt.ParentID,              
              
                       tt.CampaignID              
              
                FROM   #TempFollowUp     tt              
              
                WHERE  tt.EmailID <> ''              
              
            ) A              
              
                   
UPDATE A                
SET step1=1,step1datetime=getdate(),step1recipients = isnull(B.[RecipientsCount],0)      
FROM [dbo].UserCampaignHistory A INNER JOIN                 
(SELECT a.campaignid as campaignid,isnull(count(e.CampaignID),0) AS [RecipientsCount]                
         FROM UserCampaignHistory A left outer join [dbo].[EmailsFilterCampaignExecution] e on e.CampaignID=a.ID group by a.campaignid                
 ) B                
ON A.[campaignid] = B.[campaignid] join ##campaignrunmail c on a.ID=c.CampaignrunID                                   
            
                   
              
                   
              
     DROP TABLE #TempFollowUp              
              
