update UserCampaignExecution                                            
set CampaignExecutedDatetime=@CampaignStarttime                                            
where issms=0 and isevent=1          
exec Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail @jobid      
end      
  else      
  begin      
  if (select Lasterrorreported from UserCampaignExecution where issms=0 and isnull(isevent,0)=1) is null or (DATEDIFF(mi,(select isnull(Lasterrorreported,dateadd(mi,-6,getdate())) from UserCampaignExecution where issms=0 and isnull(isevent,0)=1),getdate( 
 
    
))>5 and DATEDIFF(mi,(select isnull(CampaignExecutedDatetime,dateadd(mi,-6,getdate())) from UserCampaignExecution where issms=0 and isnull(isevent,0)=1),getdate())>5)      
  begin      
  declare @campaignstart datetime =(select CampaignExecutedDatetime from UserCampaignExecution where issms=0 and isnull(isevent,0)=1)      
  , @lastjobid bigint =(select isnull(cjobid,(select top 1 jobid from usercampaignhistory (nolock) where issms=0 and iseventbased=1 and       
  campaignid<>0 and jobid<>@jobid order by ID desc)) from usercampaignexecution where issms=0 and isevent=1)      
      
  select top 1 @campaignstart = CreatedOn from usercampaignhistory(nolock) where jobid=@lastjobid      
      
  declare @step int = (select top 1 case when step2datetime is null then 2 else 3 end from usercampaignhistory (nolock) where jobid=@lastjobid)      
  declare @error nvarchar(200)='Last Campaign with jobid ' + cast(@lastjobid as varchar(10)) + ' failed at step ' + cast(@step as varchar) + ' running since ' + cast(@campaignstart as nvarchar(20))      
  exec usp_InsertCampaignError'Mail',1,@error      
        
  if @step=2      
  begin      
  exec Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail @lastjobid      
  end      
  else if @step=3      
  begin      
  exec Usp_insertclonedeliverycampaignmailsCorrected_segregatemail @lastjobid      
  end      
      
        
  update UserCampaignExecution set Lasterrorreported=GETDATE() where issms=0 and isnull(isevent,0)=1      
  --GOTO RETRY      
  end      
  end   
  */   
END         
        


