--Review the stored procedure along with shruthi. Check last two update statement  
    
CREATE   PROCEDURE [dbo].[usp_GetRecipientsEventBasedMailsCorrected_withcampaignmessage]  --(@jobScheduleId bigint)                
AS                  
BEGIN                                
  
 DECLARE @Body VARCHAR(500)                                        
 DEclare @JobId Bigint = (Select ISNULL(MAX(JobId),0)+1 from UserCampaignHistory UCH )  
  declare @campaignstartdate datetime=getdate()
  INSERT INTO UserCampaignHistory                 
 (              
     -- ID -- this column value is auto-generated                  
 CampaignID,                  
    ParentID,                  
    Step1,                  
    Step2,                  
    Step3,               
    IsSMS,                  
    IsMail,                  
    IsScheduled,                  
    IsEventBased,                  
    CreatedOn,  
 JobId                  
   )                  
   --output getdate(),inserted.id,inserted.campaignid into ##campaignrunmail                 
 SELECT 0,                  
        0,                  
        0,                  
        0,                  
        0,                  
        0,                  
        1,                  
        0,                  
        1,                  
        @campaignstartdate,  
  @JobId 
   
 DECLARE @LastExecutedTime datetime = isnull((select Top 1 CampaignExecutedDatetime from UserCampaignExecution where issms=0 and isevent=1 order by id desc),getdate())   

RETRY:  
 if exists(select 1 from UserCampaignExecution where issms=0 and isnull(isevent,0)=1 and isrunning=0)
 begin
 update UserCampaignExecution set isrunning=1,Cjobid=@Jobid where issms=0 and isnull(isevent,0)=1
   
 Declare @CampaignStarttime datetime = Getdate()  
   
  if OBJECT_ID('tempdb..#temptemplate') is not null                
 Begin   
 Drop table #temptemplate   
end    
  
 SELECT      ROW_NUMBER()Over(Order by Ucm.ID,Ucm.ParentID) AS Id,  
       ucm.ID      AS CampaignID,                  
                   ucm.ParentID,                  
                   A.[value]  AS Applicabilty,                  
                   AGL.[value] AS ApplicabiltyGroupList,                  
                   EGL.[Value] AS ExclusionsGroupList,                  
                   ucm.NotificationMail,                  
                   ucm.ExclusionsNumber,                  
                   E.[Value] AS Exclusions,                  
                   ucm.InclusionsNumber,                  
                   ucm.AccountUsed,                  
                   ucm.SenderID,                  
                   ucm.[Message],                  
                   ucm.TemplateID,                  
                   ucm.TemplateGroupID,                  
                   ucm.IsUnicode,                  
                   ucm.EventsName      INTO #TempTemplate            
            FROM   UserCampaignMaster ucm    
   Inner join  User_detail AS Ud  on Ud.[User_ID]  = AccountUsed and Ud.[Status] <> 0                       
            OUTER APPLY dbo.fn_Split(ucm.Applicabilty, '#') AS A     
   OUTER APPLY dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS AGL  
   OUTER APPLY dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS EGL               
   OUTER APPLY dbo.fn_Split(ucm.Exclusions, '#') AS E                  
           WHERE  ucm.IsEventBased = 1                  
                  AND ucm.IsActive = 1                  
                 AND ucm.MailReplyTo <> ''   
      AND DATEDIFF(                                        
                           Minute,                                        
                           getdate(),                                        
                           CASE                                         
                                WHEN Ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1,getdate())                                        
                                ELSE ISNULL(Ucm.ExpiryDate, getdate())                                        
                       END                                        
                       ) > 0                                        
                   AND DATEDIFF(Minute, getdate(), ISNULL(Ucm.StartDate, getdate()))  < 0                                        
   
    SELECT ud.EMail,ucm.AccountUsed,ucm.Id As CampaignId,ucm.ParentID,tt.templateid into #UserAccountDetails  
 FROM   UserCampaignMaster AS ucm  
 Inner join User_Detail AS ud on ud.[User_ID] = ucm.AccountUsed  
 Inner join #TempTemplate tt on tt.CampaignId = ucm.ID  
    WHERE  ucm.ID = tt.CampaignID AND ucm.IsActive = 1  
             
 INSERT INTO UserCampaignHistory                 
 (              
     -- ID -- this column value is auto-generated                  
 CampaignID,                  
    ParentID,                  
    Step1,                  
    Step2,                  
    Step3,               
    IsSMS,                  
    IsMail,                  
    IsScheduled,                  
    IsEventBased,                  
    CreatedOn,  
 JobId                  
   )                  
   --output getdate(),inserted.id,inserted.campaignid into ##campaignrunmail                 
 SELECT CampaignID,                  
        ParentID,                  
        0,                  
        0,                  
        0,                  
        0,                  
        1,                  
        0,                  
        1,                  
        @campaignstartdate,  
  @JobId                
 FROM   #TempTemplate                  
                  
 IF NOT EXISTS (SELECT 'x' FROM   #TempTemplate )                  
 BEGIN                  
     SET @Body = 'No Campaign Found'                  
     SELECT @Body 
     INSERT INTO UserCampaignHistory                 
 (              
     -- ID -- this column value is auto-generated                  
 CampaignID,                  
    ParentID,                  
    Step1,                  
    Step2,                  
    Step3,               
    IsSMS,                  
    IsMail,                  
    IsScheduled,                  
    IsEventBased,                  
    CreatedOn,  
 JobId                  
   )                  
   --output getdate(),inserted.id,inserted.campaignid into ##campaignrunmail                 
 SELECT 0,                  
        0,                  
        0,                  
        0,                  
        0,                  
        0,                  
        1,                  
        0,                  
        1,                  
        GETDATE()  ,  
  @JobId                      
 END                  
 ELSE                  
 BEGIN   
       CREATE TABLE #temptablesearchapp                                        
     (                                        
      CampaignID             BIGINT,                                        
      SearchID               BIGINT,                                        
      ParentID               BIGINT,                                        
      PersonName             NVARCHAR(200),                          
      CompanyName            NVARCHAR(200),                                        
      MobileNo               NVARCHAR(200),                                        
      MobileNo1              NVARCHAR(200),                                        
      MobileNo2              NVARCHAR(200),                                        
      EmailID                NVARCHAR(200),                                        
      EmailID1               NVARCHAR(200),                                        
      EmailID2               NVARCHAR(200),                                        
      City      NVARCHAR(200),                                        
      STATE                  NVARCHAR(200),                                        
   Country     NVARCHAR(200),                                        
      CountryCode            NVARCHAR(200),                                        
      PinCode     NVARCHAR(200),                                        
      ResidentialAddress     NVARCHAR(200),                                        
      OfficeAddress          NVARCHAR(200),                                        
      SourceName             NVARCHAR(200),                                        
      MediumName             NVARCHAR(200),                                        
      CampaignName           NVARCHAR(200),                                        
      InitialRemarks         NVARCHAR(1000)                                        
     )              
                  
     CREATE TABLE #temptablesearchexc                                        
     (                                
      CampaignID             BIGINT,                                        
      SearchID               BIGINT,                                        
      ParentID               BIGINT,                                        
      PersonName             NVARCHAR(200),                                        
      CompanyName            NVARCHAR(200),                                        
      MobileNo               NVARCHAR(200),                                        
      MobileNo1              NVARCHAR(200),                                        
      MobileNo2              NVARCHAR(200),                                        
      EmailID   NVARCHAR(200),                                        
      EmailID1               NVARCHAR(200),                                        
      EmailID2               NVARCHAR(200),                                        
      City                   NVARCHAR(200),                                        
      STATE                  NVARCHAR(200),                                        
      Country NVARCHAR(200),                                        
      CountryCode            NVARCHAR(200),                                        
      PinCode                NVARCHAR(200),                                        
      ResidentialAddress     NVARCHAR(200),                                        
      OfficeAddress          NVARCHAR(200),                                        
      SourceName             NVARCHAR(200),                                        
      MediumName             NVARCHAR(200),                                        
      CampaignName           NVARCHAR(200),                                        
      InitialRemarks         NVARCHAR(1000)                                        
     )                  
                  
    INSERT INTO #temptablesearchapp(  EmailID,CampaignID,ParentID  )                                        
    Select ISNULL(Usd.EmailID, ''),Tt.CampaignID, Tt.ParentID     
 FROM  #temptemplate TT  
 Inner join  Usersearchdata AS Usd  (nolock)  on   
 Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.ApplicabiltyGroupList and Tt.ApplicabiltyGroupList is not null                       
 INSERT INTO #temptablesearchapp(EmailID,CampaignID,ParentID)                                        
    SELECT ISNULL(Cd.Contact_Email, ''),Tt.CampaignID, Tt.ParentID     
    FROM  #temptemplate TT                                     
 Inner join Contact_group_detail AS Cgd  (nolock) on Cgd.Group_ID = TT.ApplicabiltyGroupList and Tt.ApplicabiltyGroupList is not null               
    INNER JOIN Contact_detail  AS  Cd   (nolock) ON  Cgd.Contact_ID = Cd.Contact_ID     
     
    INSERT INTO #temptablesearchexc (  EmailID,CampaignID,ParentID  )            
 SELECT ISNULL(Usd.EmailID, ''),Tt.CampaignID, Tt.ParentID     
 FROM #temptemplate TT                 
 Inner join   Usersearchdata AS Usd  (nolock) on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.ExclusionsGroupList   
 and Tt.ExclusionsGroupList is not null                       
                                                                              
    INSERT INTO #temptablesearchexc  (  EmailID,CampaignID,ParentID  )                                                               
 SELECT ISNULL(Cd.Contact_Email, ''),Tt.CampaignID, Tt.ParentID     
 FROM  #temptemplate TT                                     
 Inner join Contact_group_detail AS Cgd  (nolock) on Cgd.Group_ID = TT.ExclusionsGroupList and Tt.ExclusionsGroupList is not null  INNER JOIN Contact_detail  AS  Cd   (nolock) ON  Cgd.Contact_ID = Cd.Contact_ID    
      
create table #EligibleCampaigns(Id int identity(1,1),Campaignid bigint,parentid bigint,accountused bigint,applicabilty bigint,exclusions bigint)  
 insert into #EligibleCampaigns(Campaignid ,parentid ,accountused ,applicabilty ,exclusions)  
 select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t join userenquiry u on t.ParentID=u.ParentID and t.EventsName='enqadd' where u.CreatedDate>@LastExecutedTime  
 union  
 select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t join userleads u on t.ParentID=u.ParentID and t.EventsName='LEDADD' where u.Createdon>@LastExecutedTime   
 union  
 select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t join userleads u on t.ParentID=u.ParentID and t.EventsName='FOLADD' join LeadInteractionHistory l on u.LeadNo=l.LeadNo and u.ParentID=l.ParentID where l.Createdon>@LastExecutedTime  
  
  --select * from #EligibleCampaigns     
      
 DECLARE @CountCampaign     INT = isnull((Select MAX(Id) from #EligibleCampaigns),0    )                                        
    DECLARE @Count INT = 1                                                                         
                                             
    WHILE (@Count <= @CountCampaign)                                        
    BEGIN                    
         DECLARE @Applicability BIGINT,                                     
      @Exclusions BIGINT,  
                 @Parentid BIGINT,                                        
                 @Campaignid BIGINT       
                
         Select @Campaignid =Campaignid, @Parentid = Parentid  
         ,@Applicability = tt.Applicabilty,@Exclusions = tt.Exclusions  
         from #EligibleCampaigns tt Where Id = @Count             
                  
         If(@Applicability is not null)  
         Begin                                         
    INSERT INTO #temptablesearchapp                                        
    (                                       
      PersonName,                                        
      CompanyName,                                        
      MobileNo,                                        
      MobileNo1,                                        
      MobileNo2,                                        
      EmailID,                                        
      EmailID1,                                        
      EmailID2,                                        
      Country,                                        
      [STATE],                           
      City,                                  
      PinCode,                                        
      ResidentialAddress,                                        
      OfficeAddress,                                        
      SourceName,                                        
      MediumName,                                        
      CampaignName,                                        
      InitialRemarks,                                        
      SearchID,                                        
      ParentID,                                        
      CampaignID                                        
    )                                        
    EXEC Usp_executeusersearch                                        
       @ParentId,                                        
       @Applicability,                                        
       @Campaignid  
         End  
            
         if(@Exclusions is not null)  
         Begin                                    
    INSERT INTO #temptablesearchexc                                        
      (                                        
     PersonName,                                        
     CompanyName,                                        
     MobileNo,                                        
     MobileNo1,                                        
     MobileNo2,                                        
     EmailID,                                        
     EmailID1,                                        
     EmailID2,                                        
     Country,                                        
     [STATE],                                        
     City,                                        
     PinCode,                                        
     ResidentialAddress,                                        
    OfficeAddress,                                        
     SourceName,                                        
     MediumName,                                        
     CampaignName,                                        
     InitialRemarks,                                        
     SearchID,                                        
     ParentID,                                        
     CampaignID                                        
      )                                        
    EXEC Usp_executeusersearch                                        
      @Parentid,                                        
      @Exclusions,                                        
      @Campaignid  
      
   END  
     
    
       
  SET @Count = @Count+1  
       
     END  
     
     drop table #EligibleCampaigns 
  
    SELECT Distinct A.EmailID,                                        
            A.ParentID,                                        
            A.CampaignID                                        
            INTO     #tmpemailid                    
     FROM   (                                        
                SELECT Tt2.EmailID,                                        
                       Tt2.ParentID,                                        
                       Tt2.CampaignID                                        
                FROM   #TempTableSearchApp Tt2                                        
                WHERE  NOT EXISTS (SELECT 1 FROM   #temptablesearchexc Tt   
       Where (tt.CampaignID=tt2.CampaignID) and (Tt2.EmailID = Tt.EmailID OR Tt2.EmailID = Tt.EmailID1 OR Tt2.EmailID = Tt.EmailID2 ) )                         
    UNION                                        
                  
    SELECT Tt2.EmailID1,                                        
                       Tt2.ParentID,                                        
        Tt2.CampaignID                                        
                FROM   #TempTableSearchApp Tt2                   
                 WHERE  NOT EXISTS (SELECT 1                                        
                                           FROM   #temptablesearchexc Tt Where (tt.CampaignID=tt2.CampaignID) and (Tt2.EmailID1 = Tt.EmailID OR Tt2.EmailID1 = Tt.EmailID1 OR  Tt2.EmailID1 = Tt.EmailID2)  )     
                UNION                                        
                SELECT Tt2.EmailID2,                                        
                       Tt2.ParentID,                                        
                       Tt2.CampaignID                                        
                FROM   #TempTableSearchApp Tt2                                        
                 WHERE  NOT EXISTS (SELECT 1                                        
                                           FROM   #temptablesearchexc Tt Where (tt.CampaignID=tt2.CampaignID) and (Tt2.EmailID2 = Tt.EmailID OR Tt2.EmailID2 = Tt.EmailID1 OR  Tt2.EmailID2= Tt.EmailID2)  )     
       )        A         
                  
 IF EXISTS( SELECT * FROM   #TempTemplate WHERE  EventsName = 'ENQADD')                  
 BEGIN     
   
  select * into #UserEnquiry from UserEnquiry ue  (nolock) WHERE  ue.CreatedDate Between @LastExecutedTime and @CampaignStarttime  
               
                  
     SELECT tt.EmailID,                  
            tt.ParentID,                  
            tid.CampaignID                  
           INTO #TempEnq                  
   FROM   (   
      SELECT  ue.EmailID,                  
        ue.ParentID,                  
        ue.CreatedDate                  
                FROM   #UserEnquiry AS ue                
    Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T WHERE  EventsName = 'ENQADD') ucs on ucs.ParentID = ue.ParentID     
                WHERE  ue.CreatedDate Between @LastExecutedTime and @CampaignStarttime  
          
    UNION                  
                SELECT ue.EmailID1,                  
        ue.ParentID,                  
        ue.CreatedDate                  
                FROM   #UserEnquiry AS ue     
    Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T WHERE  EventsName = 'ENQADD') ucs on ucs.ParentID = ue.ParentID                  
                WHERE  ue.CreatedDate Between @LastExecutedTime and @CampaignStarttime                
    UNION                  
                SELECT ue.EmailID2,                  
                       ue.ParentID,                  
                       ue.CreatedDate                  
                FROM   #UserEnquiry AS ue                  
                Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'ENQADD') ucs on ucs.ParentID = ue.ParentID     
    WHERE  ue.CreatedDate Between @LastExecutedTime and @CampaignStarttime                
       ) tt          
    Inner join #tmpemailid tid on tid.EmailId = (CAST(tt.EmailID COLLATE Latin1_General_CI_AI AS VARCHAR(50)))  
 WHERE tt.EmailID <> ''   
   
  drop table #UserEnquiry                  
       
     INSERT INTO UserCampaignExecutionHistory                  
     (                  
      -- ID -- this column value is auto-generated                  
         CampaignID,                  
         ExecutionTime,                  
         NoOfRecipients,                  
         Response,                  
         BatchID,                  
         IsRecipients,                  
         IsMessages,                  
         IsExecuted,              
         ParentID ,  
         Jobid                 
       )                  
     SELECT DISTINCT tt.CampaignID,                  
            GETDATE(),                  
            0,                  
            NULL,                  
            0,                  
            1,                  
            0,                  
            0,                  
            tt.ParentID,  
            @JobId                 
     FROM   #TempEnq tt WHERE  tt.EmailID <> ''   
                  
     INSERT INTO EmailsfiltercampaignexecutionTEST2                  
     (                  
         Mail_GUID,                  
         Mail_FromEmail,                  
         Mail_ToEmail,                  
         Mail_UserID,                  
         Mail_InsertedDate,                  
         ParentID,                  
         CampaignID,                  
         IsCompleted ,
            JobId,templateid                   
       )                                  
     SELECT NEWID(),                  
            UAD.EMail,                  
            tt.EmailID,  
   UAD.AccountUsed,                  
            GETDATE(),                  
            tt.ParentID,                  
            tt.CampaignID,                  
            0    ,
            @JobId ,uad.templateid               
     FROM   #TempEnq     tt  
  Inner join #UserAccountDetails UAD on UAD.CampaignID = tt.CampaignID and UAD.ParentID = tt.ParentID WHERE  Tt.EmailID <> '' and tt.EmailID is not null  
                  
     DROP TABLE #TempEnq                  
                  
 END                  
                  
 IF EXISTS( SELECT * FROM   #TempTemplate WHERE  EventsName = 'LEDADD' )                  
 BEGIN    
   
  select * into #UserLeads from UserLeads ue (nolock) WHERE ue.CreatedOn Between @LastExecutedTime and @CampaignStarttime      
                
     SELECT tt.EmailID,                  
            tt.ParentID,                  
            tid.CampaignID                  
            INTO #TempLeads                  
     FROM   (                  
    SELECT ue.EmailID,                  
                       ue.ParentID,                  
                       ue.CreatedOn  AS CreatedDate                  
                FROM   #UserLeads     AS ue                  
    Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'LEDADD') ucs on ucs.ParentID = ue.ParentID   
                WHERE ue.CreatedOn Between @LastExecutedTime and @CampaignStarttime                  
    UNION                  
                SELECT ue.EmailID1,                  
                       ue.ParentID,                  
                       ue.CreatedOn  AS CreatedDate                  
                FROM   #UserLeads     AS ue   
    Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'LEDADD') ucs on ucs.ParentID = ue.ParentID                
                WHERE   ue.CreatedOn Between @LastExecutedTime and @CampaignStarttime                  
                UNION                  
                SELECT ue.EmailID2,                  
                       ue.ParentID,                  
                       ue.CreatedOn  AS CreatedDate                  
                FROM   #UserLeads     AS ue                  
                Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'LEDADD') ucs on ucs.ParentID = ue.ParentID   
    WHERE   ue.CreatedOn Between @LastExecutedTime and @CampaignStarttime                           
            ) tt       
   Inner join #tmpemailid tid on tid.EmailId = (CAST(tt.EmailID COLLATE Latin1_General_CI_AI AS VARCHAR(50)))             
  WHERE  tt.EmailID <> ''   
    
  drop table #UserLeads                 
                  
     INSERT INTO UserCampaignExecutionHistory                  
     (                  
         -- ID -- this column value is auto-generated                  
         CampaignID,                  
         ExecutionTime,                  
         NoOfRecipients,                  
         Response,                  
         BatchID,                  
         IsRecipients,                  
         IsMessages,                  
         IsExecuted,                  
         ParentID,  
         Jobid                  
       )                  
     SELECT DISTINCT tt.CampaignID,                  
            GETDATE(),                  
            0,                  
            NULL,                  
            0,                  
            1,                  
            0,                  
            0,                  
            tt.ParentID ,  
            @JobId                 
     FROM   #TempLeads tt                  
     WHERE  tt.EmailID <> ''    
       
     INSERT INTO EmailsfiltercampaignexecutionTEST2                  
       (                  
         Mail_GUID,                  
         -- Mail_ID -- this column value is auto-generated                  
         Mail_FromEmail,                  
         Mail_ToEmail,                  
         Mail_UserID,                  
         Mail_InsertedDate,                  
         ParentID,                  
         CampaignID,                  
         IsCompleted,
            JobId,templateid                    
       )                  
     SELECT NEWID(),                  
            UAD.Email,                  
            tt.EmailID,                  
            UAD.AccountUsed,                  
            GETDATE(),                  
   tt.ParentID,                  
            tt.CampaignID,                  
            0 ,
            @JobId,uad.templateid                   
     FROM #TempLeads     tt  
  Inner join #UserAccountDetails UAD on UAD.CampaignID = tt.CampaignID and UAD.ParentID = tt.ParentID WHERE  Tt.EmailID <> '' and tt.EmailID is not null  
    
     DROP TABLE #TempLeads                  
 END                  
  
IF EXISTS( SELECT * FROM   #TempTemplate WHERE  EventsName = 'FOLADD' )                  
BEGIN     
  
select ue.* into #userleadsupdated FROM   UserLeads AS ue (nolock)  INNER JOIN LeadInteractionHistory AS lih (nolock) ON  lih.LeadNo = ue.LeadNo AND lih.ParentID = ue.ParentID WHERE  lih.CreatedOn Between @LastExecutedTime and @CampaignStarttime    
               
     SELECT tt.EmailID,                  
            tt.ParentID,                  
            tid.CampaignID AS CampaignID                  
            INTO #TempFollowUp                  
     FROM   (                  
                SELECT ue.EmailID,                  
                       ue.ParentID,                  
                       lih.CreatedOn  AS CreatedDate                  
                FROM   #userleadsupdated      AS ue                  
                       INNER JOIN LeadInteractionHistory AS lih ON  lih.LeadNo = ue.LeadNo AND lih.ParentID = ue.ParentID  
        Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'FOLADD') ucs on ucs.ParentID = lih.ParentID   
                WHERE  lih.CreatedOn Between @LastExecutedTime and @CampaignStarttime                                        
                UNION                  
                SELECT ue.EmailID1,                  
                       ue.ParentID,                  
                       lih.CreatedOn  AS CreatedDate                  
                FROM   #userleadsupdated      AS ue                  
                       INNER JOIN LeadInteractionHistory AS lih ON  lih.LeadNo = ue.LeadNo AND lih.ParentID = ue.ParentID                  
        Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'FOLADD') ucs on ucs.ParentID = lih.ParentID   
                WHERE  lih.CreatedOn Between @LastExecutedTime and @CampaignStarttime                                             
                UNION                  
                SELECT ue.EmailID2,                  
                       ue.ParentID,                  
                       lih.CreatedOn  AS CreatedDate                  
                FROM   #userleadsupdated      AS ue                  
                       INNER JOIN LeadInteractionHistory AS lih  ON  lih.LeadNo = ue.LeadNo AND lih.ParentID = ue.ParentID                  
        Inner  join (Select Distinct CampaignID,ParentID from #TempTemplate T  WHERE  EventsName = 'FOLADD') ucs on ucs.ParentID = lih.ParentID   
                WHERE  lih.CreatedOn Between @LastExecutedTime and @CampaignStarttime                                                    
            )tt                  
   Inner join #tmpemailid tid on tid.EmailId = (CAST(tt.EmailID COLLATE Latin1_General_CI_AI AS VARCHAR(50)))  
        WHERE  tt.EmailID <> ''    
          
        drop table #userleadsupdated                                           
                  
     INSERT INTO UserCampaignExecutionHistory                  
       (                  
         -- ID -- this column value is auto-generated                  
         CampaignID,                  
         ExecutionTime,                  
         NoOfRecipients,                  
         Response,                  
         BatchID,                  
         IsRecipients,                  
         IsMessages,                  
         IsExecuted,                  
         ParentID,  
         Jobid                  
       )                  
     SELECT DISTINCT tt.CampaignID,                  
            GETDATE(),                  
            0,                  
            NULL,                  
            0,                  
            1,                  
            0,                  
            0,                  
            tt.ParentID,  
            @JobId                  
     FROM   #TempFollowUp tt                  
     WHERE  tt.EmailID <> ''                  
   
 INSERT INTO EmailsfiltercampaignexecutionTEST2                  
       (                  
         Mail_GUID,                  
         -- Mail_ID -- this column value is auto-generated                  
         Mail_FromEmail,                  
         Mail_ToEmail,                  
         Mail_UserID,                  
         Mail_InsertedDate,                  
         ParentID,                  
         CampaignID,                  
         IsCompleted,
            JobId,templateid                    
       )                  
     SELECT NEWID(),                  
            UAD.Email,                  
            tt.EmailID,                  
            UAD.Accountused,                  
            GETDATE(),                  
            tt.ParentID,                  
            tt.CampaignID,                  
            0,
            @JobId,uad.templateid                    
     FROM   #TempFollowUp     tt  
  Inner join #UserAccountDetails UAD on UAD.CampaignID = tt.CampaignID and UAD.ParentID = tt.ParentID WHERE  Tt.EmailID <> '' and tt.EmailID is not null  
  
     DROP TABLE #TempFollowUp                  
                  
 END                  
  
 UPDATE A                            
SET step1=1,step1datetime=getdate(),step1recipients = isnull(B.[RecipientsCount],0)                  
FROM [dbo].UserCampaignHistory A INNER JOIN                             
(SELECT a.campaignid as campaignid, A.Jobid,isnull(count(e.CampaignID),0) AS [RecipientsCount]                            
         FROM UserCampaignHistory A (nolock)   
    left outer join [dbo].[EmailsfiltercampaignexecutionTEST2] e (nolock) on e.CampaignID=a.CampaignID and e.jobid=@jobid   
    Where A.Jobid = @jobId  
         group by a.campaignid  , A.Jobid                          
 ) B                            
ON A.[campaignid] = B.[campaignid] and A.Jobid = B.JoBId  
                  
  IF OBJECT_ID(N'tempdb..#TempTableSearchApp', N'U') IS NOT NULL                  
  BEGIN                  
   DROP TABLE #TempTableSearchApp                  
  END                  
                  
  IF OBJECT_ID(N'tempdb..#temptablesearchexc', N'U') IS NOT NULL                  
  BEGIN                  
                  
   DROP TABLE #temptablesearchexc                  
                  
  END                  
                  
  IF OBJECT_ID(N'tempdb..#TempTemplate', N'U') IS NOT NULL                  
  BEGIN                  
     DROP TABLE #TempTemplate                  
  END                  
  
           
  
END    
                        
update UserCampaignExecution                                      
set CampaignExecutedDatetime=@CampaignStarttime                                      
where issms=0 and isevent=1    
exec Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail @jobid
end
  else
  begin
  if (select Lasterrorreported from UserCampaignExecution where issms=0 and isnull(isevent,0)=1) is null or (DATEDIFF(mi,(select isnull(Lasterrorreported,dateadd(mi,-6,getdate())) from UserCampaignExecution where issms=0 and isnull(isevent,0)=1),getdate())>5 and DATEDIFF(mi,(select isnull(CampaignExecutedDatetime,dateadd(mi,-6,getdate())) from UserCampaignExecution where issms=0 and isnull(isevent,0)=1),getdate())>5)
  begin
  declare @campaignstart datetime =(select CampaignExecutedDatetime from UserCampaignExecution where issms=0 and isnull(isevent,0)=1), @lastjobid bigint =(select top 1 jobid from usercampaignhistory (nolock) where issms=0 and iseventbased=1 and campaignid<>0 and jobid<>@jobid order by ID desc)
  declare @step int = (select top 1 case when step2datetime is null then 2 else 3 end from usercampaignhistory (nolock) where jobid=@lastjobid)
  declare @error nvarchar(200)='Last Campaign with jobid ' + cast(@lastjobid as varchar(10)) + ' failed at step ' + cast(@step as varchar) + ' running since ' + cast(@campaignstart as nvarchar(20))
  exec usp_InsertCampaignError'Mail',1,@error
  
  if @step=2
  begin
  exec Usp_userexecutecampaignmessagesmailsnewCorrected_segregatemail @lastjobid
  end
  else if @step=3
  begin
  exec Usp_insertclonedeliverycampaignmailsCorrected_segregatemail @lastjobid
  end

  
  update UserCampaignExecution set Lasterrorreported=GETDATE() where issms=0 and isnull(isevent,0)=1
  --GOTO RETRY
  end
  end
END   
  
  
  
  


GO

