CREATE   PROCEDURE [dbo].[usp_GetRecipientsEventBasedMailsCorrected_withid21102020]  @campid bigint=null   
 --(@jobScheduleId bigint)                    
AS                      
BEGIN                                    
      
 DECLARE @Body VARCHAR(500)                                            
 DEclare @JobId Bigint = (Select ISNULL(MAX(JobId),0)+1 from UserCampaignHistory UCH )      
  declare @campaignstartdate datetime=getdate()    
  INSERT INTO UserCampaignHistory                     
 (                  
     -- ID -- this column value is auto-generated                      
 CampaignID,                      
    ParentID,                      
    Step1,                      
    Step2,                      
    Step3,                   
    IsSMS,                      
    IsMail,                      
    IsScheduled,                      
    IsEventBased,                      
    CreatedOn,      
 JobId                      
   )                      
   --output getdate(),inserted.id,inserted.campaignid into ##campaignrunmail                     
 SELECT 0,                      
        0,                      
        0,                      
        0,                      
        0,                      
        0,                      
        1,                      
        0,                      
        1,                      
        @campaignstartdate,      
  @JobId     
       
 DECLARE @LastExecutedTime datetime = isnull((select Top 1 CampaignExecutedDatetime from UserCampaignExecution(nolock) where issms=0 and isevent=1 order by id desc),getdate())       
    
RETRY:      
 if  @campid is not null or  exists(select 1 from UserCampaignExecution(nolock) where issms=0 and isnull(isevent,0)=1 and isrunning=0)    
 begin    
 if  @campid is null  
 update UserCampaignExecution set isrunning=1,Cjobid=@Jobid where issms=0 and isnull(isevent,0)=1    
       
 Declare @CampaignStarttime datetime = Getdate()      
       
  if OBJECT_ID('tempdb..#temptemplate') is not null                    
 Begin       
 Drop table #temptemplate       
end        
      
 SELECT      ROW_NUMBER()Over(Order by Ucm.ID,Ucm.ParentID) AS Id,      
       ucm.ID      AS CampaignID,                      
                   ucm.ParentID,                      
                   A.[value]  AS Applicabilty,                      
                   AGL.[value] AS ApplicabiltyGroupList,                      
                   EGL.[Value] AS ExclusionsGroupList,                      
                   ucm.NotificationMail,                      
                   ucm.ExclusionsNumber,                      
                   E.[Value] AS Exclusions,                      
                   ucm.InclusionsNumber,                      
                   ucm.AccountUsed,                      
                   ucm.SenderID,                      
                   ucm.[Message],                      
                   ucm.TemplateID,                      
                   ucm.TemplateGroupID,                      
                   ucm.IsUnicode,                      
                   ucm.EventsName      INTO #TempTemplate                
            FROM   UserCampaignMaster(nolock) ucm        
   Inner join  User_detail(nolock) AS Ud  on Ud.[User_ID]  = AccountUsed and Ud.[Status] <> 0      
   join (select distinct user_id as parentaccount from User_detail(nolock) AS Ud  
   join Price_UserSubscriptionDetails(nolock) p on p.UserID=ud.parentid and IsNewPlan=1 and planenddate>getdate() and ud.status=1  
   and ud.user_id=ud.ParentID  
   )  
   p on p.parentaccount=ucm.ParentID                          
            OUTER APPLY dbo.fn_Split(ucm.Applicabilty, '#') AS A         
   OUTER APPLY dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS AGL      
   OUTER APPLY dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS EGL                   
   OUTER APPLY dbo.fn_Split(ucm.Exclusions, '#') AS E                      
           WHERE  ucm.IsEventBased = 1                      
                  AND ucm.IsActive = 1                      
                 AND ucm.MailReplyTo <> ''       
      AND DATEDIFF(                                            
                           Minute,                                            
                           getdate(),                                            
                           CASE                                             
                                WHEN Ucm.IsNeverExpire = 1 THEN DATEADD(DAY, 1,getdate())                             
                                ELSE ISNULL(Ucm.ExpiryDate, getdate())                                            
                       END                                            
                       ) > 0                                            
                   AND DATEDIFF(Minute, getdate(), ISNULL(Ucm.StartDate, getdate()))  < 0         
       and ucm.id=case when @campid is not null then @campid else ucm.id end    
       and nullif(ucm.eventid,0) is null                                                                                                                                                                                                         
       
 SELECT ud.EMail,ucm.AccountUsed,ucm.Id As CampaignId,ucm.ParentID,tt.TemplateID into #UserAccountDetails      
 FROM   UserCampaignMaster(nolock) AS ucm      
 Inner join User_Detail(nolock) AS ud on ud.[User_ID] = ucm.AccountUsed      
 Inner join #TempTemplate tt on tt.CampaignId = ucm.ID      
    WHERE  ucm.ID = tt.CampaignID AND ucm.IsActive = 1      
                 
 INSERT INTO UserCampaignHistory                     
 (                  
     -- ID -- this column value is auto-generated                      
 CampaignID,                      
    ParentID,                      
    Step1,                      
    Step2,                      
    Step3,                   
    IsSMS,                      
    IsMail,                      
    IsScheduled,                      
    IsEventBased,                      
    CreatedOn,      
 JobId                      
   )                      
   --output getdate(),inserted.id,inserted.campaignid into ##campaignrunmail                     
 SELECT CampaignID,                      
        ParentID,                      
        0,                      
        0,                      
        0,                      
        0,                      
        1,                      
        0,                      
        1,                      
        @campaignstartdate,      
  @JobId                    
 FROM   #TempTemplate                      
                      
 IF NOT EXISTS (SELECT 'x' FROM   #TempTemplate )                      
 BEGIN                      
     SET @Body = 'No Campaign Found'                      
     SELECT @Body     
     INSERT INTO UserCampaignHistory                     
 (                  
     -- ID -- this column value is auto-generated                      
 CampaignID,                      
    ParentID,                      
    Step1,                      
    Step2,                      
    Step3,                   
    IsSMS,                      
    IsMail,                      
    IsScheduled,                      
    IsEventBased,                      
    CreatedOn,      
 JobId                      
   )                      
   --output getdate(),inserted.id,inserted.campaignid into ##campaignrunmail                     
 SELECT 0,                      
        0,                      
        0,                      
        0,                      
        0,                      
        0,                      
        1,                      
        0,                      
        1,                      
        GETDATE()  ,      
  @JobId                          
 END                      
 ELSE                      
 BEGIN       
       CREATE TABLE #temptablesearchapp                                            
     (                                            
