      SearchID               BIGINT,                                            
      ParentID               BIGINT,                                            
      PersonName             NVARCHAR(200),                              
      CompanyName            NVARCHAR(200),                                            
      MobileNo               NVARCHAR(200),                                            
      MobileNo1              NVARCHAR(200),                                            
      MobileNo2              NVARCHAR(200),                                            
      EmailID                NVARCHAR(200),                                            
      EmailID1               NVARCHAR(200),                                            
      EmailID2               NVARCHAR(200),                                            
      City      NVARCHAR(200),                                            
