 Inner join Contact_group_detail AS Cgd  (nolock) on Cgd.Group_ID = TT.ExclusionsGroupList and Tt.ExclusionsGroupList is not null  INNER JOIN Contact_detail  AS  Cd   (nolock) ON  Cgd.Contact_ID = Cd.Contact_ID        
          
create table #EligibleCampaigns(Id int identity(1,1),Campaignid bigint,parentid bigint,accountused bigint,applicabilty bigint,exclusions bigint)      
 insert into #EligibleCampaigns(Campaignid ,parentid ,accountused ,applicabilty ,exclusions)      
 select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t join userenquiry(nolock) u on t.ParentID=u.ParentID and t.EventsName='enqadd' where u.CreatedDate>@LastExecutedTime      
 union      
 select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t join userleads(nolock) u on t.ParentID=u.ParentID and t.EventsName='LEDADD' where u.Createdon>@LastExecutedTime       
  union            
 select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t  (nolock) join userleads u  (nolock) on t.ParentID=u.ParentID and t.EventsName='FOLDUE' where       
 u.FollowupDate>@LastExecutedTime   
 union      
  select t.Campaignid ,t.parentid ,t.accountused ,t.applicabilty ,t.exclusions from #TempTemplate t join userleads(nolock) u on t.ParentID=u.ParentID and t.EventsName='FOLADD' join LeadInteractionHistory l on   
 u.LeadNo=l.LeadNo and u.ParentID=l.ParentID where l.Createdon>@LastExecutedTime      
      
  --select * from #EligibleCampaigns         
          
 DECLARE @CountCampaign     INT = isnull((Select MAX(Id) from #EligibleCampaigns),0    )                                            
