mobileno1 NVARCHAR(200), mobileno2 NVARCHAR(200), emailid NVARCHAR(200), emailid1 NVARCHAR(200), emailid2 NVARCHAR(200), 
country NVARCHAR(200), STATE NVARCHAR(200),city NVARCHAR(200),pincode NVARCHAR(200),residentialaddress NVARCHAR(500), 
officeaddress NVARCHAR(500),sourcename NVARCHAR(200), mediumname NVARCHAR(200), campaignname NVARCHAR(200), initialremarks NVARCHAR(1000)
,searchid BIGINT, parentid BIGINT, campaignid BIGINT
  )
)''
 )'
 
 --)'        
 print len(@sqlcmd123)     
 print @Sqlcmd123       
    Exec(@Sqlcmd123)   
      
      
          
         End      
                
         if(@Exclusions is not null)      
         Begin                                        
   -- INSERT INTO #temptablesearchexc                                            
