EmailID2,Country,[STATE],City,PinCode,ResidentialAddress,OfficeAddress,SourceName,MediumName,CampaignName,InitialRemarks,SearchID,
ParentID,CampaignID)                    
   SELECT EntityName,Entityid, PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,Country,[STATE],City,
 PinCode,ResidentialAddress, OfficeAddress,SourceName,MediumName,CampaignName, InitialRemarks,SearchID, ParentID, CampaignID 
  FROM          
  OPENROWSET         
 (''SQLNCLI'',''Server=aznetpocdbs01;Database=MySMS;Uid=kit19;PWD=P@ssword3110;'',''Exec Usp_executeusersearchwithid ' + 
 Cast(@ParentId as nvarchar) + ','+ CAST(@Exclusions as nvarchar ) +','+ CAST(@Campaignid as nvarchar ) +'
 WITH RESULT SETS
(
  (Entityname nvarchar(20),Entityid bigint, personname NVARCHAR(200), companyname NVARCHAR(200), mobileno NVARCHAR(200), 
mobileno1 NVARCHAR(200), mobileno2 NVARCHAR(200), emailid NVARCHAR(200), emailid1 NVARCHAR(200), emailid2 NVARCHAR(200), 
country NVARCHAR(200), STATE NVARCHAR(200),city NVARCHAR(200),pincode NVARCHAR(200),residentialaddress NVARCHAR(500), 
officeaddress NVARCHAR(500),sourcename NVARCHAR(200), mediumname NVARCHAR(200), campaignname NVARCHAR(200), initialremarks NVARCHAR(1000)
,searchid BIGINT, parentid BIGINT, campaignid BIGINT
  )
)''
 )'
 --)'        
 
