  SET @Count = @Count+1      
           
     END      
         
     drop table #EligibleCampaigns     
      
    SELECT Distinct Entityname,Entityid,A.EmailID,                                            
            A.ParentID,                                            
            A.CampaignID                                            
            INTO     #tmpemailid                        
     FROM   (                                            
                SELECT Entityname,Entityid,Tt2.EmailID,                                            
                       Tt2.ParentID,                                            
