SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_getRecvddetails]        
@pagename varchar(200)        
as        
    
declare @host varchar(max) = ''      
set @host = CHARINDEX ('localhost', @pagename ,  0 )      
--select @host ,@pagename       
Declare @pgname varchar(max) = @pagename      
if @host = 0      
SELECT recvmobile, recvemail       
  FROM  [ClientPageDetail](nolock) where pagename='www.kit19.com/'+@pagename   
 else    
 SELECT recvmobile, recvemail       
  FROM  [ClientPageDetail](nolock) where pagename=@pagename 


