/* ============================================================
   Procedure: [dbo].[usp_GetReferrerReportDetailed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[usp_GetReferrerReportDetailed]  -- 2             
@referid int                
as                
begin             
if exists(select 1 from Referrer_Details where id=@referid and isadmin=1)            
begin            
select cast(a.datecreated as date) AS Date,a.ConversionAmount,a.ID as referrerContactid,User_Login as Referrer,a.Name as ReferredContact,a.Company,a.source,a.Signupstatus,a.ConversionStatus,isnull(PayoutEligible,0) as PayoutEligible,isnull(p.CommissionAmount,0) as PayoutTracked,rp.SlabName as Commissionslab,rp.id as Commissionid,p.Status from ReferredContacts a left join          
(select referredcontactid,CommissionAmount,Status,commissionid from PayoutTracking pt where pt.ID=(select MAX(id) from PayoutTracking pt1 where pt1.ReferredContactId=pt.referredcontactid)          
) p on a.ID=p.ReferredContactId join Referrer_Details r on r.ID=a.referrerid left join Referrer_Payout_Rates rp      
on rp.ID=p.Commissionid order by a.DateCreated desc            
end            
else                                                                                                                     
begin            
select cast(a.datecreated as date) AS Date,Name as ReferredContact,Company,source,Signupstatus,ConversionStatus,isnull(PayoutEligible,0) as PayoutEligible,isnull(p.CommissionAmount,0) as PayoutTracked,p.Status from ReferredContacts a left join (select referredcontactid,CommissionAmount,Status from PayoutTracking pt where Referrerid=@referid and pt.ID=(select MAX(id) from PayoutTracking pt1 where pt1.ReferredContactId=pt.referredcontactid)          
) p on a.ID=p.ReferredContactId where a.referrerid=@referid order by a.DateCreated desc            
end            
end 






GO

/* ============================================================
   Procedure: [dbo].[usp_GetReferrerReportSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetReferrerReportSummary]      
@referid int      
as      
begin   
  
select DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0) AS Period ,COUNT(a.id) as ContactsReferred into #ReferredCount   
from ReferredContacts a where a.referrerid=@referid group by DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0)  
  
select DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0) AS Period ,count(a.id)  as Conversions into #ConvertedContacts from ReferredContacts a where ConversionStatus=1 and a.referrerid=@referid group by DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated)
, 0)  
  
select DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0) AS Period ,isnull(sum(p.commissionamount),0) as PayoutsTracked into #payoutstracked from ReferredContacts a left join 
(select referredcontactid,CommissionAmount,Status from PayoutTracking pt where pt.ID=(select MAX(id) from PayoutTracking pt1 where pt1.ReferredContactId=pt.referredcontactid)
)p on p.referredcontactid=a.id where a.referrerid=@referid and 
p.Status='Payout Tracked'group by DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0),status  
  
select DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0) AS Period ,isnull(sum(p1.commissionamount),0) as Payoutsconfirmed into #payoutsconfirmed  from ReferredContacts a left join 
(select referredcontactid,CommissionAmount,Status from PayoutTracking pt where pt.ID=(select MAX(id) from PayoutTracking pt1 where pt1.ReferredContactId=pt.referredcontactid)
) p1 
on p1.referredcontactid=a.id where a.referrerid=@referid and p1.Status='Payment Approved' group by DATEADD(MONTH, DATEDIFF(MONTH, 0, a.datecreated), 0),status  
  
Select r.Period,isnull(ContactsReferred,0) as ContactsReferred,isnull(Conversions,0) as Conversions,isnull  
(PayoutsTracked,0) as PayoutsTracked,isnull(Payoutsconfirmed,0) as Payoutsconfirmed from #ReferredCount r left join #ConvertedContacts c on c.Period=r.Period left join #payoutstracked p on r.Period=p.Period left join #payoutsconfirmed pc on pc.Period=r.Period  
  
drop table #ReferredCount  
drop table #payoutsconfirmed  
drop table #payoutstracked    
drop table #ConvertedContacts   
  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_GetReferrerStats]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_GetReferrerStats          
@referid int          
as          
begin          
declare @TotalContactsReferred int,@TotalRefrencesConverted int,@totalPayoutsTracked numeric(18,2),@totalPayoutsConfirmed numeric(18,2),@totalCommissionPaid numeric(18,2),@referrerlink nvarchar(max)=(select 'https://kit19.com/signup_new.aspx?rid='+cast(ReferrerLinkid as varchar) from Referrer_Details where ID=@referid)      
select @TotalContactsReferred=isnull((select COUNT(1) from ReferredContacts where ReferrerID=@referid),0)      
select @TotalRefrencesConverted=isnull((select COUNT(1) from ReferredContacts where ReferrerID=@referid and ConversionStatus=1),0)      
select @totalPayoutsConfirmed=isnull((select SUM(CommissionAmount) from PayoutTracking where ReferrerID=@referid and Status='Payout Approved'),0)      
select @totalPayoutsTracked=isnull((select SUM(CommissionAmount) from PayoutTracking where ReferrerID=@referid  and Status='Payout Approved'),0)      
select @totalCommissionPaid=isnull((select SUM(isnull(paymentrequested,0)) from Payoutstatus where ReferrerID=@referid and payoutStatus='Closed' and Type='Payment Requested'),0)      
select @TotalContactsReferred as TotalContactsReferred,@TotalRefrencesConverted as TotalRefrencesConverted,@totalPayoutsTracked as totalPayoutsTracked,@totalPayoutsConfirmed as totalPayoutsConfirmed,@totalCommissionPaid as totalPayoutsPaid,@referrerlink as referrerlink       
end 


