   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetReportSummaryByParentId]
    @ParentId bigint
AS
BEGIN
    BEGIN TRY
        -- Start the try block

        SELECT 
            id,
            reportdate,
            parentid,
            summary,
            Whatsappsendid,
            error
        FROM 
            ReportSummaryStatus (nolock)
        WHERE 
            parentid = @ParentId;

    END TRY
    BEGIN CATCH
        -- Start the catch block
		exec usp_InsertErrorInfo 
        -- Capture and return error information
        SELECT 
            ERROR_NUMBER() AS ErrorNumber,
            ERROR_SEVERITY() AS ErrorSeverity,
            ERROR_STATE() AS ErrorState,
            ERROR_PROCEDURE() AS ErrorProcedure,
            ERROR_LINE() AS ErrorLine,
            ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END;


