/* ============================================================
   Procedure: [dbo].[USP_GetResellerDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_GetResellerDetail --'','','sms19','',1,10            
@UserLogin Varchar(20),            
@SenderID Varchar(20),            
@ResellerLogin Varchar(35),            
@Domain Varchar(60)          
AS        
BEGIN            
        
 DECLARE @Where Varchar(2000)            
 DECLARE @Query Varchar(5000)            
 DECLARE @CountQuery Varchar(1000)        
 SET @Where = ''            
    IF (IsNull(@UserLogin,'') != '')            
    BEGIN            
  SET @Where = 'uD.[User_Login]=' + '''' + @UserLogin + ''' '            
 END            
 ELSE             
    BEGIN            
  SET @Where = ' 1=1 '            
 END            
             
    IF (IsNull(@SenderID,'') != '')             
    BEGIN            
  SET @Where = @Where + ' and sD.[Sender_Name] =' + '''' + @SenderID + ''' '            
 END            
    ELSE             
    BEGIN            
  SET @Where = @Where + ' and 1=1 '            
 END            
            
 IF (IsNull(@ResellerLogin,'') != '')            
    BEGIN            
  SET @Where = @Where + ' and rD.User_Login=' + '''' + @ResellerLogin + ''' '            
 END            
 ELSE             
    BEGIN            
  SET @Where = @Where +' and 1=1 '            
 END            
            
 IF (IsNull(@Domain,'') != '')            
    BEGIN            
  SET @Where = @Where + ' and rD.Domain =' + '''' + @Domain + ''' '            
 END            
    ELSE             
    BEGIN            
  SET @Where = @Where + ' and 1=1 '            
 END            
    SET @Query = 'WITH CTE (USerID , UserLogin, ResellerLogin , Domain , Sender_Name ) AS ('            
    SET @Query = @Query + 'SELECT sD.[User_ID] as UserID , uD.[User_Login] As UserLogin ,'            
    SET @Query = @Query + ' rD.User_Login As ResellerLogin ,rD.Domain,sD.Sender_Name  '        
    --SET @Query = @Query + ' CEILING((ROW_NUMBER() OVER (ORDER BY uD.[User_Login] ASC))) AS PageNumber  '            
    SET @Query = @Query + ' FROM SenderID_Detail  sD '            
    SET @Query = @Query + ' LEFT JOIN User_Detail uD '            
    SET @Query = @Query + ' ON sD.[User_ID] = uD.[User_ID] '            
    SET @Query = @Query + ' LEFT JOIN (SELECT Reseller_ID,USer_Login,Domain  '            
    SET @Query = @Query + ' From User_Detail userD '           
    SET @Query = @Query + ' Inner Join Reseller_Detail resD '          
    SET @Query = @Query + ' On userD.[User_ID]=resd.[User_ID]) rD '           
    SET @Query = @Query + ' On uD.[M_ID] = rD.Reseller_ID '           
    SET @Query = @Query + ' WHERE rD.User_Login is not null and ' + @Where + ')'        
    SET @Query = @Query + ' SELECT USerID , UserLogin, ResellerLogin , Domain , Sender_Name  FROM CTE '        
    --SET @Query = @Query + ' WHERE PageNumber between '+ @StartPage +' AND ' + @EndPage        
    Exec (@Query)        
    --print  @Query              
END   
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  


GO

