/* ============================================================
   Procedure: [dbo].[Usp_GetResellers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



    
--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 2:32:20 PM        
CREATE   PROCEDURE [dbo].[Usp_GetResellers] --28052--335    
 @UserID INT    
AS    
BEGIN    
 SELECT ud.[User_ID],    
        --ud.FName + ISNULL(ud.LName, '')   
        ud.User_Login + ' ' +  
        + '(' + uf.Name + ')'     
        + (    
            CASE     
                 WHEN OnlineStatus = 0 THEN ' (Active) '    
                 ELSE ' (InActive) '    
            END    
        )     
        + (    
            CASE     
                 WHEN USER_ID = ParentID THEN ''--'<b>' + User_Login + '</b>'    
                 ELSE ''    
            END    
        )   + '(' + isnull(ud.FName,'') +' '+ isnull(ud.Lname,'') +')'  AS NAME    
 FROM   User_Detail             AS ud    
        INNER JOIN User_Filter  AS uf    
             ON  uf.Code = ud.userfilter    
 WHERE  ud.[User_ID] = @UserID     
     
 UNION        
     
 SELECT Ud.User_ID,    
        --ud.FName + ISNULL(ud.LName, '')   
        ud.User_Login + ' ' +  
        + '(' + uf.Name + ')'     
        + (    
            CASE     
                 WHEN OnlineStatus = 0 THEN ' (Active) '    
                 ELSE ' (Inactive) '    
            END    
        )     
        + (    
            CASE     
                 WHEN USER_ID = ParentID THEN ''--'<b>' + User_Login + '</b>'    
                 ELSE ''    
            END    
        ) + '(' + isnull(ud.FName,'') +' '+ isnull(ud.Lname,'') +')'  AS NAME    
 FROM   User_Detail UD    
        INNER JOIN User_Filter  AS uf    
             ON  uf.Code = ud.userfilter    
 WHERE  UD.ParentID = @UserID    
        AND UD.IsInternalUser = 1    
END 




