/* ============================================================
   Procedure: [dbo].[usp_GetReserveFundList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetReserveFundList]    
    @UserId BIGINT,    
    @UserIds nvarchar(255) = null,    
    @FilterText NVARCHAR(255) = NULL,    
    @OffsetValue INT,    
    @PagingSize INT    
AS    
BEGIN    
     
 --DECLARE      
 -- @UserId BIGINT = 335,    
 -- @UserIds NVARCHAR(255) = '34594',    
 -- @FilterText NVARCHAR(255) = '',    
 -- @OffsetValue INT=0,    
 -- @PagingSize INT=20    
    
    SET NOCOUNT ON;    
    
	DECLARE @ParentId BIGINT;    
	DECLARE @StartPoint INT = (@OffsetValue + 1),     
		@EndPoint INT = (@OffsetValue + @PagingSize);    
	DECLARE @ReservedFunds DECIMAL(18,4) = 0;    
	DECLARE @UnreservedFunds DECIMAL(18,4) = 0;    
	DECLARE @TotalFunds DECIMAL(18,4) = 0;      
	DECLARE @TotalMoney DECIMAL(18,4) = 0;    
    
    
    SELECT @ParentId = ParentID FROM User_Detail(NOLOCK)     
    WHERE User_ID = @UserIds;    
   
 PRINT CONCAT('@ParentID => ', @ParentID)  
   
 SET  @TotalMoney=dbo.[fn_GetMoneyBalance](@ParentID);    
  
 --SELECT @ReservedFunds =SUM(ISNULL(al.Debit, 0)) FROM tbl_intCreditAuditLog(NOLOCK) Al    
 --LEFT JOIN Price_Master_TypeCredit(NOLOCK) pt ON pt.CreditTypeID = Al.CreditTypeId    
  
 --WHERE Al.ParentId = @ParentId and Action='Debit'    
  
 SELECT @ReservedFunds = SUM(ISNULL(Amount, 0)) FROM tbl_IntCreditReserveFunds(NOLOCK) WHERE ParentId = @ParentId  
  
  --AND IsLock = 1    
  --AND (ISNULL(@FilterText, '') = '' OR pt.CreditName LIKE '%' + @FilterText + '%');    
  
     -- AND IsLock = 0    
      --AND (ISNULL(@FilterText, '') = '' OR pt.CreditName LIKE '%' + @FilterText + '%');    
    
    SELECT @TotalFunds = SUM(ISNULL(Amount, 0)) FROM tbl_IntCreditReserveFunds(NOLOCK) A    
    LEFT JOIN Price_Master_TypeCredit(NOLOCK) pt ON pt.CreditTypeID = A.CreditTypeId    
    WHERE A.ParentId = @ParentId    
   
 SET @TotalFunds = ISNULL(@TotalFunds, 0)  
 SET @ReservedFunds = ISNULL(@ReservedFunds, 0)  
    
 set @UnreservedFunds= @TotalMoney - @ReservedFunds;    
    
 declare @tblUserIds as table (UserId bigint)    
 insert into @tblUserIds(UserId)    
 select [value] from string_split(trim(@UserIds), ',') where len(trim([value])) > 0    
  
;WITH  fund AS (    
  SELECT     
   ROW_NUMBER() OVER (PARTITION BY (SELECT NULL) ORDER BY pt.Display_Name DESC) AS SNo,    
   pt.id as [Id],    
   pt.CreditTypeID as [CreditTypeId],    
   pt.Display_Name AS ServiceName,    
   isnull(pt.IsLock, 0) as [IsLock],    
   isnull(pt.Amount, 0) [Amount],    
   @ReservedFunds AS TotalReservedFunds,    
   @UnreservedFunds AS TotalUnreservedFunds,    
   @TotalFunds AS TotalAmount,    
   @TotalMoney as TotalMoney    
  FROM (   
 select p.id, p.CreditTypeID, p.Display_Name, am.IsLock, am.Amount    
  from Price_Master_TypeCredit (NOLOCK) p LEFT JOIN (     
     
   SELECT a.ParentId, a.CreditTypeId, a.[IsLock], SUM(isnull(a.Amount, 0)) as [Amount]     
    FROM tbl_IntCreditReserveFunds(NOLOCK) a INNER JOIN @tblUserIds u ON a.ParentId = u.UserId     
    GROUP BY a.ParentId, a.CreditTypeId, a.IsLock    
   )  
  am on p.CreditTypeID = am.CreditTypeId   
  
  where p.IsVisible = 1 AND 1 = (  CASE     
   WHEN ISNULL(@FilterText, '') = '' THEN 1    
   WHEN p.Display_Name LIKE '%' + @FilterText + '%' THEN 1    
   ELSE 0 END    
  )) pt )    
 SELECT SNo, (select count(1) from fund ) as [TotalRow],    
  Id, CreditTypeId, ServiceName, [IsLock], [Amount],    
  @ReservedFunds AS TotalReservedFunds,    
  @UnreservedFunds AS TotalUnreservedFunds,    
  @TotalFunds AS TotalAmount,    
  @TotalMoney as TotalMoney     
 FROM fund WHERE SNo BETWEEN @StartPoint AND @EndPoint;    
    
END    


GO

