/* ============================================================
   Procedure: [dbo].[usp_getRowData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_getRowData @ParentId=34594,@RowId=123              
-- exec usp_getRowData @ParentId=34594,@RowId=21928                   
CREATE   PROC usp_getRowData        
(              
 @ParentId bigint,              
 @RowId bigint              
)              
AS              
BEGIN              
 --declare @ParentId bigint=34594,@RowId bigint=504              
 declare @tabname varchar(100)='MySMSAudit.dbo.tbl_Audit_'+cast(@ParentId as varchar)              
 declare @SqlString nvarchar(max), @SqlParam nvarchar(max), @RowJson nvarchar(max),              
   @ActTabName varchar(100)              
 set @SqlString='Select @Row_Json=RowJson, @tabName=Table_name from ' + @tabname + ' Where RowId=@Row_Id'              
 set @SqlParam='@Row_Id bigint,@Row_Json nvarchar(max) out, @tabName varchar(100) out'              
 exec sp_executesql @SqlString,@SqlParam,@Row_Id=@RowId, @Row_Json=@RowJson out, @tabName=@ActTabName out              
               
 print @RowJson              
              
 If(@ActTabName='UserEnquiry')              
 Begin              
  drop table if exists #tempJsonData_UserEnquiry              
  select PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City              
      State,Country,CountryCode,CountryCode1,CountryCode2,PinCode,ResidentialAddress,              
      OfficeAddress,InitialRemarks,              
   SourceName=(Select top 1 [Name] From UserSourceSettings(nolock) Where IsActive=1 and UserID=ParentId and SourceId=SourceName),              
   MediumName=isnull((Select top 1 [Name] From UserMediumSettings(nolock) Where IsActive=1 and UserID=ParentId and MediumID=MediumName),''),              
   CampaignName=isnull((Select top 1 [Name] From UserCampaignSettings(nolock) Where IsActive=1 and UserID=ParentId and CampaignID=CampaignName),''),              
   CreatedDate=format(CreatedDate,'dd-MMM-yyyy HH:mm:ss'),              
   CreatedBy=dbo.udf_mk_GetTaskCreatorName(CreatedBy),              
   IsOpen,LeadNo,img_ext,ProfileImgFileName,whereAddress,latitude,longitude,              
   IsduplicateEmail,IsduplicateMobile              
  into #tempJsonData_UserEnquiry              
  from openjson(@RowJson)              
  with              
  (              
   --EnquiryID bigint,              
   PersonName varchar(100),              
   CompanyName varchar(100),              
   MobileNo varchar(100),              
   MobileNo1 varchar(100),              
   MobileNo2 varchar(100),              
   EmailID  varchar(100),              
   EmailID1 varchar(100),              
   EmailID2 varchar(100),              
   City varchar(100),              
   State varchar(100),              
   Country varchar(100),              
   CountryCode varchar(50),              
   CountryCode1 varchar(50),              
   CountryCode2 varchar(50),              
   PinCode bigint,              
   ResidentialAddress varchar(500),              
   OfficeAddress varchar(500),              
   SourceName bigint,              
   MediumName bigint,              
   CampaignName bigint,              
   InitialRemarks varchar(1000),              
   ParentID bigint,              
   CreatedDate datetime,              
   CreatedBy bigint,              
   IsOpen bit,              
   LeadNo int,              
   img_ext varchar(10),              
   ProfileImgFileName nvarchar(500),              
   --enquirysource int,              
   WhatsAppNoColName varchar(10),              
   whereAddress nvarchar(510),              
   latitude float,              
   longitude float,              
   IsduplicateEmail bit,              
   IsduplicateMobile bit              
  )              
              
  select * from #tempJsonData_UserEnquiry for json auto              
  drop table if exists #tempJsonData_UserEnquiry              
 End              
 else If(@ActTabName='UserLeads')              
 Begin              
  drop table if exists #tempJsonData_UserLeads              
  select LeadNo,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,              
   City,State,Country,CountryCode,CountryCode1,CountryCode2,PinCode,ResidentialAddress,              
   OfficeAddress,      
   AssignedTo=dbo.udf_mk_GetTaskCreatorName(AssignedTo),              
   SourceName=(Select top 1 [Name] From UserSourceSettings(nolock) Where IsActive=1 and UserID=ParentId and SourceId=SourceName),              
   MediumName=isnull((Select top 1 [Name] From UserMediumSettings(nolock) Where IsActive=1 and UserID=ParentId and MediumID=MediumName),''),              
   CampaignName=isnull((Select top 1 [Name] From UserCampaignSettings(nolock) Where IsActive=1 and UserID=ParentId and CampaignID=CampaignName),''),              
   CreatedOn=format(CreatedOn,'dd-MMM-yyyy HH:mm:ss'),              
   CreatedBy=dbo.udf_mk_GetTaskCreatorName(CreatedBy),              
   ModifiedOn=format(ModifiedOn,'dd-MMM-yyyy HH:mm:ss'),       ModifiedBy=dbo.udf_mk_GetTaskCreatorName(ModifiedBy),              
   InitialRemarks,              
   --FollowUpStatus=(Select top 1 FollowupStatus From FollowUp_Status(nolock) Where IsActive=1 and FollowUp_Status.ID = A.FollowUpStatus),            
   cast((select cast(fs.FollowUpStatus as varchar) from FollowUp_Status as fs where fs.id= cast(A.FollowUpStatus as bigint)) as varchar) as FollowUpStatus,            
   FollowupDate=format(FollowupDate,'dd-MMM-yyyy HH:mm:ss'),              
