/* ============================================================
   Procedure: [dbo].[usp_GetSavedSearchDetailsforAddCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetSavedSearchDetailsforAddCampaign]
AS
BEGIN
	SELECT sd.ID,
	       ISNULL(sd.SearchName, '_Blank Name') + ' ( ' + CASE 
	                                                           WHEN sd.IsKit19 =
	                                                                1 THEN 
	                                                                'Kit19'
	                                                           ELSE CASE 
	                                                                     WHEN sd.IsKitever 
	                                                                          =
	                                                                          1 THEN 
	                                                                          'Kitever'
	                                                                     ELSE CASE 
	                                                                               WHEN 
	                                                                                    sd.IsCRMDB 
	                                                                                    =
	                                                                                    1 THEN 
	                                                                                    'CRM'
	                                                                               ELSE CASE 
	                                                                                         WHEN 
	                                                                                              sd.IsList 
	                                                                                              =
	                                                                                              1 THEN 
	                                                                                              'List'
	                                                                                         ELSE 
	                                                                                              ''
	                                                                                    END
	                                                                          END
	                                                                END
	                                                      END + ' )' AS 
	       SearchName
	FROM   SearchDetails AS sd
	WHERE  sd.IsActive = 1
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetSchedule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetSchedule]  
    @CreatedBy BIGINT = NULL,  
    @ScheduleName NVARCHAR(100) = NULL  
AS  
BEGIN  
    BEGIN TRY  
        -- Begin transaction if required for data consistency  
        BEGIN TRANSACTION;  
  
        -- Select statement with filtering on CreatedBy and ScheduleName  
       SELECT   
            s.id,  
            s.schedule_name,  
            s.is_daily,  
            s.dayfreq,  
            s.is_weekly,  
            s.weekno,  
            s.weekdays,  
            s.is_monthly,  
            s.months,  
            s.monthdates,  
            s.lastmonthday,  
            s.is_once,  
            s.recur_int,  
            s.recur_unit,  
            s.start_time,  
            s.end_time,  
            s.parentid,  
            --s.createdby, 
			CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
            s.createdon,  
            s.is_active,  
            s.startdate,  
            s.expiry,  

			CASE   

             WHEN s.is_once = 1 THEN 'Once at ' +  
                    
                    
                    
                  CAST(s.start_time AS VARCHAR(50)) + 'End at' +  
                    
                    
                    
                  CAST(s.end_time AS VARCHAR(50))  
				  
             ELSE ''  
        END + CASE   
                   WHEN s.is_daily = 1 THEN 'Daily at ' +  
                          
                          
                          
                        CAST(s.dayfreq AS VARCHAR(50)) + 'end ' +  
                          
                          
                          
                        CAST(s.expiry AS VARCHAR(50))  
                   ELSE ''  
              END + CASE   
                         WHEN s.is_weekly = 1 THEN 'Weekly at Day No(s)  ' +  
                                
                                
                                
                              REPLACE(  
                                  REPLACE(  
                                      REPLACE(  
                                          REPLACE(  
                                              REPLACE(  
                                                  REPLACE(  
                                                      REPLACE(REPLACE(s.weekdays, '#', ', '), '1', 'Sunday'),  
                                                      '2',  
                                                      'Monday'  
                                                  ),  
                                                  '3',  
                                                  'Tuesday'  
                                              ),  
                                              '4',  
                                              'Wednesday'  
                                          ),  
                                          '5',  
                                          'Thursday'  
                                      ),  
                                      '6',  
                                      'Friday'  
                                  ),  
                                  '7',  
                                  'Saturday'  
                              ) + ' at ' +  
                                
                                
                                
                              CAST(s.startdate AS VARCHAR(50)) + '  :' +  
                                
                                
                                
                              CAST(s.expiry AS VARCHAR(50))  
                         ELSE ''  
                    END + CASE   
                               WHEN s.is_monthly = 1 THEN 'Monthly in ' +  
                                      
                                    ISNULL(  
                                        REPLACE(  
                                            REPLACE(  
                                                REPLACE(  
                                                    REPLACE(  
                                                        REPLACE(  
                                                            REPLACE(  
                                                                REPLACE(  
                                                                    REPLACE(  
                                                                        REPLACE(  
                                                                            REPLACE(  
                                                                                REPLACE(  
                                                                                    REPLACE(REPLACE(s.months, '#', ', '), '10', 'October'),  
                                                                                    '11',  
                                                       'November'  
                                                                                ),  
                                                                                '12',  
                                                                                'December'  
                                                                            ),  
                                                                            '1',  
                                                                            'January'  
                                                                        ),  
                                                                        '2',  
                                                                        'February'  
                                                                    ),  
                                                                    '3',  
                                                                    'March'  
                                                                ),  
                                                                '4',  
                                                                'April'  
                                                            ),  
                                                            '5',  
                                                            'May'  
                                                        ),  
                                                        '6',  
                                                        'June'  
                                                    ),  
                                                    '7',  
                                                    'July'  
                                                ),  
                                                '8',  
                                                'August'  
                                            ),  
                                            '9',  
                                            'September'  
                                        ),  
                                        ''  
                                    )  
                                      
                                    +  
                                      
                                    ' at Day No(s)  ' +  
                                      
                                      
                                      
                                    ISNULL(REPLACE(s.monthdates, '#', ', '), '')   
                                      
                                    + ' at ' +  
                                      
                                      
                                      
                                    CAST(s.start_time AS VARCHAR(50)) +  
                                      
                                    '  :' +  
                                      
                                      
                                      
                                    CAST(s.end_time AS VARCHAR(50))  
                               ELSE ''  
                          END  AS ScheduleDetails,






            -- Determine the type: 'once' if is_once = 1, otherwise 'recurring' if recur_int = 1
            CASE  
                WHEN s.is_once = 1 THEN 'once'  
                WHEN s.recur_int = 1 THEN 'recurring'  
                ELSE 'unknown' -- Add a default case if neither condition is met  
            END AS ScheduleType,  
            -- Count the related schedules from triggeredcampaign table  
            (SELECT COUNT(*)  
             FROM triggeredcampaigns tc  
             WHERE tc.Schedule = s.id) AS TriggeredCampaignCount  
        FROM   
            [dbo].[schedules] s 
			INNER JOIN 
        User_Detail ud ON s.createdby = ud.User_ID
        WHERE   
            (TRY_CAST(s.parentid AS BIGINT) = @CreatedBy)  
            AND (s.schedule_name = @ScheduleName OR @ScheduleName IS NULL OR @ScheduleName = '') order by s.id desc--and s.is_active=1;  
  print '1'
        -- Commit transaction if no errors  
        COMMIT TRANSACTION;   
    END TRY  
    BEGIN CATCH  
        -- Rollback the transaction in case of an error  
        IF @@TRANCOUNT > 0  
        BEGIN  
            ROLLBACK TRANSACTION;  
			print '2'
        END  
		SELECT 
            ERROR_MESSAGE() AS ErrorMessage,
            ERROR_LINE() AS ErrorLine,
            ERROR_PROCEDURE() AS ErrorProcedure;
  exec usp_InsertErrorInfo    
    END CATCH  
END 


