/* ============================================================
   Procedure: [dbo].[USP_GETSCHEDULE_SMS_FOR_TABLE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[USP_GETSCHEDULE_SMS_FOR_TABLE]     --  'R20100904181728953',36278    
@TABLENAME VARCHAR(100),    
@BATCHIND BIGINT    
AS    
BEGIN    
DECLARE @QUERY NVARCHAR(MAX)    
DECLARE @QUERY_COUNT NVARCHAR(MAX)    
DECLARE @COUNT BIGINT    
    
SET @QUERY_COUNT=' SELECT @COUNT=Count(Message) FROM '+@TABLENAME+' WITH(NOLOCK) where  BATCHID='+convert(varchar,@BATCHIND,20)    
EXEC SP_EXECUTESQL @QUERY_COUNT,N'@COUNT BIGINT OUTPUT',@COUNT  OUTPUT;    
    
    
SET @QUERY=' SELECT TOP(1)   Message, SenderID, ScheduledDate, ScheduledTime, U_ID, BatchID AS MessageID, '+CONVERT(VARCHAR,@COUNT,20)+' As TotalMessages,isPrority,isunicode            
FROM '+@TABLENAME+' WITH(NOLOCK) where ScheduledDate<>'''' AND  BATCHID='+convert(varchar,@BATCHIND,20)+' order by isPrority desc' --+' Group by  Message, SenderID, ScheduledDate, ScheduledTime, U_ID, BatchID'                         
    
PRINT  @QUERY    
EXEC SP_EXECUTESQL @QUERY    
END



GO

