ScheduledMailProcessed=0 and tablename is not null and isrunning=0 and Tablename<>'CloneEmailsFilter' and isprocess<>1)                                      
begin 
print 'Records found'
--select 'begin try'   
drop table if exists #Batchtobeprocessed
