and isnull(ScheduledDate,dateadd(dd,-1,getdate()))<=GETDATE() and IsProcess=0 and tablename is not null and         
ScheduledMailProcessed=0  and isrunning=0   and Tablename<>'CloneEmailsFilter'   and isprocess<>1                               
--select * from #Batchtobeprocessed                                 
update b set isrunning=1,mail_source='csv' from BatchEmail_Infos b join #Batchtobeprocessed bp on bp.batchid=b.BatchID                          
--select 'updated'                    
declare @tablecount int= (select COUNT(1) from #Batchtobeprocessed)                                      
