insert into #cloneemailsfilter (Mail_GUID,Mail_ID,Mail_FromEmail ,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,                 
Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source,ispersonalized) output inserted.mail_id,inserted.mail_batchid into #c_mailid                                     
select top 1000 Mail_GUID,Mail_ID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,            
Mail_ParentID,ReplyTo,Mail_BatchID,case when isnull(count,11)<=10 then 1 else Mail_Priority end,Mail_ScheduleDate,Mail_ScheduledTime             
,Mail_Attechement,Mail_TempleteBody,IsMonitor,                     
TemplateID,Count,Source,'+cast(@ispersonalized as nvarchar)+' from ' + @tablename + ' order by mail_id;              
print @@rowcount;            
delete m from '+@tablename+ ' m join #c_mailid c on m.mail_id=c.mail_id and m.mail_batchid=c.c_batchid;              
print @@rowcount;            
truncate table #c_mailid;              
