exec usp_inserterrorinfo            
end catch            
--select @dropquery='drop table '+ @tablename +''                       
select @dropquery='insert into TablesToBeRemoved(Tablename,Query,DateOfDeletion) Select '''+@tablename+''',''drop table '+ @tablename +              
''','''+              
cast(dateadd(d,30,getdate()) as nvarchar)+''''              
              
select @dropquery='if  (select OBJECT_ID('''+@tablename+''')) not in (select object_id(''UserAlertMails'')           
   union select object_id(''FollowupAlertMails'') union select object_id(''cloneemailsfilter'') )          
begin drop table '+ @tablename +' end;'                                     
--select @dropquery='if  (select OBJECT_ID('''+@tablename+'''))               
--not in (select object_id(''UserAlertMails'') union select object_id(''FollowupAlertMails''))               
--begin insert into TablesToBeRemoved(Tablename,Query,DateOfDeletion)               
--Select '''+@tablename+''',''drop table '+ @tablename +              
--''','''+              
--cast(dateadd(d,30,getdate()) as nvarchar)+''' end;'                                     
            
print @dropquery              
exec(@dropquery)                                      
end                                
delete From #Batchtobeprocessed where batchid=@batchid                                      
            
select @tablecount=@tablecount-1                                      
end                    
--select 'clone',* from #cloneemailsfilter                 
--select top 1 @batchid=min(mail_batchid) from #cloneemailsfilter   
--select @mail_parentid=Mail_ParentID from #cloneemailsfilter where mail_batchid=@batchid

--print concat('Now testing if batch exists in clientemails batch: ',@batchid, ' for parentid: ',@mail_parentid)              
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)                             
declare @RecordCnt int=(select COUNT(1) FROM #cloneemailsfilter)
declare @batchsize int,@templateid bigint,@batchrecords int 
declare @ORecordCnt int=(select COUNT(1) FROM #cloneemailsfilter)                     
                    
insert into #batchestobeupdated                  
select distinct mail_BatchID from #cloneemailsfilter                             
select top 1 @batchid=min(mail_batchid) from #cloneemailsfilter   

while(@RecordCnt > 0 and isnull(@batchid,0)<>0)                            
BEGIN  
begin try
select @batch_process_error=''
select top 1 @batchid=min(mail_batchid) from #cloneemailsfilter   

select @batchsize=dbo.fn_min_no( (select COUNT(1) FROM #cloneemailsfilter where mail_batchid=@batchid),1000) 
select @ispersonalized=isnull(ispersonalized,0),@mail_parentid=Mail_ParentID,@templateid=TemplateID from #cloneemailsfilter where mail_batchid=@batchid
select @mailroute=isnull(mailroute,'T'),@batchrecords=TotalRecords from BatchEmail_Infos(nolock) where batchid=@batchid                     
select @ismonitor=case when @mailroute='P' then 1 when @RecordCnt>=plimit and Status=1 and @mailroute='T' then 0 else 1 end from processmaillimit                          
update batchemail_infos set bmonitor=@ismonitor where batchid=@batchid                     

print concat('Now processing batch: ',@batchid, ' for parentid: ',@mail_parentid)              

IF (select count(1) from clientemails (nolock) where batchid=@batchid) <  @batchrecords                           
BEGIn                                      
print 'full batchid not exists-2'

--SET NOCOUNT ON;                             
INSERT INTO Clientemails                                                                            
                  (                                                            
     -- Id -- this column value is auto-generated         
      GUID,                                                                            
                   Email_Id,                                                                            
                   SentDateTime,                                                                            
               UserId,                                                                  
                   ReplyTo,                                                                
                   [Status],                                                                            
                   BatchID,                                         
                   [Message],                                        
                   campaignid,                                        
                   parentid)                                         
      OUTPUT inserted.GUID  as GUId,inserted.email_id as Email,inserted.batchid  INTO #output                                                
      SELECT top (@batchsize) Newid(),                                                                            
             Efce.Mail_ToEmail,                                           
             Getdate(),                                                                            
             Efce.Mail_UserID,                                                          
             Efce.ReplyTo,                                                                            
   '',                                                                            
             efce.mail_BatchID,                                                                            
             case when efce.ispersonalized=1 and cast(isnull(efce.Messages,'') as nvarchar(max))<>cast('' as nvarchar(max)) then efce.Messages
			 when efce.ispersonalized=1 and cast(isnull(efce.Mail_TempleteBody,'') as nvarchar(max))<>cast('' as nvarchar(max)) then efce.Mail_TempleteBody else null end, 
			 0,                                        
             efce.mail_ParentID                                                                            
      FROM   #cloneemailsfilter AS Efce 
   left join UserMailTemplate umt(nolock) on umt.ID=efce.TemplateID                     
   left join (select top 1 * from campaignmessages (nolock) as r where r.batchid=@batchid) as c on c.batchid=efce.mail_batchid 
   where efce.mail_batchid=@batchid
   order by efce.id                                     
                       
--   select * from ClientEmails (nolock) where BatchID=@batchid                    
if @mail_parentid=0--<>33819                                        
begin    
print concat('If block: Mailparentid: ',@mail_parentid,', batchid: ',@batchid)

INSERT INTO Emailsfilter                                        
                  (Mail_GUID,                                                                            
                   Mail_FromEmail,                                                          
                   Mail_ToEmail,                                                                            
                   Mail_Subject,                                                                            
                   Mail_TempleteName,                                                                            
                   Messages,                                        
                   Mail_InsertedDate,                                           
                   Mail_UserID,                                                                            
                   ReplyTo,                                         
                   Mail_BatchID,                                                                            
                   Mail_Priority,                                                                            
                   Mail_ScheduleDate,                                                         
                   Mail_Attechement,                                                                            
                   Mail_TempleteBody,                                                                            
                   IsMonitor)                                                                            
SELECT top (@batchsize) O.Guid,                                                                            
             Efce.Mail_FromEmail,                                                                            
             Efce.Mail_ToEmail,                                                
             case when isnull(efce.mail_subject,'')<>'' then efce.mail_subject when isnull(efce.templateid,0)<>0 then umt.mailsubject collate SQL_Latin1_General_CP1_CI_AS when isnull(efce.mail_subject,'')='' then c.mail_subject else efce.mail_subject end
as Mail_Subject,                                                 
    Efce.Mail_TempleteName,                                                                            
    case when efce.ispersonalized=1  and cast(isnull(efce.Messages,'') as nvarchar(max))<>cast('' as nvarchar(max)) then efce.Messages
			 when efce.ispersonalized=1 and cast(isnull(efce.Mail_TempleteBody,'') as nvarchar(max))<>cast('' as nvarchar(max)) then efce.Mail_TempleteBody else null end,                    
        
    isnull(Efce.Mail_InsertedDate,getdate()),                                                                            
             Efce.Mail_UserID,                                                                            
             Efce.ReplyTo,                                                                            
             efce.mail_BatchID,                                                                            
             Efce.Mail_Priority,                                 
             isnull(Efce.Mail_ScheduleDate,getdate()),                         
             Efce.Mail_Attechement,                                                               
             case when efce.ispersonalized=1  and cast(isnull(efce.Messages,'') as nvarchar(max))<>cast('' as nvarchar(max)) then efce.Messages
			 when efce.ispersonalized=1 and cast(isnull(efce.Mail_TempleteBody,'') as nvarchar(max))<>cast('' as nvarchar(max)) then efce.Mail_TempleteBody else null end,                                 
        @ismonitor as limit                    
      FROM   #cloneemailsfilter AS Efce                                                                            
             inner join #output o on o.email=Efce.mail_toemail and o.Batchid=efce.Mail_BatchID                                        
             left join UserMailTemplate umt (nolock) on umt.ID=efce.TemplateID                     
             left join (select top 1 * from campaignmessages (nolock) as q where q.batchid=@batchid) as c on c.batchid=efce.mail_batchid 
			 where efce.Mail_BatchID=@batchid
			 order by Efce.id                    
end
else
begin
begin try
print concat('Mailparentid: ',@mail_parentid,', batchid: ',@batchid)
--select @dist_message=case when @ispersonalized=0 then 1 else 2 end
select @dist_message=count(distinct isnull(nullif(cast(messages as nvarchar(max)),''),cast(Mail_TempleteBody as nvarchar(max))))  from #cloneemailsfilter where Mail_BatchID=@batchid

select top 1 @Mail_UserID=mail_userid,@fromemail=Mail_FromEmail from #cloneemailsfilter where Mail_BatchID=@batchid

select  @frommailname=coalesce(
(select top 1 displayname from [FromMailIDDetails] (nolock) where [Mail_ID]=@fromemail and user_id=@Mail_UserID and status=1 ),
(select top 1 k_d_name from [karixmailroute](nolock) where [frommailid]=@fromemail and mailuser=@Mail_UserID and isactive=1),
(select top 1 value from dbo.fn_split(@FROMEMAIL,'@') where position=1 ))



select @samemessage=case when @dist_message>1 then 0 else 1 end
select @mailbody=case when @samemessage=1 
and @templateid>0
then try_cast((select top 1 MailContent from UserMailTemplate (nolock) as q where q.id=@templateid) as nvarchar(max))
when @samemessage=1 
and isnull(try_cast((select top 1 messages from #cloneemailsfilter (nolock) as q where q.Mail_BatchID=@batchid) as nvarchar(max)),'')<>''
then try_cast((select top 1 messages from #cloneemailsfilter (nolock) as q where q.Mail_BatchID=@batchid) as nvarchar(max))
when @samemessage=1 
