select @payload=cast((
SELECT top 1
Efce.Mail_FromEmail,
isnull(@frommailname,'') as Mail_FromName,
Efce.Mail_TempleteName,                                                
isnull(Efce.Mail_InsertedDate,getdate()) as Mail_InsertedDate, 
