@samemessage  SameMessage,
cast((select top (@batchsize)
O.Guid,  
Efce.Mail_ToEmail,                    
    case when isnull(efce.templateid,0)<>0 then umt.MailSubject           
    when isnull(efce.mail_subject,'')<>'' then efce.mail_subject           
    else c.Mail_Subject end as Mail_Subject,   
