/* ============================================================
   Procedure: [dbo].[usp_getscheduledmails_loop]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROC [dbo].[usp_getscheduledmails_loop]                        
as                        
begin      
--select 'begin'                        
begin try                        
if exists(select 1 from BatchEmail_Infos where isnull(ScheduledDate,dateadd(dd,-1,getdate()))<=GETDATE() and ScheduledMailProcessed=0 and tablename is not null and isrunning=0)                        
begin                        
--select 'begin try'      
create table #Batchtobeprocessed(batchid bigint,Tablename nvarchar(50),ispersonalized int)                        
insert into  #Batchtobeprocessed(batchid,Tablename,ispersonalized)                        
select batchid,Tablename, case when (ispersonalized=1) or (Tablename in ('UserAlertMails','FollowupAlertMails')) 
or not exists(select 1 from campaignmessages c where c.batchid=b.batchid) then 1 else 0 end from BatchEmail_Infos b where 
--tablename='M3865420231003124314073'
isnull(ScheduledDate,dateadd(dd,-1,getdate()))<=GETDATE() and IsProcess=0 and tablename is not null and ScheduledMailProcessed=0  and isrunning=0                      
--select * from #Batchtobeprocessed                   
update b set isrunning=1,mail_source='csv' from BatchEmail_Infos b join #Batchtobeprocessed bp on bp.batchid=b.BatchID            
--select 'updated'      
declare @tablecount int= (select COUNT(1) from #Batchtobeprocessed)                        
declare @tablename nvarchar(50),@batchid bigint                        
declare @query nvarchar(max)                        
create table #cloneemailsfilter(id int identity(1,1),Mail_GUID nvarchar(100),Mail_ID bigint,Mail_FromEmail nvarchar(250) collate SQL_Latin1_General_CP1_CI_AS,Mail_ToEmail  nvarchar(250) collate SQL_Latin1_General_CP1_CI_AS ,Mail_Subject  nvarchar(250)    
 
collate SQL_Latin1_General_CP1_CI_AS,Mail_TempleteName  nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS,Messages text collate SQL_Latin1_General_CP1_CI_AS ,Mail_InsertedDate datetime,Mail_UserID bigint,Mail_ParentID bigint,
ReplyTo  nvarchar(250) collate
SQL_Latin1_General_CP1_CI_AS,Mail_BatchID bigint,Mail_Priority int,Mail_ScheduleDate  nvarchar(50),Mail_ScheduledTime  nvarchar(50),Mail_Attechement  varchar(500) collate SQL_Latin1_General_CP1_CI_AS,Mail_TempleteBody text collate       
SQL_Latin1_General_CP1_CI_AS,IsMonitor int,TemplateID bigint,Count int,Source  nvarchar(20),ispersonalized int default 0)                        
declare @dropquery nvarchar(max),@ispersonalized int=0         
create table #batchestobeupdated(mail_BatchID bigint)           
       
 declare @ismonitor int ,@mailroute nvarchar(20)          
 create table #c_mailid(mail_id bigint)
 create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)               
while @tablecount>0                        
begin                        
select @batchid=MIN(batchid) from #Batchtobeprocessed                 
select @ispersonalized=isnull(ispersonalized,0) from #Batchtobeprocessed where batchid=@batchid      
--select @batchid,@ispersonalized      
select @tablename= tablename from #Batchtobeprocessed where batchid=@batchid                        
if OBJECT_ID(''+@tablename+'') is not null  and not exists(select 1 from clientemails (nolock) where batchid=@batchid)                        
Begin        
select @query = 
'
while exists (select 1 from '+@tablename+')
begin
begin try
insert into #cloneemailsfilter (Mail_GUID,Mail_ID,Mail_FromEmail ,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,   
Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source,ispersonalized) output inserted.mail_id into #c_mailid                       
select top 1000 Mail_GUID,Mail_ID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,case when isnull(count,11)<=10 then 1 else Mail_Priority end,Mail_ScheduleDate,Mail_ScheduledTime
,Mail_Attechement,Mail_TempleteBody,IsMonitor,       
TemplateID,Count,Source,'+cast(@ispersonalized as nvarchar)+' from ' + @tablename + ' order by mail_id; 
delete m from '+@tablename+ ' m join #c_mailid c on m.mail_id=c.mail_id;
truncate table #c_mail_id
end try
begin catch
exec usp_inserterrorinfo
end catch
end
'                        
--select @query      
exec(@query) 

select top 1 @batchid=min(mail_batchid) from #cloneemailsfilter             
IF not exists(select 1 from clientemails (nolock) where batchid=@batchid)                
BEGIN                        
--select 'batchid not exists-2'      

declare @RecordCnt int=(select COUNT(1) FROM #cloneemailsfilter where mail_batchid=@batchid)         
declare @ORecordCnt int=(select COUNT(1) FROM #cloneemailsfilter  where mail_batchid=@batchid)       
select @mailroute=isnull(mailroute,'T') from BatchEmail_Infos(nolock) where batchid=@batchid       
select @ismonitor=case when @mailroute='P' then 1 when @RecordCnt>=plimit and Status=1 and @mailroute='T' then 0 else 1 end from processmaillimit            
update batchemail_infos set bmonitor=@ismonitor where batchid=@batchid       
      
--insert into #batchestobeupdated             
--select distinct mail_BatchID from #cloneemailsfilter               

while(@RecordCnt > 0)              
BEGIN              
SET NOCOUNT ON;               
INSERT INTO Clientemails                                                              
                  (                                              
     -- Id -- this column value is auto-generated                                 
      GUID,                                                              
                   Email_Id,                                                              
                   SentDateTime,                                                              
               UserId,                                                              
                   ReplyTo,                                                  
                   [Status],                                                              
                   BatchID,                                                              
                   [Message],                          
                   campaignid,                          
                   parentid)                           
      OUTPUT inserted.GUID  as GUId,inserted.email_id as Email,inserted.batchid  INTO #output                                  
      SELECT top 1000 Newid(),                                                              
             Efce.Mail_ToEmail,                                                              
             Getdate(),                                                              
             Efce.Mail_UserID,                                            
             Efce.ReplyTo,                                                              
   '',                                                              
             efce.mail_BatchID,                                                              
             case when efce.ispersonalized=1 then efce.Messages else null end,      
             0,                          
             efce.mail_ParentID                                                              
      FROM   #cloneemailsfilter AS Efce left join UserMailTemplate umt(nolock) on umt.ID=efce.TemplateID       
   left join campaignmessages c(nolock) on c.batchid=efce.mail_batchid  where Efce.mail_batchid=@batchid order by efce.id                       
         
--   select * from ClientEmails (nolock) where BatchID=@batchid      
                                                       
INSERT INTO Emailsfilter                          
                  (Mail_GUID,                                                              
                   Mail_FromEmail,                                            
                   Mail_ToEmail,                                                              
                   Mail_Subject,                                                              
                   Mail_TempleteName,                                                              
                   Messages,                          
                   Mail_InsertedDate,                             
                   Mail_UserID,                                                              
                   ReplyTo,                                                              
                   Mail_BatchID,                                                              
                   Mail_Priority,                                                              
                   Mail_ScheduleDate,                                                              
                   Mail_Attechement,                                                              
                   Mail_TempleteBody,                                                              
                   IsMonitor)                                                              
SELECT top 1000 O.Guid,                                                              
             Efce.Mail_FromEmail,                                                              
             Efce.Mail_ToEmail,                                  
             case when isnull(efce.templateid,0)<>0 then umt.mailsubject collate SQL_Latin1_General_CP1_CI_AS when isnull(efce.mail_subject,'')='' then c.mail_subject else efce.mail_subject end as Mail_Subject,                                            
    Efce.Mail_TempleteName,                                                              
    case when efce.ispersonalized=1 then efce.Messages else null end,      
             --case when isnull(efce.templateid,0)<>0 then umt.mailcontent collate SQL_Latin1_General_CP1_CI_AS when isnull(cast(efce.messages as varchar(max)),'')='' then cast(c.messages as varchar(max)) else cast(Efce.Messages as varchar(max)) collate S
  --QL_Latin1_General_CP1_CI_AS end as Messages,                   
    isnull(Efce.Mail_InsertedDate,getdate()),                                                              
             Efce.Mail_UserID,                                                              
             Efce.ReplyTo,                                                              
             efce.mail_BatchID,                                                              
             Efce.Mail_Priority,                   
             isnull(Efce.Mail_ScheduleDate,getdate()),                                                              
             Efce.Mail_Attechement,                                                 
             case when efce.ispersonalized=1 then efce.Messages else null end,                   
             --case when isnull(efce.templateid,0)<>0 then umt.mailcontent collate SQL_Latin1_General_CP1_CI_AS when isnull(cast(efce.messages as varchar(max)),'')='' then cast(c.messages as varchar(max)) else cast(Efce.Messages as varchar(max)) collate S
  --QL_Latin1_General_CP1_CI_AS end,                                                              
             --1 AS Limit                                                   
    @ismonitor as limit      
      FROM   #cloneemailsfilter AS Efce                                                              
             inner join #output o on o.email=Efce.mail_toemail and o.Batchid=efce.Mail_BatchID                          
             left join UserMailTemplate umt (nolock) on umt.ID=efce.TemplateID       
             left join campaignmessages c(nolock) on c.batchid=efce.mail_batchid 
			 where Efce.mail_batchid=@batchid 
			 order by Efce.id      
          
--    select * from Emailsfilter (nolock) where mail_BatchID=@batchid      
           
--delete c From #cloneemailsfilter c  where ID<=(@oRecordCnt-@RecordCnt)+1000    
delete c From #cloneemailsfilter c join #output o on o.email=c.mail_toemail and o.Batchid=c.Mail_BatchID 
delete from #output          
SET @RecordCnt=@RecordCnt-1000;              
SET NOCOUNT ON;              
end

ENd  

update B set ScheduledMailProcessed=1,isrunning=0 from BatchEmail_Infos b  where BatchID=@batchid             

select @dropquery='drop table '+ @tablename +''                   
select @dropquery='if  (select OBJECT_ID('''+@tablename+''')) not in (select object_id(''UserAlertMails'') union select object_id(''FollowupAlertMails'')) begin drop table '+ @tablename +' end;'                       
exec(@dropquery)                        
end                  
delete From #Batchtobeprocessed where batchid=@batchid                        
select @tablecount=@tablecount-1                        
end      
--select * from #cloneemailsfilter   
--select 1      
drop table if exists #Batchtobeprocessed      
drop table if exists #batchestobeupdated      
drop table if exists #cloneemailsfilter      
drop table if exists #output
drop table if exists #c_mailid
end                     
/*else       
begin      
Select 'no scheduled mails'      
end*/      
end try                    
begin catch                        
exec usp_InsertErrorInfo              
end catch                        
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_getscheduledmails_NoMailBody]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_getscheduledmails_NoMailBody]                  
as                  
begin                  
begin try                  
if exists(select 1 from BatchEmail_Infos where scheduleddate is not null and ScheduledDate<=GETDATE() and ScheduledMailProcessed=0 and tablename is not null and isrunning=0)                  
begin                  
create table #Batchtobeprocessed(batchid bigint,Tablename nvarchar(50))                  
insert into  #Batchtobeprocessed(batchid,Tablename)                  
select batchid,Tablename from BatchEmail_Infos where scheduleddate is not null and ScheduledDate<=GETDATE() and IsProcess=0 and tablename is not null and ScheduledMailProcessed=0  and isrunning=0                
update b set isrunning=1 from BatchEmail_Infos b join #Batchtobeprocessed bp on bp.batchid=b.BatchID      
--select * from #Batchtobeprocessed             
declare @tablecount int= (select COUNT(1) from #Batchtobeprocessed)                  
declare @tablename nvarchar(50),@batchid bigint                  
declare @query nvarchar(max)                  
create table #cloneemailsfilter(id int identity(1,1),Mail_GUID nvarchar(100),Mail_ID bigint,Mail_FromEmail nvarchar(250) collate SQL_Latin1_General_CP1_CI_AS,Mail_ToEmail  nvarchar(250) collate SQL_Latin1_General_CP1_CI_AS ,Mail_Subject  nvarchar(250) collate SQL_Latin1_General_CP1_CI_AS,Mail_TempleteName  nvarchar(50) collate SQL_Latin1_General_CP1_CI_AS,Messages text collate SQL_Latin1_General_CP1_CI_AS ,Mail_InsertedDate datetime,Mail_UserID bigint,Mail_ParentID bigint,ReplyTo  nvarchar(250) collate   
SQL_Latin1_General_CP1_CI_AS,Mail_BatchID bigint,Mail_Priority int,Mail_ScheduleDate  nvarchar(50),Mail_ScheduledTime  nvarchar(50),Mail_Attechement  varchar(500) collate SQL_Latin1_General_CP1_CI_AS,Mail_TempleteBody text collate 
SQL_Latin1_General_CP1_CI_AS,IsMonitor int,TemplateID bigint,Count int,Source  nvarchar(20))                  
declare @dropquery nvarchar(max)  
create table #batchestobeupdated(mail_BatchID bigint)     
      
                
while @tablecount>0                  
begin                  
select @batchid=MIN(batchid) from #Batchtobeprocessed          
select @tablename= tablename from #Batchtobeprocessed where batchid=@batchid                  
if OBJECT_ID(''+@tablename+'') is not null  and not exists(select 1 from clientemails (nolock) where batchid=@batchid)                  
Begin                   
select @query = 'insert into #cloneemailsfilter (Mail_GUID,Mail_ID,Mail_FromEmail ,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,   
  
    
     
Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)                  
select Mail_GUID,Mail_ID,Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,case when isnull(count,11)<=10 then 1 else Mail_Priority end,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor, 
  
    
      
       
TemplateID,Count,Source from ' + @tablename + ''                  
exec(@query)                  
select @dropquery='drop table '+ @tablename +''             
select @dropquery='if  (select OBJECT_ID('''+@tablename+''')) not in (select object_id(''UserAlertMails'') union select object_id(''FollowupAlertMails'')) begin drop table '+ @tablename +' end;'                 
exec(@dropquery)                  
end            
delete From #Batchtobeprocessed where batchid=@batchid                  
select @tablecount=@tablecount-1                  
end          
IF not exists(select 1 from clientemails (nolock) where batchid=@batchid)          
BEGIN                  
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)         
declare @RecordCnt int=(select COUNT(1) FROM #cloneemailsfilter)   
declare @ORecordCnt int=(select COUNT(1) FROM #cloneemailsfilter)        

insert into #batchestobeupdated       
select distinct mail_BatchID from #cloneemailsfilter         
while(@RecordCnt > 0)        
BEGIN        
SET NOCOUNT ON;         
INSERT INTO Clientemails                                                        
                  (                                        
     -- Id -- this column value is auto-generated                           
      GUID,                                                        
                   Email_Id,                                                        
                   SentDateTime,                                                        
               UserId,                                                        
                   ReplyTo,                                            
                   [Status],                                                        
                   BatchID,                                                        
                   --[Message],                    
                   campaignid,                    
                   parentid)                     
      OUTPUT inserted.GUID  as GUId,inserted.email_id as Email,inserted.batchid  INTO #output                            
      SELECT top 1000 Newid(),                                                        
             Efce.Mail_ToEmail,                                                        
             Getdate(),                                                        
             Efce.Mail_UserID,                                      
             Efce.ReplyTo,                                                        
   '',                                                        
             efce.mail_BatchID,                                                        
             --case when isnull(efce.templateid,0)<>0 then umt.mailcontent collate SQL_Latin1_General_CP1_CI_AS when isnull(cast(efce.messages as varchar(max)),'')='' then cast(c.messages as varchar(max)) else cast(Efce.Messages as varchar(max)) collate SQL_Latin1_General_CP1_CI_AS end as Messages,                    
             0,                    
             efce.mail_ParentID                                                        
      FROM   #cloneemailsfilter AS Efce left join UserMailTemplate umt on umt.ID=efce.TemplateID 
	  left join campaignmessages c on c.batchid=efce.mail_batchid order by efce.id                 
                                                        
INSERT INTO Emailsfilter                                                       
                  (Mail_GUID,                                                        
                   Mail_FromEmail,                                                        
                   Mail_ToEmail,                                                        
                   Mail_Subject,                                                        
                   Mail_TempleteName,                                                        
                   --Messages,                    
                   Mail_InsertedDate,                       
                   Mail_UserID,                                                        
                   ReplyTo,                                                        
                   Mail_BatchID,                                                        
                   Mail_Priority,                                                        
                   Mail_ScheduleDate,                                                        
                   Mail_Attechement,                                                        
                   --Mail_TempleteBody,                                                        
                   IsMonitor)                                                        
SELECT top 1000 O.Guid,                                                        
             Efce.Mail_FromEmail,                                                        
             Efce.Mail_ToEmail,                            
             case when isnull(efce.templateid,0)<>0 then umt.mailsubject collate SQL_Latin1_General_CP1_CI_AS when isnull(efce.mail_subject,'')='' then c.mail_subject else efce.mail_subject end as Mail_Subject,                                                               
			 Efce.Mail_TempleteName,                                                        
             --case when isnull(efce.templateid,0)<>0 then umt.mailcontent collate SQL_Latin1_General_CP1_CI_AS when isnull(cast(efce.messages as varchar(max)),'')='' then cast(c.messages as varchar(max)) else cast(Efce.Messages as varchar(max)) collate SQL_Latin1_General_CP1_CI_AS end as Messages,             
			 isnull(Efce.Mail_InsertedDate,getdate()),                                                        
             Efce.Mail_UserID,                                                        
             Efce.ReplyTo,                                                        
efce.mail_BatchID,                                                        
             Efce.Mail_Priority,             
             isnull(Efce.Mail_ScheduleDate,getdate()),                                                        
             Efce.Mail_Attechement,                                                        
             --case when isnull(efce.templateid,0)<>0 then umt.mailcontent collate SQL_Latin1_General_CP1_CI_AS when isnull(cast(efce.messages as varchar(max)),'')='' then cast(c.messages as varchar(max)) else cast(Efce.Messages as varchar(max)) collate SQL_Latin1_General_CP1_CI_AS end,                                                        
             1 AS Limit                                             
      FROM   #cloneemailsfilter AS Efce                                                        
             inner join #output o on o.email=Efce.mail_toemail                     
             left join UserMailTemplate umt on umt.ID=efce.TemplateID 
			 left join campaignmessages c on c.batchid=efce.mail_batchid order by Efce.id        
delete From #cloneemailsfilter where ID<=(@oRecordCnt-@RecordCnt)+1000        
SET @RecordCnt=@RecordCnt-1000;        
SET NOCOUNT ON;        
end               
ENd       
update B set ScheduledMailProcessed=1,isrunning=0 from BatchEmail_Infos b join #BatchestobeUpdated c on b.BatchID=c.Mail_BatchID      
end               
end try              
begin catch                  
exec usp_InsertErrorInfo                  
end catch                  
end 


GO

