/* ============================================================
   Procedure: [dbo].[Usp_GetScoreDetailsByLeadID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetScoreDetailsByLeadID  --679386  
 (  
    @LeadID bigint  
 )  
 as  
 Begin  
       
    --select 'hello'  
   declare @PersonName nvarchar(200) = ''  
   declare @companyname nvarchar(500) = ''

   declare @Createdon datetime = null  
   declare @CurrentScore numeric(18,2) = 0   
   declare @ScoreSum numeric(18,2) = 0  
   declare @ScoreSumPRCNTG numeric(18,2) = 0  
   declare @profit_Loss nvarchar(200) = ''  
   declare @lastRecordBefore7 numeric(18,2) = 0   
   declare @TopScoringFactors nvarchar(max) = ''  
   declare @top3ScoringFatcors nvarchar(max) = ''  
   declare @top3Scores nvarchar(max) = ''  
  
    
  
   select @PersonName = Personname, @companyname = CompanyName , @Createdon = Createdon  from  userleads(nolock) where id = @LeadID    
   --select @PersonName ,@Createdon   
  
   select top 1 @CurrentScore = CurrentScore from lead_score_history(nolock) where  isnull(CurrentScore,0) <> 0    and  leadid = @LeadID order by id desc  
     
  
   select  @ScoreSum = SUM(isnull(ScoreAdded,0)) from lead_score_history(nolock) where datediff(d,createdon,getdate()) <= 7 and leadid = @LeadID  
  
   select top 1 @lastRecordBefore7 = CurrentScore from lead_score_history(nolock) where  isnull(CurrentScore,0) <> 0 and datediff(d,createdon,getdate()) > 7   and  leadid = @LeadID order by id desc  
  
    --select top 3 event  from lead_score_history(nolock) where  leadid = @LeadID order by ScoreAdded desc      
      
   --select top 3 AM.EventName from lead_score_history(nolock) as LCH   
   --join lead_scoring_rules(nolock) as LSR on LCH.rule_id = LSR.id  
   --join ActivityMaster(nolock) as AM on LSR.event_id = AM.ID     
   --    where datediff(d,LCH.createdon,getdate()) <= 7 and leadid = @LeadID  
  
     
       SELECT     
       @top3ScoringFatcors =  
   STUFF    
   (    
     (    
     SELECT  top 3 '#'+ CAST(AM.EventName  AS VARCHAR(MAX))    
         
      FROM lead_score_history(nolock) as LCH   
               join lead_scoring_rules(nolock) as LSR on LCH.rule_id = LSR.id  
               join ActivityMaster(nolock) as AM on LSR.event_id = AM.ID     
                  where datediff(d,LCH.createdon,getdate()) <= 7 and leadid = @LeadID     
      FOR XMl PATH('')    
    ),1,1,''    
   )     
  
  
   SELECT   
     @top3Scores = STUFF    
   (    
     (    
     SELECT  top 3 '#'+ CAST(LCH.ScoreAdded AS VARCHAR(MAX))    
         
      FROM lead_score_history(nolock) as LCH   
               join lead_scoring_rules(nolock) as LSR on LCH.rule_id = LSR.id  
               join ActivityMaster(nolock) as AM on LSR.event_id = AM.ID     
                  where datediff(d,LCH.createdon,getdate()) <= 7 and leadid = @LeadID     
      FOR XMl PATH('')    
    ),1,1,''    
   )     
  
  
  
  
  
   declare @temp  numeric(18,2) = 0  
     
   set @temp =  (isnull(@ScoreSum,0)/7)  
  
   if((isnull(@ScoreSum,0)/7 )<> 0  )  
     begin  
        set @ScoreSumPRCNTG = (( @lastRecordBefore7 - @temp )/(@temp)) * 100     
     end  
      
    --set @ScoreSumPRCNTG = (isnull(@ScoreSum,0) * 100)/7    
     
    if(@ScoreSumPRCNTG < 0)  
       begin  
       set @profit_Loss = 'Green_Up'  
    end   
       else if (@ScoreSumPRCNTG > 0)  
      begin  
      set @profit_Loss = 'Red_Down'  
   end      
  
   select @PersonName as PersonName , @companyname as companyname  , @Createdon as Createdon, [dbo].[fn_getrelativescore](@LeadID) as CurrentScore, (@ScoreSumPRCNTG *(-1)) as ScorePRCNTG , @profit_Loss as Profit_Loss , @top3Scores as Top3Scores,@top3ScoringFatcors as Top3ScoringFactors  
     
  
  
  
  
      -- select top 10 * from userleads(nolock) as UL  
  --left join  
  --lead_score_history(nolock) as LCH   
  --on UL.ID = LCH.leadid  
  --where UL.ID = @LeadID  
     
    
     
 End


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetScoreDetailsByLeadID_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetScoreDetailsByLeadID_New  --836764          
 (          
    @LeadID bigint          
 )          
 as          
 Begin    
   
   
 declare @lastscoreupdate datetime,@lastscore int,@topscore nvarchar(max),@topevents nvarchar(max),@topprofit nvarchar(max)  
 --,@leadid bigint=836764  
 select top 1 @lastscoreupdate=createdon,@lastscore=scoreadded from lead_score_history(nolock) where leadid=@leadid order by id desc   
  
select @topscore=coalesce(@topscore+'#','')+cast(TopScore as nvarchar),   
@topevents=coalesce(@topevents+'#','')+cast(EventDescription as nvarchar(max)),  
@topprofit=coalesce(@topprofit+'#','')+Score_profitloss  
from  
(select   
top 3 scoreadded TopScore,  
 t.EventDescription,   
 case when ScoreAdded>0 then 'Green_Up' else 'Red_Down' end as Score_profitloss   
 from   
 lead_score_history (nolock) l join   
 tbl_LeadEventHistory(nolock) t on l.lead_activity_id=t.HistoryID  
 where l.leadid=@leadid order by abs(scoreadded) desc,createdon desc  
) s   
  
 select  personname,companyname,createdon,[dbo].[fn_getrelativescore](@LeadID) as CurrentScore,  
  isnull(ScorePRCNTG,0) as ScorePRCNTG ,Profit_loss,case when [dbo].[fn_getrelativescore](@LeadID)>=isnull(l.Warm,(select Warm from lead_cateogy_thresholds(nolock) where parentid=0)) then 'Hot'  
  when [dbo].[fn_getrelativescore](@LeadID) between isnull(l.Cold,(select cold from lead_cateogy_thresholds(nolock) where parentid=0))  
  and isnull(l.warm,(select warm from lead_cateogy_thresholds(nolock) where parentid=0)) then 'Warm' else 'Cold' end as ThresholdColor,  
  @topscore Top3Scores,@topevents Top3ScoringFactors,@topprofit as Top3_ProfileLoss,'' as EventDescription  
from userleads(nolock) u  
 left join lead_cateogy_thresholds l on u.parentid=l.parentid  
left join  
( select   
 case when datediff(dd,@lastscoreupdate,getdate()) > 7 then 0   
 else  
 cast(sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)  
 /cast(sum(ScoreAdded) as float)*100 as int)   
 end  as ScorePRCNTG,  
 case   
 when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)>0 then 'Green_Up'   
 when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)<0 then 'Red_Down'  
 when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)=0 and @lastscore>0 then 'Green_Up'  
 when sum(case when datediff(dd,createdon,getdate())<=7 then ScoreAdded else 0 end)=0 and @lastscore<0 then 'Red_Down'   
 when  datediff(dd,@lastscoreupdate,getdate()) > 7 and @lastscore>0 then 'Grey_Up'  
 when  datediff(dd,@lastscoreupdate,getdate()) > 7 and @lastscore<0 then 'Grey_Down'  
  end as Profit_loss  
 from lead_score_history (nolock) where leadid=@leadid  
) h on 1=1  
 where u.id=@LeadID   
  
 end  
  
  


GO

