SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetSearchesandGroupforUserCoupons  --'335'  
 @ParentID BIGINT    
AS    
BEGIN   
 SELECT pm.SearchName + ' (' + CASE     
                                    WHEN pm.SearchType = 'AL' THEN 'All'    
                                    ELSE CASE     
                                              WHEN pm.SearchType = 'Co' THEN     
                                                   'Conversion'    
                                              ELSE CASE     
                                                        WHEN pm.SearchType =     
                                                             'LE' THEN     
                                                             'Leads'    
                                                        ELSE CASE     
                                                                  WHEN pm.SearchType     
                                                                       =    
                                                                       'En' THEN     
                                                                       'Enquiry'    
                                                                  ELSE CASE     
                                                                            WHEN     
                                                                                 pm.IsResponse     
                                                                                 =     
                                                                                 1 THEN     
                                                                                 'Response'    
                                                                            ELSE CASE     
                                                                                      WHEN     
                                                                                           pm.IsUnsubscribe     
                                                                                           =    
                                                                                           1 THEN     
                                                                                           'Unsubscribe'    
                                                                                      ELSE CASE     
                                                                                                WHEN     
                                                                                                     pm.IsGroup     
                                                                                                     =    
                                                                                                     1 THEN     
                                                                                                     'Group'    
                                                                                                ELSE     
                                                                                                     ''    
                                                                                           END    
                                                                                 END    
                                                                       END    
                                                             END    
                                                   END    
                                         END    
                               END + ')' AS SearchName,    
        pm.ID    
 FROM   UserSearchList AS pm    
 WHERE  pm.ParentID = @ParentID    
 --ORDER BY    
 --       pm.ID DESC  
  Union
   SELECT      
        gd.Group_Name + ' (Custom Groups)' AS SearchName ,gd.Group_ID   AS ID     
 FROM   Group_Detail     gd
  WHERE  gd.[User_ID] = @ParentID        
 --WHERE  gd.[User_ID] = @UserID  
 END       


