CREATE   PROCEDURE [dbo].[Usp_GetSearchNameAndIDCollections] --2
(  
  @Trg_CMPGN_ID bigint  
)  
as  
Begin  

    --declare @Trg_CMPGN_ID bigint = 2   

 Declare @TriggerCampaignJson nvarchar(max)=(  
        SELECT   
     STUFF((  
   SELECT ', ' + TBL.SearchNameAndID    
   FROM   
   (  
      select USL.CriteriaName +':'+ cast(fnsplitTBL.value as nvarchar) as SearchNameAndID  from tbl_SearchCriteria as USL with(nolock)  --UserSearchList(nolock) as USL   
           join   
            (  
        select value from fn_Split(TGC.Audience,'#')  
      ) as fnsplitTBL  
     on   USL.ID = fnsplitTBL.value  
  
   ) as TBL  
   FOR XML PATH (''))  
    ,1,2,'') AS SearchNameAndIDCollections    
    ,eventid  
    ,[datefield]  
  ,[datefieldtype]  
  ,[dateformattomatch]  
  ,[tc_timeafterevent]  
  ,[tc_timeunit]  
  ,[fixedtime]  
    from triggeredcampaigns(nolock) as TGC  
    where TGC.id = @Trg_CMPGN_ID  
     for json auto, include_null_values )  
 select @TriggerCampaignJson   
