/* ============================================================
   Procedure: [dbo].[usp_GetSearchResultCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  --------Modified By Abhishek Makkar ----------- Time: 8/26/2017 10:54:43 AM------/

CREATE   PROCEDURE [dbo].[usp_GetSearchResultCount] --335,2
	@ParentID BIGINT,
	@SearchID BIGINT
AS
BEGIN
	DECLARE @IsPreDefined      BIT,
	        @IsCustom          BIT,
	        @IsSeach           BIT,
	        @IsResponse        BIT,
	        @isUnsubscribe     BIT
	
	
	
	
	
	
	
	SELECT @IsPreDefined = usl.IsPredefined,
	       @IsResponse        = usl.IsResponse,
	       @isUnsubscribe     = usl.IsUnsubscribe,
	       @IsSeach           = usl.IsSearch,
	       @IsCustom          = usl.IsCustom
	FROM   UserSearchList AS usl
	WHERE  usl.ID = @SearchID
	       AND usl.ParentID = @ParentID
	
	
	
	
	
	
	IF @IsPreDefined = 1
	   OR @IsSeach = 1
	BEGIN
	    CREATE TABLE #TempSearch
	    (
	    	PersonName         VARCHAR(500),
	    	CompanyName        VARCHAR(500),
	    	MobileNo           VARCHAR(500),
	    	MobileNo1          VARCHAR(500),
	    	MobileNo2          VARCHAR(500),
	    	EMailID            VARCHAR(500),
	    	EMailID1           VARCHAR(500),
	    	EMailID2           VARCHAR(500),
	    	Country            VARCHAR(500),
	    	StateEnq           VARCHAR(500),
	    	City               VARCHAR(500),
	    	PinCode            VARCHAR(500),
	    	RAddress           VARCHAR(500),
	    	OAddress           VARCHAR(500),
	    	SourceName         VARCHAR(500),
	    	MediumName         VARCHAR(500),
	    	CampaignName       VARCHAR(500),
	    	InitialRemarks     VARCHAR(500),
	    	SearchID           VARCHAR(500),
	    	ParentID           VARCHAR(500),
	    	CampaignID         VARCHAR(500) 
	    )
	    
	    INSERT INTO #TempSearch
	      (
	        PersonName,
	        CompanyName,
	        MobileNo,
	        MobileNo1,
	        MobileNo2,
	        EMailID,
	        EMailID1,
	        EMailID2,
	        Country,
	        StateEnq,
	        City,
	        PinCode,
	        RAddress,
	        OAddress,
	        SourceName,
	        MediumName,
	        CampaignName,
	        InitialRemarks,
	        SearchID,
	        ParentID,
	        CampaignID 
	      )
	    EXEC usp_ExecuteUserSearch @ParentID,
	         @SearchID
	    
	    
	    SELECT COUNT(*)
	    FROM   #TempSearch AS ts
	END
	ELSE 
	
	
	
	IF @IsResponse = 1
	   OR @isUnsubscribe = 1
	BEGIN
	    SELECT COUNT(*)
	    FROM   ClientLeadDetails AS cld
	    WHERE  cld.CampaignName IN (SELECT TOP 1 ucm.Name
	                                FROM   UserSearchList AS usl
	                                       INNER JOIN UserCampaignSettings AS 
	                                            ucm
	                                            ON  ucm.CampaignID = usl.Campaign
	                                WHERE  usl.ID = @SearchID
	                                       AND usl.ParentID = @parentID)
	END
	ELSE
	BEGIN
	    IF EXISTS (
	           SELECT *
	           FROM   Contact_Group_Detail AS cgd
	           WHERE  cgd.Group_ID = @SearchID
	                  AND cgd.[User_ID] IN (SELECT ud.[User_ID]
	                                        FROM   User_Detail AS ud
	                                        WHERE  ud.ParentID = @ParentID)
	       )
	    BEGIN
	        SELECT COUNT(*)
	        FROM   Contact_Group_Detail AS cgd
	        WHERE  cgd.Group_ID = @SearchID
	               AND cgd.[User_ID] IN (SELECT ud.[User_ID]
	                                     FROM   User_Detail AS ud
	                                     WHERE  ud.ParentID = @ParentID)
	    END
	    ELSE
	    BEGIN
	        SELECT COUNT(*)
	        FROM   UserSearchData uilc
	        WHERE  uilc.ParentID = @ParentID
	               AND uilc.ImportedListID = @SearchID
	    END
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetSearchResultsList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetSearchResultsList
	@ID BIGINT,
	@SearchTech VARCHAR(50),
	@pageSize INT
AS
BEGIN
	BEGIN TRY
		SELECT cld.cname,
		       cld.CampaignName,
		       cld.FirstName,
		       cld.LastName,
		       cld.Email,
		       STR(cld.Mobile)    AS Mobile,
		       cld.[Address],
		       cld.City,
		       cld.Zip,
		       cld.Remarks,
		       CASE 
		            WHEN cld.IsCallMicrosite = 0 THEN 'Call'
		            ELSE 'Microsite'
		       END                AS [TYPE],
		       cld.DateCreated
		FROM   ClientLeadDetails  AS cld
		WHERE  cld.CampaignName IN (SELECT cm.CampaignName
		                            FROM   CampaignMaster AS cm
		                            WHERE  cm.ID IN (SELECT sd.CampaignID
		                                             FROM   SearchDetails AS sd
		                                             WHERE  sd.ID = @ID))
		       AND cld.cname IN (SELECT cld.cname
		                         FROM   CampaignShortURL AS csu
		                         WHERE  csu.CampaignName = cld.CampaignName
		                                AND csu.Track_Unsubscribe IN (SELECT sd.IsTrackUnsubscribe
		                                                              FROM   
		                                                                     SearchDetails AS 
		                                                                     sd
		                                                              WHERE  sd.ID = 
		                                                                     @ID))
	END TRY
	BEGIN CATCH
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END


GO

