CREATE   PROC [dbo].[USP_GetSenderIDPriority]       
(      
@USERID INT ,    
@SENDERNAME VARCHAR(20)    
)      
as      
SET NOCOUNT ON      
SELECT  Sender_ID as sendername,DNDConfig,SMSPriority,SMPPID FROM UserConfigurations      
where Sender_ID=@SENDERNAME   AND U_ID=@USERID 




