/* ============================================================
   Procedure: [dbo].[Usp_GetSenderIDs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetSenderIDs --335  
(  
  @UserID bigint  
)  
as  
Begin  
    
  select  Sender_ID,Sender_Name,Status,User_ID,M_ID,userfilter  from  
  ((Select SD.Sender_ID,SD.Sender_Name,SD.Status,SD.User_ID,SD.M_ID,Ud.userfilter from SenderID_Detail(Nolock) SD  
  join User_Detail(nolock) UD on SD.User_ID = UD.User_ID   
  where SD.User_ID = @UserID  
  and LEN(ISNULL(Sender_Name,'')) = 6  
  and ISNUMERIC(ISNULL(Sender_Name,'')) = case when UD.userfilter = 'MTIX_PRO' then 1 else 0 end    
  and ((SD.Status = 0) or (SD.Status = 3)) )  
  
  union all  
    
  (Select SD.Sender_ID,SD.Sender_Name,SD.Status,SD.User_ID,SD.M_ID,Ud.userfilter from SenderID_Detail(Nolock) SD  
  join User_Detail(nolock) UD on SD.User_ID = UD.User_ID   
  where SD.User_ID = @UserID  
  and LEN(ISNULL(Sender_Name,'')) = 6  
  and ISNUMERIC(ISNULL(Sender_Name,'')) = case when UD.userfilter = 'MTIX_PRO' then 1 else 0 end    
  and (SD.Status = 1)  )  
   ) as tbl order by Sender_Name asc  
  
  
End


GO

