/* ============================================================
   Procedure: [dbo].[usp_GetSenderPriority]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  /****************************************************************************  
SP_Name        : [usp_GetSenderPriority]                     
Author         : Mukesh 
Created ON     : 25/12/2009 04:30 PM        
Version        : 1  
Alter BY       :          
Alter Date    :   
Location       : PELSOFT  
SP Description : This SP is Used to Select SenderId from MessageStorage table
         
****************************************************************************/ 
CREATE   PROC [dbo].[usp_GetSenderPriority]      
@UserId int,  
@SenderId varchar(100)=null                                                       
  
As  
/* we can not afford to use hardcode database name in proc and join is not required here to update priority   
of any user ,sender or batch becouse all the data is available in same table   
*/  
SET NOCOUNT ON  
   
if ((@SenderId is null) or @SenderId ='' )  
BEGIN  
  
select distinct senderid as sender_id,senderid as sender_Name,  
CASE  
    WHEN priority=1   
     THEN 'H'  
    WHEN priority=2  
    THEN 'N'       
   ELSE 'L'  
     END as priority  
  
from MessageStorage     
 where u_id=@UserId     
END  
else  
BEGIN  
select distinct senderid as sender_Id,senderid  as sender_Name,  
CASE  
    WHEN priority=1   
     THEN 'L'  
    WHEN priority=2  
    THEN 'M'       
   ELSE 'H'  
     END as priority  
from MessageStorage where u_id=@UserId  and SenderId =@SenderId  
  
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetSendMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC  Usp_GetSendMessage  
AS  
Begin  
Declare @total int  
Declare @priority int  
Declare @normal int  
set @total=0  
set @priority=0  
set @normal=0  
select @total=count(*) from mysmstrans.dbo.messagedeliverystatustemp with(nolock)  
select @priority=count(*) from mysmstrans.dbo.messagedeliverystatustemp with(nolock) where priority!=0  
select @normal=count(*) from mysmstrans.dbo.messagedeliverystatustemp with(nolock) where priority=0  
select @total as Total,@priority as Priority,@normal as Normal  
  
End 



GO

