/* ============================================================
   Procedure: [dbo].[usp_GetSequenceMasterByParentIdSeventId_2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------------------




----------------------------------need to run in mysmsconversation

CREATE   PROCEDURE [dbo].[usp_GetSequenceMasterByParentIdSeventId_2]        
(        
    @ParentId BIGINT,          
    @seventid BIGINT = 0        
)          
AS           
BEGIN           
    SET NOCOUNT ON;           
      
    BEGIN TRY           
        DECLARE @context NVARCHAR(50);      
            
        -- Fetch the context from ActivityMaster based on @seventid      
        SELECT @context = ama.Context      
        FROM Mysms.dbo.ActivityMaster ama      
        WHERE ama.ID = @seventid;      
            
        -- First part: General and other activity sequence types      
        SELECT DISTINCT  *       
        FROM (        
            -- For 'otheractivity' type    
            SELECT sm.SequenceId, sm.Name, sm.sequencetype, sm.s_eventid, ama.EventName, trg.s_maxlimit       
            FROM tbl_WA_SequenceMaster (NOLOCK) sm          
            LEFT JOIN Mysms.dbo.ActivityMaster ama ON sm.s_eventid = ama.ID      
            LEFT JOIN Mysms.dbo.Triggeredcampaigns trg ON ama.ID  = trg.eventid  -- Updated join    
            WHERE sm.ParentId = @ParentId       
            AND sm.s_eventid = (CASE WHEN @seventid != 0 THEN @seventid ELSE sm.s_eventid END)           
            AND sm.sequencetype = 'otheractivity'       
            AND sm.IsActive = 1       
            AND sm.IsDeleted = 0          
      
            UNION ALL        
      
            -- For 'general' type    
            SELECT sm.SequenceId, sm.Name, sm.sequencetype, sm.s_eventid, '' AS EventName, trg.s_maxlimit        
            FROM tbl_WA_SequenceMaster (NOLOCK) sm      
            LEFT JOIN Mysms.dbo.Triggeredcampaigns trg ON sm.s_eventid = trg.eventid -- Updated join    
            WHERE sm.ParentId = @ParentId       
            AND sm.s_eventid = 0           
            AND sm.sequencetype = 'general'       
            AND sm.IsActive = 1       
            AND sm.IsDeleted = 0          
      
            -- Conditional union based on context ('enquiry' or 'lead')      
            UNION ALL        
      
            -- Context: 'enquiry'      
            SELECT  sm.SequenceId, sm.Name, sm.sequencetype, sm.s_eventid, '' AS EventName, trg.s_maxlimit        
            FROM tbl_WA_SequenceMaster (NOLOCK) sm      
            LEFT JOIN Mysms.dbo.Triggeredcampaigns trg ON sm.s_eventid = trg.eventid -- Updated join    
            WHERE sm.ParentId = @ParentId       
            --AND sm.s_eventid <> 0           
            AND sm.sequencetype = 'enquiry'       
            AND sm.IsActive = 1       
            AND sm.IsDeleted = 0        
            AND @context = 'enquiry'      
            
            UNION ALL        
      
            -- Context: 'lead'      
            SELECT  sm.SequenceId, sm.Name, sm.sequencetype, sm.s_eventid, '' AS EventName, trg.s_maxlimit        
            FROM tbl_WA_SequenceMaster (NOLOCK) sm     
            LEFT JOIN Mysms.dbo.Triggeredcampaigns trg ON sm.s_eventid = trg.eventid -- Updated join    
            WHERE sm.ParentId = @ParentId       
            --AND sm.s_eventid <> 0           
            AND sm.sequencetype = 'lead'       
            AND sm.IsActive = 1       
            AND sm.IsDeleted = 0        
            AND @context = 'lead'      
      
        ) t;      
      
    END TRY                                 
    BEGIN CATCH                         
        DECLARE @ErrorMessage NVARCHAR(4000);                         
        SELECT @ErrorMessage = ERROR_MESSAGE();                         
        RAISERROR (@ErrorMessage, 16, 1);                         
    END CATCH;         
END; 




GO

/* ============================================================
   Procedure: [dbo].[usp_getserviceusage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getserviceusage
@period nvarchar(20)=null
as
begin
set @period=coalesce(@period,'Day')

select c.user_id,User_login,'SMS' as ServiceName, sum(case when c.user_id<>fromuser_id then debits else 0 end) Deducted,
sum(case when c.user_id=fromuser_id then debits else 0 end) Used,
sum(case when c.user_id<>fromuser_id then credits else 0 end) [Purchased/Refunded],  
sum(case when c.user_id=fromuser_id then credits else 0 end) Returned,
dbo.fn_getSMSbalance(c.user_id) as Balance,
cast(dbo.fn_serviceusedlast(c.user_id,'sms') as date) as LastUsageOn
into #sms
from credit_details c(nolock)  join user_detail u (nolock) 
on dbo.ufn_getuserparentid(c.user_id)=u.user_id
where 
1= case when @period='Day' and cast(c.fromdate as date)=dateadd(d,-1,cast(getdate() as date)) then 1
when @period='Month' and month(c.fromdate)=month(getdate()) and year(c.fromdate)=year(getdate()) then 1 
else 0 end
group by User_login,c.user_id

select c.user_id,User_login,'Mail' as ServiceName, sum(case when c.user_id<>fromuser_id then debits else 0 end) Deducted,
sum(case when c.user_id=fromuser_id then debits else 0 end) Used,
sum(case when c.user_id<>fromuser_id then credits else 0 end) [Purchased/Refunded],  
sum(case when c.user_id=fromuser_id then credits else 0 end) Returned,
dbo.fn_getMailbalance(c.user_id) as Balance,
cast(dbo.fn_serviceusedlast(c.user_id,'Mail') as date) as LastUsageOn
into #mail
from mailcreditdetails c(nolock)  join user_detail u (nolock) 
on dbo.ufn_getuserparentid(c.user_id)=u.user_id
where 
1= case when @period='Day' and cast(c.fromdate as date)=dateadd(d,-1,cast(getdate() as date)) then 1
when @period='Month' and month(c.fromdate)=month(getdate()) and year(c.fromdate)=year(getdate()) then 1 
else 0 end
group by User_login,c.user_id

select c.user_id,User_login,creditname as ServiceName, sum(case when c.user_id<>fromuser_id then debits else 0 end) Deducted,
sum(case when c.user_id=fromuser_id then debits else 0 end) Used,
sum(case when c.user_id<>fromuser_id or creditname='refund' then credits else 0 end) [Purchased/Refunded],  
sum(case when c.user_id=fromuser_id  then credits else 0 end) Returned,
dbo.fn_getMoneybalance(c.user_id) as Balance,
dbo.fn_serviceusedlast(c.user_id,creditname) as LastUsageOn
into #wallet
from intcredit_details c(nolock)  join user_detail u (nolock) 
on dbo.ufn_getuserparentid(c.user_id)=u.user_id
join price_master_typecredit p(nolock) on p.credittypeid=c.typecredit
where 
1= case when @period='Day' and cast(c.fromdate as date)=dateadd(d,-1,cast(getdate() as date)) then 1
when @period='Month' and month(c.fromdate)=month(getdate()) and year(c.fromdate)=year(getdate()) then 1 
else 0 end
group by User_login,c.user_id,creditname

select * from #sms
select * from #mail
select * from #wallet
end


GO

/* ============================================================
   Procedure: [dbo].[usp_GetSetCommonData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_GetSetCommonData @jsonData='{"Mode": "GlobalSearch","UserId":"32222","SearchText":"User"}'
CREATE   PROC usp_GetSetCommonData
(
	@jsonData	nvarchar(max)
)
As
Begin

	-- declare @jsonData nvarchar(max)=N'{"Mode": "GlobalSearch","UserId":"32222","SearchText":"User"}'

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, 
			@TableName varchar(100)='', @ParentId bigint, @UserId bigint, @IsAdmin bit, @Mode nvarchar(100)=''

	Declare @SearchText nvarchar(200)
	
	Select @Mode=Mode,@UserId=UserId
	From openjson(@jsonData)
	With 
	(
		Mode		nvarchar(100)	'$.Mode',
		UserId		bigint			'$.UserId'
	)

	print '@jsonData: ' + isnull(@jsonData,'')
	print '@Mode: ' + isnull(@Mode,'')

	SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;    

	If(@Mode = 'GlobalSearch')
	Begin
		Select @SearchText=SearchText
		From openjson(@jsonData)
		With 
		(
			SearchText		nvarchar(200)		'$.SearchText'
		)

		select *
		From (
		Select ROW_NUMBER()over(order by T.ConversationId desc) SNo,T.* 
		From (
		SELECT	ROW_NUMBER()over(partition by CON.ConversationId/*,CDT.ReceiverId*/ order by CON.ConversationId desc) RNo,
				CON.ConversationId, CON.GroupId, CON.ParentId, CON.[Content], CON.ContentTypeId, CON.SenderId,
				CON.ReceiverType, CON.ContentAction, CON.ContentActionRef, CON.SentOn, CON.StatusId, 
				IsStarred=IIF(CON.SenderId=@userId,CON.IsStarred,CDT.IsStarred), UD.User_Login as SenderName,
				IsDeleted=IIF(CON.SenderId=@userId,CON.IsDeleted,CDT.IsDeleted), 
				ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
				CON.IsActive, CON.CreatedBy, CON.CreatedOn, CON.ModifiedBy, CON.ModifiedOn,
				GRP.GroupName, GRP.Visibility, GRP.GroupType, CT.ContentType, STAT.StatusName, CDT.ReceiverId,
				CDT.DeliveredOn, CDT.ReadOn, CDT.ReceivedOn
		FROM	tbl_clb_Conversation(nolock) CON INNER JOIN tbl_clb_Group(nolock) GRP
		ON		CON.GroupId = GRP.GroupId INNER JOIN tbl_clb_ContentType(nolock) CT
		ON		CON.ContentTypeId = CT.ContentTypeId INNER JOIN tbl_clb_ConversationStatus(nolock) STAT 
		ON		CON.StatusId = STAT.StatusId INNER JOIN User_Detail(Nolock) UD
		ON		CON.SenderId = UD.User_ID LEFT JOIN tbl_clb_ConversationDetail(NOLOCK) CDT
		ON		CON.ConversationId = CDT.ConversationId and CON.IsActive=1 and CDT.IsActive=1 
				--and CDT.IsDeleted=0 and CDT.ReceiverId=@userId
		Where CON.ParentId=@ParentId and
			  (CON.GroupId in (Select GroupId from tbl_clb_GroupMembers(nolock) where UserId=@UserId and IsBlocked=0 and IsActive=1 and IsLeftGroup=0)) and 
			  --CON.IsDeleted=0 and CON.IsActive=1 and 
			  CON.StatusId not in (6)
		) T
		Where T.RNo=1
		) U
		Where	U.[Content] like '%'+@SearchText+'%'

		select  UD.User_ID, UD.User_Login, concat(FName,' ',LName,'(',User_Login,')') as FullName, LH.ActivityType,
		ActivityDate=LH.Datecreated,ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
		CountryCode, cast(Mobile as bigint) as Mobile, GroupId=(select top 1 G.GroupId From tbl_clb_Group(nolock) G inner join tbl_clb_GroupMembers(nolock) GM On G.GroupId=GM.GroupId Where G.GroupType='Individual' and G.IsActive=1 and GM.IsActive=1 and GM.userId=UD.User_ID)
		FROM	User_Detail(Nolock) UD outer apply (SELECT top 1 * FROM [loginhistory](NOLOCK) WHERE user_id = UD.User_id order by 1 desc) LH 
		Where	UD.ParentID=@ParentId and UD.Status=1 and concat(FName,' ',LName,'(',User_Login,')') like '%' + @SearchText+ '%'

		Select *
		From (
			select ROW_NUMBER()over(partition by GR.GroupId order by CONV.ConversationId desc) Sno, GR.GroupId,
			GroupName=case when GR.GroupType='Individual' then isnull((select top 1 concat(UD.FName,' ',UD.LName,'(',UD.User_Login,')') from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId) ),GR.GroupName) else GR.GroupName end,GR.GroupDesc,GR.Visibility,GR.GroupType,GR.ParentId,GR.IsActive,GR.CreatedBy,GR.CreatedOn,GR.ModifiedBy,GR.ModifiedOn,GR.ProfileUrl,UnreadMsgCnt=sum(iif(CONVDET.ReadOn is null and CONVDET.ReceiverId=@UserId,1,0)) over(partition by GR.GroupId), LastMsg=CONV.Content,LastMsgTimeStamp=isnull(CONVDET.DeliveredOn, CONV.SentOn), IsGrpAdmin=IIF(GR.CreatedBy=@UserId,1,isnull(GRM.IsGroupAdmin,0)), ContentTypeId=isnull(CONV.ContentTypeId,0), ContentType=isnull(CT.ContentType,''), CONV.ConversationId
			from tbl_clb_Group(nolock)GR left join tbl_clb_Conversation(nolock)CONV
			on	 GR.groupId=CONV.GroupId and CONV.IsActive=1 and CONV.IsDeleted=0 left join tbl_clb_ConversationDetail(nolock)CONVDET
			on	CONV.ConversationId = CONVDET.ConversationId and CONVDET.IsActive=1 and CONVDET.IsDeleted=0 and CONVDET.ReceiverId=@UserId /*and CONVDET.ReadOn is null*/ left join tbl_clb_GroupMembers(nolock) GRM
			on	GR.GroupId=GRM.GroupId and GRM.IsleftGroup=0 and GRM.IsBlocked=0 and GRM.IsActive=1 and GRM.UserId=@UserId left join tbl_clb_ContentType(nolock) CT
			on	CONV.ContentTypeId=CT.ContentTypeId
			where GR.ParentId=@ParentId and GR.IsActive=1 and (GR.CreatedBy=@UserId or GR.GroupId in (Select GRM.GroupId from tbl_clb_GroupMembers(nolock)GRM where GRM.IsActive=1 and GRM.IsBlocked=0 and GRM.IsLeftGroup=0 and GRM.UserId=@UserId))
		) T
		Where T.Sno=1 and T.GroupName like '%' + @SearchText+ '%'
		order by T.ConversationId desc

		SET @rowJson = ''
		SET @activity = 'View_Srch_Global'
		SET @action = 'S'  
		SET @TableName = 'tbl_clb_Conversation'
	End

	If(@rowJson is not null)
	Begin
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = @TableName
	End

End



GO

