/* ============================================================
   Procedure: [dbo].[usp_GetSetTraiConsentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  -- Exec usp_GetSetTraiConsentDetails @UserId=42803,@Mode='Get'    
-- Exec usp_GetSetTraiConsentDetails @UserId=32222,@Mode='Set'    
CREATE   PROC usp_GetSetTraiConsentDetails  
(    
 @UserId bigint,  
 @Mode varchar(3)--'get','set'  
)  
As  
Begin  
-- declare @UserId bigint=42803, @Mode varchar(3)='get'
declare @Country varchar(50)=''
Select @Country=LTRIM(RTRIM(Country)) from User_Detail(nolock) where User_Id=@UserId

 If(@Mode = 'Get')  
 Begin  
  If exists(Select UserId From tbl_TraiNotification(nolock) where UserId=@UserId)  
  Begin  
   Select 1 as Id  
  End  
  Else  
  Begin  
   Select case when @Country='India' then 0 else 1 end as Id  
  End  
 End  
  
 If(@Mode = 'Set')  
 Begin  
  If not exists(Select UserId From tbl_TraiNotification(nolock) where UserId=@UserId)  
  Begin  
   insert into tbl_TraiNotification(UserId) values(@UserId)  
  
   Select Scope_Identity() as ID  
  End  
  Else  
  Begin  
   Select 0 as Id  
  End  
 End  
  
End  



GO

/* ============================================================
   Procedure: [dbo].[usp_GetSetUserPresence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- exec usp_GetSetUserPresence 32222,'get' ,1   
-- exec usp_GetSetUserPresence 32222,'set',1    
CREATE   PROC usp_GetSetUserPresence    
(    
    @User_Id bigint,    
    @Mode varchar(3)='set',    
    @Presence int=0    
)    
As    
Begin    
    
    If(@Mode = 'get')    
    Begin    
		select Presence from User_Detail(nolock) where User_ID=@User_Id       
    End    
        
    If(@Mode = 'set')    
    Begin    
		update User_Detail set Presence=case when onduty=1 then @Presence else Presence end where User_ID=@User_Id    
		Select @@ROWCOUNT AS Presence  
    End    
    
End 



