/* ============================================================
   Procedure: [dbo].[usp_getshorturl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE usp_getshorturl        
(@users nvarchar(max),@batchid bigint)        
as        
begin    
/*
select distinct userid  value     
into #user       
from Price_UserSubscriptionDetails (nolock)  where IsNewPlan=1 and PlanEndDate>=cast(getdate() as date) --and userid=17626      
select [value] into #user from dbo.fn_split(@users,',')        
*/    
select [value] into #user from dbo.fn_split(@users,',')        
insert into Link_smsUrl_dtl(batchid,short_url,longurl,parentid,page_nm,lAction,P_url)        
select batchid,short_url,longurl,parentid,page_nm,lAction,P_url        
from        
(select @batchid batchid,'pel.im' short_url,'kit19.com/UserCRMCampaign/Report/UsageReport.aspx?id='+cast(u.value as nvarchar(100)) +'&authid='+cast(ud.id as nvarchar(100)) longurl,335 parentid,'Automated' page_nm        
,'Original Url' lAction,'kit19.com/UserCRMCampaign/Report/UsageReport.aspx?id='+cast(u.value as nvarchar(100)) +'&authid='+cast(ud.id as nvarchar(100)) P_url        
from #user u         
join user_detail ud on u.[value]=ud.user_id        
join userreport r on u.[value]=r.user_id        
where ud.User_ID=ud.ParentID  and str(mobile)<>'0'        
union all        
select @batchid batchid,'pel.im' short_url,'kit19.com/UserCRMCampaign/Report/UserActivityReport.aspx?id='+cast(r.id as nvarchar(100))+'&authid='+cast(r.authid as nvarchar(100)) longurl,335 parentid,'Automated' page_nm        
,'Original Url' lAction,'kit19.com/UserCRMCampaign/Report/UserActivityReport.aspx?id='+cast(r.id as nvarchar(100))+'&authid='+cast(r.authid as nvarchar(100)) P_url        
from #user u         
join user_detail ud on u.value=ud.user_id        
join userreport r on u.value=r.user_id        
where ud.User_ID=ud.ParentID and str(mobile)<>'0'    
) A      
drop table #user  
end 


