/* ============================================================
   Procedure: [dbo].[Usp_getSixDaysRecordByUserIDTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_getSixDaysRecordByUserIDTable]   --'SixDaysHistory1','messagestop1','MessageDND1','MessageFailed1','PremiumMessage1',5013 
@SixDaysHistory nvarchar(200),  
@Stopped nvarchar(200),   
@MessageDND nvarchar(200),  
@MessageFailed nvarchar(200),  
@PremiumMessage nvarchar(200),   
@U_ID nvarchar(200)    
AS      
BEGIN    
SET NOCOUNT ON        
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED                
Declare @Total nvarchar(2000),@Deliver nvarchar(2000)  
Declare @stop nvarchar(2000),@dnd nvarchar(2000)  
Declare @Failed nvarchar(2000),@Premium nvarchar(2000)  
  
set @Total='select cast(count(*) as nvarchar(100))  as Total from '+@SixDaysHistory+' where U_id='+@U_ID+''    
set @Deliver='Select  cast(count(*) as nvarchar(100))  as Deliver   from '+@SixDaysHistory+' Where MessageStatus is not null and U_id='+@U_ID+''  
set @stop='select  cast(count(*) as nvarchar(100))  as Stop  from '+@Stopped+' where U_id='+@U_ID+''  
set @dnd='select   cast(count(*) as nvarchar(100))  as DND from '+@MessageDND+' where U_id='+@U_ID+''  
set @Failed='select  cast(count(*) as nvarchar(100))  as Faild  from '+@MessageFailed+' where U_id='+@U_ID+''  
set @Premium='select   cast(count(*) as nvarchar(100))   as Premium  from '+@PremiumMessage+' where U_id='+@U_ID+''  
  
exec (@Total)  
exec   (@Deliver)  
exec      (@stop)  
exec      (@dnd)  
exec      (@Failed)  
exec      (@Premium)  
  
end  


GO

