/* ============================================================
   Procedure: [dbo].[usp_GetSmsCampaignExecutionDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetSmsCampaignExecutionDetails]
	@camid bigint = NULL,
    @UserId bigint = NULL, 
    @FromDate DATETIME = NULL, 
    @ToDate DATETIME = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- Temporary table to store intermediate results (if needed)
    CREATE TABLE #TempResults (
        CampaignName NVARCHAR(255),
        BatchID INT,
        ExecutionDate DATETIME,
        ReplyTo NVARCHAR(255),
        Status NVARCHAR(50),
        Message NVARCHAR(MAX)
    );

    -- Main Query to Fetch Data
    INSERT INTO #TempResults (CampaignName, BatchID, ExecutionDate, ReplyTo, Status, Message)
    SELECT 
        UCM.CampaignName,                    
        UCEH.BatchID,                        
        UCEH.ExecutionTime,                  
        CE.Mobile,                          
        CE.MessageStatus,                           
        CE.Message                           
    FROM 
        UserCampaignExecutionHistory UCEH
    INNER JOIN 
        UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
    INNER JOIN 
        batchinfo BEI ON UCEH.BatchID = BEI.BatchID
    INNER JOIN 
        messagedeliverystatus CE ON BEI.BatchID = CE.BatchID
    WHERE 
        --(@UserId IS NULL OR UCEH.UserID = @UserId) 
		(@camid IS NULL OR UCEH.CampaignID = @camid)
        and (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
        AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);   

    -- Return Results
    SELECT * 
    FROM #TempResults;

    -- Cleanup
    DROP TABLE #TempResults;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_GetSmsConsumptionByMID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetSmsConsumptionByMID
    @m_id INT
AS
BEGIN
    SET NOCOUNT ON;

    -- Retrieve total consumption for each User_ID based on m_id from Reseller_Detail
    SELECT 
        u.User_ID,
        ISNULL(SUM(dc.TotalConsumption), 0) AS TotalConsumption
    FROM 
        Reseller_Detail AS r
    INNER JOIN 
        User_Detail AS u ON r.M_ID = u.M_ID
    LEFT JOIN 
        DailyConsumption AS dc ON u.User_ID = dc.User_ID
    WHERE 
        r.m_id = @m_id
    GROUP BY 
        u.User_ID
    ORDER BY 
        u.User_ID;

END;



GO

/* ============================================================
   Procedure: [dbo].[usp_GetSmsConsumptionByMID_2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetSmsConsumptionByMID_2]
    @m_id INT
AS
BEGIN
    SET NOCOUNT ON;

    -- Main query to retrieve total consumption for each User_ID
    SELECT TOP 5 
        u.User_ID,
         u.FName + ' ' + u.LName + ' (' + u.user_login + ')' AS FullName,
        ISNULL(SUM(dc.TotalConsumption), 0) AS TotalConsumption
    FROM 
       
        User_Detail (nolock) AS u 
    LEFT JOIN 
        DailyConsumption AS dc ON u.User_ID = dc.User_ID
    WHERE 
        u.m_id = @m_id AND month(dc.Date)=MONTH(getdate()) and year(dc.Date)=year(getdate())
    GROUP BY 
        u.User_ID, u.FName, u.LName, u.user_login  -- Include FName and LName here
    ORDER BY 
        u.User_ID DESC;
END;



GO

