/* ============================================================
   Procedure: [dbo].[Usp_getsmsforAPI]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_getsmsforAPI](@batchid bigint)
as
begin
            
SELECT  
right(t.MessageID,9) UserTag,t.MessageID,'91' + rtrim(ltrim(t.Mobile)) as Mobile,  
REPLACE(case when t.IsUniCode = 0 then REPLACE(REPLACE([Message],char(146),char(39)),char(145),char(39))    
        else   [Message] end    
       ,char(150),char(45)) as [Message],rtrim(ltrim(SenderID)) SenderID,mysms.dbo.ufn_getuserparentid(t.u_id),dbo.fn_IsUnicode(t.Message) as IsUnicode,
	   2 priority,t.BATCHID,'' Operator
	   ,isnull(d.flash,0) isflash
	   ,dbo.fn_getpe_id(u_id) PE_ID,d.DLT_TemplateID             
FROM  dbo.CloneMessageDeliveryStatusLess t with (nolock) 
join mysms.dbo.DLT_Template_MSG d with (nolock) on t.BatchID=d.BatchID 
where t.batchid=@batchid
end







GO

/* ============================================================
   Procedure: [dbo].[Usp_GetSMSMailRecipient]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 CREATE   PROC [dbo].[Usp_GetSMSMailRecipient]
(@ParentID BIGINT)
 AS
BEGIN
	SELECT tblSMS.NoOfRecipients  AS SMSMailRecipients,
	       'SMS' AS                  SMS_Mail
	FROM   (
	           SELECT UCEH.CampaignID AS CampaignID,
	                  SUM(UCEH.NoOfRecipients) AS NoOfRecipients
	           FROM   UserCampaignExecutionHistory UCEH(NOLOCK)
	                  INNER JOIN UserCampaignMaster UCM(NOLOCK)
	                       ON  UCEH.CampaignID = UCM.ID
	           WHERE  ISNULL(UCM.SenderID, '') <> ''
	                  AND ucm.ParentID = @ParentID
	           GROUP BY
	                  UCEH.CampaignID
	       )                      AS tblSMS 
	
	UNION 
	
	SELECT tblMail.NoOfRecipients  AS SMSMailRecipients,
	       'Mail' AS                  SMS_Mail
	FROM   (
	           SELECT UCEH.CampaignID AS CampaignID,
	                  SUM(UCEH.NoOfRecipients) AS NoOfRecipients
	           FROM   UserCampaignExecutionHistory UCEH(NOLOCK)
	                  INNER JOIN UserCampaignMaster UCM(NOLOCK)
	                       ON  UCEH.CampaignID = UCM.ID
	           WHERE  ISNULL(UCM.SenderID, '') = ''
	                  AND ucm.ParentID = @ParentID
	           GROUP BY
	                  UCEH.CampaignID
	       )                       AS tblMail
END                 



GO

/* ============================================================
   Procedure: [dbo].[usp_getSMSMailWalletBalance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_getSMSMailWalletBalance @User_ID=31871
CREATE   PROC usp_getSMSMailWalletBalance
(
	@User_ID bigint
)
AS
BEGIN
	-- declare @User_ID bigint=32222
    Declare @ParentID bigint, @MIDP bigint, @Type int, @AcType varchar(50)='', @MoneyBalance numeric(18,2)=0
	Declare @SmsValidity int=0, @MailValidity int=0, @BalStrMail nvarchar(500)='', @BalStrSMS nvarchar(500)=''

	select @ParentID=ParentID, @MIDP=M_ID, @Type=Type, @AcType=(case userfilter when 'MT' then 'MOMT' when 'MTIX_PRO' then 'Promotional' when 'TRANS' then 'Transactional' when 'OPEN' then 'OPEN DND' when 'TR_CURVE' then 'SCRUB' when 'MT_TRANS' then 'Transactional' when 'MTIX_TR' then 'Transactional' when 'MTIX_TRC' then 'SCRUB' WHEN 'CRITICAL' THEN 'CRITICAL' else 'Promotional' end), @MoneyBalance=dbo.[fn_GetMoneyBalance](@ParentID)
	from User_Detail with(nolock) 
	where User_ID = @User_ID
  
	if exists(select 1 from user_detail(nolock) where HasVirtualCredits=1 and IsSuperReseller=1 and USER_ID=@ParentID)          
	begin          
		declare @actualbalance bigint= isnull((select top 1 balance       
		from  superresellercredit_details(nolock) where m_id=@MIDP and user_id=@ParentID order by credit_id desc),0)         
	
		select top 1 @SmsValidity=99999,@BalStrSMS=cast(balance as nvarchar) + ' ( ' +cast(@actualbalance as nvarchar) + ' ) '
		from credit_details(nolock) --with(index(idx_Credit_id_user_id_m_id))               
		where m_id=@MIDP and user_id=@ParentID order by credit_id desc                 
		
		SELECT TOP 1 @MailValidity=99999,@BalStrMail=cast(balance as nvarchar) + ' ( ' +cast(@actualbalance as nvarchar) + ' ) '
		FROM   MailCreditDetails(nolock) WHERE  m_id = @MIDP  AND USER_ID = @ParentID ORDER BY credit_id DESC            

	end          
	else          
	begin         
		select top 1 @SmsValidity=99999,@BalStrSMS=balance  from credit_details(nolock) --with(index(idx_Credit_id_user_id_m_id))
		where m_id=@MIDP and user_id=@ParentID order by credit_id desc          
		
		SELECT TOP 1 @MailValidity=99999,@BalStrMail=balance FROM MailCreditDetails(nolock) WHERE  m_id = @MIDP  AND USER_ID = @ParentID ORDER BY credit_id DESC             

	end        

	select @Type as [Type], @AcType as AcType, @MoneyBalance as MoneyBalance, @SmsValidity as SmsValidity, @MailValidity as MailValidity, @BalStrMail as BalStrMail, @BalStrSMS as BalStrSMS

END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetSmsNotificationsByCategory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetSmsNotificationsByCategory]--null, 335
    @Search NVARCHAR(100) = NULL ,
	@UserId bigint
AS
BEGIN

 --declare 

 --@Search NVARCHAR(100) = NULL,
 --@UserId bigint=335

    SET NOCOUNT ON;
	 BEGIN TRY
	 DECLARE @ResellerID BIGINT;
    DECLARE @Result NVARCHAR(100);


	 SELECT @ResellerID = Reseller_ID
        FROM [dbo].reseller_detail (NOLOCK)
        WHERE User_ID = @UserID;

    -- Retrieve distinct categories only from the smsnotifications table
    SELECT DISTINCT Category   
    FROM dbo.smsnotifications sn (nolock)  
    WHERE isactive = 1  
	 AND  1= case when @Search is not null  
	 and sn.eventname like '%'+ @Search+'%' then 1 when @Search IS NULL then 1 else 0 end
      --AND (@Search IS NULL OR eventname = @Search);  

    -- First, select data from DLTMappedEvent with the category from smsnotifications (if available)
    	  --declare @search nvarchar(50),@resellerid bigint=10043
 SELECT   
        ISNULL(sn.id, 0) AS id,  -- Use 0 as a placeholder if no ID from smsnotifications
        ISNULL(sn.Category, '') AS Category,  
        isnull(de.smscontent,sn.messagetext) AS description,  
        isnull(de.eventid,sn.eventid) AS Eventid,  
        isnull(de.Event,sn.eventname) AS eventname,  
        isnull(de.smscontent,sn.messagetext) AS messagetext,  
        sn.messagetext_wvariables AS messagetext_wvariables,  
        de.mappeddate AS createdon,
        isnull(de.isactive,0) AS status,  
        de.DLTTemplateID AS dltid,  
        de.senderid AS senderid  
    FROM 
	(select * from dbo.DLTMappedEvent AS de (nolock) where  de.ResellerID=@resellerid) de
     right JOIN dbo.smsnotifications AS sn (nolock) ON sn.eventname = de.Event
    WHERE 
	  1= case when @search is not null  and sn.eventname like '%'+ @Search+'%' then 1 when @Search IS NULL then 1 else 0 end
	  END TRY
    BEGIN CATCH
        -- Handle errors and return error message
        SELECT ERROR_MESSAGE() AS ResultMessage;
    END CATCH
END;


GO

