	--	@OffsetValue int=0,
	--	@PagingSize int=20
	
	declare @ParentId bigint
	select @ParentId=ParentID  from User_Detail(NOLOCK) where User_ID = @UserId
	
	declare @StartPoint int = (@OffsetValue + 1),  @Endpoint int = (@OffsetValue + @PagingSize);

	;with snap as  (
		SELECT 
		ROW_NUMBER() OVER (PARTITION BY A.ParentBy ORDER BY A.createdOn DESC) AS SNo,
		 A.Id, guid,snapshotName,createdBy,
		Format(createdOn,'dd-MMM-yyyy hh:mm:ss tt') as createdOn,A.ParentId,A.parentBy, 
		CONCAT( ud.User_Login ,'(',FName,' ',LName,')') as UserName, ud.EMail, ud.Mobile, ud.Address              
	FROM tbl_snapshot (NOLOCK) A LEFT JOIN User_Detail (NOLOCK) ud ON ud.User_ID =A.parentBy
		WHERE isnull(A.ParentBy, 0) = @ParentId AND A.isActive = 1
			AND ( ISNULL(@FilterText, '') = '' 
				OR A.snapshotName LIKE '%' + @FilterText + '%'
			)
	)
	select
		SNo,
		(select count(1) from snap) AS TotalRow,
		Id, guid, snapshotName, createdBy, createdOn, ParentId, parentBy, UserName, EMail, Mobile, Address
	from snap where snap.SNo BETWEEN @StartPoint AND @Endpoint;
end



GO

/* ============================================================
   Procedure: [dbo].[usp_GetSnapshotModuleJsonById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetSnapshotModuleJsonById]
(
@UserId bigint,
@SnapshotGuid nvarchar(255)
)
as
begin
--declare 
--@UserId bigint=34594,
--@SnapshotGuid nvarchar(255)='789f20b3c2524d73b04405a4752defda'
declare @ParentId bigint
select @ParentId=ParentID  from User_Detail(NOLOCK) where User_ID = @UserId
 select (select m.moduleName, sm.snapshot_meta_data, m.dependencies from tbl_snapshotMapping(nolock) sm
	inner join tbl_Snapshotmodules(nolock) m on sm.moduleId = m.id 
	inner join tbl_Snapshot(nolock) sp on sp.Id = sm.snapshotId  

	where sp.guid = @SnapshotGuid and sp.ParentId!=@ParentId for json path) as jsonSetting
end


