/* ============================================================
   Procedure: [dbo].[Usp_GetSourcewiseLeadReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetSourcewiseLeadReport --31031,'01-Sep-2023','30-Sep-2023'        
  (        
    @userid BIGINT                  
   ,@fromdate DATE                  
   ,@todate DATE           
 )        
as        
begin        
       /*  for debugging   
      declare  @UserID bigint = 31031,        
          @fromdate DATE ='01-Sep-2023',         
             @todate DATE ='30-Sep-2023'        
          
        */
        
    declare @Isadmin bit = 0,@parentid bigint;              
        select @ParentID = ParentID from user_detail with(nolock)  where User_ID = @userID          
        
 DECLARE @tbluser TABLE (                  
   User_ID BIGINT                  
   ,Name VARCHAR(100)                  
   ,IMAGE VARCHAR(100)                  
   )                  
                
                  
  SELECT @IsAdmin = IsAdmin                  
  FROM User_Detail(NOLOCK)                  
  WHERE User_ID = @Userid                  
                  
 IF (@IsAdmin = 1)                  
 BEGIN                  
  --set @Userid = 0;                            
  INSERT INTO @tbluser                  
  EXEC Use_GetUserDetails @ParentId                  
 END                  
 ELSE                  
 BEGIN                  
  INSERT INTO @tbluser                  
  EXEC Use_GetUserDetails @UserId                  
 END                  
                  
 DECLARE @TeamCode VARCHAR(10) = ''                  
 DECLARE @ScopeCode VARCHAR(10) = ''                  
 DECLARE @UserIdTeamLst nVARCHAR(max) = ''                  
 DECLARE @HierarchyJSON nVARCHAR(Max) = ''                  
                  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')                  
 FROM @tbluser                  
                  
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst        
        
        
        
 drop table if exists #source        
 SELECT sourceid,Name as SourceName        
    INTO #source          
 FROM usersourcesettings(NOLOCK) f          
   WHERE isactive = 1          
        AND UserID = @parentid          
           
 DECLARE @listtopivot NVARCHAR(max)          
  ,@sql NVARCHAR(max) , @ListPivotSelect nvarchar(max) -- = ''           
          
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + SourceName + ']'          
 FROM #source(NOLOCK)         
        
   print concat('columnName ' , cast(@listtopivot as varchar(max)))      
          
 SELECT @ListPivotSelect = coalesce( @ListPivotSelect +',','') + ' isnull(' + QUOTENAME(SourceName) + ',0) as '     
   + replace(Replace(replace(QUOTENAME(SourceName),' ',''),'-',''),'.','')         
    FROM #source(NOLOCK) --where FollowupStatus != ''       
      
--  SELECT @ListPivotSelect =  STRING_AGG( + ' cast(isnull(' + QUOTENAME(SourceName) + ',0) as nvarchar(max))  as ' + Replace(replace(SourceName,' ',''),'-',''),',')          
-- FROM #source(NOLOCK) --where FollowupStatus != ''        
      
   print concat('columnValue ' , cast(@ListPivotSelect as varchar(max)))      
      
      
 --where parentid=@parentid and IsActive=1  and isdisabled=0                            
 SELECT @sql = concat( N' select User_ID,UserByName ,User_Login, TotalAssigned, Pending, ' , @ListPivotSelect  , '   from (SELECT * FROM (        
   select    ul.User_ID, user_login,f.sourcename,dbo.fn_userleadsassigned(ul.user_id) as TotalAssigned,         
   dbo.fn_userpendingfollowup(ul.user_id) Pending,        
   sum(case when l.sourcename=f.sourceid and followupdate<getdate() then 1 else 0 end) as Count              
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                               
   from userleads(nolock) l                             
   join user_detail(nolock) ul on ul.User_ID=l.assignedto                            
   join #source(nolock) f on f.sourceID=l.sourcename
   left join prohibitedcharacters p on f.sourcename like ''%''+p.charactersymbol+''%'' and p.charactersymbol<>''%''
   where l.parentid=' , cast(@parentid AS NVARCHAR) , ' and         
   cast(createdon as date) between ''' , cast(@fromdate AS NVARCHAR) , ''' and ''' , cast(@todate AS NVARCHAR) , '''                    
   and p.id is null
   and (ul.User_ID in        
     (case when ''' , CAST(@IsAdmin AS NVARCHAR) , ''' = ''1'' then ul.User_ID        
     end        
    )     
     or                     
     ul.User_ID in ((select * from STRING_SPLIT(''' , isnull(                  
       @UserIdTeamLst, '') , ''', '','')))          
    )                    
   group by ul.User_ID,user_login,f.sourcename,ul.FName,ul.LName      )                           
   sourcewiseleads                            
   PIVOT (                          
   SUM([Count])                                  
   FOR [sourcename]                                  
   IN ( ' , cast(@listtopivot as nvarchar(max) ), '                          
   ))                         
    AS PivotTable      
   ) as tblSelectAlias ' ,'')           
          
   PRINT concat( 'Query: ' , cast( @sql as varchar(max)))         
         
   --declare @Query nvarchar(max) = ''      
   -- select @Query =  concat(@Query, cast( @sql as varchar(max)))         
      
    exec sp_executesql @sql        
       
       
   EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid                  
  ,@Activity_type = 'View_Rpt_Lead'                  
  ,@ActionType = 'S'                  
  ,@RowJson = ''                  
  ,@Table_name = 'Userleads and usersourcesetting'                  
         
   drop table if exists #source       
        
end 


GO

