/* ============================================================
   Procedure: [dbo].[Usp_getStages_withDeal_byPipelineID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.Usp_getStages_withDeal_byPipelineID
(
  @PipelineID bigint
)
as
Begin

    select distinct PipeLineStage,Name from LeadPipelineMapping(nolock) as LPM
          join PipelineStages PS  on LPM.PipeLineStage = ps.ID 
          where LPM.PipelineID = @PipelineID order by LPM.PipeLineStage

end


