/* ============================================================
   Procedure: [dbo].[usp_GetStateFromLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--- exec usp_GetStateFromLead 40204  
CREATE   PROCEDURE [dbo].[usp_GetStateFromLead] --41475 --335              
(@ParentID BIGINT)          
AS          
BEGIN          
 SELECT DISTINCT
      rtrim(ltrim(isnull(REPLACE(REPLACE([STATE], CHAR(13), ''), CHAR(10), ''),'')))
	  --isnull(STATE,'') 
      as [STATE]      
 FROM   UserLeads  with(nolock)          
 WHERE  ParentID = @ParentID       
       and isnull(STATE,'') != '-- Select State --'    
       and isnull(STATE,'') != 'Select State'      
    and trim(isnull(STATE,'')) != ''  
 order by 1  
END   


GO

