/* ============================================================
   Procedure: [dbo].[usp_getsubscribersusage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_getsubscribersusage]  --'1,335'            
(@user_id nvarchar(max)=null,              
@start nvarchar(20)=null,              
@end nvarchar(20)=null              
)              
as              
begin            
--declare @user_id nvarchar(max)  ='1,335'            
set @start=convert(date,coalesce(@start,'01/01/1980'),104)              
set @end=convert(date,coalesce(@end,dateadd(d,1,getdate())),104)             
set @user_id =coalesce(@user_id,'0')             
              
select u.user_login as Kit19UserLogin,              
TotalUsers,              
ul.lastlogin,ul.parentid               
into #user              
from user_detail(nolock) u               
join (select max(isnull(Lastlogin1,datecreated)) as LastLogin,count(parentid) TotalUsers,parentid  from user_detail(nolock) u group by parentid              
) ul on ul.ParentID=u.user_id              
where u.User_ID=u.parentid              
and u.parentid in  (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.user_login,ul.TotalUsers,ul.parentid,              
ul.lastlogin               
order by TotalUsers desc              
              
              
select isnull(sum(totalconsumption),0) SMS ,u.parentid, case when sum(totalconsumption) is null then 0 when datediff(d,max(dc.date),getdate()) >30 then 1 when datediff(d,max(dc.date),getdate()) between 16 and 30 then 2 else 3 end as SMSActive             
  
   
into #sms              
from user_detail(nolock) u               
left join dailyconsumption dc on dc.User_id=u.user_id              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))               
group by u.ParentID              
order by sum(totalconsumption) desc              
              
              
select isnull(sum(totalmailconsumption),0) Mail ,u.parentid, case when sum(totalmailconsumption) is null then 0 when datediff(d,max(dc.date),getdate()) >30 then 1 when datediff(d,max(dc.date),getdate()) between 16 and 30 then 2 else 3 end as MailActive   
  
    
      
        
          
            
             
into #mail              
from user_detail(nolock) u               
left join dailymailconsumption dc on dc.User_id=u.user_id              
where  u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID              
order by sum(totalmailconsumption) desc              
              
select isnull(sum(case when dc.FromUser_ID=dc.user_id and dc.typecredit=1 then debits else 0 end),0) Voice,u.parentid               
,case when sum(case when dc.FromUser_ID=dc.user_id and dc.typecredit=1 then debits else 0 end) =0 then 0 when datediff(d,max(dc.DateCreated),getdate()) >30 then 1 when datediff(d,max(dc.DateCreated),getdate()) between 16 and 30 then 2 else 3 end          
 
as VoiceActive              
into #Voice              
from user_detail(nolock) u               
left join IntCredit_Details dc on dc.User_id=u.user_id              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID              
order by sum(debits) desc              
              
/*0=Credit Added,1=Voice,8=Phoneno,5=landingpage,7=users,6=webform*/              
/*Considering 2 for Google adwords*/              
select isnull(sum(case when dc.FromUser_ID=dc.user_id and dc.typecredit=4 then debits else 0 end),0) Adwords,u.parentid               
,case when sum(case when dc.FromUser_ID=dc.user_id and dc.typecredit=4 then debits else 0 end) =0 then 0 when datediff(d,max(dc.DateCreated),getdate()) >30 then 1 when datediff(d,max(dc.DateCreated),getdate()) between 16 and 30 then 2 else 3 end          
 
as AdwordsActive              
into #Adwords              
from user_detail(nolock) u               
left join IntCredit_Details dc on dc.User_id=u.user_id              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID              
order by sum(debits) desc              
              
select parentid,count(Parentid) as MailsForwarded                
into #mailsforwarded              
from UserMailbox u              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by parentid              
              
              
select u.parentid,isnull(ParsedEnquiries,0) ParsedEnquiries ,isnull(ParsingActive,0) ParsingActive    
into #enqqsparsed    
from user_detail u  (nolock)    
left join(select parentid,     
count(p.Parentid) as ParsedEnquiries, case when p.parentid is null then 0 when datediff(d,max(p.Createddate),getdate()) >30 then 1 when datediff(d,max(p.Createddate),getdate()) between 16 and 30 then 2 else 3 end as ParsingActive     from ParsedEnquiries 
  
p(nolock) group by p.parentid) P on u.parentid=p.parentid            
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))            
group by u.parentid,ParsedEnquiries,ParsingActive    
    
              
              
select distinct u.parentid,case when j.jdparentid is null then 0 end as JDAPI,case when j.jdparentid is null then 0 when datediff(d,max(p.datereceived),getdate()) >30 then 1 when datediff(d,max(p.datereceived),getdate()) between 16 and 30 then 2 else 3   
  
    
      
        
end as JDActive               
into #jdapi              
from JDMapping J  (nolock)              
right join user_detail u (nolock) On u.user_id=j.kit19parentid              
left join JustdialLeads p (nolock) On p.jdparentid=j.jdparentid              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
--where p.enquirysource ='Just Dial API'               
group by u.parentid,j.jdparentid               
              
select u.parentid,case when j.kit19parentid is null then 0 end as IndiamartAPI,case when j.kit19parentid is null then 0 when datediff(d,max(p.datereceived),getdate()) >30 then 1 when datediff(d,max(p.datereceived),getdate()) between 16 and 30 then 2 else 
  
3 end as IndiamartActive               
into #indiamartapi              
from IndiamartMapping J  (nolock)              
right join user_detail u (nolock)On u.user_id=j.kit19parentid              
left join IndiamartLeads p (nolock) On p.indiamartkey=j.indiamartid              
--where p.enquirysource ='Just Dial API'               
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.parentid,j.kit19parentid               
              
select u.parentid,case when j.kit19parentid is null then 0 end as SulekhaAPI,case when j.kit19parentid is null then 0 when datediff(d,max(p.insertdate),getdate()) >30 then 1 when datediff(d,max(p.insertdate),getdate()) between 16 and 30 then 2 else 3 end 
  
    
      
        
          
            
as SulekhaActive               
into #sulekhaapi              
from SulekhaMapping J  (nolock)              
right join user_detail u (nolock) On u.user_id=j.kit19parentid              
left join SulekhaLeads p (nolock) On p.sul_customer=j.sulekhaid              
--where p.enquirysource ='Just Dial API'               
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.parentid,j.kit19parentid               
              
              
select u.Parentid,isnull(Enquiries,0) Enquiries,isnull(EnquiriesActive,0) EnquiriesActive              
into #enquiries              
from user_detail u (nolock)              
left join              
(select parentid,COUNT(parentid) Enquiries,case when datediff(d,max(e.CreatedDate),getdate()) >30 then 1 when datediff(d,max(e.CreatedDate),getdate()) between 16 and 30 then 2 else 3 end as EnquiriesActive from userenquiry(nolock) e group by parentid)    
  
    
      
        
          
           
e on e.ParentID=u.parentid              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID,Enquiries,EnquiriesActive--,e.CreatedDate              
order by parentid              
              
              
select u.Parentid,case when e.parentid is null then 0  else Leads end Leads,case when e.parentid is null then 0  else LeadsActive end LeadsActive              
into #leads              
from user_detail u (nolock) left join              
(select parentid,COUNT(e.parentid) Leads,case when datediff(d,max(e.CreatedOn),getdate()) >30 then 1 when datediff(d,max(e.CreatedOn),getdate()) between 16 and 30 then 2 else 3 end as LeadsActive              
from userleads(nolock) e group by e.ParentID) e           
on e.ParentID=u.parentid               
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID, Leads,LeadsActive,e.parentid--,e.CreatedDate              
              
              
              
select u.Parentid,isnull(Followups,0) Followups, isnull(LeadsActive,0) LeadsActive              
into #Followups              
from user_detail u(nolock)               
left join              
(select e.parentid,isnull(Followups,0) followups,isnull(LeadsActive,0) LeadsActive from      
userleads(nolock) e left join       
(select i.parentid,count(i.parentid) followups,case when datediff(d,max(i.CreatedOn),getdate()) >30 then 1 when datediff(d,max(i.CreatedOn),getdate()) between 16 and 30 then 2
 else 3 end as LeadsActive from LeadInteractionHistory i(nolock) group by i.parentid) i       
on i.parentid=e.parentid         
group by e.ParentID,followups,leadsactive) i              
on i.ParentID=u.parentid               
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID,Followups,LeadsActive                  
              
              
              
                
select u.parentid,isnull(EventCampaigns,0) EventCampaigns,isnull(ScheduledCampaigns,0) ScheduledCampaigns,isnull(EventActive,0) EventActive,isnull(ScheduleActive,0) ScheduleActive               
into #campaigns              
from               
user_detail(nolock) u              
left join (select ParentID              
,COUNT(parentid) EventCampaigns              
,case              
when datediff(d,max(c.ExecutedDateTime),getdate())>30 then 1               
when datediff(d,max(c.ExecutedDateTime),getdate()) between 16 and 30 then 2               
when datediff(d,max(c.ExecutedDateTime),getdate()) <16 then 3 end as EventActive              
from UserCampaignMaster c(nolock) where c.IsEventBased=1 group by c.parentid) c on u.parentid=c.parentid              
left join              
(select ParentID              
,COUNT(parentid) ScheduledCampaigns              
,case              
when datediff(d,max(c.ExecutedDateTime),getdate())>30 then 1               
when datediff(d,max(c.ExecutedDateTime),getdate()) between 16 and 30 then 2               
when datediff(d,max(c.ExecutedDateTime),getdate()) <16 then 3 end as ScheduleActive              
from UserCampaignMaster c(nolock) where c.Isscheduled=1 group by c.parentid) uc on u.parentid=uc.parentid              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID,EventCampaigns,ScheduledCampaigns,EventActive,ScheduleActive              
              
              
              
select u.parentid,isnull(LandingPages,0) LandingPages,isnull(LandingPagesActive,0) LandingPagesActive              
into #landingPages              
from user_detail(nolock) u               
left join               
(select user_id,COUNT(user_id) LandingPages,isnull(max(LandingPagesActive),0)  as LandingPagesActive               
from ClientPageDetail (nolock) c               
left join (select cname,case when datediff(d,max(l.datecreated),getdate())>30 then 1               
when datediff(d,max(l.datecreated),getdate()) between 16 and 30 then 2               
when datediff(d,max(l.datecreated),getdate()) <16 then 3 end as LandingPagesActive              
from ClientLeadDetails l group by cname) l on l.cname=right(c.pagename,len(c.pagename)-charindex('/',pagename,1))              
group by c.User_ID) ce              
on ce.user_id=u.parentid              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.parentid,LandingPages,LandingPagesActive              
              
              
select u.parentid,isnull(WebForms,0) WebForms,isnull(WebFormActives,0) WebFormActives              
into #webforms              
from user_detail(nolock) u               
left join (select Parentid,count(parentid) WebForms              
,case when MAX(maxentrydate) is null then 0               
when DATEDIFF(d,MAX(maxentrydate),getdate()) >30 then 1               
when DATEDIFF(d,MAX(maxentrydate),getdate())between 16 and 30 then 2 else 3 end WebFormActives from UserWebForms w (nolock)               
left join (select formid,MAX(entrydate) MaxEntryDate from WebEntryTbl w group by formid) wf              
on wf.formid=w.ID group by w.ParentID) w on u.parentid=w.ParentID              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.parentid,WebForms,WebFormActives              
              
              
select u.parentid,case when domain is null then 0 else 1 end EshopActives,sum(Products) Products,isnull(OrderActive ,0) OrderActive,Orders              
into #orders              
from user_detail(nolock) u              
left join               
(select distinct parentid Domain from UserCartSettings with (nolock)) c on c.domain=u.parentid              
left join               
(select user_id,count(User_ID) Products from Products with (nolock) group by user_id) p on p.user_id=u.user_id              
left join               
(select Parentid,count(parentid) Orders,case when DATEDIFF(d,max(o.CreatedOn),getdate()) >30 then 1 when DATEDIFF(d,max(o.CreatedOn),getdate())between 16 and 30 then 2 else 3 end OrderActive from UserOrders o with (nolock) group by parentid) o on o.parentid=u.parentid 
  
    
     
         
          
            
             
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by Domain,u.parentid,OrderActive,Orders              
              
              
select u.parentid,case when virtual_domain is null then 0 else 1 end as TicketPortalActive,isnull(TicketCustomers,0) TicketCustomers,Tickets,TicketActive              
into #tickets              
from user_detail(nolock) u              
left join               
(select virtual_domain,Parentid from serv_user_domain) c on c.parentid=u.parentid              
left join               
(select Parentid,SUM(case when isnull(kit19_id,0)<>0 then 1 else 0 end) TicketCustomers from serv_user_master group by parentid) p on p.parentid=u.parentid              
left join               
(select parentid,count(parentid) Tickets,case when DATEDIFF(d,max(update_date),getdate()) >30 then 1 when DATEDIFF(d,max(update_date),getdate())between 16 and 30 then 2 else 3 end TicketActive from Serv_TicketMaster group by parentid) o           
on o.parentid=u.parentid              
--where u.ParentID=335              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by virtual_domain,u.parentid,TicketCustomers,Tickets,TicketActive              
              
              
select u.parentid,0 as IVRMObile,isnull(IVRLandline,0) IVRLandline,isnull(IVRIncoming,0) IVRIncoming,isnull(IVRIncomingActive,0) IVRIncomingActive,isnull(IVROutgoing,0) IVROutgoing,ISNULL(IVROutgoingActive,0) IVROutgoingActive              
into #ivr              
from user_detail (nolock) u               
left join               
(select parentid,sum(case when c.Active=1 then 1 else 0 end) IVRLandline from Cloud_user_phone c group by parentid) c on u.parentid=c.Parentid              
left join               
(select k.clientid,case when IVRIncoming IS null then 0 else IVRIncoming end as IVRIncoming              
,isnull(Maxdate,0) IVRIncomingActive              
,case when IVROutgoing IS null then 0 else IVROutgoing end as IVROutgoing              
,isnull(oMaxdate,0) IVROutgoingActive              
from Kit19Calls k              
left join              
(select clientid,COUNT(clientid) IVRIncoming,case when MAX(call_start_time)              
IS null then 0 when DATEDIFF(d,MAX(call_start_time),getdate())>30 then 1              
 when DATEDIFF(d,MAX(call_start_time),getdate()) between 16 and 30 then 2 else 3 end Maxdate              
from Kit19Calls where CONTEXT in ('inbound','inbound1','incoming','internal') group by clientid) kc on kc.clientid=k.clientid              
left join              
(select clientid,COUNT(clientid) IVROutgoing,case when MAX(call_start_time)              
IS null then 0 when DATEDIFF(d,MAX(call_start_time),getdate())>30 then 1              
 when DATEDIFF(d,MAX(call_start_time),getdate()) between 16 and 30 then 2 else 3 end oMaxdate              
from Kit19Calls where CONTEXT in ('outbound','outbound-user') group by clientid) kco on kco.clientid=k.clientid              
--where k.clientid=335              
 group by k.clientid,IVRIncoming,Maxdate              
,IVROutgoing,oMaxdate) k on k.clientid=u.parentid              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
group by u.ParentID,IVRIncoming,IVRIncomingActive,IVROutgoing              
,IVROutgoingActive,IVRLandline              
              
              
          
truncate table kit19usage              
--select count(1) from user_detail              
insert into kit19usage          
select distinct u.parentid,Kit19UserLogin,TotalUsers,lastlogin              
,SMS,SMSActive              
,Mail,MailActive              
,Voice,VoiceActive              
,Adwords,AdwordsActive              
,isnull(MailsForwarded,0) MailsForwarded              
,JDAPI,j.JDActive JDAPIActive              
,e.ParsedEnquiries Parsing,ParsingActive              
,i.IndiamartActive IndiamartAPIActive,IndiamartAPI              
,SulekhaAPI,su.SulekhaActive SulekhaAPIActive              
,Enquiries,EnquiriesActive--Culprit              
,Leads,le.LeadsActive               
,FollowUps,f.LeadsActive FollowUpsActive              
,c.EventCampaigns EventBasedCampaigns,EventActive,c.ScheduledCampaigns ScheduleBasedCampaigns,ScheduleActive              
,LandingPages,LandingPagesActive              
,WebForms,w.WebFormActives WebFormsActive              
,o.EshopActives EshopActive,o.Products Product,Orders,OrderActive              
,TicketPortalActive,TicketCustomers,Tickets,TicketActive              
,IVRMobile,IVRLandline,IVRIncoming,IVRIncomingActive,IVROutgoing,IVROutgoingActive              
,0 as IssuesTotal, 0 as IssuesOpen              
from #user u              
left join #Adwords a on u.ParentID=a.ParentID              
left join #Followups f on f.ParentID=u.ParentID              
left join #Voice v on v.ParentID=u.ParentID              
left join #enqqsparsed e on e.ParentID=u.ParentID              
left join #enquiries en on en.ParentID=u.ParentID              
left join #indiamartapi i on i.ParentID=u.ParentID              
left join #ivr iv on iv.ParentID=u.ParentID              
left join #jdapi j on j.ParentID=u.ParentID              
left join #landingPages l on l.ParentID=u.ParentID              
left join #leads le on le.ParentID=u.ParentID              
left join #mail m on m.ParentID=u.ParentID              
left join #mailsforwarded mf on mf.ParentID=u.ParentID              
left join #orders o on o.ParentID=u.ParentID              
left join #sms s on s.ParentID=u.parentid               
left join #sulekhaapi su on su.ParentID=u.ParentID              
left join #tickets t on t.ParentID=u.ParentID              
left join #webforms w on w.ParentID=u.parentid              
left join #campaigns c on c.ParentID=u.ParentID              
where u.parentid in (select case when @user_id='0' then (select u.parentid) else value end from dbo.fn_split(@user_id,','))              
order by u.ParentID              
              
              
drop table #Adwords              
drop table #Followups              
drop table #Voice              
drop table #campaigns              
drop table #enqqsparsed              
drop table #enquiries              
drop table #indiamartapi              
drop table #ivr              
drop table #jdapi              
drop table #landingPages              
drop table #mail              
drop table #leads              
drop table #mailsforwarded              
drop table #orders              
drop table #sms              
drop table #sulekhaapi              
drop table #tickets              
drop table #user              
drop table #webforms               
              
end      
      
      
    




