/* ============================================================
   Procedure: [dbo].[usp_GetSubscriptionAndUserActivityWithPagination]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetSubscriptionAndUserActivityWithPagination] 
    @UserID BIGINT,
    @OffsetValue INT,
    @PagingSize INT,
    @Filter NVARCHAR(50) = NULL  -- Single filter parameter for ActivityType or Date
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        /*DECLARE 
            @UserID BIGINT = 32222,
            @OffsetValue INT = 0,
            @PagingSize INT = 20,
            @Filter NVARCHAR(50) = NULL;*/

        DECLARE @parentid BIGINT;
        SELECT @parentid = ParentID FROM User_Detail (NOLOCK) WHERE User_ID = @UserID;

        -- Calculate Total Rows
        DECLARE @TotalRows INT;
        SELECT @TotalRows = (
            -- Total Row Count for User Activity
            SELECT COUNT(1)
            FROM tbl_pt_AllowUserTransactions (NOLOCK)
            WHERE 
                UserId = @parentid
                AND IsActive = 1
                AND (
                    @Filter IS NULL 
                    OR 'UserAdded' = @Filter  -- Match ActivityType
                    OR CAST(CreatedOn AS NVARCHAR(50)) = @Filter  -- Match Date
                )
        ) + (
            -- Total Row Count for Subscription Details
            SELECT COUNT(1)
            FROM (
                SELECT *,
                    ROW_NUMBER() OVER (PARTITION BY IsTrailPlan ORDER BY Created_Date ASC) AS TrailRank
                FROM 
                    Price_UserSubscriptionDetails (NOLOCK)
                WHERE 
                    UserID = @parentid
            ) AS FilteredSubscriptions
            WHERE 
                (IsTrailPlan = 0 OR TrailRank = 1)  -- Exclude subsequent 'IsTrailPlan = 1' rows
                AND (
                    @Filter IS NULL 
                    OR ('Subscription/Trial' = @Filter AND TrailRank = 1)  
                    OR ('Renewal' = @Filter AND IsTrailPlan = 0)  
                    OR CAST(Created_Date AS NVARCHAR(50)) = @Filter  
                )
        );

        -- Select combined results with pagination
        SELECT 
            [Date],
            ActivityType,
            Details,
            @TotalRows AS TotalRows,
            RowNum
        FROM (
            -- User Activity (User Added)
            SELECT 
                CreatedOn AS [Date],
                'UserAdded' AS ActivityType,
                CONCAT('User Added Count: ', SUM(UserAdded)) AS Details,
                ROW_NUMBER() OVER (ORDER BY CreatedOn DESC) AS RowNum
            FROM 
                tbl_pt_AllowUserTransactions (NOLOCK)
            WHERE 
                UserId = @parentid
                AND IsActive = 1
                AND (
                    @Filter IS NULL 
                    OR 'UserAdded' = @Filter  -- Match ActivityType
                    OR CAST(CreatedOn AS NVARCHAR(50)) = @Filter  -- Match Date
                )
            GROUP BY 
                CreatedOn

            UNION ALL

            -- Subscription Details
            SELECT 
                Created_Date AS [Date],
                CASE 
                    WHEN IsTrailPlan = 1 THEN 'Subscription/Trial'
                    WHEN IsTrailPlan = 0 THEN 'Renewal'
                    ELSE 'Regular'
                END AS ActivityType,
                CONCAT('Date: ', FORMAT(PlanStartDate, 'dd/MM/yyyy'), ' - ', FORMAT(PlanEndDate, 'dd/MM/yyyy')) AS Details,
                ROW_NUMBER() OVER (ORDER BY Created_Date DESC) AS RowNum
            FROM (
                SELECT *, 
                    ROW_NUMBER() OVER (PARTITION BY IsTrailPlan ORDER BY Created_Date ASC) AS TrailRank
                FROM 
                    Price_UserSubscriptionDetails (NOLOCK)
                WHERE 
                    UserID = @parentid
            ) AS FilteredSubscriptions
            WHERE 
                (IsTrailPlan = 0 OR TrailRank = 1)  -- Exclude subsequent 'IsTrailPlan = 1' rows
                AND (
                    @Filter IS NULL 
                    OR ('Subscription/Trial' = @Filter AND TrailRank = 1)  
                    OR ('Renewal' = @Filter AND IsTrailPlan = 0)  
                    OR CAST(Created_Date AS NVARCHAR(50)) = @Filter  
                )
        ) AS CombinedResults
        WHERE RowNum BETWEEN @OffsetValue + 1 AND @OffsetValue + @PagingSize
        ORDER BY [Date] DESC;

    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END





GO

/* ============================================================
   Procedure: [dbo].[usp_GetSubscriptionStatsByUserID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetSubscriptionStatsByUserID]
    @UserID INT
AS
BEGIN

    SET NOCOUNT ON;

    -- Get the current date and time
    DECLARE @CurrentDateTime DATETIME = GETDATE();
    DECLARE @FirstOfMonth DATE = DATEADD(MONTH, DATEDIFF(MONTH, 0, @CurrentDateTime), 0);
    DECLARE @LastOfMonth DATE = EOMONTH(@CurrentDateTime);

    BEGIN TRY
        -- Count of active subscriptions as of the current date for the given UserID
        DECLARE @ActiveSubscriptions INT = (
            SELECT COUNT(*)
            FROM Price_UserSubscriptionDetails
            WHERE 
                @CurrentDateTime BETWEEN PlanStartDate AND PlanEndDate
                AND UserID = @UserID
        );

        -- Count of subscriptions expiring in the current month for the given UserID
        DECLARE @ExpiringSubscriptions INT = (
            SELECT COUNT(*)
            FROM Price_UserSubscriptionDetails
            WHERE 
                PlanEndDate BETWEEN @FirstOfMonth AND @LastOfMonth
                AND UserID = @UserID
        );

        -- Count of new subscriptions added in the current month for the given UserID
        DECLARE @NewSubscriptions INT = (
            SELECT COUNT(*)
            FROM Price_UserSubscriptionDetails
            WHERE 
                created_date BETWEEN @FirstOfMonth AND @LastOfMonth
                AND UserID = @UserID
        );

        -- Output the results
        SELECT 
            @ActiveSubscriptions AS ActiveSubscriptions,
            @ExpiringSubscriptions AS ExpiringSubscriptions,
            @NewSubscriptions AS NewSubscriptions;
    END TRY
    BEGIN CATCH
        -- Handle errors
        EXEC usp_InsertErrorInfo;
    END CATCH
END;
----------------------------------------------------------------------------------




GO

/* ============================================================
   Procedure: [dbo].[usp_GetSubscriptionStatsByUserID_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetSubscriptionStatsByUserID_new]-----latest running
    @UserID INT
AS
BEGIN
    SET NOCOUNT ON;

    -- Declare variables
    DECLARE @CurrentDateTime DATETIME = GETDATE();
    DECLARE @FirstOfMonth DATE = DATEADD(MONTH, DATEDIFF(MONTH, 0, @CurrentDateTime), 0);
    DECLARE @LastOfMonth DATE = EOMONTH(@CurrentDateTime);
    DECLARE @MID INT;

    BEGIN TRY
        -- Step 1: Get the MID for the given UserID from the ResellerDetail table
        SELECT @MID = reseller_id
        FROM reseller_detail (nolock)
        WHERE User_ID = @UserID;

        IF @MID IS NULL
        BEGIN
            THROW 50000, 'No MID found for the provided UserID.', 1;
        END

        -- Step 2: Retrieve all UserIDs associated with the MID from the User_Detail table
        DECLARE @UserIDs TABLE (UserID bigint);

        INSERT INTO @UserIDs (UserID)
        SELECT User_ID
        FROM User_Detail (nolock)
        WHERE M_ID = @MID;

        -- Step 3: Calculate subscription statistics for each UserID in the @UserIDs table
        -- Count of active subscriptions as of the current date for the given UserIDs
        DECLARE @ActiveSubscriptions INT = (
            SELECT COUNT(*)
            FROM Price_UserSubscriptionDetails AS PUSD
            INNER JOIN @UserIDs AS UID ON PUSD.UserID = UID.UserID
            WHERE @CurrentDateTime BETWEEN PlanStartDate AND PlanEndDate
        );

        -- Count of subscriptions expiring in the current month for the given UserIDs
        DECLARE @ExpiringSubscriptions INT = (
            SELECT COUNT(*)
            FROM Price_UserSubscriptionDetails AS PUSD
            INNER JOIN @UserIDs AS UID ON PUSD.UserID = UID.UserID
            WHERE PlanEndDate BETWEEN @FirstOfMonth AND @LastOfMonth
        );

        -- Count of new subscriptions added in the current month for the given UserIDs
        DECLARE @NewSubscriptions INT = (
            SELECT COUNT(*)
            FROM Price_UserSubscriptionDetails AS PUSD
            INNER JOIN @UserIDs AS UID ON PUSD.UserID = UID.UserID
            WHERE created_date BETWEEN @FirstOfMonth AND @LastOfMonth
        );

        -- Output the results
        SELECT 
            @ActiveSubscriptions AS ActiveSubscriptions,
            @ExpiringSubscriptions AS ExpiringSubscriptions,
            @NewSubscriptions AS NewSubscriptions;
    END TRY
    BEGIN CATCH
        -- Handle errors
        EXEC usp_InsertErrorInfo;
    END CATCH
END;


-----------------------------------------------------------------------------------



GO

