CREATE   PROCEDURE dbo.usp_GetSuperResellerBalanceCheck      
(      
     
@FromUserID int,      
@ToUserID int,      
@Credits  bigint,      
@Debits bigint      
      
)      
as      
Begin      
Declare @SMSBalance bigint = 0;      
Declare @MID bigint = 0;      
      
select @MID = isnull(m_id,0) from User_Detail where [user_id]=@ToUserID        
       
select top 1 @SMSBalance = isnull(Balance,0) from SuperResellerCredit_Details where USER_ID = @ToUserID order by Credit_ID     desc       
    
    if(@Credits>0)  
      Begin  
            select 'ValidBalance'  
      End      
        
      if(@Debits>0)  
        Begin  
               if(@Debits<=@SMSBalance)  
                  Begin  
                      select 'ValidBalance'  
                  End  
               else if(@Debits > @SMSBalance)  
                   Begin  
                      select 'LowBalance'  
                   End     
        End        
        
        
--set @SMSBalance = @SMSBalance + @Credits      
--set @SMSBalance = @SMSBalance - @Debits      
      
      
      
End  
  




GO

