/* ============================================================
   Procedure: [dbo].[usp_GetTagsByParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetTagsByParentID] --34594
    @ParentID BIGINT = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- Check if ParentID is provided, fetch tags accordingly
    IF @ParentID IS NOT NULL
    BEGIN
        SELECT 
            ID,
            Tag,
            ParentID,
            CreatedDate,
            CreatedBy,
            IsActive
        FROM 
            [dbo].[TagMaster] (nolock)
        WHERE 
            ParentID = @ParentID
            AND IsActive = 1;
    END
    ELSE
    BEGIN
        -- If ParentID is not provided, fetch all active tags without parent filtering
        SELECT 
            ID,
            Tag,
            ParentID,
            CreatedDate,
            CreatedBy,
            IsActive
        FROM 
            [dbo].[TagMaster] (nolock)
        WHERE 
            IsActive = 1;
    END
END
--GO





