/* ============================================================
   Procedure: [dbo].[usp_gettaskappointmentreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_gettaskappointmentreport
@userid BIGINT
	,@parentid BIGINT
	,@fromdate DATE
	,@todate DATE
as
begin

select user_login as Executive,cast(t.enddate as date) as DueDate,count(1) TotalAssigned,sum(case when t.Status='completed' then 1 else 0 end)
as Completed,sum(case when t.status='Open' then 1 else 0 end) as [Open] 
from [dbo].[tbl_tsk_TaskHistory] t with (nolock) join user_detail u with (nolock) on t.AssignedTo=u.User_ID
where u.parentid=@parentid and cast(t.enddate as date) BETWEEN @fromdate	AND @todate and istask=1
group by user_login,cast(t.enddate as date),t.Status

select user_login as Executive,cast(t.StartDate as date) as DueDate,count(1) TotalAssigned,sum(case when t.Status='completed' then 1 else 0 end)
as Completed,sum(case when t.status='Open' then 1 else 0 end) as [Open] 
from [dbo].[tbl_tsk_TaskHistory] t with (nolock) join user_detail u with (nolock) on t.AssignedTo=u.User_ID
where u.parentid=@parentid and cast(t.enddate as date) BETWEEN @fromdate	AND @todate and IsAppointment=1
group by user_login,cast(t.StartDate as date),t.Status

end


GO

