CREATE   PROCEDURE [dbo].[usp_GetTeam_By_Name] (    
 @Name varchar(150),      
 @UserID bigINT  
 )  
as                    
begin                 
                
begin try                
                
begin transaction                
  
--Declare @Name varchar(150) = 'anim'  
  DECLARE @ParentId BIGINT = 0;        
 SELECT @ParentId = ParentID FROM User_Detail(nolock) WHERE User_ID = @UserId;                          
 Declare @IsAdmin bit = 0              
        
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))        
 select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId        
 if(@IsAdmin = 1)        
 begin        
  set @UserId = 0;        
  insert into @tbluser        
  exec Use_GetUserDetails @ParentId        
 end        
 else        
 Begin        
  insert into @tbluser        
  exec Use_GetUserDetails @UserId        
 End        
           
 Declare @TeamCode varchar(10) = ''        
 Declare @ScopeCode varchar(10) = ''         
 Declare @UserIdTeamLst varchar(Max) = ''         
 Declare @UserLoginTeamLst varchar(Max) = ''         
        
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)         
-- select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser        
   
select distinct p.TeamCode, p.TeamName from TBL_UA_TeamMaster p(nolock)
inner join User_Detail ud on p.ParentId = ud.ParentId
inner join TBL_UA_TeamUserMappingMaster ttu on ud.User_ID = ttu.UserID
 WHERE  ttu.UserID in (select User_ID From @tbluser) and TeamName like '%'+ @Name +'%'  

 commit transaction                
                
end try                
begin catch                
 declare @errormessage nvarchar(max) = ( SELECT ERROR_NUMBER() AS ErrorNumber, ERROR_SEVERITY() AS ErrorSeverity, ERROR_STATE() AS ErrorState, ERROR_PROCEDURE() AS ErrorProcedure, ERROR_LINE() AS ErrorLine, ERROR_MESSAGE() AS ErrorMessage for json path)  
  
      
 print @errormessage                
 rollback transaction                
end catch                
                
end  



GO

