  Begin      
    --Declare @GroupID Bigint = 22;      
   Select UMT.Name + ':('+ CAST(UGTM.OrderNo as varchar)+')'+ CASE WHEN UMT.IsMail=1 THEN '('+UMT.MailSubject+')' ELSE '' END as TMPLT ,cast(TemplateId as varchar)+':'+cast(OrderNo as varchar) as IDAndOrderNo from UserGroupTemplateMix as UGTM(nolock)      
