CREATE   PROCEDURE dbo.usp_getTemplateGroups --335,14  
(  
 @ParentID BIGINT,    
 @TemplateID BIGINT  
)      
 as  
  Begin   
      
  select ISNULL(Groups,'') as Groups  from (select  stuff(  
                (   select  '#' + cast (GroupID as nvarchar(50))  
                    from    UserGroupTemplateMix t1  
                    where   TemplateID = @TemplateID and ParentID = @ParentID   
                    for xml path('')  
