/* ============================================================
   Procedure: [dbo].[Usp_GetTicketsStatusForGraph_Kit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.Usp_GetTicketsStatusForGraph_Kit19 --233,335        
(        
@EnqNo bigint,        
@kit19UserID bigint        
        
)         
        
as        
        
Begin        
        
  Declare @DateCurrentTo date = null        
  Declare @Status nvarchar(50) = 'Red'  
        
   CREATE TABLE #TempLinked                                          
    (                                          
      Result VARCHAR(200)                                          
    )                 
                            
     INSERT INTO #TempLinked                                          
     EXEC GetStatusofLinkedServer 'CRM'                                          
     IF NOT EXISTS(                                          
        SELECT 'x'                                          
        FROM   #TempLinked                                          
    )                               
    begin           
        
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID         
 and Stage = 'Customer Accepted Setup Request'          
         
 --for temp        
          
   -- Declare @DateCurrentTo date = null        
      
 --set @DateCurrentTo = '2019-01-01 21:08:03.167'        
      
  
  
  if(exists  
    (  
      select 1 from Support_Detail where User_ID = @kit19UserID    
    )  
  )  
  Begin  
      if(exists  
      (  
       select 1 from Serv_User_Detail where ParentId = @kit19UserID    
      )  
    )  
      Begin  
          
     declare @TicketsCount int = 0  
     declare @ResolvedTicketsCount int = 0  
  
     select @TicketsCount = Count(*)  From Serv_TicketMaster where ParentID = @kit19UserID and convert(date,Date_Created) > = convert(date,@DateCurrentTo)  
       
     select @ResolvedTicketsCount = Count(*)  From Serv_TicketMaster where ParentID = @kit19UserID and convert(date,Date_Created) > = convert(date,@DateCurrentTo)  
     and  ISNULL(resolved_dt,'')<> '' and DATEDIFF(HOUR,Date_Created,resolved_dt ) <= 24 and Status = 2  
       
     declare @Resolvedprnctge int = 0;  
  
     set @Resolvedprnctge = ((@ResolvedTicketsCount)*(100))/(@TicketsCount)   
  
     --select @Resolvedprnctge,@ResolvedTicketsCount,@TicketsCount  
     if(@Resolvedprnctge >= 70)  
       Begin  
        set @Status = 'Green'  
    End  
  
  
  
   End  
  
       
  
  End       
        
   end        
        
  drop table  #TempLinked        
        
   select @Status as status  
  
        
End        
        




GO

