/* ============================================================
   Procedure: [dbo].[usp_GetTopUnprocessedSMSUrls]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetTopUnprocessedSMSUrls] AS BEGIN  SET NOCOUNT ON;                          
BEGIN TRY                          
                        
 DROP TABLE IF EXISTS #sms_api_urls                        
 SELECT TOP 5   id,   sms_url,   createdon,   isprocessed,   Response,   processedon                           
  INTO #sms_api_urls                       
  FROM dbo.sms_api_urls(nolock)  WHERE                   
 (   
 (isprocessed=0 and createdon < dateadd(SS,-5,getdate()) )   
 or  (isprocessed=2 and processedon<dateadd(mi,-1,getdate()) and isnull(response,'')<>'')  
 )                     
  and cast(createdon as date)= cast(getdate() as date)                   
  --and createdon < dateadd(mi,-5,getdate())                        
  --isprocessed=2 and processedon<dateadd(mi,-2,getdate())                        
  --(isprocessed = 0 or (isprocessed=2 and processedon<dateadd(mi,-2,getdate())) )                       
  --and id=0                      
  order by case when dbo.GetQueryStringValue(sms_url,'sender') ='KITAPP' then 0 else id end                     
                        
 update m set m.isprocessed = 2,processedon=getdate()  FROM sms_api_urls m                         
  inner join #sms_api_urls t on m.id = t.id                        
                        
 select * from #sms_api_urls -- id=0  ORDER BY id asc;                        
END TRY                          
  BEGIN CATCH  exec usp_InsertErrorInfo                          
END CATCH END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetTopUnprocessedSMSUrls_withconsolename]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetTopUnprocessedSMSUrls_withconsolename] 
@consolename nvarchar(100)  =null  
AS 
BEGIN  
SET NOCOUNT ON;                    
BEGIN TRY                    
set @consolename=coalesce(@consolename,'')      
                
 DROP TABLE IF EXISTS #sms_api_urls                  
 SELECT TOP 5   id,   sms_url,   createdon,   isprocessed,   Response,   processedon                     
  INTO #sms_api_urls                 
  FROM dbo.sms_api_urls(nolock)  WHERE             
 ( (isprocessed=0 and createdon < dateadd(SS,-5,getdate()) ) or  
 (isprocessed=2 and processedon<dateadd(mi,-2,getdate())))               
  and cast(createdon as date)= cast(getdate() as date)             
  --and createdon < dateadd(mi,-5,getdate())                  
  --isprocessed=2 and processedon<dateadd(mi,-2,getdate())                  
  --(isprocessed = 0 or (isprocessed=2 and processedon<dateadd(mi,-2,getdate())) )                 
  --and id=0                
  order by case when dbo.GetQueryStringValue(sms_url,'sender') ='KITAPP' then 0 else id  end
  
insert into trace_updatems(p_id,Status,Response,consolename)      
select id,2,null,@consolename from #sms_api_urls     

                  
 update m set m.isprocessed = 2,processedon=getdate(),  consolename=@consolename      
  FROM sms_api_urls m                   
  inner join #sms_api_urls t on m.id = t.id                  

                  
 select * from #sms_api_urls -- id=0  ORDER BY id asc;                  
END TRY                    
  BEGIN CATCH  exec usp_InsertErrorInfo                    
END CATCH 
END      
      
      


GO

