   Procedure: [dbo].[usp_GetTotalConsumptionByReseller]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetTotalConsumptionByReseller
    @m_id INT
AS
BEGIN
    -- Calculate total consumption for all users under a specific reseller
    SELECT 
        COALESCE(SUM(dc.TotalConsumption), 0) AS TotalConsumption
    FROM 
        User_Detail ud
        INNER JOIN Reseller_Detail rd 
            ON ud.M_ID = rd.M_ID 
            AND rd.m_id = @m_id
        LEFT JOIN DailyConsumption dc 
            ON dc.User_ID = ud.User_ID;
END;



