/* ============================================================
   Procedure: [dbo].[Usp_GetTotalTicketsForGraph_Kit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 CREATE   PROCEDURE dbo.Usp_GetTotalTicketsForGraph_Kit19 --233,335            
(            
@EnqNo bigint,            
@kit19UserID bigint            
            
)             
            
as            
            
Begin            
            
  Declare @DateCurrentTo date = null            
            
   CREATE TABLE #TempLinked                                              
    (                                              
      Result VARCHAR(200)                                              
    )                     
                                
     INSERT INTO #TempLinked                                              
     EXEC GetStatusofLinkedServer 'CRM'                                              
     IF NOT EXISTS(                                              
        SELECT 'x'                                              
        FROM   #TempLinked                                              
    )                                   
    begin               
            
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID             
 and Stage = 'Customer Accepted Setup Request'              
             
 --for temp            
              
 --Declare @DateCurrentTo date = null            
   -- set @DateCurrentTo = '2019-01-01 21:08:03.167'            
    select CONVERT(date,Date_Created) as Date,COUNT(CONVERT(date,Date_Created)) as Count into #t1 from Serv_TicketMaster where Status = 1 and ParentID = @kit19UserID and CONVERT(date,Date_Created) >= convert(date,@DateCurrentTo)      
 group by CONVERT(date,Date_Created) order by CONVERT(date,Date_Created) asc      
            
  select CONVERT(date,Date_Created) as Date,COUNT(CONVERT(date,Date_Created)) as Count into #t2  from Serv_TicketMaster where Status = 2 and ParentID = @kit19UserID and CONVERT(date,Date_Created) >= convert(date,@DateCurrentTo)      
 group by CONVERT(date,Date_Created)  order by CONVERT(date,Date_Created) asc      
            
    
 --   select * from    
 -- (    
 -- select Date,isnull(#t1.Count,0) as [Open] , 0 as Closed  From #t1     
 -- union    
 -- Select Date,0 as [Open] , isnull(#t2.Count,0) as Closed    From #t2 --on #t1.Date = #t2.Date    
     
 --) as tbl order by date asc    
            
  
 select tbl.Date as Date ,isnull(tbl.[Open],0) as [Open],isnull(tbl.Closed,0) as Closed from    
  (    
  select Date,isnull(#t1.Count,0) as [Open] ,(select ISNULL(#t2.Count,0) from #t2 where #t2.Date = #t1.date) as Closed  From #t1     
  union    
  Select Date,(select ISNULL(#t1.Count,0) from #t1 where #t1.Date = #t2.date) as [Open] , isnull(#t2.Count,0) as Closed    From #t2 --on #t1.Date = #t2.Date    
 ) as tbl order by date asc   
    
  
   end            
            
  drop table  #TempLinked      
  drop table #t1    
  drop table #t2                  
            
            
End 













GO

/* ============================================================
   Procedure: [dbo].[Usp_Gettp_GetTicketCountAndStatusOnDashBoard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
CREATE   PROCEDURE [dbo].[Usp_Gettp_GetTicketCountAndStatusOnDashBoard]

@UserId BIGINT

AS

BEGIN

	--DECLARE @UserId BIGINT = 39832;  -- remove when using parameter

	SET NOCOUNT ON;
 
	DECLARE @Tpuserid BIGINT, @Parentid BIGINT, @subdomain NVARCHAR(MAX);
 
	SELECT @Parentid = ParentId 

	FROM User_Detail (NOLOCK) 

	WHERE User_Id = @UserId;
 
	SELECT @Tpuserid = TpUser_Id 

	FROM tbl_tp_UserLogin (NOLOCK)

	WHERE User_Id = @UserId AND ParentId = @ParentId;
 
	SELECT @subdomain = PortalName 

	FROM tbl_Tp_PortalSetting (NOLOCK) 

	WHERE ParentId = @Parentid AND IsActive = 1;
 
	DROP TABLE IF EXISTS #tblTicketCountAndStatusOnDashBoard;
 
	CREATE TABLE #tblTicketCountAndStatusOnDashBoard 

	(

		TicketStatus VARCHAR(100),

		StatusCount INT,

		Type VARCHAR(100),

		Assigned VARCHAR(100) NULL   -- allow NULL for 3-column cases

	);
 
	BEGIN TRY

		-- Try inserting as if 4 columns exist

		INSERT INTO #tblTicketCountAndStatusOnDashBoard (TicketStatus, StatusCount, Type, Assigned)

		EXEC Usp_tp_GetTicketCountAndStatusOnDashBoard @Tpuserid;

	END TRY

	BEGIN CATCH

		-- If fails, insert only 3 columns

		INSERT INTO #tblTicketCountAndStatusOnDashBoard (TicketStatus, StatusCount, Type)

		EXEC Usp_tp_GetTicketCountAndStatusOnDashBoard @Tpuserid;

	END CATCH
 
	-- Final Dashboard Pivot

	SELECT  

		 [Close],

		 [Duplicate],

		 [InValid],

		 [New],

		 [Open],

		 [Pending],

		 [Resolved],

		 [Spam],

		 [Waiting On Customer],

		 [Waiting On Third Party],

		 [Unresolved],

		 [Total],

		 ISNULL(@subdomain,'') AS subdomain

	FROM

	(

		SELECT TicketStatus, StatusCount 

		FROM #tblTicketCountAndStatusOnDashBoard

	) AS SourceData

	PIVOT

	(

		MAX(StatusCount) FOR TicketStatus IN 

		([Close],[Duplicate],[InValid],[New],[Open],[Pending],[Resolved],[Spam],

		 [Waiting On Customer],[Waiting On Third Party],[Unresolved],[Total])

	) AS PivotData;
 
	DROP TABLE #tblTicketCountAndStatusOnDashBoard;

END




GO

/* ============================================================
   Procedure: [dbo].[usp_GetTranslateHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetTranslateHistory](
	@RefTableName nvarchar(255),
	@RefId bigint,
	@UserId bigint
)
as
begin

	--declare 
	--	@RefTableName nvarchar(255) = 'conversations',
	--	@RefId bigint = 18864445,
	--	@UserId bigint = 34594

	declare @ParentId bigint
	select @ParentId = dbo.ufn_GetUserParentId(@UserId)

	declare @resStatus nvarchar(25), @resCode int = 0, @resMessage nvarchar(255), @metaData nvarchar(max) = '{}'

	set @RefTableName = ( case isnull(@RefTableName, '')
		when 'conversations' then concat('tbl_conversations_', @ParentId)
		when 'calllog' then 'calllog'
		else '' end )

	select  
		id as [Id],
		json_value(detail_json, '$.TranslateTextRequest.Text') as [OriginalText],
		json_value(detail_json, '$.TranslatedText') as [TranslatedText],
		languageCode as [LanguageCode],
		createon as [CreatedOn]
	from tbl_translation_deduction with (nolock) 
		where refTableName = @RefTableName and refTableId = @RefId order by id desc

end



GO

/* ============================================================
   Procedure: [dbo].[usp_GetTranslationDeductionHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetTranslationDeductionHistory (
	@language nvarchar(10) = '',
	@term nvarchar(255) = '',
	@fromdate datetime = '',
	@todate datetime = '',
	@UserId bigint = 0,
	@Offsets int = 0,
	@PageSize int = 10
)
as
begin
	--declare 
	--	@language nvarchar(10) = '',
	--	@term nvarchar(255) = '',
	--	@fromdate datetime = '20260101',
	--	@todate datetime = '20260630',
	--	@UserId bigint = 34594,
	--	@Offsets int = 0,
	--	@PageSize int = 10


	declare @ParentId bigint = 0
	select @ParentId = parentid from User_Detail where User_Id = @UserId

	declare @startPoint int = @Offsets * @PageSize
	declare @endPoint int = @startPoint + @PageSize

	;with history as (
	select 
		row_number() over (order by t.id desc) as RowNum,
		t.id, parentid, char_count, cost_applied, createon, detail_json, languageCode

	from tbl_translation_deduction t with (nolock)
		inner join IntCredit_Details d with (nolock) on t.int_credit_id = d.Credit_ID
		where parentid = @ParentId
			and 1 = (case  when isnull(@fromdate, '') = '' or isnull(@todate, '') = '' then 1
					when cast(createon as date) between (cast(@fromdate as date)) and (cast(@todate as date)) then 1
				 else 0 end)
			and 1 = (case when isnull(@language, '') = '' then 1
				when languageCode = @language then 1
				else 0 end)
			and 1 = (case when isnull(@term, '') = '' then 1
				when detail_json like '%' + @term + '%' then 1
				else 0 end)
	)	
	select RowNum,
		(select count(1) from history) as TotalRecords,
	id, parentid, char_count, cost_applied, format(createon, 'dd-MMM-yyyy HH:mm:ss' ) as [createon], detail_json, languageCode 
	from history where RowNum between @startPoint and @endPoint
end



GO

