/* ============================================================
   Procedure: [dbo].[usp_getTriggeredcampaigndetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getTriggeredcampaigndetails] --6157
@triggeredcampaignid bigint
as
begin

 

--declare @triggeredcampaignid bigint=6157

 

Declare @SMSCampaignID bigint, @MailCampaignID bigint,@VoiceCampaignID bigint,    
  @WhatsappCampaignID bigint,@sequenceid bigint,@sr bigint,@mr bigint,@vr bigint,@wr bigint,@sqr bigint          
select @smscampaignid=smscampaignid,@MailCampaignID=mailcampaignid,@VoiceCampaignID=voicecampaignid,@WhatsappCampaignID=
whatsappcampaignid,@sequenceid=sequenceid
from triggeredcampaigns(nolock) where id=@triggeredcampaignid                        

 

select @sr= SUM(case when campaignid=isnull(@SMSCampaignID,0) then NoOfRecipients else 0 end),
@mr=SUM(case when campaignid=isnull(@MailCampaignID,0) then NoOfRecipients else 0 end),
@vr=SUM(case when campaignid=isnull(@VoiceCampaignID,0) then NoOfRecipients else 0 end),
@wr=SUM(case when campaignid=isnull(@WhatsappCampaignID,0) then NoOfRecipients else 0 end)
from UserCampaignExecutionHistory(nolock)    
    where campaignID in    
               (    
        isnull(@SMSCampaignID,0),    
        isnull(@MailCampaignID,0),    
        isnull(@VoiceCampaignID,0),    
        isnull(@WhatsappCampaignID,0)    
      )
--select @sqr=isnull((select count(distinct activityid) from MySMSConversations.dbo.tbl_wa_automationtasks(nolock) where activityid
--is not null and ruleid=@triggeredcampaignid),0)
DECLARE @SQLQuery NVARCHAR(MAX);
--SET @SQLQuery = 'SELECT ISNULL((SELECT COUNT(DISTINCT activityid) FROM tbl_wa_automationtasks (NOLOCK) WHERE activityid IS NOT NULL AND ruleid = ' + CAST(@triggeredcampaignid AS NVARCHAR) + '), 0)';
SET @SQLQuery =
'
SELECT CAST(COUNT(DISTINCT activityid) AS BIGINT)
FROM tbl_wa_automationtasks (NOLOCK)
WHERE activityid IS NOT NULL
AND ruleid = ' + CAST(@triggeredcampaignid AS VARCHAR(20));
EXEC usp_clr_GetRemoteLongValue @SQLQuery, @retval = @sqr OUTPUT;

 

select  @sr as SMSRecipients,@mr as MailRecipients,@vr as VoiceRecipients,@wr as WhatsappRecipients,@sqr as SequenceRecipients  

 

 

end



GO

/* ============================================================
   Procedure: [dbo].[usp_getTriggeredcampaigndetails_datewise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getTriggeredcampaigndetails_datewise] --770
@triggeredcampaignid bigint,@fromdate date=null,@todate date =null  
as  
begin  
drop table if exists #cid
drop table if exists #sid

declare @fdate date --,@triggeredcampaignid bigint=770,@fromdate date=null,@todate date =null  

Declare @SMSCampaignID bigint, @MailCampaignID bigint,@VoiceCampaignID bigint,      
  @WhatsappCampaignID bigint,@sequenceid bigint,@sr bigint,@mr bigint,@vr bigint,@wr bigint,@sqr bigint            
select @smscampaignid=smscampaignid,@MailCampaignID=mailcampaignid,@VoiceCampaignID=voicecampaignid,@WhatsappCampaignID=  
whatsappcampaignid,@sequenceid=sequenceid,@fdate=cast(createdon as date)  
from triggeredcampaigns(nolock) where id=@triggeredcampaignid                          
select @fromdate=coalesce(@fromdate,@fdate),@todate=
coalesce(dateadd(d,1,@todate),dbo.funcToGetLastRun_New_includingsequence(@triggeredcampaignid),dateadd(d,1,getdate()))  
  
select cast(date_id as date) as Campaigndate,  
@smscampaignid as smscampaignid,@MailCampaignID as mailcampaignid,@VoiceCampaignID as voicecampaignid,  
@WhatsappCampaignID as whatsappcampaignid,  
SUM(case when campaignid=isnull(@SMSCampaignID,0) then NoOfRecipients else 0 end) SMSRecipients,  
SUM(case when campaignid=isnull(@MailCampaignID,0) then NoOfRecipients else 0 end) MailRecipients,  
SUM(case when campaignid=isnull(@VoiceCampaignID,0) then NoOfRecipients else 0 end) VoiceRecipients,  
SUM(case when campaignid=isnull(@WhatsappCampaignID,0) then NoOfRecipients else 0 end) WhatsappRecipients  
into #cid  
from UserCampaignExecutionHistory(nolock)  u  right join calendar c (nolock)   
on cast(date_id as date)=cast(u.ExecutionTime as date)  
    where   
 (u.id is null or campaignID in      
               (      
        isnull(@SMSCampaignID,0),      
        isnull(@MailCampaignID,0),      
        isnull(@VoiceCampaignID,0),      
        isnull(@WhatsappCampaignID,0)      
      ))  
   and cast(date_id as date) between @fromdate and @todate  
   group by cast(date_id as date)  order by cast(date_id as date) desc  
  
DROP TABLE IF EXISTS #temp;
    CREATE TABLE #temp (createdon datetime,id bigint,activityid BIGINT, ruleid BIGINT);

DECLARE @query NVARCHAR(MAX);
SET @query = '
        SELECT createdon,id,activityid, ruleid
        FROM tbl_wa_automationtasks (NOLOCK) ';

    -- Execute the query using your CLR procedure
        INSERT INTO #temp(createdon,id,activityid, ruleid)
    EXEC usp_clr_FillRemoteData @query;


/*select cast(date_id as date) Campaigndate,count(distinct activityid) as SequenceRun, @sequenceid as sequenceid  
into #sid  
from MySMSConversations.dbo.tbl_wa_automationtasks(nolock)  
u  right join calendar c (nolock)   
on cast(date_id as date)=cast(u.createdon as date)  
where   
(u.id is null or (activityid  
is not null and ruleid=@triggeredcampaignid)) and cast(date_id as date) between @fromdate and @todate  
group by cast(date_id as date) order by cast(date_id as date) desc  */

select cast(date_id as date) Campaigndate,count(distinct activityid) as SequenceRun, @sequenceid as sequenceid  
into #sid  
--from MySMSConversations.dbo.tbl_wa_automationtasks(nolock)  
from #temp 
u  right join calendar c (nolock)   
on cast(date_id as date)=cast(u.createdon as date)  
where   
(u.id is null or (activityid  
is not null and ruleid=@triggeredcampaignid)) and cast(date_id as date) between @fromdate and @todate  
group by cast(date_id as date) order by cast(date_id as date) desc 
  
select isnull(c.campaigndate,s.campaigndate) as Campaigndate,c.smscampaignid,c.mailcampaignid,c.voicecampaignid,c.whatsappcampaignid,
s.sequenceid,c.smsrecipients,c.MailRecipients,c.VoiceRecipients,c.WhatsappRecipients,s.SequenceRun
from #cid c full outer join #sid s on c.Campaigndate=s.Campaigndate  
where isnull(smsrecipients,0)+isnull(mailrecipients,0)+isnull(voicerecipients,0)+isnull(whatsapprecipients,0)+isnull(sequencerun,0)
>0
  
end



GO

