   Procedure: [dbo].[usp_getTriggeredcampaigndetails_datewise_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getTriggeredcampaigndetails_datewise_new1] --770  
@triggeredcampaignid bigint=null,@fromdate date=null,@todate date =null,@CampName VARCHAR(500)=null,@OffsetValue INT = 0, @PagingSize INT = 10   
as    
begin    
/*drop table if exists #cid  
drop table if exists #sid  
  
declare @fdate date --,@triggeredcampaignid bigint=770,@fromdate date=null,@todate date =null    
  
Declare @SMSCampaignID bigint, @MailCampaignID bigint,@VoiceCampaignID bigint,        
  @WhatsappCampaignID bigint,@sequenceid bigint,@sr bigint,@mr bigint,@vr bigint,@wr bigint,@sqr bigint 
   DECLARE @Remarks NVARCHAR(200);
    DECLARE @CampaignName NVARCHAR(200);
  
select @smscampaignid=smscampaignid,@MailCampaignID=mailcampaignid,@VoiceCampaignID=voicecampaignid,@WhatsappCampaignID=    
whatsappcampaignid,@sequenceid=sequenceid,@fdate=cast(createdon as date),@CampaignName=cname    
from triggeredcampaigns(nolock) where id=@triggeredcampaignid and (@CampName IS NULL OR cname = @CampName)   

--select @fromdate=coalesce(@fromdate,@fdate),@todate=  
--coalesce(dateadd(d,1,@todate),dbo.funcToGetLastRun_New_includingsequence(@triggeredcampaignid),dateadd(d,1,getdate()))    
SELECT 
    @fromdate = COALESCE(@fromdate, @fdate),
    @todate = COALESCE(
        DATEADD(DAY, 1, @todate),
        TRY_CONVERT(DATE, dbo.funcToGetLastRun_New_includingsequence(@triggeredcampaignid)),
        DATEADD(DAY, 1, GETDATE())
    );
    
select cast(date_id as date) as Campaigndate,    
@smscampaignid as smscampaignid,@MailCampaignID as mailcampaignid,@VoiceCampaignID as voicecampaignid,    
@WhatsappCampaignID as whatsappcampaignid,    
SUM(case when campaignid=isnull(@SMSCampaignID,0) then NoOfRecipients else 0 end) SMSRecipients,    
SUM(case when campaignid=isnull(@MailCampaignID,0) then NoOfRecipients else 0 end) MailRecipients,    
SUM(case when campaignid=isnull(@VoiceCampaignID,0) then NoOfRecipients else 0 end) VoiceRecipients,    
SUM(case when campaignid=isnull(@WhatsappCampaignID,0) then NoOfRecipients else 0 end) WhatsappRecipients    
into #cid    
from UserCampaignExecutionHistory(nolock)  u  right join calendar c (nolock)     
on cast(date_id as date)=cast(u.ExecutionTime as date)    
    where     
 (u.id is null or campaignID in        
               (        
        isnull(@SMSCampaignID,0),        
        isnull(@MailCampaignID,0),        
        isnull(@VoiceCampaignID,0),        
        isnull(@WhatsappCampaignID,0)        
      ))    
   and cast(date_id as date) between @fromdate and @todate    
   group by cast(date_id as date)  order by cast(date_id as date) desc    
    
select cast(date_id as date) Campaigndate,count(distinct activityid) as SequenceRun, @sequenceid as sequenceid,messagetext as Remarks    
into #sid    
from [10.0.0.135].mysmsConversations.dbo.tbl_wa_automationtasks(nolock)    
u  right join calendar c (nolock)     
on cast(date_id as date)=cast(u.createdon as date)    
where     
(u.id is null or (activityid    
is not null and ruleid=@triggeredcampaignid)) and cast(date_id as date) between @fromdate and @todate    
group by cast(date_id as date), messagetext order by cast(date_id as date) desc    
    
select isnull(c.campaigndate,s.campaigndate) as Campaigndate,c.smscampaignid,c.mailcampaignid,c.voicecampaignid,c.whatsappcampaignid,  
s.sequenceid,c.smsrecipients,c.MailRecipients,c.VoiceRecipients,c.WhatsappRecipients,s.SequenceRun,s.Remarks,t.cname  
from #cid c full outer join #sid s on c.Campaigndate=s.Campaigndate 
left join triggeredcampaigns t (nolock) on t.id = @triggeredcampaignid
where isnull(smsrecipients,0)+isnull(mailrecipients,0)+isnull(voicerecipients,0)+isnull(whatsapprecipients,0)+isnull(sequencerun,0)  
>0  */
 -- Declare variables
 begin try
    DECLARE @SMSCampaignID BIGINT, 
            @MailCampaignID BIGINT,
            @VoiceCampaignID BIGINT,
            @WhatsappCampaignID BIGINT,
            @SequenceID BIGINT,
            @DefaultDate DATE;

    -- Get campaign details
    SELECT 
        @SMSCampaignID = smscampaignid,
        @MailCampaignID = mailcampaignid,
        @VoiceCampaignID = voicecampaignid,
        @WhatsappCampaignID = whatsappcampaignid,
        @SequenceID = sequenceid,
        --@DefaultDate = CAST(createdon AS DATE)
		@DefaultDate = createdon 
    FROM triggeredcampaigns (NOLOCK)
    WHERE id = @triggeredcampaignid 
      AND (@CampName IS NULL OR cname = @CampName);

    -- Calculate date range
    SELECT 
        @fromdate = COALESCE(@fromdate, @DefaultDate),
        @todate = COALESCE(
            DATEADD(DAY, 1, @todate),
            TRY_CONVERT(DATE, dbo.funcToGetLastRun_New_includingsequence(@triggeredcampaignid)),
            DATEADD(DAY, 1, GETDATE())
        );

    -- Temporary table for Campaign Data
    WITH CampaignData AS (
        SELECT 
            CAST(date_id AS DATE) AS Campaigndate,
            @SMSCampaignID AS smscampaignid,
            @MailCampaignID AS mailcampaignid,
            @VoiceCampaignID AS voicecampaignid,
            @WhatsappCampaignID AS whatsappcampaignid,
            SUM(CASE WHEN campaignid = ISNULL(@SMSCampaignID, 0) THEN NoOfRecipients ELSE 0 END) AS SMSRecipients,
            SUM(CASE WHEN campaignid = ISNULL(@MailCampaignID, 0) THEN NoOfRecipients ELSE 0 END) AS MailRecipients,
            SUM(CASE WHEN campaignid = ISNULL(@VoiceCampaignID, 0) THEN NoOfRecipients ELSE 0 END) AS VoiceRecipients,
            SUM(CASE WHEN campaignid = ISNULL(@WhatsappCampaignID, 0) THEN NoOfRecipients ELSE 0 END) AS WhatsappRecipients
        FROM UserCampaignExecutionHistory (NOLOCK) u
        RIGHT JOIN calendar c (NOLOCK) 
            ON CAST(date_id AS DATE) = CAST(u.ExecutionTime AS DATE)
        WHERE 
            (u.id IS NULL OR campaignID IN (
                ISNULL(@SMSCampaignID, 0),
                ISNULL(@MailCampaignID, 0),
                ISNULL(@VoiceCampaignID, 0),
                ISNULL(@WhatsappCampaignID, 0)
            ))
            AND CAST(date_id AS DATE) BETWEEN @fromdate AND @todate
        GROUP BY CAST(date_id AS DATE)
    ),

    SequenceData AS (
        SELECT 
            CAST(date_id AS DATE) AS Campaigndate,
            COUNT(DISTINCT activityid) AS SequenceRun,
            @SequenceID AS sequenceid,
            messagetext AS Remarks
        FROM [10.0.0.135].mysmsConversations.dbo.tbl_wa_automationtasks as u with(NOLOCK) 
        RIGHT JOIN calendar c (NOLOCK) 
            ON CAST(date_id AS DATE) = CAST(u.createdon AS DATE)
        WHERE 
            (u.id IS NULL OR (activityid IS NOT NULL AND ruleid = @triggeredcampaignid))
            AND CAST(date_id AS DATE) BETWEEN @fromdate AND @todate
        GROUP BY CAST(date_id AS DATE), messagetext
    )

    -- Combine results and apply pagination
    SELECT * 
    FROM (
        SELECT 
            ISNULL(c.Campaigndate, s.Campaigndate) AS Campaigndate,
            c.smscampaignid,
            c.mailcampaignid,
            c.voicecampaignid,
            c.whatsappcampaignid,
            s.sequenceid,
            c.SMSRecipients,
            c.MailRecipients,
            c.VoiceRecipients,
            c.WhatsappRecipients,
            s.SequenceRun,
            s.Remarks,
            t.cname,
            ROW_NUMBER() OVER (ORDER BY ISNULL(c.Campaigndate, s.Campaigndate) DESC) AS RowNum
        FROM CampaignData c (NOLOCK)
        FULL OUTER JOIN SequenceData s (NOLOCK)
            ON c.Campaigndate = s.Campaigndate
        LEFT JOIN triggeredcampaigns t (NOLOCK) 
            ON t.id = @triggeredcampaignid
        WHERE 
            ISNULL(c.SMSRecipients, 0) 
            + ISNULL(c.MailRecipients, 0) 
            + ISNULL(c.VoiceRecipients, 0) 
            + ISNULL(c.WhatsappRecipients, 0) 
            + ISNULL(s.SequenceRun, 0) > 0
    ) AS Result
    WHERE RowNum BETWEEN @OffsetValue + 1 AND @OffsetValue + @PagingSize;  
	END TRY

    -- Catch block to handle errors
    BEGIN CATCH
        -- Log error information
        EXEC usp_InsertErrorInfo;
    END CATCH
end

--go
----------------------------------------------------------




GO

