/* ============================================================
   Procedure: [dbo].[USP_GetUnprocessedIntSMSBatchId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_GetUnprocessedIntSMSBatchId]  
as  
BEGIN  
    SET NOCOUNT ON;  
 drop table if exists #temp  
 drop table if exists #temps  
  drop table if exists #ActionDetails  
    -- Declare a table variable to hold the output of the inserted rows  
    DECLARE @InsertedRows TABLE (  
        MessageID BIGINT,  
        BatchID BIGINT,  
        Country_code NVARCHAR(10),  
        Mobile NVARCHAR(15),  
        Message NVARCHAR(MAX),  
        MessageInsertDate DATETIME,  
        U_ID BIGINT,  
        IsUniCode BIT,  
        --MobileSubSet NVARCHAR(5),  
        Processed INT,  
        Price DECIMAL(18, 2),  
        EntityId INT,  
        EntityName NVARCHAR(50),  
        ProcessStartDatetime DATETIME  
    );  
  
    -- Fetch unprocessed records from Int_MessageDeliveryStatus into a temporary table  
    SELECT   
        s.BatchID,  
        s.CountryCode,  
        s.Mobile,  
        s.Message,   
        s.MessageStatus,   
        s.MessageInsertDate,   
        s.U_ID,    
        s.StatusCode,      
        s.ProviderReference,            
        s.LastError,          
        s.IsUniCode,  
        s.Status,  
        s.IsCompleted,  
        s.StatusCompletedTime,  
        s.StatusCompletedTimeSecs,  
        s.StatusDescription,  
        --s.IsDND,  
        --s.Operator,  
        --s.Isallowdnd,  
        --s.DbType,  
        s.Processed,  
        s.EntityId,  
        s.EntityName,  
        ROW_NUMBER() OVER (PARTITION BY s.EntityId ORDER BY s.MessageInsertDate) AS RowNum  
    INTO #temp     
    FROM Int_MessageDeliveryStatus s WITH (NOLOCK)   
    WHERE s.Processed = 2 AND ISNULL(s.MessageStatus,'') = '' and SmsMode='Multiple';  
  
    -- Create a temporary table to store the results of the stored procedure  
    CREATE TABLE #ActionDetails (  
        EntityID BIGINT,  
        ActionDetails NVARCHAR(MAX),  
  Message  nvarchar(max),  
  Mobile nvarchar(max)  
    );  
  
    DECLARE @EntityID INT;  
    DECLARE @EntityName NVARCHAR(50);  
    DECLARE @Message NVARCHAR(MAX);  
    DECLARE @Placeholders NVARCHAR(MAX);  
 declare @Mobile nvarchar(max)  
   -- DECLARE @entities dbo.entities;  
     
    -- Initialize the cursor to iterate over each row in #temp  
    DECLARE entity_cursor CURSOR FOR  
    SELECT DISTINCT EntityID, EntityName ,Message,Mobile  
    FROM #temp;  
  
    OPEN entity_cursor;  
    FETCH NEXT FROM entity_cursor INTO @EntityID, @EntityName,@Message,@Mobile;  
  
    WHILE @@FETCH_STATUS = 0  
    BEGIN  
        -- Insert data into the table variable for the current entity  
       DECLARE @entities dbo.entities;  
        INSERT INTO @entities (EntityID, entity)  
        VALUES (@EntityID, @EntityName);  
  
        -- Iterate over each row with the current EntityID in #temp  
        DECLARE @RowNum INT = 1;  
  
        WHILE EXISTS (SELECT 1 FROM #temp WHERE EntityID = @EntityID AND RowNum = @RowNum)  
        BEGIN  
  
            -- Extract placeholders for the current message  
            SET @Placeholders = dbo.ExtractPlaceholders(@EntityName, @Message);  
  
            -- Execute the stored procedure and capture the result  
   create table #temps(  
             EntityID BIGINT,  
             ActionDetails NVARCHAR(MAX),  
             )  
   truncate table #temps  
            DECLARE @ActionDetails NVARCHAR(MAX);  
   insert into #temps  
            EXEC @ActionDetails = dbo.usp_replaceentityplaceholders_bulk_singlecontent @entities, @Message, @Placeholders;  
  
   --select distinct * from #temps  
   set @ActionDetails=(select distinct ActionDetails from #temps )  
   drop table #temps  
   --select @ActionDetails  
            -- Insert the result into the temporary table  
            INSERT INTO #ActionDetails (EntityID, ActionDetails,Message,Mobile)  
            VALUES (@EntityID, @ActionDetails,@Message,@Mobile);  
    
  
            SET @RowNum = @RowNum + 1;  
    END  
  
        FETCH NEXT FROM entity_cursor INTO @EntityID, @EntityName,@Message,@Mobile;  
    END;  
  
    CLOSE entity_cursor;  
    DEALLOCATE entity_cursor;  
  --select distinct * from #ActionDetails  
    -- Final SELECT statement to include ActionDetails from #ActionDetails table  
  INSERT INTO CloneIntMsgDeliveryStatus  
        (BatchID, Country_code, Mobile, Message, MessageInsertDate, U_ID, IsUniCode, Processed, Price, EntityId, EntityName, ProcessStartDatetime)  
    OUTPUT   
        INSERTED.MessageID,  
        INSERTED.BatchID,   
        INSERTED.Country_code,   
        INSERTED.Mobile,   
        INSERTED.Message,   
        INSERTED.MessageInsertDate,   
        INSERTED.U_ID,   
        INSERTED.IsUniCode,   
        --INSERTED.MobileSubSet,   
        INSERTED.Processed,   
        INSERTED.Price,   
        INSERTED.EntityId,   
        INSERTED.EntityName,   
        INSERTED.ProcessStartDatetime  
  
    INTO @InsertedRows  
    SELECT distinct  
        t.BatchID,  
        t.CountryCode,  
        t.Mobile,  
        a.ActionDetails,   
        GETDATE() AS MessageInsertDate,  
        t.U_ID,  
        dbo.fn_isunicode(t.Message) AS IsUniCode,  
        --LEFT(t.Mobile, 5) AS MobileSubSet,  
        2 AS Processed,  
        (SELECT TOP 1 Balance FROM IntCredit_Details WITH (NOLOCK)   
         WHERE User_ID = t.U_ID ORDER BY DateCreated DESC) AS Price,  
        t.EntityId,  
        t.EntityName,  
        GETDATE() AS ProcessStartDatetime  
    FROM #temp t  
    left JOIN #ActionDetails a ON t.EntityId = a.EntityID and t.Mobile = a.Mobile;  
  
    -- Select from the table variable to return the inserted rows  
    SELECT *,replace(trim(a.Country_code),'+','')+trim(a.Mobile) as MobileNo FROM @InsertedRows a;  
  
    -- Clean up temporary tables  
    DROP TABLE #ActionDetails;  
    DROP TABLE #temp;  
  
END;  



GO

/* ============================================================
   Procedure: [dbo].[USP_GetUnprocessedMassOperationsSMS]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-------------------------------------------------------


CREATE   PROCEDURE USP_GetUnprocessedMassOperationsSMS AS BEGIN     SET NOCOUNT ON;      -- Fetch unprocessed records from tblmassoperationsummary       
SELECT          s.BatchID AS OperationID,           
s.MassOperationName,           
s.UserID,           
d.EntityID,    
-- Fetch EntityID from Tbl_MassOperationDetails         
s.EntityType,          
s.CreatedDate,         
s.IsProcessed,      
s.Remarks,         
s.BatchStartTime,   
s.BatchEndTime,          
s.IsValid,              
s.Metadata,        
s.ErrorDetails   FROM    Tbl_MassOperationSummary s (NOLOCK)     INNER JOIN     
Tbl_MassOperationDetails d (NOLOCK) ON s.BatchID = d.summaryid      
WHERE         
s.IsProcessed = 0           
AND s.IsValid = 1     
AND s.MassOperationName = 'Send InternationalSMS'     
UNION ALL        
-- Fetch unprocessed records from Tbl_MassInternationalSMS1     
SELECT    
SmsID AS OperationID,  
MassOperationName,    
UserID,   
EntityID,  
EntityType,  
CreatedDate,   
IsProcessed,   
Remarks,  
BatchStartTime,   
BatchEndTime,          
IsValid,           
TextMessages,           
ErrorDetails     FROM      
Tbl_MassInternationalSMS1 (NOLOCK)     
WHERE         
IsProcessed = 0          
AND IsValid = 1; END; 





GO

/* ============================================================
   Procedure: [dbo].[USP_GetUnprocessedMassOperationsSMSBatchId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_GetUnprocessedMassOperationsSMSBatchId]
AS
BEGIN          
    SET NOCOUNT ON;  
    
    -- Fetch unprocessed records from Tbl_MassOperationSummary where ScheduledDateTime is <= current datetime
    SELECT           
        s.BatchID,         
        s.MassOperationName,         
        s.UserID,             
        s.EntityType,           
        s.CreatedDate,          
        s.IsProcessed,             
        s.Remarks,            
        s.BatchStartTime,          
        s.BatchEndTime,          
        s.IsValid,          
        s.Metadata,        
        s.ErrorDetails,   
        s.SenderId,
        s.UrlTrack,
        s.TrackedUrl,             
        s.SmsPlaceHolder,
        s.ScheduleDateTime 
    FROM           
        Tbl_MassOperationSummary s (NOLOCK) 
    WHERE            
        s.IsProcessed = 0
        AND s.IsValid = 1
        AND s.MassOperationName = 'Send InternationalSMS'
        AND s.ScheduleDateTime <= GETDATE(); 
END;



GO

/* ============================================================
   Procedure: [dbo].[USP_GetUnprocessedMassOperationsSMSEntityId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE USP_GetUnprocessedMassOperationsSMSEntityId    
AS    
BEGIN    
    SET NOCOUNT ON;    
    
     SELECT     
        SmsID AS OperationID,    
        MassOperationName,     
        UserID,     
        EntityID,     
        EntityType,     
        CreatedDate,     
        IsProcessed,     
        Remarks,     
        BatchStartTime,     
        BatchEndTime,     
        IsValid,     
        TextMessages,     
        ErrorDetails, 
		Parentid,
  SenderId ,  
  UrlTrack  
    FROM     
        Tbl_MassInternationalSMS1 (NOLOCK)    
    WHERE     
        IsProcessed = 0     
        AND IsValid = 1    
  END;


GO

/* ============================================================
   Procedure: [dbo].[USP_GetUnprocessedOneToManyIntSMSBatchId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_GetUnprocessedOneToManyIntSMSBatchId]  
as  
BEGIN  
    SET NOCOUNT ON;  
		drop table if exists #temp  
		drop table if exists #temps  
		drop table if exists #ActionDetails  
		-- Declare a table variable to hold the output of the inserted rows  
		DECLARE @InsertedRows TABLE (  
			MessageID BIGINT,  
			BatchID BIGINT,  
			Country_code NVARCHAR(20),  
			Mobile NVARCHAR(40),  
			Message NVARCHAR(MAX),  
			SenderId nvarchar(40),
			MessageInsertDate DATETIME,  
			U_ID BIGINT,  
			IsUniCode BIT,  
			Processed INT,  
			Price numeric(18, 4),  
			EntityId INT,  
			EntityName NVARCHAR(50),  
			MassOpBatchId bigint,
			ProcessStartDatetime DATETIME,  
			SmsMode varchar(100),  
			MessageDeliveryStatusID bigint,
			UrlTrack bit
		);  
  
		-- Fetch unprocessed records from Int_MessageDeliveryStatus into a temporary table  
		SELECT top 10
		 s.MessageDeliveryStatusID,  
			s.BatchID,  
			s.CountryCode,  
			s.Mobile,  
			s.Message,   
			s.SenderID,
			s.MessageStatus,   
			s.MessageInsertDate,   
			s.U_ID,    
			s.IsUniCode,  
			s.Status,  
			s.IsCompleted,  
			s.StatusCompletedTime,  
			s.StatusCompletedTimeSecs,  
			s.StatusDescription,  
			s.Processed,  
			s.EntityId,  
			s.EntityName,  
			s.SmsMode,
			s.MassOpBatchId,
			s.UrlTrack,
			ROW_NUMBER() OVER (ORDER BY s.MessageDeliveryStatusID) AS RowNum  
		INTO #temp     
		FROM Int_MessageDeliveryStatus s WITH (NOLOCK)   
		WHERE s.Processed = 0 AND ISNULL(s.MessageStatus,'') = '' and SmsMode='singleTomulti' and MessageDeliveryStatusID not in (select MessageDeliveryStatusID From CloneIntMsgDeliveryStatus(nolock) where MessageDeliveryStatusID is not null)  
  
		-- Create a temporary table to store the results of the stored procedure  
		CREATE TABLE #ActionDetails (  
			EntityID BIGINT,  
			ActionDetails NVARCHAR(MAX),  
			Message  nvarchar(max),  
			Mobile nvarchar(max),  
			Price numeric(18,4)  
		);  
  
  
		DECLARE @EntityID INT;  
		DECLARE @EntityName NVARCHAR(50);  
		DECLARE @SenderId NVARCHAR(40);  
		DECLARE @Message NVARCHAR(MAX);  
		DECLARE @Placeholders NVARCHAR(MAX);  
		declare @Mobile nvarchar(max)  
		declare @CountryCode NVARCHAR(10);  
		declare @parentid bigint  
		declare @userid bigint  
		DECLARE @RowNum INT = 1
		DECLARE @RowCnt int=0
		declare @Sno int=0
		declare @UrlTrack bit=0
	   -- DECLARE @entities dbo.entities;  
	   declare @reccnt int=0
  			
		drop table if exists #temps  
            
		-- Execute the stored procedure and capture the result  
		create table #temps
		(  
			EntityID BIGINT,  
			ActionDetails NVARCHAR(MAX),  
		)  

		drop table if exists #TempTable  
		CREATE TABLE #TempTable (Sno int identity(1,1), entityid INT,     actiondetails NVARCHAR(max) );

	BEGIN TRY                
			 
		-- Initialize variables & iterate over each row in #temp  

		Select @RowCnt=count(*) from #temp
  
		WHILE (@RowNum <= @RowCnt)
		BEGIN
			BEGIN TRY
				print concat('@RowNum: ',@RowNum,' of ',@RowCnt)

				Select	@EntityID=EntityID, @EntityName=EntityName, @SenderId=trim(SenderID), @Message=Message,
						@Mobile=Mobile,	@userid=U_ID, @CountryCode=CountryCode, @UrlTrack=UrlTrack
				From	#Temp
				Where	RowNum=@RowNum

				print concat('@EntityID: ',@EntityID)
				print concat('@EntityName: ',@EntityName)
				print concat('@SenderId: ',@SenderId)
				print concat('@Message: ',@Message)
				print concat('@Mobile: ',@Mobile)
				print concat('@userid: ',@userid)
				print concat('@CountryCode: ',@CountryCode)
				print concat('@UrlTrack: ',@UrlTrack)

				-- Insert data into the table variable for the current entity  
				DECLARE @entities dbo.entities;  
				INSERT INTO @entities (EntityID, entity)  
				VALUES (@EntityID, @EntityName);  
  
				-- Extract placeholders for the current message  
				SET @Placeholders = dbo.ExtractPlaceholders(@EntityName, @Message);  

				print concat('@Placeholders: ',@Placeholders)
		
				truncate table #temps  
            
				DECLARE @ActionDetails NVARCHAR(MAX);  
   
				insert into #temps  
				EXEC /*@ActionDetails =*/ dbo.usp_replaceentityplaceholders_bulk_singlecontent @entities, @Message, @Placeholders;  

				--select distinct * from #temps  
				set @ActionDetails=(select distinct ActionDetails from #temps )  
  
  				print concat('@ActionDetails: ',@ActionDetails)
  
				--price  
				declare @cost_in_inr as numeric(18,4);     
      
				SELECT @Parentid=Parentid FROM user_detail (NOLOCK) WHERE user_id = @UserId  
            
				if exists(select PTrnsScurb from Price_Base_SMS_Rate_Exception(nolock) where parentid=@Parentid and DestinationCountryCode=trim(@CountryCode))
				begin    
					select @cost_in_inr=isnull(PTrnsScurb,0) 
					from Price_Base_SMS_Rate_Exception with(nolock)
					where parentid=@Parentid  and DestinationCountryCode=trim(@CountryCode)
				end    
				else    
				begin    
					select @cost_in_inr=isnull(PTrnsScurb,0) 
					from Price_base_sms_rate with(nolock)
					where  DestinationCountryCode=(@CountryCode) and IsEligible=1    
					--and UserID=@userId    
				end    

    
				-- DECLARE @entities dbo.entities;  -- Insert data into the table variable   
				--INSERT INTO @entities (EntityID, entity) VALUES     (@EntityID,@EntityName)
     
				INSERT INTO #TempTable (EntityID, actiondetails)
				EXEC dbo.usp_replaceentityplaceholders_bulk_singlecontent @entities, @message, @Placeholders

				select @Sno=SCOPE_IDENTITY()
			
				declare @Price numeric(18,4)=0, @IsUnicode bit =0  
				select @IsUnicode=dbo.fn_isunicode(@Message)  
				select @Price= Cast((@cost_in_inr * (case when @IsUnicode=0 and len(actiondetails)<=160 then 1 when @IsUnicode=0   and     LEN    (actiondetails)>160 then ceiling(LEN(actiondetails)/cast(153 as FLOat)) when @IsUnicode=1 and len      (actiondetails) <=70   then  1 else ceiling(LEN(actiondetails)/cast(67 as float)) end)) as Numeric(18,4))  
				from #TempTable   
				where Sno=@Sno--EntityID=@EntityID  
                  
				print concat('@cost_in_inr: ',@cost_in_inr)  
				print concat('@Price: ',@Price)  
				print concat('@IsUnicode: ',@IsUnicode)  
				print concat('@Sno: ',@Sno)  
  
				INSERT INTO #ActionDetails (EntityID, ActionDetails,Message,Mobile,Price)  
				VALUES (@EntityID, @ActionDetails,@Message,@Mobile,@Price);  
  
					delete from @entities
				--select * from #ActionDetails  
			END TRY
			BEGIN CATCH
				  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)
				  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()
			END CATCH
  
			SET @RowNum = @RowNum + 1;  
		END;-- End While  
  
  /*
		select * from @entities
		select * from #TempTable
		select * from #ActionDetails
		SELECT distinct
			t.BatchID, t.CountryCode, t.Mobile, a.ActionDetails, trim(t.SenderID) as SenderID, GETDATE() AS MessageInsertDate, t.U_ID, dbo.fn_isunicode(t.Message) AS IsUniCode, 1 AS Processed, a.Price, t.EntityId, t.EntityName,  
			GETDATE() AS ProcessStartDatetime,'singleTomulti' as SmsMode,t.MessageDeliveryStatusID, t.MassOpBatchId
		FROM #temp t left JOIN #ActionDetails a 
		ON isnull(t.EntityId,0) = isnull(a.EntityID,0) and t.Mobile = a.Mobile
		Where t.MessageDeliveryStatusID not in (select MessageDeliveryStatusID From CloneIntMsgDeliveryStatus(nolock) where MessageDeliveryStatusID is not null)
	*/

	-- Final SELECT statement to include ActionDetails from #ActionDetails table  
	INSERT INTO CloneIntMsgDeliveryStatus  
        (BatchID, Country_code, Mobile, Message, SenderID, MessageInsertDate, U_ID, IsUniCode, Processed, Price, EntityId, EntityName, ProcessStartDatetime,SmsMode,MessageDeliveryStatusID,MassOpBatchId,UrlTrack)  
    OUTPUT
        INSERTED.MessageID,  
        INSERTED.BatchID,   
        INSERTED.Country_code,   
        INSERTED.Mobile,   
        INSERTED.Message,   
        INSERTED.SenderID,   
        INSERTED.MessageInsertDate,   
        INSERTED.U_ID,   
        INSERTED.IsUniCode,   
        INSERTED.Processed,   
        INSERTED.Price,   
        INSERTED.EntityId,   
        INSERTED.EntityName,   
        INSERTED.MassOpBatchId,
        INSERTED.ProcessStartDatetime,  
		inserted.SmsMode,  
		inserted.MessageDeliveryStatusID,
		inserted.UrlTrack
    INTO @InsertedRows  
    SELECT distinct
        t.BatchID, t.CountryCode, t.Mobile, a.ActionDetails, trim(t.SenderID) as SenderID, GETDATE() AS MessageInsertDate, t.U_ID, dbo.fn_isunicode(t.Message) AS IsUniCode, -1 AS Processed, a.Price, t.EntityId, t.EntityName,  
        GETDATE() AS ProcessStartDatetime,'singleTomulti' as SmsMode,t.MessageDeliveryStatusID, t.MassOpBatchId, t.UrlTrack
    FROM #temp t left JOIN #ActionDetails a 
	ON isnull(t.EntityId,0) = isnull(a.EntityID,0) and t.Mobile = a.Mobile
	--Where t.MessageDeliveryStatusID not in (select MessageDeliveryStatusID From CloneIntMsgDeliveryStatus(nolock) where MessageDeliveryStatusID is not null)
  
    -- Select from the table variable to return the inserted rows  
    SELECT *,replace(trim(a.Country_code),'+','')+trim(a.Mobile) as MobileNo FROM @InsertedRows a;  

 END TRY                    
 BEGIN CATCH

  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date) 
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE() 

 END CATCH      
  
    -- Clean up temporary tables  
    DROP TABLE #ActionDetails;  
    DROP TABLE #temp;  
  
END;  



GO

/* ============================================================
   Procedure: [dbo].[USP_GetUnprocessedOneToManyIntSMSBatchId_linktracking]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_GetUnprocessedOneToManyIntSMSBatchId_linktracking]  
as                    
BEGIN                    
  SET NOCOUNT ON;                    
  drop table if exists #temp                    
  drop table if exists #temps                    
  drop table if exists #ActionDetails                    
  -- Declare a table variable to hold the output of the inserted rows        
  if 1=1--datepart(HH,getdate())=5 and datepart(mi,getdate())=0 and datepart(ss,getdate())=0      
  begin      
	BEGIN TRY
		DECLARE @InsertedRows TABLE (                    
			MessageID BIGINT,
			BatchID BIGINT,
			Country_code NVARCHAR(20),
			Mobile NVARCHAR(40),
			Message NVARCHAR(MAX),
			SenderId nvarchar(40),
			MessageInsertDate DATETIME,
			U_ID BIGINT,
			IsUniCode BIT,
			Processed INT,
			Price numeric(18, 4),
			EntityId INT,
			EntityName NVARCHAR(50),
			MassOpBatchId bigint,
			ProcessStartDatetime DATETIME,
			SmsMode varchar(100),
			MessageDeliveryStatusID bigint,
			UrlTrack bit,
			IsPersonalised bit
		);
                    
		-- Fetch unprocessed records from Int_MessageDeliveryStatus into a temporary table                    
        
		SELECT top 500
		s.MessageDeliveryStatusID,
		s.BatchID,
		s.CountryCode,
		s.Mobile,
		s.Message,
		s.SenderID,
		s.MessageStatus,
		s.MessageInsertDate,
		s.U_ID,
		s.IsUniCode,
		s.Status,
		s.IsCompleted,
		s.StatusCompletedTime,
		s.StatusCompletedTimeSecs,
		s.StatusDescription,
		s.Processed,
		s.EntityId,
		s.Price ,
		s.EntityName,
		s.SmsMode,
		s.MassOpBatchId,
		s.UrlTrack,
		s.IsPersonalised,
		ROW_NUMBER() OVER (ORDER BY s.MessageDeliveryStatusID) AS RowNum
		INTO #temp
		FROM Int_MessageDeliveryStatus s WITH (NOLOCK)
		WHERE --MessageDeliveryStatusID= 17376 and s.Processed in (0)
		dbo.ufn_getuserparentid(u_id) in (46489,42707,46700) and s.Processed = 0--2575 and MessageDeliveryStatusID=0
		--s.BatchID=137670884 and s.Processed in (0,2) --AND ISNULL(s.MessageStatus,'') = '' and SmsMode='multiTomulti'
		--and MessageDeliveryStatusID not in (select MessageDeliveryStatusID From CloneIntMsgDeliveryStatus(nolock) where MessageDeliveryStatusID is not null)
		update t set processed=2 from Int_MessageDeliveryStatus t join #temp p on p.MessageDeliveryStatusID=t.MessageDeliveryStatusID
		-- Create a temporary table to store the shortu url for tracking
		drop table if exists #remp

		create table #remp([id] int identity(1,1),[rexp] nvarchar(20))
		create index ix_#temp_id on #remp(ID);            

		DECLARE @Message NVARCHAR(MAX),@entity nvarchar(20);
		DECLARE @Placeholders NVARCHAR(MAX),@batchcount int,@batchid bigint=0,@parentid bigint,@cost numeric(18,4),@count int;
		DECLARE @entities dbo.entities;

		drop table if exists #batchid

		select distinct batchid into #batchid from #temp

		select @batchcount=count(1) from #batchid
                  
		--Iterate through each batch to replace placeholders and link tracking, if any
		WHILE @batchcount>0
		BEGIN
			BEGIN TRY
				select @batchid=min(batchid) from #batchid where batchid>@batchid
				select top 1 @message=message,@entity=entityname,@parentid=dbo.ufn_getuserparentid(u_id) from #temp where batchid=@batchid
				select @count=count(1) from #temp where batchid=@batchid
				SET @Placeholders = dbo.ExtractPlaceholders(@Entity, @Message);
				print concat('Placeholders found: ',@Placeholders)

				if @Placeholders<>''
				begin
				print 'Entered placeholder replacement '

				insert into @entities(entity,entityid)
				select distinct entityname,entityid from #temp where batchid=@batchid


				--Procedure to replace and insert replaced placeholders in message content and insert them in table mass_replaced_content
				--insert into #temps(EntityID,actiondetails)
				EXEC dbo.usp_replaceentityplaceholders_bulk_singlecontent_tableinsert @entities, @Message, @Placeholders,@batchid,'bulkintsms',0;

				--select * from mass_replaced_content where batchid=@batchid and type='bulkintsms'
				--update temp table with messagecontent with placeholders replaced
				update t set message=isnull(replacedcontent,message) from mass_replaced_content p left join #temp t on p.EntityID=t.entityid and p.batchid=t.batchid and p.entity=t.EntityName
				join @entities e on e.entityid=t.EntityId and e.entity=t.EntityName
				where t.batchid=@batchid

				--select 'message replaced',* from #temp
				delete from mass_replaced_content where batchid=@batchid and type='bulkintsms'
				end

				if exists (select 1 from Link_smsUrl_dtl(nolock) where batchid=@batchid)
				begin
					print 'Entered Link tracking '
					DECLARE @result NCHAR(4),@shorturl nvarchar(100),@longurl nvarchar(1000),@processurlid bigint ,@dlcount int
					select top 1 @shorturl=short_url,@processurlid=ProcessUrl_Id,@longurl=longurl from Link_smsUrl_dtl(nolock) where BatchId=@BATCHID
					print concat('longurl: ',@longurl, ', @batchid: ',@batchid)

					RETRY:
					BEGIN TRY
					BEGIN TRAN

					select @dlcount=count(1) from #temp m join Link_smsUrl_dtl(nolock) l on
					m.BatchID=l.BatchId and m.Message like '%'+l.longurl+'%'
					where m.batchid=@BATCHID


					--create short urls for each message
					insert into #remp(rexp)
					select top (@dlcount) r.[randomexp]
					from dbo.randomexp(nolock) r where r.id>(select isnull(lastid,0) from Link_urlMaster(nolock) where shorturl=@shorturl) order by r.id


					--update short url master so the short urls are picked after the ones that are used above
					update Link_urlMaster set lastid=isnull(lastid,0)+@dlcount where shorturl=@shorturl ;

					COMMIT
					END TRY
					BEGIN CATCH
						IF @@TRANCOUNT>0
							ROLLBACK
						
						--EXECUTE USP_INSERTERRORINFO;
						IF ERROR_NUMBER() = 1205 -- Deadlock Error Number
						BEGIN
							WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms
							GOTO RETRY -- Go to Label RETRY
						END
					END CATCH

					--update temp table with link tracking urls, temporarily use status description column for short url exp
					;WITH CTE AS (
					SELECT rownum,ROW_NUMBER() OVER (ORDER BY rownum) AS id
					FROM #temp
					)

					UPDATE T1
					SET T1.message=case when t2.rexp is not null then replace(message,@longurl,@shorturl+'/'+rexp) else message end

					,t1.StatusDescription=rexp
					FROM #temp T1
					JOIN CTE C1 ON T1.RowNum = C1.rownum
					left JOIN #remp T2 ON C1.id = T2.id where t1.batchid=@batchid;

					--insert in link tracking table so we recognize the mobile associated with the short url
					insert into dbo.Link_smsMobile
					(Mobile, batchid, shorturl, longurl, ProcessUrl_id, Final_url, Parentid, MessageID, Page_nm,p_url)
					select Mobile, batchid, @shorturl, @longurl, @processurlid, rexp, @Parentid, lk.MessageDeliveryStatusID, 'Send IntSMS Proc', @longurl
					from #remp ins inner join #temp lk
					on ins.rexp=lk.StatusDescription
					print concat('rowsinserted in link_smsmobile: ',@@rowcount, ', @batchid: ',@batchid)

					--update statusdescription to its original null value
					update t set t.StatusDescription=null from #temp t where batchid=@batchid
				end

				update p set price=Cast((dbo.fn_GetIntSMSUnitPrice(@parentid,CountryCode) *
				(case when dbo.fn_isunicode(p.message)=0 and len(p.message)<=160 then 1
				when dbo.fn_isunicode(p.message)=0 and LEN(p.message)>160 then
				ceiling(LEN(p.message)/cast(153 as FLOat))
				when dbo.fn_isunicode(p.message)=1 and len(p.message)<=70 then 1
				else ceiling(LEN(p.message)/cast(67 as float)) end)) as Numeric(18,4))
				from #temp p where batchid=@batchid

				delete from @entities
				truncate table #remp

			END TRY
			BEGIN CATCH
				insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)
				SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()
			END CATCH

			set @batchcount=@batchcount-1
		END -- End While

		-- Final SELECT statement to include ActionDetails from #ActionDetails table                    
		INSERT INTO CloneIntMsgDeliveryStatus
        (BatchID, Country_code, Mobile, Message, SenderID, MessageInsertDate, U_ID, IsUniCode, Processed, Price, EntityId, EntityName, ProcessStartDatetime, SmsMode, MessageDeliveryStatusID, MassOpBatchId, UrlTrack, IsPersonalised)                    
		OUTPUT
		INSERTED.MessageID,
		INSERTED.BatchID,
		INSERTED.Country_code,
		INSERTED.Mobile,
		INSERTED.Message,
		INSERTED.SenderID,
		INSERTED.MessageInsertDate,
		INSERTED.U_ID,
		INSERTED.IsUniCode,
		INSERTED.Processed,
		INSERTED.Price,
		INSERTED.EntityId,
		INSERTED.EntityName,
		INSERTED.MassOpBatchId,
		INSERTED.ProcessStartDatetime,
		inserted.SmsMode,
		inserted.MessageDeliveryStatusID,
		inserted.UrlTrack,
		inserted.IsPersonalised
		INTO @InsertedRows
		SELECT distinct
		t.BatchID, t.CountryCode, t.Mobile, t.message, trim(t.SenderID) as SenderID, GETDATE() AS MessageInsertDate, t.U_ID, dbo.fn_isunicode(t.Message) AS IsUniCode, -1 AS Processed, t.Price, t.EntityId, t.EntityName, GETDATE() AS ProcessStartDatetime, 'multiTomulti' as SmsMode, t.MessageDeliveryStatusID, t.MassOpBatchId, t.UrlTrack, t.IsPersonalised
		FROM #temp t

		SELECT *,replace(trim(a.Country_code),'+','')+trim(a.Mobile) as MobileNo FROM @InsertedRows a;                    
		--update s set processed=2 from Int_MessageDeliveryStatus s join @InsertedRows i on i.MessageDeliveryStatusID=s.MessageDeliveryStatusID                 
	END TRY                                      
	BEGIN CATCH                  
		insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date) 
		SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE() 
	END CATCH 
  end--end if
END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUnSentRevertRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Created by Abhishek
--Date 13/07/2010
CREATE   PROCEDURE [dbo].[usp_GetUnSentRevertRecord]            
as            
Begin            
Select MessageID , BatchID , Mobile , SenderID , MessageInsertDate , U_ID , IsUnicode ,                
[Message],Priority,        
(cast(case IsSent        
when 0 Then 'NotSent'        
when 1 Then 'Sent'        
End as varchar)        
) as Status,ServiceName,SourceTable        
 from RevertedRecord Where IsNull(IsReverted,0) = 0 
And convert(datetime,MessageInsertDate ,103) = convert(datetime, getdate() , 103)               
End 


GO

