/* ============================================================
   Procedure: [dbo].[usp_getupdatedCRMlinkedaccount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getupdatedCRMlinkedaccount  
as  
begin  
truncate table [MYsms].[dbo].linkedaccount   
declare @c int,@id bigint=0  
select @c=count(1) from CRM.CRMDB.dbo.linkedaccount with (nolock)   
  
drop table if exists #userid  
create table #userid(user_id bigint)  
  
drop table if exists #la  
  
select * into #la from CRM.CRMDB.dbo.linkedaccount  with (nolock)  
  
while @c>0  
begin  
  
insert into #userid(user_id)  
select top 5000 user_id from #la where user_id>@id order by user_id  
  
  
if exists(select 1 from CRM.CRMDB.dbo.linkedaccount l with (nolock) join #userid u on l.user_id=u.user_id)  
begin  
Insert Into linkedaccount(ID,M_ID,User_ID,User_Login,Pwd,FName,LName,EMail,Mobile,City,State,Country,Type,Stype,ACType,Status,DateCreated,DateUpdated,EmpUpdated,userfilter,FilterMode,RefrenceNo,Verified,  
LastPurchasedCredits,LastPurchasedDate      
,AverageLast3MonthConsumption,LastLogin1)      
select ID,M_ID,l.User_ID,User_Login,Pwd,FName,LName,EMail,Mobile,City,State,Country,Type,Stype,ACType,Status,DateCreated,DateUpdated,EmpUpdated,userfilter,FilterMode,RefrenceNo,Verified,  
LastPurchasedCredits,LastPurchasedDate      
,AverageLast3MonthConsumption,LastLogin1 from CRM.CRMDB.dbo.linkedaccount l with (nolock) join #userid u on l.user_id=u.user_id  
  
end  

update l set l.user_login=u.user_login from  CRM.[CRMDB].[dbo].linkedaccount l with (nolock) join #userid u on u.User_ID=l.User_ID where l.user_login<>u.user_login

  
select @id =max(user_id) from #userid  
truncate table #userid  
set @c=@c-5000  
end  
end  


GO

