--exec usp_GetUrlKeywordHint @Url='kit19.com',@UserId='335'
CREATE   PROC usp_GetUrlKeywordHint
(
	@Url varchar(500),
	@UserId varchar(50)=''
)
As
Begin

	If(Isnull(@UserId,'') != '')
	Begin
		Insert into tbl_UserKeywordHintRequest([Url],UserId)
		Values (@Url, @UserId)
	End

	Select top 1 *
	From [tbl_UrlKeywords]
	Where IsArchived = 0 and [Url]=@Url
End



