   Procedure: [dbo].[usp_GetURlTrackDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetURlTrackDetails -- 335,17626        
	(
	@UserID BIGINT
	,@ParentID BIGINT
	)
AS
BEGIN
	IF @UserID = 335
	BEGIN
		SELECT UTRBL.trackId
			,UTRBL.urlid
			,
			-- UTRBL.visiteddate ,  
			dbo.[fn_getusertimefromindiantime](@ParentID, UTRBL.visiteddate) AS visiteddate
			,UTRBL.Mail_ToEmail
			,UTRBL.templateid
			,UTRBL.CampaignID
			,UTRBL.ParentID
			,(
				SELECT User_Login
				FROM User_Detail
				WHERE USER_ID = UTRBL.ParentID
				) AS ParentUserName
			,UURL.url_dtl
			,UMT.Name AS TemplateName
			,UCS.CampaignName AS CampaignName
			,isnull(ul.PersonName, '') lname
			,isnull(ul.PersonName, 'nolead') leadok
		FROM url_tracktbl(NOLOCK) UTRBL
		LEFT JOIN UserUrl(NOLOCK) UURL ON UTRBL.urlid = UURL.urlid
		LEFT JOIN UserMailTemplate(NOLOCK) UMT ON UTRBL.templateid = UMT.ID
		LEFT JOIN UserCampaignmaster(NOLOCK) UCS ON UTRBL.CampaignID = UCS.ID
		LEFT OUTER JOIN UserLeads ul(NOLOCK) ON ul.EmailID = UTRBL.Mail_ToEmail
			OR ul.EmailID1 = UTRBL.Mail_ToEmail
			OR ul.EmailID2 = UTRBL.Mail_ToEmail
	END
	ELSE
	BEGIN
		SELECT UTRBL.trackId
			,UTRBL.urlid
			,
			-- UTRBL.visiteddate ,  
			dbo.[fn_getusertimefromindiantime](@ParentID, UTRBL.visiteddate) AS visiteddate
			,UTRBL.Mail_ToEmail
			,UTRBL.templateid
			,UTRBL.CampaignID
			,UTRBL.ParentID
			,(
				SELECT User_Login
				FROM User_Detail
				WHERE USER_ID = UTRBL.ParentID
				) AS ParentUserName
			,UURL.url_dtl
			,UMT.Name AS TemplateName
			,UCS.CampaignName AS CampaignName
			,isnull(ul.PersonName, '') lname
			,isnull(ul.PersonName, 'nolead') leadok
		FROM url_tracktbl(NOLOCK) UTRBL
		LEFT JOIN UserUrl(NOLOCK) UURL ON UTRBL.urlid = UURL.urlid
		LEFT JOIN UserMailTemplate(NOLOCK) UMT ON UTRBL.templateid = UMT.ID
		LEFT JOIN UserCampaignmaster(NOLOCK) UCS ON UTRBL.CampaignID = UCS.ID
		LEFT OUTER JOIN UserLeads ul(NOLOCK) ON ul.EmailID = UTRBL.Mail_ToEmail
			OR ul.EmailID1 = UTRBL.Mail_ToEmail
			OR ul.EmailID2 = UTRBL.Mail_ToEmail
		WHERE UTRBL.ParentID = @ParentID
			/*( UTRBL.ParentID  <> case        
              when @UserID = 335        
              then  0        
            end        
                    
            or         
                    
            UTRBL.ParentID =   case        
              when @UserID <> 335        
              then  @ParentID        
            end        
         )*/
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @parentid = @ParentID
		,@Activity_type = 'View_UrlTrck '
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'url_tracktbl'
END



GO

