/* ============================================================
   Procedure: [dbo].[usp_GetUsedChoicesByFieldId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_GetUsedChoicesByFieldId(@FieldId BIGINT)
AS
    BEGIN
        --declare @FieldId bigint = 1520
        DECLARE @ValueTable AS TABLE(ValueText NVARCHAR(MAX));
        INSERT INTO @ValueTable(ValueText)
               SELECT [value]
               FROM
               (
                   SELECT [value]
                   FROM fn_Split
                   (
                   (
                       SELECT STUFF(
                       (
                           SELECT DISTINCT 
                                  ', ' + LTRIM(RTRIM(CAST(fieldvalue AS NVARCHAR)))
                           FROM customfieldLeadvalue
                           WHERE fieldID = @FieldId
                                 AND ISNULL(CAST(fieldvalue AS NVARCHAR), '') <> '' FOR XML PATH('')
                       ), 1, 1, '') AS CSV
                   ), ','
                   )
                   UNION
                   SELECT [value]
                   FROM fn_Split
                   (
                   (
                       SELECT STUFF(
                       (
                           SELECT DISTINCT 
                                  ', ' + LTRIM(RTRIM(CAST(fieldvalue AS NVARCHAR)))
                           FROM customfieldEnquiryvalue
                           WHERE fieldID = @FieldId
                                 AND ISNULL(CAST(fieldvalue AS NVARCHAR), '') <> '' FOR XML PATH('')
                       ), 1, 1, '') AS CSV
                   ), ','
                   )
               ) AS tv;
        SELECT *
        FROM @ValueTable;
    END;



GO

/* ============================================================
   Procedure: [dbo].[USP_GETUSER_BYROLE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
if object_id('USP_SM_GETUSER_ROLES') is not null
begin
 drop procedure USP_SM_GETUSER_ROLES
end

DECLARE @P_RoleExist bit =0;

EXEC USP_GETUSER_BYROLE 32222 ,'manager', @P_RoleExist output
select @P_RoleExist

*/

CREATE   PROC USP_GETUSER_BYROLE
(
	@P_USER_ID INT,
	@P_Role_name varchar(100),
	@P_RoleExist bit output 
)
AS
BEGIN

	 DECLARE @PARENTID BIGINT = 0  
	 SELECT TOP 1 @PARENTID = ISNULL(PARENTID,USER_ID) FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @P_USER_ID    

	 create table #temp_users_role
	 (
		RoleCode varchar(30),
		ParentId bigint,
		UserId bigint
	 )

	 /*	 
	 SELECT RoleCode, UserId , ParentId  FROM TBL_UA_USERROLEMAPPINGMASTER  where ParentId = 32222 and RoleCode
		in  ( SELECT RoleCode FROM TBL_UA_ROLEMASTER  where  parentid = 32222 and RoleName ='assistent')

	 */

	insert into #temp_users_role
	SELECT RoleCode, UserId , ParentId  FROM TBL_UA_USERROLEMAPPINGMASTER  where ParentId = @PARENTID and RoleCode
	in  ( SELECT RoleCode FROM TBL_UA_ROLEMASTER  where  parentid = @PARENTID and  
	(case when  @P_Role_name = 'All' then '1' else RoleName end ) in  (case when  @P_Role_name = 'All' then '1' else @P_Role_name end ))

	--   RoleName IN (@P_Role_name) )

	set  @P_RoleExist =0 ;

	select @P_RoleExist = 1 from #temp_users_role  where UserId =  @P_USER_ID  


END


GO

/* ============================================================
   Procedure: [dbo].[USP_GetUser_DailyDebitAmount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC  [dbo].[USP_GetUser_DailyDebitAmount]  
 @UserFilter   varchar(100),  
 @UserID    varchar(100),  
 @FromDate   varchar(10),  
 @ToDate    varchar(10)  
  as  
  begin  
   SELECT cr.User_ID ,ud.User_Login, ud.FName+' '+ ud.LName as UName, sum(cr.Debits) as DebitAmt, count(mdst.U_ID) as EstimateDebit            
   FROM [MySMS].[dbo].[Credit_Details] cr join   
   [MySMS].[dbo].[User_Detail] ud on cr.User_id=ud.User_id   
   join  [mysmstrans].[dbo].[MessageDeliveryStatusTemp] mdst on cr.User_id=mdst.U_ID  
   where ud.userfilter='MTIX_pro' and cr.FromUser_ID=cr.User_ID and convert(varchar(10),convert(datetime, cr.DateCreated),104) between convert(varchar(10),convert(datetime, '11/26/2013'),104) and convert(varchar(10),convert(datetime, '11/26/2013'),104)  



   group by  cr.user_id,  ud.User_Login,ud.FName, ud.LName   
  end  
  



GO

