/* ============================================================
   Procedure: [dbo].[usp_GetUserAccounts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserAccounts]
	@Search VARCHAR(50) = ''
AS
BEGIN
	SELECT ud.[User_ID]            AS ID,
	       ISNULL(ud.User_Login, '') + ' / ' + ISNULL(ud.FName, '') + ' ' +
	       ISNULL(ud.LName, '') + ' ( ' + ISNULL(uf.Name, '') +
	       ' )' AS                    UserName
	FROM   User_Detail             AS ud
	       INNER JOIN User_Filter  AS uf
	            ON  uf.Code = ud.userfilter
	WHERE  m_id = 10043
	       AND ud.User_Login <> ''
	       AND (
	               ISNULL(@Search, '') = ''
	               OR ud.FName LIKE '%' + @Search + '%'
	               OR uf.Name LIKE '%' + @Search + '%'
	               OR ud.LName LIKE '%' + @Search + '%'
	               OR ud.User_Login LIKE '%' + @Search + '%'
	           )
	ORDER BY
	       ud.User_Login + ' / ' + ud.FName + ' ' + ud.LName + ' ( ' + uf.Name +
	       ' )'
END


GO

