/* ============================================================
   Procedure: [dbo].[usp_GetUserAccountsCRM_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-------Modified By Abhishek Makkar ----------- Time: 8/17/2017 10:08:30 AM    
CREATE   PROCEDURE dbo.usp_GetUserAccountsCRM_New -- 335    
	@ParentID BIGINT
AS
BEGIN
	SELECT ud.[User_ID] AS ID
		,ud.ParentID
		,ud.[User_ID] AS UserID
		,ut.Name AS UserType
		,ud.FName + ISNULL(ud.LName, '') AS UserName
		,ud.User_Login + '(' + UF.Name + ')' AS AccountName
		,ut.CreatedBy
		,
		--ut.CreatedOn,
		dbo.[fn_getusertimefromindiantime](ud.ParentID, ut.CreatedOn) AS CreatedOn
		,ud.User_Login
		,0 AS IsEditable
	FROM User_Detail AS ud
	LEFT JOIN User_Type AS ut(NOLOCK) ON ud.UserType = ut.ID
	INNER JOIN User_Filter UF(NOLOCK) ON ud.userfilter = Uf.Code
	WHERE ud.[User_ID] = @ParentID
	
	UNION
	
	SELECT ua.ID
		,ua.ParentID
		,ua.UserID
		,ut.Name AS UserType
		,ua.UserName
		,ua.AccountName + '(' + UF.Name + ')' AS AccountName
		,ua.CreatedBy
		,
		-- ua.CreatedOn,
		dbo.[fn_getusertimefromindiantime](ua.ParentID, ua.CreatedOn) AS CreatedOn
		,ud.User_Login
		,1 AS IsEditable
	FROM UserAccounts AS ua(NOLOCK)
	LEFT JOIN User_Detail AS ud(NOLOCK) ON ua.UserID = ud.User_ID
	LEFT JOIN User_Type AS ut(NOLOCK) ON ud.UserType = ut.ID
	LEFT JOIN User_Detail UD1(NOLOCK) ON ua.CreatedBy = UD1.User_ID
	INNER JOIN User_Filter AS UF(NOLOCK) ON ud.userfilter = UF.Code
	WHERE ua.ParentID = @ParentID

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
		,@Activity_type = 'View_UsrAccnts_Sttng '
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'UserAccounts'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserAccountsCRM_New_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
--------Modified By Abhishek Makkar ----------- Time: 8/17/2017 10:08:30 AM    
CREATE   PROCEDURE [dbo].[usp_GetUserAccountsCRM_New_INTDateTime]-- 335    
 @ParentID BIGINT    
AS    
BEGIN    
 SELECT ud.[User_ID]         AS ID,    
        ud.ParentID,    
        ud.[User_ID]         AS UserID,    
        ut.Name              AS UserType,    
        ud.FName + ISNULL(ud.LName, '') AS UserName,    
        ud.User_Login +'('+UF.Name+')'  AS AccountName,    
        ut.CreatedBy,    
        
      --ut.CreatedOn,
        dbo.[fn_getusertimefromindiantime](ud.ParentID,ut.CreatedOn) as CreatedOn,
                
        ud.User_Login,    
        0                    AS IsEditable    
 FROM   User_Detail          AS ud    
        LEFT JOIN User_Type  AS ut(NOLOCK)    
             ON  ud.UserType = ut.ID    
        inner join User_Filter UF(Nolock)  
        on ud.userfilter = Uf.Code       
 WHERE  ud.[User_ID] = @ParentID    
 UNION    
 SELECT ua.ID,    
        ua.ParentID,    
        ua.UserID,    
        ut.Name                AS UserType,    
        ua.UserName,    
        ua.AccountName + '('+UF.Name+')' as AccountName ,    
        ua.CreatedBy,    
        
     -- ua.CreatedOn,
        dbo.[fn_getusertimefromindiantime](ua.ParentID,ua.CreatedOn) as CreatedOn,    
        
        ud.User_Login,    
        1                      AS IsEditable    
 FROM   UserAccounts           AS ua(NOLOCK)    
        LEFT JOIN User_Detail  AS ud(NOLOCK)    
             ON  ua.UserID = ud.User_ID    
        LEFT JOIN User_Type    AS ut(NOLOCK)    
             ON  ud.UserType = ut.ID    
        LEFT JOIN User_Detail UD1(NOLOCK)    
             ON  ua.CreatedBy = UD1.User_ID  
        inner join User_Filter as UF(Nolock)  
             ON ud.userfilter = UF.Code        
                 
 WHERE  ua.ParentID = @ParentID    
END  


