CREATE   PROCEDURE [dbo].[usp_GetUserAccountsCRM_NewForMail] --335  
 @ParentID BIGINT  
AS  
BEGIN  
 SELECT ud.[User_ID]         AS ID,  
        ud.ParentID,  
        ud.[User_ID]         AS UserID,  
        ut.Name              AS UserType,  
        ud.FName + ISNULL(ud.LName, '') AS UserName,  
        ud.User_Login +'(Transactional - ' + CAST(ISNULL(mcd.Balance,0)  as Varchar) + ')'  AS AccountName ,  
        ut.CreatedBy,  
        ut.CreatedOn,  
        ud.User_Login,  
        0                    AS IsEditable  
 FROM   User_Detail          AS ud  
        LEFT JOIN User_Type  AS ut(NOLOCK)  
             ON  ud.UserType = ut.ID 
        Left Join (select top 1 Balance,USER_ID from MailcreditDetails where USER_ID = @ParentID order by DateCreated desc) MCD
             On ud.User_ID = MCD.User_ID       
 WHERE  ud.[User_ID] = @ParentID and ud.userfilter='MTIX_TR'  
 UNION  
 SELECT ua.ID,  
        ua.ParentID,  
        ua.UserID,  
        ut.Name                AS UserType,  
        ua.UserName,  
        ua.AccountName+'(Transactional - '+ CAST(ISNULL(mcd.Balance,0) as Varchar) + ')' AS AccountName,  
        ua.CreatedBy,  
        ua.CreatedOn,  
        ud.User_Login,  
