             On ud.User_ID = MCD.User_ID             
 WHERE  ud.[User_ID] = @ParentID and ud.userfilter='MTIX_TR'       
 END        
 ELSE        
 BEGIN        
     SELECT ua.UserID,        
            ud.User_Login +        
            ' ( Transactional Balance: ' + ISNULL(        
                (        
                    SELECT TOP 1 CAST(mcd.Balance AS VARCHAR(50))        
                    FROM   MailCreditDetails AS mcd        
                    WHERE  mcd.[User_ID] = ua.UserID        
                    ORDER BY        
                           mcd.DateCreated DESC        
                ),        
