 SELECT ud.user_Id                AS ID,  
        ISNULL(ud.Fname, '') + ' '  +  
        ISNULL(ud.Lname, '') + ' ( ' + ud.user_login + ' )' AS UserName  
  FROM   user_detail  AS ud  join CampaignAccounts ca on  ca.UserID=ud.user_id and ud.userfilter='mtix_tr'
 ORDER BY  
        Id DESC  
END





