/* ============================================================
   Procedure: [dbo].[USP_GetUserActiveTimeData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
 CREATE   PROCEDURE [dbo].[USP_GetUserActiveTimeData]  
    @UserID NVARCHAR(50),  
    @FromDate DATETIME,  
    @Todate DATETIME,  
    @PageNumber INT = 1,  
    @PageSize INT = 10,  
    @IsFilter BIT = 0 ,
	@Mode varchar(50) = 'All'
AS  
BEGIN  
    DECLARE @PreviousFromDate DATETIME = DATEADD(DAY, -DATEDIFF(DAY, @FromDate, @Todate) - 1, @FromDate);  
    DECLARE @PreviousToDate DATETIME = DATEADD(DAY, -DATEDIFF(DAY, @FromDate, @Todate) - 1, @Todate);  
  
    -- Declare variables for pagination if not skipping  
    DECLARE @Offset INT, @Fetch INT;  
  
    IF (@IsFilter = 0)  -- If IsFilter is not set, apply pagination  
    BEGIN  
        -- Apply pagination logic  
        SET @Offset = (@PageNumber - 1) * @PageSize;  
        SET @Fetch = @PageSize;  
    END  
  
    DECLARE @ParentId BIGINT;  
    SELECT @ParentId = ParentId FROM User_Detail (NOLOCK) WHERE User_Id = @UserID;  
  
    DROP TABLE IF EXISTS #tempUsers;  
    CREATE TABLE #tempUsers(User_ID BIGINT, Name NVARCHAR(255), Image NVARCHAR(255));  
  
    INSERT INTO #tempUsers(User_ID, Name, Image)  
    EXEC Use_GetUserDetails @UserID = @UserID;  
  
    -- Pre-Aggregate Previous Period Data  
 DROP TABLE IF EXISTS #PrevTotal;  
    CREATE TABLE #PrevTotal (UserID BIGINT, SpendTime BIGINT);  
    INSERT INTO #PrevTotal (UserID, SpendTime)  
    SELECT   
        tem.UserID,  
        SUM(ted.SpendTime) AS SpendTime  
    FROM tbl_user_engagement_track_master (NOLOCK) tem  
    INNER JOIN tbl_user_engagement_track_details ted ON ted.UserEngMasterId = tem.EngagementID  
    WHERE ted.CreatedDate >= @PreviousFromDate AND ted.CreatedDate < DATEADD(DAY, 1, @PreviousToDate)  
    GROUP BY tem.UserID;  
  
    -- Main Query  
    DECLARE @query NVARCHAR(MAX);  
    SET @query = '  
        SELECT   
    tem.UserID,  
    COUNT(*) OVER () AS TotalRecords,  
    CASE  
        WHEN SUM(tem.SpendTime) > MAX(ISNULL(pt.SpendTime, 0)) THEN ''Up''  
        WHEN SUM(tem.SpendTime) < MAX(ISNULL(pt.SpendTime, 0)) THEN ''Down''  
        ELSE ''Same''  
    END AS Lag,  
    CONCAT(FORMAT(CAST(@FromDate AS DATE), ''dd-MMM-yyyy''), '' to '', FORMAT(CAST(@Todate AS DATE), ''dd-MMM-yyyy'')) AS Period,  
    CONCAT(ud.ParentID, '' ('', MAX(pud.User_Login), '')'') AS [Parentlogin],  
    CONCAT(ud.User_ID, '' ('', MAX(ud.User_Login), '')'') AS [UserLogin],  
    MAX(tem.Mode) AS Mode,  
    CONCAT(  
        FLOOR(SUM(tem.SpendTime) / 3600), '' h '',  
        FLOOR(CAST(SUM(tem.SpendTime) AS INT) % 3600 / 60), '' m '',  
        CAST(SUM(tem.SpendTime) AS INT) % 60, '' s''  
    ) AS [ActiveTime],  
    CONCAT(  
        FLOOR(SUM(tem.InactiveTime) / 3600), '' h '',  
        FLOOR(CAST(SUM(tem.InactiveTime) AS INT) % 3600 / 60), '' m '',  
        CAST(SUM(tem.InactiveTime) AS INT) % 60, '' s''  
    ) AS [PassiveTime],  
    COUNT(DISTINCT tem.PageURL) AS [pages],  
    CONCAT(  
        FLOOR(ROUND(CAST(SUM(tem.SpendTime) AS INT) / COUNT(DISTINCT tem.EngagementID), 2) / 3600), '' h '',  
        FLOOR(ROUND(CAST(SUM(tem.SpendTime) AS INT) / COUNT(DISTINCT tem.EngagementID), 2) % 3600 / 60), '' m '',  
        ROUND(CAST(SUM(tem.SpendTime) AS INT) / COUNT(DISTINCT tem.EngagementID), 2) % 60, '' s''  
    ) AS [AvgTime]  
FROM (  
    SELECT   
        tem.UserID,  
        ted.Mode,  
        ted.SpendTime,  
        ted.InactiveTime,  
        tem.PageURL,  
        tem.EngagementID,  
        ted.CreatedDate  
    FROM tbl_user_engagement_track_master (NOLOCK) tem  
    INNER JOIN tbl_user_engagement_track_details ted ON ted.UserEngMasterId = tem.EngagementID  
) tem  
LEFT JOIN #tempUsers tu ON tem.UserID = tu.User_ID  
LEFT JOIN User_Detail ud ON tem.UserID = ud.User_ID  
LEFT JOIN User_Detail pud ON ud.ParentID = pud.User_ID  
LEFT JOIN #PrevTotal pt ON pt.UserID = tem.UserID  
WHERE   
    --(  
    --    (@UserID = @ParentId AND tu.User_ID = tem.UserID)  
    --    OR  
    --    (@UserID <> @ParentId AND tem.UserID = @UserID)  
    --)  
  ud.M_ID  = (select rd.Reseller_ID from User_Detail ud join reseller_detail rd ON rd.User_ID = ud.User_ID where  ud.User_ID = @UserID)  
    AND FORMAT(tem.CreatedDate, ''yyyy-MM-dd'') BETWEEN CAST(@FromDate AS DATE) AND CAST(@Todate AS DATE)  
	AND tem.mode =   (case when @Mode =''All''  then tem.mode  else @mode   end ) 

GROUP BY   
    tem.UserID,  
    ud.ParentID,  
    ud.User_ID,
	tem.Mode

ORDER BY   
    tem.UserID DESC';  
  
    -- If pagination is enabled, append OFFSET and FETCH logic  
    IF (@IsFilter = 0)  -- If IsFilter is not set, apply pagination  
    BEGIN  
        SET @query = @query + ' OFFSET ' + CAST(@Offset AS NVARCHAR(10)) + ' ROWS FETCH NEXT ' + CAST(@Fetch AS NVARCHAR(10)) + ' ROWS ONLY;';  
    END  
  
    -- Execute the dynamic query  
    EXEC sp_executesql @query, N'@FromDate DATETIME, @Todate DATETIME, @UserID NVARCHAR(50), @ParentId BIGINT ,  @Mode varchar(50)', @FromDate, @Todate, @UserID, @ParentId , @Mode;  
 PRINT @query  
    -- Drop Temp Tables  
    DROP TABLE #tempUsers;  
    DROP TABLE #PrevTotal;  
END;  


GO

