   Procedure: [dbo].[Usp_getUserAutoSuggest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getUserAutoSuggest --'Abhi0'      
(      
  @SearchFilter nvarchar(max)      
)      
as      
Begin      
     -- select  @SearchFilter = RTRIM(LTRIM(@SearchFilter))          
      
   SELECT distinct User_Login, User_Login + ' (' + (isnull( FName,'') + ' ' + isnull(LName,'')) + ')' as NameDetails, User_ID   from User_Detail with(nolock)       
  where User_Login like ''+ @SearchFilter +'%'      
          or       
          (isnull( FName,'') + ' ' + isnull(LName,'')) like  '' + @SearchFilter +'%'    
    OR ( isnull( FName,'')  like  '' + @SearchFilter +'%' )     
    OR ( isnull( LName,'')  like  '' + @SearchFilter +'%' )     
  
  
   
 End   
  
  
  
  
 SELECT distinct User_Login, User_Login + ' (' + (isnull( FName,'') + ' ' + isnull(LName,'')) + ')' as NameDetails, User_ID   from User_Detail with(nolock)       
  where User_Login like ''+ @SearchFilter +'%'      
          or       
          (isnull( FName,'') + ' ' + isnull(LName,'')) like  '' + @SearchFilter +'%'    
    OR ( isnull( FName,'')  like  '' + @SearchFilter +'%' )     
    OR ( isnull( LName,'')  like  '' + @SearchFilter +'%' )     
  
  
  
 


