/* ============================================================
   Procedure: [dbo].[usp_GetUserByTerritory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_GetUserByTerritory 32222,0
-- Exec usp_GetUserByTerritory 32222,16
CREATE   PROC dbo.usp_GetUserByTerritory (
	@UserId BIGINT
	,@TerritoryId BIGINT = 0
	)
AS
BEGIN
	-- declare @UserId bigint=33819, @TerritoryId bigint=0
	DECLARE @isadmin BIT = 0
		,@ParentId BIGINT = 0

	SELECT @isadmin = isadmin
		,@ParentId = ParentId
	FROM user_detail(NOLOCK)
	WHERE user_id = @UserId

	IF (@UserId = @ParentId)
	BEGIN
		SET @isadmin = 1
	END

	IF (@isadmin = 1)
	BEGIN
		SELECT LTM.User_Id
			,LTM.PersonName AS UserName
			,LTM.ROLE
			,LTM.Territory_Id
		FROM User_Detail UD
		INNER JOIN tbl_location_territory_mapping LTM ON UD.User_Id = LTM.User_ID
		WHERE UD.ParentID = @ParentId
			AND LTM.Territory_Id = CASE 
				WHEN @TerritoryId = 0
					THEN LTM.Territory_Id
				ELSE @TerritoryId
				END
	END
	ELSE
	BEGIN
		SELECT 0 AS User_Id
			,'Unauthorized User' AS UserName
			,'No Role' AS ROLE
			,0 AS Territory_Id
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_UsrLocatn'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_location_territory_mapping'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCampaignmaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
        
CREATE   PROCEDURE [dbo].[usp_GetUserCampaignmaster] --34594,1,1              
              
 @ParentID BIGINT,              
              
 @IsActive BIT,              
              
 @IsInActive BIT              
              
AS              
              
BEGIN              
              
 SELECT A.ID,              
              
        A.CampaignName,              
              
        (              
              
            '<p><b> Type:</b> ' + CASE               
              
                                       WHEN A.IsEventBased = 1 THEN               
              
                                            'Event based (' + CASE               
              
                                                                   WHEN A.EventsName               
              
                                                                                      
              
                                                                                      
              
                                                                                      
              
                                                                        =              
              
                                                                                      
              
                                                                        'ENQADD' THEN               
              
                                                                        'Enquiry Added'              
              
                                                                   ELSE CASE               
              
                                                                             WHEN               
              
                                                                                  A.EventsName               
              
                                                                                                
              
                                                                                                
              
                                                                                                
              
                                                                                  =              
              
                                                                                                
              
                                                                                                
              
                                                                                                
              
                                                                                  'LEDADD' THEN               
              
                                                                                  'Lead Added'              
              
                                                                             ELSE               
              
                                                                                  'Follow Up Added'              
              
                                                                        END              
              
                                                              END + ')'              
              
                                       ELSE 'Scheduled'              
              
                                  END + '</p>' + '<p><b> Medium:</b> ' + CASE               
              
                                                                              WHEN               
              
                                                                                   A.MailReplyTo               
              
                                                                                                 
              
                                                                                                 
              
                                                                      
              
                                                                                   =       
              
                                                                                                 
              
                                    
              
                                                                                                 
              
                                    '' THEN               
              
                                                                                   'SMS'              
              
                                          ELSE               
              
                                                                                   'Mail'              
              
                           END               
              
                          
              
                          
              
                          
              
            + '</p>'              
              
        )                AS CampaignType,              
              
        (              
              
            CASE               
              
                 WHEN ISNULL(A.ApplicabiltyName, '') <> '' THEN               
              
                      '<p><b> Applicabilty:</b> ' + ISNULL(A.ApplicabiltyName, '')               
              
                                    
              
                                    
              
                                    
              
                      + ',' + ISNULL(A.AppGroups, '') + ',' + ISNULL(A.AppLists, '')               
              
                                    
              
                                    
              
                                    
              
                      + '</p>'              
              
                 ELSE ''              
              
            END + CASE               
              
                       WHEN ISNULL(A.InclusionsNumber, '') <> '' THEN               
              
                            '<p><b> Included Number:</b> ' + A.InclusionsNumber               
              
                                          
              
                                          
              
                                          
              
                            + '</p>'              
              
                       ELSE ''              
              
                  END + CASE               
              
                             WHEN ISNULL(A.ExclusionsName, '') <> '' THEN               
              
                                  '<p><b> Exclusions:</b> ' + ISNULL(A.ExclusionsName, '')               
              
                                                
              
                                                
              
                                                
              
                                  + ',' + ISNULL(A.ExclusionsGroups, '') +              
              
                                                
              
                                                
              
                                                
              
                                  ',' +              
              
                                                
              
                                                
              
                                                
              
                                  ISNULL(A.ExclusionsLists, '') + '</p>'              
              
                             ELSE ''              
              
                        END + CASE               
              
                                   WHEN ISNULL(A.ExclusionsNumber, '') <>              
              
                                                      
              
                                                      
              
               
              
                                        '' THEN               
              
                                        '<p><b> Excluded Numbers:</b> ' + A.ExclusionsNumber               
              
                                                      
              
                                                      
              
       
              
                                        + '</p>'              
              
                                   ELSE ''              
              
                              END              
                                          
                              +            
                              '<p><b> IsSurplusExclusions:</b> ' + CASE               
              
                                                                                WHEN               
              
                                                                                     A.IsSurplusExclusions               
              
                                                                                                   
              
                                 
              
                                                                                                   
              
                                                                                     =              
              
                                                                                                   
              
                                                                                                   
              
                                                                                                   
              
                                                                                     1 THEN               
              
                                                                                     'Yes'              
              
                                                                                ELSE               
              
                                                     'No'              
              
                                                                           END               
              
                                                            
              
                                                            
              
                                                            
              
                                              + '</p>'                      
            
                                          
              
        )                AS Recipients,              
              
        (              
              
            CASE               
              
                 WHEN ISNULL(A.AccountUsed, '') <> '' THEN               
              
                      '<p><b> Account:</b> ' + A.AccountUsed + '</p>'              
              
                 ELSE ''              
              
            END + CASE               
              
                       WHEN ISNULL(A.SenderID, '') <> '' THEN               
              
                            '<p><b> Sender-ID:</b> ' + A.SenderID + '</p>'              
              
                       ELSE ''              
              
                  END        
                  +        
                          
                  CASE               
              
                       WHEN ISNULL(A.FromMailID, '') <> '' THEN               
              
                            '<p><b> FromMailID:</b> ' + A.FromMailID + '</p>'              
              
                       ELSE ''              
              
                  END        
                          
                          
                   + CASE               
              
                             WHEN ISNULL(A.TEMPLATEused, '') <> '' THEN               
              
                                  '<p><b>Template:</b> ' +              
              
                                                
              
                                                
              
                                                
              
                                  A.TEMPLATEused + '</p>'              
              
                             ELSE ''              
              
                        END + CASE               
              
                                   WHEN ISNULL(A.TEMPLATEGroup, '') <> '' THEN               
              
                '<p><b>Template Group:</b> ' + A.TEMPLATEGroup               
              
                                                      
              
                                                      
              
                                                      
              
                                        +              
              
                                                      
              
                                                      
              
                                                      
              
                                        '</p><p><b>Sequence No&nbsp;:&nbsp;</b>'               
              
                                                      
              
                                                      
              
                                                      
              
                                        + CAST(A.TemplateGroupSequence AS VARCHAR(50))               
              
                                                      
              
                                                      
              
                                                      
              
                                        + '</p><p>' + CASE            
              
                                                           WHEN A.IsRecurring               
              
                                                                              
              
                                                
              
                                                                              
              
                                                                = 1 THEN               
              
                                                                'Recurring'              
              
                                                           ELSE               
              
                                                                'Ends After Group Template count Ends'              
              
                                                      END + '</p>'              
              
                                   ELSE ''              
              
                              END + CASE               
              
                                         WHEN ISNULL(A.[Message], '') <> '' THEN               
              
                                              '<p><b>Message:</b> ' + A.[Message]               
              
                                                            
              
                                                            
              
                                                            
              
                                              + '</p>'               
              
                                                            
              
                                                            
              
                                                            
              
                                              + '<p><b> IsUnicode:</b> ' + CASE               
              
                                                                                WHEN               
              
                                              A.IsUnicode               
              
                                                                                                   
     
                                                                                                   
              
                                                                                                   
              
                                                                                     =              
              
                                                                                                   
              
                                                                                                   
              
                                                                                                   
              
                                     1 THEN               
              
                                                                                     'Yes'              
              
                                                                                ELSE               
              
                                                                                     'No'              
              
                                                                           END               
              
                                                            
              
                                                            
              
                                                            
              
                                              + '</p>'              
              
                                         ELSE ''              
              
                                    END + CASE               
              
                                               WHEN ISNULL(A.MailReplyTo, '')               
              
                                                                  
              
                                                                  
              
                                                                  
              
                                                    <> '' THEN               
              
                                                    '<p><b>  Reply To:</b> '               
              
                                                                  
              
           
              
                                                                  
              
                                                    + A.MailReplyTo + '</p>'              
              
                                               ELSE ''              
              
                                          END + CASE               
              
                                                     WHEN ISNULL(A.MailSubject, '')               
              
                                                                        
              
                               
              
                                                                        
              
                                                          <> '' THEN               
              
                                                          '<p><b>  Subject:</b> '               
              
                                                                        
              
                                                                        
              
                                                               
              
                                                          + A.MailSubject +              
              
                                                                        
              
                                                                        
              
                                
              
                                                          '</p>'              
              
                                                     ELSE ''              
              
                                                END + CASE               
              
                                                           WHEN ISNULL(A.MailContent, '')               
              
                                                                              
              
                                                                              
              
                                                                              
              
                                                                <> '' THEN               
              
                                                                '<p><b>   Content:</b> '               
              
                                                                              
              
                                                                          
              
                                 
              
                                                                + A.MailContent               
              
                                                                              
              
                                                                              
              
                                                                              
              
                                                                + '</p>'              
              
                                                           ELSE ''              
              
                                                      END              
              
        )                AS Accounts,              
              
        (              
              
            CASE               
              
                 WHEN ISNULL(A.TrackResponse, '') <> '' THEN               
              
                      '<p><b>  Track Response:</b> '               
              
                      
              
                                    
              
                                    
              
                      + A.TrackResponse + '</p>'              
              
                 ELSE ''              
              
            END + CASE               
              
                       WHEN ISNULL(A.UnsubscribePage, '')               
              
                                          
              
                                          
              
                                          
              
                            <> '' THEN '<p><b>  Unsubscribe Page:</b> ' + A.UnsubscribePage               
              
                                          
              
                                          
              
                                          
              
                            + '</p>'              
              
                       ELSE ''              
              
                  END + CASE               
              
                             WHEN ISNULL(A.Tags, '') <> '' THEN               
              
                                  '<p><b>  Tags:</b> ' + A.Tags +              
              
                                                
              
                                                
              
                                                
              
                                  '</p>'              
              
                             ELSE ''              
              
                        END              
              
        )                AS Tracking,              
              
        (              
              
            CASE               
              
                 WHEN ISNULL(A.StartDate, '') <> '' THEN               
              
                      '<p><b>  Start Date at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate)  AS VARCHAR(50))               
              
                                    
              
                                    
              
                                    
              
              + '</p>'              
              
                 ELSE ''              
              
            END + CASE               
              
                       WHEN ISNULL(A.ExpiryDate, '') <> '' THEN               
              
               '<p><b>  Expiry Date:</b> ' + CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) AS VARCHAR(50))               
              
                                          
              
                                          
              
                                          
              
                            + '</p>'              
              
                       ELSE ''              
              
                  END + CASE               
              
                             WHEN ISNULL(A.SceduleName, '') <> '' THEN               
              
                 '<p><b>  Scheduled:</b> ' +              
              
                                                
              
                                                
              
                  
              
                                  A.SceduleName + '</p>'              
              
                             ELSE ''              
              
                        END + CASE               
              
                                   WHEN ISNULL(A.ExecutedDateTime, '') <>              
              
                                                      
              
                                                  
              
                                                      
              
                                        '' THEN '<p><b>  Executed at:</b> ' +              
              
                                                      
              
                                                      
              
                                                      
              
                                        CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) AS VARCHAR(50))               
              
                                                      
              
                                                      
              
                                                      
              
                                        +              
              
            
              
                                                      
              
                                                      
              
                                        '</p>'              
              
                                   ELSE ''              
              
                              END + CASE               
              
                                         WHEN ISNULL(A.NextExecuteDateTime, '')               
              
                                                            
              
                                                            
              
                                                            
              
                                              < > '' THEN               
              
                                              '<p><b>  Next Execution at:</b> '               
              
                                                            
              
                                                            
              
                                                            
              
                        + CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) AS VARCHAR(50))               
              
                                                            
              
                                                            
              
                                                            
              
              +              
              
                                                            
              
                                                            
              
                                                           
              
                                              '</p>'              
              
                                         ELSE ''              
              
                                    END               
              
                          
              
            +              
              
                          
              
                          
              
                          
              
            CASE               
              
                 WHEN ISNULL(A.LastScheduledRunTime, '')               
              
                                    
              
                                    
              
                                    
              
                      = '' THEN '<p><b>Last Scheduled Run Time:</b> '               
              
                                    
              
                                    
              
                                    
              
                      + 'Never'               
              
                                    
              
                                    
              
                                    
              
                      +              
              
                                  
              
                                    
              
                                    
              
                      '</p>'              
              
                 ELSE '<p><b>Last Scheduled Run Time:</b> '               
              
                                    
              
                                    
              
                                    
              
                      + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.LastScheduledRunTime) AS VARCHAR(50))               
              
                                    
              
                      +              
              
                                    
              
                      '</p>'              
              
            END              
              
        )        AS Scheduling,              
              
        CASE               
              
             WHEN ISNULL(A.NotificationMail, '') <>              
              
                                
              
                                
              
                                
              
                  '' THEN '<p><b>Notification EMail:</b> ' + CAST(A.NotificationMail AS VARCHAR(250))               
              
                                
              
                                
              
                                
              
                  + '</p>'              
              
             ELSE ''              
              
        END + CASE               
              
                   WHEN ISNULL(A.SuccessNotificationEmail, '') <>              
              
                                      
              
                                      
              
                                      
              
                        '' THEN '<p><b>Success Notification:</b> ' + CAST(A.SuccessNotificationEmail AS VARCHAR(250))               
              
                                      
              
                                      
              
                                      
              
                        + '</p>'              
              
                   ELSE ''              
              
              END + CASE               
              
                         WHEN ISNULL(A.FailureNotificationEmail, '') <> '' THEN               
              
                              '<p><b>Failure Notification:</b> ' +              
              
                                            
              
                                            
              
                                            
              
                              CAST(A.FailureNotificationEmail AS VARCHAR(250))               
              
                                            
              
                               
              
                                            
              
                              + '</p>'              
              
                         ELSE ''              
              
                    END  AS Notifications,              
              
        A.IsEventBased,              
              
        A.IsScheduled,              
              
        A.SceduleName,              
              
      --  A.ExecutedDateTime,              
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) as ExecutedDateTime,      
              
      --  A.NextExecuteDateTime,       
        dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) as NextExecuteDateTime,      
              
        A.Applicabilty,              
              
        A.ApplicabiltyName,              
              
        A.ExclusionsName,              
              
        A.ExclusionsNumber,              
              
        A.InclusionsNumber,              
              
        A.Exclusions,              
              
        A.SenderID,              
              
        A.[Message],              
              
        A.IsUnicode,              
              
        A.MailReplyTo,              
              
        A.MailSubject,              
              
        A.MailContent,              
              
        A.UnsubscribePage,              
              
        A.TrackResponse,              
              
        A.Tags,              
              
        --A.ExpiryDate,      
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) as ExpiryDate,            
              
        A.User_Login,              
              
       -- A.CreatedOn,              
       dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,            
       convert( nvarchar(50), dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn),13) as CreatedOn1,      
        A.IsActive,              
              
        A.NotificationMail,              
              
        A.SuccessNotificationEmail,              
              
        A.FailureNotificationEmail,              
              
        A.IsRecurring,              
              
        A.IsEnding,              
              
        A.TemplateGroupSequence,              
              
        A.IsNeverExpire,              
              
        A.EventsName ,            
        A.IsSurplusExclusions,          
              
              
        --A.StartDate ,        
              
        dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) as StartDate,      
              
        A.FromMailID,  
  A.Medium            
                     
              
 FROM   (              
              
            SELECT ucm.ID,              
                   ucm.Medium,            
                   ucm.CampaignName,        
                   ucm.FromMailID,            
              
                   ucm.IsEventBased,              
              
                   ucm.IsScheduled,              
              
                   ucm.StartDate,              
              
                   us.SceduleName,              
              
                   (              
              
                       SELECT TOP 1 uceh.ExecutionTime              
              
                       FROM   UserCampaignExecutionHistory AS uceh              
              
                       WHERE  uceh.CampaignID = ucm.ID              
              
         ORDER BY              
              
                              uceh.ExecutionTime DESC              
              
                   )                   AS ExecutedDateTime,              
              
                   ucm.NextExecuteDateTime,              
              
                   (              
              
                       SELECT STUFF(              
              
                                  (              
                          SELECT N', ' +                                 
                                          usl.CriteriaName + ' (' + 
                                                                               usl.CriteriaType               
                                                     +                
                                            ')'              
              
                             FROM   tbl_SearchCriteria(nolock) AS usl              
              
                                             INNER JOIN dbo.fn_Split(ucm.Applicabilty, '#') AS               
              
                                                  fs              
              
                       ON  usl.ID = fs.[value] FOR               
              
                                                                    
              
                                                                    
              
                                                                    
              
                                            XML PATH(''),              
              
                                             TYPE              
              
                                  ) .value('text()[1]', 'nvarchar(max)'),              
              
                                  1,              
              
                                  2,              
              
                                  N''              
              
                              )              
              
                   )                   AS ApplicabiltyName,              
              
                   ucm.Applicabilty,              
              
                   ucm.ExclusionsNumber,              
                    (              
                       SELECT STUFF(              
              
                                  (         
                                      SELECT N', ' + usl.CriteriaName +              
              
                                             ' (' +               
                                                        usl.CriteriaType               
                                              + ')'              
              
                                      FROM   tbl_SearchCriteria(nolock) AS usl              
                                             INNER JOIN dbo.fn_Split(ucm.Exclusions, '#') AS               
                                                  fs              
                                                  ON  usl.ID = fs.[value] FOR               
              
                                                      XML PATH(''),              
              
                                             TYPE              
              
                                  ) .value('text()[1]', 'nvarchar(max)'),              
              
                                  1,              
              
                                  2,              
              
                                  N''              
              
                              )              
              
                   )                   AS ExclusionsName,              
              
                   (              
                       SELECT STUFF(              
                                  (              
                                    SELECT N', ' + gd.Group_Name +              
                                                           
                                             ' (Groups)'              
              
                                      FROM   Group_Detail AS gd              
              
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS               
              
                                                  fs              
              
                                                  ON  gd.Group_ID = fs.[value]               
              
                                                                    
              
                                                                    
              
                                                                    
              
                                                      FOR XML PATH(''),              
              
                                             TYPE              
              
                                  ) .value('text()[1]', 'nvarchar(max)'),              
              
                                  1,              
              
                                  2,              
              
                                  N''              
              
                              )              
              
                  )                   AS ExclusionsGroups,              
              
                   (              
              
                       SELECT STUFF(              
              
                                  (              
              
                                      SELECT N', ' + gd.ImportName +              
              
                                                           
              
                                                           
              
                                                           
              
                                             ' (Imported Lists)'              
              
                                      FROM   UserImportedListColumn AS gd              
              
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS               
              
                                                  fs              
              
                                        ON  gd.ID = fs.[value] FOR               
              
                                                                    
              
                                                                    
              
                                                                    
              
                                                      XML PATH(''),              
              
                                             TYPE              
              
                                  ) .value('text()[1]', 'nvarchar(max)'),              
              
                                  1,              
              
                                  2,              
              
                                  N''              
              
                              )              
              
                   )                   AS ExclusionsLists,              
              
                   (              
              
          SELECT STUFF(              
              
                                  (              
              
                                      SELECT N', ' + gd.Group_Name +              
              
                                             ' (Groups)'              
              
                                      FROM   Group_Detail AS gd              
              
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS               
              
                                                  fs              
              
                                                  ON  gd.Group_ID = fs.[value]               
              
                                                                    
              
                                                                    
              
                                                                    
              
                                                      FOR XML PATH(''),              
              
                                             TYPE              
              
                                  ) .value('text()[1]', 'nvarchar(max)'),              
              
                                  1,              
              
                                  2,              
              
                                  N''              
              
                              )              
              
                   )                   AS AppGroups,              
              
       (              
              
                       SELECT STUFF(              
              
                                  (              
              
                                      SELECT N', ' + gd.ImportName +              
              
                                                           
   
                                                           
              
                                                           
              
                                             ' (Imported Lists)'              
              
     FROM   UserImportedListColumn AS gd              
              
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS               
              
                                                  fs              
              
                                                  ON  gd.ID = fs.[value] FOR             
              
                                                                    
              
                                                                    
              
                                                                    
              
                                                      XML PATH(''),              
              
                                             TYPE              
              
                                  ) .value('text()[1]', 'nvarchar(max)'),              
              
                                  1,              
              
                                  2,              
              
                                  N''              
              
                         )              
              
                   )                   AS AppLists,              
              
                   ucm.InclusionsNumber,              
              
                   ucm.Exclusions,              
              
                   ucm.SenderID,              
              
                   ucm.[Message],              
              
                   ucm.IsUnicode,              
              
                   ucm.MailReplyTo,              
              
                   ucm.MailSubject,              
              
                   ucm.MailContent,              
              
                   (              
              
                       SELECT TOP 1 cpd.PageName              
              
                       FROM   ClientPageDetail cpd              
              
                       WHERE  cpd.Id = ucm.TrackResponse              
              
                   )                   AS TrackResponse,              
              
                   (              
              
                       SELECT TOP 1 cpd.PageName              
              
                       FROM   ClientPageDetail cpd              
              
                       WHERE  cpd.Id = ucm.UnsubscribePage              
              
                   )                   AS UnsubscribePage,              
              
                   ucm.Tags,              
              
                   ucm.ExpiryDate,             
              
                   ucm.CreatedOn,              
              
                   ucm.IsActive,              
              
                   ud.User_Login,              
              
                   (              
              
                       SELECT ud.User_Login              
              
                       FROM   User_Detail ud              
              
                       WHERE  ud.[User_ID] = ucm.AccountUsed              
              
                   )                   AS AccountUsed,              
              
                   (              
              
                       SELECT TOP 1 umt.Name              
              
                       FROM   UserMailTemplate               
              
                                            
              
                                            
              
                                            
              
                              umt              
              
                       WHERE  umt.ID = ucm.TemplateID              
              
                   )                   AS TEMPLATEused,              
              
                   (   
              
                       SELECT utgd.GroupName              
              
                       FROM   UserTemplateGroupDetails utgd              
              
                       WHERE  utgd.ID = ucm.TemplateGroupID              
              
       )                   AS TEMPLATEGroup,              
              
                   ucm.NotificationMail,              
              
                   ucm.SuccessNotificationEmail,              
              
                   ucm.FailureNotificationEmail,              
              
                   ucm.IsRecurring,              
              
                   ucm.IsEnding,              
              
                   ucm.TemplateGroupSequence,              
              
                   ucm.IsNeverExpire,            
           ucm.IsSurplusExclusions,              
              
                   ucm.EventsName,              
              
                  (SELECT TOP 1 ucerm.ExecutionTime               
              
                     FROM UserCampaignExecutionHistory AS ucerm WHERE ucerm.CampaignID=ucm.ID ORDER BY ucerm.ExecutionTime DESC)  AS LastScheduledRunTime              
              
            FROM   UserCampaignMaster  AS ucm              
              
                   LEFT JOIN UserSchedules AS us              
              
                        ON  ucm.ScheduleID = us.ID         
              
                   LEFT JOIN User_Detail AS UD(NOLOCK)              
              
                        ON  ucm.Createdby = UD.User_ID               
              
            WHERE  ucm.ParentID = @ParentID   and  isnull(UCM.EventID,0) = 0            
              
                   AND (              
              
                           ucm.IsActive = CASE               
              
                                               WHEN @IsActive = 1 THEN 1              
              
                                               ELSE NULL              
              
                                          END              
              
                           OR ucm.IsActive = CASE               
              
                                                  WHEN @IsinActive = 1 THEN 0              
              
                                                  ELSE NULL              
              
                                             END              
              
                       )              
              
        )               
              
                      
              
                      
              
                      
              
        A              
              
 ORDER BY              
              
        A.CreatedOn DESC              
              
END         


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCampaignmaster_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE [dbo].[usp_GetUserCampaignmaster_INTDateTime] --17626,1,1        
        
 @ParentID BIGINT,        
        
 @IsActive BIT,        
        
 @IsInActive BIT        
        
AS        
        
BEGIN        
        
 SELECT A.ID,        
        
        A.CampaignName,        
        
        (        
        
            '<p><b> Type:</b> ' + CASE         
        
                                       WHEN A.IsEventBased = 1 THEN         
        
                                            'Event based (' + CASE         
        
                                                                   WHEN A.EventsName         
        
                                                                                
        
                                                                                
        
                                                                                
        
                                                                        =        
        
                                                                                
        
                                                                        'ENQADD' THEN         
        
                                                                        'Enquiry Added'        
        
                                                                   ELSE CASE         
        
                                                                             WHEN         
        
                                                                                  A.EventsName         
        
                                                                                          
        
                                                                                          
        
                                                                                          
        
                                                                                  =        
        
                                                                                          
        
                                                                                          
        
                                                                                          
        
                                                                                  'LEDADD' THEN         
        
                                                                                  'Lead Added'        
        
                                                                             ELSE         
        
                                                                                  'Follow Up Added'        
        
                                                                        END        
        
                                                              END + ')'        
        
                                       ELSE 'Scheduled'        
        
                                  END + '</p>' + '<p><b> Medium:</b> ' + CASE         
        
                                                                              WHEN         
        
                                                                                   A.MailReplyTo         
        
                                                                                           
        
                                                                                           
        
                                                                                           
        
                                                                                   =        
        
                                                                                           
        
                                                                                           
        
                                                                                           
        
                                    '' THEN         
        
                                                                                   'SMS'        
        
                                          ELSE         
        
                                                                                   'Mail'        
        
                           END         
        
                    
        
                    
        
                    
        
            + '</p>'        
        
        )                AS CampaignType,        
        
        (        
        
            CASE         
        
                 WHEN ISNULL(A.ApplicabiltyName, '') <> '' THEN         
        
                      '<p><b> Applicabilty:</b> ' + ISNULL(A.ApplicabiltyName, '')         
        
                              
        
                              
        
                              
        
                      + ',' + ISNULL(A.AppGroups, '') + ',' + ISNULL(A.AppLists, '')         
        
                              
        
                              
        
                              
        
                      + '</p>'        
        
                 ELSE ''        
        
            END + CASE         
        
                       WHEN ISNULL(A.InclusionsNumber, '') <> '' THEN         
        
                            '<p><b> Included Number:</b> ' + A.InclusionsNumber         
        
                                    
        
                                    
        
                                    
        
                            + '</p>'        
        
                       ELSE ''        
        
                  END + CASE         
        
                             WHEN ISNULL(A.ExclusionsName, '') <> '' THEN         
        
                                  '<p><b> Exclusions:</b> ' + ISNULL(A.ExclusionsName, '')         
        
                                          
        
                                          
        
                                          
        
                                  + ',' + ISNULL(A.ExclusionsGroups, '') +        
        
                                          
        
                                          
        
                                          
        
                                  ',' +        
        
                                          
        
                                          
        
                                          
        
                                  ISNULL(A.ExclusionsLists, '') + '</p>'        
        
                             ELSE ''        
        
                        END + CASE         
        
                                   WHEN ISNULL(A.ExclusionsNumber, '') <>        
        
                                                
        
                                                
        
                                                
        
                                        '' THEN         
        
                                        '<p><b> Excluded Numbers:</b> ' + A.ExclusionsNumber         
        
                                                
        
                                                
        
                                                
        
                                        + '</p>'        
        
                                   ELSE ''        
        
                              END        
                                    
                              +      
                              '<p><b> IsSurplusExclusions:</b> ' + CASE         
        
                                                                                WHEN         
        
                                                                                     A.IsSurplusExclusions         
        
                                                                                             
        
                           
        
                                                                                             
        
                                                                                     =        
        
                                                                                             
        
                                                                                             
        
                                                                                             
        
                                                                                     1 THEN         
        
                                                                                     'Yes'        
        
                                                                                ELSE         
        
                                                     'No'        
        
                                                                           END         
        
                                                      
        
                                                      
        
                                                      
        
                                              + '</p>'                
      
                                    
        
        )                AS Recipients,        
        
        (        
        
            CASE         
        
                 WHEN ISNULL(A.AccountUsed, '') <> '' THEN         
        
                      '<p><b> Account:</b> ' + A.AccountUsed + '</p>'        
        
                 ELSE ''        
        
            END + CASE         
        
                       WHEN ISNULL(A.SenderID, '') <> '' THEN         
        
                            '<p><b> Sender-ID:</b> ' + A.SenderID + '</p>'        
        
                       ELSE ''        
        
                  END  
                  +  
                    
                  CASE         
        
                       WHEN ISNULL(A.FromMailID, '') <> '' THEN         
        
                            '<p><b> FromMailID:</b> ' + A.FromMailID + '</p>'        
        
                       ELSE ''        
        
                  END  
                    
                    
                   + CASE         
        
                             WHEN ISNULL(A.TEMPLATEused, '') <> '' THEN         
        
                                  '<p><b>Template:</b> ' +        
        
                                          
        
                                          
        
                                          
        
                                  A.TEMPLATEused + '</p>'        
        
                             ELSE ''        
        
                        END + CASE         
        
                                   WHEN ISNULL(A.TEMPLATEGroup, '') <> '' THEN         
        
                                        '<p><b>Template Group:</b> ' + A.TEMPLATEGroup         
        
                                                
        
                                                
        
                                                
        
                                        +        
        
                                                
        
                                                
        
                                                
        
                                        '</p><p><b>Sequence No&nbsp;:&nbsp;</b>'         
        
                                                
        
                                                
        
                                                
        
                                        + CAST(A.TemplateGroupSequence AS VARCHAR(50))         
        
                                                
        
                                                
        
                                                
        
                                        + '</p><p>' + CASE      
        
                                                           WHEN A.IsRecurring         
        
                                                                        
        
                                          
        
                                                                        
        
                                                                = 1 THEN         
        
                                                                'Recurring'        
        
                                                           ELSE         
        
                                                                'Ends After Group Template count Ends'        
        
                                                      END + '</p>'        
        
                                   ELSE ''        
        
                              END + CASE         
        
                                         WHEN ISNULL(A.[Message], '') <> '' THEN         
        
                                              '<p><b>Message:</b> ' + A.[Message]         
        
                                                      
        
                                                      
        
                                                      
        
                                              + '</p>'         
        
                                                      
        
                                                      
        
                                                      
        
                                              + '<p><b> IsUnicode:</b> ' + CASE         
        
                                                                                WHEN         
        
                                              A.IsUnicode         
        
                                                                                             
        
                                                                                             
        
                                                                                             
        
                                                                                     =        
        
                                                                                             
        
                                                                                             
        
                                                                                             
        
                                                                                     1 THEN         
        
                                                                                     'Yes'        
        
                                                                                ELSE         
        
                                                                                     'No'        
        
                                                                           END         
        
                                                      
        
                                                      
        
                                                      
        
                                              + '</p>'        
        
                                         ELSE ''        
        
                                    END + CASE         
        
                                               WHEN ISNULL(A.MailReplyTo, '')         
        
                                                            
        
                                                            
        
                                                            
        
                                                    <> '' THEN         
        
                                                    '<p><b>  Reply To:</b> '         
        
                                                            
        
     
        
                                                            
        
                                                    + A.MailReplyTo + '</p>'        
        
                                               ELSE ''        
        
                                          END + CASE         
        
                                                     WHEN ISNULL(A.MailSubject, '')         
        
                                                                  
        
                         
        
                                                                  
        
                                                          <> '' THEN         
        
                                                          '<p><b>  Subject:</b> '         
        
                                                                  
        
                                                                  
        
                                                         
        
                                                          + A.MailSubject +        
        
                                                                  
        
                                                                  
        
                          
        
                                                          '</p>'        
        
                                                     ELSE ''        
        
                                                END + CASE         
        
                                                           WHEN ISNULL(A.MailContent, '')         
        
                                                                        
        
                                                                        
        
                                                                        
        
                                                                <> '' THEN         
        
                                                                '<p><b>   Content:</b> '         
        
                                                                        
        
                                                                    
        
                                                                        
        
                                                                + A.MailContent         
        
                                                                        
        
                                                                        
        
                                                                        
        
                                                                + '</p>'        
        
                                                           ELSE ''        
        
                                                      END        
        
        )                AS Accounts,        
        
        (        
        
            CASE         
        
                 WHEN ISNULL(A.TrackResponse, '') <> '' THEN         
        
                      '<p><b>  Track Response:</b> '         
        
                              
        
                              
        
                              
        
                      + A.TrackResponse + '</p>'        
        
                 ELSE ''        
        
            END + CASE         
        
                       WHEN ISNULL(A.UnsubscribePage, '')         
        
                                    
        
                                    
        
                                    
        
                            <> '' THEN '<p><b>  Unsubscribe Page:</b> ' + A.UnsubscribePage         
        
                                    
        
                                    
        
                                    
        
                            + '</p>'        
        
                       ELSE ''        
        
                  END + CASE         
        
                             WHEN ISNULL(A.Tags, '') <> '' THEN         
        
                                  '<p><b>  Tags:</b> ' + A.Tags +        
        
                                          
        
                                          
        
                                          
        
                                  '</p>'        
        
                             ELSE ''        
        
                        END        
        
        )                AS Tracking,        
        
        (        
        
            CASE         
        
                 WHEN ISNULL(A.StartDate, '') <> '' THEN         
        
                      '<p><b>  Start Date at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate)  AS VARCHAR(50))         
        
                              
        
                              
        
                              
        
                      + '</p>'        
        
                 ELSE ''        
        
            END + CASE         
        
                       WHEN ISNULL(A.ExpiryDate, '') <> '' THEN         
        
               '<p><b>  Expiry Date:</b> ' + CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) AS VARCHAR(50))         
        
                                    
        
                                    
        
                                    
        
                            + '</p>'        
        
                       ELSE ''        
        
                  END + CASE         
        
                             WHEN ISNULL(A.SceduleName, '') <> '' THEN         
        
                 '<p><b>  Scheduled:</b> ' +        
        
                                          
        
                                          
        
                                          
        
                                  A.SceduleName + '</p>'        
        
                             ELSE ''        
        
                        END + CASE         
        
                                   WHEN ISNULL(A.ExecutedDateTime, '') <>        
        
                                                
        
                                            
        
                                                
        
                                        '' THEN '<p><b>  Executed at:</b> ' +        
        
                                                
        
                                                
        
                                                
        
                                        CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) AS VARCHAR(50))         
        
                                                
        
                                                
        
                                                
        
                                        +        
        
                             
        
                                                
        
                                                
        
                                        '</p>'        
        
                                   ELSE ''        
        
                              END + CASE         
        
                                         WHEN ISNULL(A.NextExecuteDateTime, '')         
        
                                                      
        
                                                      
        
                                                      
        
                                              < > '' THEN         
        
                                              '<p><b>  Next Execution at:</b> '         
        
                                                      
        
                                                      
        
                                                      
        
                        + CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) AS VARCHAR(50))         
        
                                                      
        
                                                      
        
                                                      
        
              +        
        
                                                      
        
                                                      
        
                                                      
        
                                              '</p>'        
        
                                         ELSE ''        
        
                                    END         
        
                    
        
            +        
        
                    
        
                    
        
                    
        
            CASE         
        
                 WHEN ISNULL(A.LastScheduledRunTime, '')         
        
                              
        
                              
        
                              
        
                      = '' THEN '<p><b>Last Scheduled Run Time:</b> '         
        
                              
        
                              
        
                              
        
                      + 'Never'         
        
                              
        
                              
        
                              
        
                      +        
        
                              
        
                              
        
                              
        
                      '</p>'        
        
                 ELSE '<p><b>Last Scheduled Run Time:</b> '         
        
                              
        
                              
        
                              
        
                      + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.LastScheduledRunTime) AS VARCHAR(50))         
        
                              
        
                      +        
        
                              
        
                      '</p>'        
        
            END        
        
        )        AS Scheduling,        
        
        CASE         
        
             WHEN ISNULL(A.NotificationMail, '') <>        
        
                          
        
                          
        
                          
        
                  '' THEN '<p><b>Notification EMail:</b> ' + CAST(A.NotificationMail AS VARCHAR(250))         
        
                          
        
                          
        
                          
        
                  + '</p>'        
        
             ELSE ''        
        
        END + CASE         
        
                   WHEN ISNULL(A.SuccessNotificationEmail, '') <>        
        
                                
        
                                
        
                                
        
                        '' THEN '<p><b>Success Notification:</b> ' + CAST(A.SuccessNotificationEmail AS VARCHAR(250))         
        
                                
        
                                
        
                                
        
                        + '</p>'        
        
                   ELSE ''        
        
              END + CASE         
        
                         WHEN ISNULL(A.FailureNotificationEmail, '') <> '' THEN         
        
                              '<p><b>Failure Notification:</b> ' +        
        
                                      
        
                                      
        
                                      
        
                              CAST(A.FailureNotificationEmail AS VARCHAR(250))         
        
                                      
        
                         
        
                                      
        
                              + '</p>'        
        
                         ELSE ''        
        
                    END  AS Notifications,        
        
        A.IsEventBased,        
        
        A.IsScheduled,        
        
        A.SceduleName,        
        
      --  A.ExecutedDateTime,        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) as ExecutedDateTime,
        
      --  A.NextExecuteDateTime, 
        dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) as NextExecuteDateTime,
        
        A.Applicabilty,        
        
        A.ApplicabiltyName,        
        
        A.ExclusionsName,        
        
        A.ExclusionsNumber,        
        
        A.InclusionsNumber,        
        
        A.Exclusions,        
        
        A.SenderID,        
        
        A.[Message],        
        
        A.IsUnicode,        
        
        A.MailReplyTo,        
        
        A.MailSubject,        
        
        A.MailContent,        
        
        A.UnsubscribePage,        
        
        A.TrackResponse,        
        
        A.Tags,        
        
        --A.ExpiryDate,
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) as ExpiryDate,      
        
        A.User_Login,        
        
       -- A.CreatedOn,        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,      
        
        A.IsActive,        
        
        A.NotificationMail,        
        
        A.SuccessNotificationEmail,        
        
        A.FailureNotificationEmail,        
        
        A.IsRecurring,        
        
        A.IsEnding,        
        
        A.TemplateGroupSequence,        
        
        A.IsNeverExpire,        
        
        A.EventsName ,      
        A.IsSurplusExclusions,    
        
        
        --A.StartDate ,  
        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) as StartDate,
        
        A.FromMailID      
               
        
 FROM   (        
        
            SELECT ucm.ID,        
        
                   ucm.CampaignName,  
                   ucm.FromMailID,      
        
                   ucm.IsEventBased,        
        
                   ucm.IsScheduled,        
        
                   ucm.StartDate,        
        
                   us.SceduleName,        
        
                   (        
        
                       SELECT TOP 1 uceh.ExecutionTime        
        
                       FROM   UserCampaignExecutionHistory AS uceh        
        
                       WHERE  uceh.CampaignID = ucm.ID        
        
                       ORDER BY        
        
                              uceh.ExecutionTime DESC        
        
                   )                   AS ExecutedDateTime,        
        
                   ucm.NextExecuteDateTime,        
        
                   (        
        
                       SELECT STUFF(        
        
                                  (        
        
                                      SELECT N', ' +        
        
                                                     
        
                                                     
        
                                            
        
                                             usl.SearchName + ' (' + CASE         
        
                                                                          WHEN         
        
                                                                               usl.SearchType         
        
                                                                                       
        
                                                                                       
        
                                                                                       
        
                                                                               =        
        
                                                                                       
        
                                                                                       
        
                                                                                       
        
                                                                               'EN' THEN         
        
                                                                               'Enquiry'        
        
                                                                          ELSE CASE         
        
                                                                                    WHEN         
        
                                                              usl.SearchType         
        
                                                                                                 
        
                                                                                                 
        
                                     
        
                           =        
        
                                                                                                 
        
                                                                                                 
        
                                                                                                 
        
                                                                                         'LE' THEN         
        
                               'Leads'        
        
                                                                                    ELSE CASE         
        
                                                                                              WHEN         
        
                                                                                                   usl.SearchType         
        
                                                                                                           
        
                                                                                                           
        
                                                                                                           
        
                                                                                                   =        
        
                                                                                                           
        
                                                                                                           
        
                                                                                                           
        
                                                                                                   'Co' THEN         
        
                                                                                                   'Conversion'        
        
                                                                                              ELSE CASE         
        
                                                                                                        WHEN         
        
                                                                                                             usl.SearchType         
                                                                                                                           
        
                                                                                                                     
        
                                                                                                                     
        
                                                                                                             =        
        
                                                                                                                     
        
                                                                                                                     
        
                                                                                                                     
        
                                                                                                             'Ls' THEN         
        
                                                                                                             'Uploaded List'        
        
                                                                                                        ELSE CASE         
        
                                                                                                                  WHEN         
        
                                                                                                                       usl.IsResponse         
        
                                             
        
                                                                                                                   
        
                                                                                                                               
        
                                              =        
        
                                                                                                                               
        
                                                                                                                               
        
                                                                                                                               
        
                                                                                                                       1 THEN         
        
                                                                                                                       'Response'        
        
                                                                                                                  ELSE CASE         
        
                                                                                                                            WHEN         
        
                                                                                                                                 usl.IsUnsubscribe         
        
                                                                                                                                         
        
                                                                                                                                         
        
                                                                                                                                         
        
                                                                                                                                 =        
        
                                                                                                                                         
        
                                                                                                                                         
        
                                                                                                                                         
        
                                                                                                                  1 THEN         
        
                                                                                                                                 'Unsubscribe'        
        
                                                                                                                            ELSE         
        
                                                                                                                                 ''        
        
                                                                                                                       END        
        
                                                                                                             END        
        
                                                                                                   END        
        
                                                                                         END        
        
                                                                               END        
        
                                                                     END +        
        
                                                     
        
                                                     
        
                                                     
        
                                             ')'        
        
                             FROM   UserSearchList AS usl        
        
                                             INNER JOIN dbo.fn_Split(ucm.Applicabilty, '#') AS         
        
                                                  fs        
        
                       ON  usl.ID = fs.[value] FOR         
        
                                                              
        
                                                              
        
                                                              
        
                                            XML PATH(''),        
        
                                             TYPE        
        
                                  ) .value('text()[1]', 'nvarchar(max)'),        
        
                                  1,        
        
                                  2,        
        
                                  N''        
        
                              )        
        
                   )                   AS ApplicabiltyName,        
        
                   ucm.Applicabilty,        
        
                   ucm.ExclusionsNumber,        
        
                   (        
        
                       SELECT STUFF(        
        
                                  (        
        
                                      SELECT N', ' + usl.SearchName +        
        
                                                     
        
                                                     
                                                     
        
                                             ' (' + CASE         
        
                                                         WHEN usl.SearchType         
        
                                                                      
        
                                                                      
        
                                                                      
        
                                                              = 'EN' THEN         
        
                                                              'Enquiry'        
        
                                                         ELSE CASE         
        
                                                                   WHEN usl.SearchType         
        
                                                                                
        
                                                                                
        
                                                                                
        
                                                                        =        
        
                                                           
        
                                                                                
        
                                                                                
        
                                                                        'LE' THEN         
        
                                                                        'Leads'        
        
                                                                   ELSE CASE         
        
                                                                             WHEN         
        
                                                                                  usl.SearchType         
        
                                                                                          
        
                                                                                          
        
                                                                                          
        
                                                                                  =        
        
                                                                                          
        
                                                                                          
        
                                                                             
        
                                                                                  'Co' THEN         
        
                                                                                  'Conversion'        
        
                                                                             ELSE CASE         
        
                                                                                       WHEN         
        
                                                                                            usl.SearchType         
        
                                                                                                    
        
                                                                                                    
        
                                                                  
        
                                                                                           =        
        
                                                                                                    
        
                                                                                                    
        
                                                                                                    
        
                                                                                            'Ls' THEN         
        
                                                                                            'Uploaded List'        
        
                                                                                       ELSE CASE         
        
                                                                                                 WHEN         
        
                                                                                                      usl.IsResponse         
        
                                                                                                              
        
                                                                                                              
        
                                                                                                              
        
                                                                                                      =        
        
                                                                                                              
        
                                                                                                              
        
                                                                                                              
        
                                                                               1 THEN         
        
                                                                                                      'Response'        
        
                                                                                                 ELSE CASE         
        
                                                                                                           WHEN         
        
                                                                                                                usl.IsUnsubscribe         
        
                                                                                                                        
        
                                                                                                                        
        
                                                                                                                        
        
                                                                                                                =        
        
                                                   
        
                                                                                                                        
        
                                                                                                                        
        
                                                                                                                1 THEN         
        
                                                                                                                'Unsubscribe'        
        
                                                                                                           ELSE         
        
                                                                                                                ''        
        
                                                                                                      END        
        
                                                                                            END        
        
                                                                                  END        
        
                                                                      END        
        
                                                              END        
        
                                                    END + ')'        
        
                                      FROM   UserSearchList AS usl        
        
                                             INNER JOIN dbo.fn_Split(ucm.Exclusions, '#') AS         
        
                                                  fs        
        
                                                  ON  usl.ID = fs.[value] FOR         
        
                                                              
        
                                                              
        
                                                              
        
                                                      XML PATH(''),        
        
                                             TYPE        
        
                                  ) .value('text()[1]', 'nvarchar(max)'),        
        
                                  1,        
        
                                  2,        
        
                                  N''        
        
                              )        
        
                   )                   AS ExclusionsName,        
        
                   (        
        
                       SELECT STUFF(        
        
                                  (        
        
                                      SELECT N', ' + gd.Group_Name +        
        
                                                     
        
                                                     
        
                                                     
        
                                             ' (Groups)'        
        
                                      FROM   Group_Detail AS gd        
        
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS         
        
                                                  fs        
        
                                                  ON  gd.Group_ID = fs.[value]         
        
                                                              
        
                                                              
        
                                                              
        
                                                      FOR XML PATH(''),        
        
                                             TYPE        
        
                                  ) .value('text()[1]', 'nvarchar(max)'),        
        
                                  1,        
        
                                  2,        
        
                                  N''        
        
                              )        
        
                  )                   AS ExclusionsGroups,        
        
                   (        
        
                       SELECT STUFF(        
        
                                  (        
        
                                      SELECT N', ' + gd.ImportName +        
        
                                                     
        
                                                     
        
                                                     
        
                                             ' (Imported Lists)'        
        
                                      FROM   UserImportedListColumn AS gd        
        
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS         
        
                                                  fs        
        
                                                  ON  gd.ID = fs.[value] FOR         
        
                                                              
        
                                                              
        
                                                              
        
                                                      XML PATH(''),        
        
                                             TYPE        
        
                                  ) .value('text()[1]', 'nvarchar(max)'),        
        
                                  1,        
        
                                  2,        
        
                                  N''        
        
                              )        
        
                   )                   AS ExclusionsLists,        
        
                   (        
        
          SELECT STUFF(        
        
                                  (        
        
                                      SELECT N', ' + gd.Group_Name +        
        
                                                     
        
                                                     
        
                                                     
        
                                             ' (Groups)'        
        
                                      FROM   Group_Detail AS gd        
        
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS         
        
                                                  fs        
        
                                                  ON  gd.Group_ID = fs.[value]         
        
                                                              
        
                                                              
        
                                                              
        
                                                      FOR XML PATH(''),        
        
                                             TYPE        
        
                                  ) .value('text()[1]', 'nvarchar(max)'),        
        
                                  1,        
        
                                  2,        
        
                                  N''        
        
                              )        
        
                   )                   AS AppGroups,        
        
       (        
        
                       SELECT STUFF(        
        
                                  (        
        
                                      SELECT N', ' + gd.ImportName +        
        
                                                     
        
                                                     
        
                                                     
        
                                             ' (Imported Lists)'        
        
     FROM   UserImportedListColumn AS gd        
        
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS         
        
                                                  fs        
        
                                                  ON  gd.ID = fs.[value] FOR       
        
                                                              
        
                                                              
        
                                                              
        
                                                      XML PATH(''),        
        
                                             TYPE        
        
                                  ) .value('text()[1]', 'nvarchar(max)'),        
        
                                  1,        
        
                                  2,        
        
                                  N''        
        
                              )        
        
                   )                   AS AppLists,        
        
                   ucm.InclusionsNumber,        
        
                   ucm.Exclusions,        
        
                   ucm.SenderID,        
        
                   ucm.[Message],        
        
                   ucm.IsUnicode,        
        
                   ucm.MailReplyTo,        
        
                   ucm.MailSubject,        
        
                   ucm.MailContent,        
        
                   (        
        
                       SELECT TOP 1 cpd.PageName        
        
                       FROM   ClientPageDetail cpd        
        
                       WHERE  cpd.Id = ucm.TrackResponse        
        
                   )                   AS TrackResponse,        
        
                   (        
        
                       SELECT TOP 1 cpd.PageName        
        
                       FROM   ClientPageDetail cpd        
        
                       WHERE  cpd.Id = ucm.UnsubscribePage        
        
                   )                   AS UnsubscribePage,        
        
                   ucm.Tags,        
        
                   ucm.ExpiryDate,        
        
                   ucm.CreatedOn,        
        
                   ucm.IsActive,        
        
                   ud.User_Login,        
        
                   (        
        
                       SELECT ud.User_Login        
        
                       FROM   User_Detail ud        
        
                       WHERE  ud.[User_ID] = ucm.AccountUsed        
        
                   )                   AS AccountUsed,        
        
                   (        
        
                       SELECT TOP 1 umt.Name        
        
                       FROM   UserMailTemplate         
        
                                      
        
                                      
        
                                      
        
                              umt        
        
                       WHERE  umt.ID = ucm.TemplateID        
        
                   )                   AS TEMPLATEused,        
        
                   (        
        
                       SELECT utgd.GroupName        
        
                       FROM   UserTemplateGroupDetails utgd        
        
                       WHERE  utgd.ID = ucm.TemplateGroupID        
        
       )                   AS TEMPLATEGroup,        
        
                   ucm.NotificationMail,        
        
                   ucm.SuccessNotificationEmail,        
        
                   ucm.FailureNotificationEmail,        
        
                   ucm.IsRecurring,        
        
                   ucm.IsEnding,        
        
                   ucm.TemplateGroupSequence,        
        
                   ucm.IsNeverExpire,      
           ucm.IsSurplusExclusions,        
        
                   ucm.EventsName,        
        
                  (SELECT TOP 1 ucerm.ExecutionTime         
        
                     FROM UserCampaignExecutionHistory AS ucerm WHERE ucerm.CampaignID=ucm.ID ORDER BY ucerm.ExecutionTime DESC)  AS LastScheduledRunTime        
        
            FROM   UserCampaignMaster  AS ucm        
        
                   LEFT JOIN UserSchedules AS us        
        
                        ON  ucm.ScheduleID = us.ID   
        
                   LEFT JOIN User_Detail AS UD(NOLOCK)        
        
                        ON  ucm.Createdby = UD.User_ID         
        
            WHERE  ucm.ParentID = @ParentID        
        
                   AND (        
        
                           ucm.IsActive = CASE         
        
                                               WHEN @IsActive = 1 THEN 1        
        
                                               ELSE NULL        
        
                                          END        
        
                           OR ucm.IsActive = CASE         
        
                                                  WHEN @IsinActive = 1 THEN 0        
        
                                                  ELSE NULL        
        
                                             END        
        
                       )        
        
        )         
        
                
        
                
        
                
        
        A        
        
 ORDER BY        
        
        A.CreatedOn DESC        
        
END   
  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCampaignmaster1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetUserCampaignmaster1 --34594,1,1                            
	@ParentID BIGINT
	,@IsActive BIT
	,@IsInActive BIT
	,@fromdate datetime = null
	,@todate datetime = null
	,@campname varchar(max) =null
	,@status char(1)=null  
AS
BEGIN
	SELECT A.ID
		,A.CampaignName
		,(
			'<p><b> Type:</b> ' + CASE 
				WHEN A.IsEventBased = 1
					THEN 'Event based (' + CASE 
							WHEN A.EventsName = 'ENQADD'
								THEN 'Enquiry Added'
							ELSE CASE 
									WHEN A.EventsName = 'LEDADD'
										THEN 'Lead Added'
									ELSE CASE 
											WHEN A.EventsName = 'FOLADD'
												THEN 'Follow Up Added'
											ELSE 'Follow Up Due'
											END
									END
							END + ')'
				ELSE 'Scheduled'
				END + '</p>' + '<p><b> Medium:</b> ' + A.Medium
			--CASE                             
			--                      WHEN                             
			--                         A.MailReplyTo =                            
			--                         '' THEN                             
			--                          'SMS'                            
			--                          ELSE                             
			--                             'Mail'                            
			--                          END                             
			+ '</p>'
			) AS CampaignType
		,(
			CASE 
				WHEN ISNULL(A.ApplicabiltyName, '') <> ''
					THEN '<p><b> Applicabilty:</b> ' + ISNULL(A.ApplicabiltyName, '') + ',' + ISNULL(A.AppGroups, '') + ',' + ISNULL(A.AppLists, '') + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.InclusionsNumber, '') <> ''
					THEN '<p><b> Included Number:</b> ' + A.InclusionsNumber + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.ExclusionsName, '') <> ''
					THEN '<p><b> Exclusions:</b> ' + ISNULL(A.ExclusionsName, '') + ',' + ISNULL(A.ExclusionsGroups, '') + ',' + ISNULL(A.ExclusionsLists, '') + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.ExclusionsNumber, '') <> ''
					THEN '<p><b> Excluded Numbers:</b> ' + A.ExclusionsNumber + '</p>'
				ELSE ''
				END + '<p><b> IsSurplusExclusions:</b> ' + CASE 
				WHEN A.IsSurplusExclusions = 1
					THEN 'Yes'
				ELSE 'No'
				END + '</p>'
			) AS Recipients
		,(
			CASE 
				WHEN ISNULL(A.AccountUsed, '') <> ''
					THEN '<p><b> Account:</b> ' + A.AccountUsed + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.SenderID, '') <> ''
					THEN '<p><b> Sender-ID:</b> ' + A.SenderID + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.FromMailID, '') <> ''
					THEN '<p><b> FromMailID:</b> ' + A.FromMailID + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.TEMPLATEused, '') <> ''
					THEN '<p><b>Template:</b> ' + A.TEMPLATEused + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.TEMPLATEGroup, '') <> ''
					THEN '<p><b>Template Group:</b> ' + A.TEMPLATEGroup + '</p><p><b>Sequence No&nbsp;:&nbsp;</b>' + CAST(A.TemplateGroupSequence AS VARCHAR(50)) + '</p><p>' + CASE 
							WHEN A.IsRecurring = 1
								THEN 'Recurring'
							ELSE 'Ends After Group Template count Ends'
							END + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.[Message], '') <> ''
					THEN '<p><b>Message:</b> ' + A.[Message] + '</p>' + '<p><b> IsUnicode:</b> ' + CASE 
							WHEN A.IsUnicode = 1
								THEN 'Yes'
							ELSE 'No'
							END + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.MailReplyTo, '') <> ''
					THEN '<p><b>  Reply To:</b> ' + A.MailReplyTo + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.MailSubject, '') <> ''
					THEN '<p><b>  Subject:</b> ' + A.MailSubject + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.MailContent, '') <> ''
					THEN '<p><b>   Content:</b> ' + A.MailContent + '</p>'
				ELSE ''
				END
			) AS Accounts
		,(
			CASE 
				WHEN ISNULL(A.TrackResponse, '') <> ''
					THEN '<p><b>  Track Response:</b> ' + A.TrackResponse + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.UnsubscribePage, '') <> ''
					THEN '<p><b>  Unsubscribe Page:</b> ' + A.UnsubscribePage + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.Tags, '') <> ''
					THEN '<p><b>  Tags:</b> ' + A.Tags + '</p>'
				ELSE ''
				END
			) AS Tracking
		,(
			CASE 
				WHEN ISNULL(A.StartDate, '') <> ''
					THEN '<p><b>  Start Date at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID, A.StartDate) AS VARCHAR(50)) + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.ExpiryDate, '') <> ''
					THEN '<p><b>  Expiry Date:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID, A.ExpiryDate) AS VARCHAR(50)) + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.SceduleName, '') <> ''
					THEN '<p><b>  Scheduled:</b> ' + A.SceduleName + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.ExecutedDateTime, '') <> ''
					THEN '<p><b>  Executed at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID, A.ExecutedDateTime) AS VARCHAR(50)) + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.NextExecuteDateTime, '') < > ''
					THEN '<p><b>  Next Execution at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID, A.NextExecuteDateTime) AS VARCHAR(50)) + '</p>'
				ELSE ''
				END + CASE 
				WHEN ISNULL(A.LastScheduledRunTime, '') = ''
					THEN '<p><b>Last Scheduled Run Time:</b> ' + 'Never' + '</p>'
				ELSE '<p><b>Last Scheduled Run Time:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID, A.LastScheduledRunTime) AS VARCHAR(50)) + '</p>'
				END
			) AS Scheduling
		,CASE 
			WHEN ISNULL(A.NotificationMail, '') <> ''
				THEN '<p><b>Notification EMail:</b> ' + CAST(A.NotificationMail AS VARCHAR(250)) + '</p>'
			ELSE ''
			END + CASE 
			WHEN ISNULL(A.SuccessNotificationEmail, '') <> ''
				THEN '<p><b>Success Notification:</b> ' + CAST(A.SuccessNotificationEmail AS VARCHAR(250)) + '</p>'
			ELSE ''
			END + CASE 
			WHEN ISNULL(A.FailureNotificationEmail, '') <> ''
				THEN '<p><b>Failure Notification:</b> ' + CAST(A.FailureNotificationEmail AS VARCHAR(250)) + '</p>'
			ELSE ''
			END AS Notifications
		,A.IsEventBased
		,A.IsScheduled
		,A.SceduleName
		,
		--A.ExecutedDateTime,                            
		dbo.[fn_getusertimefromindiantime](@ParentID, A.ExecutedDateTime) AS ExecutedDateTime
		,
		-- A.NextExecuteDateTime,                
		dbo.[fn_getusertimefromindiantime](@ParentID, A.NextExecuteDateTime) AS NextExecuteDateTime
		,A.Applicabilty
		,A.ApplicabiltyName
		,A.ExclusionsName
		,A.ExclusionsNumber
		,A.InclusionsNumber
		,A.Exclusions
		,A.SenderID
		,A.[Message]
		,A.IsUnicode
		,A.MailReplyTo
		,A.MailSubject
		,A.MailContent
		,A.UnsubscribePage
		,A.TrackResponse
		,A.Tags
		,
		-- A.ExpiryDate,                
		dbo.[fn_getusertimefromindiantime](@ParentID, A.ExpiryDate) AS ExpiryDate
		,A.User_Login
		,
		-- A.CreatedOn,                            
		dbo.[fn_getusertimefromindiantime](@ParentID, A.CreatedOn) AS CreatedOn
		,Convert(NVARCHAR(50), dbo.[fn_getusertimefromindiantime](@ParentID, A.CreatedOn), 13) AS CreatedOn1
		,A.IsActive
		,A.NotificationMail
		,A.SuccessNotificationEmail
		,A.FailureNotificationEmail
		,A.IsRecurring
		,A.IsEnding
		,A.TemplateGroupSequence
		,A.IsNeverExpire
		,A.EventsName
		,A.IsSurplusExclusions
		,
		--A.StartDate ,                      
		dbo.[fn_getusertimefromindiantime](@ParentID, A.StartDate) AS StartDate
		,A.FromMailID
		,A.Medium
	FROM (
		SELECT ucm.ID
			,ucm.CampaignName
			,ucm.FromMailID
			,ucm.IsEventBased
			,ucm.IsScheduled
			,ucm.StartDate
			,us.SceduleName
			,(
				SELECT TOP 1 uceh.ExecutionTime
				FROM UserCampaignExecutionHistory AS uceh
				WHERE uceh.CampaignID = ucm.ID
				ORDER BY uceh.ExecutionTime DESC
				) AS ExecutedDateTime
			,ucm.NextExecuteDateTime
			,(
				SELECT STUFF((
							SELECT N', ' + usl.CriteriaName + ' (' + usl.CriteriaType + ')'
							FROM tbl_SearchCriteria(NOLOCK) AS usl
							INNER JOIN dbo.fn_Split(ucm.Applicabilty, '#') AS fs ON usl.ID = fs.[value]
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS ApplicabiltyName
			,ucm.Applicabilty
			,ucm.ExclusionsNumber
			,(
				SELECT STUFF((
							SELECT N', ' + usl.CriteriaName + ' (' + usl.CriteriaType + ')'
							-- FROM   UserSearchList AS usl                    
							FROM tbl_SearchCriteria(NOLOCK) AS usl
							INNER JOIN dbo.fn_Split(ucm.Exclusions, '#') AS fs ON usl.ID = fs.[value]
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS ExclusionsName
			,(
				SELECT STUFF((
							SELECT N', ' + gd.Group_Name + ' (Groups)'
							FROM Group_Detail AS gd
							INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS fs ON gd.Group_ID = fs.[value]
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS ExclusionsGroups
			,(
				SELECT STUFF((
							SELECT N', ' + gd.ImportName + ' (Imported Lists)'
							FROM UserImportedListColumn AS gd
							INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS fs ON gd.ID = fs.[value]
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS ExclusionsLists
			,(
				SELECT STUFF((
							SELECT N', ' + gd.Group_Name + ' (Groups)'
							FROM Group_Detail AS gd
							INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS fs ON gd.Group_ID = fs.[value]
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS AppGroups
			,(
				SELECT STUFF((
							SELECT N', ' + gd.ImportName + ' (Imported Lists)'
							FROM UserImportedListColumn AS gd
							INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS fs ON gd.ID = fs.[value]
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS AppLists
			,ucm.InclusionsNumber
			,ucm.Exclusions
			,ucm.SenderID
			,ucm.[Message]
			,ucm.IsUnicode
			,ucm.MailReplyTo
			,ucm.MailSubject
			,ucm.MailContent
			,(
				SELECT TOP 1 cpd.PageName
				FROM ClientPageDetail cpd
				WHERE cpd.Id = ucm.TrackResponse
				) AS TrackResponse
			,(
				SELECT TOP 1 cpd.PageName
				FROM ClientPageDetail cpd
				WHERE cpd.Id = ucm.UnsubscribePage
				) AS UnsubscribePage
			,ucm.Tags
			,ucm.ExpiryDate
			,ucm.CreatedOn
			,ucm.IsActive
			,ud.User_Login
			,(
				SELECT ud.User_Login
				FROM User_Detail ud
				WHERE ud.[User_ID] = ucm.AccountUsed
				) AS AccountUsed
			,(
				SELECT TOP 1 umt.Name
				FROM UserMailTemplate umt
				WHERE umt.ID = ucm.TemplateID
				) AS TEMPLATEused
			,(
				SELECT utgd.GroupName
				FROM UserTemplateGroupDetails utgd
				WHERE utgd.ID = ucm.TemplateGroupID
				) AS TEMPLATEGroup
			,ucm.NotificationMail
			,ucm.SuccessNotificationEmail
			,ucm.FailureNotificationEmail
			,ucm.IsRecurring
			,ucm.IsEnding
			,ucm.TemplateGroupSequence
			,ucm.IsNeverExpire
			,ucm.IsSurplusExclusions
			,ucm.EventsName
			,ucm.Medium
			,(
				SELECT TOP 1 ucerm.ExecutionTime
				FROM UserCampaignExecutionHistory AS ucerm
				WHERE ucerm.CampaignID = ucm.ID
				ORDER BY ucerm.ExecutionTime DESC
				) AS LastScheduledRunTime
		FROM UserCampaignMaster AS ucm
		LEFT JOIN UserSchedules AS us ON ucm.ScheduleID = us.ID
		LEFT JOIN User_Detail AS UD(NOLOCK) ON ucm.Createdby = UD.User_ID
		WHERE ucm.ParentID = @ParentID
			AND isnull(UCM.EventID, 0) = 0
			AND (
				ucm.IsActive = CASE 
					WHEN @IsActive = 1
						THEN 1
					ELSE NULL
					END
				OR ucm.IsActive = CASE 
					WHEN @IsinActive = 1
						THEN 0
					ELSE NULL
					END
				)
		) A
		WHERE ( @fromdate IS NULL OR A.CreatedOn >  @fromdate) AND
			(@todate IS NULL OR A.CreatedOn < @todate) AND
			(@campname IS NULL OR A.CampaignName LIKE '%'+@campname+'%')

	ORDER BY A.CreatedOn DESC

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
		,@Activity_type = 'View_Cmpgn_Mstr'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'UserCampaignMaster'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCampaignmaster1_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserCampaignmaster1_INTDateTime] --17626,1,1            
            
 @ParentID BIGINT,            
            
 @IsActive BIT,            
            
 @IsInActive BIT            
            
AS            
            
BEGIN            
            
 SELECT A.ID,            
            
        A.CampaignName,            
            
        (            
            
            '<p><b> Type:</b> ' + CASE             
            
                                       WHEN A.IsEventBased = 1 THEN             
            
                                            'Event based (' + CASE             
            
                                                                   WHEN A.EventsName             
            
                                                                                    
            
                                                                                    
            
                                                                                    
            
                                                                        =            
            
                                                                                    
            
                                                                        'ENQADD' THEN             
            
                                                                        'Enquiry Added'            
            
                                                                   ELSE CASE             
            
                                                                             WHEN             
            
                                                                                  A.EventsName             
            
                                                                                              
            
                                                                                              
            
                                                                                              
            
                                                                                  =            
            
                                                                                              
            
                                                                                              
            
                                                                                              
            
                                                                                  'LEDADD' THEN             
            
                                                                                  'Lead Added'            
            
                                                                             ELSE             
            
                                                                                  'Follow Up Added'            
            
                                                                        END            
            
                                                              END + ')'            
            
                                       ELSE 'Scheduled'            
            
                                  END + '</p>' + '<p><b> Medium:</b> ' + CASE             
            
                                                                              WHEN             
            
                                                                                   A.MailReplyTo             
            
                                                                                               
            
                                                                                               
            
                                                                                               
            
                                                                                   =            
     
                                                                                               
            
                           
            
                                                                                               
            
                                '' THEN             
            
                                                                                   'SMS'            
            
                                          ELSE             
            
                                                                                   'Mail'            
            
                           END             
            
                        
            
                        
            
                        
            
            + '</p>'            
            
        )                AS CampaignType,            
            
        (            
            
            CASE             
            
                 WHEN ISNULL(A.ApplicabiltyName, '') <> '' THEN             
            
                      '<p><b> Applicabilty:</b> ' + ISNULL(A.ApplicabiltyName, '')             
            
                                  
            
                                  
            
                                  
            
                      + ',' + ISNULL(A.AppGroups, '') + ',' + ISNULL(A.AppLists, '')             
            
                                  
            
                                  
            
                                  
            
                      + '</p>'            
            
                 ELSE ''            
            
            END + CASE             
            
                       WHEN ISNULL(A.InclusionsNumber, '') <> '' THEN             
            
                            '<p><b> Included Number:</b> ' + A.InclusionsNumber             
            
                                        
            
                                        
            
                                        
            
                            + '</p>'            
            
                       ELSE ''            
            
                  END + CASE             
            
                             WHEN ISNULL(A.ExclusionsName, '') <> '' THEN             
            
                                  '<p><b> Exclusions:</b> ' + ISNULL(A.ExclusionsName, '')             
            
                                              
            
                                              
            
                                              
            
                                  + ',' + ISNULL(A.ExclusionsGroups, '') +            
            
                                              
            
                                              
            
                                              
            
                                  ',' +            
            
                                              
            
                                              
            
                                              
            
                                  ISNULL(A.ExclusionsLists, '') + '</p>'            
            
                             ELSE ''            
            
                        END + CASE             
            
                                   WHEN ISNULL(A.ExclusionsNumber, '') <>            
            
                                                    
            
                                                    
            
                                                    
            
                                        '' THEN             
            
                                        '<p><b> Excluded Numbers:</b> ' + A.ExclusionsNumber             
            
                                                    
            
                                                    
            
                                                    
            
                                   + '</p>'            
            
                                   ELSE ''            
            
                              END            
                                        
                              +          
                              '<p><b> IsSurplusExclusions:</b> ' + CASE             
            
                                                                     WHEN             
            
                                                                                     A.IsSurplusExclusions             
            
                                                                                                 
            
                           
            
                                                                                                 
            
                                                                                     =            
            
                                                                                                 
            
                                                                                                 
            
                                                                                                 
            
                                                                                     1 THEN             
            
                                                                                     'Yes'            
            
                                                                                ELSE             
            
                                                     'No'            
            
                                                                           END             
            
                                                          
            
                                                          
            
                                                          
            
                                              + '</p>'                    
          
                                        
            
        )                AS Recipients,            
            
        (            
            
            CASE             
            
                 WHEN ISNULL(A.AccountUsed, '') <> '' THEN             
            
                      '<p><b> Account:</b> ' + A.AccountUsed + '</p>'            
            
                 ELSE ''            
            
            END + CASE             
            
                       WHEN ISNULL(A.SenderID, '') <> '' THEN             
            
                            '<p><b> Sender-ID:</b> ' + A.SenderID + '</p>'            
            
                       ELSE ''            
            
                  END      
                  +      
                        
                  CASE             
            
                       WHEN ISNULL(A.FromMailID, '') <> '' THEN             
            
                            '<p><b> FromMailID:</b> ' + A.FromMailID + '</p>'            
            
                       ELSE ''            
            
                  END      
                        
                        
                   + CASE             
            
                             WHEN ISNULL(A.TEMPLATEused, '') <> '' THEN             
            
                                  '<p><b>Template:</b> ' +            
            
                                              
            
                                              
            
                                              
            
                                  A.TEMPLATEused + '</p>'            
            
                             ELSE ''            
            
                        END + CASE             
            
                                   WHEN ISNULL(A.TEMPLATEGroup, '') <> '' THEN             
            
                                        '<p><b>Template Group:</b> ' + A.TEMPLATEGroup             
            
                                                    
            
                                                    
            
                                                    
            
                                        +            
            
                                                    
            
                                                    
            
                                                    
            
                                        '</p><p><b>Sequence No&nbsp;:&nbsp;</b>'             
            
                                                    
            
                                                    
            
                                                    
            
                                        + CAST(A.TemplateGroupSequence AS VARCHAR(50))             
            
                                                    
            
                                                    
            
                                                    
            
                                        + '</p><p>' + CASE                     
                                                           WHEN A.IsRecurring             
            
                                                                            
            
                                              
            
                                                                            
            
                                                                = 1 THEN             
            
                                                                'Recurring'            
            
                                                           ELSE             
            
                                                                'Ends After Group Template count Ends'            
            
                                                      END + '</p>'            
            
                                   ELSE ''            
            
                              END + CASE             
            
                                         WHEN ISNULL(A.[Message], '') <> '' THEN             
            
                                              '<p><b>Message:</b> ' + A.[Message]             
            
                                                          
            
                                                          
            
                                                          
            
                                              + '</p>'             
            
                                                          
            
                                                          
            
                                                          
            
                                              + '<p><b> IsUnicode:</b> ' + CASE             
            
                                                                                WHEN             
            
                                              A.IsUnicode             
            
                                                                                                 
            
                                                                                                 
            
                                                                                                 
            
                                                                                     =            
            
                                                                                                 
            
                                                                                                 
            
                                                                                                 
            
                                                                                     1 THEN             
            
                                                                                     'Yes'            
            
                                                                                ELSE             
            
                                                                                     'No'            
            
                                                                           END             
            
                                                          
            
                                                          
            
                                                          
            
                                              + '</p>'            
            
                                     ELSE ''            
            
                                    END + CASE             
            
                                               WHEN ISNULL(A.MailReplyTo, '')             
            
                                                                
            
                                                                
            
                                                                
            
                                                    <> '' THEN             
            
                                                    '<p><b>  Reply To:</b> '             
            
                                                                
            
                                                                        
                                                                
            
                                                    + A.MailReplyTo + '</p>'            
            
                                               ELSE ''            
            
                                          END + CASE             
            
                                                     WHEN ISNULL(A.MailSubject, '')             
            
                                                                      
            
                             
            
                                                                      
            
                                                          <> '' THEN             
            
                                                          '<p><b>  Subject:</b> '             
            
                                                                      
            
                                                                      
            
                                                             
            
                                                          + A.MailSubject +            
            
                                                                      
            
                                                                      
            
                              
            
                                                          '</p>'            
            
                                                     ELSE ''            
            
                                                END + CASE             
            
                                                           WHEN ISNULL(A.MailContent, '')             
            
                                                                            
            
                                                                            
            
                                                                            
            
                                                                <> '' THEN             
            
                                                                '<p><b>   Content:</b> '             
            
                                                                            
            
                                                                        
            
                                        
            
                                                                + A.MailContent             
            
                                                                            
            
                                                                            
            
                                                                            
            
                                                                + '</p>'            
            
                                                           ELSE ''            
            
                                                      END            
            
        )                AS Accounts,            
            
        (            
            
            CASE             
            
                 WHEN ISNULL(A.TrackResponse, '') <> '' THEN             
            
                      '<p><b>  Track Response:</b> '             
            
                                  
            
                                  
            
                                  
            
                      + A.TrackResponse + '</p>'            
            
                 ELSE ''            
            
            END + CASE             
            
                       WHEN ISNULL(A.UnsubscribePage, '')             
            
                                        
            
                                        
            
                                        
            
                            <> '' THEN '<p><b>  Unsubscribe Page:</b> ' + A.UnsubscribePage             
            
                                        
            
                                        
            
                                        
            
                            + '</p>'            
            
                       ELSE ''            
            
                  END + CASE             
            
                             WHEN ISNULL(A.Tags, '') <> '' THEN             
            
                                  '<p><b>  Tags:</b> ' + A.Tags +            
            
                                              
            
                                              
            
                                              
            
                                  '</p>'            
            
                             ELSE ''            
            
                        END            
            
        )                AS Tracking,            
            
        (            
            
            CASE             
            
                 WHEN ISNULL(A.StartDate, '') <> '' THEN             
            
                      '<p><b>  Start Date at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) AS VARCHAR(50))             
            
                                  
            
                                  
            
                                  
            
                      + '</p>'            
            
                 ELSE ''            
            
            END + CASE             
            
                       WHEN ISNULL(A.ExpiryDate, '') <> '' THEN             
            
                            '<p><b>  Expiry Date:</b> ' + CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) AS VARCHAR(50))             
            
                                        
            
                                        
            
                                        
            
                            + '</p>'            
            
                       ELSE ''            
            
                  END + CASE             
            
                             WHEN ISNULL(A.SceduleName, '') <> '' THEN             
            
                 '<p><b>  Scheduled:</b> ' +            
            
                                              
            
                                              
            
                                              
            
    A.SceduleName + '</p>'            
            
                             ELSE ''            
            
                        END + CASE             
            
                                   WHEN ISNULL(A.ExecutedDateTime, '') <>            
            
                                                    
            
                                                
            
                                                    
            
                                        '' THEN '<p><b>  Executed at:</b> ' +            
            
                                                    
            
                                                    
            
                                                    
            
                                        CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) AS VARCHAR(50))             
            
                                                    
            
                                                    
            
                                                    
            
                                        +            
            
                                 
            
                                                    
            
                                          
            
                                        '</p>'            
            
                                   ELSE ''            
            
                              END + CASE             
            
                                         WHEN ISNULL(A.NextExecuteDateTime, '')             
            
                                                          
            
                                                          
            
                                                          
            
                                              < > '' THEN             
            
                                              '<p><b>  Next Execution at:</b> '             
            
                                                          
            
                                                          
            
                                                          
            
                               + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) AS VARCHAR(50))             
            
                                                          
            
                                                          
            
                                                          
            
          +            
            
                                                          
            
                                                          
            
                                                          
            
                                              '</p>'            
            
                                         ELSE ''            
            
                                    END             
            
                        
            
            +            
            
                        
            
                        
            
                        
            
            CASE             
            
                 WHEN ISNULL(A.LastScheduledRunTime, '')             
            
                                  
            
                                  
            
                                  
            
                      = '' THEN '<p><b>Last Scheduled Run Time:</b> '             
            
                                  
            
                                  
            
                                  
            
                      + 'Never'             
            
                                  
            
                                  
            
                                  
            
                      +            
            
                                  
            
                                  
            
    
            
                      '</p>'            
            
                 ELSE '<p><b>Last Scheduled Run Time:</b> '             
            
                                  
            
                                  
            
                                  
            
                      + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.LastScheduledRunTime) AS VARCHAR(50))             
            
                                  
            
                      +            
            
                                  
            
                      '</p>'            
            
            END            
            
        )        AS Scheduling,            
            
        CASE             
            
             WHEN ISNULL(A.NotificationMail, '') <>            
            
                              
            
                              
            
                              
            
                  '' THEN '<p><b>Notification EMail:</b> ' + CAST(A.NotificationMail AS VARCHAR(250))             
            
                              
            
                              
            
                              
            
                  + '</p>'            
            
             ELSE ''            
            
        END + CASE             
            
                   WHEN ISNULL(A.SuccessNotificationEmail, '') <>            
            
                                    
            
                                    
            
      
            
                        '' THEN '<p><b>Success Notification:</b> ' + CAST(A.SuccessNotificationEmail AS VARCHAR(250))             
            
                                    
            
                                    
            
                                    
            
                        + '</p>'            
            
                   ELSE ''            
            
              END + CASE             
            
                         WHEN ISNULL(A.FailureNotificationEmail, '') <> '' THEN             
            
                              '<p><b>Failure Notification:</b> ' +            
            
                                          
            
                                          
            
                                          
            
                              CAST(A.FailureNotificationEmail AS VARCHAR(250))             
            
                                          
            
                             
            
                                          
            
                              + '</p>'            
            
                         ELSE ''            
            
                    END  AS Notifications,            
            
        A.IsEventBased,            
            
        A.IsScheduled,            
            
        A.SceduleName,            
            
        --A.ExecutedDateTime,            
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) as ExecutedDateTime,  
            
       -- A.NextExecuteDateTime,
        dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) as NextExecuteDateTime,              
        A.Applicabilty,            
            
        A.ApplicabiltyName,            
            
        A.ExclusionsName,            
            
        A.ExclusionsNumber,            
            
        A.InclusionsNumber,            
            
        A.Exclusions,            
            
        A.SenderID,            
            
        A.[Message],            
            
        A.IsUnicode,            
            
        A.MailReplyTo,            
            
        A.MailSubject,            
            
        A.MailContent,            
            
        A.UnsubscribePage,            
            
        A.TrackResponse,            
            
        A.Tags,            
            
      -- A.ExpiryDate,
         dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) as ExpiryDate,           
        
        A.User_Login,            
      -- A.CreatedOn,            
        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,              
        
        A.IsActive,            
            
        A.NotificationMail,            
            
        A.SuccessNotificationEmail,            
            
        A.FailureNotificationEmail,         
            
        A.IsRecurring,            
            
        A.IsEnding,            
            
        A.TemplateGroupSequence,            
            
        A.IsNeverExpire,            
            
        A.EventsName ,          
        A.IsSurplusExclusions, 
               
        --A.StartDate ,      
        dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) as StartDate,              
        
        A.FromMailID          
                   
            
 FROM   (            
            
            SELECT ucm.ID,            
            
                   ucm.CampaignName,      
                   ucm.FromMailID,          
            
                   ucm.IsEventBased,            
            
                   ucm.IsScheduled,            
            
                   ucm.StartDate,            
            
                   us.SceduleName,            
            
                   (            
            
                       SELECT TOP 1 uceh.ExecutionTime            
            
                       FROM   UserCampaignExecutionHistory AS uceh            
            
                       WHERE  uceh.CampaignID = ucm.ID            
            
                       ORDER BY            
            
                              uceh.ExecutionTime DESC            
            
                   )                   AS ExecutedDateTime,            
            
                   ucm.NextExecuteDateTime,            
            
                   (            
            
                       SELECT STUFF(            
            
                                  (            
            
                                      SELECT N', ' +            
            
                                                         
            
                                                         
            
                                                
            
                                             usl.SearchName + ' (' + CASE             
            
                                                                          WHEN             
            
                                                                               usl.SearchType             
            
                                                                                           
            
                                                                                           
            
                                                                                           
            
                                                                               =            
            
                                                                                           
            
                                                                                           
            
                                                                                           
            
                                                                               'EN' THEN             
            
                                                                               'Enquiry'            
            
                                                                          ELSE CASE             
            
                                                                                    WHEN             
            
                                                              usl.SearchType             
            
                                                                                                     
            
                                                                                                     
            
                                     
            
                           =            
            
                                                                                                     
            
                                                                                                     
            
                                     
            
                                                                                         'LE' THEN             
            
                               'Leads'            
            
                                                                                    ELSE CASE             
            
                                                                                              WHEN             
            
                                                                                                   usl.SearchType             
            
                                                                                                               
            
                                                                                                               
            
                                                                                                               
            
                                                                                                   =            
            
                                                                                                               
            
                                                                                                               
            
                                                                                                               
            
                                                                                                   'Co' THEN             
            
                                                                                                   'Conversion'            
            
                                                                                              ELSE CASE             
            
                                          WHEN             
            
                                                                                                             usl.SearchType             
                                                                                                                               
            
                                                                                                                         
            
                                                                                                                         
            
                                                                                                             =            
            
                                                                                                                         
            
                                                                                                                         
            
                                                                                                                         
            
                                                                                                             'Ls' THEN             
            
                                                                                                             'Uploaded List'            
            
                                                                                                        ELSE CASE             
            
                                                                                                                  WHEN             
            
                                                                                                                       usl.IsResponse             
            
                                                 
            
                                                                                                                   
            
                                                                 
            
                                              =            
            
                                                                                                                                   
            
                                                                                                                                   
            
                                                                                                                                   
            
                                                                                                                       1 THEN             
            
                                                                                                                       'Response'            
            
                                                                                                                  ELSE CASE             
            
                                                                                                                            WHEN             
            
                                                                                                                                 usl.IsUnsubscribe             
            
                                                                                                                                             
            
                                                                                                                                             
            
                                                                                                                                             
            
                                                                                                                                 =            
            
                                                                                                                     
            
                                                                                                                                             
            
                                                                                                                                             
            
                                                                                                                  1 THEN             
            
                                                                                                                                 'Unsubscribe'            
            
                                                                                                                            ELSE             
            
                                                                                                                                 ''            
            
                                                                                                                       END            
            
                                                                                                             END            
            
                                                                                                   END            
            
                                                                                         END            
            
                                                                               END            
            
                                                                     END +            
            
                                                         
            
                                                         
            
                                                         
            
                                             ')'            
            
                         FROM   UserSearchList AS usl            
            
                                             INNER JOIN dbo.fn_Split(ucm.Applicabilty, '#') AS             
            
                                                  fs            
            
                       ON  usl.ID = fs.[value] FOR             
            
                                                                  
            
                                                                  
            
                                                                  
            
                                            XML PATH(''),            
            
                                             TYPE            
            
                                  ) .value('text()[1]', 'nvarchar(max)'),            
            
                                  1,            
            
                                  2,            
            
                                  N''            
            
                              )            
            
                   )                   AS ApplicabiltyName,            
            
                   ucm.Applicabilty,            
            
                   ucm.ExclusionsNumber,            
            
                   (            
            
                       SELECT STUFF(            
            
                                  (            
            
                                      SELECT N', ' + usl.SearchName +            
            
                                                         
            
                                                         
                                                         
            
                                             ' (' + CASE             
            
                                                         WHEN usl.SearchType             
            
                                                                          
            
                                                                          
            
                                     
            
                                                              = 'EN' THEN             
            
                                                              'Enquiry'            
            
                                                         ELSE CASE             
            
                                                                   WHEN usl.SearchType             
            
                                                                                    
            
                                                                                    
            
                                                                                    
            
                                                                        =            
            
                                                               
            
                                                                                    
            
                                                                                    
            
                                                                        'LE' THEN             
            
                                                                        'Leads'            
            
                                                                   ELSE CASE             
            
                                                                             WHEN             
            
                                                                                  usl.SearchType             
            
                                                                                              
            
                                                                                              
            
                                             
            
                                                                                  =            
            
                                                                                              
            
                                                                                              
            
                                                                             
            
                                                                                  'Co' THEN             
            
                                                                                  'Conversion'            
            
                                                                             ELSE CASE             
            
                                                                                       WHEN             
            
                                                                                            usl.SearchType             
            
                                                                                                        
            
                                                                                                        
            
                                                                      
            
                                                                                           =            
            
                                                                                                        
            
                                                                                                        
            
                                                                                                        
            
                                                                                            'Ls' THEN             
            
                                                                                            'Uploaded List'            
            
                                                                                       ELSE CASE             
            
                                                WHEN             
            
                                                                                                      usl.IsResponse             
            
                                                                                                                  
            
                                                                                                                  
            
                                                                                                                  
            
                                                                                                      =            
            
                                                                                                                  
            
                                                                                                                  
            
                                                                                                                  
            
                                                                               1 THEN             
            
                                                                                                      'Response'            
            
                                                                                                 ELSE CASE             
            
                                                                                                           WHEN             
            
                                                                                                                usl.IsUnsubscribe             
            
                                                                                                         
            
                                                                                                                            
            
                                                                                                                            
            
                                                                                                                =            
            
                                                   
            
                                                                                                                            
            
                                                                                                                            
            
                                                                                                                1 THEN             
            
                                                                                                                'Unsubscribe'            
            
                                                                                                           ELSE             
            
                                                                                                                ''            
            
                                                                                                      END            
            
                                                                                            END            
            
                                                                                  END            
            
                                                                      END            
            
                                                              END            
            
                                                    END + ')'            
            
                                      FROM   UserSearchList AS usl            
            
                                             INNER JOIN dbo.fn_Split(ucm.Exclusions, '#') AS             
            
                                                  fs            
            
                                       ON  usl.ID = fs.[value] FOR             
            
                                                                  
            
                                                                  
            
                                                                  
            
                                                      XML PATH(''),            
            
                                             TYPE            
            
                                  ) .value('text()[1]', 'nvarchar(max)'),            
            
                                  1,            
            
                                  2,            
            
                                  N''            
            
                              )            
            
                   )                   AS ExclusionsName,            
            
                   (            
            
                       SELECT STUFF(            
            
                                  (            
            
                                      SELECT N', ' + gd.Group_Name +            
            
                                                         
            
                                                         
            
                                                         
            
                                             ' (Groups)'            
            
                                      FROM   Group_Detail AS gd            
            
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS             
            
                                              fs            
            
                                                  ON  gd.Group_ID = fs.[value]             
            
                                                                  
            
                                                                  
            
                                                                  
            
                                                      FOR XML PATH(''),            
            
                                             TYPE            
            
                                  ) .value('text()[1]', 'nvarchar(max)'),            
            
                                  1,            
            
                                  2,            
            
                                  N''            
            
                              )            
            
              )                   AS ExclusionsGroups,            
            
                   (            
            
                       SELECT STUFF(            
            
                                  (            
            
                                      SELECT N', ' + gd.ImportName +            
            
                                                         
            
                                                         
            
                                                         
            
                                             ' (Imported Lists)'            
            
                                      FROM   UserImportedListColumn AS gd            
            
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS             
            
                                                  fs            
            
                                                  ON  gd.ID = fs.[value] FOR             
            
                                                                  
            
                                                                  
            
                                                                  
            
                                                      XML PATH(''),            
            
                                             TYPE            
            
                                  ) .value('text()[1]', 'nvarchar(max)'),            
            
                                  1,            
            
                                  2,            
            
                             N''            
            
                              )            
            
                   )                   AS ExclusionsLists,            
            
                   (            
            
          SELECT STUFF(            
            
                                  (            
            
                                      SELECT N', ' + gd.Group_Name +            
            
                                                         
            
                                                         
            
                                                         
            
                                             ' (Groups)'            
            
                                      FROM   Group_Detail AS gd            
            
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS             
            
                                                  fs            
            
                                                  ON  gd.Group_ID = fs.[value]             
            
                                                                  
            
                                                                  
            
                                                                  
            
                                                      FOR XML PATH(''),            
            
                                           TYPE            
            
                                  ) .value('text()[1]', 'nvarchar(max)'),            
            
                                  1,            
            
                                  2,            
            
                                  N''            
            
                              )            
            
                   )                   AS AppGroups,            
            
       (            
            
                       SELECT STUFF(            
            
                                  (            
            
                                      SELECT N', ' + gd.ImportName +            
            
                                                         
            
                                                         
            
                                                         
            
                                             ' (Imported Lists)'            
            
     FROM   UserImportedListColumn AS gd            
            
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS             
            
                                                  fs            
            
                                                  ON  gd.ID = fs.[value] FOR       
            
                                                                  
            
                                                                  
            
                                                                  
            
                                                      XML PATH(''),            
            
                                             TYPE            
            
                                  ) .value('text()[1]', 'nvarchar(max)'),            
            
                                  1,            
            
                                  2,            
            
                                  N''            
            
                              )            
            
                   )                   AS AppLists,            
            
                   ucm.InclusionsNumber,            
            
                   ucm.Exclusions,            
            
                   ucm.SenderID,            
            
                   ucm.[Message],            
            
                   ucm.IsUnicode,            
            
                   ucm.MailReplyTo,            
            
                   ucm.MailSubject,            
            
                   ucm.MailContent,            
            
                   (            
            
                       SELECT TOP 1 cpd.PageName            
            
      FROM   ClientPageDetail cpd            
            
                       WHERE  cpd.Id = ucm.TrackResponse            
            
                   )                   AS TrackResponse,            
            
                   (            
            
                       SELECT TOP 1 cpd.PageName            
            
                       FROM   ClientPageDetail cpd            
            
                       WHERE  cpd.Id = ucm.UnsubscribePage            
            
                   )                   AS UnsubscribePage,            
            
                   ucm.Tags,            
            
                   ucm.ExpiryDate,            
            
                   ucm.CreatedOn,            
            
                   ucm.IsActive,            
            
                   ud.User_Login,            
            
                   (            
            
                       SELECT ud.User_Login            
            
                       FROM   User_Detail ud            
            
                       WHERE  ud.[User_ID] = ucm.AccountUsed            
            
                   )                   AS AccountUsed,            
            
                   (            
        
                       SELECT TOP 1 umt.Name            
            
                       FROM   UserMailTemplate             
            
                                          
            
                                          
            
                                          
            
                              umt            
            
                       WHERE  umt.ID = ucm.TemplateID            
            
                   )                   AS TEMPLATEused,            
            
                   (            
            
                       SELECT utgd.GroupName            
            
                       FROM   UserTemplateGroupDetails utgd            
            
                       WHERE  utgd.ID = ucm.TemplateGroupID            
            
       )                   AS TEMPLATEGroup,            
            
                   ucm.NotificationMail,            
            
                   ucm.SuccessNotificationEmail,            
            
                   ucm.FailureNotificationEmail,            
            
                   ucm.IsRecurring,            
            
                   ucm.IsEnding,            
            
                   ucm.TemplateGroupSequence,            
            
                   ucm.IsNeverExpire,          
           ucm.IsSurplusExclusions,            
            
                   ucm.EventsName,            
            
                  (SELECT TOP 1 ucerm.ExecutionTime             
            
                     FROM UserCampaignExecutionHistory AS ucerm WHERE ucerm.CampaignID=ucm.ID ORDER BY ucerm.ExecutionTime DESC)  AS LastScheduledRunTime            
            
            FROM   UserCampaignMaster  AS ucm            
            
                   LEFT JOIN UserSchedules AS us            
            
                        ON  ucm.ScheduleID = us.ID            
          
                   LEFT JOIN User_Detail AS UD(NOLOCK)            
            
                        ON  ucm.Createdby = UD.User_ID             
            
            WHERE  ucm.ParentID = @ParentID            
            
                   AND (            
            
                           ucm.IsActive = CASE             
            
                                               WHEN @IsActive = 1 THEN 1            
            
                                               ELSE NULL            
            
                                          END            
            
                           OR ucm.IsActive = CASE             
            
                                                  WHEN @IsinActive = 1 THEN 0            
            
                                                  ELSE NULL            
            
                                             END            
            
                       )            
            
        )             
    
                    
            
                    
            
                    
            
        A            
            
 ORDER BY            
            
        A.CreatedOn DESC            
            
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCampaignmaster1_voice]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserCampaignmaster1_voice] --17626,1,1  
 @ParentID BIGINT,  
 @IsActive BIT,  
 @IsInActive BIT  
AS  
BEGIN  
 SELECT A.ID,A.CampaignName,(  
'<p><b> Type:</b> ' + CASE   
   WHEN A.IsEventBased = 1 THEN   
        'Event based (' + CASE   
       WHEN A.EventsName ='ENQADD' THEN 'Enquiry Added'  
       ELSE CASE WHEN A.EventsName ='LEDADD' THEN 'Lead Added'  
     ELSE 'Follow Up Added' END END + ')'  ELSE 'Scheduled'  
          END + '</p>' + '<p><b> Medium:</b> ' + A.Medium  
          --CASE WHEN A.MailReplyTo = '' THEN 'SMS' ELSE 'Mail' END   
+ '</p>'  
        )    AS CampaignType,  
        (  
CASE   
     WHEN ISNULL(A.ApplicabiltyName, '') <> '' THEN   
          '<p><b> Applicabilty:</b> ' + ISNULL(A.ApplicabiltyName, '')   
          + ',' + ISNULL(A.AppGroups, '') + ',' + ISNULL(A.AppLists, '')   
          + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.InclusionsNumber, '') <> '' THEN   
    '<p><b> Included Number:</b> ' + A.InclusionsNumber   
    + '</p>'  
           ELSE ''  
      END + CASE   
     WHEN ISNULL(A.ExclusionsName, '') <> '' THEN   
          '<p><b> Exclusions:</b> ' + ISNULL(A.ExclusionsName, '')   
          + ',' + ISNULL(A.ExclusionsGroups, '') +  
          ',' +  
          ISNULL(A.ExclusionsLists, '') + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.ExclusionsNumber, '') <>  
    '' THEN   
    '<p><b> Excluded Numbers:</b> ' + A.ExclusionsNumber   
           + '</p>'  
           ELSE ''  
      END  
      +            
      '<p><b> IsSurplusExclusions:</b> ' + CASE   
         WHEN   
 A.IsSurplusExclusions   
 =  
 1 THEN   
 'Yes'  
        ELSE   
     'No'  
   END   
          + '</p>'          
        )    AS Recipients,  
        (  
CASE   
     WHEN ISNULL(A.AccountUsed, '') <> '' THEN   
          '<p><b> Account:</b> ' + A.AccountUsed + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.SenderID, '') <> '' THEN   
    '<p><b> Sender-ID:</b> ' + A.SenderID + '</p>'  
           ELSE ''  
      END        
      +        
      CASE   
           WHEN ISNULL(A.FromMailID, '') <> '' THEN   
    '<p><b> FromMailID:</b> ' + A.FromMailID + '</p>'  
           ELSE ''  
      END        
       + CASE   
     WHEN ISNULL(A.TEMPLATEused, '') <> '' THEN   
          '<p><b>Template:</b> ' +  
          A.TEMPLATEused + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.TEMPLATEGroup, '') <> '' THEN   
    '<p><b>Template Group:</b> ' + A.TEMPLATEGroup   
    +  
    '</p><p><b>Sequence No&nbsp;:&nbsp;</b>'   
    + CAST(A.TemplateGroupSequence AS VARCHAR(50))   
    + '</p><p>' + CASE           
           WHEN A.IsRecurring   
    = 1 THEN   
    'Recurring'  
           ELSE   
    'Ends After Group Template count Ends'  
      END + '</p>'  
           ELSE ''  
      END + CASE   
     WHEN ISNULL(A.[Message], '') <> '' THEN   
          '<p><b>Message:</b> ' + A.[Message]   
          + '</p>'   
          + '<p><b> IsUnicode:</b> ' + CASE   
        WHEN   
          A.IsUnicode   
 =  
 1 THEN   
 'Yes'  
        ELSE   
 'No'  
   END   
          + '</p>'  
 ELSE ''  
END + CASE   
           WHEN ISNULL(A.MailReplyTo, '')   
    <> '' THEN   
    '<p><b>  Reply To:</b> '   
    + A.MailReplyTo + '</p>'  
           ELSE ''  
      END + CASE   
     WHEN ISNULL(A.MailSubject, '')   
          <> '' THEN   
          '<p><b>  Subject:</b> '   
          + A.MailSubject +  
          '</p>'  
  ELSE ''  
END + CASE   
           WHEN ISNULL(A.MailContent, '')   
    <> '' THEN   
    '<p><b>   Content:</b> '   
    + A.MailContent   
    + '</p>'  
           ELSE ''  
      END  
        )    AS Accounts,  
        (  
CASE   
     WHEN ISNULL(A.TrackResponse, '') <> '' THEN   
          '<p><b>  Track Response:</b> '   
          + A.TrackResponse + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.UnsubscribePage, '')   
    <> '' THEN '<p><b>  Unsubscribe Page:</b> ' + A.UnsubscribePage   
    + '</p>'  
           ELSE ''  
      END + CASE   
     WHEN ISNULL(A.Tags, '') <> '' THEN   
'<p><b>  Tags:</b> ' + A.Tags +  
          '</p>'  
     ELSE ''  
END  
        )    AS Tracking,  
        (  
CASE   
     WHEN ISNULL(A.StartDate, '') <> '' THEN   
          '<p><b>  Start Date at:</b> ' + CAST(A.StartDate AS VARCHAR(50))   
          + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.ExpiryDate, '') <> '' THEN   
    '<p><b>  Expiry Date:</b> ' + CAST( A.ExpiryDate AS VARCHAR(50))   
    + '</p>'  
           ELSE ''  
      END + CASE   
     WHEN ISNULL(A.SceduleName, '') <> '' THEN   
     '<p><b>  Scheduled:</b> ' +  
    A.SceduleName + '</p>'  
     ELSE ''  
END + CASE   
           WHEN ISNULL(A.ExecutedDateTime, '') <>  
    '' THEN '<p><b>  Executed at:</b> ' +  
    CAST( A.ExecutedDateTime AS VARCHAR(50))   
    +  
    '</p>'  
           ELSE ''  
      END + CASE   
     WHEN ISNULL(A.NextExecuteDateTime, '')   
          < > '' THEN   
          '<p><b>  Next Execution at:</b> '   
       + CAST(A.NextExecuteDateTime AS VARCHAR(50))   
          +    
          '</p>'  
     ELSE ''  
END   
+  
CASE   
     WHEN ISNULL(A.LastScheduledRunTime, '')   
          = '' THEN '<p><b>Last Scheduled Run Time:</b> '   
          + 'Never'   
          +  
          '</p>'  
     ELSE '<p><b>Last Scheduled Run Time:</b> '   
          + CAST(A.LastScheduledRunTime AS VARCHAR(50))          +  
          '</p>'  
END  
        )        AS Scheduling,  
        CASE   
 WHEN ISNULL(A.NotificationMail, '') <>  
      '' THEN '<p><b>Notification EMail:</b> ' + CAST(A.NotificationMail AS VARCHAR(250))   
      + '</p>'  
 ELSE ''  
        END + CASE   
       WHEN ISNULL(A.SuccessNotificationEmail, '') <>  
'' THEN '<p><b>Success Notification:</b> ' + CAST(A.SuccessNotificationEmail AS VARCHAR(250))   
+ '</p>'  
       ELSE ''  
  END + CASE   
 WHEN ISNULL(A.FailureNotificationEmail, '') <> '' THEN   
      '<p><b>Failure Notification:</b> ' +  
      CAST(A.FailureNotificationEmail AS VARCHAR(250))   
      + '</p>'  
 ELSE ''  
        END  AS Notifications,  
        A.IsEventBased,  
        A.IsScheduled,  
        A.SceduleName,  
        --A.ExecutedDateTime,  
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) as ExecutedDateTime,    
        --A.NextExecuteDateTime,  
        dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) as NextExecuteDateTime,    
        A.Applicabilty,  
        A.ApplicabiltyName,  
        A.ExclusionsName,  
        A.ExclusionsNumber,  
        A.InclusionsNumber,  
        A.Exclusions,  
        A.SenderID,  
        A.[Message],  
        A.IsUnicode,  
        A.MailReplyTo,  
        A.MailSubject,  
        A.MailContent,  
        A.UnsubscribePage,  
        A.TrackResponse,  
        A.Tags,  
       --A.ExpiryDate,  
         dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) as ExpiryDate,             
        A.User_Login,  
       --A.CreatedOn,  
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,    
        A.IsActive,  
        A.NotificationMail,  
        A.SuccessNotificationEmail,  
        A.FailureNotificationEmail,           
        A.IsRecurring,  
        A.IsEnding,  
        A.TemplateGroupSequence,  
        A.IsNeverExpire,  
        A.EventsName ,            
        A.IsSurplusExclusions,   
        --A.StartDate ,        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) as StartDate,    
        A.FromMailID, a.Medium            
 FROM   (  
SELECT ucm.ID,  
       ucm.CampaignName,        
       ucm.FromMailID,            
       ucm.IsEventBased,  
       ucm.IsScheduled,  
       ucm.StartDate,  
       us.SceduleName,  
       (  
           SELECT TOP 1 uceh.ExecutionTime  
           FROM   UserCampaignExecutionHistory AS uceh  
           WHERE  uceh.CampaignID = ucm.ID  
           ORDER BY  
      uceh.ExecutionTime DESC  
       )       AS ExecutedDateTime,  
       ucm.NextExecuteDateTime,  
       (  
           SELECT STUFF(  
          (  
        SELECT N', ' +  
         usl.SearchName + ' (' + CASE   
  WHEN   
       usl.SearchType   
       =  
       'EN' THEN   
       'Enquiry'  
  ELSE CASE   
WHEN   
  usl.SearchType   
   =  
     'LE' THEN   
       'Leads'  
ELSE CASE   
          WHEN   
   usl.SearchType   
   =  
   'Co' THEN   
   'Conversion'  
          ELSE CASE   
      WHEN   
 usl.SearchType   
 =  
 'Ls' THEN   
 'Uploaded List'  
        ELSE CASE   
      WHEN   
           usl.IsResponse   
          =  
           1 THEN   
           'Response'  
      ELSE CASE   
    WHEN   
         usl.IsUnsubscribe   
         =  
      1 THEN   
         'Unsubscribe'  
    ELSE   
         ''  
           END  
 END  
   END  
     END  
       END  
         END +  
         ')'  
 FROM   UserSearchList AS usl  
         INNER JOIN dbo.fn_Split(ucm.Applicabilty, '#') AS   
  fs  
           ON  usl.ID = fs.[value] FOR   
        XML PATH(''),  
         TYPE  
          ) .value('text()[1]', 'nvarchar(max)'),  
          1,  
          2,  
          N''  
      )  
       )       AS ApplicabiltyName,  
       ucm.Applicabilty,  
 ucm.ExclusionsNumber,  
       (  
           SELECT STUFF(  
          (  
  SELECT N', ' + usl.SearchName +  
         ' (' + CASE   
         WHEN usl.SearchType   
  = 'EN' THEN   
  'Enquiry'  
         ELSE CASE   
       WHEN usl.SearchType   
=  
'LE' THEN   
'Leads'  
       ELSE CASE   
     WHEN   
          usl.SearchType   
          =  
          'Co' THEN   
          'Conversion'  
     ELSE CASE   
   WHEN   
        usl.SearchType   
       =  
        'Ls' THEN   
        'Uploaded List'  
   ELSE CASE   
WHEN   
      usl.IsResponse   
      =  
       1 THEN   
      'Response'  
 ELSE CASE   
           WHEN   
    usl.IsUnsubscribe   
    =  
    1 THEN   
           'Unsubscribe'  
           ELSE   
    ''  
      END  
        END  
          END  
          END  
  END  
    END + ')'  
  FROM   UserSearchList AS usl  
         INNER JOIN dbo.fn_Split(ucm.Exclusions, '#') AS   
  fs  
   ON  usl.ID = fs.[value] FOR   
      XML PATH(''),  
         TYPE  
          ) .value('text()[1]', 'nvarchar(max)'),  
          1,  
          2,  
          N''  
      )  
       )       AS ExclusionsName,  
       (  
           SELECT STUFF(  
          (  
  SELECT N', ' + gd.Group_Name +  
         ' (Groups)'  
  FROM   Group_Detail AS gd  
         INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS   
          fs  
  ON  gd.Group_ID = fs.[value]   
      FOR XML PATH(''),  
         TYPE  
          ) .value('text()[1]', 'nvarchar(max)'),  
          1,  
          2,  
          N''  
      )  
  )       AS ExclusionsGroups,  
       (  
           SELECT STUFF(  
          (  
  SELECT N', ' + gd.ImportName +  
         ' (Imported Lists)'  
  FROM   UserImportedListColumn AS gd  
         INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS   
  fs  
  ON  gd.ID = fs.[value] FOR   
      XML PATH(''),  
         TYPE  
          ) .value('text()[1]', 'nvarchar(max)'),  
          1,  
          2,  
     N''  
      )  
       )       AS ExclusionsLists,  
       (  
          SELECT STUFF(  
          (  
  SELECT N', ' + gd.Group_Name +  
         ' (Groups)'  
  FROM   Group_Detail AS gd  
         INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS   
  fs  
  ON  gd.Group_ID = fs.[value]   
      FOR XML PATH(''),  
       TYPE  
          ) .value('text()[1]', 'nvarchar(max)'),  
          1,  
          2,  
          N''  
      )  
       )       AS AppGroups,  
       (  
           SELECT STUFF(  
          (  
  SELECT N', ' + gd.ImportName +  
         ' (Imported Lists)'  
     FROM   UserImportedListColumn AS gd  
         INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS   
  fs  
  ON  gd.ID = fs.[value] FOR         
      XML PATH(''),  
         TYPE  
          ) .value('text()[1]', 'nvarchar(max)'),  
          1,  
          2,  
          N''  
      )  
       )       AS AppLists,  
       ucm.InclusionsNumber,  
       ucm.Exclusions,  
       ucm.SenderID,  
       ucm.[Message],  
       ucm.IsUnicode,  
       ucm.MailReplyTo,  
       ucm.MailSubject,  
       ucm.MailContent,  
       (  
           SELECT TOP 1 cpd.PageName  
      FROM   ClientPageDetail cpd  
           WHERE  cpd.Id = ucm.TrackResponse  
       )       AS TrackResponse,  
       (  
           SELECT TOP 1 cpd.PageName  
           FROM   ClientPageDetail cpd  
           WHERE  cpd.Id = ucm.UnsubscribePage  
       )       AS UnsubscribePage,  
       ucm.Tags,  
       ucm.ExpiryDate,  
       ucm.CreatedOn,  
       ucm.IsActive,  
       ud.User_Login,  
       (  
           SELECT ud.User_Login  
           FROM   User_Detail ud  
           WHERE  ud.[User_ID] = ucm.AccountUsed  
       )       AS AccountUsed,  
       (  
           SELECT TOP 1 umt.Name  
           FROM   UserMailTemplate   
      umt  
           WHERE  umt.ID = ucm.TemplateID       
       )       AS TEMPLATEused,  
       (  
           SELECT utgd.GroupName  
           FROM   UserTemplateGroupDetails utgd  
           WHERE  utgd.ID = ucm.TemplateGroupID  
       )       AS TEMPLATEGroup,  
       ucm.NotificationMail,  
       ucm.SuccessNotificationEmail,  
       ucm.FailureNotificationEmail,  
       ucm.IsRecurring,  
       ucm.IsEnding,  
       ucm.TemplateGroupSequence,  
       ucm.IsNeverExpire,            
           ucm.IsSurplusExclusions,  
       ucm.EventsName,  
      (SELECT TOP 1 ucerm.ExecutionTime   
         FROM UserCampaignExecutionHistory AS ucerm WHERE ucerm.CampaignID=ucm.ID ORDER BY ucerm.ExecutionTime DESC)  AS LastScheduledRunTime, ucm.Medium  
FROM   UserCampaignMaster  AS ucm  
       LEFT JOIN UserSchedules AS us  
ON  ucm.ScheduleID = us.ID  
       LEFT JOIN User_Detail AS UD(NOLOCK)  
ON  ucm.Createdby = UD.User_ID   
WHERE  ucm.ParentID = @ParentID  
       AND (  
   ucm.IsActive = CASE   
           WHEN @IsActive = 1 THEN 1  
           ELSE NULL  
      END  
   OR ucm.IsActive = CASE   
  WHEN @IsinActive = 1 THEN 0  
  ELSE NULL  
         END  
           )  
        )   
        A  
 ORDER BY  
        A.CreatedOn DESC  
END   


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCampaignmaster1_WithNewCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserCampaignmaster1_WithNewCriteria] --335,1,1                        
                        
 @ParentID BIGINT,                        
                        
 @IsActive BIT,                        
                        
 @IsInActive BIT                        
                        
AS                        
                        
BEGIN                        
                        
 SELECT A.ID,                        
                        
        A.CampaignName,                        
                        
        (                        
                        
            '<p><b> Type:</b> ' + CASE                         
                        
                                       WHEN A.IsEventBased = 1 THEN                         
                        
                                            'Event based (' + CASE                         
                        
                                                                   WHEN A.EventsName                         
                        
                                                                                                
                        
                                                                                                
                        
                                                                                                
                        
                                                                        =                        
                        
                                                                                                
                        
                                                                        'ENQADD' THEN                         
                        
                                                                        'Enquiry Added'                        
                        
                                                                   ELSE CASE                         
                        
                                                                             WHEN                         
                        
                                                                                  A.EventsName                         
                        
                                                                                                          
                        
                                                                                                          
                        
                                                                                                          
                        
                                                                                  =                        
                        
                                                                                                          
                        
                                                                                                          
                        
                                                                                                          
                        
                                                                                  'LEDADD' THEN                         
                        
                                                                                   'Lead Added'                        
                        
                                                                             ELSE                         
                                                                                CASE                         
                        
                                                                             WHEN                         
                        
                                                                                  A.EventsName                
                        
                        
                                                                                  =           
                        
                                                                                                          
        
                                                                                  'FOLADD' THEN                         
                        
                                                                  'Follow Up Added'          
                         else          
                                    
                                                                         'Follow Up Due'                        
                        
                                                                           End          
                  END                        
                        
                                                              END + ')'                        
                        
                                       ELSE 'Scheduled'                        
                        
                                  END + '</p>' + '<p><b> Medium:</b> ' + A.Medium         
                  
                                --CASE                         
                                --                      WHEN                         
                                --                         A.MailReplyTo =                        
                                --                         '' THEN                         
                                --                          'SMS'                        
                                --                          ELSE                         
                                --                             'Mail'                        
                                --                          END                         
                                    
                        
            + '</p>'                        
                        
        )                AS CampaignType,                        
                        
        (                        
                        
            CASE                         
                        
                 WHEN ISNULL(A.ApplicabiltyName, '') <> '' THEN                         
                        
                      '<p><b> Applicabilty:</b> ' + ISNULL(A.ApplicabiltyName, '')                         
                                              
                        
                      + ',' + ISNULL(A.AppGroups, '') + ',' + ISNULL(A.AppLists, '')                         
                                              
                        
                      + '</p>'                        
                        
                 ELSE ''                        
                        
            END + CASE                         
                        
                       WHEN ISNULL(A.InclusionsNumber, '') <> '' THEN                         
                        
                            '<p><b> Included Number:</b> ' + A.InclusionsNumber                         
                                                    
                        
                            + '</p>'                        
                        
                       ELSE ''                        
                        
                  END + CASE                         
                        
                             WHEN ISNULL(A.ExclusionsName, '') <> '' THEN                         
                        
                                  '<p><b> Exclusions:</b> ' + ISNULL(A.ExclusionsName, '')                         
                                                          
                        
                          + ',' + ISNULL(A.ExclusionsGroups, '') +                        
                        
                                                          
      
                                ',' +                        
                        
                                                          
                        
                                  ISNULL(A.ExclusionsLists, '') + '</p>'                        
                        
                             ELSE ''                        
                        
                        END + CASE                         
                        
                                   WHEN ISNULL(A.ExclusionsNumber, '') <>                        
                        
                                                                
                        
                                                                
                        
                                                                
             
                                        '' THEN                         
                        
                                        '<p><b> Excluded Numbers:</b> ' + A.ExclusionsNumber                         
                        
                                                                
                        
                                                                
                        
                                                                
                        
                                   + '</p>'                        
                        
                                   ELSE ''                        
                        
                              END                        
                                                    
                              +                      
                              '<p><b> IsSurplusExclusions:</b> ' + CASE                         
                        
                                                                     WHEN                         
                        
                                                                                     A.IsSurplusExclusions                         
                        
                                                                                                             
                        
                                       
                        
                                                                                                             
                        
                                                                                     =                        
                        
                                                                                                             
                        
                                                                                                             
                        
                                                                                                             
                        
                                                                                     1 THEN                         
                        
                                                                                     'Yes'                        
                        
                                                                                ELSE       
                        
                                                     'No'                        
                        
                                                                           END                         
                        
                                                                      
                        
                                                                      
                        
                                
                        
                                              + '</p>'                                
                      
                                                    
           
        )   AS Recipients,                        
                        
        (                        
                        
            CASE                         
                        
                 WHEN ISNULL(A.AccountUsed, '') <> '' THEN                         
                        
       '<p><b> Account:</b> ' + A.AccountUsed + '</p>'                        
                        
                 ELSE ''                        
                        
            END + CASE                         
                        
                       WHEN ISNULL(A.SenderID, '') <> '' THEN                         
                        
                            '<p><b> Sender-ID:</b> ' + A.SenderID + '</p>'                        
                        
                       ELSE ''                        
                        
                  END                  
                  +                  
                                    
                  CASE                         
                        
                       WHEN ISNULL(A.FromMailID, '') <> '' THEN                         
                        
                            '<p><b> FromMailID:</b> ' + A.FromMailID + '</p>'                        
                        
                       ELSE ''                        
                        
                  END                  
                                    
                                    
                   + CASE                         
                        
                             WHEN ISNULL(A.TEMPLATEused, '') <> '' THEN                         
                        
                                  '<p><b>Template:</b> ' +                        
                        
                                                          
                        
                                                          
                        
                                                          
                        
                                  A.TEMPLATEused + '</p>'                        
                        
                             ELSE ''                        
                        
                        END + CASE                         
                        
                                   WHEN ISNULL(A.TEMPLATEGroup, '') <> '' THEN                         
                        
                                        '<p><b>Template Group:</b> ' + A.TEMPLATEGroup                         
                        
                                                                
                        
                                                                
                        
                                                                
                        
                                        +                        
                        
                                                                
                        
                                                                
                        
                                                                
                        
                                        '</p><p><b>Sequence No&nbsp;:&nbsp;</b>'                         
                        
                                                                
                        
                                                                
                        
                                       
                        
                                        + CAST(A.TemplateGroupSequence AS VARCHAR(50))                         
                        
                                                                
                        
                                                                
                        
                                                                
                        
                                        + '</p><p>' + CASE             
                                                           WHEN A.IsRecurring                  
                                                                                        
                        
                                                                = 1 THEN                         
                        
                                                                'Recurring'                        
                        
                     ELSE                         
                        
'Ends After Group Template count Ends'                        
                        
                                                      END + '</p>'                        
                        
                                   ELSE ''                        
                        
                              END + CASE                         
                        
                                         WHEN ISNULL(A.[Message], '') <> '' THEN                         
                        
                                              '<p><b>Message:</b> ' + A.[Message]                         
                        
                                                                      
                        
                                              + '</p>'                         
                        
                                                                      
                        
                                              + '<p><b> IsUnicode:</b> ' + CASE                         
                        
                                                                                WHEN                         
                        
                                              A.IsUnicode                         
                        
                       
                        
                                                                                                             
                        
                                                                                                             
                        
                                                                                     =                        
                        
                                                                                                             
                        
                                                                                                             
                        
                                                                                                             
                        
                                                                                     1 THEN                         
                        
                                                                                     'Yes'                        
                        
                      ELSE                         
                        
                                                                                     'No'                        
                        
                                                                           END                         
                        
                                                                      
                        
                                                                      
                        
                                                                      
                        
                                              + '</p>'                        
                        
                                     ELSE ''                        
                  
                                    END + CASE                         
                        
                                               WHEN ISNULL(A.MailReplyTo, '')                         
                        
                                                               
                        
                                                                            
                        
                                                                            
                        
                                                    <> '' THEN                         
                        
                                                    '<p><b>  Reply To:</b> '                         
                        
                      
                        
                                                                            
                                                                            
                        
                                                    + A.MailReplyTo + '</p>'                        
                        
                                               ELSE ''                        
                        
                                          END + CASE                         
                        
                                                     WHEN ISNULL(A.MailSubject, '')                         
                        
                                                                                  
                        
                                         
                        
                                                                                  
                        
                                                          <> '' THEN                         
                        
                                                          '<p><b>  Subject:</b> '                         
                        
                                                                                  
                        
                                                                                  
                        
                                                                         
                        
                                                          + A.MailSubject +                        
                        
                                                                                  
                        
                                                                                  
                        
                                          
                        
                                                          '</p>'                        
                        
                          ELSE ''                        
                        
                                                END + CASE                         
                        
                                                           WHEN ISNULL(A.MailContent, '')                         
                        
                                                                                        
                        
                                                                                        
                        
                                                                         
                        
                                                                <> '' THEN                         
                        
                                                                '<p><b>   Content:</b> '                         
                        
                                                                                        
                        
                                                                                    
                        
                                                    
                        
                                                                + A.MailContent                         
                        
                                                                                        
                        
                     
                        
                                                                                        
                        
                                                                + '</p>'                        
                        
                                                           ELSE ''                        
                        
                                                      END                        
                        
        )                AS Accounts,                        
                        
        (                        
                        
            CASE                         
                        
                 WHEN ISNULL(A.TrackResponse, '') <> '' THEN                         
                        
                      '<p><b>  Track Response:</b> '                         
                        
                                              
                   
                                              
                        
                                              
                        
                      + A.TrackResponse + '</p>'                        
                        
              ELSE ''                        
                        
            END + CASE                         
                        
                       WHEN ISNULL(A.UnsubscribePage, '')                         
                        
                                                    
                        
                                                    
                        
                                                    
                        
                            <> '' THEN '<p><b>  Unsubscribe Page:</b> ' + A.UnsubscribePage                         
                        
                                                    
                        
                                                    
                        
                                                    
                        
                            + '</p>'                        
                        
                       ELSE ''                        
                        
                  END + CASE                         
                        
                             WHEN ISNULL(A.Tags, '') <> '' THEN                         
                        
                                  '<p><b>  Tags:</b> ' + A.Tags +                        
                        
                                                          
                        
                                                          
                        
                                                          
                        
                                  '</p>'                        
                        
                             ELSE ''                        
                        
                        END                        
                        
        )                AS Tracking,                        
                        
        (                        
                        
            CASE                         
                        
                 WHEN ISNULL(A.StartDate, '') <> '' THEN                  
                        
                      '<p><b>  Start Date at:</b> ' + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) AS VARCHAR(50))                         
                        
                         
                        
                                              
                        
                                              
                        
                      + '</p>'                        
                        
                 ELSE ''                        
                        
            END + CASE                         
                        
                       WHEN ISNULL(A.ExpiryDate, '') <> '' THEN                         
                     
                            '<p><b>  Expiry Date:</b> ' + CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) AS VARCHAR(50))                         
                        
                                                    
                        
                                                    
                        
                          
                        
                            + '</p>'                        
                        
                       ELSE ''                        
                        
                  END + CASE                         
                        
                             WHEN ISNULL(A.SceduleName, '') <> '' THEN                         
                        
                 '<p><b>  Scheduled:</b> ' +                        
                        
                                                          
                        
                                                          
                        
                                                          
                        
    A.SceduleName + '</p>'                        
                        
                             ELSE ''                        
                        
                        END + CASE                         
                        
                                   WHEN ISNULL(A.ExecutedDateTime, '') <>                        
                        
                                                                
                        
                                                
                        
                                                                
                        
                                        '' THEN '<p><b>  Executed at:</b> ' +                        
                        
                                                                
                        
                                                                
                        
                                
                        
                                        CAST( dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) AS VARCHAR(50))                         
                        
                                                                
                        
                                                                
                        
                                                                
                        
                                        +                        
                        
                                             
                        
                                                                
                        
                                                      
                        
                                        '</p>'                        
                        
                                   ELSE ''                        
                        
                              END + CASE                         
                        
                                         WHEN ISNULL(A.NextExecuteDateTime, '')                         
                        
                                                                      
                        
                                                                      
                        
                                  
                        
                                              < > '' THEN                         
                        
                                              '<p><b>  Next Execution at:</b> '                         
                        
                                                                      
                        
                                                                      
                        
                                                                      
                        
                              + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) AS VARCHAR(50))                         
                        
                                                                      
                        
                                                                      
                        
                                                                      
                        
          +              
                        
                                                                      
                        
                                                                      
                        
                                                          
                        
                                              '</p>'                        
                        
                                         ELSE ''                        
                        
                                    END                         
                        
                                    
                        
            +                        
                        
                                    
                        
                                    
                        
                                    
                        
            CASE                         
                        
                 WHEN ISNULL(A.LastScheduledRunTime, '')                         
                        
                                              
                        
                                              
                        
                                              
                        
                      = '' THEN '<p><b>Last Scheduled Run Time:</b> '                         
                        
                                              
                        
                                              
                        
                                              
                        
                      + 'Never'                         
                 
                                              
                        
                                              
                        
                                              
                        
                      +                        
                        
                                              
                        
                                              
                        
                
                        
                      '</p>'                        
                        
                 ELSE '<p><b>Last Scheduled Run Time:</b> '                         
                        
                                              
                        
                       
                        
                                              
                        
                      + CAST(dbo.[fn_getusertimefromindiantime](@ParentID,A.LastScheduledRunTime) AS VARCHAR(50))                         
                        
                                              
                        
                      +                        
                        
                                              
                        
                      '</p>'                        
                        
            END                        
                        
        )        AS Scheduling,                        
                        
        CASE                         
                        
WHEN ISNULL(A.NotificationMail, '') <>                        
                        
                                          
                        
                                          
                        
                                          
                        
                  '' THEN '<p><b>Notification EMail:</b> ' + CAST(A.NotificationMail AS VARCHAR(250))                         
                        
                                          
                        
                                          
                        
                                          
                        
                  + '</p>'                        
                        
             ELSE ''                        
                        
        END + CASE                         
                        
                   WHEN ISNULL(A.SuccessNotificationEmail, '') <>                        
                        
                                                
                        
                                                
                        
                  
                        
                        '' THEN '<p><b>Success Notification:</b> ' + CAST(A.SuccessNotificationEmail AS VARCHAR(250))                         
                        
                                                
                        
                                                
                        
                                                
       
                        + '</p>'                        
                        
                   ELSE ''                        
                        
              END + CASE                         
                        
                         WHEN ISNULL(A.FailureNotificationEmail, '') <> '' THEN                         
                        
                              '<p><b>Failure Notification:</b> ' +                        
                        
                                                      
                        
                                                      
                        
                                                     
                        
                              CAST(A.FailureNotificationEmail AS VARCHAR(250))                         
                        
                                                      
                        
                                         
                        
                                                      
                        
                              + '</p>'                        
                        
                         ELSE ''                        
                        
                    END  AS Notifications,                        
                        
        A.IsEventBased,                        
                        
        A.IsScheduled,                        
                        
        A.SceduleName,                        
                        
        --A.ExecutedDateTime,                        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.ExecutedDateTime) as ExecutedDateTime,              
                        
       -- A.NextExecuteDateTime,            
        dbo.[fn_getusertimefromindiantime](@ParentID,A.NextExecuteDateTime) as NextExecuteDateTime,                          
        A.Applicabilty,                        
                        
        A.ApplicabiltyName,                        
                        
        A.ExclusionsName,                        
                        
        A.ExclusionsNumber,                        
                        
        A.InclusionsNumber,                        
                        
        A.Exclusions,                        
                        
        A.SenderID,                        
                        
        A.[Message],                        
                        
        A.IsUnicode,                        
                        
        A.MailReplyTo,                        
                        
        A.MailSubject,                        
                        
        A.MailContent,                        
                      
        A.UnsubscribePage,                        
                        
        A.TrackResponse,                        
                        
        A.Tags,                        
                        
      -- A.ExpiryDate,            
         dbo.[fn_getusertimefromindiantime](@ParentID,A.ExpiryDate) as ExpiryDate,                       
                    
        A.User_Login,                        
      -- A.CreatedOn,                        
                    
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,                          
                    
        A.IsActive,                        
                        
        A.NotificationMail,                        
                        
        A.SuccessNotificationEmail,                        
                        
        A.FailureNotificationEmail,                     
                        
        A.IsRecurring,                        
                        
        A.IsEnding,                        
                        
        A.TemplateGroupSequence,                        
                        
        A.IsNeverExpire,                        
                        
        A.EventsName ,                      
        A.IsSurplusExclusions,             
                           
        --A.StartDate ,                  
        dbo.[fn_getusertimefromindiantime](@ParentID,A.StartDate) as StartDate,                          
                    
        A.FromMailID,    
  A.Medium                      
                               
                        
 FROM   (                        
                        
            SELECT ucm.ID,                        
                        
                ucm.CampaignName,                  
                   ucm.FromMailID,                      
                        
                   ucm.IsEventBased,                        
                        
                   ucm.IsScheduled,                        
                        
                   ucm.StartDate,                        
                        
                   us.SceduleName,                        
                        
                   (                        
                        
                       SELECT TOP 1 uceh.ExecutionTime                        
                        
                       FROM   UserCampaignExecutionHistory AS uceh                        
                        
                       WHERE  uceh.CampaignID = ucm.ID                        
                        
                       ORDER BY                        
                        
                              uceh.ExecutionTime DESC                        
                        
                   )                   AS ExecutedDateTime,                        
                        
                   ucm.NextExecuteDateTime,                        
                        
                   (                        
                        
                       SELECT STUFF(                        
                        
                                  (                        
                        
                                SELECT N', ' +                        
                        
                                             usl.CriteriaName + ' (' +                     
                        
                                                                                                 
                                                   usl.CriteriaType   +  
                                                                     
                        
                                             ')'                        
                        
                         FROM   tbl_SearchCriteria(nolock) AS usl                        
                        
                                             INNER JOIN dbo.fn_Split(ucm.Applicabilty, '#') AS                         
                        
                                                  fs                        
                        
                       ON  usl.ID = fs.[value] FOR                        
                        
                                            XML PATH(''),                        
                        
                                             TYPE                        
                        
                                  ) .value('text()[1]', 'nvarchar(max)'),                        
                        
                                  1,                        
                        
                                  2,                        
                        
                                  N''                        
                        
                              )                        
                        
                   )                   AS ApplicabiltyName,                        
                    
                  ucm.Applicabilty,                        
                        
             ucm.ExclusionsNumber,                        
                        
                   (                        
                        
                       SELECT STUFF(                        
                        
                                  (                        
                        
                                      SELECT N', ' + usl.CriteriaName +                        
                        
                                                                     
                        
                                                                     
                                                                     
                        
                                             ' (' +                          
                        
                                                     usl.CriteriaType                         
                        
                                                                                
                        
                                                    + ')'                        
                        
                                     -- FROM   UserSearchList AS usl                
                                        FROM   tbl_SearchCriteria(nolock) AS usl                
                                             INNER JOIN dbo.fn_Split(ucm.Exclusions, '#') AS                         
                        
                                                  fs                        
                        
                                       ON  usl.ID = fs.[value] FOR                         
                        
                                                      XML PATH(''),                        
                        
                                             TYPE                        
                        
                                  ).value('text()[1]', 'nvarchar(max)'),                        
                        
                                  1,                        
                        
                                  2,                        
                        
                                  N''                        
                        
                              )                        
                        
                   )                   AS ExclusionsName,                        
                        
                   (                        
                        
                       SELECT STUFF(                        
                        
                                  (                        
                        
                                      SELECT N', ' + gd.Group_Name +                        
                                                                     
                        
                                             ' (Groups)'                        
                        
                                      FROM   Group_Detail AS gd                        
                        
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS                         
                        
                                              fs                        
            
                                                  ON  gd.Group_ID = fs.[value]                         
                        
                                                                              
                        
                                                                              
                        
                                                                              
                        
                                                      FOR XML PATH(''),                        
                        
                                             TYPE                        
                        
                                  ) .value('text()[1]', 'nvarchar(max)'),                        
                        
                                  1,                        
                        
                                  2,                        
                        
                                  N''                        
                    
                              )                        
                        
              )                   AS ExclusionsGroups,                        
                        
                   (                        
                        
                       SELECT STUFF(                        
                        
                                  (                        
                        
                                      SELECT N', ' + gd.ImportName +                        
                        
                                                                     
                        
                                                                     
                        
                                                                     
                        
                                             ' (Imported Lists)'                     
                        
                                      FROM   UserImportedListColumn AS gd                        
                        
                                             INNER JOIN dbo.fn_Split(ucm.ExclusionsGroupList, '#') AS                         
                        
                                                  fs                        
                        
                                                  ON  gd.ID = fs.[value] FOR                         
                        
                                                                              
                        
                                                                              
                        
                                                                              
                        
                                                      XML PATH(''),                        
                        
                                             TYPE                        
                        
                                  ) .value('text()[1]', 'nvarchar(max)'),                        
                        
                                  1,                        
                        
                                  2,                        
                        
                             N''                        
                        
                              )           
                        
                   )                   AS ExclusionsLists,                        
                        
                   (                        
                        
          SELECT STUFF(                        
                        
                                  (                        
                        
                                      SELECT N', ' + gd.Group_Name +                        
             
                                                                     
                        
                                                                     
                        
                                                                     
                        
                                             ' (Groups)'                        
                        
                                      FROM   Group_Detail AS gd                        
                        
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS                         
                        
       fs                        
                        
                                                  ON  gd.Group_ID = fs.[value]                         
                        
                                                                              
                        
                                                                              
                        
                                                                              
                        
                                                      FOR XML PATH(''),                        
                        
                                           TYPE                        
                        
                                  ) .value('text()[1]', 'nvarchar(max)'),                        
                        
                                  1,                        
                        
                                  2,                        
                        
                                  N''                        
                        
                              )                        
                        
                   )                   AS AppGroups,                        
                        
       (                        
                        
                       SELECT STUFF(                        
                        
                                  (                        
                        
                          SELECT N', ' + gd.ImportName +                        
                        
                                                                     
          
                                                                     
                        
                                                                     
                        
                                             ' (Imported Lists)'                        
                        
     FROM   UserImportedListColumn AS gd                        
                        
                                             INNER JOIN dbo.fn_Split(ucm.ApplicabiltyGroupList, '#') AS                         
                        
                                                  fs                        
                        
                                                  ON  gd.ID = fs.[value] FOR                   
                        
                                                                              
                        
                                                                              
                        
                                                                              
                        
                                                      XML PATH(''),                        
                        
                                             TYPE                        
                        
                                  ) .value('text()[1]', 'nvarchar(max)'),                        
             
                                  1,                        
                        
                                  2,                        
                        
                                  N''                        
                        
                              )                
                        
                   )                   AS AppLists,                        
                        
                   ucm.InclusionsNumber,                        
                        
                   ucm.Exclusions,                        
                        
                   ucm.SenderID,                        
                        
                   ucm.[Message],                        
                        
                   ucm.IsUnicode,                        
                        
                   ucm.MailReplyTo,                        
                        
                   ucm.MailSubject,                        
                        
                   ucm.MailContent,                        
                        
                   (                        
                        
                       SELECT TOP 1 cpd.PageName                        
                        
      FROM   ClientPageDetail cpd                        
                        
                       WHERE  cpd.Id = ucm.TrackResponse                        
                        
                   )                   AS TrackResponse,                   
                        
                   (                        
                        
                       SELECT TOP 1 cpd.PageName                        
                        
                       FROM   ClientPageDetail cpd                        
                        
                       WHERE  cpd.Id = ucm.UnsubscribePage                        
                        
                   )                   AS UnsubscribePage,                        
                        
                   ucm.Tags,                        
                        
                   ucm.ExpiryDate,                        
                        
                   ucm.CreatedOn,                        
                        
                   ucm.IsActive,                        
                        
                   ud.User_Login,                        
                        
                   (                        
                        
                       SELECT ud.User_Login                        
                        
                       FROM   User_Detail ud                        
                        
                       WHERE  ud.[User_ID] = ucm.AccountUsed                        
                        
                   )                   AS AccountUsed,                        
                        
                   (                        
                    
                       SELECT TOP 1 umt.Name                        
                        
                       FROM   UserMailTemplate                         
                        
                                                      
                        
                                                      
                        
                                                      
                        
                              umt                        
                        
                       WHERE  umt.ID = ucm.TemplateID                 
                        
                   )                   AS TEMPLATEused,                        
                        
                   (                        
                        
                       SELECT utgd.GroupName                        
                        
                       FROM   UserTemplateGroupDetails utgd                        
                        
             WHERE  utgd.ID = ucm.TemplateGroupID                        
                        
       )                   AS TEMPLATEGroup,                        
                        
                   ucm.NotificationMail,                        
                                         ucm.SuccessNotificationEmail,                        
                        
  ucm.FailureNotificationEmail,                        
                        
                   ucm.IsRecurring,                        
                        
                   ucm.IsEnding,                        
                        
                   ucm.TemplateGroupSequence,                        
                        
                   ucm.IsNeverExpire,                      
           ucm.IsSurplusExclusions,                        
                        
                   ucm.EventsName,                        
                   ucm.Medium,        
                  (SELECT TOP 1 ucerm.ExecutionTime                         
                        
                     FROM UserCampaignExecutionHistory AS ucerm WHERE ucerm.CampaignID=ucm.ID ORDER BY ucerm.ExecutionTime DESC)  AS LastScheduledRunTime                        
                        
            FROM   UserCampaignMaster  AS ucm                        
                        
                   LEFT JOIN UserSchedules AS us                        
                        
                        ON  ucm.ScheduleID = us.ID                        
                      
                   LEFT JOIN User_Detail AS UD(NOLOCK)                        
                        
                        ON  ucm.Createdby = UD.User_ID                         
                        
            WHERE  ucm.ParentID = @ParentID and  isnull(UCM.EventID,0) = 0                         
                        
                   AND (                        
                        
                           ucm.IsActive = CASE                         
                        
                                               WHEN @IsActive = 1 THEN 1                        
                        
                                               ELSE NULL                        
                        
                                          END                        
                        
                           OR ucm.IsActive = CASE                         
                        
                                                  WHEN @IsinActive = 1 THEN 0                        
                        
                                                  ELSE NULL                        
                        
                                             END                        
                        
                       )                        
                        
        )                         
                
                                
                        
                                
                        
                                
                        
        A                        
                        
 ORDER BY                        
                        
        A.CreatedOn DESC                        
                        
END 


GO

