SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].usp_getUserConversionsListByMode
(
	@Mode nvarchar(25),
	@UserId bigint,
	@UserIds nvarchar(max) = null,
	@SearchText nvarchar(max) = null,
	@Contain nvarchar(max) = null,
	@FromDate date = null,
	@ToDate date = null,
	@Offsets int = 0,
	@PageSize int = 20

)
AS
BEGIN
	IF(@Mode = 'consolidated')
	BEGIN
		exec usp_getUserConversionsListConsolidated @UserId, 
			@UserIds, @SearchText, @Contain, @FromDate, @ToDate, @Offsets, @PageSize
	END

	IF(@Mode = 'individual')
	BEGIN
		exec usp_getUserConversionsListIndividual @UserId, 
			@UserIds, @SearchText, @Contain, @FromDate, @ToDate, @Offsets, @PageSize
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_getUserConversionsListConsolidated]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getUserConversionsListConsolidated]
(
	@UserId bigint,
	@UserIds nvarchar(max),
	@SearchText nvarchar(max),
	@Contain nvarchar(max),
	@FromDate date = null,
	@ToDate date = null,
	@Offsets int = 0,
	@PageSize int = 20

)
AS
BEGIN  

	--DECLARE
	--	@UserId bigint = 32222,
	--	@UserIds nvarchar(max),
	--	@SearchText nvarchar(max) = N'', --N'[{"FieldName":"LeadNo","Operator":"equal to","FirstValue":253413,"SecondValue":""}]',
	--	@Contain nvarchar(max) = N'179004',
	--	@FromDate date = null,
	--	@ToDate date = null,
	--	@Offsets int = 0,
	--	@PageSize int = 20

	--select @UserId=49503,@UserIds='',@SearchText='',@Contain='',@FromDate=N'29-Nov-2025',@ToDate=N'04-Dec-2025',@Offsets=0,@PageSize=10

	declare @ParentId BIGINT

	set @fromdate = '19000101'
	select @FromDate=coalesce(@fromdate,'19000101'), @ToDate=coalesce(@ToDate,dateadd(d,1,getdate()))

	declare @customFilter nvarchar(max) = ''

	if(isjson(@SearchText) = 1)
	begin
		select @customFilter = concat((
			case when len(@customFilter) > 0 then concat(' and ', @customFilter) else '' end ),
			concat( FieldName, (case Operator 
				when 'equal to' then concat(' = ', '''', FirstValue, '''') 
				when 'between' then concat(' between ''', FirstValue, ''' and ''', SecondValue, '''' )
				else concat(' like ', '''', FirstValue, '''') end 
			)))
		from openjson(@SearchText) with (
			FieldName nvarchar(255) '$.FieldName',
			Operator nvarchar(255) '$.Operator',
			FirstValue nvarchar(2000) '$.FirstValue',
			SecondValue nvarchar(2000) '$.SecondValue'
		)
	end

	print concat('@customFilter => ', @customFilter)
	if(isnull(@customFilter, '') = '')
	begin
		set @customFilter = ' 1 = 1 '
	end


	if(isnull(@Contain, '') = '')
	begin
		set @Contain = '1 = 1'
	end
	else
	begin
		set @Contain = CONCAT(
			N'LeadNo like ''%', @Contain, '%''',
			'or PersonName like ''%', @Contain, '%''',
			'or EmailID like ''%', @Contain, '%''',
			'or MobileNo like ''%', @Contain, '%'''
		) 
	end
	
	DECLARE @UserID_ForDatetimeConversion BIGINT = @UserId  
  
	IF ( @Userid = NULL OR @Userid = 0 )  
	BEGIN  
		SET @UserID_ForDatetimeConversion = @ParentID  
	END  
  
	DECLARE @IsAdmin BIT = 0  
  
	SELECT TOP 1 @IsAdmin = isAdmin, @ParentId = ParentID FROM User_Detail WITH (NOLOCK) WHERE User_ID = @Userid  
  
	declare @StartPoint int = (@Offsets + 1)
	declare @EndPoint int = (@Offsets + @PageSize)


	 drop table if exists #tempUsers  
	 create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))    
	 insert into #tempUsers(User_ID, Name, Image)    
	 exec Use_GetUserDetails @UserID = @UserId    
	 

	declare @filterSql nvarchar(max) = concat(N'; WITH cteConsolidated as ( SELECT ',
			N'(ROW_NUMBER() OVER(PARTITION BY t.ParentID ORDER BY t.OrderDate DESC)) as  [Sno], ',
			N'T.ParentID, T.LeadNo, T.PersonName, T.User_Login, T.SourceName, T.MediumName, T.CampaignName, T.CompanyName, ',
			N'T.MobileNo, T.EmailID, T.City, T.[State], T.Country, T.PinCode, T.ResidentialAddress, T.OfficeAddress, T.[ADDRESS], ',
			N'T.CreatedBy, T.TotalAmount, T.TotalOrders, T.OrderDate, T.AssignedToByName ',
		N'FROM ( ',
			N'SELECT DISTINCT UL.ParentID, ',
			N'UL.LeadNo, UL.PersonName, UD.User_Login, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, ',
			N'ISNULL(ul.CompanyName, '''') AS CompanyName, ',
			N'ISNULL(ul.CountryCode, '''') + ''-'' + ISNULL(ul.MobileNo, '''') +  ',
				N'CASE WHEN ISNULL(ul.MobileNo1, '''') <> '''' THEN '','' + ISNULL(ul.CountryCode1, '''') + ''-'' + ISNULL(ul.MobileNo1, '''') ELSE '''' END + ',
				N'CASE WHEN ISNULL(ul.MobileNo2, '''') <> '''' THEN '','' + ISNULL(ul.CountryCode2, '''') + ''-'' + ISNULL(ul.MobileNo2, '''') ELSE '''' END AS MobileNo, ',
			N'ISNULL(ul.EmailID, '''') + ',
				N'CASE WHEN ISNULL(ul.EmailID1, '''') <> '''' THEN '','' + ISNULL(ul.EmailID1, '''') ELSE '''' END + ',
				N'CASE WHEN ISNULL(ul.EmailID2, '''') <> '''' THEN '','' + ISNULL(ul.EmailID2, '''') ELSE '''' END AS EmailID, ',
			N'ul.City, ul.[State], ul.Country, ul.PinCode, ul.ResidentialAddress, ul.OfficeAddress, ',
			N'CASE WHEN ul.Companyname <> '''' THEN ul.Officeaddress ELSE ul.Residentialaddress END AS [ADDRESS], ',
			N'ISNULL(ud.User_Login, '''') AS CreatedBy, TotalAmount, TotalOrders, OrderDate, ',
			@ParentID, ' AS AssignedToByName  ',
	N'FROM UserLeads(NOLOCK) ul  ',
		N'inner join #tempUsers tu on ul.AssignedTo = tu.User_Id ',
		N'inner join vwUC_LeadInteractionSummary t on ul.ParentID = t.ParentID and ul.LeadNo = t.LeadNo ',
		N'LEFT JOIN User_Detail(NOLOCK) ud ON ud.[User_ID] = ul.CreatedBy ',
		N'LEFT JOIN User_Detail(NOLOCK) ud2 ON ud2.[User_ID] = t.AssignedTo ', 
		N'LEFT JOIN UserSourceSettings(NOLOCK) USS ON USS.SourceID = ul.SourceName ',
		N'LEFT JOIN UserMediumSettings(NOLOCK) UMS ON UMS.MediumID = ul.MediumName ',
		N'LEFT JOIN UserCampaignSettings UCS ON UCS.CampaignID = ul.CampaignName ',
		N'WHERE ul.ParentID = ', @ParentID, --' AND UL.CreatedBy = CASE WHEN (', @Userid, ' = 0) THEN UL.CreatedBy ELSE ', @Userid, ' END  ',
	N') T  where  ', @customFilter, case when len(@Contain) > 2 then concat(' and ', @Contain ) else '' end ,' ) ',
	N'select Sno, (select count(1) from cteConsolidated ) as [TotalRow], ',
		N'ParentID, LeadNo, PersonName, User_Login, SourceName, MediumName, CampaignName, CompanyName, MobileNo, EmailID, City, State, ',
		N'Country, PinCode, ResidentialAddress, OfficeAddress, ADDRESS, CreatedBy, TotalAmount, TotalOrders, OrderDate, AssignedToByName ',
	N'from cteConsolidated where Sno between ', @StartPoint, ' and ', @EndPoint)

	print @filterSql

	execute sp_executesql @filterSql
  
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId 
		@User_id = @UserID_ForDatetimeConversion,
		@Activity_type = 'View_Cnvrsn_Lead',
		@ActionType = 'S',
		@RowJson = '',
		@Table_name = 'UserLeads'
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_getUserConversionsListIndividual]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getUserConversionsListIndividual]
(
	@UserId bigint,
	@UserIds nvarchar(max),
	@SearchText nvarchar(max),
	@Contain nvarchar(max),
	@FromDate date = null,
	@ToDate date = null,
	@Offsets int = 0,
	@PageSize int = 20

)
AS
BEGIN

	--DECLARE
	--	@UserId bigint = 47535,
	--	@UserIds nvarchar(max),
	--	@SearchText nvarchar(max),
	--	@Contain nvarchar(max) = '6064',
	--	@FromDate date = '31-Jan-2026',
	--	@ToDate date = '05-Feb-2026',
	--	@Offsets int = 0,
	--	@PageSize int = 20

	--select @UserId=49370,@UserIds=N'',@SearchText=N'',@Contain=N'',@FromDate=N'31-Dec-2025',@ToDate=N'05-Jan-2026',@Offsets=0,@PageSize=10
	
	declare @ParentId BIGINT
	select @FromDate=coalesce(@fromdate,'19000101'), @ToDate=coalesce(@ToDate,dateadd(d,1,getdate()))

	declare @customFilter nvarchar(max) = ''

	if(isjson(@SearchText) = 1)
	begin
		select @customFilter = concat((
			case when len(@customFilter) > 0 then concat(' and ', @customFilter) else '' end ),
			concat( FieldName, (case Operator 
				when 'equal to' then concat(' = ', '''', FirstValue, '''') 
				when 'between' then concat(' between ''', FirstValue, ''' and ''', SecondValue, '''' )
				else concat(' like ', '''', FirstValue, '''') end 
			)))
		from openjson(@SearchText) with (
			FieldName nvarchar(255) '$.FieldName',
			Operator nvarchar(255) '$.Operator',
			FirstValue nvarchar(2000) '$.FirstValue',
			SecondValue nvarchar(2000) '$.SecondValue'
		)
	end

	print concat('@customFilter => ', @customFilter)
	if(isnull(@customFilter, '') = '')
	begin
		set @customFilter = ' 1 = 1 '
	end

	if(isnull(@Contain, '') = '')
	begin
		set @Contain = '1 = 1'
	end
	else
	begin
		set @Contain = CONCAT(N'LeadNo like ''%', @Contain, '%'' ',
			N'or PersonName like ''%', @Contain, '%'' ',
			N'or EmailID like ''%', @Contain, '%'' ',
			N'or MobileNo like ''%', @Contain, '%'' ')
	end

	declare @StartPoint int = (@Offsets + 1)
	declare @EndPoint int = (@Offsets + @PageSize)
	
	DECLARE @UserID_ForDatetimeConversion BIGINT = @UserId  
  
	IF ( @Userid = NULL OR @Userid = 0 )  
	BEGIN  
		SET @UserID_ForDatetimeConversion = @ParentID  
	END  
  
	DECLARE @IsAdmin BIT = 0  
  
	SELECT TOP 1 @IsAdmin = isAdmin, @ParentId = ParentID FROM User_Detail WITH (NOLOCK) WHERE User_ID = @Userid  
  
	print '@customFilter'

	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))    
	insert into #tempUsers(User_ID, Name, Image)    
	exec Use_GetUserDetails @UserID = @UserId    


	declare @filterSql nvarchar(max) = concat(N'; WITH cteIndividual as ( ',
		N'SELECT ',
		N'(ROW_NUMBER() OVER(PARTITION BY t.ParentID ORDER BY t.OrderDate DESC)) as  [Sno], ',
		N'* FROM ( ',
		N'SELECT DISTINCT UL.LeadNo, ',
		N'ul.ParentID, ',
		N'UL.PersonName, UD.User_Login, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, ',
		N'ISNULL(ul.CompanyName, '''') AS CompanyName, ',
		N'ISNULL(ul.CountryCode, '''') + ''-'' + ISNULL(ul.MobileNo, '''') + ',
			N'CASE WHEN ISNULL(ul.MobileNo1, '''') <> '''' ',
				N'THEN '','' + ISNULL(ul.CountryCode1, '''') + ''-'' + ISNULL(ul.MobileNo1, '''') ELSE '''' END + ',
			N'CASE WHEN ISNULL(ul.MobileNo2, '''') <> '''' ',
				N'THEN '','' + ISNULL(ul.CountryCode2, '''') + ''-'' + ISNULL(ul.MobileNo2, '''') ELSE '''' END AS MobileNo, ',
		N'ISNULL(ul.EmailID, '''') + CASE WHEN ISNULL(ul.EmailID1, '''') <> '''' ',
			N'THEN '','' + ISNULL(ul.EmailID1, '''') ELSE '''' END + ',
			N'CASE WHEN ISNULL(ul.EmailID2, '''') <> '''' THEN '','' + ISNULL(ul.EmailID2, '''') ELSE '''' END AS EmailID, ',
		N'ul.City, ul.[State], ul.Country, ul.PinCode, ul.ResidentialAddress, ul.OfficeAddress, ',
		N'CASE WHEN ul.Companyname <> '''' THEN ul.Officeaddress ELSE ul.Residentialaddress END AS [ADDRESS], ',    
		N'ISNULL(ud.User_Login, '''') AS CreatedBy, ',
		N'LIH.AmountPaid AS TotalAmount, ''1'' AS TotalOrders, LIH.FollowupDate AS [OrderDate], ',
		N'FL.FollowupStatus, ',
		@ParentID, N' AS AssignedToByName ',
	N'FROM UserLeads(NOLOCK) ul ',
	N'inner join #tempUsers tu on ul.AssignedTo = tu.User_Id ',
	N'INNER JOIN LeadInteractionHistory(NOLOCK) lih ON lih.LeadNo = ul.LeadNo and lih.ParentID = ul.ParentID ',
	N'AND lih.ParentID = ', @ParentID, N' AND lih.FollowUpStatus IN (SELECT Id FROM FollowUp_Status fup WHERE fup.IsConvert = 1 ',
    N'AND ( fup.ParentID = ', @ParentID, N' OR fup.ParentID IS NULL )) ', --= 5
	N'LEFT JOIN User_Detail(NOLOCK) ud ON ud.[User_ID] = lih.CreatedBy ',
	N'LEFT JOIN User_Detail(NOLOCK) ud2 ON ud2.[User_ID] = lih.AssignedTo ',
	N'LEFT JOIN UserSourceSettings(NOLOCK) USS ON USS.SourceID = ul.SourceName ',
	N'LEFT JOIN UserMediumSettings(NOLOCK) UMS ON UMS.MediumID = ul.MediumName ',
	N'LEFT JOIN UserCampaignSettings UCS ON UCS.CampaignID = ul.CampaignName ',
	N'LEFT JOIN FollowUp_Status(NOLOCK) FL ON lih.FollowUpStatus = FL.ID ',
	N'WHERE ul.ParentID = ', @ParentID, 
		--N'AND UL.AssignedTo = CASE WHEN (', @IsAdmin, N' = 1) THEN UL.AssignedTo ELSE ', @Userid, ' END ',
		N'AND ul.LeadNo IN ( SELECT lih.LeadNo FROM LeadInteractionHistory(NOLOCK) lih WHERE lih.ParentID = ', @ParentID, N' ', 
		N'AND lih.FollowUpStatus IN ( SELECT Id FROM FollowUp_Status fup WHERE fup.IsConvert = 1 ', 
			N'AND ( fup.ParentID = ', @ParentID, N' OR fup.ParentID IS NULL ))) ',
	N') T  where ', @customFilter, case when len(@Contain) > 2 then concat(' and ', @Contain ) else '' end ,' ) ',
	N'SELECT Sno, (select count(1) from cteIndividual ) as [TotalRow], ',	
		N'LeadNo, ParentID, PersonName, User_Login, SourceName, MediumName, CampaignName, CompanyName, MobileNo, EmailID, City, ',
		N'State, Country, PinCode, ResidentialAddress, OfficeAddress, ADDRESS, CreatedBy, TotalAmount, TotalOrders, OrderDate, AssignedToByName, FollowupStatus ',
	N'FROM cteIndividual where Sno between ', @StartPoint, ' and ', @EndPoint)

	print '@filterSql'
	print @filterSql


	execute sp_executesql @filterSql

END




GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserCoupons]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetUserCoupons] --335  
@ParentID bigint  
as  
    select  DATEDIFF(day, usrcoupon.ExpiryDate, GETDATE()) as datedifference,usrcoupon.CouponName as CouponCode,usrcoupon.CouponDescription,Convert(varchar(10),  
    CONVERT(date,usrcoupon.ExpiryDate,106),103) as validity from [UserCouponSettings1] usrcoupon inner join UserCartSettings usrcart  
    on usrcoupon.ParentID=usrcart.ParentID where Status=1 and  DisplayValidCoupons=1 and usrcoupon.ParentID=@ParentID and usrcoupon.ExpiryDate<=GETDATE()   
  


