/* ============================================================
   Procedure: [dbo].[usp_getuserCredit_Batchinfo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getuserCredit_Batchinfo  -- 335,'07/147/2010','07/14/2010',2          
@userid varchar(20),            
@fromdate varchar(30),            
@todate varchar(30),            
@select int          
as            
declare @getid varchar(20)            
declare @mid varchar (20)            
Begin            
           
--select  @getid=user_id from user_detail where user_login=@username            
--select  @mid=m_id  from user_detail where user_login=@username 

   Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @userid )    
   Declare @MIDP bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )    
           
if(@select=1)          
Begin          
select  convert(nvarchar,convert(datetime,fromdate,104),111),Balance,credits,debits from credit_details with(nolock)  where             
 User_id=@ParentID and  convert(nvarchar,convert(datetime,fromdate,104),112)            
between convert(nvarchar,convert(datetime,@fromdate,104),112) and            
 convert(nvarchar,convert(datetime,@todate,104),112)            
order by credit_id desc              
End          
          
if(@select=2)          
Begin          
select  distinct [message],dbo.fn_getmessagecount(len([message]),inf.isunicode) as Length,inf.batchid into #temptableBatchinfo from         
Messagedeliverystatus mds (nolock) join [batchinfo] inf (nolock) on        
mds.batchid=inf.batchid where u_id=@userid and  convert(nvarchar,convert(datetime,batchprocesstime,104),112)            
between convert(nvarchar,convert(datetime,@fromdate,104),112) and            
 convert(nvarchar,convert(datetime,@todate,104),112)          
        
select distinct BatchInfoID,inf.batchid infbatch,isnull(#temptableBatchinfo.[message],'Not Found') as msg,isnull(#temptableBatchinfo.length,'0' )as msglen,TotalRecords,IsProcess,IsPrority,IsAllowDND,BatchProcessTime,        
ScheduledDate,ScheduledTime,IsUniCode,PageName,userfilter        
from [batchinfo] inf (nolock) left join #temptableBatchinfo on inf.batchid=#temptableBatchinfo.batchid        
 where userid=@userid and  convert(nvarchar,convert(datetime,batchprocesstime,104),112)            
between convert(nvarchar,convert(datetime,@fromdate,104),112) and            
 convert(nvarchar,convert(datetime,@todate,104),112)         
        
drop table #temptableBatchinfo        
        
  End          
End 


