/* ============================================================
   Procedure: [dbo].[usp_GetUserDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_GetUserDashboard 32222
-- Exec usp_GetUserDashboard 39298
-- Exec usp_GetUserDashboard 39299
-- Exec usp_GetUserDashboard 39300
CREATE   PROC usp_GetUserDashboard
(
	@UserId bigint
)
As
Begin

 DECLARE @ParentId BIGINT = 0;              
 DECLARE @IsAdmin bit = 0;              
 DECLARE @RoleType varchar(10);              
 Declare @TeamCode VARCHAR(20)                            

SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;              

if object_id('tempdb..#tblUserIds') is not null begin drop table #tblUserIds end

CREATE TABLE #tblUserIds(
   UserId bigint  NOT NULL)

select @TeamCode = tum.TeamCode from TBL_UA_TeamUserMappingMaster(nolock) tum
inner join TBL_UA_TeamMaster(nolock) tm on tm.TeamCode = tum.TeamCode
where tum.UserId = @UserId
 
if((@TeamCode is null) and ( @ParentId = @UserId or @IsAdmin = 1))
Begin
--set @RoleType = 'Global'
Insert into #tblUserIds (UserId)
Select User_Id UserId FROM User_Detail(nolock) where ParentId = @ParentId 
End
Else if(@TeamCode != null) 
Begin
---set @RoleType = 'Team'
Insert into #tblUserIds (UserId)
Select UserId FROM TBL_UA_TeamUserMappingMaster(nolock) where TeamCode = @TeamCode
End
Else 
Begin
--set @RoleType = 'User'
Insert into #tblUserIds (UserId)
select @UserId 
End

	If(@ParentId=@UserId)
	Begin
		Select * From tbl_Dashboard(nolock) Where IsActive=1 and ParentId=@ParentId order by IsDefault desc
	End
	Else
	Begin
		Select DUM.*, DB.DashboardName 
		from tbl_DashboardUserMapping(nolock) DUM inner join tbl_Dashboard(nolock) DB
		on	 DUM.DashboardId = DB.DashboardId
		Where DUM.IsActive=1 and DUM.UserId in (select UserId From #tblUserIds) order by DUM.IsDefault desc
	End
End



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserDashboardReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_GetUserDashboardReport 32222, 4, 0
-- Exec usp_GetUserDashboardReport 32222, 9, 0
-- Exec usp_GetUserDashboardReport 32222, 14, 0
-- Exec usp_GetUserDashboardReport 32222, 4, 2
-- Exec usp_GetUserDashboardReport 32222, 4, 3
-- Exec usp_GetUserDashboardReport 32222, 9, 13
CREATE   PROC dbo.usp_GetUserDashboardReport (
	@UserId BIGINT
	,@DashboardId BIGINT
	,@ReportId INT = 0
	)
AS
BEGIN
	DECLARE @ParentId BIGINT = 0

	SELECT @ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE USER_ID = @UserId

	IF (@ParentId = @UserId)
	BEGIN
		SELECT D.DashboardId
			,D.DashboardName
			,D.IsDefault
			,D.ParentId
			,@UserId AS UserId
			,DRM.DRMapId
			,DRM.ReportId
			,DRM.SequenceNo
			,DRM.RangeCode
			,DR.ReportName
			,DR.ReportType
			,DR.JasperReportID
			,DTR.RangeId
			,DTR.RangeName
			,DTR.StartDays
			,DTR.EndDays
			,FromDate = CASE 
				WHEN DRM.RangeCode = 'NONE_+000_+000'
					THEN CAST(GETDATE() AS DATE)
				ELSE DateAdd(day, DTR.StartDays, CAST(GETDATE() AS DATE))
				END
			,ToDate = CASE 
				WHEN DRM.RangeCode = 'NONE_+000_+000'
					THEN CAST(GETDATE() AS DATE)
				ELSE DateAdd(day, DTR.EndDays, CAST(GETDATE() AS DATE))
				END
		FROM tbl_Dashboard(NOLOCK) D
		INNER JOIN tbl_DashboardReportMapping AS DRM WITH (NOLOCK) ON D.DashboardId = DRM.DashboardId
		INNER JOIN tbl_DashboardReports AS DR WITH (NOLOCK) ON DRM.ReportId = DR.ReportId
		INNER JOIN tbl_DateRange AS DTR WITH (NOLOCK) ON DRM.RangeCode = DTR.RangeCode
		WHERE (D.IsActive = 1)
			AND (DRM.IsActive = 1)
			AND (DR.IsActive = 1)
			AND (DTR.IsActive = 1)
			AND (D.ParentId = @UserId)
			AND (D.DashboardId = @DashboardId)
			AND DRM.ReportId = (
				CASE 
					WHEN @ReportId = 0
						THEN DRM.ReportId
					ELSE @ReportId
					END
				)
	END
	ELSE
	BEGIN
		SELECT D.DashboardId
			,D.DashboardName
			,D.IsDefault
			,@ParentId AS ParentId
			,DUM.UserId
			,DRM.DRMapId
			,DRM.ReportId
			,DRM.SequenceNo
			,DRM.RangeCode
			,DR.ReportName
			,DR.ReportType
			,DR.JasperReportID
			,DTR.RangeId
			,DTR.RangeName
			,DTR.StartDays
			,DTR.EndDays
			,FromDate = CASE 
				WHEN DRM.RangeCode = 'NONE_+000_+000'
					THEN CAST(GETDATE() AS DATE)
				ELSE DateAdd(day, DTR.StartDays, CAST(GETDATE() AS DATE))
				END
			,ToDate = CASE 
				WHEN DRM.RangeCode = 'NONE_+000_+000'
					THEN CAST(GETDATE() AS DATE)
				ELSE DateAdd(day, DTR.EndDays, CAST(GETDATE() AS DATE))
				END
		FROM tbl_Dashboard(NOLOCK) D
		INNER JOIN tbl_DashboardUserMapping AS DUM WITH (NOLOCK) ON D.DashboardId = DUM.DashboardId
		INNER JOIN tbl_DashboardReportMapping AS DRM WITH (NOLOCK) ON DUM.DashboardId = DRM.DashboardId
		INNER JOIN tbl_DashboardReports AS DR WITH (NOLOCK) ON DRM.ReportId = DR.ReportId
		INNER JOIN tbl_DateRange AS DTR WITH (NOLOCK) ON DRM.RangeCode = DTR.RangeCode
		WHERE (DUM.IsActive = 1)
			AND (DRM.IsActive = 1)
			AND (DR.IsActive = 1)
			AND (DTR.IsActive = 1)
			AND (DUM.UserId = @UserId)
			AND (DRM.DashboardId = @DashboardId)
			AND DRM.ReportId = (
				CASE 
					WHEN @ReportId = 0
						THEN DRM.ReportId
					ELSE @ReportId
					END
				)
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_Dsbrd'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_Dashboard'
END



GO

