   Procedure: [dbo].[usp_GetUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserDetails]
@searchTerm NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- Fetch user details matching user_login or UserName using LIKE
        SELECT 
            [User_ID],
            user_login,
            CONCAT(fname, ' ', lname) AS UserName
        FROM 
            [dbo].[User_Detail] with(nolock)
        WHERE
            user_login LIKE '%' + @searchTerm + '%'
           -- OR CONCAT(fname, ' ', lname) LIKE '%' + @searchTerm + '%'

    END TRY
    BEGIN CATCH
        -- Insert error information in case of any error
        EXEC usp_InsertErrorInfo
    END CATCH
END;




GO

