/* ============================================================
   Procedure: [dbo].[usp_GetUserFilteredSchedules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

       
    
CREATE   PROCEDURE [dbo].[usp_GetUserFilteredSchedules] --335,1,0    
 @ParentID BIGINT,    
 @IsActive BIT,    
 @isInActive BIT,  
 @Schedule nvarchar(max)=null  
AS    
BEGIN    
 SELECT us.ID,    
        us.SceduleName,    
        CASE     
             WHEN us.IsOnce = 1 THEN 'Once at ' +    
                      
                      
                      
                  CAST(us.OnceHours AS VARCHAR(50)) + ':' +    
                      
                      
                      
                  CAST(us.OnceMins AS VARCHAR(50))    
             ELSE ''    
        END + CASE     
                   WHEN us.IsDaily = 1 THEN 'Daily at ' +    
                            
                            
                            
                        CAST(us.DailyHours AS VARCHAR(50)) + ':' +    
                            
                            
                            
                        CAST(us.DailyMins AS VARCHAR(50))    
                   ELSE ''    
              END + CASE     
                         WHEN us.IsWeekly = 1 THEN 'Weekly at Day No(s)  ' +    
                                  
                                  
                                  
                              REPLACE(    
                                  REPLACE(    
                                      REPLACE(    
                                          REPLACE(    
                                              REPLACE(    
                                                  REPLACE(    
                                                      REPLACE(REPLACE(us.WeeklyDayNo, '#', ', '), '1', 'Sunday'),    
                                                      '2',    
                                                      'Monday'    
                                                  ),    
                                                  '3',    
                                                  'Tuesday'    
                                              ),    
                                              '4',    
                                              'Wednesday'    
                                          ),    
                                          '5',    
                                          'Thursday'    
                                      ),    
                                      '6',    
                                      'Friday'    
                                  ),    
                                  '7',    
                                  'Saturday'    
                              ) + ' at ' +    
                                  
                                  
                                  
                              CAST(us.WeeklyHours AS VARCHAR(50)) + '  :' +    
                                  
                                  
                                  
                              CAST(us.WeeklyMins AS VARCHAR(50))    
                         ELSE ''    
                    END + CASE     
                               WHEN us.IsMonthly = 1 THEN 'Monthly in ' +    
                                        
                                    ISNULL(    
                                        REPLACE(    
                                            REPLACE(    
                                                REPLACE(    
                                                    REPLACE(    
                                                        REPLACE(    
                                                            REPLACE(    
                                                                REPLACE(    
                                                                    REPLACE(    
                                                                        REPLACE(    
                                                                            REPLACE(    
                                                                                REPLACE(    
                               REPLACE(REPLACE(us.MonthNo, '#', ', '), '10', 'October'),    
                                                                                    '11',    
                                                       'November'    
                                                                                ),    
                                                                                '12',    
                                                                                'December'    
                                                                            ),    
                                                                            '1',    
                                                                            'January'    
                                                                        ),    
                                                                        '2',    
                                                                        'February'    
                                                                    ),    
                                                                    '3',    
                                                                    'March'    
                                                                ),    
                                                                '4',    
                                                                'April'    
                                                            ),    
                                                            '5',    
                                                            'May'    
                                                        ),    
                                                        '6',    
                                                        'June'    
                                                    ),    
                                                    '7',    
                                                    'July'    
                                                ),    
                                                '8',    
                                                'August'    
                                            ),    
                                            '9',    
                                            'September'    
                                        ),    
                                        ''    
                                    )    
                                        
                                    +    
                                        
                                    ' at Day No(s)  ' +    
                                        
                                        
                                        
                                    ISNULL(REPLACE(us.MonthlyDayNo, '#', ', '), '')     
                                        
                                    + ' at ' +    
                                        
                                        
                                        
                                    CAST(us.MonthlyHours AS VARCHAR(50)) +    
                                        
                                    '  :' +    
                                        
                                        
                                        
                                    CAST(us.MonthlyMins AS VARCHAR(50))    
                               ELSE ''    
                          END  AS Schedules,    
        us.IsActive,    
        us.IsOnce,    
        us.OnceHours,    
        us.OnceMins,    
        us.IsDaily,    
        us.DailyHours,    
        us.DailyMins,    
        us.IsWeekly,    
        us.WeeklyDayNo,    
        us.WeeklyHours,    
        us.WeeklyMins,    
        us.IsMonthly,    
        us.MonthlyHours,    
        us.MonthlyMins,    
        us.MonthlyDayNo,    
        ud.User_Login    
 FROM   UserSchedules          AS us(NOLOCK)    
        LEFT JOIN User_Detail UD(NOLOCK)    
             ON  us.CreatedBy = UD.User_ID    
 WHERE  us.ParentID = @ParentID    
        AND (    
                us.IsActive = CASE     
                                   WHEN @IsActive = 1 THEN 1    
                                   ELSE NULL    
                              END    
        OR us.IsActive = CASE     
                                      WHEN @isInActive = 1 THEN 0    
                                      ELSE NULL    
                                 END    
            )    
   AND (      
                ISNULL(@Schedule, '') = ''      
                OR us.SceduleName LIKE '%' + @Schedule + '%'      
            )  
END    
                


GO

