/* ============================================================
   Procedure: [dbo].[usp_GetUserIdByAuthKey]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserIdByAuthKey]  
    @authKey NVARCHAR(255),  
    @vendorName NVARCHAR(255)  
AS  
BEGIN  
  
    IF @vendorName = 'CreateTicket'  
    BEGIN  
        SELECT   
            ul.LoginName as User_Login,  
            ul.Pwd,   
            ak.ParentId,   
            ak.CreatedBy,   
            ul.TpUser_Id  
        FROM tbl_AuthKey AS ak WITH (NOLOCK)  
        INNER JOIN tbl_tp_userlogin AS ul WITH (NOLOCK) ON ak.ParentId = ul.User_Id  
        WHERE   
            ak.AuthKey = @authKey   
            AND ak.VendorName = @vendorName  
            AND ak.IsActive = 1  
            --AND ul.Status = 1;  
    END  
    ELSE  
    BEGIN  
        SELECT   
            ud.User_Login,   
            ud.Pwd,   
            ak.ParentId,   
            ak.CreatedBy ,
			'0' TpUser_Id  
        FROM tbl_AuthKey AS ak WITH (NOLOCK)  
        INNER JOIN User_Detail AS ud WITH (NOLOCK) ON ak.ParentId = ud.User_ID  
        WHERE   
            ak.AuthKey = @authKey   
            AND ak.VendorName = @vendorName  
            AND ak.IsActive = 1  
            AND ud.Status = 1;  
    END  
END  


GO

