/* ============================================================
   Procedure: [dbo].[usp_GetUserIdsCountBySegmentIds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserIdsCountBySegmentIds]
    @userSegmentId BIGINT,
    @recordCount INT OUTPUT
AS
BEGIN
	
	--DECLARE
	--	@userSegmentId BIGINT = 4,
	--	@recordCount INT = 0 

    SET NOCOUNT ON;

    DECLARE @filterConditions NVARCHAR(MAX) = N'';
    DECLARE @userIdsSql NVARCHAR(MAX) = N'';
    DECLARE @ApplyTo NVARCHAR(25) = 'and';
    DECLARE @userCount INT = 0;
	DECLARE @ParentId BIGINT = 0;

    BEGIN TRY

        SELECT @ApplyTo = ApplyTo, @ParentId = ParentID FROM tbl_UserSegments WITH (NOLOCK) WHERE Id = @userSegmentId;

		DECLARE @ResellerId BIGINT = 0;
		SELECT @ResellerId = reseller_id FROM reseller_detail(nolock) where User_ID = @ParentId

		PRINT CONCAT('@ResellerId => ', @ResellerId)

		drop table if exists #filterQuery
		create table #filterQuery(
			TableName nvarchar(255),
			ColumnName nvarchar(255),
			OperatorSymbol nvarchar(255),
			ValuePlaceHolder nvarchar(255),
			FieldValue nvarchar(255)
		)
		insert into #filterQuery(TableName, ColumnName, OperatorSymbol, ValuePlaceHolder, FieldValue)
		select c.TableName, c.ColumnName, sc.OperatorSymbol, sc.ValuePlaceHolder, sc.FieldValue
			FROM tbl_SegmentConditions AS sc WITH (NOLOCK)  INNER JOIN tbl_us_FilterColumnDetail AS c WITH (NOLOCK) 
            ON sc.FieldId = c.Id WHERE sc.SegmentID = @userSegmentId;


        SELECT @filterConditions = 
            CONCAT( @filterConditions,
                (CASE WHEN LEN(ISNULL(@filterConditions, '')) > 0 THEN CONCAT(' ', @ApplyTo, ' ') ELSE '' END),
                (CASE
                    WHEN TableName = 'MySMS.dbo.User_Detail'
                        THEN CONCAT('[ud].[', ColumnName, '] ', OperatorSymbol, ' ', REPLACE(ValuePlaceHolder, 'value', FieldValue))
					WHEN TableName = 'MySMS.dbo.ve_UserSubscriptionDetails'
                       THEN CONCAT('[us].[', ColumnName, '] ', OperatorSymbol, ' ', REPLACE(ValuePlaceHolder, 'value', FieldValue))
					WHEN TableName = 'MySMS.dbo.reseller_detail'
                       THEN CONCAT('[rd].[', ColumnName, '] ', OperatorSymbol, ' ', REPLACE(ValuePlaceHolder, 'value', FieldValue))
                    ELSE '' END
				) ) 
        FROM #filterQuery

		declare @IsViewUsed bit = 0
		if(exists(select 1 from #filterQuery where TableName = 'MySMS.dbo.ve_UserSubscriptionDetails'))
		begin
			set @IsViewUsed = 1
		end

        SET @userIdsSql = CONCAT( N'SELECT @recountCountOut = COUNT(1) ', 
							N'FROM User_Detail(NOLOCK) ud ',
							(case when @IsViewUsed = 1
								then  N'left join ve_UserSubscriptionDetails us on ud.User_ID = us.User_ID ' else  '' end),
							N'left join reseller_detail(NOLOCK) rd on ud.User_ID = rd.User_ID ',
							N'WHERE ud.M_ID = ', @ResellerId, N' AND  ud.User_ID = ud.ParentID ', 
							( CASE WHEN isnull(@filterConditions, '') <> '' THEN CONCAT (' AND ', @filterConditions) ELSE '' END)
						);

        PRINT CONCAT('@filterConditions => ', @filterConditions);
        PRINT CONCAT('@userIdsSql => ', @userIdsSql);

        EXEC sp_executesql 
            @userIdsSql, 
            N'@recountCountOut INT OUTPUT', 
            @recountCountOut = @userCount OUTPUT;

        -- Set the output parameter
        SET @recordCount = @userCount;

    END TRY
    BEGIN CATCH
		SELECT ERROR_MESSAGE()
        EXEC usp_InsertErrorInfo;
        SET @recordCount = -1;
    END CATCH

	--SELECT @recordCount

END;



GO

