CREATE   PROCEDURE dbo.Usp_GetUserIDsFromUserLogins --'sms19'  
(  
  @UserLoginCollections nvarchar(max)  
)  
as  
Begin  
       select  
    stuff  
    (   
     (select ',' + cast(tbl.User_ID as nvarchar(max)) from  
      (  
       select User_ID from User_Detail as UD with(nolock)    
        where UD.User_Login in  
          (  
        select cast(value as nvarchar) from fn_split(@UserLoginCollections,',')  
