/* ============================================================
   Procedure: [dbo].[usp_GetUserImportStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[usp_GetUserImportStatus]    
(    
    @FromDate datetime,    
    @ToDate datetime,    
    @UserId  bigint,    
    @ImportRow_Id bigint=0    
)    
AS    
BEGIN    
    
	DECLARE @PARENTID BIGINT = 0;                  
	DECLARE @ISADMIN BIT = 0;                  
	
	SELECT @PARENTID = PARENTID, @ISADMIN = ISADMIN FROM USER_DETAIL(NOLOCK) WHERE USER_ID = @USERID;                  
    
	IF OBJECT_ID('TEMPDB..#tblUselList') IS NOT NULL BEGIN DROP TABLE #tblUselList END    

	DECLARE @tbluser TABLE (
		User_ID BIGINT,
		Name VARCHAR(100),
		IMAGE NVARCHAR(200)
	)

	IF (@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @ParentId
	END
	ELSE
	BEGIN
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @UserId
	END
	IF (@IMPORTROW_ID > 0) BEGIN
	
		SELECT IMPORTROW_ID, [USER_ID], CONVERT(VARCHAR,IMPORTDATE,0) AS IMPORTDATE,     
		IsProcessed = Case when IsProcessed=1 then 'Yes' else 'Under Process' end,     
		IsValid = Case when ISNULL(Remarks,'') = '' and IsProcessed=1 then 'Yes'     
		when ISNULL(Remarks,'') != '' and IsProcessed=1 then 'No' else '' end ,   
		TotalRecords,ImportFilename, UserCnt,  
		[Status] =Case  when UserCnt = TotalRecords and IsProcessed=1  then 'Successful'   
		when  UserCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'  
		when  UserCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'  
		else '' end ,Remarks = ISNULL(Remarks,'')   FROM TBL_USERIMPORTSUMMARY  WHERE [USER_ID] IN (SELECT USER_ID FROM @TBLUSER) AND IMPORTROW_ID = @IMPORTROW_ID    

	END
	ELSE BEGIN
		
		SELECT IMPORTROW_ID, [USER_ID], CONVERT(VARCHAR,IMPORTDATE,0) AS IMPORTDATE,     
		IsProcessed = Case when IsProcessed=1 then 'Yes' else 'Under Process' end,     
		IsValid = Case when ISNULL(Remarks,'') = '' and IsProcessed=1 then 'Yes'     
		when ISNULL(Remarks,'') != '' and IsProcessed=1 then 'No' else '' end ,   
		TotalRecords,ImportFilename, UserCnt,  
		[Status] =Case  when UserCnt = TotalRecords and IsProcessed=1  then 'Successful'   
		when  UserCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'  
		when  UserCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'  
		else '' end ,Remarks = ISNULL(Remarks,'')     FROM TBL_USERIMPORTSUMMARY  WHERE [USER_ID] IN (SELECT USER_ID FROM @TBLUSER) 
		AND CONVERT(VARCHAR,IMPORTDATE,106) BETWEEN @FROMDATE AND @TODATE    

	END

END    
 




GO

