/* ============================================================
   Procedure: [dbo].[usp_GetUserKit19usage_old09052019]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserKit19usage_old09052019] --18559--'17626'    
@u nvarchar(max)    
as    
begin    
Select u.user_id,u.user_login,case when u.lastlogin1 is not null then u.lastlogin1 else c.datecreated end as LastLoggedIn,c.datecreated as LastSMSSent into #temp1 from user_detail u left join credit_details c (nolock) on u.user_id=c.user_id where   
c.credit_id = (select max(credit_id) from credit_details c1 (nolock) where c1.user_id=c1.fromuser_id and c1.debits>0 and c1.user_id=c.user_id) and u.m_id=10043 and u.user_id in (select value from dbo.fn_split(@u,','))    
    
select user_id,datecreated into #temp2 from mailcreditdetails c (nolock) where c.credit_id = (select max(credit_id) from mailcreditdetails c1 (nolock) where c1.user_id=c1.fromuser_id and c1.debits>0 and c1.user_id=c.user_id)  and  c.user_id in (select value from dbo.fn_split(@u,','))    
    
select parentid,CreatedOn into #temp3 from usermailtemplate umt(nolock) where id=(select max(id) from usermailtemplate where parentid=umt.parentid)    
 and parentid in (select value from dbo.fn_split(@u,','))    
    
select parentid,max(step3datetime) as Step3datetime into #temp4 from     
(select ucm.parentid,step3datetime from usercampaignmaster ucm (nolock) join usercampaignhistory uch (nolock) on ucm.id=uch.campaignid and uch.isscheduled=1    
where uch.id=(select max(id) from usercampaignhistory (nolock) where step3recipients>0 and campaignid=uch.campaignid) and ucm.parentid in (select value from dbo.fn_split(@u,','))) A     
group by parentid    
    
select distinct user_id,dbo.fn_Max_date(dateupdated,datecreated) as LastMicrositeCreatedEdited into #temp5 from    
(select user_id,dateupdated,datecreated from clientpagedetail c where dateupdated=(select max(dateupdated) from clientpagedetail cd where cd.user_id=c.user_id and dateupdated is not null) and user_id in (select value from dbo.fn_split(@u,','))     
union all    
select user_id,datecreated,datecreated from clientpagedetail c where id=(select max(id) from clientpagedetail cd where cd.user_id=c.user_id and dateupdated is null) and user_id in (select value from dbo.fn_split(@u,','))) A    
    
select user_id,max(LastLeadFromMicrosite) as LastLeadFromMicrosite into #temp6 from     
(select p.user_id,c.datecreated as LastLeadFromMicrosite from clientleaddetails c join clientpagedetail p on c.cname=right(pagename,len(pagename)-charindex('/',pagename))    
where c.id=(select max(id) from clientleaddetails c1 where cname=c.cname) and p.user_id in (select value from dbo.fn_split(@u,','))) A group by user_id    
    
select parentid,createddate as LastWebFormCreated into #temp7 from WebFormTbl w where formid=(select max(formid) from webformtbl where parentid=w.parentid)    
and parentid in (select value from dbo.fn_split(@u,','))    
    
select parentid,max(entrydate) as LastWebformResponse into #temp8 from (SELECT w.parentid,[EntryDate] FROM [WebEntryTbl] we join webformtbl w     
on w.formid=we.formid where we.entryid=(select max(entryid) from webentrytbl wt where wt.formid=we.formid) and w.parentid in (select value from dbo.fn_split(@u,','))) A  group by parentid    
    
select parentid,domain into #temp9 from usercartsettings where domain<>'' and parentid in (select value from dbo.fn_split(@u,','))    
    
select parentid,max(createdon) LastOrderDate into #temp10 from userorders where parentid in (select value from dbo.fn_split(@u,',')) group by parentid    
    
select parentid,max(createddate) LastEnquiryAdded into #temp11 from userenquiry where parentid in (select value from dbo.fn_split(@u,',')) group by parentid    
select parentid,max(dbo.fn_max_date(createdon,modifiedon)) LastLeadAddedEdited into #temp12 from userleads where parentid in (select value from dbo.fn_split(@u,',')) group by parentid    
select parentid,max(createdon) LastLeadFollowUp into #temp13 from leadinteractionhistory where parentid in (select value from dbo.fn_split(@u,',')) group by parentid    
select parentid,vdomain_name TicketPortal into #temp14 from serv_user_domain where vdomain_name <>'' and parentid in (select value from dbo.fn_split(@u,','))    
    
select parentid,max(HistoryDate) as LastTicketUpdated into #temp15 from Serv_Tickethistory where parentid in (select value from dbo.fn_split(@u,',')) group by parentid    
    
SELECT [ParentID],count([ForwadingEmail]) MailAddressesForwarded into #temp16 FROM [UserMailbox] where parentid in (select value from dbo.fn_split(@u,',')) group by parentid     
    
select parentid,max(maildate) LastMailForwarded into #temp17 from usermails u join user_detail ud on u.userid=ud.parentid where ud.parentid in (select value from dbo.fn_split(@u,',')) group by ud.parentid     
    
select parentid,count(parentid) as MailsParsed,max(createddate) LastMailParsedDate into #temp18 from dbo.ParsedEnquiries where parentid in (select value from dbo.fn_split(@u,',')) group by parentid order by count(parentid) desc    
    
/*select u.parentid,u.CreatedDate from userenquiry u where u.enquiryid=(select max(enquiryid) from userenquiry ue join usermediumsettings s on ue.SourceName in (select s.mediumid where s.name like '%microsite-%') and ue.parentid=u.parentid)    
    
select top 10 charindex('/',pagename),len(pagename),right(pagename,len(pagename)-charindex('/',pagename)),* from clientpagedetail order by id desc    
    
    
select u.parentid,u.CreatedDate from userenquiry u join usermediumsettings s on u.SourceName in (select s.mediumid where s.name like '%microsite-%') and ue.parentid=u.parentid)    
*/    
    
    
 Select distinct t.user_id,t.user_login,t.LastLoggedIn,t.LastSMSSent,m.datecreated as LastMailSent,mt.createdon as LastMailTemplateCreated,    
 t4.step3datetime as LastScheduledCampaignrun,    
 LastMicrositeCreatedEdited,LastLeadFromMicrosite,LastWebFormCreated,LastWebformResponse,domain,LastOrderDate,    
 LastEnquiryAdded,LastLeadAddedEdited,LastLeadFollowUp,isnull(TicketPortal,'Not Created Yet') TicketPortal,LastTicketUpdated,    
 isnull(MailAddressesForwarded,0) MailAddressesForwarded,LastMailForwarded,isnull(MailsParsed,0) MailsParsed,LastMailParsedDate into #temp19    
  from #temp1 t left join #temp2 m on t.user_id=m.user_id left join #temp3 mt on mt.parentid=t.user_id left join #temp4     
 t4 on t.user_id=t4.parentid left join #temp5 t5 on t.user_id=t5.user_id left join #temp6 t6 on t6.user_id=t.user_id left join #temp7 t7     
 on t.user_id=t7.parentid left join #temp8 t8 on t8.parentid=t.user_id left join #temp9 t9 on t9.parentid=t.user_id left join #temp10 t10    
 on t.user_id=t10.parentid left join #temp11 t11 on t11.parentid=t.user_id left join #temp12 t12 on t12.parentid=t.user_id     
 left join #temp13 t13 on t13.parentid=t.user_id left join #temp14 t14 on t14.parentid=t.user_id left join #temp15 t15 on t15.parentid=t.user_id    
   left join #temp16 t16 on t16.parentid=t.user_id  left join #temp17 t17 on t17.parentid=t.user_id left join #temp18 t18 on t18.parentid=t.user_id    
    
--select * from #temp19    
    
