insert into #temp20(AccountName,FeatureName,LastUsed,UsageType)    
select user_login,'Added Enquiry','Total Enquiries received : '+ cast(isnull(TotalEnquiries,0) as nvarchar) + '. Last Enquiry received on: '+ isnull(cast(LastEnquiryAdded as nvarchar),'Never')LastEnquiryAdded,case when LastEnquiryAdded is null then 0 when datediff(d,LastEnquiryAdded,getdate())>15 then 1 else 2 end from #temp19    

