insert into #temp20(AccountName,FeatureName,LastUsed,UsageType)    
select user_login,'Added Follow-up To Lead',LastLeadFollowUp,case when LastLeadFollowUp is null then 0 when datediff(d,LastLeadFollowUp,getdate())>15 then 1 else 2 end from #temp19    

