/* ============================================================
   Procedure: [dbo].[usp_GetUserLeadsByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserLeadsByLeadId]      
 @LeadId BIGINT      
AS
BEGIN       
 SELECT top 1 ul.Id, LeadNo, Country, State, City, PinCode, OfficeAddress, ProfileImgFileName from UserLeads AS ul            
 WHERE ul.Id = @LeadId       
END   


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserLeadsConversions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserLeadsConversions] --42261,0 --41181,41186   --31871,31871  --35610,0                        
 @ParentID BIGINT  
 ,@Userid INT --=0                              
AS  
BEGIN  
   -- declare         
    --@ParentID BIGINT = 44095,                      
     -- @Userid int = 44095 --44112  --44095          
 DECLARE @UserID_ForDatetimeConversion BIGINT = @UserId  
  
 IF (  
   @Userid = NULL  
   OR @Userid = 0  
   )  
 BEGIN  
  SET @UserID_ForDatetimeConversion = @ParentID  
 END  
  
 DECLARE @IsAdmin BIT = 0  
  
 SELECT TOP 1 @IsAdmin = isAdmin  
 FROM User_Detail WITH (NOLOCK)  
 WHERE User_ID = @Userid  
  
 IF (isnull(@IsAdmin, 0) = 1)  
 BEGIN  
  SET @Userid = 0  
 END  
  
 SELECT DISTINCT UL.LeadNo  
  ,UL.PersonName  
  ,UD.User_Login  
  ,USS.Name AS SourceName  
  ,UMS.Name AS MediumName  
  ,UCS.Name AS CampaignName  
  ,ISNULL(ul.CompanyName, '') AS CompanyName  
  ,ISNULL(ul.CountryCode, '') + '-' + ISNULL(ul.MobileNo, '') + CASE   
   WHEN ISNULL(ul.MobileNo1, '') <> ''  
    THEN ',' + ISNULL(ul.CountryCode1, '') + '-' + ISNULL(ul.MobileNo1, '')  
   ELSE ''  
   END + CASE   
   WHEN ISNULL(ul.MobileNo2, '') <> ''  
    THEN ',' + ISNULL(ul.CountryCode2, '') + '-' + ISNULL(ul.MobileNo2, '')  
   ELSE ''  
   END AS MobileNo  
  ,ISNULL(ul.EmailID, '') + CASE   
   WHEN ISNULL(ul.EmailID1, '') <> ''  
    THEN ',' + ISNULL(ul.EmailID1, '')  
   ELSE ''  
   END + CASE   
   WHEN ISNULL(ul.EmailID2, '') <> ''  
    THEN ',' + ISNULL(ul.EmailID2, '')  
   ELSE ''  
   END AS EmailID  
  ,ul.City  
  ,ul.[State]  
  ,ul.Country  
  ,ul.PinCode  
  ,ul.ResidentialAddress  
  ,ul.OfficeAddress  
  ,CASE   
   WHEN ul.Companyname <> ''  
    THEN ul.Officeaddress  
   ELSE ul.Residentialaddress  
   END AS [ADDRESS]  
  ,  
  --ISNULL(ud.Fname, '') + ' ' + ISNULL(ud.LName, '') AS CreatedBy,       
  ISNULL(ud.User_Login, '') AS CreatedBy  
  ,(  
   SELECT SUM(lih.AmountPaid)  
   FROM LeadInteractionHistory(NOLOCK) lih  
   WHERE lih.ParentID = @ParentID  
    AND lih.LeadNo = ul.LeadNo  
    --AND lih.AmountPaid <> 0              
    AND lih.FollowUpStatus IN (  
     SELECT Id  
     FROM FollowUp_Status fup  
     WHERE fup.IsConvert = 1  
      AND (  
       fup.ParentID = @ParentID  
       OR fup.ParentID IS NULL  
       )  
     ) --= 5  
	 --and lih.ID
	 --   in ( select max (id) from LeadInteractionHistory(NOLOCK) lihinner
		--     where lihinner.ParentID = @ParentID  
		--     and  lihinner.LeadNo = ul.LeadNo 
		--     and  lihinner.ParentID = ul.ParentID
		--	 and lihinner.FollowUpStatus IN (  
		--		 SELECT Id  
		--		 FROM FollowUp_Status fup1  
		--		 WHERE fup1.IsConvert = 1  
		--		  AND (  
		--		   fup1.ParentID = @ParentID  
		--		   OR fup1.ParentID IS NULL  
		--		   )  

		--	)) 

   ) AS TotalAmount  
  ,(  
   SELECT COUNT(*)  
   FROM LeadInteractionHistory(NOLOCK) lih  
   WHERE lih.ParentID = @ParentID  
    AND lih.LeadNo = ul.LeadNo  
    --AND lih.AmountPaid <> 0              
    AND lih.FollowUpStatus IN (  
     SELECT Id  
     FROM FollowUp_Status fup  
     WHERE fup.IsConvert = 1  
      AND (  
       fup.ParentID = @ParentID  
       OR fup.ParentID IS NULL  
       )  
     ) --= 5                              
   ) AS TotalOrders  
  ,(  
   SELECT TOP 1  dbo.[fn_getusertimefromindiantime](@UserID_ForDatetimeConversion, lih.CreatedOn)  
   -- SELECT TOP 1 dbo.[fn_getusertimefromindiantime](@ParentID,lih.FollowupDate)                            
   FROM LeadInteractionHistory(NOLOCK) AS lih  
   WHERE lih.LeadNo = ul.LeadNo  
    AND lih.ParentID = @ParentID
   --AND lih.AmountPaid <> 0               
    AND lih.FollowUpStatus IN (  
     SELECT Id  
     FROM FollowUp_Status fup  
     WHERE fup.IsConvert = 1  
      AND (  
       fup.ParentID = @ParentID  
       OR fup.ParentID IS NULL  
       )  
     ) --= 5                             
     
   ORDER BY lih.ID DESC  
   ) AS OrderDate  
  --,ud2.User_Login
  ,@ParentID AS AssignedToByName  
 FROM UserLeads(NOLOCK) ul  
 INNER JOIN LeadInteractionHistory(NOLOCK) lih ON lih.LeadNo = ul.LeadNo and lih.ParentID = ul.ParentID  
  AND lih.ParentID = @ParentID  
  --AND ISNULL(lih.AmountPaid, 0) <> 0                            
  AND lih.FollowUpStatus IN (  
   SELECT Id  
   FROM FollowUp_Status fup  
   WHERE fup.IsConvert = 1  
    AND (  
     fup.ParentID = @ParentID  
     OR fup.ParentID IS NULL  
     )  
   ) --= 5            
 LEFT JOIN User_Detail(NOLOCK) ud ON ud.[User_ID] = ul.CreatedBy  
 LEFT JOIN User_Detail(NOLOCK) ud2 ON ud2.[User_ID] = lih.AssignedTo  
 LEFT JOIN UserSourceSettings(NOLOCK) USS ON USS.SourceID = ul.SourceName  
 LEFT JOIN UserMediumSettings(NOLOCK) UMS ON UMS.MediumID = ul.MediumName  
 LEFT JOIN UserCampaignSettings UCS ON UCS.CampaignID = ul.CampaignName  
 WHERE ul.ParentID = @ParentID  
  AND UL.AssignedTo = CASE   
   WHEN (@IsAdmin = 1)  
    THEN UL.AssignedTo  
   ELSE @Userid  
   END  
  AND ul.LeadNo IN (  
   SELECT lih.LeadNo  
   FROM LeadInteractionHistory(NOLOCK) lih  
   WHERE lih.ParentID = @ParentID  
    --AND ISNULL(lih.AmountPaid, 0) <> 0                           
    AND lih.FollowUpStatus IN (  
     SELECT Id  
     FROM FollowUp_Status fup  
     WHERE fup.IsConvert = 1  
      AND (  
       fup.ParentID = @ParentID  
       OR fup.ParentID IS NULL  
       )  
     ) --= 5        
   )
    and lih.ID
	    in ( select max (id) from LeadInteractionHistory(NOLOCK) lihinner
		     where lihinner.ParentID = @ParentID  
		     and  lihinner.LeadNo = ul.LeadNo 
		     and  lihinner.ParentID = ul.ParentID
			 and lihinner.FollowUpStatus IN (  
				 SELECT Id  
				 FROM FollowUp_Status fup  
				 WHERE fup.IsConvert = 1  
				  AND (  
				   fup.ParentID = @ParentID  
				   OR fup.ParentID IS NULL  
				   )  

			)) 

 ORDER BY OrderDate DESC  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID_ForDatetimeConversion  
  ,@Activity_type = 'View_Cnvrsn_Lead'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'UserLeads'  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserLeadsConversions_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserLeadsConversions_INTDateTime] --335          
 @ParentID BIGINT,    
 @Userid int=0            
AS            
BEGIN            
 SELECT UL.LeadNo,            
        UL.PersonName,          
        UD.User_Login,          
        USS.Name as SourceName,          
        UMS.Name as MediumName,          
        UCS.Name as CampaignName,            
        ISNULL(ul.CompanyName, '')  AS CompanyName,            
        ISNULL(ul.CountryCode, '') + '-' + ISNULL(ul.MobileNo, '') +            
                    
        CASE             
             WHEN ISNULL(ul.MobileNo1, '') <> '' THEN ',' + ISNULL(ul.CountryCode1, '')             
                              
                  + '-' + ISNULL(ul.MobileNo1, '')            
             ELSE ''            
        END + CASE             
                   WHEN ISNULL(ul.MobileNo2, '') <> '' THEN ',' + ISNULL(ul.CountryCode2, '')             
                                    
                        + '-' + ISNULL(ul.MobileNo2, '')            
                   ELSE ''            
              END                   AS MobileNo,            
        ISNULL(ul.EmailID, '') + CASE             
                                      WHEN ISNULL(ul.EmailID1, '') <> '' THEN             
                                           ',' + ISNULL(ul.EmailID1, '')            
                                      ELSE ''            
                                 END + CASE             
                                            WHEN ISNULL(ul.EmailID2, '') <>            
                                                             
                                                 '' THEN ',' + ISNULL(ul.EmailID2, '')            
                                            ELSE ''            
                                       END AS EmailID,            
        ul.City,            
        ul.[State],            
        ul.Country,            
        ul.PinCode,            
        ul.ResidentialAddress,            
        ul.OfficeAddress,    
        CASE         
                        WHEN ul.Companyname <> '' THEN ul.Officeaddress        
                        ELSE ul.Residentialaddress        
                   END          AS [ADDRESS],               
        ISNULL(ud.Fname, '') + ' ' + ISNULL(ud.LName, '') AS CreatedBy,            
        (            
            SELECT SUM(lih.AmountPaid)            
            FROM   LeadInteractionHistory lih            
            WHERE  lih.ParentID = @ParentID            
                   AND lih.LeadNo = ul.LeadNo            
                   AND lih.AmountPaid <> 0            
        )                           AS TotalAmount,            
        (            
            SELECT COUNT(*)            
            FROM   LeadInteractionHistory lih            
            WHERE  lih.ParentID = @ParentID            
                   AND lih.LeadNo = ul.LeadNo            
                   AND lih.AmountPaid <> 0            
        )                           AS TotalOrders,            
        (            
            SELECT TOP 1 dbo.[fn_getusertimefromindiantime](@ParentID,lih.CreatedOn)          
            FROM   LeadInteractionHistory AS lih            
            WHERE  lih.LeadNo = ul.LeadNo            
                   AND lih.AmountPaid <> 0            
                   AND lih.ParentID = @ParentID            
        )                           AS OrderDate            
 FROM   UserLeads ul            
        LEFT JOIN User_Detail ud            
             ON  ud.[User_ID] = ul.CreatedBy           
        Left Join UserSourceSettings USS          
              ON USS.SourceID = ul.SourceName          
        Left JOIN UserMediumSettings UMS          
              ON UMS.MediumID = ul.MediumName          
        Left Join UserCampaignSettings UCS          
             ON UCS.CampaignID = ul.CampaignName                             
 WHERE  ul.ParentID = @ParentID    
 AND UL.CreatedBy = CASE     
                               WHEN (@Userid = 0) THEN UL.CreatedBy     
                      ELSE @Userid    
                          END     
        AND ul.LeadNo IN (SELECT lih.LeadNo            
                          FROM   LeadInteractionHistory lih            
                          WHERE  lih.ParentID = @ParentID            
                                 AND ISNULL(lih.AmountPaid, 0) <> 0)         
                                order by OrderDate desc         
END


