CREATE   PROCEDURE [dbo].[usp_GetUserLeadsConversionsDetailed] --42261,0    --34594 --31871,0 --35610,0                        
 @ParentID BIGINT  
 ,@Userid INT = 0  
AS  
BEGIN  
 DECLARE @UserID_ForDatetimeConversion BIGINT = @UserId  
  
 IF (  
   @Userid is NULL  
   OR @Userid = 0  
   )  
 BEGIN  
  SET @UserID_ForDatetimeConversion = @ParentID  
 END  
  
 DECLARE @IsAdmin BIT = 0  
  
 SELECT TOP 1 @IsAdmin = isAdmin  
 FROM User_Detail WITH (NOLOCK)  
 WHERE User_ID = @Userid  
  
 IF (isnull(@IsAdmin, 0) = 1)  
 BEGIN  
  SET @Userid = 0  
 END  
      
 exec Usp_createProductMasterTable @ParentID  
  
 Declare @Query nvarchar(max) = concat( N'  SELECT distinct lih.ID FollowUpID,  
  ul.ID LeadId,
  ul.LeadNo  
  ,ul.PersonName  
  ,UD.User_Login  
  ,USS.Name AS SourceName  
  ,UMS.Name AS MediumName  
  ,UCS.Name AS CampaignName  
  ,ISNULL(ul.CompanyName, '''') AS CompanyName  
  ,ISNULL(ul.CountryCode, '''') + ''-'' + ISNULL(ul.MobileNo, '''') + CASE   
   WHEN ISNULL(ul.MobileNo1, '''') <> ''''  
    THEN '','' + ISNULL(ul.CountryCode1, '''') + ''-'' + ISNULL(ul.MobileNo1, '''')  
   ELSE ''''  
   END + CASE   
   WHEN ISNULL(ul.MobileNo2, '''') <> ''''  
    THEN '','' + ISNULL(ul.CountryCode2, '''') + ''-'' + ISNULL(ul.MobileNo2, '''')  
   ELSE ''''  
   END AS MobileNo  
  ,ISNULL(ul.EmailID, '''') + CASE   
   WHEN ISNULL(ul.EmailID1, '''') <> ''''  
    THEN '','' + ISNULL(ul.EmailID1, '''')  
   ELSE ''''  
   END + CASE   
   WHEN ISNULL(ul.EmailID2, '''') <> ''''  
    THEN '','' + ISNULL(ul.EmailID2, '''')  
   ELSE ''''  
   END AS EmailID  
  ,ul.City  
  ,ul.[State]  
  ,ul.Country  
  ,ul.PinCode  
  ,ul.ResidentialAddress  
  ,ul.OfficeAddress  
  ,CASE   
   WHEN ul.Companyname <> ''''  
    THEN ul.Officeaddress  
   ELSE ul.Residentialaddress  
   END AS [ADDRESS]  
  ,ISNULL(ud.Fname, '''') + '' '' + ISNULL(ud.LName, '''') AS CreatedBy  
  ,fus.FollowupStatus AS FollowUpStatus  
  ,lih.Remarks  
  ,(  
   SELECT STUFF((  
      SELECT N'', '' + pm.Name  
      FROM tbl_ProductMaster_', cast(@ParentID as nvarchar(max)) ,' (nolock) pm  
      INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS fs ON pm.ProductID = fs.[value]  
      FOR XML PATH('''')  
       ,TYPE  
      ).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')  
   ) AS Products  
  ,lih.AmountPaid  
  ,ISNULL(ud2.Fname, '''') + '' '' + ISNULL(ud2.LName, '''') AS AssignTo  
  ,dbo.[fn_getusertimefromindiantime](', cast( @UserID_ForDatetimeConversion as nvarchar(max)),', lih.CreatedOn) AS OrderedDate  
  ,ud2.User_Login AS AssignedToByName  
 FROM UserLeads(NOLOCK) ul  
 INNER JOIN LeadInteractionHistory lih ON lih.LeadNo = ul.LeadNo  
  AND lih.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
  -- AND ISNULL(lih.AmountPaid, 0) <> 0                          
  AND lih.FollowUpStatus IN (  
   SELECT Id  
   FROM FollowUp_Status fup  
   WHERE  
    -- fup.IsCallback = 1   
    fup.IsConvert = 1  
    AND (  
     fup.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
     OR fup.ParentID is NULL  
     )  
   )  
 LEFT JOIN User_Detail(NOLOCK) ud ON ud.[User_ID] = ul.CreatedBy  
 LEFT JOIN User_Detail(NOLOCK) ud2 ON ud2.[User_ID] = lih.AssignedTo  
 LEFT JOIN FollowUp_Status fus ON fus.ID = lih.FollowUpStatus  
 LEFT JOIN UserSourceSettings USS ON USS.SourceID = ul.SourceName  
 LEFT JOIN UserMediumSettings UMS ON UMS.MediumID = ul.MediumName  
 LEFT JOIN UserCampaignSettings UCS ON UCS.CampaignID = ul.CampaignName  
 WHERE ul.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
  AND UL.CreatedBy = CASE   
   WHEN (',cast(@Userid as nvarchar(max)),' = 0)  
    THEN UL.CreatedBy  
   ELSE ',cast(@Userid as nvarchar(max)),'  
   END  
  AND ul.LeadNo IN (  
   SELECT lih.LeadNo  
   FROM LeadInteractionHistory lih  
   WHERE lih.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
    --AND ISNULL(lih.AmountPaid, 0) <> 0            
    AND lih.FollowUpStatus IN (  
     SELECT Id  
     FROM FollowUp_Status fup  
     WHERE  
      --fup.IsCallback = 1  
      fup.IsConvert = 1  
      AND (  
       fup.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
       OR fup.ParentID is NULL  
       )  
     )  
   )  
   --and lih.id in ( select max (id) from LeadInteractionHistory(NOLOCK) lihinner
		 --    where lihinner.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
		 --    and  lihinner.LeadNo = ul.LeadNo 
		 --    and  lihinner.ParentID = ul.ParentID
			-- and lihinner.FollowUpStatus IN (  
			--	 SELECT Id  
			--	 FROM FollowUp_Status fup  
			--	 WHERE fup.IsConvert = 1  
			--	  AND (  
			--	   fup.ParentID = ', cast(@ParentID as nvarchar(max)) ,'  
			--	   OR fup.ParentID IS NULL  
			--	   )  
		
			--))

 ORDER BY OrderedDate DESC  ')  
  
 print @Query  
 exec sp_executesql @query  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID_ForDatetimeConversion  
  ,@Activity_type = 'View_DetCnvrn_Lead'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'UserLeads'  
END  


