/* ============================================================
   Procedure: [dbo].[usp_GetUserLeadsConversionsDetailed_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserLeadsConversionsDetailed_INTDateTime]            
 @ParentID BIGINT,    
  @Userid int=0            
AS            
BEGIN            
 SELECT ul.LeadNo,            
        ul.PersonName,          
        UD.User_Login,        
        USS.Name as SourceName,          
        UMS.Name as MediumName,          
        UCS.Name as CampaignName,             
        ISNULL(ul.CompanyName, '')  AS CompanyName,            
        ISNULL(ul.CountryCode, '') + '-' + ISNULL(ul.MobileNo, '') +            
        CASE             
             WHEN ISNULL(ul.MobileNo1, '') <> '' THEN ',' + ISNULL(ul.CountryCode1, '')             
                  + '-' + ISNULL(ul.MobileNo1, '')            
             ELSE ''            
        END + CASE             
                   WHEN ISNULL(ul.MobileNo2, '') <> '' THEN ',' + ISNULL(ul.CountryCode2, '')             
                        + '-' + ISNULL(ul.MobileNo2, '')            
                   ELSE ''            
              END                   AS MobileNo,            
        ISNULL(ul.EmailID, '') + CASE             
                                      WHEN ISNULL(ul.EmailID1, '') <> '' THEN             
                                           ',' + ISNULL(ul.EmailID1, '')            
                                      ELSE ''            
                                 END + CASE             
                                            WHEN ISNULL(ul.EmailID2, '') <>            
                                                 '' THEN ',' + ISNULL(ul.EmailID2, '')            
                                            ELSE ''            
                                       END AS EmailID,            
        ul.City,            
        ul.[State],            
        ul.Country,            
        ul.PinCode,            
        ul.ResidentialAddress,            
        ul.OfficeAddress,    
         CASE         
                        WHEN ul.Companyname <> '' THEN ul.Officeaddress        
                        ELSE ul.Residentialaddress        
                   END          AS [ADDRESS],          
                   
        ISNULL(ud.Fname, '') + ' ' + ISNULL(ud.LName, '') AS CreatedBy,            
        fus.FollowupStatus          AS FollowUpStatus,            
        lih.Remarks,            
        (            
            SELECT STUFF(            
                       (            
                           SELECT N', ' + pm.Name            
                           FROM   ProductMaster pm            
                                  INNER JOIN dbo.fn_Split(lih.Products, '#') AS             
                                       fs            
                                       ON  pm.ProductID = fs.[value]             
                                           FOR XML             
                                           PATH(''),            
                                  TYPE            
                       )             
                       .value('text()[1]', 'nvarchar(max)'),            
                       1,            
                       2,            
                       N''            
                   )            
        )                           AS Products,            
        lih.AmountPaid,            
        ISNULL(ud2.Fname, '') + ' ' + ISNULL(ud2.LName, '') AS AssignTo,            
          dbo.[fn_getusertimefromindiantime](@ParentID,lih.CreatedOn) AS OrderedDate            
 FROM   UserLeads ul            
        INNER JOIN LeadInteractionHistory lih            
             ON  lih.LeadNo = ul.LeadNo            
             AND lih.ParentID = @ParentID            
             AND ISNULL(lih.AmountPaid, 0) <> 0            
        LEFT JOIN User_Detail ud            
             ON  ud.[User_ID] = ul.CreatedBy            
        LEFT JOIN User_Detail ud2            
             ON  ud2.[User_ID] = lih.AssignedTo            
        LEFT JOIN FollowUp_Status fus            
             ON  fus.ID = lih.FollowUpStatus         
        Left Join UserSourceSettings USS          
              ON USS.SourceID = ul.SourceName          
        Left JOIN UserMediumSettings UMS          
              ON UMS.MediumID = ul.MediumName          
        Left Join UserCampaignSettings UCS          
             ON UCS.CampaignID = ul.CampaignName             
 WHERE  ul.ParentID = @ParentID    
 AND UL.CreatedBy = CASE     
                               WHEN (@Userid = 0) THEN UL.CreatedBy     
                               ELSE @Userid    
                          END             
        AND ul.LeadNo IN (SELECT lih.LeadNo            
                          FROM   LeadInteractionHistory lih            
                          WHERE  lih.ParentID = @ParentID            
                                 AND ISNULL(lih.AmountPaid, 0) <> 0)        
                                       
                                 order by OrderedDate desc          
END


