/* ============================================================
   Procedure: [dbo].[usp_getuserlocationtrackingstatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getuserlocationtrackingstatus  
as  
begin  
drop table if exists #temp  
drop table if exists #temp_loc  
drop table if exists #temp_fin  
drop table if exists #temp_new  
begin try  
create table #temp_new(id bigint)  
  
select t.* into #temp from tbl_mob_DeviceSyncHistory(nolock) t where dbo.fn_IsUserInGeoGroup(t.userid)=1 and cast(t.createddate as date)=cast(getdate() as date) and dbo.fn_UserLastMovementCode(userid)  not in ('signout','Sign_out','breakin')  
and t.HistoryId=(select max(historyid) from tbl_mob_DeviceSyncHistory(nolock) where userid=t.UserId)  
  
--select * from #temp   
  
select userid,max(locationdatetime) locationdatetime,max(movementcode) movementcode,max(UserLocationTrackingId) LocationId into #temp_loc from [TBL_ET_UserLocationTracking](nolock) where  
  isnull(address,'')<>'' and datediff(d,locationdatetime,getdate()) <=2 group by userid   
  
  --select * from #temp_loc  
  
  select t.userid as   
user_id,modelname,LocationReason,locationdatetime,movementcode,LocationId,locationcapturing,dbo.ufn_GetUserParentId(t.userid) parentid into #temp_fin from #temp t left join #temp_loc l on t.UserId=l.UserId  
  
  --select * from #temp_fin   
  
  
  
  --select t.user_id,locationdatetime,movementcode,t.modelname,case when datediff(mi,locationdatetime,getdate())>15 then 0 else 1 end,  
  --LocationReason,locationid,locationcapturing,parentid from #temp_fin t left join vw_userlocationtracking_latest u on t.user_id=u.user_id  
  --where 1= case when datediff(mi,isnull(locationdatetime,dateadd(d,-1,getdate())),getdate())>15 and u.Currentlytrackable=0 then 0  
  --when datediff(mi,isnull(locationdatetime,getdate()),getdate())<=15 and u.Currentlytrackable=1 then 0 else 1 end  
  
  
  insert into UserLocationTracking(user_id,lastlocationtracked,laststatus,modelname,Currentlytrackable,lastlocationreason,locationid,  
  lastlocationcapturing,parentid)  
  output inserted.id into #temp_new  
  select t.user_id,locationdatetime,movementcode,t.modelname,case when datediff(mi,isnull(locationdatetime,dateadd(d,-1,getdate())),getdate())>15 then 0 else 1 end,  
  LocationReason,locationid,locationcapturing,parentid from #temp_fin t left join vw_userlocationtracking_latest u on t.user_id=u.user_id  
  where 1= case when datediff(mi,isnull(locationdatetime,dateadd(d,-1,getdate())),getdate())>15 and u.Currentlytrackable=0 then 0  
  when datediff(mi,isnull(locationdatetime,getdate()),getdate())<=15 and u.Currentlytrackable=1 then 0 else 1 end  
  
  declare @tbl as LeadActivitywithid_Tbltype  
  
  insert into @tbl(leadid,userid,parentid,eventname,eventdescription,reftable,refid)  
  select t.user_id,t.user_id,t.parentid,case when currentlytrackable=0 then 'User not trackable' else 'User Location is now tracking' end,  
  case when currentlytrackable=0 then  user_login + ' is not trackable'+'. Reason: '+case when lastlocationcapturing='Yes' then   
'Possibly user has not turned auto start on for the app' else replace(t.lastlocationreason,cast(u.user_id as nvarchar),user_login) end+'. Last location tracked was '+  
  isnull(' at '+cast(lastlocationtracked as nvarchar),'never in last 2 days')+       
  '. User device model is '+t.modelname   
  else user_login + '''s Location is now trackable.'  
--  User was reported not trackable since '+  isnull(cast(lastlocationtracked as nvarchar),' last 2 days')+isnull('  with status as: '+  
--laststatus,'')   
  end,'userlocationtracking',t.id   
from userlocationtracking t(nolock) join #temp_new n on t.id=n.id  
join user_detail u(nolock) on u.user_id=t.user_id  
  
--select * from @tbl  
exec [UspSaveentityActivity_withMultipleValue_withid_bulk] @tbl  
 
end try
begin catch
exec usp_inserterrorinfo
end catch
 
drop table if exists #temp  
drop table if exists #temp_loc  
drop table if exists #temp_fin  
drop table if exists #temp_new  
  
end  
--truncate table userlocationtracking  
--select * from userlocationtracking order by user_id


GO

