/* ============================================================
   Procedure: [dbo].[usp_GetUserLoginStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_GetUserLoginStatus 32222,20,1
-- Exec usp_GetUserLoginStatus 335,50,1
CREATE   PROCEDURE dbo.usp_GetUserLoginStatus (
	@Userid BIGINT = 335
	,-- (335)SuperAdmin
	@PageSize INT = 0
	,-- (0)All Records
	@PageNo INT = 1
	)
AS
BEGIN
	-- declare @Userid int=335,@PageSize int=20, @PageNo int=2 
	DECLARE @ParentId BIGINT = 0
		,@IsAdmin INT = 0

	SET @PageSize = IIF(@PageSize < 0, 0, @PageSize)
	SET @PageNo = IIF(@PageNo < 1, 1, @PageNo)

	SELECT @ParentId = ParentId
		,@IsAdmin = CASE 
			WHEN IsAdmin = 1
				OR User_id = parentId
				THEN 1
			ELSE 0
			END
	FROM user_detail(NOLOCK)
	WHERE User_Id = @Userid

	IF (@Userid = 335)
	BEGIN
		IF (@PageSize = 0)
		BEGIN
			SELECT Row_number() OVER (
					ORDER BY LRL.CreatedDate DESC
					) AS Sno
				,UD.User_ID
				,UD.User_Login
				,UserName = isnull(UD.FName, '') + isnull(' ' + UD.LName, '')
				,UD.EMail
				,UD.Mobile
				,OnField = isnull(UD.OnField, 0)
				,OnDuty = isnull(UD.onduty, 0)
				,Presence = isnull(UD.Presence, 0)
				,IsAppLogin = IIF(len(isnull(UD.DeviceID, '')) > 20, 1, 0)
				,IsWebLogin = IIF(len(isnull(UD.MacAddress, '')) > 5, 1, 0)
				,TrackingFrequency = isnull(LS.FrequencyUnit, 0)
				,UnTrackableFrequency = isnull(LS.Untrackableunit, 0)
				,LastLocationAddress = isnull(LRL.MeaningfulAddress, 'No Location')
				,LastLocationDate = isnull(convert(VARCHAR, LRL.CreatedDate, 113), '')
				,AppVersion = isnull(AppVersion, '')
				,OSVersion = isnull(OSVersion, '')
				,OSName = isnull(OSName, '')
				,ModelName = isnull(ModelName, '')
			FROM User_Detail(NOLOCK) UD
			LEFT JOIN tbl_location_setting(NOLOCK) LS ON UD.User_ID = LS.User_ID
			LEFT JOIN v_LastRealTimeLocation LRL ON UD.User_ID = LRL.UserID
		END
		ELSE
		BEGIN
			SELECT *
			FROM (
				SELECT Row_number() OVER (
						ORDER BY LRL.CreatedDate DESC
						) AS Sno
					,UD.User_ID
					,UD.User_Login
					,UserName = isnull(UD.FName, '') + isnull(' ' + UD.LName, '')
					,UD.EMail
					,UD.Mobile
					,OnField = isnull(UD.OnField, 0)
					,OnDuty = isnull(UD.onduty, 0)
					,Presence = isnull(UD.Presence, 0)
					,IsAppLogin = IIF(len(isnull(UD.DeviceID, '')) > 20, 1, 0)
					,IsWebLogin = IIF(len(isnull(UD.MacAddress, '')) > 5, 1, 0)
					,TrackingFrequency = isnull(LS.FrequencyUnit, 0)
					,UnTrackableFrequency = isnull(LS.Untrackableunit, 0)
					,LastLocationAddress = isnull(LRL.MeaningfulAddress, 'No Location')
					,LastLocationDate = isnull(convert(VARCHAR, LRL.CreatedDate, 113), '')
					,AppVersion = isnull(AppVersion, '')
					,OSVersion = isnull(OSVersion, '')
					,OSName = isnull(OSName, '')
					,ModelName = isnull(ModelName, '')
				FROM User_Detail(NOLOCK) UD
				LEFT JOIN tbl_location_setting(NOLOCK) LS ON UD.User_ID = LS.User_ID
				LEFT JOIN v_LastRealTimeLocation LRL ON UD.User_ID = LRL.UserID
				) T
			WHERE T.Sno BETWEEN (((@PageNo - 1) * @PageSize) + 1)
					AND (@PageNo * @PageSize)
		END
	END
	ELSE
	BEGIN
		IF (@IsAdmin = 1)
		BEGIN
			IF (@PageSize = 0)
			BEGIN
				SELECT Row_number() OVER (
						ORDER BY LRL.CreatedDate DESC
						) AS Sno
					,UD.User_ID
					,UD.User_Login
					,UserName = isnull(UD.FName, '') + isnull(' ' + UD.LName, '')
					,UD.EMail
					,UD.Mobile
					,OnField = isnull(UD.OnField, 0)
					,OnDuty = isnull(UD.onduty, 0)
					,Presence = isnull(UD.Presence, 0)
					,IsAppLogin = IIF(len(isnull(UD.DeviceID, '')) > 20, 1, 0)
					,IsWebLogin = IIF(len(isnull(UD.MacAddress, '')) > 5, 1, 0)
					,TrackingFrequency = isnull(LS.FrequencyUnit, 0)
					,UnTrackableFrequency = isnull(LS.Untrackableunit, 0)
					,LastLocationAddress = isnull(LRL.MeaningfulAddress, 'No Location')
					,LastLocationDate = isnull(convert(VARCHAR, LRL.CreatedDate, 113), '')
					,AppVersion = isnull(AppVersion, '')
					,OSVersion = isnull(OSVersion, '')
					,OSName = isnull(OSName, '')
					,ModelName = isnull(ModelName, '')
				FROM User_Detail(NOLOCK) UD
				LEFT JOIN tbl_location_setting(NOLOCK) LS ON UD.User_ID = LS.User_ID
				LEFT JOIN v_LastRealTimeLocation LRL ON UD.User_ID = LRL.UserID
				WHERE UD.ParentID = @ParentId
			END
			ELSE
			BEGIN
				SELECT *
				FROM (
					SELECT Row_number() OVER (
							ORDER BY LRL.CreatedDate DESC
							) AS Sno
						,UD.User_ID
						,UD.User_Login
						,UserName = isnull(UD.FName, '') + isnull(' ' + UD.LName, '')
						,UD.EMail
						,UD.Mobile
						,OnField = isnull(UD.OnField, 0)
						,OnDuty = isnull(UD.onduty, 0)
						,Presence = isnull(UD.Presence, 0)
						,IsAppLogin = IIF(len(isnull(UD.DeviceID, '')) > 20, 1, 0)
						,IsWebLogin = IIF(len(isnull(UD.MacAddress, '')) > 5, 1, 0)
						,TrackingFrequency = isnull(LS.FrequencyUnit, 0)
						,UnTrackableFrequency = isnull(LS.Untrackableunit, 0)
						,LastLocationAddress = isnull(LRL.MeaningfulAddress, 'No Location')
						,LastLocationDate = isnull(convert(VARCHAR, LRL.CreatedDate, 113), '')
						,AppVersion = isnull(AppVersion, '')
						,OSVersion = isnull(OSVersion, '')
						,OSName = isnull(OSName, '')
						,ModelName = isnull(ModelName, '')
					FROM User_Detail(NOLOCK) UD
					LEFT JOIN tbl_location_setting(NOLOCK) LS ON UD.User_ID = LS.User_ID
					LEFT JOIN v_LastRealTimeLocation LRL ON UD.User_ID = LRL.UserID
					WHERE UD.ParentID = @ParentId
					) T
				WHERE T.Sno BETWEEN (((@PageNo - 1) * @PageSize) + 1)
						AND (@PageNo * @PageSize)
			END
		END
		ELSE
		BEGIN
			SELECT Row_number() OVER (
					ORDER BY LRL.CreatedDate DESC
					) AS Sno
				,UD.User_ID
				,UD.User_Login
				,UserName = isnull(UD.FName, '') + isnull(' ' + UD.LName, '')
				,UD.EMail
				,UD.Mobile
				,OnField = isnull(UD.OnField, 0)
				,OnDuty = isnull(UD.onduty, 0)
				,Presence = isnull(UD.Presence, 0)
				,IsAppLogin = IIF(len(isnull(UD.DeviceID, '')) > 20, 1, 0)
				,IsWebLogin = IIF(len(isnull(UD.MacAddress, '')) > 5, 1, 0)
				,TrackingFrequency = isnull(LS.FrequencyUnit, 0)
				,UnTrackableFrequency = isnull(LS.Untrackableunit, 0)
				,LastLocationAddress = isnull(LRL.MeaningfulAddress, 'No Location')
				,LastLocationDate = isnull(convert(VARCHAR, LRL.CreatedDate, 113), '')
				,AppVersion = isnull(AppVersion, '')
				,OSVersion = isnull(OSVersion, '')
				,OSName = isnull(OSName, '')
				,ModelName = isnull(ModelName, '')
			FROM User_Detail(NOLOCK) UD
			LEFT JOIN tbl_location_setting(NOLOCK) LS ON UD.User_ID = LS.User_ID
			LEFT JOIN v_LastRealTimeLocation LRL ON UD.User_ID = LRL.UserID
			WHERE UD.User_ID = @Userid
		END
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentId
		,@Activity_type = 'View_usrLogn_stats'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'User_Detail'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserMailbox]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetUserMailbox @UserID BIGINT
AS
BEGIN
	DECLARE @ParentId BIGINT = 0;
	DECLARE @IsAdmin BIT = 0;
	DECLARE @RoleType VARCHAR(10);
	DECLARE @TeamCode VARCHAR(20)

	SELECT @ParentId = ParentID
		,@IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId;

	IF object_id('tempdb..#tblUserIds') IS NOT NULL
	BEGIN
		DROP TABLE #tblUserIds
	END

	CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)

	SELECT @TeamCode = tum.TeamCode
	FROM TBL_UA_TeamUserMappingMaster(NOLOCK) tum
	INNER JOIN TBL_UA_TeamMaster(NOLOCK) tm ON tm.TeamCode = tum.TeamCode
	WHERE tum.UserId = @UserId

	IF (
			(@TeamCode IS NULL)
			AND (
				@ParentId = @UserId
				OR @IsAdmin = 1
				)
			)
	BEGIN
		--set @RoleType = 'Global'  
		INSERT INTO #tblUserIds (UserId)
		SELECT User_Id UserId
		FROM User_Detail(NOLOCK)
		WHERE ParentId = @ParentId
	END
	ELSE IF (@TeamCode != NULL)
	BEGIN
		---set @RoleType = 'Team'  
		INSERT INTO #tblUserIds (UserId)
		SELECT UserId
		FROM TBL_UA_TeamUserMappingMaster(NOLOCK)
		WHERE TeamCode = @TeamCode
	END
	ELSE
	BEGIN
		--set @RoleType = 'User'  
		INSERT INTO #tblUserIds (UserId)
		SELECT @UserId
	END

	SELECT um.ID
		,um.EmailID
		,um.ForwadingEmail
		,um.IsStep7
	FROM UserMailbox AS um
	WHERE um.UserID IN (
			SELECT UserId
			FROM #tblUserIds
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_UsrMailBox '
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'UserMailbox'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserMailboxCheck]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetUserMailboxCheck]  
 @ParentID BIGINT  
AS  
BEGIN  
 IF EXISTS (  
        SELECT 'x'  
        FROM   UserMailbox AS um  
        WHERE  um.ParentID = @ParentID  
    )  
 BEGIN  
 declare @cnt bigint
 select @cnt=COUNT(ID) from UserMailbox where IsStep1='1' and IsStep2='1' and IsStep3='1' and ParentID=@ParentID
 if (@cnt > 0)
 begin
 select ''
 end
 else
 begin
     SELECT CASE   
                 WHEN um.IsStep1 = 0 THEN '1'  
                 ELSE CASE   
                           WHEN um.IsStep1 = 0 THEN '2'  
                           ELSE CASE   
                                     WHEN um.IsStep3 = 0 THEN '3'  
                                     ELSE ''  
                                END  
                      END  
            END  
     FROM   UserMailbox AS um  
     WHERE  um.ParentID = @ParentID  
 END  
 end
END  


GO

