/* ============================================================
   Procedure: [dbo].[usp_GetUserMailboxSteps]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserMailboxSteps]
	@ID BIGINT
AS
BEGIN
	SELECT um.ID,
	       um.EmailID,
	       um.ForwadingEmail,
	       CASE 
	            WHEN um.IsStep1 = 1 THEN CASE 
	                                          WHEN um.IsStep2 = 1 THEN CASE 
	                                                                        WHEN 
	                                                                             um.IsStep3 
	                                                                             = 
	                                                                             1 THEN CASE 
	                                                                                         WHEN 
	                                                                                              um.IsStep4 
	                                                                                              = 
	                                                                                              1 THEN CASE 
	                                                                                                          WHEN 
	                                                                                                               um.IsStep5 
	                                                                                                               = 
	                                                                                                               1 THEN CASE 
	                                                                                                                           WHEN 
	                                                                                                                                um.IsStep6 
	                                                                                                                                = 
	                                                                                                                                1 THEN CASE 
	                                                                                                                                            WHEN 
	                                                                                                                                                 um.IsStep7 
	                                                                                                                                                 = 
	                                                                                                                                                 1 THEN 7
	                                                                                                                                            ELSE 
	                                                                                                                                                 6
	                                                                                                                                       END
	                                                                                                                           ELSE 
	                                                                                                                                5
	                                                                                                                      END
	                                                                                                          ELSE 
	                                                                                                               4
	                                                                                                     END
	                                                                                         ELSE 
	                                                                                              3
	                                                                                    END
	                                                                        ELSE 
	                                                                             2
	                                                                   END
	                                          ELSE 1
	                                     END
	            ELSE 0
	       END          AS IsSteps
	FROM   UserMailbox  AS um
	WHERE  um.ID = @ID
END



