/* ============================================================
   Procedure: [dbo].[usp_GetUserMailsFilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserMailsFilter]
	@UserID BIGINT,
	@isActive BIT
AS
BEGIN
	SELECT umf.ID,
	       umf.FilterName,
	       umf.Source_EmailID,
	       umf.FilterFrom,
	       umf.FilterTo,
	       umf.MailContains,
	       umf.MappingColumn,
	       umf.SourceID,
	       umf.MediumID,
	       umf.CampaignID,
	       ums.Name                      AS MediumName,
	       ucs.Name                      AS CampaignName,
	       uss.Name                      AS SourceName
	FROM   UserMailsFilter               AS umf
	       LEFT JOIN UserMediumSettings  AS ums
	            ON  ums.MediumID = umf.MediumID
	       LEFT JOIN UserCampaignSettings AS ucs
	            ON  umf.CampaignID = ucs.CampaignID
	       LEFT JOIN UserSourceSettings  AS uss
	            ON  umf.SourceID = uss.SourceID
	WHERE  umf.IsActive = @isActive
	       AND umf.UserID = @UserID
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserMailsFilter_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserMailsFilter_New]
	@UserID BIGINT,
	@IsActive BIT,
	@IsInactive BIT,
	@SourceEmail VARCHAR(500)
AS
BEGIN
	SELECT umf.ID,
	       umf.FilterName,
	       umf.Source_EmailID,
	       umf.FilterFrom,
	       umf.FilterTo,
	       umf.MailContains,
	       umf.MappingColumn,
	       umf.SourceID,
	       umf.MediumID,
	       umf.CampaignID,
	       ums.Name                      AS MediumName,
	       ucs.Name                      AS CampaignName,
	       uss.Name                      AS SourceName
	FROM   UserMailsFilter               AS umf
	       LEFT JOIN UserMediumSettings  AS ums
	            ON  ums.MediumID = umf.MediumID
	       LEFT JOIN UserCampaignSettings AS ucs
	            ON  umf.CampaignID = ucs.CampaignID
	       LEFT JOIN UserSourceSettings  AS uss
	            ON  umf.SourceID = uss.SourceID
	WHERE  (
	           umf.IsActive = CASE @IsActive
	                               WHEN 1 THEN 1
	                               ELSE NULL
	                          END
	           OR umf.IsActive = CASE @IsInactive
	                                  WHEN 1 THEN 0
	                                  ELSE NULL
	                             END
	       )
	       AND umf.UserID = @UserID
	       AND umf.Source_EmailID = @SourceEmail
END



