/* ============================================================
   Procedure: [dbo].[usp_GetUserMailsFiltersPart1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetUserMailsFiltersPart1] --335,0,1  
 @ParentID BIGINT,  
 @IsMapped BIT,  
 @IsNotMapped BIT  
AS  
BEGIN  
 SELECT A.ID, A.Name, A.FromEmail, A.ToEmail, A.SubjectContains,  
        A.MailContentContains, A.FStatus, A.FStatus1, A.FilterCount,  
        A.ValidCount, A.InValidCount, A.Mapping, A.Criteria, A.EmailID,  
        A.CreatedOn  
 FROM   (  
            SELECT umf.ID,  
                   umf.Name,  
                   umf.FromEmail,  
                   umf.ToEmail,  
                   umf.SubjectContains,  
                   umf.MailContentContains,  
                   umf.IsActive       AS FStatus,  
                   CASE   
                        WHEN umf.IsActive = 1 THEN 'ACTIVE'  
                        ELSE 'IN-ACTIVE'  
                   END                AS FStatus1,  
                   (  
                       SELECT COUNT(*)  
                       FROM   UserMailsParsing AS umft  
                       WHERE  umft.FilterID = umf.ID  
                   )                  AS FilterCount,  
                   (  
                       (  
                           SELECT COUNT(*)  
                           FROM   UserEnquiryRawEntries AS uere  
                           WHERE  uere.FilterName = umf.Name  
                                  AND uere.ParentID = @ParentID  
                                  AND uere.IsValid = 1  
                                  AND uere.IsTransfered = 0  
                       )  
                       + (  
                           SELECT COUNT(*)  
                           FROM   UserExtractedData AS ued  
                           WHERE  ued.ParentID = @ParentID  
                                  AND ued.FilterName = umf.Name  
                       )  
                   )                  AS ValidCount,  
                   (  
                       SELECT COUNT(*)  
                       FROM   UserEnquiryRawEntries AS uere  
                       WHERE  uere.FilterName = umf.Name  
                              AND uere.ParentID = @ParentID  
                              AND uere.IsInValid = 1  
                   )                  AS InValidCount,  
                   CASE   
                        WHEN umf.IsMapped = 1 THEN 'Mapped'  
                        ELSE 'Not Mapped'  
                   END                AS Mapping,  
                   (  
                       CASE   
                            WHEN umf.FromEmail <> '' THEN   
                                 '<p><b>From Mail :</b> ' +  
                                 umf.FromEmail +  
                                 '</p>'  
                            ELSE ''  
                       END + CASE   
                                  WHEN umf.ToEmail <> '' THEN   
                                       '<p><b>To Mail :</b> ' +  
                                       umf.ToEmail + '</p>'  
                                  ELSE ''  
                             END + CASE   
                                        WHEN umf.SubjectContains  
                                             <>  
                                             '' THEN '<p><b>Subject :</b> ' +   
                                             umf.SubjectContains   
                                             + '</p>'  
                                        ELSE ''  
                                   END  
                       +  
                       CASE   
                            WHEN umf.MailContentContains <> '' THEN   
                                 '<p><b>Body :</b> '   
                                 +  
                                 umf.MailContentContains + '</p>'  
                            ELSE ''  
                       END  
                   )                  AS Criteria,  
                   umf.SampleEmailID  AS EmailID,  
                   dbo.[fn_getusertimefromindiantime](@ParentID,umf.CreatedOn) as  CreatedOn
                      
            FROM   UserMailsFilters   AS umf  
            WHERE  umf.ParentID = @ParentID  
                   AND umf.IsMapped = @IsMapped  
        AND umf.IsNotMapped = 0  
            UNION  
            SELECT umf.ID,  
                   umf.Name,  
                   umf.FromEmail,  
                   umf.ToEmail,  
                   umf.SubjectContains,  
                   umf.MailContentContains,  
                   umf.IsActive       AS FStatus,  
                   CASE   
                        WHEN umf.IsActive = 1 THEN 'ACTIVE'  
                        ELSE 'IN-ACTIVE'  
                   END                AS FStatus1,  
                   (  
                       SELECT COUNT(*)  
                       FROM   UserMailsParsing AS umft  
                       WHERE  umft.FilterID = umf.ID  
                   )                  AS FilterCount,  
                   (  
                       (  
                           SELECT COUNT(*)  
                           FROM   UserEnquiryRawEntries AS uere  
                           WHERE  uere.FilterName = umf.Name  
                                  AND uere.ParentID = @ParentID  
                                  AND uere.IsValid = 1  
                                  AND uere.IsTransfered = 0  
                       )  
                       + (  
                           SELECT COUNT(*)  
                           FROM   UserExtractedData AS ued  
                           WHERE  ued.ParentID = @ParentID  
                                  AND ued.FilterName = umf.Name  
                       )  
                   )                  AS ValidCount,  
                   (  
                       SELECT COUNT(*)  
                       FROM   UserEnquiryRawEntries AS uere  
                       WHERE  uere.FilterName = umf.Name  
                              AND uere.ParentID = @ParentID  
                              AND uere.IsInValid = 1  
                   )                  AS InValidCount,  
                   CASE   
                        WHEN umf.IsMapped = 1 THEN 'Mapped'  
                        ELSE 'Not Mapped'  
                   END                AS Mapping,  
                   (  
                       CASE   
                            WHEN umf.FromEmail <> '' THEN   
                                 '<p><b>From Mail :</b> ' +  
                                 umf.FromEmail +  
                                 '</p>'  
                            ELSE ''  
                       END + CASE   
                                  WHEN umf.ToEmail <> '' THEN   
                                       '<p><b>To Mail :</b> ' +  
                                       umf.ToEmail + '</p>'  
                                  ELSE ''  
                             END + CASE   
                                        WHEN umf.SubjectContains  
                                             <>  
                                             '' THEN '<p><b>Subject :</b> ' +   
                                             umf.SubjectContains   
                                             + '</p>'  
                                        ELSE ''  
                                   END  
                       +  
                       CASE   
                            WHEN umf.MailContentContains <> '' THEN   
                                 '<p><b>Body :</b> '   
                                 +  
                                 umf.MailContentContains + '</p>'  
                            ELSE ''  
                       END  
                   )                  AS Criteria,  
                   umf.SampleEmailID  AS EmailID,  
                   dbo.[fn_getusertimefromindiantime](@ParentID,umf.CreatedOn) as  CreatedOn
            FROM   UserMailsFilters   AS umf  
            WHERE  umf.ParentID = @ParentID  
                   AND umf.IsMapped = 0  
                   AND umf.IsNotMapped = @IsNotMapped  
        ) A  
 ORDER BY  
        A.CreatedOn DESC  
END    



GO

