/* ============================================================
   Procedure: [dbo].[usp_GetUserMailsforService]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserMailsforService]  
AS  
BEGIN  
 SELECT top 100 um.ID,  
        um.UserID,  
        um.FromMail,  
        um.MailDate,  
        um.MailSubject,  
        um.MailContent,  
        ud.ParentID  
 FROM   UserMails              AS um  
        LEFT JOIN User_Detail  AS ud  
             ON  um.UserID = ud.[User_ID]  
 WHERE  ISNULL(um.IsFiltered, 0) = 0  
        AND ud.[User_ID] <> 0  
 ORDER BY  
        um.UserID,  
        um.FromMail  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserMailsforServiceNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserMailsforServiceNew]  
AS  
BEGIN 
SELECT top 100 um.ID,  
        um.UserID,  
        um.FromMail,  
        um.MailDate,  
        um.MailSubject,  
        um.MailContent,  
        ud.ParentID  into #temp
 FROM   UserMails              AS um  
        JOIN User_Detail  AS ud  
             ON  um.UserID = ud.[User_ID] join UserMailsFilter AS umf on um.userid=umf.userid
 WHERE  ISNULL(um.IsFiltered, 0) = 0  
        AND ud.[User_ID] <> 0  
 ORDER BY  
        um.UserID,  
        um.FromMail 

SELECT distinct umf.ID,  
        umf.UserID,  
        umf.FilterName,  
        umf.Source_EmailID,  
        umf.FilterFrom,  
        umf.FilterTo,  
        umf.MailContains,  
        umf.MappingColumn,  
        umf.SourceID,  
        umf.CampaignID,  
        umf.MediumID,  
        umf.Prefix,  
        umf.Suffix,  
        umf.LeftValue,  
        umf.RightValue,  
        umf.BtwFrom,  
        umf.BtwTo  into #temp2
 FROM   UserMailsFilter AS umf join #temp um with (nolock) on um.userid=umf.userid
 WHERE  umf.IsActive = 1 
 ORDER BY  
        umf.UserID,  
        umf.Source_EmailID,  
        umf.FilterName
        
select * from #temp
select * from #temp2
drop table #temp
drop table #temp2
End


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserMailsSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetUserMailsSetting --335,1,1  
	@ParentID BIGINT
	,@IsActive BIT
	,@isInActive BIT
AS
BEGIN
	SELECT ums.ID
		,ums.MailName
		,ums.EmailAddress
		,ums.IsActive
		,isnull(USS.IsEditable, 0) AS IsEditable
		,Ud.User_Login
	FROM UserMailsSettings AS ums(NOLOCK)
	LEFT JOIN User_Detail UD(NOLOCK) ON ums.CreatedBy = UD.User_ID
	LEFT JOIN UserSourceSettings AS USS(NOLOCK) ON ums.MailName = USS.Name
	WHERE ums.ParentID = @ParentID
		AND (
			ums.IsActive = CASE 
				WHEN @IsActive = 0
					THEN NULL
				ELSE @IsActive
				END
			OR ums.IsActive = CASE 
				WHEN @isInActive = 0
					THEN NULL
				ELSE 0
				END
			)
	ORDER BY ums.CreatedOn
		,ums.ModifiedOn DESC

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @parentid = @ParentID
		,@Activity_type = 'View_UsrMail_Sttng'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'UserMailsSettings'
END



GO

