/* ============================================================
   Procedure: [dbo].[usp_GetUserMailTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserMailTemplate] --26647 --335                      
 @ParentID BIGINT                      
AS                      
BEGIN                      
 SELECT umt.ID,                      
        umt.Name,                      
        umt.MailSubject,                      
        '' as MailContent,                      
        umt.IsSMS,                      
        umt.IsMail,        
        isnull(UMT.DLT_TemplateID,'') as DLT_TemplateID,                      
       --umt.CreatedOn,                  
        dbo.[fn_getusertimefromindiantime](@ParentID,umt.CreatedOn) as CreatedOn,        
                        
        umt.IsRTE,                      
        (                      
            CASE                       
                 WHEN IsLeads = 1 THEN 'Leads'                      
                 WHEN IsEnquiry = 1 THEN 'Enquiry'                      
                 WHEN IsGroup = 1 THEN 'Group'                      
                 WHEN IsList = 1 THEN 'List-ImportName:' + (                      
                          SELECT ImportName                      
                          FROM   UserImportedListColumn                      
                          WHERE  ID = umt.ListID                     
                      )                      
                 ELSE ''                      
            END                      
        )                 AS DynamicValuesFrom,                      
        UD.User_Login,                      
        (                      
            CASE                       
                 WHEN IsLeads = 1 THEN 'Leads'                      
                 WHEN IsEnquiry = 1 THEN 'Enquiry'                      
                 WHEN IsGroup = 1 THEN 'Groups'                      
                 WHEN IsList = 1 THEN 'List'                      
                 ELSE ''                      
            END                      
        )                 AS DynamicValues,                      
        (                      
            CASE                       
                 WHEN IsLeads = 1 THEN 'Leads'                      
                 WHEN IsEnquiry = 1 THEN 'Enquiry'                      
                 ELSE ''                      
            END                      
        )                 AS EnqorLeads,                      
        umt.ListID,                      
        uilc.ImportName   AS ListName,                      
        0                 AS GroupId,                
        umt.IsPersonalized,'a' as body_disp                
        , umt.IsNewMailBuilder 
	   
	   --CASE WHEN umt.IsPersonalized=1 THEN '1' ELSE '0' END AS IsPersonalized                      
 FROM   UserMailTemplate  AS umt(NOLOCK)                      
        LEFT JOIN User_Detail UD(NOLOCK)                      
             ON  umt.CreatedBy = UD.User_ID                      
        LEFT JOIN UserImportedListColumn AS uilc                      
             ON  uilc.ID = umt.ListID                      
 WHERE  umt.ParentID = @ParentID                     
 ORDER BY                      
