 @isSMS BIT,          
 @isMail BIT,  
 @Eventid BIGINT=''  
AS          
BEGIN     
begin try
 SELECT A.ID,          
        A.Name + ' ( ' + A.DynamicValuesFrom + ' )' AS NAME,          
 A.MailSubject,    
     A.MailContent,        
  A.MailTemplateURL        
 FROM   (          
            SELECT umt.ID,          
                   umt.Name,          
       umt.MailSubject,          
       umt.MailContent,          
       'https://www.kit19.com/UserCRMCampaign/UserMailTemplateView.aspx?ID=' + cast(umt.ID as varchar(50)) + '&U='+ cast(@ParentID as varchar(50))  MailTemplateURL,          
                   umt.CreatedOn,          
                   (          
                       CASE           
                            WHEN IsLeads = 1 THEN 'Leads'          
                            WHEN IsEnquiry = 1 THEN 'Enquiry'          
                            WHEN IsList = 1 THEN 'List-ImportName:' + (          
                                     SELECT ImportName          
                                     FROM   UserImportedListColumn          
                                     WHERE  ID = umt.ListID          
                                 )          
                            ELSE ''          
                       END          
                   )                 AS DynamicValuesFrom          
            FROM   UserMailTemplate  AS umt(NOLOCK)          
                   LEFT JOIN User_Detail UD(NOLOCK)          
                        ON  umt.CreatedBy = UD.User_ID          
            WHERE  umt.ParentID = @ParentID          
