/* ============================================================
   Procedure: [dbo].[usp_GetUserMailTemplateFilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserMailTemplateFilter] --26647 --335                      
	@ParentID BIGINT,
	@fromdate datetime = null,
	@todate datetime = null,
	@tempname varchar(max) = null
AS
BEGIN
	SELECT umt.ID
		,umt.Name
		,umt.MailSubject
		,'' AS MailContent
		,umt.IsSMS
		,umt.IsMail
		,isnull(UMT.DLT_TemplateID, '') AS DLT_TemplateID
		,
		--umt.CreatedOn,                  
		dbo.[fn_getusertimefromindiantime](@ParentID, umt.CreatedOn) AS CreatedOn
		,umt.IsRTE
		,(
			CASE 
				WHEN IsLeads = 1
					THEN 'Leads'
				WHEN IsEnquiry = 1
					THEN 'Enquiry'
				WHEN IsGroup = 1
					THEN 'Group'
				WHEN IsList = 1
					THEN 'List-ImportName:' + (
							SELECT ImportName
							FROM UserImportedListColumn
							WHERE ID = umt.ListID
							)
				ELSE ''
				END
			) AS DynamicValuesFrom
		,UD.User_Login
		,(
			CASE 
				WHEN IsLeads = 1
					THEN 'Leads'
				WHEN IsEnquiry = 1
					THEN 'Enquiry'
				WHEN IsGroup = 1
					THEN 'Groups'
				WHEN IsList = 1
					THEN 'List'
				ELSE ''
				END
			) AS DynamicValues
		,(
			CASE 
				WHEN IsLeads = 1
					THEN 'Leads'
				WHEN IsEnquiry = 1
					THEN 'Enquiry'
				ELSE ''
				END
			) AS EnqorLeads
		,umt.ListID
		,uilc.ImportName AS ListName
		,0 AS GroupId
		,umt.IsPersonalized
		,'a' AS body_disp
	--CASE WHEN umt.IsPersonalized=1 THEN '1' ELSE '0' END AS IsPersonalized                      
	FROM UserMailTemplate AS umt(NOLOCK)
	LEFT JOIN User_Detail UD(NOLOCK) ON umt.CreatedBy = UD.User_ID
	LEFT JOIN UserImportedListColumn AS uilc ON uilc.ID = umt.ListID
	WHERE umt.ParentID = @ParentID 
	AND (@fromdate IS NULL OR umt.CreatedOn >@fromdate) 
	AND (@todate IS NULL OR umt.CreatedOn <@todate)
	AND (@tempname IS NULL OR umt.Name LIKE '%'+@tempname+'%')
	ORDER BY umt.CreatedOn DESC
END



GO

