CREATE   PROCEDURE [dbo].[usp_GetUserName_By_Id] (    
 @ID bigINT     
)  
as                    
begin                 
                
begin try                
                
begin transaction                
  
--Declare @Name varchar(150) = 'anim'  
  
select User_Id, (FName + ' ' + LName) as [Name]  from User_Detail(nolock)  
