/* ============================================================
   Procedure: [dbo].[usp_GetUserNamekit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetUserNamekit19]  
AS  
BEGIN  
 SELECT distinct  ud.[User_ID],  
        ud.FName + ' ' + ud.LName + ' ( ' + uf.Name + ' )' AS [NAME]  
 FROM   User_Detail             AS ud  
        INNER JOIN User_Filter  AS uf  
             ON  uf.Code = ud.userfilter  
 WHERE  ISNULL(ud.FName, '') <> ''  
        AND ISNULL(uf.Code, '') <> ''  
        AND ISNULL(ud.LName, '') <> ''  
        AND ud.[Status] = 1  
 ORDER BY  
        ud.FName + ' ' + ud.LName + ' ( ' + uf.Name + ' )'
END  


GO

