BEGIN            
SELECT  a.FilterID as id,b.name,b.FromEmail,  ( CASE             
                        WHEN b.IsActive = 1 THEN 'ACTIVE'            
                        ELSE 'IN-ACTIVE'            
                   END   ) as Status                   
FROM UserPreDefineMailsParsing a       
INNER JOIN UserPreDefineMailsFilters b      
on a.FilterID=b.id       
--WHERE  b.ParentID = @ParentID           
 GROUP BY a.FilterID,b.Name,b.FromEmail,b.IsActive      
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserPriority]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************  
SP_Name        : [usp_GetUserPriority]                     
Author         : Mukesh 
Created ON     : 25/12/2009 04:30 PM        
Version        : 1  
Alter BY       :          
Alter Date    :   
Location       : PELSOFT  
SP Description : This SP is Used to SELECT  Records From MessageStorage
         
****************************************************************************/ 
    
CREATE   PROC [dbo].[usp_GetUserPriority]      
@UserId int                                                       
As  
Begin  
SET NOCOUNT ON  
select distinct u_id as user_id,u_id as User_LOGIN,  
 CASE  
    WHEN priority=1   
     THEN 'H'  
    WHEN priority=2  
    THEN 'N'       
   ELSE 'L'  
     END as priority  
 from MessageStorage WITH(NOLOCK) where U_ID=@UserId    
End  
  



GO

/* ============================================================
   Procedure: [dbo].[usp_getuserreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_getuserreport (@parentid BIGINT)
AS
BEGIN
	IF EXISTS (
			SELECT 1
			FROM userreport(NOLOCK)
			WHERE Reportdate = dateadd(d, - 1, cast(getdate() AS DATE))
			)
	BEGIN
		SELECT *
		FROM userreport(NOLOCK)
		WHERE parentid = @parentid
	END
	ELSE
	BEGIN
		DECLARE @fromdate NVARCHAR(20) = convert(VARCHAR, dateadd(d, - 1, cast(getdate() AS DATE)), 104)

		EXEC usp_dailyagentreportallusers '0'
			,@fromdate

		SELECT *
		FROM userreport(NOLOCK)
		WHERE parentid = @parentid
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @parentid = @parentid
		,@Activity_type = 'View_usr_Rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'userreport'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_getuserreport_DateWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getuserreport_DateWise] --34594, '09-Sep-2023'       
(  
   @parentid BIGINT,  
   @ReportDate nvarchar(50) = null  
)        
AS        
BEGIN       
      
 Declare @ReportDateSql date = dateadd(d, - 1, cast(getdate() AS DATE));    
  
 if(@ReportDate is not null and @ReportDate != '')  
   begin  
     set  @ReportDateSql = cast(@ReportDate AS DATE);              
   end  
     
  if(@ReportDateSql >= cast(getdate() as date))  
    begin  
     set  @ReportDateSql = dateadd(d, - 1, cast(getdate() AS DATE));    
    end  
  
  
  
    declare @IsAdmin bit = 0      
 declare @ParentMain bigint = (select top 1 isnull(ParentID,0) from user_detail with(nolock) where user_id = @ParentID )      
      
   SELECT @IsAdmin = isnull(IsAdmin, 0)          
 FROM User_Detail(NOLOCK)          
 WHERE User_ID = @ParentID          
           
  DECLARE @tbluser TABLE (          
  User_ID BIGINT          
  ,Name VARCHAR(100)          
  ,IMAGE VARCHAR(100)          
  )        
      
   DECLARE @UserIdTeamLst VARCHAR(Max) = ''        
      
 IF (@IsAdmin = 1)          
 BEGIN          
   INSERT INTO @tbluser          
   EXEC Use_GetUserDetails @ParentMain          
 END          
 ELSE          
 BEGIN          
  INSERT INTO @tbluser          
  EXEC Use_GetUserDetails @parentid          
 END          
          
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')          
 FROM @tbluser                 
         
if( @ReportDateSql = dateadd(d, - 1, cast(getdate() AS DATE)))   
 begin  
  
      
 IF EXISTS (        
   SELECT 1        
   FROM userreport(NOLOCK)        
   WHERE Reportdate = dateadd(d, - 1, cast(getdate() AS DATE))        
   )        
 BEGIN 
 
  DECLARE @fromdate_M NVARCHAR(20) = convert(VARCHAR, dateadd(d, - 1, cast(getdate() AS DATE)), 104)        
        
  EXEC [usp_dailyagentreportallusers_revised] @UserIdTeamLst        
   ,@fromdate_M        
  
  SELECT m1.*, ud.FName + ' ' + ud.LName as Name        
  FROM userreport(NOLOCK) as m1     
  join user_detail(nolock) as ud    
    on m1.user_id = ud.User_ID    
  WHERE --Reportdate = @ReportDateSql 
        --  and    
        m1.parentid = @ParentMain        
          and      
        1 =       
         case when @Isadmin = 1      
               then  1      
         when m1.user_id  in (select User_Id from  @tbluser)      
           then 1      
         else 0      
        end        
 END        
 ELSE        
 BEGIN        
  DECLARE @fromdate NVARCHAR(20) = convert(VARCHAR, dateadd(d, - 1, cast(getdate() AS DATE)), 104)        
        
  EXEC [usp_dailyagentreportallusers_revised] @UserIdTeamLst        
   ,@fromdate        
        
  SELECT m1.*, ud.FName + ' ' + ud.LName as Name        
  FROM userreport(NOLOCK) as m1    
       join user_detail(nolock) as ud    
    on m1.user_id = ud.User_ID     
  WHERE      
       m1.parentid = @ParentMain      
         and      
      1 =       
         case when @Isadmin = 1      
               then  1      
       when m1.user_id  in (select User_Id from  @tbluser)      
          then 1      
   else 0      
  end        
 END        
  
  
 End  -- end of yesterday  
else -- before yesterday  
 Begin  
    IF EXISTS (        
   SELECT 1        
   FROM userreport_Archived(NOLOCK)        
   WHERE Reportdate = @ReportDateSql        
   )   
   begin
   
   -- DECLARE @fromdateTemp_M NVARCHAR(20) = convert(VARCHAR,cast(@ReportDateSql AS DATE), 104)        
  
  --EXEC [usp_dailyagentreportallusers_revisedForArchivedOnly] @UserIdTeamLst        
    --       ,@fromdateTemp_M     
 
 SELECT m1.*, ud.FName + ' ' + ud.LName as Name        
  FROM userreport_Archived(NOLOCK) as m1     
  join user_detail(nolock) as ud    
    on m1.user_id = ud.User_ID    
  WHERE m1.parentid = @ParentMain  and  Reportdate = @ReportDateSql       
          and      
      1 =       
         case when @Isadmin = 1      
               then  1      
       when m1.user_id  in (select User_Id from  @tbluser)      
          then 1      
     else 0      
    end   
 end -- not exists in archived   
  else  
     begin  
       
  DECLARE @fromdateTemp NVARCHAR(20) = convert(VARCHAR,cast(@ReportDateSql AS DATE), 104)        
  
  EXEC [usp_dailyagentreportallusers_revisedForArchivedOnly] @UserIdTeamLst        
           ,@fromdateTemp     
       
         SELECT m1.*, ud.FName + ' ' + ud.LName as Name        
    FROM userreport_Archived(NOLOCK) as m1     
    join user_detail(nolock) as ud    
   on m1.user_id = ud.User_ID    
    WHERE m1.parentid = @ParentMain  and  Reportdate = @ReportDateSql       
      and      
     1 =       
     case when @Isadmin = 1      
        then  1      
      when m1.user_id  in (select User_Id from  @tbluser)      
      then 1      
    else 0      
   end    
            
  
  end  
  
  
 End -- from archived  
  
        
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @parentid = @parentid        
  ,@Activity_type = 'View_usr_Rpt'        
  ,@ActionType = 'S'        
  ,@RowJson = ''        
  ,@Table_name = 'userreport'        
END 


GO

