/* ============================================================
   Procedure: [dbo].[usp_getuserreportbyauthid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getuserreportbyauthid] --'a',1
 (@authid nvarchar(200),@id int)
 as
 begin
 declare @parentid bigint
 select @parentid=parentid from userreport(nolock) where authid=@authid and id=@id
 if @parentid is not null
 begin
 if exists(select 1 from userreport(nolock) where Reportdate=dateadd(d,-1,cast(getdate() as date)))
 begin
 select * from userreport(nolock) where parentid=@parentid
 end
 else
 begin
 declare @fromdate nvarchar(20)=convert(varchar,dateadd(d,-1,cast(getdate() as date)),104)
 exec usp_dailyagentreportallusers '0',@fromdate 
 select * from userreport(nolock) where parentid=@parentid
 end
 end
 else
 begin
 Select 'Unauthorized request' as Status
 end
 end


GO

