 WHERE User_ID = @ParentID      
       
  DECLARE @tbluser TABLE (      
  User_ID BIGINT      
  ,Name VARCHAR(100)      
  ,IMAGE VARCHAR(100)      
  )    
  
   DECLARE @UserIdTeamLst VARCHAR(Max) = ''    
  
 IF (@IsAdmin = 1)      
 BEGIN      
   INSERT INTO @tbluser      
   EXEC Use_GetUserDetails @parentid      
 END      
 ELSE      
 BEGIN      
  INSERT INTO @tbluser      
  EXEC Use_GetUserDetails @UserID      
 END    
  
  SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')      
 FROM @tbluser   
   
 if @parentid is not null    
 begin    
 if exists(select 1 from userreport(nolock) where Reportdate=dateadd(d,-1,cast(getdate() as date)))    
 begin    
 select m1.*, ud.FName + ' ' + ud.LName as Name from userreport(nolock) as m1  
      join user_detail(nolock) as ud
	   on m1.user_id = ud.User_ID

     where m1.parentid=@parentid    
          and  
    1 =   
         case when @Isadmin = 1  
               then  1  
       when m1.user_id  in (select User_Id from  @tbluser)  
          then 1  
   else 0  
  end     
   
 end    
 else    
 begin    
 declare @fromdate nvarchar(20)=convert(varchar,dateadd(d,-1,cast(getdate() as date)),104)    
 exec [usp_dailyagentreportallusers_revised] @UserIdTeamLst,@fromdate     
 select m1.*, ud.FName + ' ' + ud.LName as Name from userreport(nolock) as m1 
        join user_detail(nolock) as ud
	   on m1.user_id = ud.User_ID
 where   
      m1.parentid=@parentid  
    and   
    1 =   
         case when @Isadmin = 1  
               then  1  
       when m1.user_id  in (select User_Id from  @tbluser)  
          then 1  
   else 0  
  end    
 end    
 end    
 else    
 begin    
 Select 'Unauthorized request' as Status    
 end    
 end


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserReportDataByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetUserReportDataByParentId
@ParentId bigint
AS
BEGIN 
    BEGIN TRY
    SET NOCOUNT ON;

    -- Join the main userreport table with user_detail and filter by conditions
    SELECT 
        u.*
       -- d.Status
    FROM userreport u WITH (NOLOCK)
    JOIN user_detail d ON u.user_id = d.user_id
    --JOIN DistinctParentIds dp ON u.ParentId = dp.ParentId
    WHERE u.parentid=@ParentId and d.Status = 1
      AND u.ReportDate = CAST(DATEADD(DAY, -1, GETDATE()) AS DATE);

 END TRY

    -- Begin CATCH block to handle errors
    BEGIN CATCH
        exec usp_InsertErrorInfo   
    END CATCH;
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserReportDataByParentId_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserReportDataByParentId_1]    
 @ParentId bigint    
AS    
BEGIN     
    BEGIN TRY    
    SET NOCOUNT ON;    
    
   select d.user_login,TotalOutBoundCallsToday  
,TotalOutBoundCallsThisMonth  
,TotalInboundToday  
,TotalInboundThisMonth  
,[CallPeriodToday(InMins)]  
,[CallPeriodThisMonth(InMins)]  
,TotalLeads  
,FollowUpsOverDue  
,FollowupsDoneToday  
,ClosuresToday  
,AmountClosedToday  
,FollowupsDoneThisMonth  
,ClosuresThisMonth  
,AmountClosedThisMonth  
,TaskOverDue  
,TasksCompletedToday  
,TasksCompletedthismonth  
,Reportdate  
,TotalEnquiriesAddedToday  
,TotalEnquiriesAddedThismonth  
,TotalLeadsAddedToday  
,TotalLeadsAddedThisMonth  
,TasksCreatedToday  
,TasksCreatedThisMonth  
,AppointmentsCreatedToday  
,AppointmentsCreatedThisMonth  
,AppointmentsOverDue  
,AppointmentsCompletedToday  
,AppointmentsCompletedthismonth  
,NewPipelineCasesAddedToday  
,NewPipelineCasesAddedThisMonth  
,PipelineMovedToday  
,PipelineMovedThisMonth  
,PipelineCasesWonToday  
,PipelineCasesWonThisMonth  
,PipelineCasesExpiredToday  
,PipelineCasesExpiringThisMonth  
,PipelineCasesLostToday  
,PipelineCasesLostThisMonth  
,TotalCallsMissedToday  
,TotalCallsMissedThisMonth from userreport(nolock) u join     
   user_detail d on u.user_id=d.user_id where u.parentid=@ParentId and     
   d.Status=1  and u.reportdate=cast(dateadd(d,-1,getdate()) as date)    
    
 END TRY    
    
    -- Begin CATCH block to handle errors    
    BEGIN CATCH    
        exec usp_InsertErrorInfo       
    END CATCH;    
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUsers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUsers]
	@ParentID BIGINT
AS
BEGIN
	SELECT DISTINCT UD.User_Login  AS NAME
	FROM   UserMailTemplate        AS umt(NOLOCK)
	       LEFT JOIN User_Detail UD(NOLOCK)
	            ON  umt.CreatedBy = UD.User_ID
	WHERE  umt.ParentID = @ParentID
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUsers_GroupDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUsers_GroupDetails] --335
	@ParentID BIGINT
AS
BEGIN
	SELECT DISTINCT ud.User_Login    AS NAME
	FROM   UserTemplateGroupDetails  AS utgd
	       LEFT JOIN User_Detail     AS ud
	            ON  ud.[User_ID] = utgd.CreatedBy
	WHERE  utgd.ParentID = @ParentID
END



GO

