@M_ID varchar(50)=10001,                
@user_id nvarchar(50)=3573,                
@usertype varchar(10)='All',        
@AC_Type varchar(50),              
@pageindex int=1,                        
@pagesize int=10                
AS                
BEGIN                
declare @rid varchar(20),@query varchar(2000),@query2 varchar(2000)                  
Declare @whereClase varchar(1000)       
--declare @AC_Type varchar(50)      
--set @AC_Type =''           
set  @whereClase=''              
if (@usertype='All')              
Begin              
set  @whereClase=@whereClase +' 1=1 and  '              
End              
Else              
Begin              
set  @whereClase=@whereClase +' ud.type='''+ @usertype +'''and  '              
end        
--code added by ajay        
 if(@AC_Type='')        
begin        
 set  @whereClase=@whereClase +'  1=1 '              
end        
else        
begin        
 set  @whereClase=@whereClase +'  ud.userfilter='''+@AC_Type+'''  '              
        
end        
 --end             
              
set @rid=(select reseller_id from reseller_detail where m_id=@m_id and user_id=@user_id)               
--code added by raghwendra              
create  table #TempTableNew               
(              
user_id bigint,              
credit_id bigint              
)              
insert into #TempTableNew(credit_id,user_id)              
select max(credit_id) as credit_id,user_id from credit_details where m_id=@rid   group by user_id               
            
--End code                       
                
declare @TempTable1 table                          
(                          
 Id int  identity(1,1),                          
 m_id  varchar(50),                          
 user_id varchar(50),                          
 [type] varchar(50),                          
 Status varchar(50),                          
 user_login varchar(50),                          
 Pwd varchar(50),                          
 mobile float,                          
 email varchar(50),                          
 city varchar(50),        
 userfilter varchar(50),                    
 Domain varchar(50)                          
)                          
                      
--insert into @TempTable1(m_id,user_id,[type],Status,user_login,Pwd,mobile,email,city,Domain)                
set @query='Select ud.m_id,ud.user_id,ud.[type],ud.status,ud.user_login,ud.Pwd,ud.mobile,ud.email,ud.city,(case ud.userfilter when ''MT'' then ''MOMT'' when ''ON'' then ''Transactional'' when ''TRANS'' then ''Transactional''   
when ''OPEN'' then ''OPEN DND'' when ''MTIX_TR'' then ''MTransactional'' when ''MTIX_TRC'' then ''MTRC'' else ''Promotional'' end) as userfilter,rd.Domain             
  
    
From user_detail ud                                   
Left join reseller_detail rd                 
On ud.m_id=rd.m_id and ud.user_id=rd.user_id                                             
Where ud.User_id in (Select [User_ID] From ( select cd.M_ID,cd.User_ID as User_ID from #TempTableNew tmp join credit_details cd on tmp.credit_id=cd.credit_id where cd.balance<=5000) G ) and '+@whereClase+''              
insert into @TempTable1(m_id,user_id,[type],Status,user_login,Pwd,mobile,email,city,userfilter,Domain)                
exec (@query)              
Select count(id)from @TempTable1             
--select * from @TempTable1            
              
