)                         
set @query2='Select ud.m_id,ud.user_id,ud.[type],ud.status,ud.user_login,ud.Pwd,ud.mobile,ud.email,ud.city,(case ud.userfilter when ''MT'' then ''MOMT'' when ''ON'' then ''Transactional'' when ''TRANS'' then ''Transactional''   
when ''OPEN'' then ''OPEN DND'' when ''MTIX_TR'' then ''MTransactional'' when ''MTIX_TRC'' then ''MTRC'' end) as userfilter,rd.Domain From user_detail ud Left join reseller_detail rd                 
On ud.m_id=rd.m_id and ud.user_id=rd.user_id                                             
Where ud.User_id in (Select [User_ID] From ( select cd.M_ID,cd.User_ID as User_ID from #TempTableNew tmp join credit_details cd on tmp.credit_id=cd.credit_id where cd.balance<=5000) G ) and  '+ @whereClase+ ''              
insert into @TempTable(m_id,user_id,[type],Status,user_login,Pwd,mobile,email,city,userfilter,Domain)                 
