 Pwd varchar(50),                          
 mobile float,                          
 email varchar(50),                          
 city varchar(50),        
 userfilter varchar(50),                          
                          
 Domain varchar(50),              
  BALANCE nvarchar(300)                        
)                
              
insert into  @TempTableFinal(m_id,user_id,type,Status,user_login,Pwd,mobile,email,city,userfilter,Domain,BALANCE)                  
SELECT TMP.m_id,TMP.user_id,TMP.type,TMP.Status,TMP.user_login,TMP.Pwd,TMP.mobile,TMP.email,TMP.city,TMP.userfilter,TMP.Domain,cd.BALANCE               
FROM @TempTable  TMP              
JOIN               
#TempTableNew  tmpN              
ON              
TMP.USER_ID =tmpN.USER_ID join               
credit_details cd on tmpN.credit_id=cd.credit_id              
--select * from @TempTableFinal            
---- [USP_GetUsersBalanceInfo] 10001,335,'All',1,100                
            
            
select * from (SELECT  *, ROW_NUMBER()   OVER(ORDER BY Id ASC) AS rownum from @TempTableFinal) as TempTable                
