/* ============================================================
   Procedure: [dbo].[usp_GetUserSchedules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetUserSchedules --335,1,0
	@ParentID BIGINT
	,@IsActive BIT
	,@isInActive BIT
AS
BEGIN
	SELECT us.ID
		,us.SceduleName
		,CASE 
			WHEN us.IsOnce = 1
				THEN 'Once at ' + CAST(us.OnceHours AS VARCHAR(50)) + ':' + CAST(us.OnceMins AS VARCHAR(50))
			ELSE ''
			END + CASE 
			WHEN us.IsDaily = 1
				THEN 'Daily at ' + CAST(us.DailyHours AS VARCHAR(50)) + ':' + CAST(us.DailyMins AS VARCHAR(50))
			ELSE ''
			END + CASE 
			WHEN us.IsWeekly = 1
				THEN 'Weekly at Day No(s)  ' + REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(us.WeeklyDayNo, '#', ', '), '1', 'Sunday'), '2', 'Monday'), '3', 'Tuesday'), '4', 'Wednesday'), '5', 'Thursday'), '6', 'Friday'), '7', 'Saturday') + ' at ' + CAST(us.WeeklyHours AS VARCHAR(50)) + '  :' + CAST(us.WeeklyMins AS VARCHAR(50))
			ELSE ''
			END + CASE 
			WHEN us.IsMonthly = 1
				THEN 'Monthly in ' + ISNULL(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(us.MonthNo, '#', ', '), '10', 'October'), '11', 'November'), '12', 'December'), '1', 'January'), '2', 'February'), '3', 'March'), '4', 'April'), '5', 'May'), '6', 'June'), '7', 'July'), '8', 'August'), '9', 'September'), '') + ' at Day No(s)  ' + ISNULL(REPLACE(us.MonthlyDayNo, '#', ', '), '') + ' at ' + CAST(us.MonthlyHours AS VARCHAR(50)) + '  :' + CAST(us.MonthlyMins AS VARCHAR(50))
			ELSE ''
			END AS Schedules
		,us.IsActive
		,us.IsOnce
		,us.OnceHours
		,us.OnceMins
		,us.IsDaily
		,us.DailyHours
		,us.DailyMins
		,us.IsWeekly
		,us.WeeklyDayNo
		,us.WeeklyHours
		,us.WeeklyMins
		,us.IsMonthly
		,us.MonthlyHours
		,us.MonthlyMins
		,us.MonthlyDayNo
		,ud.User_Login
	FROM UserSchedules AS us(NOLOCK)
	LEFT JOIN User_Detail UD(NOLOCK) ON us.CreatedBy = UD.User_ID
	WHERE us.ParentID = @ParentID
		AND (
			us.IsActive = CASE 
				WHEN @IsActive = 1
					THEN 1
				ELSE NULL
				END
			OR us.IsActive = CASE 
				WHEN @isInActive = 1
					THEN 0
				ELSE NULL
				END
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
		,@Activity_type = 'View_Cmpgn_Schdls '
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'UserSchedules'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserSchedulesBind]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserSchedulesBind] --335,1,0
	@ParentID BIGINT
AS
BEGIN
	SELECT A.ID,
	       A.SceduleName + ' ( ' + REPLACE (A.Schedules, '#', ', ') + ' )' AS 
	       SceduleName
	FROM   (
	           SELECT us.ID,
	                  us.SceduleName,
	                  CASE 
	            WHEN us.IsOnce = 1 THEN 'Once at ' +
	                 
	                 CAST(us.OnceHours AS VARCHAR(50)) + ':' +
	                 
	                 CAST(us.OnceMins AS VARCHAR(50))
	            ELSE ''
	       END + CASE 
	                  WHEN us.IsDaily = 1 THEN 'Daily at ' +
	                       
	                       CAST(us.DailyHours AS VARCHAR(50)) + ':' +
	                       
	                       CAST(us.DailyMins AS VARCHAR(50))
	                  ELSE ''
	             END + CASE 
	                        WHEN us.IsWeekly = 1 THEN 'Weekly at Day No(s)  ' +
	                             
	                             REPLACE(
	                                 REPLACE(
	                                     REPLACE(
	                                         REPLACE(
	                                             REPLACE(
	                                                 REPLACE(
	                                                     REPLACE(REPLACE(us.WeeklyDayNo, '#', ', '), '1', 'Sunday'),
	                                                     '2',
	                                                     'Monday'
	                                                 ),
	                                                 '3',
	                                                 'Tuesday'
	                                             ),
	                                             '4',
	                                             'Wednesday'
	                                         ),
	                                         '5',
	                                         'Thursday'
	                                     ),
	                                     '6',
	                                     'Friday'
	                                 ),
	                                 '7',
	                                 'Saturday'
	                             ) + ' at ' +
	                             
	                             CAST(us.WeeklyHours AS VARCHAR(50)) + '  :' +
	                             
	                             CAST(us.WeeklyMins AS VARCHAR(50))
	                        ELSE ''
	                   END + CASE 
	                              WHEN us.IsMonthly = 1 THEN 'Monthly in ' +
	                                   ISNULL(
	                                       REPLACE(
	                                           REPLACE(
	                                               REPLACE(
	                                                   REPLACE(
	                                                       REPLACE(
	                                                           REPLACE(
	                                                               REPLACE(
	                                                                   REPLACE(
	                                                                       REPLACE(
	                                                                           REPLACE(
	                                                                               REPLACE(
	                                                                                   REPLACE(REPLACE(us.MonthNo, '#', ', '), '1', 'January'),
	                                                                                   '2',
	                                                                                   'February'
	                                                                               ),
	                                                                               '3',
	                                                                               'March'
	                                                                           ),
	                                                                           '4',
	                                                                           'April'
	                                                                       ),
	                                                                       '5',
	                                                                       'May'
	                                                                   ),
	                                                                   '6',
	                                                                   'June'
	                                                               ),
	                                                               '7',
	                                                               'July'
	                                                           ),
	                                                           '8',
	                                                           'August'
	                                                       ),
	                                                       '9',
	                                                       'September'
	                                                   ),
	                                                   '10',
	                                                   'October'
	                                               ),
	                                               '11',
	                                               'November'
	                                           ),
	                                           '12',
	                                           'December'
	                                       ),
	                                       ''
	                                   )
	                                   +
	                                   ' at Day No(s)  ' +
	                                   
	                                   ISNULL(REPLACE(us.MonthlyDayNo, '#', ', '), '') 
	                                   + ' at ' +
	                                   
	                                   CAST(us.MonthlyHours AS VARCHAR(50)) +
	                                   '  :' +
	                                   
	                                   CAST(us.MonthlyMins AS VARCHAR(50))
	                              ELSE ''
	                         END  AS Schedules
	           FROM   UserSchedules AS us(NOLOCK)
	           WHERE  us.ParentID = @ParentID
	                  AND us.IsActive = 1
	       ) A
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserSchedulesByID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserSchedulesByID] --335,1,0
	@ID BIGINT
AS
BEGIN
	SELECT us.ID,
	       us.SceduleName,
	       us.IsOnce,
	       us.OnceHours,
	       us.OnceMins,
	       us.IsDaily,
	       us.DailyHours,
	       us.DailyMins,
	       us.IsWeekly,
	       us.WeeklyDayNo,
	       us.WeeklyHours,
	       us.WeeklyMins,
	       us.IsMonthly,
	       us.MonthlyHours,
	       us.MonthlyMins,
	       us.MonthNo,
	       us.MonthlyDayNo
	FROM   UserSchedules AS us
	WHERE  ID = @ID
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserSearchList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserSearchList]  --335,1,1,1,1,1            
 @ParentID BIGINT,              
 @IsPredefined BIT,              
 @IsResponse BIT,              
 @IsUnsubscribe BIT,              
 @IsSearch BIT,              
 @IsCustom BIT              
AS              
BEGIN              
 SELECT A.ID,              
        A.SearchName,              
        A.SearchTyp,              
        (  case when A.IsGroup = 1        
              then         
                  CASE               
                       WHEN ISNULL(A.NameGRP, '') <> '' THEN               
                            '<p><b>Name(Group):</b> '               
                                          
                            + A.NameGRP + '</p>'              
                       ELSE ''              
                  END        
                  +        
                 CASE               
                       WHEN ISNULL(A.CompanyGRP, '') <> '' THEN               
                            '<p><b>Company(Group):</b> '               
                                          
                            + A.CompanyGRP + '</p>'              
                       ELSE ''              
                 END        
                  +        
                 CASE               
                       WHEN ISNULL(A.MobileGRP, '') <> '' THEN               
                            '<p><b>Mobile(Group):</b> '               
                                          
                            + A.MobileGRP + '</p>'              
                       ELSE ''              
                 END        
                  +        
                 CASE               
                       WHEN ISNULL(A.EmailGRP, '') <> '' THEN               
                            '<p><b>Email(Group):</b> '               
                                          
                            + A.EmailGRP + '</p>'              
                       ELSE ''              
                 END        
                          
                  +        
                 CASE               
                       WHEN ISNULL(A.CityGRP, '') <> '' THEN               
                            '<p><b>City(Group):</b> '               
                                          
                            + A.CityGRP + '</p>'              
                       ELSE ''              
                 END        
                         
                  +        
                 CASE               
                       WHEN ISNULL(A.StateGRP, '') <> '' THEN               
                            '<p><b>State(Group):</b> '               
                                          
                            + A.StateGRP + '</p>'              
                       ELSE ''              
                 END        
                         
                  +        
                 CASE               
                       WHEN ISNULL(A.CountryGRP, '') <> '' THEN               
                            '<p><b>Country(Group):</b> '               
                                          
                            + A.CountryGRP + '</p>'              
                       ELSE ''              
                 END        
                         
                  +        
                 CASE               
                       WHEN ISNULL(A.AddressGRP, '') <> '' THEN               
                            '<p><b>Address(Group):</b> '               
                                          
                            + A.AddressGRP + '</p>'              
                       ELSE ''              
                 END        
                                           
                         
              else ''             
           end         
                   
           +           
            CASE               
                 WHEN ISNULL(A.SearchType, '') <> '' THEN               
                      '<p><b>Search Type:</b> ' + A.SearchType + '</p>'              
     ELSE ''              
            END + CASE               
                       WHEN ISNULL(A.Medium, '') <> '' THEN               
                            '<p><b>Medium:</b> '               
                                   
                            + A.Medium + '</p>'              
       ELSE ''              
                  END + CASE               
                             WHEN ISNULL(A.Source, '') <> '' THEN               
                                  '<p><b>Source:</b> ' + A.Source + '</p>'              
                             ELSE ''              
                        END + CASE               
                                   WHEN ISNULL(A.Campaign, '') <> '' THEN               
                                        '<p><b>Campaign:</b> ' + A.Campaign +              
                                                      
                                        '</p>'              
                                   ELSE ''              
                              END + CASE               
                                         WHEN ISNULL(A.SpecificName, '') <>              
                                                            
                                              '' THEN '<p><b>Name:</b> ' + A.SpecificName               
                                                            
                                              + '</p>'              
                                         ELSE ''              
                                    END + CASE               
                                               WHEN ISNULL(A.SpecificAddress, '')               
                                                                  
                                                    <> '' THEN               
                                                    '<p><b>Address:</b> ' + A.SpecificAddress               
                                                                  
                                                    + '</p>'              
                                               ELSE ''              
                                          END + CASE               
                                                     WHEN ISNULL(A.SpecificMobileNo, '')               
                                                                        
                                                          <> '' THEN               
                                                          '<p><b>Mobile No:</b> '               
                                                                        
                                                          + A.SpecificMobileNo               
                                                                        
                                                          +              
                                                                        
                                                          '</p>'              
                                                     ELSE ''              
                                                END + CASE               
                                                           WHEN ISNULL(A.SpecificEmail, '')               
                                                                              
                                                                <> '' THEN               
                                                                '<p><b>Email:</b> '               
                                                                              
                                                                + A.SpecificEmail               
                                                                              
                                                                + '</p>'              
                                         ELSE ''              
                                                      END + CASE               
                     WHEN ISNULL(A.SpecificCity, '')               
                      
                                                                      <> '' THEN               
                                                                      '<p><b> City:</b> '               
                                                              
                                                                      + A.SpecificCity               
                                         
                                                                      +              
                                                                                    
                                                                      '</p>'              
                                     ELSE ''              
                                                            END + CASE               
                                                                       WHEN               
                                                                            ISNULL(A.SpecificState, '')               
                                                                                          
                                                                            <              
                                                                                          
                                                                            >              
                                                                                          
                                                                            '' THEN               
                                                                            '<p><b>State:</b> '               
                                                                                          
                                                                            +              
                                                                                          
                                                                            A.SpecificState               
                                                                                          
                                                                            +              
                                                                                          
                                                                            '</p>'              
                                                                       ELSE               
                                                                            ''              
                                                                  END + CASE               
                                                                             WHEN               
                                                                                  ISNULL(A.SpecificCountry, '')               
                                                                                                
                                                                                  <              
                                                                                                
                                                                                  >              
                                                                                                
                                                                                  '' THEN               
                                                                                  '<p><b>Country:</b> '               
                                                                                                
                                                                                  +              
                                                                                                
                                                                            A.SpecificCountry               
                                                                                       
                                                                                  +              
                                             
                                           '</p>'              
                          ELSE               
                                                                                  ''              
                       END + CASE               
                                                                                   WHEN               
                                                                                        ISNULL(A.CurrentlyAssignedTo, '')               
                                                                                                      
                                                                                      <              
                                                                                                      
                                                                                        >              
                                                                                                      
                                                                                        '' THEN               
                                                                                        '<p><b>Assigned To:</b> '               
                                                                                                      
                                                                                        +              
                                                                                                      
                                                                                        A.CurrentlyAssignedTo               
                                                                                                      
                                                                                        +              
                                                                                                      
                                                                                        '</p>'              
                                                                                   ELSE               
                                                                                        ''              
                                                                              END               
                          
            + CASE               
                   WHEN ISNULL(A.FollowUpStatus, '')               
                                      
                        <              
                                      
                        >              
                                      
                        '' THEN '<p><b>FollowUp Status:</b> '               
                                      
                        +              
                                      
                        A.FollowUpStatus               
                                      
                        +              
                                      
                        '</p>'              
                   ELSE ''              
              END + CASE               
                         WHEN ISNULL(A.CreatedBetweenFrom, '')               
                                            
                              <              
                                            
                              >              
                                            
                              ''              
            AND ISNULL(A.CreatedBetweenTo, '')               
                              
                <              
                        
                >              
                              
                '' THEN '<p><b>Created Between:</b> '               
                              
                +              
                              
                A.CreatedBetweenFrom + ' - ' + A.CreatedBetweenTo               
                              
                +              
                              
                '</p>'               
               
                ELSE ''               
                              
                END + CASE               
                        WHEN ISNULL(A.NextFollowUpDateFrom, '')               
                                              
                                <              
                                              
                 >              
                                              
                                ''              
            AND ISNULL(A.NextFollowUpDateTo, '')               
                              
                <              
                              
                >              
                              
                '' THEN '<p><b>Next FollowUp Days:</b> '               
                              
                +              
                              
                A.NextFollowUpDateFrom + ' - ' + A.NextFollowUpDateTo               
                             
                +              
                              
                '</p>'               
                              
                ELSE ''               
                              
                END + CASE               
                           WHEN ISNULL(A.ConvertedWithinFrom, '')               
                                              
                                <              
                                              
                                >              
                                              
                                ''              
            AND ISNULL(A.ConvertedWithinTo, '')               
                              
                <              
                              
                >              
                              
                '' THEN '<p><b>Converted With-in:</b> '               
                              
                +              
                              
                A.ConvertedWithinFrom + ' - ' + A.ConvertedWithinTo               
                              
                +              
                              
                '</p>'               
                              
                ELSE ''               
                              
                END +            
                          
                CASE               
                           WHEN ISNULL(A.NextFollowUpDaysFrom, '')               
                                              
                                <              
                                              
                                >              
                                              
                                ''              
            AND ISNULL(A.NextFollowUpDaysTo, '')               
                              
                <              
                              
                >              
                              
                '' THEN '<p><b>Followup Days within:</b> '               
                              
                +              
                              
                A.NextFollowUpDaysFrom + ' - ' + A.NextFollowUpDaysTo               
                              
                +              
                              
                '</p>'               
                              
                ELSE ''               
                              
                END          
                          
                  +            
                          
                CASE               
       WHEN ISNULL(A.BirthBetweenFromGRP, '')               
                                              
                                <              
                                              
                                >              
                                              
                                ''              
            AND ISNULL(A.BirthBetweenToGRP, '')               
                              
                <              
                              
                >              
                              
                '' THEN '<p><b>Birth Days within(Group):</b> '               
     
                +              
                              
                A.BirthBetweenFromGRP + ' - ' + A.BirthBetweenToGRP               
                              
                +              
                              
                '</p>'               
                              
                ELSE ''               
                              
                END          
                          
                  +            
                          
                CASE               
                           WHEN ISNULL(A.ANVBetweenFromGRP, '')               
                                              
                                <              
                                              
                                >              
                                              
                                ''              
            AND ISNULL(A.ANVBetweenToGRP, '')               
                              
                <              
                              
                >              
                              
                '' THEN '<p><b>Anniversary Days within(Group):</b> '               
                              
                +              
                              
                A.ANVBetweenFromGRP + ' - ' + A.ANVBetweenToGRP               
                              
                +              
              
                '</p>'               
                              
                ELSE ''               
                              
                END          
                          
                  +            
                          
                CASE               
                           WHEN ISNULL(A.CreatedBetweenFromGRP, '')               
                                              
                                <              
                                              
                                >              
                                              
                                ''              
            AND ISNULL(A.CreatedBetweenToGRP, '')               
                              
                <              
                              
                >              
                              
                '' THEN '<p><b>Created Days within(Group):</b> '               
                              
                +              
                              
                A.CreatedBetweenFromGRP + ' - ' + A.CreatedBetweenToGRP               
                              
                +              
                              
                '</p>'               
                              
                ELSE ''               
                              
                END          
                          
                            
        )  AS SearchCriteria,              
        A.SearchType,              
        A.Medium,              
        A.Source,              
        A.Campaign,              
        A.SpecificName,              
        A.SpecificAddress,              
        A.SpecificMobileNo,              
        A.SpecificEmail,              
        ISNULL(A.SpecificCity,'')as SpecificCity,              
        ISNULL(A.SpecificState,'') as  SpecificState,            
        ISNULL(A.SpecificCountry,'') as   SpecificCountry,                    A.CurrentlyAssignedTo,              
        A.FollowUpStatus,              
        A.CreatedBetweenFrom,              
        A.CreatedBetweenTo,              
        A.NextFollowUpDateFrom,              
        A.NextFollowUpDateTo,              
        A.ConvertedWithinFrom,              
        A.ConvertedWithinTo,              
        A.User_Login,          
                  
        A.TotalOrdersFrom,          
        A.TotalOrdersTo,          
        A.TotalBusinessFrom,          
        A.TotalBusinessTo,          
        A.NextFollowUpDaysFrom,          
        A.NextFollowUpDaysTo,          
        A.IsRestrictToConversionDate,              
                  
        A.IsPredefined,              
        A.IsResponse,              
        A.IsSearch,              
        A.IsUnsubscribe,              
        A.IsCustom,      
        A.CreatedOn,  
        A.CreatedOn1              
 FROM   (              
            SELECT usl.ID,              
                   usl.SearchName,              
                   usl.IsPredefined,              
                   usl.IsResponse,              
           usl.IsUnsubscribe,              
                   usl.IsSearch,              
                   usl.IsCustom,              
                   CASE               
                        WHEN usl.IsPredefined = 1 THEN 'Pre-Defined'              
                        ELSE CASE               
                                  WHEN usl.IsResponse = 1 THEN 'Response'              
                                  ELSE CASE               
                                            WHEN usl.IsUnsubscribe              
                                             
                                                 = 1 THEN 'Unsubscribe'              
                                            ELSE CASE               
                                                      WHEN usl.IsSearch              
                                                                         
                                                           =              
                                                                         
                                                           1 THEN 'Saved Search'              
                                                      ELSE CASE               
                                                                WHEN usl.IsCustom              
                                                                                   
                                                                     =              
                                                                                   
                                                                    1 THEN               
                                                                     'Custom'              
                                                                ELSE ''              
                                                           END              
                END              
                                       END              
                             END              
                   END             AS SearchTyp,              
                   CASE               
                        WHEN usl.SearchType = 'EN' THEN 'Enquiry'              
                        ELSE CASE               
                                  WHEN usl.SearchType               
                                                     
                                       = 'LE' or usl.SearchType               
                                                     
                                       = 'AL'  THEN 'Leads'              
                                  ELSE CASE               
                                            WHEN usl.SearchType               
                                              
                                                 =              
                                                               
                                                 'Co' THEN 'Conversion'              
                                            ELSE CASE               
                                                      WHEN usl.SearchType               
                                                                         
                                                           =              
                                                                         
                                                           'Ls' THEN               
                                                           'Uploaded List'              
                                                      ELSE ''              
                                                 END              
                                       END              
                             END              
                   END             AS SearchType,              
                   CASE               
                        WHEN usl.Medium = '0' THEN 'All'              
                        ELSE (              
                                 SELECT STUFF(              
                                            (              
                                                SELECT N', ' + ums.Name              
                                                FROM   UserMediumSettings AS               
                                                       ums              
                                                       INNER JOIN dbo.fn_Split(usl.Medium, '#') AS               
                                                            fs              
                                                            ON  ums.MediumID =               
                                                       fs.[value]               
                                                                              
                                                                FOR XML               
                                                  
                                                                PATH(''),              
                                                       TYPE              
                                            )               
                                                          
                                            .value('text()[1]', 'nvarchar(max)'),              
                                            1,              
                                            2,              
                                            N''              
                                        )              
                             )              
                   END             AS Medium,              
                   CASE               
                        WHEN usl.Source = '0' THEN 'All'              
                        ELSE (              
                                 SELECT STUFF(              
                                            (              
                                                SELECT N', ' + ums.Name              
                                                FROM   UserSourceSettings AS               
                                                       ums              
                                                       INNER JOIN dbo.fn_Split(usl.Source, '#') AS               
                                                            fs              
                                                            ON  ums.SourceID =               
                                                                fs.[value]               
                                                                              
        FOR XML               
                                                                              
                                                                PATH(''),              
                                                       TYPE              
                                            )               
                                                          
             .value('text()[1]', 'nvarchar(max)'),              
                                            1,              
                                            2,              
                                            N''              
                                        )              
                             )              
                   END             AS Source,              
  CASE               
                        WHEN usl.Campaign = '0' THEN 'All'              
                        ELSE (              
                                 SELECT STUFF(              
                                            (              
                                                SELECT N', ' + ums.Name              
                                                FROM   UserCampaignSettings AS               
                                                       ums              
                                                       INNER JOIN dbo.fn_Split(usl.Campaign, '#') AS               
                                                            fs              
                                            ON  ums.CampaignID =               
                                                                fs.[value]               
                                                                              
                                                                FOR XML               
                                                                              
                                                                PATH(''),              
                                                       TYPE              
                                            )               
                                                          
                                            .value('text()[1]', 'nvarchar(max)'),              
                                            1,              
                                            2,              
                                            N''              
          )              
                             )              
                   END             AS Campaign,              
                   usl.SpecificName,              
                   usl.SpecificAddress,              
                   usl.SpecificMobileNo,              
                   usl.SpecificEmail,              
                   usl.SpecificCity,              
                   usl.SpecificState,              
                   usl.SpecificCountry,              
                   CASE               
                        WHEN usl.CurrentlyAssignedTo = '0' THEN 'All'              
                        ELSE (              
                                 SELECT STUFF(              
                                            (              
                                                SELECT N', ' + ums.FName +              
                                                                     
                                                       ' ' + ums.LName              
                                                FROM   User_Detail AS ums              
                                                       INNER JOIN dbo.fn_Split(usl.CurrentlyAssignedTo, '#') AS               
                                                            fs              
                                                          ON  ums.[User_ID] =               
                                                                fs.[value]               
                                                                              
                                                                FOR XML               
                                                                              
                                                                PATH(''),              
                                                       TYPE              
                                            )              
                                                          
                                            .value('text()[1]', 'nvarchar(max)'),              
     1,              
                                            2,              
                                            N''              
                                        )              
                             )              
                   END             AS CurrentlyAssignedTo,              
                   CASE               
                        WHEN usl.FollowUpStatus = '0' THEN 'All'              
                        ELSE (              
                                 SELECT STUFF(              
                                            (              
                                                SELECT N', ' + ums.FollowupStatus              
                                                FROM   FollowUp_Status AS ums              
                                                       INNER JOIN dbo.fn_Split(usl.FollowUpStatus, '#') AS               
                                                            fs              
                                                         ON  ums.ID = fs.[value]               
                                                                              
                                                                FOR XML               
                                                                              
                                                                PATH(''),              
                                                       TYPE              
                                            )               
                                                          
                                            .value('text()[1]', 'nvarchar(max)'),              
                                            1,              
                                            2,              
                                            N''              
                                        )              
                             )              
                   END             AS FollowUpStatus,              
                   usl.CreatedBetweenFrom,              
                   usl.CreatedBetweenTo,              
           usl.NextFollowUpDateFrom,              
                   usl.NextFollowUpDateTo,              
                   usl.ConvertedWithinFrom,              
                   usl.ConvertedWithinTo,              
                     
                   dbo.[fn_getusertimefromindiantime](@ParentID,isnull(usl.CreatedOn,null)) as CreatedOn ,   
                     
                   usl.CreatedOn as CreatedOn1,  
                                               
       usl.TotalOrdersFrom,          
                   usl.TotalOrdersTo,          
                   usl.TotalBusinessFrom,          
                   usl.TotalBusinessTo,          
                   usl.NextFollowUpDaysFrom,          
                   usl.NextFollowUpDaysTo,          
                   usl.IsRestrictToConversionDate,        
                   usl.NameGRP,        
                   usl.CompanyGRP,        
                   usl.MobileGRP,        
                   usl.EmailGRP,        
                   usl.CityGRP,        
                   usl.StateGRP,        
                   usl.CountryGRP,        
                   usl.AddressGRP,        
                   usl.BirthBetweenFromGRP,        
                   usl.BirthBetweenToGRP,        
                   usl.ANVBetweenFromGRP,        
                   usl.ANVBetweenToGRP,        
                   usl.CreatedBetweenFromGRP,        
                   usl.CreatedBetweenToGRP,        
                   usl.IsENQLeadCNV,        
                   usl.IsGroup,               
                   UD.User_Login              
            FROM   UserSearchList  AS usl              
                   LEFT JOIN User_Detail UD(NOLOCK)   
                      ON  usl.CreatedBy = UD.User_ID              
            WHERE  usl.ParentID = @ParentID              
                   AND (              
                           usl.IsPredefined = CASE               
                                                   WHEN @IsPredefined = 1 THEN               
                                                        1              
                                                   ELSE NULL              
                                              END              
                           OR usl.IsResponse = CASE               
                                                    WHEN @IsResponse = 1 THEN               
                                                         1              
                                                    ELSE NULL              
                                               END              
                           OR usl.IsUnsubscribe = CASE               
                                                       WHEN @IsUnsubscribe =              
                                                                          
                                                            1 THEN 1              
                                                       ELSE NULL              
                                                  END              
                           OR usl.IsSearch = CASE               
                                                  WHEN @IsSearch = 1 THEN 1              
 ELSE NULL              
                                             END              
                           OR usl.IsCustom = CASE               
                                                  WHEN @IsCustom = 1 THEN 1              
                                                  ELSE NULL              
                                             END              
                       )              
        )     A              
 ORDER BY              
        A.CreatedOn1 DESC              
END   


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserSearchList_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetUserSearchList_INTDateTime  --335,1,1,1,1,1          
 @ParentID BIGINT,            
 @IsPredefined BIT,            
 @IsResponse BIT,            
 @IsUnsubscribe BIT,            
 @IsSearch BIT,            
 @IsCustom BIT            
AS            
BEGIN            
 SELECT A.ID,            
        A.SearchName,            
        A.SearchTyp,            
        (  case when A.IsGroup = 1      
              then       
                  CASE             
                       WHEN ISNULL(A.NameGRP, '') <> '' THEN             
                            '<p><b>Name(Group):</b> '             
                                        
                            + A.NameGRP + '</p>'            
                       ELSE ''            
                  END      
                  +      
                 CASE             
                       WHEN ISNULL(A.CompanyGRP, '') <> '' THEN             
                            '<p><b>Company(Group):</b> '             
                                        
                            + A.CompanyGRP + '</p>'            
                       ELSE ''            
                 END      
                  +      
                 CASE             
                       WHEN ISNULL(A.MobileGRP, '') <> '' THEN             
                            '<p><b>Mobile(Group):</b> '             
                                        
                            + A.MobileGRP + '</p>'            
                       ELSE ''            
                 END      
                  +      
                 CASE             
                       WHEN ISNULL(A.EmailGRP, '') <> '' THEN             
                            '<p><b>Email(Group):</b> '             
                                        
                            + A.EmailGRP + '</p>'            
                       ELSE ''            
                 END      
                        
                  +      
                 CASE             
                       WHEN ISNULL(A.CityGRP, '') <> '' THEN             
                            '<p><b>City(Group):</b> '             
                                        
                            + A.CityGRP + '</p>'            
                       ELSE ''            
                 END      
                       
                  +      
                 CASE             
                       WHEN ISNULL(A.StateGRP, '') <> '' THEN             
                            '<p><b>State(Group):</b> '             
                                        
                            + A.StateGRP + '</p>'            
                       ELSE ''            
                 END      
                       
                  +      
                 CASE             
                       WHEN ISNULL(A.CountryGRP, '') <> '' THEN             
                            '<p><b>Country(Group):</b> '             
                                        
                            + A.CountryGRP + '</p>'            
                       ELSE ''            
                 END      
                       
                  +      
                 CASE             
                       WHEN ISNULL(A.AddressGRP, '') <> '' THEN             
                            '<p><b>Address(Group):</b> '             
                                        
                            + A.AddressGRP + '</p>'            
                       ELSE ''            
                 END      
                                         
                       
              else ''           
           end       
                 
           +         
            CASE             
                 WHEN ISNULL(A.SearchType, '') <> '' THEN             
                      '<p><b>Search Type:</b> ' + A.SearchType + '</p>'            
                 ELSE ''            
            END + CASE             
                       WHEN ISNULL(A.Medium, '') <> '' THEN             
                            '<p><b>Medium:</b> '             
                                 
                            + A.Medium + '</p>'            
       ELSE ''            
                  END + CASE             
                             WHEN ISNULL(A.Source, '') <> '' THEN             
                                  '<p><b>Source:</b> ' + A.Source + '</p>'            
                             ELSE ''            
                        END + CASE             
                                   WHEN ISNULL(A.Campaign, '') <> '' THEN             
                                        '<p><b>Campaign:</b> ' + A.Campaign +            
                                                    
                                        '</p>'            
                                   ELSE ''            
                              END + CASE             
                                         WHEN ISNULL(A.SpecificName, '') <>            
                                                          
                                              '' THEN '<p><b>Name:</b> ' + A.SpecificName             
                                                          
                                              + '</p>'            
                                         ELSE ''            
                                    END + CASE             
                                               WHEN ISNULL(A.SpecificAddress, '')             
                                                                
                                                    <> '' THEN             
                                                    '<p><b>Address:</b> ' + A.SpecificAddress             
                                                                
                                                    + '</p>'            
                                               ELSE ''            
                                          END + CASE             
                                                     WHEN ISNULL(A.SpecificMobileNo, '')             
                                                                      
                                                          <> '' THEN             
                                                          '<p><b>Mobile No:</b> '             
                                                                      
                                                          + A.SpecificMobileNo             
                                                                      
                                                          +            
                                                                      
                                                          '</p>'            
                                                     ELSE ''            
                                                END + CASE             
                                                           WHEN ISNULL(A.SpecificEmail, '')             
                                                                            
                                                                <> '' THEN             
                                                                '<p><b>Email:</b> '             
                                                                            
                                                                + A.SpecificEmail             
                                                                            
                                                                + '</p>'            
                                         ELSE ''            
                                                      END + CASE             
                                              WHEN ISNULL(A.SpecificCity, '')             
                    
                                                                      <> '' THEN             
                                                                      '<p><b> City:</b> '             
                                                            
                                                                      + A.SpecificCity             
                                       
                                                                      +            
                                                                                  
                                                                      '</p>'            
                                     ELSE ''            
                                                            END + CASE             
                                                                       WHEN             
                                                                            ISNULL(A.SpecificState, '')             
                                                                                        
                                                                            <            
                                                                                        
                                                                            >            
                                                                                        
                                                                            '' THEN             
                                                                            '<p><b>State:</b> '             
                                                                                        
                                                                            +            
                                                                                        
                                                                            A.SpecificState             
                                                                                        
                                                                            +            
                                                                                        
                                                                            '</p>'            
                                                                       ELSE             
                                                                            ''            
                                                                  END + CASE             
                                                                             WHEN             
                                                                                  ISNULL(A.SpecificCountry, '')             
                                                                                              
                                                                                  <            
                                                                                              
                                                                                  >            
                                                                                              
                                                                                  '' THEN             
                                                                                  '<p><b>Country:</b> '             
                                                                                              
                                                                                  +            
                                                                                              
                                                                                  A.SpecificCountry             
                                                                                     
                                                                                  +            
                                           
                                           '</p>'            
                          ELSE             
                                                                                  ''            
                       END + CASE             
                                                                                   WHEN             
                                                                                        ISNULL(A.CurrentlyAssignedTo, '')             
                                                                                                    
                                                                                      <            
                                                                                                    
                                                                                        >            
                                                                                                    
                                                                                        '' THEN             
                                                                                        '<p><b>Assigned To:</b> '             
                                                                                                    
                                                                                        +            
                                                                                                    
                                                                                        A.CurrentlyAssignedTo             
                                                                                                    
                                                                                        +            
                                                                                                    
                                                                                        '</p>'            
                                                                                   ELSE             
                                                                                        ''            
                                                                              END             
                        
            + CASE             
                   WHEN ISNULL(A.FollowUpStatus, '')             
                                    
                        <            
                                    
                        >            
                                    
                        '' THEN '<p><b>FollowUp Status:</b> '             
                                    
                        +            
                                    
                        A.FollowUpStatus             
                                    
                        +            
                                    
                        '</p>'            
                   ELSE ''            
              END + CASE             
                         WHEN ISNULL(A.CreatedBetweenFrom, '')             
                                          
                              <            
                                          
                              >            
                                          
                              ''            
            AND ISNULL(A.CreatedBetweenTo, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Created Between:</b> '             
                            
                +            
                            
                A.CreatedBetweenFrom + ' - ' + A.CreatedBetweenTo             
                            
                +            
                            
                '</p>'             
             
                ELSE ''             
                            
                END + CASE             
                        WHEN ISNULL(A.NextFollowUpDateFrom, '')             
                                            
                                <            
                                            
                 >            
                                            
                                ''            
            AND ISNULL(A.NextFollowUpDateTo, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Next FollowUp Days:</b> '             
                            
                +            
                            
                A.NextFollowUpDateFrom + ' - ' + A.NextFollowUpDateTo             
                           
                +            
                            
                '</p>'             
                            
                ELSE ''             
                            
                END + CASE             
                           WHEN ISNULL(A.ConvertedWithinFrom, '')             
                                            
                                <            
                                            
                                >            
                                            
                                ''            
            AND ISNULL(A.ConvertedWithinTo, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Converted With-in:</b> '             
                            
                +            
                            
                A.ConvertedWithinFrom + ' - ' + A.ConvertedWithinTo             
                            
                +            
                            
                '</p>'             
                            
                ELSE ''             
                            
                END +          
                        
                CASE             
                           WHEN ISNULL(A.NextFollowUpDaysFrom, '')             
                                            
                                <            
                                            
                                >            
                                            
                                ''            
            AND ISNULL(A.NextFollowUpDaysTo, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Followup Days within:</b> '             
                            
                +            
                            
                A.NextFollowUpDaysFrom + ' - ' + A.NextFollowUpDaysTo             
                            
                +            
                            
                '</p>'             
                            
                ELSE ''             
                            
                END        
                        
                  +          
                        
                CASE             
                           WHEN ISNULL(A.BirthBetweenFromGRP, '')             
                                            
                                <            
                                            
                                >            
                                            
                                ''            
            AND ISNULL(A.BirthBetweenToGRP, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Birth Days within(Group):</b> '             
   
                +            
                            
                A.BirthBetweenFromGRP + ' - ' + A.BirthBetweenToGRP             
                            
                +            
                            
                '</p>'             
                            
                ELSE ''             
                            
                END        
                        
                  +          
                        
                CASE             
                           WHEN ISNULL(A.ANVBetweenFromGRP, '')             
                                            
                                <            
                                            
                                >            
                                            
                                ''            
            AND ISNULL(A.ANVBetweenToGRP, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Anniversary Days within(Group):</b> '             
                            
                +            
                            
                A.ANVBetweenFromGRP + ' - ' + A.ANVBetweenToGRP             
                            
                +            
            
                '</p>'             
                            
                ELSE ''             
                            
                END        
                        
                  +          
                        
                CASE             
                           WHEN ISNULL(A.CreatedBetweenFromGRP, '')             
                                            
                                <            
                                            
                                >            
                                            
                                ''            
            AND ISNULL(A.CreatedBetweenToGRP, '')             
                            
                <            
                            
                >            
                            
                '' THEN '<p><b>Created Days within(Group):</b> '             
                            
                +            
                            
                A.CreatedBetweenFromGRP + ' - ' + A.CreatedBetweenToGRP             
                            
                +            
                            
                '</p>'             
                            
                ELSE ''             
                            
                END        
                        
                          
        )  AS SearchCriteria,            
        A.SearchType,            
        A.Medium,            
        A.Source,            
        A.Campaign,            
        A.SpecificName,            
        A.SpecificAddress,            
        A.SpecificMobileNo,            
        A.SpecificEmail,            
        ISNULL(A.SpecificCity,'')as SpecificCity,            
        ISNULL(A.SpecificState,'') as  SpecificState,          
        ISNULL(A.SpecificCountry,'') as   SpecificCountry,          
        A.CurrentlyAssignedTo,            
        A.FollowUpStatus,            
        A.CreatedBetweenFrom,            
        A.CreatedBetweenTo,            
        A.NextFollowUpDateFrom,            
        A.NextFollowUpDateTo,            
        A.ConvertedWithinFrom,            
        A.ConvertedWithinTo,            
        A.User_Login,        
                
        A.TotalOrdersFrom,        
        A.TotalOrdersTo,        
        A.TotalBusinessFrom,        
        A.TotalBusinessTo,        
        A.NextFollowUpDaysFrom,        
        A.NextFollowUpDaysTo,        
        A.IsRestrictToConversionDate,            
                
        A.IsPredefined,            
        A.IsResponse,            
        A.IsSearch,            
        A.IsUnsubscribe,            
        A.IsCustom,    
        A.CreatedOn,
        A.CreatedOn1            
 FROM   (            
            SELECT usl.ID,            
                   usl.SearchName,            
                   usl.IsPredefined,            
                   usl.IsResponse,            
           usl.IsUnsubscribe,            
                   usl.IsSearch,            
                   usl.IsCustom,            
                   CASE             
                        WHEN usl.IsPredefined = 1 THEN 'Pre-Defined'            
                        ELSE CASE             
                                  WHEN usl.IsResponse = 1 THEN 'Response'            
                                  ELSE CASE             
                                            WHEN usl.IsUnsubscribe            
                                           
                                                 = 1 THEN 'Unsubscribe'            
                                            ELSE CASE             
                                                      WHEN usl.IsSearch            
                                                                       
                                                           =            
                                                                       
                                                           1 THEN 'Saved Search'            
                                                      ELSE CASE             
                                                                WHEN usl.IsCustom            
                                                                                 
                                                                     =            
                                                                                 
                                                                    1 THEN             
                                                                     'Custom'            
                                                                ELSE ''            
                                                           END            
                END            
                                       END            
                             END            
                   END             AS SearchTyp,            
                   CASE             
                        WHEN usl.SearchType = 'EN' THEN 'Enquiry'            
                        ELSE CASE             
                                  WHEN usl.SearchType             
                                                   
                                       = 'LE' THEN 'Leads'            
                                  ELSE CASE             
                                            WHEN usl.SearchType             
                                            
                                                 =            
                                                             
                                                 'Co' THEN 'Conversion'            
                                            ELSE CASE             
                                                      WHEN usl.SearchType             
                                                                       
                                                           =            
                                                                       
                                                           'Ls' THEN             
                                                           'Uploaded List'            
                                                      ELSE ''            
                                                 END            
                                       END            
                             END            
                   END             AS SearchType,            
                   CASE             
                        WHEN usl.Medium = '0' THEN 'All'            
                        ELSE (            
                                 SELECT STUFF(            
                                            (            
                                                SELECT N', ' + ums.Name            
                                                FROM   UserMediumSettings AS             
                                                       ums            
                                                       INNER JOIN dbo.fn_Split(usl.Medium, '#') AS             
                                                            fs            
                                                            ON  ums.MediumID =             
                                                       fs.[value]             
                                                                            
                                                                FOR XML             
                                                
                                                                PATH(''),            
                                                       TYPE            
                                            )             
                                                        
                                            .value('text()[1]', 'nvarchar(max)'),            
                                            1,            
                                            2,            
                                            N''            
                                        )            
                             )            
                   END             AS Medium,            
                   CASE             
                        WHEN usl.Source = '0' THEN 'All'            
                        ELSE (            
                                 SELECT STUFF(            
                                            (            
                                                SELECT N', ' + ums.Name            
                                                FROM   UserSourceSettings AS             
                                                       ums            
                                                       INNER JOIN dbo.fn_Split(usl.Source, '#') AS             
                                                            fs            
                                                            ON  ums.SourceID =             
                                                                fs.[value]             
                                                                            
        FOR XML             
                                                                            
                                                                PATH(''),            
                                                       TYPE            
                                            )             
                                                        
                                            .value('text()[1]', 'nvarchar(max)'),            
                                            1,            
                                            2,            
                                            N''            
                                        )            
                             )            
                   END             AS Source,            
  CASE             
                        WHEN usl.Campaign = '0' THEN 'All'            
                        ELSE (            
                                 SELECT STUFF(            
                                            (            
                                                SELECT N', ' + ums.Name            
                                                FROM   UserCampaignSettings AS             
                                                       ums            
                                                       INNER JOIN dbo.fn_Split(usl.Campaign, '#') AS             
                                                            fs            
                                            ON  ums.CampaignID =             
                                                                fs.[value]             
                                                                            
                                                                FOR XML             
                                                                            
                                                                PATH(''),            
                                                       TYPE            
                                            )             
                                                        
                                            .value('text()[1]', 'nvarchar(max)'),            
                                            1,            
                                            2,            
                                            N''            
          )            
                             )            
                   END             AS Campaign,            
                   usl.SpecificName,            
                   usl.SpecificAddress,            
                   usl.SpecificMobileNo,            
                   usl.SpecificEmail,            
                   usl.SpecificCity,            
                   usl.SpecificState,            
                   usl.SpecificCountry,            
                   CASE             
                        WHEN usl.CurrentlyAssignedTo = '0' THEN 'All'            
                        ELSE (            
                                 SELECT STUFF(            
                                            (            
                                                SELECT N', ' + ums.FName +            
                                                                   
                                                       ' ' + ums.LName            
                                                FROM   User_Detail AS ums            
                                                       INNER JOIN dbo.fn_Split(usl.CurrentlyAssignedTo, '#') AS             
                                                            fs            
                                                          ON  ums.[User_ID] =             
                                                                fs.[value]             
                                                                            
                                                                FOR XML             
                                                                            
                                                                PATH(''),            
                                                       TYPE            
                                            )             
                                                        
                                            .value('text()[1]', 'nvarchar(max)'),            
     1,            
                                            2,            
                                            N''            
                                        )            
                             )            
                   END             AS CurrentlyAssignedTo,            
                   CASE             
                        WHEN usl.FollowUpStatus = '0' THEN 'All'            
                        ELSE (            
                                 SELECT STUFF(            
                                            (            
                                                SELECT N', ' + ums.FollowupStatus            
                                                FROM   FollowUp_Status AS ums            
                                                       INNER JOIN dbo.fn_Split(usl.FollowUpStatus, '#') AS             
                                                            fs            
                                                         ON  ums.ID = fs.[value]             
                                                                            
                                                                FOR XML             
                                                                            
                                                                PATH(''),            
                                                       TYPE            
                                            )             
                                                        
                                            .value('text()[1]', 'nvarchar(max)'),            
                                            1,            
                                            2,            
                                            N''            
                                        )            
                             )            
                   END             AS FollowUpStatus,            
                   usl.CreatedBetweenFrom,            
                   usl.CreatedBetweenTo,            
           usl.NextFollowUpDateFrom,            
                   usl.NextFollowUpDateTo,            
                   usl.ConvertedWithinFrom,            
                   usl.ConvertedWithinTo,            
                   
                   dbo.[fn_getusertimefromindiantime](@ParentID,isnull(usl.CreatedOn,null)) as CreatedOn , 
                   
                   usl.CreatedOn as CreatedOn1,
                                             
       usl.TotalOrdersFrom,        
                   usl.TotalOrdersTo,        
                   usl.TotalBusinessFrom,        
                   usl.TotalBusinessTo,        
                   usl.NextFollowUpDaysFrom,        
                   usl.NextFollowUpDaysTo,        
                   usl.IsRestrictToConversionDate,      
                   usl.NameGRP,      
                   usl.CompanyGRP,      
                   usl.MobileGRP,      
                   usl.EmailGRP,      
                   usl.CityGRP,      
                   usl.StateGRP,      
                   usl.CountryGRP,      
                   usl.AddressGRP,      
                   usl.BirthBetweenFromGRP,      
                   usl.BirthBetweenToGRP,      
                   usl.ANVBetweenFromGRP,      
                   usl.ANVBetweenToGRP,      
                   usl.CreatedBetweenFromGRP,      
                   usl.CreatedBetweenToGRP,      
                   usl.IsENQLeadCNV,      
                   usl.IsGroup,             
                   UD.User_Login            
            FROM   UserSearchList  AS usl            
                   LEFT JOIN User_Detail UD(NOLOCK)            
                      ON  usl.CreatedBy = UD.User_ID            
            WHERE  usl.ParentID = @ParentID            
                   AND (            
                           usl.IsPredefined = CASE             
                                                   WHEN @IsPredefined = 1 THEN             
                                                        1            
                                                   ELSE NULL            
                                              END            
                           OR usl.IsResponse = CASE             
                                                    WHEN @IsResponse = 1 THEN             
                                                         1            
                                                    ELSE NULL            
                                               END            
                           OR usl.IsUnsubscribe = CASE             
                                                       WHEN @IsUnsubscribe =            
                                                                        
                                                            1 THEN 1            
                                                       ELSE NULL            
                                                  END            
                           OR usl.IsSearch = CASE             
                                                  WHEN @IsSearch = 1 THEN 1            
 ELSE NULL            
                                             END            
                           OR usl.IsCustom = CASE             
                                                  WHEN @IsCustom = 1 THEN 1            
                                                  ELSE NULL            
                                             END            
                       )            
        )     A            
 ORDER BY            
        A.CreatedOn1 DESC            
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserSearchListCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetUserSearchListCampaign   --335  
 @ParentID BIGINT    
AS    
BEGIN    
 SELECT A.ID,    
        A.SearchName + ' ( ' + A.SearchType + ' ) ' AS SearchName    
 FROM   (    
            SELECT usl.ID,    
                   usl.SearchName,    
                   CASE     
                        WHEN usl.SearchType = 'EN' THEN 'Enquiry'    
                        ELSE CASE     
                                  WHEN usl.SearchType     
                                           
                                       = 'LE' THEN 'Leads'    
                                  ELSE CASE     
                                            WHEN usl.SearchType     
                                                     
                                                 =    
                                                     
                                                 'Co' THEN 'Conversion'    
                                                   
                                       ELSE CASE     
                                            WHEN usl.SearchType     
                                                     
                                                 =    
                                                     
                                                 'GR' THEN 'Custom Contact Search'    
                                            ELSE CASE     
                                                      WHEN usl.SearchType     
                                                               
                                                           =    
                                                               
                                                           'Ls' THEN     
                                                           'Uploaded List'    
                                                      ELSE CASE     
                                                                WHEN usl.IsResponse    
                                                                     = 1 THEN     
                                                                     'Response'    
                                                                ELSE CASE     
                                                                          WHEN     
                                                                               usl.IsUnsubscribe    
                                                                               =     
                                                                               1 THEN     
                                                                               'Unsubscribe'    
                                                                          ELSE     
                                                                               ''    
                                                                     END    
                                                           END    
                                                 END    
                                       END   
                                   END   
                             END    
                   END    AS SearchType    
            FROM   UserSearchList  AS usl    
            WHERE  usl.ParentID = @ParentID    
        ) A    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserSearchListForCampaignPopup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetUserSearchListForCampaignPopup]
	@ParentID BIGINT
AS
BEGIN
	SELECT A.ID,
	       A.SearchName,
	       (
	           CASE 
	                WHEN ISNULL(A.SearchType, '') <> '' THEN 
	                     '<p><b>Search Type:</b> ' + A.SearchType + '</p>'
	                ELSE ''
	           END + CASE 
	                      WHEN ISNULL(A.Medium, '') <> '' THEN 
	                           '<p><b>Medium:</b> ' 
	                           + A.Medium + '</p>'
	                      ELSE ''
	                 END + CASE 
	                            WHEN ISNULL(A.Source, '') <> '' THEN 
	                                 '<p><b>Source:</b> ' + A.Source + '</p>'
	                            ELSE ''
	                       END + CASE 
	                                  WHEN ISNULL(A.Campaign, '') <> '' THEN 
	                                       '<p><b>Campaign:</b> ' + A.Campaign +
	                                       '</p>'
	                                  ELSE ''
	                             END + CASE 
	                                        WHEN ISNULL(A.SpecificName, '') <>
	                                             '' THEN '<p><b>Name:</b> ' + A.SpecificName 
	                                             + '</p>'
	                                        ELSE ''
	                                   END + CASE 
	                                              WHEN ISNULL(A.SpecificAddress, '') 
	                                                   <> '' THEN 
	                                                   '<p><b>Address:</b> ' + A.SpecificAddress 
	                                                   + '</p>'
	                                              ELSE ''
	                                         END + CASE 
	                                                    WHEN ISNULL(A.SpecificMobileNo, '') 
	                                                         <> '' THEN 
	                                                         '<p><b>Mobile No:</b> ' 
	                                                         + A.SpecificMobileNo 
	                                                         +
	                                                         '</p>'
	                                                    ELSE ''
	                                               END + CASE 
	                                                          WHEN ISNULL(A.SpecificEmail, '') 
	                                                               <> '' THEN 
	                                                               '<p><b>Email:</b> ' 
	                                                               + A.SpecificEmail 
	                                                               + '</p>'
	                                                          ELSE ''
	                                                     END + CASE 
	                                                                WHEN ISNULL(A.SpecificCity, '') 
	                                                                     <> '' THEN 
	                                                                     '<p><b> City:</b> ' 
	                                                                     + A.SpecificCity 
	                                                                     +
	                                                                     '</p>'
	                                                                ELSE ''
	                                                           END + CASE 
	                                                                      WHEN 
	                                                                           ISNULL(A.SpecificState, '') 
	                                                                           <
	                                                                           >
	                                                                           '' THEN 
	                                                                           '<p><b>State:</b> ' 
	                                                                           +
	                                                                           A.SpecificState 
	                                                                           +
	                                                                           '</p>'
	                                                                      ELSE 
	                                                                           ''
	                                                                 END + CASE 
	                                                                            WHEN 
	                                                                                 ISNULL(A.SpecificCountry, '') 
	                                                                                 <
	                                                                                 >
	                                                                                 '' THEN 
	                                                                                 '<p><b>Country:</b> ' 
	                                                                                 +
	                                                                                 A.SpecificCountry 
	                                                                                 +
	                                                                                 '</p>'
	                                                                            ELSE 
	                                                                                 ''
	                                                                       END + CASE 
	                                                                                  WHEN 
	                                                                                       ISNULL(A.CurrentlyAssignedTo, '') 
	                                                                                       <
	                                                                                       >
	                                                                                       '' THEN 
	                                                                                       '<p><b>Assigned To:</b> ' 
	                                                                                       +
	                                                                                       A.CurrentlyAssignedTo 
	                                                                                       +
	                                                                                       '</p>'
	                                                                                  ELSE 
	                                                                                       ''
	                                                                             END 
	           + CASE 
	                  WHEN ISNULL(A.FollowUpStatus, '') 
	                       <
	                       >
	                       '' THEN '<p><b>FollowUp Status:</b> ' 
	                       +
	                       A.FollowUpStatus 
	                       +
	                       '</p>'
	                  ELSE ''
	             END + CASE 
	                        WHEN ISNULL(A.CreatedBetweenFrom, '') 
	                             <
	                             >
	                             ''
	           AND ISNULL(A.CreatedBetweenTo, '') 
	               <
	               >
	               '' THEN '<p><b>Created Between:</b> ' 
	               +
	               A.CreatedBetweenFrom + ' - ' + A.CreatedBetweenTo 
	               +
	               '</p>' 
	               ELSE '' 
	               END + CASE 
	                          WHEN ISNULL(A.NextFollowUpDateFrom, '') 
	                               <
	                               >
	                               ''
	           AND ISNULL(A.NextFollowUpDateTo, '') 
	               <
	               >
	               '' THEN '<p><b>Next FollowUp Days:</b> ' 
	               +
	               A.NextFollowUpDateFrom + ' - ' + A.NextFollowUpDateTo 
	               +
	               '</p>' 
	               ELSE '' 
	               END + CASE 
	                          WHEN ISNULL(A.ConvertedWithinFrom, '') 
	                               <
	                               >
	                               ''
	           AND ISNULL(A.ConvertedWithinTo, '') 
	               <
	               >
	               '' THEN '<p><b>Converted With-in:</b> ' 
	               +
	               A.ConvertedWithinFrom + ' - ' + A.ConvertedWithinTo 
	               +
	               '</p>' 
	               ELSE '' 
	               END
	       )  AS SearchCriteria,
	       A.SearchType,
	       A.Medium,
	       A.Source,
	       A.Campaign,
	       A.SpecificName,
	       A.SpecificAddress,
	       A.SpecificMobileNo,
	       A.SpecificEmail,
	       A.SpecificCity,
	       A.SpecificState,
	       A.SpecificCountry,
	       A.CurrentlyAssignedTo,
	       A.FollowUpStatus,
	       A.CreatedBetweenFrom,
	       A.CreatedBetweenTo,
	       A.NextFollowUpDateFrom,
	       A.NextFollowUpDateTo,
	       A.ConvertedWithinFrom,
	       A.ConvertedWithinTo,
	       A.User_Login
	FROM   (
	           SELECT usl.ID,
	                  usl.SearchName,
	                  CASE 
	                       WHEN usl.SearchType = 'EN' THEN 'Enquiry'
	                       ELSE CASE 
	                                 WHEN usl.SearchType 
	                                      = 'LE' THEN 'Leads'
	                                 ELSE CASE 
	                                           WHEN usl.SearchType 
	                                                =
	                                                'Co' THEN 'Conversion'
	                                           ELSE CASE 
	                                                     WHEN usl.SearchType 
	                                                          =
	                                                          'Ls' THEN 
	                                                          'Uploaded List'
	                                                     ELSE ''
	                                                END
	                                      END
	                            END
	                  END             AS SearchType,
	                  CASE 
	                       WHEN usl.Medium = '0' THEN 'All'
	                       ELSE (
	                                SELECT STUFF(
	                                           (
	                                               SELECT N', ' + ums.Name
	                                               FROM   UserMediumSettings AS 
	                                                      ums
	                                                      INNER JOIN dbo.fn_Split(usl.Medium, '#') AS 
	                                                           fs
	                                                           ON  ums.MediumID = 
	                                                               fs.[value] 
	                                                               FOR XML 
	                                                               PATH(''),
	                                                      TYPE
	                                           ) 
	                                           .value('text()[1]', 'nvarchar(max)'),
	                                           1,
	                                           2,
	                                           N''
	                                       )
	                            )
	                  END             AS Medium,
	                  CASE 
	                       WHEN usl.Source = '0' THEN 'All'
	                       ELSE (
	                                SELECT STUFF(
	                                           (
	                                               SELECT N', ' + ums.Name
	                                               FROM   UserSourceSettings AS 
	                                                      ums
	                                                      INNER JOIN dbo.fn_Split(usl.Source, '#') AS 
	                                                           fs
	                                                           ON  ums.SourceID = 
	                                                               fs.[value] 
	                                                               FOR XML 
	                                                               PATH(''),
	                                                      TYPE
	                                           ) 
	                                           .value('text()[1]', 'nvarchar(max)'),
	                                           1,
	                                           2,
	                                           N''
	                                       )
	                            )
	                  END             AS Source,
	                  CASE 
	                       WHEN usl.Campaign = '0' THEN 'All'
	                       ELSE (
	                                SELECT STUFF(
	                                           (
	                                               SELECT N', ' + ums.Name
	                                               FROM   UserCampaignSettings AS 
	                                                      ums
	                                                      INNER JOIN dbo.fn_Split(usl.Campaign, '#') AS 
	                                                           fs
	                                                           ON  ums.CampaignID = 
	                                                               fs.[value] 
	                                                               FOR XML 
	                                                               PATH(''),
	                                                      TYPE
	                                           ) 
	                                           .value('text()[1]', 'nvarchar(max)'),
	                                           1,
	                                           2,
	                                           N''
	                                       )
	                            )
	                  END             AS Campaign,
	                  usl.SpecificName,
	                  usl.SpecificAddress,
	                  usl.SpecificMobileNo,
	                  usl.SpecificEmail,
	                  usl.SpecificCity,
	                  usl.SpecificState,
	                  usl.SpecificCountry,
	                  CASE 
	                       WHEN usl.CurrentlyAssignedTo = '0' THEN 'All'
	                       ELSE (
	                                SELECT STUFF(
	                                           (
	                                               SELECT N', ' + ums.FName +
	                                                      ' ' + ums.LName
	                                               FROM   User_Detail AS ums
	                                                      INNER JOIN dbo.fn_Split(usl.CurrentlyAssignedTo, '#') AS 
	                                                           fs
	                                                           ON  ums.[User_ID] = 
	                                                               fs.[value] 
	                                                               FOR XML 
	                                                               PATH(''),
	                                                      TYPE
	                                           ) 
	                                           .value('text()[1]', 'nvarchar(max)'),
	                                           1,
	                                           2,
	                                           N''
	                                       )
	                            )
	                  END             AS CurrentlyAssignedTo,
	                  CASE 
	                       WHEN usl.FollowUpStatus = '0' THEN 'All'
	                       ELSE (
	                                SELECT STUFF(
	                                           (
	                                               SELECT N', ' + ums.FollowupStatus
	                                               FROM   FollowUp_Status AS ums
	                                                      INNER JOIN dbo.fn_Split(usl.FollowUpStatus, '#') AS 
	                                                           fs
	                                                           ON  ums.ID = fs.[value] 
	                                                               FOR XML 
	                                                               PATH(''),
	                                                      TYPE
	                                           ) 
	                                           .value('text()[1]', 'nvarchar(max)'),
	                                           1,
	                                           2,
	                                           N''
	                                       )
	                            )
	                  END             AS FollowUpStatus,
	                  usl.CreatedBetweenFrom,
	                  usl.CreatedBetweenTo,
	                  usl.NextFollowUpDateFrom,
	                  usl.NextFollowUpDateTo,
	                  usl.ConvertedWithinFrom,
	                  usl.ConvertedWithinTo,
	                  usl.CreatedOn,
	                  UD.User_Login
	           FROM   UserSearchList  AS usl
	                  LEFT JOIN User_Detail UD(NOLOCK)
	                       ON  usl.CreatedBy = UD.User_ID
	           WHERE  usl.ParentID = @ParentID
	       )     A
	ORDER BY
	       A.CreatedOn DESC
END



GO

