/* ============================================================
   Procedure: [dbo].[usp_GetUserSegmentList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserSegmentList](
	@UserId bigint,          
	@FilterText nvarchar(255) = '', 
	@Status nvarchar(255) = '',               
	@FromDate datetime= null,                                    
	@ToDate datetime= null,                                    
	@OffsetValue int = 0,                  
	@PagingSize int  = 20    
)
as
begin
--declare @userId bigint=34594,          
--	@FilterText nvarchar(255) = '', 
--	@Status nvarchar(255) = '',               
--	@fromDate datetime= '25-Nov-2024',                                    
--	@ToDate datetime= '26-Nov-2024',                                    
--	@OffsetValue int = 0,                  
--	@PagingSize int  = 20   

declare @StartPoint int  = (@OffsetValue + 1), @Endpoint int = (@OffsetValue + @PagingSize), @ParentId bigint = 0                                 
select  @ParentId = ParentID from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId                   
     Print concat('@ParentId=>',@ParentId)           
   select * from ( select row_number() over(partition by A.ParentId order by A.Id desc) as SNo, count(A.ParentId) over() as TotalRow, A.id,A.parentId, segmentName, a.Status,UserId ,Format(CreatedAt,'dd-MMM-yyyy hh:mm:ss tt' ) as CreatedAt,concat(FName,' ',LName) as CreatedBy, UpdatedBy,Format(UpdatedAt,'dd-MMM-yyyy hh:mm:ss tt' ) as UpdatedAt    
 from   tbl_UserSegments(nolock) as A 
 left join User_Detail(nolock) ud on ud.User_ID=a.CreatedBy
   where A.ParentId = @ParentId and  
   cast(A.CreatedAt as date)  between cast(@FromDate as date)  and  cast(@ToDate as date) and 
   1 = (case when isnull(@FilterText, '') = '' then 1  when isnull(@FilterText, '') <> '' and A.segmentName like '%'+@FilterText+'%' then 1 else 0 end ) 
   and (1 = (case when isnull(@Status, '') = '' then 1  when isnull(@Status, '') <> ''                     
   and  a.status = @Status then 1     else 0 end ))
   ) b where b.SNo between @StartPoint and @Endpoint                     
                    
       
end


