CREATE   PROC usp_GetUserShortUrlRights
@parentid bigint
as
begin
if exists(select 1 from User_smsLink_Track where Parentid =@Parentid and status = 0  and isactive=1)
begin
Select 'Feature Activated' as Status
end
else if exists(select 1 from User_smsLink_Track where Parentid =@Parentid and status = 0  and isactive=0)
begin
Select 'Already Taken Demo' as Status
end
else if exists(select 1 from TrackLinkRequest where Parentid =@Parentid and isnull(DemoapprovalStatus,0)=0)
begin
Select 'Demo Request Under Process' as Status
end
else
begin
SElect 'Request Now'
end
end



