/* ============================================================
   Procedure: [dbo].[usp_GetUserSubscriptionStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------------------------------------------------------------------


CREATE   PROCEDURE [dbo].[usp_GetUserSubscriptionStatus]--32222
    @UserID BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        DECLARE @parentid BIGINT;
        SELECT @parentid = ParentID FROM User_Detail (NOLOCK) WHERE User_ID = @UserID;

        SELECT TOP 1 
            CONVERT(VARCHAR(11), u.PlanStartDate, 106) AS PlanStartDate,
            CONVERT(VARCHAR(11), u.PlanEndDate, 106) AS PlanEndDate,
            t.AllowUserCount,
            t.LicenceType,
            CASE 
                WHEN GETDATE() BETWEEN u.PlanStartDate AND u.PlanEndDate THEN 'Active'
                ELSE 'Expired'
            END AS Status
        FROM dbo.Price_UserSubscriptionDetails AS u (NOLOCK)
        LEFT JOIN dbo.tbl_pt_AllowUserTransactions AS t (NOLOCK) 
            ON u.UserID = t.UserId 
            AND u.id = t.SubscriptionId
        WHERE u.UserID = @parentid
        ORDER BY u.id DESC;

    END TRY
    BEGIN CATCH
        -- Error handling
        SELECT 
            ERROR_NUMBER() AS ErrorNumber,
            ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserThemeData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserThemeData]  
    @tpuserid BIGINT,  
    @MetaData NVARCHAR(MAX)  
AS  
BEGIN  
    DECLARE @UserId BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;  
  
    -- Retrieve User_Id and TimeZone for the given ParentId  
  
  
    -- Extract values from the JSON metadata  
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);  
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);  
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);  
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);  
  
    -- Retrieve email setting data  
    SELECT  
         
    ThemeName from tbl_tp_UserThemes AS ES  
   WHERE UserId = @tpuserid AND IsActive = 1  
  
    -- Construct a JSON representation of the retrieved data  
    SET @rowJson = (SELECT * FROM tbl_tp_UserThemes WHERE UserId = @tpuserid FOR JSON AUTO, INCLUDE_NULL_VALUES);  
  
    -- If rowJson is not null, insert an audit record  
    IF @rowJson IS NOT NULL  
    BEGIN  
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData  
            @User_id = @UserId,  
            @Activity_type = 'View_emailsettings',  
            @ActionType = 'S',  
            @RowJson = @rowJson,  
            @Table_name = 'tbl_tp_EmailSetting',  
            @ip_adress = @IPAdress,  
            @device_id = @DeviceId,  
            @IsImpersonation = @IsImpersonation,  
            @ImpersonatorId = @ImpersonatorId;  
    END;  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetUserUrlByID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetUserUrlByID]                      
 @urlid as bigint,        
 @templateid bigint,        
 @CampaignID bigint,        
 @ParentID   bigint,         
 @Mail_ToEmail   VARCHAR(MAX)              
as            
 begin            
 update UserUrl set NoOfVisit= isnull(NoOfVisit,0)+1 where UserUrl.urlid = @urlid           
 select url_dtl from UserUrl where UserUrl.urlid = @urlid        
 declare @id bigint,@subject nvarchar(100)     
 insert into url_tracktbl (urlid,  Mail_ToEmail, templateid, CampaignID, ParentID)        
  values (@urlid,  @Mail_ToEmail, @templateid, @CampaignID, @ParentID)        
 select @id=SCOPE_IDENTITY()    
     
 if exists(select 1 from user_detail (nolock) where ParentID=@parentid and isdemoaccount=1)      
 and exists(select 1 from user_detail(nolock) where email=@mail_toemail and M_ID=10043)      
 begin      
 declare @user_login nvarchar(50),@user_id bigint,@message nvarchar(2000)      
 select @user_login=user_login,@user_id=user_id from user_detail(nolock) where email=@mail_toemail and M_ID=10043      
 select @subject=mailsubject from dbo.UserMailTemplate where id=@templateid            
    
 declare @description nvarchar(200)='User '+cast(@user_login as nvarchar)+' opened Mail with subject "'+cast(@subject as nvarchar)+'" and clicked on url "'+(select url_dtl from UserUrl where UserUrl.urlid = @urlid )+'"'      
 exec Usp_InsertUserEventDetails 'User opened mail and clicked on a link',@user_ID,@Description,'url_tracktbl',@ID        
 end          
     
  
   /* Start lead Activity a mail link tracking */  
  
Begin try  
  
 Declare @UserID_LDACTV Bigint = 0;  
 Declare @ParentID_LDACTV bigint = @ParentID;  
 Declare @Mail_ToEmail_LDACTV nvarchar(500) = @Mail_ToEmail  
 Declare @TemplateID_LDACTV bigint = @templateid    
 Declare @URLID_LDACTV bigint =  @urlid  
 Declare @Subject_LDACTV nvarchar(500)   
 Declare @LongUrl_LDACTV nvarchar(500) = ''  
 Declare @LeadID_LDACTV bigint = 0   
 Declare @MailSentDate_LDACTV nvarchar(50) = ''   
  
 select top 1 @UserID_LDACTV = isnull(user_id,0) from user_detail(nolock) where email=@Mail_ToEmail_LDACTV and M_ID=10043      
 select top 1 @Subject_LDACTV = isnull(mailsubject,'') from dbo.UserMailTemplate where id=@TemplateID_LDACTV  
 select top 1 @LongUrl_LDACTV = isnull(url_dtl,''), @MailSentDate_LDACTV =isnull(creationdate,getdate()) from UserUrl where urlid = @URLID_LDACTV   
 select top 1 @LeadID_LDACTV = isnull(ID,0) from userleads where ( (EmailID = @Mail_ToEmail_LDACTV)  
  or (EmailID1 = @Mail_ToEmail_LDACTV) or (EmailID2 = @Mail_ToEmail_LDACTV)) and @Mail_ToEmail_LDACTV <> ''   
  
  
   create table #tblEventDescrb  
   (  
      EVNT_Description nvarchar(max)   
   )  
  
  if( isnull(@LeadID_LDACTV,0) > 0)  
   Begin  
          
      insert into #tblEventDescrb  
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead visits a mail link',@UserID_LDACTV,'','',@LeadID_LDACTV,@LongUrl_LDACTV,null  
   ,0,0,@Subject_LDACTV,@Mail_ToEmail_LDACTV,0,'',0,null,null,null,null,null,0,null,null,null,null,null,null,null,null,null,null,null,  
   0,0,0,null,null,null,0,null,null,null,0,null,null  
   
      
   declare @evntMessage nvarchar(max) = ''   
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb  
    
   set @evntMessage = replace(@evntMessage,'#mailsentdate#',@MailSentdate_LDACTV)      
  
   if(@evntMessage <> '')  
   Begin  
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Lead visits a mail link','url_tracktbl',@id  
   end  
  
  
   End    
  
   End Try  
  
   Begin Catch  
  
     exec usp_insertErrorInfo   
  
   End Catch  
  
    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence    
   Begin    
        DROP TABLE #tblEventDescrb    
   End    
     
     
   /*end Lead Activity Mail Link tracking */  
  
  
                  
 end    
     


GO

