/* ============================================================
   Procedure: [dbo].[usp_GetVoiceCampaignExecutionDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetVoiceCampaignExecutionDetails]
	@camid bigint = NULL,
    @UserId bigint = NULL, 
    @FromDate DATETIME = NULL, 
    @ToDate DATETIME = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- Temporary table to store intermediate results (if needed)
    CREATE TABLE #TempResults (
        CampaignName NVARCHAR(255),
        BatchID INT,
        ExecutionDate DATETIME,
        ReplyTo NVARCHAR(255),
        Status NVARCHAR(50),
        Message NVARCHAR(MAX)
    );

    -- Main Query to Fetch Data
    INSERT INTO #TempResults (CampaignName, BatchID, ExecutionDate, ReplyTo, Status)
    SELECT 
        UCM.CampaignName,                    
        UCEH.BatchID,                        
        UCEH.ExecutionTime,                  
        CE.Mobile,                          
        CE.voiceStatus                           
        --CE.Message                           
    FROM 
        UserCampaignExecutionHistory UCEH
    INNER JOIN 
        UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
    INNER JOIN 
        batchvoiceinfo BEI ON UCEH.BatchID = BEI.BatchID
    INNER JOIN 
        voice_deliverystatus CE ON BEI.BatchID = CE.BatchID
    WHERE 
        --(@UserId IS NULL OR UCEH.UserID = @UserId) 
		(@camid IS NULL OR UCEH.CampaignID = @camid) and UCM.Medium='voice'
        and (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
        AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);   

    -- Return Results
    SELECT * 
    FROM #TempResults;

    -- Cleanup
    DROP TABLE #TempResults;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_GetWalletConsumptionByMID_2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetWalletConsumptionByMID_2] --10043
    @m_id INT
AS
BEGIN
    SET NOCOUNT ON;

    -- Main query to retrieve total consumption for each User_ID
    SELECT TOP 5 

        u.User_ID,
       u.FName + ' ' + u.LName + ' (' + u.user_login + ')' AS FullName,
        ISNULL(SUM(dc.TotalMoneyConsumption), 0) AS TotalConsumption
    FROM 
        
        User_Detail (nolock) AS u 
    LEFT JOIN 
        DailyMoneyConsumption (nolock) AS dc ON u.User_ID = dc.User_ID
    WHERE 
        u.m_id = @m_id AND month(dc.Date)=MONTH(getdate()) and year(dc.Date)=year(getdate())
    GROUP BY 
        u.User_ID, u.FName, u.LName, u.user_login 
    ORDER BY 
        ISNULL(SUM(dc.TotalMoneyConsumption), 0) DESC;
END;


GO

