/* ============================================================
   Procedure: [dbo].[Usp_getwebcontrol]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE Usp_getwebcontrol    
@formid bigint    
AS    
BEGIN    
    
select     
case    
 when UserControlName= 'Name'    
 then 'PersonName'    
     
 when UserControlName= 'Mobile'    
 then 'MobileNo'    
     
 when UserControlName= 'Email'    
 then 'EmailID'    
     
 when UserControlName= 'Address'    
 then 'ResidentialAddress'    
     
 when UserControlName= 'CountryCode'    
 then 'CountryCode'    
     
 when UserControlName= 'Remarks'    
 then 'InitialRemarks'    
 end    
  ID,    
  case    
 when UserControlName= 'Name'    
 then 'PersonName'    
     
 when UserControlName= 'Mobile'    
 then 'MobileNo'    
     
 when UserControlName= 'Email'    
 then 'EmailID'    
     
 when UserControlName= 'Address'    
 then 'ResidentialAddress'    
     
 when UserControlName= 'CountryCode'    
 then 'CountryCode'    
     
 when UserControlName= 'Remarks'    
 then 'InitialRemarks'    
 end    
 UserControlName , Ctrl_Label     
  from WebControlTbl where formid=@formid and UserControlName is not null    
 union    
select CAST( cwf.FieldId as varchar ), cf.fieldname , cwf.CtrlName from tbl_CustomFieldWebFormFieldMapping cwf    
 join customfields cf on cf.field_ID=cwf.FieldId    
where webformid = @formid    
 end    
     


GO

