 @tbl tbl_webctrlType READONLY        
 )                               
                                
as         
        
Begin         
     
 select aa.ControlID, aa.FormID, aa.ControlName, aa.Ctrl_type, aa.Ctrl_Label,    
  isnull(aa.UserControlName,'') UserControlName , aa.isenquery from [WebControlTbl] aa     
 inner join @tbl bb on bb.ctrl_dtl = aa.ControlName    
 WHERE aa.FormID = @FormID    
    
end 


