/* ============================================================
   Procedure: [dbo].[usp_GetWebEntryTbl_byFormid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
CREATE   PROCEDURE [dbo].[usp_GetWebEntryTbl_byFormid] --2130--2126 --14                    
  @FormId bigint = 0                     
AS                      
BEGIN                      
          
 select          
       [EntryId]          
      ,[FormId]          
              
     --,[EntryDate]           
                
      ,dbo.[fn_getusertimefromindiantime]((select top 1 isnull(ParentID,0)  From WebFormTbl wt where wt.FormID = @FormId),[EntryDate]) as EntryDate           
                
      ,[Mobile]          
      ,[formname]          
      ,[Name]          
      ,[Email]          
                
      --,[ContactDate]          
                
      ,dbo.[fn_getusertimefromindiantime]((select top 1 isnull(ParentID,0)  From WebFormTbl wt where wt.FormID = @FormId),ContactDate) as ContactDate           
                
      ,[Address]          
      ,replace(replace(DynimicAttr,'";"','","'),'":;"','":"","') as DynimicAttr          
      ,[Remarks]          
      ,[Status]          
      ,[enqueryId]          
      ,[mail_body]          
      ,[msg_body]          
      ,[CampaignName]  
   ,isjson(replace(replace(DynimicAttr,'";"','","'),'":;"','":"","')) as IsJson   
          
 from dbo.WebEntryTbl(nolock) where FormId = @FormId -- and 1=case when @formid=2130 and entryid< 111873  then 1 when @formid<>2130 then 1 else 0 end               
    order by EntryDate desc      
                 
END 


GO

