/* ============================================================
   Procedure: [dbo].[usp_GetWebEntryTbl_byFormidWithDate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetWebEntryTbl_byFormidWithDate] 
    @FormId BIGINT = 0,
    @FromDate DATETIME = NULL,
    @ToDate DATETIME = NULL
AS
BEGIN
select @todate=coalesce(@todate,dateadd(d,1,getdate())),@fromdate=coalesce(@fromdate,dateadd(d,-7,getdate()))
    SELECT
          [EntryId]
        , [FormId]
        , dbo.[fn_getusertimefromindiantime](
            (SELECT TOP 1 ISNULL(ParentID, 0) FROM WebFormTbl wt WHERE wt.FormID = @FormId),
            [EntryDate]) AS EntryDate
        , [Mobile]
        , [formname]
        , [Name]
        , [Email]
        , dbo.[fn_getusertimefromindiantime](
            (SELECT TOP 1 ISNULL(ParentID, 0) FROM WebFormTbl wt WHERE wt.FormID = @FormId),
            ContactDate) AS ContactDate
        , [Address]
        , REPLACE(REPLACE(DynimicAttr, '";"', '","'), '":;"', '":"","') AS DynimicAttr
        , [Remarks]
        , [Status]
        , [enqueryId]
        , [mail_body]
        , [msg_body]
        , [CampaignName]
        , ISJSON(REPLACE(REPLACE(DynimicAttr, '";"', '","'), '":;"', '":"","')) AS IsJson
    FROM dbo.WebEntryTbl WITH (NOLOCK)
    WHERE FormId = @FormId
      AND EntryDate between @FromDate 
      AND @ToDate 
    ORDER BY entryid DESC
END



GO

