/* ============================================================
   Procedure: [dbo].[Usp_GetWebFormPageForGraph_Kit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



	CREATE   PROCEDURE dbo.Usp_GetWebFormPageForGraph_Kit19 --233,335          
(          
@EnqNo bigint,          
@kit19UserID bigint          
          
)           
          
as          
          
Begin          
          
  Declare @DateCurrentTo datetime = null          
          
   CREATE TABLE #TempLinked                                            
    (                                            
      Result VARCHAR(200)                                            
    )                   
                              
     INSERT INTO #TempLinked                                            
     EXEC GetStatusofLinkedServer 'CRM'                                            
     IF NOT EXISTS(                                            
        SELECT 'x'                                            
        FROM   #TempLinked                                            
    )                                 
    begin             
          
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID           
 and Stage = 'Customer Accepted Setup Request'            
           
 --for temp          
            
   --Declare @DateCurrentTo datetime = null          
        
 --set @DateCurrentTo = '2019-01-01 21:08:03.167'          
          
       
  select convert(date,VisitDate) as Date ,count(convert(date,VisitDate)) as Count  from VisitPageDetails where ParentID = @kit19UserID and Type='Webform' and convert(date,VisitDate) > convert(date,@DateCurrentTo) group by convert(date,VisitDate)  
     order by convert(date,VisitDate) asc       
    
          
   end          
          
  drop table  #TempLinked          
      
          
End       




GO

/* ============================================================
   Procedure: [dbo].[Usp_GetWebFormPageForGraph_Kit19_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.Usp_GetWebFormPageForGraph_Kit19_New --233,335              
(              
@EnqNo bigint,              
@kit19UserID bigint              
              
)               
              
as              
              
Begin              
              
  Declare @DateCurrentTo datetime = null              
              
   CREATE TABLE #TempLinked                                                
    (                                                
      Result VARCHAR(200)                                                
    )                       
                                  
     INSERT INTO #TempLinked                                                
     EXEC GetStatusofLinkedServer 'CRM'                                                
     IF NOT EXISTS(                                                
        SELECT 'x'                                                
        FROM   #TempLinked                                                
    )                                     
    begin                 
              
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID               
 and Stage = 'Customer Accepted Setup Request'                
               
 --for temp              
                
   --Declare @DateCurrentTo datetime = null              
            
 --set @DateCurrentTo = '2019-01-01 21:08:03.167'              
              
           
  select convert(date,VisitDate) as Date ,count(convert(date,VisitDate)) as Count into #t1 from VisitPageDetails where ParentID = @kit19UserID and Type='Webform' and convert(date,VisitDate) > convert(date,@DateCurrentTo) group by convert(date,VisitDate)  
  
    
     order by convert(date,VisitDate) asc           
        
    
  select convert(date,EntryDate) as Date ,count(convert(date,EntryDate)) as Count into #t2 From WebEntryTbl where FormId in (select FormId From WebFormTbl where UserID = @kit19UserID) and convert(date,EntryDate) >= convert(date,@DateCurrentTo)     
   group by convert(date,EntryDate)       
 order by convert(date,EntryDate) asc     
          
 --  select * from    
 -- (    
 -- select Date,isnull(#t1.Count,0) as Visits , 0 as Leads  From #t1     
 -- union    
 -- Select Date,0 as Visits , isnull(#t2.Count,0) as Leads    From #t2 --on #t1.Date = #t2.Date    
 --) as tbl order by date asc    
            
  select tbl.Date as Date ,isnull(tbl.Visits,0) as Visits,isnull(tbl.Leads,0) as Leads from    
  (    
  select Date,isnull(#t1.Count,0) as Visits ,(select ISNULL(#t2.Count,0) from #t2 where #t2.Date = #t1.date) as Leads  From #t1     
  union    
  Select Date,(select ISNULL(#t1.Count,0) from #t1 where #t1.Date = #t2.date) as Visits , isnull(#t2.Count,0) as Leads    From #t2 --on #t1.Date = #t2.Date    
 ) as tbl order by date asc   
  
  
   end            
            
  drop table  #TempLinked      
  drop table #t1    
  drop table #t2                 
          
              
End 





GO

