/* ============================================================
   Procedure: [dbo].[Usp_GetWebFormPageStatus_Kit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE dbo.Usp_GetWebFormPageStatus_Kit19 --233,335            
(            
@EnqNo bigint,            
@kit19UserID bigint            
            
)             
            
as            
            
Begin            
            
     Declare @DateCurrentTo datetime = null      
  Declare @VisitCount int = 0      
  Declare @TotaDistinctDay int = 0       
  Declare @AverageVisitCount int = 0        
  Declare @Status nvarchar(50) = 'Red'        
         
   CREATE TABLE #TempLinked                                              
    (                                              
      Result VARCHAR(200)                                              
    )                     
                                
     INSERT INTO #TempLinked                                              
     EXEC GetStatusofLinkedServer 'CRM'                                              
     IF NOT EXISTS(                                              
        SELECT 'x'                                              
        FROM   #TempLinked                                              
    )                                   
    begin               
          
           
       
      
      
  --set @DateCurrentTo = '2019-01-01 21:08:03.167'            
           
      
      
  select @VisitCount = ISNULL(Count(*),0)  from VisitPageDetails where ParentID = 335 and Type='Webform' and convert(date,VisitDate) >= convert(date,@DateCurrentTo)      
      
  select @TotaDistinctDay = count( distinct  convert(date,VisitDate))  from VisitPageDetails where ParentID = @kit19UserID and Type='Webform' and convert(date,VisitDate) >= convert(date,@DateCurrentTo)       
      
	  if(@VisitCount <> 0)
	  Begin
  set @AverageVisitCount = (@VisitCount/@TotaDistinctDay)      
      End 
      
      
      
  if(exists(      
  --select 1 from ClientPageDetail where User_ID = @kit19UserID and convert(date,DateCreated) >= CONVERT(date,@DateCurrentTo)       
  select 1 From WebEntryTbl where FormId in (select FormId From WebFormTbl where UserID = @kit19UserID) and convert(date,EntryDate) >= convert(date,@DateCurrentTo)    
    
  ))      
  Begin      
           
          if(@AverageVisitCount >= 1)      
      Begin      
       set @Status ='Green'      
   End      
      
  End      
               
  end            
              
  drop table  #TempLinked            
        
  select @Status as Status      
      
            
End            
          


GO

/* ============================================================
   Procedure: [dbo].[Usp_getWebFormPayments]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON







CREATE   PROCEDURE dbo.Usp_getWebFormPayments
(
  @ParentID Bigint
)
as
Begin

  select
      
	   WFP.ID
      ,WFP.WebTBLEntryID
      ,WFP.PaymentStatus
      ,WFP.TxnID
      ,WFP.Amount
      ,WFP.Name
      ,WFP.MobNo
      ,WFP.EmailID
      ,WFP.Remarks
      ,WFP.CreatedDate
      ,WFP.ModifiedDate
      ,WFP.Source
	  
	   From WebFormPayments WFP join  WebEntryTbl WET 
  on  WFP.WebTBLEntryID = WET.EntryId 
  join
   WebFormTbl as WFT
   on Wet.FormId = WFT.FormId
  where Wft.ParentId = @ParentID    


  order by id desc 

End



GO

