/* ============================================================
   Procedure: [dbo].[usp_GetWebhook_byFormid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetWebhook_byFormid] --18        
  @FormId bigint = 0           
AS            
BEGIN  

 select 
  ent.WebAPIentryid,
  EntryId,
  apt.formid,
  
  --Created_on,
  dbo.[fn_getusertimefromindiantime]((select top 1 isnull(ParentID,0)  From WebFormTbl wt where wt.FormID = @FormId),Created_on) as Created_on ,
  
  apt.webapi,
  case  when api_processed = 1    
  then 'Yes'    
  else 'No'     
  end as Processed,    
  api_resp,
  
 --Processed_date,
 dbo.[fn_getusertimefromindiantime]((select top 1 isnull(ParentID,0)  From WebFormTbl wt where wt.FormID = @FormId),Processed_date) as Processed_date
       
  from webformApi_Tbl apt inner join [webFormap_respTbl] ent    
  on ent.apiid = apt.apiid    
  where apt.formid = @formid and apt.webapi != '' order by ent.Created_on desc    

END 



GO

