/* ============================================================
   Procedure: [dbo].[Usp_GetWebHookIdforButton]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-------------------------

CREATE   PROCEDURE Usp_GetWebHookIdforButton  
(  
    @UserId BIGINT  
)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Select the last inserted WebhookID for the given UserId  
        SELECT TOP 1 WebhookID  
        FROM Tbl_CB_WebhookSummary  
        WHERE UserId = @UserId  
        ORDER BY CreatedDate DESC;  
    END TRY  
    BEGIN CATCH  
        -- Handle errors  
        DECLARE @ErrorMessage NVARCHAR(4000), @ErrorSeverity INT, @ErrorState INT;  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE();  
  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);  
    END CATCH  
END;  




GO

