   Procedure: [dbo].[Usp_GetWebHookIds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-----------------------------------

CREATE   PROCEDURE dbo.Usp_GetWebHookIds  
    @ButtonId BIGINT,  
 @UserId BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    -- Fetch user details along with their roles  
    SELECT   
        WebhookID  
    FROM   
        tbl_CB_CustomButtons (NOLOCK) where ButtonId=@ButtonId --and UserId=@UserId  
      
END;  




GO

/* ============================================================
   Procedure: [dbo].[Usp_GetWhatsappCampaign_ByID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetWhatsappCampaign_ByID]      
(      
  @CampaignID bigint      
)      
as      
Begin      
           
   select  isnull(TemplateID,0) as TemplateID , ISNULL(ContactType,'') as  ContactType     
             ,isnull(IsActive,0) as IsActive, TimeBeforeEvent,TimeUnit       
            from UserCampaignMaster(nolock) where ID = @CampaignID        
      
    
End  


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetWhatsappCampaign_ByID_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-------------------------------------------------------
----------------------------------------


CREATE   PROCEDURE [dbo].[Usp_GetWhatsappCampaign_ByID_1]        
(        
  @CampaignID bigint        
)        
as        
Begin        
      begin try       
   select  isnull(TemplateID,0) as TemplateID , ISNULL(ContactType,'') as  ContactType       
             ,isnull(IsActive,0) as IsActive, TimeBeforeEvent,TimeUnit,maxlimit         
            from UserCampaignMaster(nolock) where ID = @CampaignID          
       END TRY

    -- Catch block to handle errors
    BEGIN CATCH
        -- Log error information
        EXEC usp_InsertErrorInfo;
    END CATCH

END;




GO

/* ============================================================
   Procedure: [dbo].[Usp_getWhatsappTemplateByID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_getWhatsappTemplateByID] --1
(
  @TemplateID bigint
)
as
Begin
       --select id,templatejson,templatetype,templatename,templatenamespace,templatebody,channeltokenid ,tlanguage,category
	      --     from MySMSConversations.dbo.convtemplates as CTL with(nolock) where id = @TemplateID 
		  DECLARE @sqlQuery NVARCHAR(MAX);

SET @sqlQuery = 
    'SELECT id, templatejson, templatetype, templatename, templatenamespace, templatebody, channeltokenid, tlanguage, category ' +
    'FROM convtemplates WITH (NOLOCK) ' +
    'WHERE id = ' + CAST(@TemplateID AS NVARCHAR);
	EXEC usp_clr_GetRemoteData @sqlQuery;

End



GO


